window.HADITH_CACHE["ahmad_7"] = {"3501":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي عَاصِمُ بْنُ عُمَرَ بْنِ قَتَادَةَ الْأَنْصَارِيُّ عَنْ مَحْمُودِ بْنِ لَبِيدٍ أَخِي بَنِي عَبْدِ الْأَشْهَلِ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِنَا الْمَغْرِبَ فِي مَسْجِدِنَا فَلَمَّا سَلَّمَ مِنْهَا قَالَ ارْكَعُوا هَاتَيْنِ الرَّكْعَتَيْنِ فِي بُيُوتِكُمْ لِلسُّبْحَةِ بَعْدَ الْمَغْرِبِ","id":"Telah bercerita kepada kami [Ya'qub] telah bercerita kepada kami [ayahku] dari [Ibnu Ishaq] telah bercerita kepadaku ['Ashim bin 'Umar bin Qatadah Al Anshari] dari [Mahmud bin Labid] -seseorang dari Bani 'Abdul Asyhal- berkata: Rasulullah shallallahu 'alaihi wasallam mendatangi kami lalu beliau shalat maghrib bersama kami dimasjid kami, saat salam beliau bersabda: \"Lakukan shalat dua rakaat ini dirumah-rumah kalian untuk shalat sunnah setelah maghrib.\""},"3502":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ أَخْبَرَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ عَمْرٍو عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اثْنَتَانِ يَكْرَهُهُمَا ابْنُ آدَمَ الْمَوْتُ وَالْمَوْتُ خَيْرٌ لِلْمُؤْمِنِ مِنْ الْفِتْنَةِ وَيَكْرَهُ قِلَّةَ الْمَالِ وَقِلَّةُ الْمَالِ أَقَلُّ لِلْحِسَابِحَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَخْبَرَنَا إِسْمَاعِيلُ أَخْبَرَنِي عَمْرُو بْنُ أَبِي عَمْرٍو عَنْ عَاصِمٍ عَنْ مَحْمُودِ بْنِ لَبِيدٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَكَرَ مِثْلَهُ حَدَّثَنَا أَبُو سَلَمَةَ أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ عَاصِمِ بْنِ عُمَرَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَكَرَ مِثْلَهُ","id":"Telah bercerita kepada kami [Abu Salamah] telah mengkhabarkan kepada kami ['Abdul 'Aziz bin Muhammad] dari ['Amru] dari ['Ashim bin 'Umar bin Qatadah] dari [Mahmud bin Labid] bahwa nabi shallallahu 'alaihi wasallam bersabda: \"Dua hal yang dibenci oleh manusia; kematian padahal kematian itu lebih baik bagi orang mu`min dari pada fitnah dan benci sedikitnya harta padahal sedikitnya harta itu lebih ringan untuk hisab.\" Telah bercerita kepada kami [Sulaiman bin Dawud] telah mengkhabarkan kepada kami [Isma'il] telah mengkhabarkan kepadaku ['Amru bin Abu 'Amru] dari ['Ashim] dari [Mamud bin Labid] bahwa nabi shallallahu 'alaihi wasallam bersabda, lalu ia menyebut hadits sepertinya. Telah bercerita kepada kami [Abu Salamah] telah mengkhabarkan kepada kami ['Abdul 'Aziz bin Muhammad] dari ['Amru bin Abu 'Amru] dari ['Ashim bin 'Umar] dari [Mahmud bin Labid] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, ia menyebut hadits serupa."},"3503":{"ar":"حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ حَدَّثَنِي عَاصِمُ بْنُ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ قَالَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَنِي عَبْدِ الْأَشْهَلِ فَصَلَّى بِهِمْ الْمَغْرِبَ فَلَمَّا سَلَّمَ قَالَ ارْكَعُوا هَاتَيْنِ الرَّكْعَتَيْنِ فِي بُيُوتِكُمْقَالَ أَبُو عَبْد الرَّحْمَنِ قُلْتُ لِأَبِي إِنَّ رَجُلًا قَالَ مَنْ صَلَّى رَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ فِي الْمَسْجِدِ لَمْ تُجْزِهِ إِلَّا أَنْ يُصَلِّيَهُمَا فِي بَيْتِهِ لِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذِهِ مِنْ صَلَوَاتِ الْبُيُوتِ قَالَ مَنْ قَالَ هَذَا قُلْتُ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ مَا أَحْسَنَ مَا قَالَ أَوْ مَا أَحْسَنَ مَا انْتَزَعَ","id":"Telah bercerita kepada kami [Ibnu Abi 'Adi] dari [Muhammad bin Ishaq] telah bercerita kepadaku ['Ashim bin 'Umar bin Qatadah] dari [Mahmud bin Labid] berkata: Rasulullah shallallahu 'alaihi wasallam mendatangi Bani 'Abdul Asyhal lalu shalat maghrib bersama mereka, seusai salam beliau bersabda: \"Shalatlah dua rakaat ini dirumah-rumah kalian.\" Berkata Abu 'Abdur Rahman: Aku berkata kepada ayahku bahwa seseorang berkata: Barangsiapa shalat dua rakaat setelah maghrib dirumah ia tidak membolehkannya kecuali bila dilakukan dirumah karena nabi shallallahu 'alaihi wasallam bersabda: \"Ini termasuk shalat-shalat (yang dilakukan) di rumah.\" Ayahku bertanya: Siapa yang mengatakannya? Aku menjawab: Muhammad bin 'Abdur Rahman, ayahnya berkata: Alangkah baiknya yang ia katakana atau alangkah baiknya yang didapatkan."},"3504":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سُلَيْمَانَ بْنِ الْغَسِيلِ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ قَالَكَسَفَتْ الشَّمْسُ يَوْمَ مَاتَ إِبْرَاهِيمُ ابْنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا كَسَفَتْ الشَّمْسُ لِمَوْتِ إِبْرَاهِيمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ عَزَّ وَجَلَّ أَلَا وَإِنَّهُمَا لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمُوهُمَا كَذَلِكَ فَافْزَعُوا إِلَى الْمَسَاجِدِ ثُمَّ قَامَ فَقَرَأَ فِيمَا نَرَى بَعْضَ الر كِتَابٌ ثُمَّ رَكَعَ ثُمَّ اعْتَدَلَ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ فَفَعَلَ مِثْلَ مَا فَعَلَ فِي الْأُولَى","id":"Telah bercerita kepada kami [Yahya bin Adam] telah bercerita kepada kami ['Abdur Rahman bin Sulaiman bin Al Ghasil] dari ['Ashim bin 'Umar bin Qatadah] dari [Mahmud bin Labid] berkata: Terjadi gerhana matahari saat Ibrahim putra Rasulullah shallallahu 'alaihi wasallam meninggal, mereka berkata: Matahari gerhana karena kematian Ibraim. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya matahari dan bulan adalah dua diantara tanda-tanda kebesaran Allah 'azza wajalla, ingat sesungguhnya keduanya tidak gerhana karena kematian atau kehidupan seseorang, bila kalian melihat keduanya seperti itu, pergilah ke masjid kemudian berdiri lalu membaca -menurut perawi: Sebagaian ayat dari surat ALIF LAAM RAA' KITAAB- kemudian ruku', kemudian i'tidal, lalu sujud dua kali kemudian berdiri lalu melakukan seperti yang dilakukan pada rakaat pertama.\""},"3505":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا لَيْثٌ عَنْ يَزِيدَ يَعْنِي ابْنَ الْهَادِ عَنْ عَمْرٍو عَنْ مَحْمُودِ بْنِ لَبِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَخْوَفَ مَا أَخَافُ عَلَيْكُمْ الشِّرْكُ الْأَصْغَرُ قَالُوا وَمَا الشِّرْكُ الْأَصْغَرُ يَا رَسُولَ اللَّهِ قَالَ الرِّيَاءُ يَقُولُ اللَّهُ عَزَّ وَجَلَّ لَهُمْ يَوْمَ الْقِيَامَةِ إِذَا جُزِيَ النَّاسُ بِأَعْمَالِهِمْ اذْهَبُوا إِلَى الَّذِينَ كُنْتُمْ تُرَاءُونَ فِي الدُّنْيَا فَانْظُرُوا هَلْ تَجِدُونَ عِنْدَهُمْ جَزَاءًحَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ عَاصِمِ بْنِ عُمَرَ الظَّفَرِيِّ عَنْ مَحْمُودِ بْنِ لَبِيدٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَخْوَفَ مَا أَخَافُ عَلَيْكُمْ فَذَكَرَ مَعْنَاهُ","id":"Telah bercerita kepada kami [Yunus] telah bercerita kepada kami [Laits] dari [Yazid bin Al Had] dari ['Amru] dari [Mahmud bin Labid] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang paling aku khawatirkan dari kalian adalah syirik kecil.\" Mereka bertanya: Apa itu syirik kecil wahai Rasulullah shallallahu 'alaihi wasallam? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Riya`, Allah 'azza wajalla berfirman kepada mereka pada hari kiamat saat orang-orang diberi balasan atas amal-amal mereka: Temuilah orang-orang yang dulu kau perlihat-lihatkan di dunia lalu lihatlah apakah kalian menemukan balasan disisi mereka?\" telah bercerita kepada kami [Ibrahim bin Abu Al 'Abbas] telah bercerita kepada kami ['Abdur Rahman bin Abu Az Zinad] dari ['Amru bin Abu 'Amru] dari ['Ashim bin 'Umar Azh Zhafari] dari [Mahmud bin Labid] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang paling aku khawatirkan dari kalian\" lalu ia menyebut makna hadits."},"3506":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا لَيْثٌ عَنْ يَزِيدَ عَنْ عَمْرٍو مَوْلَى الْمُطَّلِبِ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَحَبَّ اللَّهُ قَوْمًا ابْتَلَاهُمْ فَمَنْ صَبَرَ فَلَهُ الصَّبْرُ وَمَنْ جَزِعَ فَلَهُ الْجَزَعُ","id":"Telah bercerita kepada kami [Yunus] telah bercerita kepada kami [Laits] dari [Yazid] dari ['Amru, budak Al Muththallib] dari ['Ashim bin 'Umar bin Qatadah] dari [Mahmud bin Labid] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesunggunya Allah 'azza wajalla bila menyintai suatu kaum, Ia menguji mereka maka barangsiapa yang bersabar maka baginya kesabaran dan barangsiapa yang berkeluh kesah maka baginya keluh kesah.\""},"3507":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي الْحُصَيْنُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَمْرِو بْنِ سَعْدِ بْنِ مُعَاذٍ عَنْ أَبِي سُفْيَانَ مَوْلَى ابْنِ أَبِي أَحْمَدَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ يَقُولُ حَدِّثُونِي عَنْ رَجُلٍ دَخَلَ الْجَنَّةَ لَمْ يُصَلِّ قَطُّ فَإِذَا لَمْ يَعْرِفْهُ النَّاسُ سَأَلُوهُ مَنْ هُوَ فَيَقُولُ أُصَيْرِمُ بَنِي عَبْدِ الْأَشْهَلِ عَمْرُو بْنُ ثَابِتِ بْنِ وَقْشٍ قَالَ الْحُصَيْنُ فَقُلْتُ لِمَحْمُودِ بْنِ لَبِيدٍ كَيْفَ كَانَ شَأْنُ الْأُصَيْرِمِ قَالَ كَانَ يَأْبَى الْإِسْلَامَ عَلَى قَوْمِهِ فَلَمَّا كَانَ يَوْمُ أُحُدٍ وَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أُحُدٍ بَدَا لَهُ الْإِسْلَامُ فَأَسْلَمَ فَأَخَذَ سَيْفَهُ فَغَدَا حَتَّى أَتَى الْقَوْمَ فَدَخَلَ فِي عُرْضِ النَّاسِ فَقَاتَلَ حَتَّى أَثْبَتَتْهُ الْجِرَاحَةُ قَالَ فَبَيْنَمَا رِجَالُ بَنِي عَبْدِ الْأَشْهَلِ يَلْتَمِسُونَ قَتْلَاهُمْ فِي الْمَعْرَكَةِ إِذَا هُمْ بِهِ فَقَالُوا وَاللَّهِ إِنَّ هَذَا لَلْأُصَيْرِمُ وَمَا جَاءَ لَقَدْ تَرَكْنَاهُ وَإِنَّهُ لَمُنْكِرٌ هَذَا الْحَدِيثَ فَسَأَلُوهُ مَا جَاءَ بِهِ قَالُوا مَا جَاءَ بِكَ يَا عَمْرُو أَحَرْبًا عَلَى قَوْمِكَ أَوْ رَغْبَةً فِي الْإِسْلَامِ قَالَ بَلْ رَغْبَةً فِي الْإِسْلَامِ آمَنْتُ بِاللَّهِ وَرَسُولِهِ وَأَسْلَمْتُ ثُمَّ أَخَذْتُ سَيْفِي فَغَدَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَاتَلْتُ حَتَّى أَصَابَنِي مَا أَصَابَنِي قَالَ ثُمَّ لَمْ يَلْبَثْ أَنْ مَاتَ فِي أَيْدِيهِمْ فَذَكَرُوهُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ لَمِنْ أَهْلِ الْجَنَّةِ","id":"Telah bercerita kepada kami [Ya'qub bin Ibrahim] telah bercerita kepada kami [ayahku] dari [Ibnu Ishaq] telah bercerita kepadaku [Al Hushain bin 'Abdur Rahman bin 'Amru bin Sa'ad bin Mu'adz] dari [Abu Sufyan] budak Ibnu Abi Ahmad dari [Abu Hurairah] berkata: Ia berkata: Ceritakan padaku tentang orang yang masuk surga yang tidak pernah shalat sama sekali, bila orang-orang tidak mengenalnya, tanyakan siapa dia? Lalu jagoan Bani 'Abdul Asyhal, 'Amru bin Tsabit bin Waqsy berkata: Berkata Al Hushain lalu aku berkata kepada [Mahmud bin Labid]: Bagaimana keadaan Al Ushairim?: ia menjawab: Ia enggan masuk Islam karena kaumnya kemudian saat terjadi perang Uhud dan Rasulullah shallallahu 'alaihi wasallam pergi menuju Uhud, terlihatlah keIslamannya lalu masuk Islam. Ia mencabut pedang dan maju hingga mendatangi musuh, ia masuk dihadapan orang-orang dan berperang hingga terluka. Saat orang-orang Bani 'Abdul Asyhal mencari korban-korban mereka dalam peperangan, ternyata mereka menemukannya, mereka berkata: Demi Allah ini adalah Al Ushairim. Kami meninggalkannya dan ia memungkiri hadits ini. Mereka bertanya padanya kenapa datang, mereka berkata: Untuk apa kau datang wahai 'Amru, apa kau ingin berperang demi kaummu atau ingin masuk Islam? Ia menjawab: Ingin masuk Islam, aku beriman kepada Allah dan rasulNya, aku masuk Islam lalu aku mengambil pedangku, aku maju bersama Rasulullah shallallahu 'alaihi wasallam dan aku berperang hingga aku terkena serangan. Berkata Mahmud: Tidak berselang lama ia pun meniggal direngkuhan tangan mereka. Mereka menyebutkan hal itu kepada Rasulullah shallallahu 'alaihi wasallam lalu beliau bersabda: \"Sesungguhnya ia termasuk penghuni surga.\""},"3508":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاوِيَةَ بْنِ خَدِيجٍ قَالَ سَمِعْتُ رَجُلًا مِنْ كِنْدَةَ يَقُولُ حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَنْصَارِ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَنْتَقِصُ أَحَدُكُمْ مِنْ صَلَاتِهِ شَيْئًا إِلَّا أَتَمَّهَا اللَّهُ عَزَّ وَجَلَّ مِنْ سُبْحَتِهِ","id":"Telah bercerita kepada kami [Yahya bin Ishaq] telah bercerita kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Hubaib] dari ['Abdur Rahman bin Mu'awiyah bin Khadij] berkata: Aku mendengar [seseorang dari Kindah] berkata: Telah bercerita kepadaku seorang sahabat nabi shallallahu 'alaihi wasallam dari Anshar, bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang dari kalian yang shalatnya kurang melainkan Allah 'azza wajalla menyempurnakannya dari shalat sunnahnya.\"  "},"3509":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ حَدَّثَنِي مَحْمُودُ بْنُ لَبِيدٍ أَنَّهُعَقَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَقَلَ مَجَّةً مَجَّهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ دَلْوٍ كَانَ فِي دَارِهِمْ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Ma'mar] dari [Az Zuhri] telah bercerita kepada kami [Mahmud bin Labid] bahwa ia membayar diyat Rasulullah shallallahu 'alaihi wasallam dan membayar diyat untuk gayung yang dilemparkan Rasulullah shallallahu 'alaihi wasallam yang ada dirumah mereka.\""},"3510":{"ar":"حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ قَالَاخْتَلَفَتْ سُيُوفُ الْمُسْلِمِينَ عَلَى الْيَمَانِ أَبِي حُذَيْفَةَ يَوْمَ أُحُدٍ وَلَا يَعْرِفُونَهُ فَقَتَلُوهُ فَأَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَدِيَهُ فَتَصَدَّقَ حُذَيْفَةُ بِدِيَتِهِ عَلَى الْمُسْلِمِينَ","id":"Telah bercerita kepada kami [Yahya bin Zakariya bin Abu Za`idah] berkata: Telah mengkhabarkan kepadaku [Ishaq] dari ['Ashim bin 'Umar bin Qatadah] dari [Mahmud bin Labid] berkata: Pedang-pedang kaum muslimin menyerang Al Yaman Abu Hudzaifah saat perang Uhud, mereka tidak mengenalinya lalu membunuhnya, Rasulullah shallallahu 'alaihi wasallam ingin menebusnya lalu Hudzaifah menyedekahkan diyatnya untuk kaum muslimin."},"3511":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا مُحَمَّدٌ يَعْنِي ابْنَ أَبِي عَمْرٍو عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ مَحْمُودِ بْنِ لَبِيدٍ قَالَلَمَّا نَزَلَتْ{ أَلْهَاكُمْ التَّكَاثُرُ فَقَرَأَهَا حَتَّى بَلَغَ لَتُسْأَلُنَّ يَوْمَئِذٍ عَنْ النَّعِيمِ }قَالُوا يَا رَسُولَ اللَّهِ عَنْ أَيِّ نَعِيمٍ نُسْأَلُ وَإِنَّمَا هُمَا الْأَسْوَدَانِ الْمَاءُ وَالتَّمْرُ وَسُيُوفُنَا عَلَى رِقَابِنَا وَالْعَدُوُّ حَاضِرٌ فَعَنْ أَيِّ نَعِيمٍ نُسْأَلُ قَالَ إِنَّ ذَلِكَ سَيَكُونُ","id":"Telah bercerita kepada kami [Yazid] telah mengkhabarkan kepada kami [Muhammad bin Abu 'Amru] dari [Shafwan bin Sulaim] dari [Mahmud bin Labid] berakat: Saat turun ALHAAKUMUT TAKAATSUR, ia Mahmud membacanya hingga LATUS`ALUNNA YAUMA'IDZIN 'ANIN NA'IIM. Mereka berkata: Wahai Rasulullah! Nikmat apa yang akan ditanyakan pada kami, sesungguhnya hanya ada dua barang hitam; air dan kurma sementara pedang-pedang kami ada dileher-leher kami sementara musuh sudah ada, lalu nikmat apa yang akan ditanyakan pada kami? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya hal itu akan ada.\""},"3512":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ أَخْبَرَنِي عَمْرٌو عَنْ عَاصِمٍ عَنْ مَحْمُودِ بْنِ لَبِيدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَحَبَّ اللَّهُ قَوْمًا ابْتَلَاهُمْ فَمَنْ صَبَرَ فَلَهُ الصَّبْرُ وَمَنْ جَزِعَ فَلَهُ الْجَزَعُ","id":"Telah bercerita kepada kami [Sulaiman bin Dawud] telah mengkhabarkan kepada kami [Isma'il bin Ja'far] telah mengkhabarkan kepada kami ['Amru] dari ['Ashim] dari [Mahmud bin Labid] bahwa nabi shallallahu 'alaihi wasallam bersabda: \"Sesunggunya Allah 'azza wajalla bila menyintai suatu kaum, Ia menguji mereka maka barangsiapa yang bersabar maka baginya kesabaran dan barangsiapa yang berkeluh kesah maka baginya keluh kesah.\""},"3513":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنِ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِ��َامٍ عَنْ نَوْفَلِ بْنِ مُعَاوِيَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ فَاتَتْهُ الصَّلَاةُ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُ","id":"Telah bercerita kepada kami ['Abdul Malik bin 'Amru] telah bercerita kepada kami [Ibnu Abi Dzi'b] dari [Az Zuhri] dari [Abu Bakar bin 'Abdur Rahman bin Al Harits bin Hisyam] dari [Naufal bin Mu'awiyah] bahwa nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang ketinggalan shalat maka seolah-olah ia memperlakukan tidak adil terhadap keluarga dan hartanya.\""},"3514":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ رَجُلٍ مِنْ بَنِي ضَمْرَةَ عَنْ رَجُلٍ مِنْ قَوْمِهِ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَقِيقَةِ فَقَالَ لَا أُحِبُّ الْعُقُوقَ وَلَكِنْ مَنْ وُلِدَ لَهُ وَلَدٌ فَأَحَبَّ أَنْ يَنْسُكَ عَلَيْهِ أَوْ عَنْهُ فَلْيَفْعَلْ","id":"Telah bercerita kepada kami ['Abdur Rahman] dari [Sufyan] dari [Zaid bin Aslam] dari [Seseorang dari Bani Dlamrah] dari seseorang dari kaumnya berkata: Aku bertanya kepada nabi shallallahu 'alaihi wasallam tentang aqiqah, beliau bersabda: \"Aku tidak suka aqiqah tapi barangsiapa yang memiliki anak lalu ingin menyembelih hewan untuknya silahkan melakukannya.\""},"3515":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ رَجُلٍ عَنْ أَبِيهِ أَوْ عَنْ عَمِّهِ أَنَّهُ قَالَشَهِدْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ فَسُئِلَ عَنْ الْعَقِيقَةِ فَقَالَ لَا أُحِبُّ الْعُقُوقَ وَلَكِنْ مَنْ وُلِدَ لَهُ وَلَدٌ فَأَحَبَّ أَنَّ يَنْسُكَ عَنْهُ فَلْيَفْعَلْ","id":"Telah bercerita kepada kami [Sufyan bin 'Uyainah] telah bercerita kepada kami [Zaid bin Aslam] dari [seseorang] dari ayahnya atau dari pamannya bahwa ia bekata: Aku menyaksikan nabi shallallahu 'alaihi wasallam di Arafah, beliau ditanya tentang aqiqah, beliau bersabda: \"Aku tidak suka aqiqah tapi barangsiapa yang memiliki anak lalu ingin menyembelih hewan untuknya silahkan melakukannya.\""},"3516":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ زَيْدٍ يَعْنِي ابْنَ أَسْلَمَ عَنْ رَجُلٍ مِنْ بَنِي سُلَيْمٍ عَنْ جَدِّهِ أَنَّهُأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفِضَّةٍ فَقَالَ هَذِهِ مِنْ مَعْدِنٍ لَنَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَكُونُ مَعَادِنُ يُحْضِرُهَا شِرَارُ النَّاسِ","id":"Telah bercerita kepada kami ['Abdur Rahman] dari [Sufyan] dari [Zaid bin Aslam] dari [seseorang dari Bani Sulaim] dari kakeknya bahwa ia mendatangi nabi shallallahu 'alaihi wasallam dengan membawa perak, ia berkata: Ini salah satu barang tambang kami. Lalu nabi shallallahu 'alaihi wasallam bersabda: \"Kelak barang-barang tambang akan didatangi oleh manusia-manusia buruk.\""},"3517":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ رَجُلٍ مِنَ الْأَنْصَارِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ نَسْتَقْبِلَ الْقِبْلَتَيْنِ بِبَوْلٍ أَوْ غَائِطٍ","id":"Telah bercerita kepada kami [Isma'il] telah mengkhabarkan kepada kami [Ayyub] dari [Nafi'] dari [seseorang dari Anshar] dari ayahnya bahwa Rasulullah shallallahu 'alaihi wasallam melarang kami menghadap dua kiblat saat kencing atau berak."},"3518":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ بَنِي حَارِثَةَأَنَّ رَجُلًا وَجَأَ نَاقَةً فِي لَبَّتِهَا بِوَتِدٍ وَخَشِيَ أَنْ تَفُوتَهُ فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَوْ أَمَرَهُمْ بِأَكْلِهَا","id":"Telah bercerita kepada kami ['Abdur Rahman] dari [Sufyan] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [seorang Bani Haritsah] bahwa seseorang memukul unta dibawah lehernya dengan pasak dan khawatir akan mati lalu ia bertanya kepada nabi shallallahu 'alaihi wasallam kemudian beliau memerintahkannya atau memerintahkan mereka untuk memakannya."},"3519":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ بَنِي أَسَدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَسْأَلُ رَجُلٌ وَلَهُ أُوقِيَّةٌ أَوْ عَدْلُهَا إِلَّا سَأَلَ إِلْحَافًا","id":"Telah bercerita kepada kami ['Abdur Rahman bin Mahdi] dari [Sufyan] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [seorang Bani Asad] dari nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang meminta-minta sementara ia memiliki satu uqiyah atau senilainya kecuali ia meminta dengan menjilat-jilat.\""},"3520":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ وَعَبْدُ الرَّزَّاقِ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُئِيَ بِالْعَرْجِ وَهُوَ يَصُبُّ عَلَى رَأْسِهِ الْمَاءَ مِنْ الْحَرِّ أَوْ مِنْ الْعَطَشِ وَهُوَ صَائِمٌ","id":"Telah bercerita kepada kami ['Abdur Rahman] dan ['Abdur Razzaq] dari [Malik] dari [Sumayya] dari [Abu Bakar bin 'Abdur Rahman] dari [seorang sahabat] nabi shallallahu 'alaihi wasallam bahwa nabi shallallahu 'alaihi wasallam terlihat lemah, beliau menuangkan air diatas kepala karena panas atau haus saat beliau puasa."},"3521":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ أَسْلَمَأَنَّهُ لُدِغَ فَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّكَ قُلْتَ حِينَ أَمْسَيْتَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ لَمْ تَضُرَّكَقَالَ سُهَيْلٌ فَكَانَ أَبِي إِنْ لُدِغَ أَحَدٌ مِنَّا يَقُولُ قَالَهَا فَإِنْ قَالُوا نَعَمْ قَالَ كَأَنَّهُ يَرَى أَنَّهَا لَا تَضُرُّهُ","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [seorang Bani Aslam] bahwa ia tersengat lalu ia menyebutnya pada nabi shallallahu 'alaihi wasallam kemudian nabi shallallahu 'alaihi wasallam bersabda: \"Andai kau mengucapkan saat sore hari: A'UDZU BIKALIMAATILLAAHIT TAAMMATI MIN SYARRI MAA KHALAQ niscaya ia tidak akan membahayakanmu. Berkata Suhail: Bila seseorang diantara kami tersengat, ayahku mengatakannya bila mereka mengatakan: Iya, sepertinya menurut ayahku (binatang) itu tidak membahayakan."},"3522":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِيهِ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَيُوشِكُ أَنْ يَغْلِبَ عَلَى الدُّنْيَا لُكَعُ بْنُ لُكَعٍ وَأَفْضَلُ النَّاسِ مُؤْمِنٌ بَيْنَ كَرِيمَتَيْنِ لَمْ يَرْفَعْهُ","id":"Telah bercerita kepada kami [Abu Kamil] telah bercerita kepada kami [Ibrahim bin Sa'ad] telah bercerita kepada kami [Ibnu Syihab] dari ['Abdul Malik bin Abu Bakar bin 'Abdur Rahman bin Al Harits bin Hisyam] dari [ayahnya] dari [seorang sahabat nabi shallallahu 'alaihi wasallam] berkata: Hampir saja orang hina putra orang hina mengalahkan dunia dan orang terbaik adalah orang mu`min diantara dua kemuliaan. Ia tidak memarfu'kan hadits ini."},"3523":{"ar":"حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ عَنْ رَجُلٍ عَنْ عُبَيْدٍ مَوْلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَسُئِلَ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِصَلَاةٍ بَعْدَ الْمَكْتُوبَةِ أَوْ سِوَى الْمَكْتُوبَةِ قَالَ نَعَمْ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ","id":"Telah bercerita kepada kami [Mu'tamir] dari [ayahnya] dari [seseorang] dari ['Ubai] budak milik nabi shallallahu 'alaihi wasallam berkata: Ia ditanya apakah Rasulullah shallallahu 'alaihi wasallam memerintahkan shalat setelah shalat wajib atau selain shalat wajib? Ia menjawab: Ya, antara maghrib dan 'isya`."},"3524":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا سُلَيْمَانُ وَابْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ الْمَعْنَى عَنْ رَجُلٍ حَدَّثَهُمْ فِي مَجْلِسِ أَبِي عُثْمَانَ النَّهْدِيِّ قَالَ ابْنُ أَبِي عَدِيٍّ عَنْ شَيْخٍ فِي مَجْلِسِ أَبِي عُثْمَانَ عَنْ عُبَيْدٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ امْرَأَتَيْنِ صَامَتَا وَأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنَّ هَاهُنَا امْرَأَتَيْنِ قَدْ صَامَتَا وَإِنَّهُمَا قَدْ كَادَتَا أَنْ تَمُوتَا مِنْ الْعَطَشِ فَأَعْرَضَ عَنْهُ أَوْ سَكَتَ ثُمَّ عَادَ وَأُرَاهُ قَالَ بِالْهَاجِرَةِ قَالَ يَا نَبِيَّ اللَّهِ إِنَّهُمَا وَاللَّهِ قَدْ مَاتَتَا أَوْ كَادَتَا أَنْ تَمُوتَا قَالَ ادْعُهُمَا قَالَ فَجَاءَتَا قَالَ فَجِيءَ بِقَدَحٍ أَوْ عُسٍّ فَقَالَ لِإِحْدَاهُمَا قِيئِي فَقَاءَتْ قَيْحًا أَوْ دَمًا وَصَدِيدًا وَلَحْمًا حَتَّى قَاءَتْ نِصْفَ الْقَدَحِ ثُمَّ قَالَ لِلْأُخْرَى قِيئِي فَقَاءَتْ مِنْ قَيْحٍ وَدَمٍ وَصَدِيدٍ وَلَحْمٍ عَبِيطٍ وَغَيْرِهِ حَتَّى مَلَأَتْ الْقَدَحَ ثُمَّ قَالَ إِنَّ هَاتَيْنِ صَامَتَا عَمَّا أَحَلَّ اللَّهُ وَأَفْطَرَتَا عَلَى مَا حَرَّمَ اللَّهُ عَزَّ وَجَلَّ عَلَيْهِمَا جَلَسَتْ إِحْدَاهُمَا إِلَى الْأُخْرَى فَجَعَلَتَا يَأْكُلَانِ لُحُومَ النَّاسِ","id":"Telah bercerita kepada kami [Yazid] telah mengkhabarkan kepada kami [Sulaiman] dan [Ibnu Abi 'Adi] dari Sulaiman secara makna dari [seseorang] yang bercerita kepada mereka dimajlis Abu 'Utsman An Nahdi, berkata Ibnu Abi 'Adi dari seorang guru di majlis Abu 'Utsman dari ['Ubaid] budak Rasulullah shallallahu 'alaihi wasallam bahwa ada dua wanita puasa dan seseorang berkata: Wahai Rasulullah! Sesungguhnya disini ada dua wanita yang puasa, keduanya hampir mati karena kehausan. Rasulullah shallallahu 'alaihi wasallam berpaling darinya atau diam. Orang itu mengulang dan memperlihatkan kepada beliau lalu berkata: Wahai nabi Allah! Sesungguhnya keduanya demi Allah telah mati atau hampir mati. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Panggil keduanya.\" Kedua wanita itu datang kemudian gelas besar didatangkan lalu beliau bersabda kepada salah satunya: \"Muntahlah.\" Wanita itu memuntahkan nanah atau darah, nanah bercampur darah dan daging hingga memenuhi separuh wadah besar. Setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda kepada yang satunya: \"Muntahlah.\" Wanita itu memuntahkan nanah, darah, campuran nanah dan darah, daging, luka dan lainnya hingga memenuhi wadah besar. Selanjutnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kedua wanita ini menahan diri dari yang dihalalkan Allah namun berbuka dengan yang diharamkan Allah 'azza wajalla pada keduanya, salah satu dari keduanya berteman dengan yang lain, keduanya kemudian memakan daging manusia.\""},"3525":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنِ التَّيْمِيِّ قَالَ طَرَأَ عَلَيْنَا رَجُلٌ فِي مَجْلِسِ أَبِي عُثْمَانَ النَّهْدِيِّ فَحَدَّثَنَا عَنْ عُبَيْدٍ مَوْلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَسُئِلَ عَنْ صَلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ صَلَاتَهُ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِحَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عُثْمَانُ بْنُ غِيَاثٍ قَالَ كُنْتُ مَعَ أَبِي عُثْمَانَ قَالَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ حَدَّثَنَا سَعْدٌ أَوْ عُبَيْدٌ عُثْمَانُ بْنُ غِيَاثٍ الَّذِي يَشُكُّ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ أُمِرُوا بِصِيَامٍ قَالَ فَجَاءَ رَجُلٌ بَعْضَ النَّهَارِ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ فُلَانًا وَفُلَانَةَ قَدْ بَلَغَهُمَا الْجَهْدُ فَذَكَرَ مَعْنَى حَدِيثِ يَزِيدَ وَابْنِ أَبِي عُبَيْدٍ عَنْ سُلَيْمَانَ","id":"Telah bercerita kepada kami [Sulaiman bin Dawud] telah bercerita kepada kami [Syu'bah] dari [At Taimi] berkata: [Seseorang] muncul mendatangi kami dimajlis Bani 'Utsman An Nahdi lalu kami bercerita dari ['Ubaid] budak nabi shallallahu 'alaihi wasallam ia ditanya tentang shalatnya nabi shallallahu 'alaihi wasallam lalu ia menyebutan shalat beliau antara maghrib dan 'isya`. Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami ['Utsman bin Ghiyats] berkata: Aku pernah bersama Abu 'Utsman berkata: Lalu [seseorang] diantara mereka berkata: Telah bercerita kepada kami [Sa'ad atau 'Ubaid], 'Utsman bin Ghiyats yang meragukan budak milik Rasulullah shallallahu 'alaihi wasallam bahwa mereka diperintahkan puasa. Lalu seseorang datang disebagaian waktu siang kemudian berkata: Wahai Rasulullah! Sesungguhnya si fulanah dan fulanah telah kepayahan. Lalu ia Sa'ad menyebutkan makna hadits Yazid dan Ibnu Abi 'Ubaid dari Sulaiman."},"3526":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنِ الزُّهْرِيِّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ ثَعْلَبَةَ بْنِ صُعَيْرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَ أُحُدٍ زَمِّلُوهُمْ فِي ثِيَابِهِمْ قَالَ وَجَعَلَ يَدْفِنُ فِي الْقَبْرِ الرَّهْطَ قَالَ وَقَالَ قَدِّمُوا أَكْثَرَهُمْ قُرْآنًا","id":"Telah bercerita kepada kami [Husyaim] dari [Muhammad bin Ishaq] dari [Az Zuhri] telah bercerita kepadaku ['Abdullah bin Tsa'labah bin Shu'air] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda saat perang Uhud: \"Selimutilah aku dengan baju-baju mereka.\" Berkata 'Abdullah: Beberapa orang dikubur dalam satu makam, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulukan yang paling banyak hafalan Al Qurannya diantara mereka.\""},"3527":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ بْنِ صُعَيْرٍ قَالَلَمَّا أَشْرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَتْلَى أُحُدٍ فَقَالَ أَشْهَدُ عَلَى هَؤُلَاءِ مَا مِنْ مَجْرُوحٍ جُرِحَ فِي اللَّهِ عَزَّ وَجَلَّ إِلَّا بَعَثَهُ اللَّهُ يَوْمَ الْقِيَامَةِ وَجُرْحُهُ يَدْمَى اللَّوْنُ لَوْنُ الدَّمِ وَالرِّيحُ رِيحُ الْمِسْكِ انْظُرُوا أَكْثَرَهُمْ جَمْعًا لِلْقُرْآنِ فَقَدِّمُوهُ أَمَامَهُمْ فِي الْقَبْرِ","id":"Telah bercerita kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dari ['Abdullah bin Tsa'labah bin Shu'air] berkata: Saat Rasulullah shallallahu 'alaihi wasallam melihat syuhada` Uhud, beliau bersabda: \"Aku bersaksi atas mereka, tidaklah ada orang yang terluka dijalan Allah 'azza wajalla melainkan Allah akan membangkitkannya pada hari kiamat dan lukanya berdarah, warnanya seperti darah tapi baunya seperti minyak kasturi, carilah yang paling banyak hafalan Al Qurannya diantaranya lalu dahulukanlah dihadapan mereka dalam kubur.\""},"3528":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ بْنِ أَبِي صُعَيْرٍ وَثَبَّتَنِيهِ مَعْمَرٌأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْرَفَ عَلَى قَتْلَى أُحُدٍ فَقَالَ إِنِّي أَشْهَدُ عَلَى هَؤُلَاءِ زَمِّلُوهُمْ بِكُلُومِهِمْ وَدِمَائِهِمْ","id":"Telah bercerita kepada kami [Sufyan] dari [Az Zuhri] dari ['Abdullah bin Tsa'labah bin Abu Shu'air] dan [Ma'mar] bahwa nabi shallallahu 'alaihi wasallam melihat para syuhada` Uhud kemudian beliau bersabda: \"Aku bersaksi atas mereka, bungkuslah mereka bersama luka dan darah mereka.\""},"3529":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنِ ابْنِ أَبِي صُعَيْرٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ أَشْرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الشُّهَدَاءِ الَّذِينَ قُتِلُوا يَوْمَئِذٍ فَقَالَ زَمِّلُوهُمْ بِدِمَائِهِمْ فَإِنِّي قَدْ شَهِدْتُ عَلَيْهِمْ فَكَانَ يُدْفَنُ الرَّجُلَانِ وَالثَّلَاثَةُ فِي الْقَبْرِ الْوَاحِدِ وَيُسْأَلُ أَيُّهُمْ كَانَ أَقْرَأَ لِلْقُرْآنِ فَيُقَدِّمُونَهُقَالَ جَابِرٌ فَدُفِنَ أَبِي وَعَمِّي يَوْمَئِذٍ فِي قَبْرٍ وَاحِدٍ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Abi Shu'air] dari [Jabir bin 'Abdullah] berkata: Saat perang Uhud, nabi shallallahu 'alaihi wasallam melihat para syuhada` yang terbunuh saat itu lalu beliau bersabda: \"Bungkuslah mereka bersama darah mereka karena sesunggunya aku bersaksi atas mereka.\" Dua atau tiga jenazah dikubur dalam satu makam dan ditanyakan siapa diantara mereka yang lebih banyak hafal Al Quran lalu mereka mendahulukannya. Berkata Jabir: Ayahku dan pamanku saat itu dikubur dalam satu makam."},"3530":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا مُحَمَّدٌ يَعْنِي ابْنَ إِسْحَاقَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ بْنِ صُعَيْرٍأَنَّ أَبَا جَهْلٍ قَالَ حِينَ الْتَقَى الْقَوْمُ اللَّهُمَّ أَقْطَعَنَا الرَّحِمَ وَآتَانَا بِمَا لَا نَعْرِفُهُ فَأَحْنِهِ الْغَدَاةَ فَكَانَ الْمُسْتَفْتِحَحَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي مُحَمَّدُ بْنُ مُسْلِمٍ الزُّهْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ بْنِ صُعَيْرٍ الْعُذْرِيِّ وَفِيمَا قَرَأَ عَلَى يَعْقُوبَ الْعُذْرِيِّ حَلِيفِ بَنِي زُهْرَةَ قَالَ أَشْرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَصْحَابِ أُحُدٍ فَذَكَرَ مَعْنَى حَدِيثِ يَزِيدَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُثْمَانَ حَدَّثَنَا رَجُلٌ فِي حَلْقَةِ أَبِي عُثْمَانَ قَالَ حَدَّثَنِي سَعْدٌ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ أُمِرُوا بِصِيَامِ يَوْمٍ فَجَاءَ رَجُلٌ بَعْضَ النَّهَارِ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ فُلَانَةَ وَفُلَانَةَ قَدْ بَلَغَهُمَا الْجَهْدُ فَأَعْرَضَ عَنْهُ فَذَكَرَ الْحَدِيثَ","id":"Telah bercerita kepada kami [Yazid] telah mengkhabarkan kepada kami [Muhammad bin Ishaq] telah bercerita kepadaku [Az Zuhri] dari ['Abdullah bin Tsa'labah bin Shu'air] bahwa Abu Jahal berkata saat mereka berhadapan: Ya Allah! Ia telah memutuskan kekerabatan kami, ia membawa sesuatu yang tidak kami ketahui, karena itu tundukkanlah ia esok. Dan dialah orang yang memulai. Telah bercerita kepada kami Ya'qub telah bercerita kepada kami ayahku dari Ibnu Ishaq telah bercerita kepadaku Muhammad bin Muslaim Az Zuhri dari Abdullah bin Tsa'labah bin Shu'air Al 'Udzri dan berdasarkan riwayat yang dibacakan dari Ya'qub Al 'Udzri, sekutu Bani Zuhrah berkata: Rasulullah shallallahu 'alaihi wasallam melihat jenazah-jenazah Uhud lalu ia menyebut makna hadits Yazid. Telah bercerita kepada kami Yahya bin Sa'id dari 'Utsman telah bercerita kepada kami seseorang dalam majlis Abu 'Utsman berkata: Telah bercerita kepadaku Sa'ad, budak Rasulullah shallallahu 'alaihi wasallam baha wmereka diperintahkan puasa sehari lalu seseorang mendatangi beliau disebagaian waktu siang, ia berkata: Wahai Rasulullah! Sesungguhnya fulanah dan fulanah telah keletihan. Rasulullah shallallahu 'alaihi wasallam berpaling darinya lalu ia Sa'ad menyebutkan hadits."},"3531":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ سَأَلْتُ حَمَّادَ بْنَ زَيْدٍ عَنْ صَدَقَةِ الْفِطْرِ فَحَدَّثَنِي عَنْ نُعْمَانَ بْنِ رَاشِدٍ عَنِ الزُّهْرِيِّ عَنِ ثَعْلَبَةَ بْنِ أَبِي صُعَيْرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَدُّوا صَاعًا مِنْ قَمْحٍ أَوْ صَاعًا مِنْ بُرٍّ وَشَكَّ حَمَّادٌ عَنْ كُلِّ اثْنَيْنِ صَغِيرٍ أَوْ كَبِيرٍ ذَكَرٍ أَوْ أُنْثَى حُرٍّ أَوْ مَمْلُوكٍ غَنِيٍّ أَوْ فَقِيرٍ أَمَّا غَنِيُّكُمْ فَيُزَكِّيهِ اللَّهُ وَأَمَّا فَقِيرُكُمْ فَيُرَدُّ عَلَيْهِ أَكْثَرُ مِمَّا يُعْطِي","id":"Telah bercerita kepada kami ['Affan] berkata: Aku bertanya kepada [Hammad bin Zaid] tentang zakat fitrah lalu ia bercerita kepadaku dari [Nu'aman bin Rasyid] dari [Az Zuhri] dari [Tsa'labah bin Abu Shu'air] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tunaikanlah satu sha' jelai atau satu sha' gandum lembut -Humaid ragu dari setiap keduanya, anak kecil atau orang besar, lelaki atau perempuan, orang merdeka atau budak, kaya atau miskin. Adapun orang kaya diantara kalian maka Allah akan membersihkannya sedangkan orang fakir diantara kalian maka dikembalikan baginya yang lebih banyak dari yang ia berikan.\""},"3532":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ قَالَ قَرَأَهُ عَلَيَّ يُونُسُ عَنِ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ ثَعْلَبَةَوَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ وَجْهَهُ أَنَّهُ رَأَى سَعْدَ بْنَ أَبِي وَقَّاصٍ يُوتِرُ بِرَكْعَةٍ وَاحِدَةٍ لَا يَزِيدُ عَلَيْهَا حَتَّى يَقُومَ مِنْ جَوْفِ اللَّيْلِ","id":"Telah bercerita kepada kami ['Abdullah bin Al Harits] berkata: [Yunus] meriwayatkan kepadaku dengan membaca dari [Ibnu Syihab] berkata: Telah mengkhabarkan kepadaku ['Abdullah bin Tsa'labah] dan Rasulullah shallallahu 'alaihi wasallam pernah mengusap wajahnya bahwa ia melihat Sa'ad bin Abu Waqqash shalat witir satu rakaat, tidak lebih dari itu hingga ia bangun ditengah malam."},"3533":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ ثَعْلَبَةَ بْنِ صُعَيْرٍ الْعُذْرِيُّ قَالَوَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ مَسَحَ وَجْهَهُ زَمَنَ الْفَتْحِ أَنَّهُ رَأَى سَعْدَ بْنَ أَبِي وَقَّاصٍ كَانَ سَعْدٌ قَدْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِرَكْعَةٍ وَاحِدَةٍ بَعْدَ صَلَاةِ الْعِشَاءِ يَعْنِي الْعَتَمَةَ لَا يَزِيدُ عَلَيْهَا حَتَّى يَقُومَ مِنْ جَوْفِ اللَّيْلِ","id":"Telah bercerita kepada kami [Abu Al Yaman] telah bercerita kepada kami [Syu'aib] dari [Az Zuhri] telah bercerita kepadaku ['Abdullah bin Tsa'labah bin Shu'air Al 'Udzri] berkata dan Rasulullah shallallahu 'alaihi wasallam pernah mengusap wajahnya saat penaklukkan Makkah, bahwa ia melihat Sa'ad bin Abi Waqqash, ia turut serta dalam perang Badar bersama Rasulullah shallallahu 'alaihi wasallam shalat witir satu rakaat bersama Rasulullah shallallahu 'alaihi wasallam setelah shalat 'isya`, ia tidak menambahinya hingga ia bangun ditengah malam."},"3534":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ الْقَسَامَةِ فِي الدَّمِ قَالَكَانَتْ الْقَسَامَةُ فِي الْجَاهِلِيَّةِ عَنْ حَدِيثِ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَسُلَيْمَانَ بْنِ يَسَارٍ عَنْ رِجَالٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَنْصَارِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَرَّهَا عَلَى مَا كَانَتْ عَلَيْهِ فِي الْجَاهِلِيَّةِ وَقَضَى بِهَا بَيْنَ نَاسٍ مِنْ الْأَنْصَارِ فِي قَتِيلٍ ادَّعَوْهُ عَلَى الْيَهُودِ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Juraij] telah bercerita kepadaku [Ibnu Syihab] tentang penanggungan diyat pembunuhan, ia berkata: Qasamah ada dimasa jahiliyah dari hadits [Abu Salamah bin 'Abdur Rahman] dan [Sulaiman bin Yasar] dari [beberapa sahabat] nabi shallallahu 'alaihi wasallam dari Anshar bahwa Rasulullah shallallahu 'alaihi wasallam mengakuinya seperti yang ada dimasa jahiliyah dan memutuskannya diantara beberapa orang dari Anshar tentang korban pembunuhan yang dituduhkan pada orang-orang yahudi."},"3535":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ سَعْدٍ حَدَّثَنِي عُقَيْلٌ عَنِ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ بْنِ صُعَيْرٍ الْعُذْرِيِّوَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ مَسَحَ عَلَى وَجْهِهِ وَأَدْرَكَ أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانُوا يَنْهَوْنِي عَنْ الْقُبْلَةِ تَخَوُّفًا أَنْ أَتَقَرَّبَ لِأَكْثَرَ مِنْهَا ثُمَّ الْمُسْلِمُونَ الْيَوْمَ يَنْهَوْنَ عَنْهَا وَيَقُولُ قَائِلُهُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَهُ مِنْ حِفْظِ اللَّهِ مَا لَيْسَ لِأَحَدٍ","id":"Telah bercerita kepada kami [Hajjaj] telah bercerita kepada kami [Laits bin Sa'ad] telah bercerita kepadaku ['Uqail] dari [Ibnu Syihab] dari ['Abdullah bin Tsa'labah bin Shu'air Al 'Udzri] dan Rasulullah shallallahu 'alaihi wasallam pernah membasuh mukanya dan pernah berjumpa Rasulullah shallallahu 'alaihi wasallam berkata: Mereka melarangku mencium karena khawatir aku mendekat lebih dari itu kemudian kaum muslimin saat ini dilarang untuk itu. Diantara mereka berkata bahwa Rasulullah shallallahu 'alaihi wasallam memiliki penjagaan Allah yang tidak dimiliki oleh siapa pun."},"3536":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَدِيِّ بْنِ الْخِيَارِ أَنَّ رَجُلًا مِنَ الْأَنْصَارِ حَدَّثَهُأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي مَجْلِسٍ فَسَارَّهُ يَسْتَأْذِنُهُ فِي قَتْلِ رَجُلٍ مِنْ الْمُنَافِقِينَ فَجَهَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَيْسَ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ الْأَنْصَارِيُّ بَلَى يَا رَسُولَ اللَّهِ وَلَا شَهَادَةَ لَهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَيْسَ يَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ قَالَ بَلَى يَا رَسُولَ اللَّهِ وَلَا شَهَادَةَ لَهُ أَلَيْسَ يُصَلِّي قَالَ بَلَى يَا رَسُولَ اللَّهِ وَلَا صَلَاةَ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُولَئِكَ الَّذِينَ نَهَانِي اللَّهُ عَنْهُمْحَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَدِيِّ بْنِ الْخِيَارِ عَنْ عَبْدِ اللَّهِ بْنِ عَدِيٍّ الْأَنْصَارِيِّ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا هُوَ جَالِسٌ إِذْ جَاءَهُ رَجُلٌ يَعْنِي يَسْتَأْذِنُهُ أَيْ يُسَارُّهُ فَذَكَرَ مَعْنَاهُ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah mengkhabarkan kepada kami [Ibnu Juraij] telah mengkhabarkan kepadaku [Ibnu Syihab] dari ['Atha` bin Yazid Al Laitsi] dari ['Ubaidullah bin 'Adi bin Al Khiyar] bahwa [seorang Anshar] bercerita kepadanya, ia pernah mendatangi Rasulullah shallallahu 'alaihi wasallam saat berada dimajlis, ia membisiki Rasulullah shallallahu 'alaihi wasallam seraya meminta izin untuk membunuh seorang munafik lalu Rasulullah shallallahu 'alaihi wasallam mengeraskan surara kemudian bersabda: \"Bukankah ia bersaksi bahwa tidak ada ilah (yang haq) kecuali Allah?\" orang Anshar itu menjawab: Betul wahai Rasulullah tapi ia tidak memiliki kesaksian. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukankah ia bersaksi bahwa Muhammad utusan Allah? orang Anshar itu menjawab: Betul wahai Rasulullah tapi ia tidak memiliki kesaksian. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukankah ia shalat?\" orang Anshar itu menjawab: Betul wahai Rasulullah tapi ia tidak memiliki shalat. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mereka itulah yang aku dilarang Allah untuk (menyerang) mereka.\" Telah bercerita kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Ma'mar] dari [Az Zuhri] dari ['Atho` bin Yazid Al Laitsi] dari ['Ubaidullah bin 'Adi bin Al Khiyar] dari ['Abdullah bin 'Adi Al Anshari] ia bercerita padanya bahwa saat Rasulullah shallallahu 'alaihi wasallam duduk, tiba-tiba seseorang mendatangi beliau meminta izin dengan berbicara lirih pada beliau. Ia menyebutkan makna hadits."},"3537":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ قَالَ قَالَ الزُّهْرِيُّ وَأَخْبَرَنِي عُمَرُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ أَنَّهُ أَخْبَرَهُ بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَئِذٍ لِلنَّاسِ وَهُوَ يُحَذِّرُهُمْ فِتْنَةَ الدَّجَّالِ تَعْلَمُونَ أَنَّهُ لَنْ يَرَى أَحَدٌ مِنْكُمْ رَبَّهُ عَزَّ وَجَلَّ حَتَّى يَمُوتَ وَإِنَّهُ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ كَافِرٌ يَقْرَؤُهُ مَنْ كَرِهَ عَمَلَهُ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah mengkhabarkan kepada kami [Ma'mar] berkata [Az Zuhri] dan telah mengkhabarkan kepadaku ['Umar bin Tsabit Al Anshari] bahwa [seorang sahabat nabi shallallahu 'alaihi wasallam] memberitahunya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda saat itu kepada orang-orang, beliau mengingatkan mereka dari Dajjal: \"Kalian tahu bahwa tidaklah seorang diantara kalian melihat Rabbnya 'azza wajalla hingga mati dan sesungguhnya diantara kedua matanya tertulis KAFIR yang bisa dibaca oleh orang yang membenci perbuatannya.\""},"3538":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنِ ابْنِ الْمُسَيَّبِ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِجَدِّهِ جَدِّ سَعِيدٍ مَا اسْمُكَ قَالَ حَزْنٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلْ أَنْتَ سَهْلٌ فَقَالَ لَا أُغَيِّرُ اسْمًا سَمَّانِيهِ أَبِيقَالَ ابْنُ الْمُسَيَّبِ فَمَا زَالَتْ فِينَا حُزُونَةٌ بَعْدُ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Al Musayyib] dari [ayahnya] bahwa nabi shallallahu 'alaihi wasallam bersabda kepada kakeknya Sa'ad: \"Siapa namamu?\" ia menjawab: Hazan (sedih). Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tapi kau adalah Sahal (mudah).\" Ia berkata: Aku tidak akan merubah nama pemberian ayahku. Berkata Ibnu Al Musayyib: Kesedihan senantiasa ada pada kami."},"3539":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ فَقَالَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ بِهَا لَكَ عِنْدَ اللَّهِ عَزَّ وَجَلَّ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ قَالَ فَلَمْ يَزَالَا يُكَلِّمَانِهِ حَتَّى قَالَ آخِرَ شَيْءٍ كَلَّمَهُمْ بِهِ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ }قَالَ فَنَزَلَتْ فِيهِ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ }","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dari [ayahnya] berkata: Saat Abu Thalib sekarat, nabi shallallahu 'alaihi wasallam masuk dan didekatnya ada Abu Jahal dan 'Abdullah bin Abu Umaiyah, nabi shallallahu 'alaihi wasallam bersabda: \"Paman! Ucapkan: LAA ILAAHA ILLALLAAH sebuah kalimat yang akan aku jadikan bukti untukmu disisi Allah 'azza wajalla.\" Berkata Abu jahal dan 'Abdullah bin Abu Umaiyah: Hai Abu Thalib! Apa kau membenci agama 'Abdul Muththallib? Keduanya terus mengucapkannya hingga Abu Thalib mengucapkan sesuatu diakhir kata-katanya yang menunjukkan ia berada diatas agama 'Abdul Muththallib lalu nabi shallallahu 'alaihi wasallam bersabda: \"Aku akan memintakan ampunan untukmu selama aku tidak dilarang darimu.\" Kemudian turunlah ayat \"Tidak patut bagi nabi dan orang-orang yang beriman memintakan ampunan kepada orang-orang musyrik meski mereka memiliki kekerabatan setelah jelas bagi mereka bahwa mereka adalah para penghuni neraka jahim.\" (At-Taubah: 113) Berkata Al Musayyib: Berkenaan dengannya Abu Thalib turun ayat \"Sesungguhnya engkau tidaklah memberi petunjuk kepada orang yang kau cinta.\" (Al-Qashash: 56) "},"3540":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ طَارِقٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَكَانَ أَبِي مِمَّنْ بَايَعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحْتَ الشَّجَرَةِ بَيْعَةَ الرِّضْوَانِ فَقَالَ انْطَلَقْنَا فِي قَابِلٍ حَاجِّينَ فَعُمِّيَ عَلَيْنَا مَكَانُهَا فَإِنْ كَانَتْ بَيَّنَتْ لَكُمْ فَأَنْتُمْ أَعْلَمُ","id":"Telah bercerita kepada kami ['Affan] telah bercerita kepada kami [Abu 'Awanah] dari [Thariq] dari [Sa'id bin Al Musayyib] berkata: [Ayahku] adalah diantara orang yang berbaiat kepada nabi shallallahu 'alaihi wasallam dibawah pohon, baiatur ridlwan lalu berkata: Pada tahun berikutnya, kami pergi berhaji lalu tempatnya (tempat baiat, pent.) tidak kami ketahui, bila jelas bagi kalian maka kalian lebih tahu."},"3541":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ طَارِقٍ قَالَ ذُكِرَ عِنْدَ سَعِيدِ بْنِ الْمُسَيَّبِ الشَّجَرَةُ فَقَالَ حَدَّثَنِي أَبِيأَنَّهُ كَانَ ذَلِكَ الْعَامَ مَعَهُمْ فَنَسُوهَا مِنْ الْعَامِ الْمُقْبِلِ","id":"Telah bercerita kepada kami [Abu Ahmad] telah bercerita kepadaku [Sufyan] dari [Thariq] berkata: Pohon (tempat baiatur ridlwan, pent.) disebut didekat [Sa'id bin Al Musayyib] lalu berkata Sa'id: Telah bercerita kepadaku [ayahku] bahwa ia bersama mereka pada tahun itu lalu kami melupakannya (tempatnya, pent.) pada tahun berikutnya."},"3542":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ رَبِيعَةَ عَنْ حَارِثَةَ بْنِ النُّعْمَانِ قَالَمَرَرْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ جِبْرِيلُ عَلَيْهِ السَّلَام جَالِسٌ فِي الْمَقَاعِدِ فَسَلَّمْتُ عَلَيْهِ ثُمَّ أَجَزْتُ فَلَمَّا رَجَعْتُ وَانْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَلْ رَأَيْتَ الَّذِي كَانَ مَعِي قُلْتُ نَعَمْ قَالَ فَإِنَّهُ جِبْرِيلُ وَقَدْ رَدَّ عَلَيْكَ السَّلَامَ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] telah mengkhabarkan kepadaku ['Abdullah bin 'Amir bin Rabi'ah] dari [Haritsah bin An Nu'man] berkata: Aku melintasi Rasulullah shallallahu 'alaihi wasallam dan beliau bersama Jibril 'alaihis Salam yang tengah duduk ditempat duduk, aku mengucapkan salam pada beliau kemudian aku menyingkat, saat aku kembali dan nabi shallallahu 'alaihi wasallam hendak pulang, beliau bersabda: \"Apa kau lihat yang bersamaku tadi?\" Haritsah menjawab: Ya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dia adalah Jibril, ia menjawab salammu.\""},"3543":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الرِّجَالِ قَالَ سَمِعْتُ عُمَرَ مَوْلَى غُفْرَةَ يُحَدِّثُ عَنْ ثَعْلَبَةَ بْنِ أَبِي مَالِكٍ عَنْ حَارِثَةَ بْنِ النُّعْمَانِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَّخِذُ أَحَدُكُمْ السَّائِمَةَ فَيَشْهَدُ الصَّلَاةَ فِي جَمَاعَةٍ فَتَتَعَذَّرُ عَلَيْهِ سَائِمَتُهُ فَيَقُولُ لَوْ طَلَبْتُ لِسَائِمَتِي مَكَانًا هُوَ أَكْلَأُ مِنْ هَذَا فَيَتَحَوَّلُ وَلَا يَشْهَدُ إِلَّا الْجُمُعَةَ فَتَتَعَذَّرُ عَلَيْهِ سَائِمَتُهُ فَيَقُولُ لَوْ طَلَبْتُ لِسَائِمَتِي مَكَانًا هُوَ أَكْلَأُ مِنْ هَذَا فَيَتَحَوَّلُ فَلَا يَشْهَدُ الْجُمُعَةَ وَلَا الْجَمَاعَةَ فَيُطْبَعُ عَلَى قَلْبِهِ","id":"Telah bercerita kepada kami [Abu Sa'id] telah bercerita kepada kami ['Abdur Rahman bin Abu Ar Rijal] berkata: Aku mendengar ['Umar, budak Ghufrah] bercerita dari [Tsa'labah bin Abu Malik] dari [Haritsah bin An Nu'man] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Salah seorang diantara kalian memiliki binatang ternak lalu menghadiri shalat jamaah kemudian hewannya menahannya lalu ia berkata: Andai aku mencarikan suatu tempat untuk hewanku dan ia memakan dari tempat itu. Ia pun berubah dan tidak menghadiri shalat jamaah kecuali shalat jum'at lalu hewannya menahannya dan berkata: Andai aku mencarikan suatu tempat untuk hewanku dan ia memakan dari tempat itu. Ia pun berubah dan tidak menghadiri shalat jamaah dan tidak pula shalat jum'at lalu hatinya terkunci.\""},"3544":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ عَنْ أُمِّ الدَّرْدَاءِ عَنْ كَعْبِ بْنِ عَاصِمٍ الْأَشْعَرِيِّ وَكَانَ مِنْ أَصْحَابِ السَّقِيفَةِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ مِنْ امْبِرِّ امْصِيَامُ فِي امْسَفَرِ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Shafwan bin 'Abdullah] dari [Ummu Ad Darda`] dari [Ka'ab bin 'Ashim Al Asy'ari] -salah seorang pemilik bangsal- berkata: Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak termasuk kebaikan berpuasa saat bepergian.\""},"3545":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَابْنُ بَكْرٍ قَالَا حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ أَنَّ صَفْوَانَ بْنَ عَبْدِ اللَّهِ بْنِ صَفْوَانَ حَدَّثَهُ عَنْ أُمِّ الدَّرْدَاءِ عَنْ كَعْبِ بْنِ عَاصِمٍ الْأَشْعَرِيِّ قَالَ ابْنُ بَكْرِ ابْنِ عَاصِمٍإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah bercerita kepada kami ['Abdur Razzaq] dan [Ibnu Bakr] keduanya berkata: Telah bercerita kepada kami [Ibnu Juraij] berkata: Telah bercerita kepadaku [Ibnu Syihab] bahwa [Shafwan bin 'Abdullah bin Shafwan] bercerita kepadanya dari [Ummu Ad Darda`] dari [Ka'ab bin 'Ashim Al `Asy'ari] berkata [Ibnu Bakr bin 'Ashim] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak termasuk kebaikan berpuasa saat bepergian.\""},"3546":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ بْنِ صَفْوَانَ عَنْ أُمِّ الدَّرْدَاءِ عَنْ كَعْبِ بْنِ عَاصِمٍ الْأَشْعَرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah bercerita kepada kami [Sufyan] dari [Az Zuhri] dari [Shafwan bin 'Abdullah bin Shafwan] dari [Ummu Ad Darda`] dari [Ka'ab bin 'Ashim Al `Asy'ari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak termasuk kebaikan berpuasa saat bepergian.\""},"3547":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنَ الْأَنْصَارِ أَنَّ الْأَنْصَارِيَّ أَخْبَرَ عَطَاءًأَنَّهُ قَبَّلَ امْرَأَتَهُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ صَائِمٌ فَأَمَرَ امْرَأَتَهُ فَسَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَسُولَ اللَّهِ يَفْعَلُ ذَلِكَ فَأَخْبَرَتْهُ امْرَأَتُهُ فَقَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرَخَّصُ لَهُ فِي أَشْيَاءَ فَارْجِعِي إِلَيْهِ فَقُولِي لَهُ فَرَجَعَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ قَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرَخَّصُ لَهُ فِي أَشْيَاءَ فَقَالَ أَنَا أَتْقَاكُمْ لِلَّهِ وَأَعْلَمُكُمْ بِحُدُودِ اللَّهِ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah mengkhabarkan kepada kami [Ibnu Juraij] telah mengkhabarkan kepada kami [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [seorang Anshar] bahwa seorang Anshar memberi khabar kepada 'Atha' bahwa ia mencium istrinya dimasa Rasulullah shallallahu 'alaihi wasallam saat puasa lalu ia memerintahkan istrinya kemudian ia bertanya kepada nabi shallallahu 'alaihi wasallam tentang hal itu, nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melakukannya.\" Lalu istrinya memberitahunya kemudian ia berkata: Sesungguhnya nabi shallallahu 'alaihi wasallam diberi banyak keringanan pada beberapa hal, kembalilah pada beliau dan katakan pada beliau. Istrinya kembali lagi menemui nabi shallallahu 'alaihi wasallam lalu berkata: Sesungguhnya nabi shallallahu 'alaihi wasallam diberi keringanan pada beberapa hal. Lalu nabi shallallahu 'alaihi wasallam bersabda: \"Aku adalah yang paling bertakwa kepada Allah diantara kalian dan paling tahu batasan-batasan Allah diantara kalian.\""},"3548":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُجَاهِدٍ قَالَكَانَ جُنَادَةُ بْنُ أَبِي أُمَيَّةَ أَمِيرًا عَلَيْنَا فِي الْبَحْرِ سِتَّ سِنِينَ فَخَطَبَنَا ذَاتَ يَوْمٍ فَقَالَ دَخَلْنَا عَلَى رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقُلْنَا لَهُ حَدِّثْنَا بِمَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تُحَدِّثْنَا بِمَا سَمِعْتَ مِنْ النَّاسِ قَالُوا قَالَ فَشَدَّدُوا عَلَيْهِ فَقَالَ قَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أُنْذِرُكُمْ الْمَسِيحَ الدَّجَّالَ أُنْذِرُكُمْ الْمَسِيحَ الدَّجَّالَ وَهُوَ رَجُلٌ مَمْسُوحُ الْعَيْنِ قَالَ ابْنُ عَوْنٍ أَظُنُّهُ قَالَ الْيُسْرَى يَمْكُثُ فِي الْأَرْضِ أَرْبَعِينَ صَبَاحًا مَعَهُ جِبَالُ خُبْزٍ وَأَنْهَارُ مَاءٍ يَبْلُغُ سُلْطَانُهُ كُلَّ مَنْهَلٍ لَا يَأْتِي أَرْبَعَةَ مَسَاجِدَ فَذَكَرَ الْمَسْجِدَ الْحَرَامَ وَالْمَسْجِدَ الْأَقْصَى وَالطُّورَ وَالْمَدِينَةَ غَيْرَ أَنَّ مَا كَانَ مِنْ ذَلِكَ فَاعْلَمُوا أَنَّ اللَّهَ لَيْسَ بِأَعْوَرَ لَيْسَ اللَّهُ بِأَعْوَرَ لَيْسَ اللَّهُ بِأَعْوَرَ قَالَ ابْنُ عَوْنٍ وَأَظُنُّ فِي حَدِيثِهِ يُسَلَّطُ عَلَى رَجُلٍ مِنْ الْبَشَرِ فَيَقْتُلُهُ ثُمَّ يُحْيِيهِ وَلَا يُسَلَّطُ عَلَى غَيْرِهِ","id":"Telah bercerita kepada kami [Isma'il] telah bercerita kepada kami [Ibnu 'Aun] dari [Mujahid] berkata: [Junadah bin Abu Umaiah] memimpin kami dilaut selama enam bulan kemudian pada suatu hari ia berkhutbah, ia berkata: Kami berkunjung ke rumah [salah seorang sahabat nabi shallallahu 'alaihi wasallam], kami berkata padanya: Ceritakan pada kami yang kau dengar dari Rasulullah shallallahu 'alaihi wasallam, jangan kau ceritakan kepada kami yang kau dengar dari orang-orang. Mereka berkata: Ia menyusahkannya, kemudian ia berkata: Rasulullah shallallahu 'alaihi wasallam berdiri ditengah-tengah kami lalu bersabda: \"Aku ingatkan kalian pada Al Masih Dajjal, aku ingatkan kalian pada Al Masih Dajjal, dia adalah orang bermata satu -berkata 'Aun dalam riwayatnya: Aku kira beliau bersabda: Mata sebelah kiri- ia tinggal di bumi selama empat puluh hari, ia bersama dengan gunung roti dan sungai minuman, kekuasaannya mencapai ke mana-mana tapi tidak sampai ke empat masjid -beliau menyebut Masjidil Haram, Masjidil Aqsa, masjid Thur dan masjid Madinah- selain sebagaiannya, ketahuilah bahwa Allah tidak buta, Allah tidak buta, Allah tidak buta.\" Berkata Ibnu 'Aun dalam riwayatnya: Aku kira dalam haditsnya menyebutkan: Ia (Dajjal) menguasai seseorang lalu dibunuh kemudian dihidupan lagi tapi ia tidak bisa mengusai orang lain."},"3549":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ مُجَاهِدٍ عَنْ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ أَنَّهُ قَالَأَتَيْتُ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ حَدِّثْنِي حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الدَّجَّالِ وَلَا تُحَدِّثْنِي عَنْ غَيْرِكَ وَإِنْ كَانَ عِنْدَكَ مُصَدَّقًا فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَنْذَرْتُكُمْ فِتْنَةَ الدَّجَّالِ فَلَيْسَ مِنْ نَبِيٍّ إِلَّا أَنْذَرَهُ قَوْمَهُ أَوْ أُمَّتَهُ وَإِنَّهُ آدَمُ جَعْدٌ أَعْوَرُ عَيْنِهِ الْيُسْرَى وَإِنَّهُ يُمْطِرُ وَلَا يُنْبِتُ الشَّجَرَةَ وَإِنَّهُ يُسَلَّطُ عَلَى نَفْسٍ فَيَقْتُلُهَا ثُمَّ يُحْيِيهَا وَلَا يُسَلَّطُ عَلَى غَيْرِهَا وَإِنَّهُ مَعَهُ جَنَّةٌ وَنَارٌ وَنَهْرٌ وَمَاءٌ وَجَبَلُ خُبْزٍ وَإِنَّ جَنَّتَهُ نَارٌ وَنَارَهُ جَنَّةٌ وَإِنَّهُ يَلْبَثُ فِيكُمْ أَرْبَعِينَ صَبَاحًا يَرِدُ فِيهَا كُلَّ مَنْهَلٍ إِلَّا أَرْبَعَ مَسَاجِدَ مَسْجِدَ الْحَرَامِ وَمَسْجِدَ الْمَدِينَةِ وَالطُّورِ وَمَسْجِدَ الْأَقْصَى وَإِنْ شَكَلَ عَلَيْكُمْ أَوْ شُبِّهَ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَيْسَ بِأَعْوَرَ","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Sulaiman] dari [Mujahid] dari [Junadah bin Abu Umaiyah] ia berkata: Aku mendatangi [seorang sahabat nabi shallallahu 'alaihi wasallam] lalu aku berkata padanya: Ceritakan padaku suatu hadits yang kau dengar dari Rasulullah shallallahu 'alaihi wasallam tentang Dajjal, jangan kau ceritakan dari selain beliau meski menurutmu benar. Ia berkata: Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku ingatkan kalian akan fitnahnya Dajjal, tidaklah ada seorang nabi melainkan pasti mengingatkan kaumnya atau ummatnya, ia (Dajjal) adalah orang berambut ikal, buta mata kirinya, ia bisa menurunkan hujan tapi tidak bisa menumbuhkan tanaman, ia mengusai satu jiwa lalu ia membunuhnya kemudian dihidupkan kembali tapi ia tidak mengusai jiwa yang lain, bersamanya ada surga, neraka, sungai, air dan gunung roti, sesungguhnya surganya adalah neraka dan nerakanya adalah surga, sesungguhnya ia tinggal ditengah-tengah kalian selama empat puluh hari, semua sumber air mendatanginya kecuali empat masjid; Masjidil Haram, masjid Madinah, masjid Thur dan Masjidil Aqsa. Bila kalian sukar mengenali atau samar maka sesungguhnya Allah 'azza wajalla tidaklah buta sebelah mata.\""},"3550":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنِ الْأَعْمَشِ وَمَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ الْأَزْدِيِّ قَالَذَهَبْتُ أَنَا وَرَجُلٌ مِنْ الْأَنْصَارِ إِلَى رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا حَدِّثْنَا مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُذْكَرُ فِي الدَّجَّالِ وَلَا تُحَدِّثْنَا عَنْ غَيْرِهِ وَإِنْ كَانَ مُصَدَّقًا قَالَ خَطَبَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَنْذَرْتُكُمْ الدَّجَّالَ ثَلَاثًا فَإِنَّهُ لَمْ يَكُنْ نَبِيٌّ قَبْلِي إِلَّا قَدْ أَنْذَرَهُ أُمَّتَهُ وَإِنَّهُ فِيكُمْ أَيَّتُهَا الْأُمَّةُ وَإِنَّهُ جَعْدٌ آدَمُ مَمْسُوحُ الْعَيْنِ الْيُسْرَى مَعَهُ جَنَّةٌ وَنَارٌ فَنَارُهُ جَنَّةٌ وَجَنَّتُهُ نَارٌ وَمَعَهُ جَبَلٌ مِنْ خُبْزٍ وَنَهْرٌ مِنْ مَاءٍ وَإِنَّهُ يُمْطِرُ الْمَطَرَ وَلَا يُنْبِتُ الشَّجَرَ وَإِنَّهُ يُسَلَّطُ عَلَى نَفْسٍ فَيَقْتُلُهَا وَلَا يُسَلَّطُ عَلَى غَيْرِهَا وَإِنَّهُ يَمْكُثُ فِي الْأَرْضِ أَرْبَعِينَ صَبَاحًا يَبْلُغُ فِيهَا كُلَّ مَنْهَلٍ وَلَا يَقْرَبُ أَرْبَعَةَ مَسَاجِدَ مَسْجِدَ الْحَرَامِ وَمَسْجِدَ الْمَدِينَةِ وَمَسْجِدَ الطُّورِ وَمَسْجِدَ الْأَقْصَى وَمَا يُشَبَّهُ عَلَيْكُمْ فَإِنَّ رَبَّكُمْ لَيْسَ بِأَعْوَرَ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah mengkhabarkan kepada kami [Sufyan] dari [Al A'masy] dan [Manshur] dari [Mujahid] dari [Junadah bin Abu Umaiyah Al Azdi] berkata: Aku bersama seorang Anshar pergi menemui [seorang sahabat nabi shallallahu 'alaihi wasallam] lalu kami berkata: Ceritakan padaku yang kau dengar dari Rasulullah shallallahu 'alaihi wasallam tentang Dajjal, jangan kau ceritakan dari selain beliau meski benar. Ia berkata: Rasulullah shallallahu 'alaihi wasallam berkhutbah lalu beliau bersabda: \"Aku ingatkan kalian akan Dajjal, -beliau mengucapkannya sebanyak tiga kali- tidaklah ada seorang nabi sebelumku melainkan pasti mengingatkan ummatnya, ia (Dajjal) ditengah-tengah kalian wahai ummat da ia adalah orang berambut ikal, buta mata kirinya, ia bisa menurunkan hujan tapi tidak bisa menumbuhkan tanaman, ia mengusai satu jiwa lalu ia membunuhnya kemudian dihidupkan kembali tapi ia tidak mengusai jiwa yang lain, bersamanya ada surga, neraka, sungai, air dan gunung roti, sesungguhnya surganya adalah neraka dan nerakanya adalah surga, sesungguhnya ia tinggal ditengah-tengah kalian selama empat puluh hari, semua sumber air mendatanginya kecuali empat masjid; Masjidil Haram, masjid Madinah, masjid Thur dan Masjidil Aqsa. Bila kalian samar maka sesungguhnya Rabb kalian tidaklah buta sebelah mata.\""},"3551":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ أَخْبَرَنِي أَبِي قَالَكُنْتُ جَالِسًا إِلَى جَنْبِ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ فِي الْمَسْجِدِ فَمَرَّ شَيْخٌ جَمِيلٌ مِنْ بَنِي غِفَارٍ وَفِي أُذُنَيْهِ صَمَمٌ أَوْ قَالَ وَقْرٌ أَرْسَلَ إِلَيْهِ حُمَيْدٌ فَلَمَّا أَقْبَلَ قَالَ يَا ابْنَ أَخِي أَوْسِعْ لَهُ فِيمَا بَيْنِي وَبَيْنَكَ فَإِنَّهُ قَدْ صَحِبَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ حَتَّى جَلَسَ فِيمَا بَيْنِي وَبَيْنَهُ فَقَالَ لَهُ حُمَيْدٌ هَذَا الْحَدِيثُ الَّذِي حَدَّثْتَنِي عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الشَّيْخُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ يُنْشِئُ السَّحَابَ فَيَنْطِقُ أَحْسَنَ الْمَنْطِقِ وَيَضْحَكُ أَحْسَنَ الضَّحِكِ","id":"Telah bercerita kepada kami [Yazid] telah mengkhabarkan kepada kami [Ibrahim bin Sa'ad] telah mengkhabarkan kepadaku [ayahku] berkata: Aku duduk didekat Humaid bin 'Abdur Rahman di masjid lalu ada seorang tua rupawan dari Bani Ghifar lewat sementara telinganya tuli, Humaid mengutus seseorang menemuinya, saat ia datang ia berkata: Hai keponakanku! Luaskanlah jarak antaraku dan dia sesungguhnya ia adalah [sahabat nabi shallallahu 'alaihi wasallam]. Ia datang lalu duduk berhadapan kemudian Humaid berkata padanya: Hadits ini yang kau dengar dari Rasulullah shallallahu 'alaihi wasallam. Orang itu berkata: Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla membuat awan lalu berbicara dengan begitu baiknya dan tertawa dengan begitu indahnya.\""},"3552":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَبْدِ اللَّهِ بْنِ سَعْدٍ عَنِ الصُّنَابِحِيِّ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْغُلُوطَاتِقَالَ الْأَوْزَاعِّيُّ الْغُلُوطَاتِ شِدَادُ الْمَسَائِلِ وَصِعَابُهَا","id":"Telah bercerita kepada kami [Rauh] telah bercerita kepada kami [Al Auza'i] dari ['Abdullah bin Sa'ad] dari [Ash Shunabihi] dari [seorang sahabat nabi shallallahu 'alaihi wasallam] berkata: Rasulullah shallallahu 'alaihi wasallam melarang ghuluthat. Berkata Al Auza'i: Ghuluthat adalah masalah-masalah yang rumit dan sulit."},"3553":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَوْزَاعِىُّ عَنْ عَبْدِ اللَّهِ بْنِ سَعْدٍ عَنِ الصُّنَابِحِيِّ عَنْ مُعَاوِيَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الْغُلُوطَاتِ","id":"Telah bercerita kepada kami ['Ali bin Bahr] telah bercerita kepada kami ['Isa bin Yunus] telah bercerita kepada kami [Al Auza'i] dari ['Abdullah bin Sa'ad] dari [Ash Shunabihi] dari [Mu'awiyah] dari nabi shallallahu 'alaihi wasallam bahwa beliau melarang ghuluthat."},"3554":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا لَيْثٌ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي عُفَيْرٍ الْأَنْصَارِيِّ عَنْ مُحَمَّدِ بْنِ سَهْلِ بْنِ أَبِي حَثْمَةَ عَنْ مُحَيِّصَةَ بْنِ مَسْعُودٍ الْأَنْصَارِيِّ أَنَّهُكَانَ لَهُ غُلَامٌ حَجَّامٌ يُقَالُ لَهُ نَافِعٌ أَبُو طَيِّبَةَ فَانْطَلَقَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُهُ عَنْ خَرَاجِهِ فَقَالَ لَا تَقْرَبْهُ فَرَدَّهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اعْلِفْ بِهِ النَّاضِحَ وَاجْعَلْهُ فِي كِرْشِهِ","id":"Telah bercerita kepada kami [Hajjaj bin Muhammad] telah bercerita kepada kami [Laits] telah bercerita kepadaku [Yazid bin Abu Habib] dari [Abu 'Ufair Al Anshari] dari [Muhammad bin Sahal bin Abu Hatsmah] dari [Muhaiyyishah bin Mas'ud Al Anshari] bahwa ia memiliki budak tukang bekam bernama Nafi' Abu Thayyibah lalu ia pergi menemui Rasulullah shallallahu 'alaihi wasallam bertanya tentang pajaknya, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan kau dekati.\" Lalu ia menyerahkannya kepada Rasulullah shallallahu 'alaihi wasallam lalu beliau bersabda: \"Berikan makanan pada tukang penyiram air darinya dan tempatkan dibejananya.\""},"3555":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى أَخْبَرَنَا مَالِكٌ عَنِ الزُّهْرِيِّ عَنِ ابْنِ مُحَيِّصَةَ عَنْ أَبِيهِ أَنَّهُاسْتَأْذَنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِجَارَةِ الْحَجَّامِ فَنَهَاهُ عَنْهَا فَلَمْ يَسْأَلْهُ فِيهَا حَتَّى قَالَ لَهُ اعْلِفْهُ نَاضِحَكَ وَأَطْعِمْهُ رَقِيقَكَ","id":"Telah bercerita kepada kami [Ishaq bin 'Isa] telah mengkhabarkan kepada kami [Malik] dari [Az Zuhri] dari [Ibnu Muhaiyyishah] dari [ayahnya] bahwa ia meminta izin kepada Rasulullah shallallahu 'alaihi wasallam tentang upah bekam lalu beliau melarangnya, ia tidak lagi menanyakannya hingga Rasulullah shallallahu 'alaihi wasallam bersabda padanya: \"Berikan pada tukang penyiram airmu dan berilah budakmu makan darinya.\""},"3556":{"ar":"حَدَّثَنَا إِسْحَاقُ هُوَ ابْنُ عِيسَى حَدَّثَنَا مَالِكٌ عَنِ الزُّهْرِيِّ عَنْ حَرامِ بْنِ مُحَيِّصَةَأَنَّ نَاقَةً لِلْبَرَاءِ دَخَلَتْ حَائِطًا فَأَفْسَدَتْ فِيهِ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ عَلَى أَهْلِ الْحَوَائِطِ حِفْظَهَا بِالنَّهَارِ وَأَنَّ مَا أَفْسَدَتْ الْمَوَاشِي بِاللَّيْلِ ضَامِنٌ عَلَى أَهْلِهَا","id":"Telah bercerita kepada kami [Ishaq bin 'Isa] telah bercerita kepada kami [Malik] dari [Az Zuhri] dari [Hiram bin Muhaiyyishah] bahwa unta milik Barra` memasuki kebun dan merusaknya, lalu Rasulullah shallallahu 'alaihi wasallam memutuskan bahwa pemilik kebun harus menjaganya disiang dan yang dirusak oleh binatang ternak pada malam harinya ditanggung oleh pemiliknya."},"3557":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنِ الزُّهْرِيِّ عَنْ حَرَامِ بْنِ سَاعِدَةَ بْنِ مُحَيِّصَةَ بْنِ مَسْعُودٍ قَالَكَانَ لَهُ غُلَامٌ حَجَّامٌ يُقَالُ لَهُ أَبُو طَيِّبَةَ يَكْسِبُ كَسْبًا كَثِيرًا فَلَمَّا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْحَجَّامِ اسْتَرْخَصَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ فَأَبَى عَلَيْهِ فَلَمْ يَزَلْ يُكَلِّمُهُ فِيهِ وَيَذْكُرُ لَهُ الْحَاجَةَ حَتَّى قَالَ لَهُ لِتُلْقِ كَسْبَهُ فِي بَطْنِ نَاضِحِكَ","id":"Telah bercerita kepada kami [Yazid bin Harun] telah bercerita kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dari [Hiram bin Sa'idah bin Muhaiyyishah bin Mas'ud] berkata: Ia memiliki budak tukang bekam bernama Abu Thaibah ia mendapatkan banyak uang kemudian saat nabi shallallahu 'alaihi wasallam melarang mengambil keuntungan dari bekam, ia meminta keringanan kepada Rasulullah shallallahu 'alaihi wasallam tapi beliau tidak memberinya, ia terus berbicara kepada Rasulullah shallallahu 'alaihi wasallam menganai hal itu dan menyebutkan keperluannya hingga Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Buanglah hasilnya ke perut tukang penyiram airmu.\""},"3558":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ حَرَامِ بْنِ سَعْدِ بْنِ مُحَيِّصَةَ أَنَّ مُحَيِّصَةَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ حَجَّامٍ لَهُ فَنَهَاهُ عَنْهُ فَلَمْ يَزَلْ بِهِ يُكَلِّمُهُ حَتَّى قَالَ اعْلِفْهُ نَاضِحَكَ وَأَطْعِمْهُ رَقِيقَكَ","id":"Telah bercerita kepada kami [Sufyan] dari [Az Zuhri] dari [Hiram bin Sa'ad bin Muhaiyyishah] bahwa Muhaiyyishah bertanya kepada nabi shallallahu 'alaihi wasallam tentang hasil bekamnya lalu nabi shallallahu 'alaihi wasallam melarangnya, ia terus berbicara pada beliau hingga beliau bersabda: \"Berikan pada tukang penyiram airmu dan berilah budakmu makan darinya.\""},"3559":{"ar":"حَدَّثَنَا سُفْيَانُ قَالَ وَسَمِعَهُ الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَحَرَامِ بْنِ سَعْدِ بْنِ مُحَيِّصَةَأَنَّ نَاقَةً لِلْبَرَاءِ بْنِ عَازِبٍ دَخَلَتْ حَائِطَ قَوْمٍ فَأَفْسَدَتْ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحِفْظِ الْأَمْوَالِ عَلَى أَهْلِهَا بِالنَّهَارِ وَأَنَّ عَلَى أَهْلِ الْمَاشِيَةِ مَا أَصَابَتْ بِاللَّيْلِحَدَّثَنَا يَزِيدُ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنِ الزُّهْرِيِّ عَنْ حَرَامِ بْنِ سَاعِدَةَ بْنِ مُحَيِّصَةَ بْنِ مَسْعُودٍ عَنْ أَبِيهِ عَنْ جَدِّهِ مُحَيِّصَةَ بْنِ مَسْعُودٍ قَالَ كَانَ لَهُ غُلَامٌ حَجَّامٌ فَذَكَرَ الْحَدِيثَ","id":"Telah bercerita kepada kami [Sufyan] berkata, dan aku mendengarnya dari [Az Zuhri] dari [Sa'id ibn Al Musayyib] dan [Haram bin Sa'ad bin Muhaiyyishah] bahwa unta milik Barra` bin 'Azib memasuki kebun kaum lalu merusak kemudian Rasulullah shallallahu 'alaihi wasallam memutuskan penjagaan harta menjadi tanggungan pemiliknya pada siang hari sementara pemilik binatang ternak menanggung yang dirusak pada malam hari. Telah bercerita kepada kami Yazid telah mengkhabarkan kepada kami Muhammad bin Ishaq dari Az Zuhri dari Haram bin Sa'idah bin Muhaiyyishah bin Mas'ud dari ayahnya dari kakeknya, Muhaiyyishah bin Mas'ud berkata, ia memiliki budak tukang bekam lalu ia menyebut hadits."},"3560":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ حَرَامِ بْنِ مُحَيِّصَةَ عَنْ أَبِيهِ أَنَّهُسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْحَجَّامِ فَنَهَاهُ فَأَعَادَ عَلَيْهِ فَنَهَاهُ فَذَكَرَ مِنْ حَاجَتِهِ فَقَالَ اعْلِفْ نَاضِحَكَ وَأَطْعِمْهُ رَقِيقَكَ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Haram bin Muhaiyyishah] dari [ayahnya] dari kakeknya bahwa ia bertanya kepada nabi shallallahu 'alaihi wasallam tentang hasil bekam, nabi shallallahu 'alaihi wasallam melarangnya lalu ia mengulangnya, nabi shallallahu 'alaihi wasallam melarangnya lalu ia menyebutkan keperluannya kemudian nabi shallallahu 'alaihi wasallam bersabda: \"Berikan pada tukang penyiram airmu dan berilah budakmu makan darinya.\""},"3561":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ حَرَامِ بْنِ مُحَيِّصَةَ عَنْ أَبِيهِأَنَّ نَاقَةً لِلْبَرَاءِ بْنِ عَازِبٍ دَخَلَتْ حَائِطَ رَجُلٍ فَأَفْسَدَتْهُ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَهْلِ الْأَمْوَالِ حِفْظَهَا بِالنَّهَارِ وَعَلَى أَهْلِ الْمَوَاشِي حِفْظَهَا بِاللَّيْلِ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Ma'mar] dari [Az Zuhri] dari [Haram bin Muhaiyyishah] dari [ayahnya] bahwa unta milik Barra` bin 'Azib memasuki kebun seseorang lalu merusaknya lalu Rasulullah shallallahu 'alaihi wasallam memutuskan para pemilik harta harus menjaganya disiang hari sementara pemilik binatang ternak harus menjaganya dimalam hari."},"3562":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا ابْنُ أَبِي ذِئْبٍ عَنِ الزُّهْرِيِّ عَنْ حَرَامِ بْنِ مُحَيِّصَةَ عَنْ أَبِيهِ أَنَّهُسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْحَجَّامِ فَنَهَاهُ عَنْهُ فَذَكَرَ لَهُ الْحَاجَةَ فَقَالَ اعْلِفْهُ نَوَاضِحَكَ","id":"Telah bercerita kepada kami [Yazid] telah mengkhabarkan kepada kami [Ibnu Abi Dzi'b] dari [Az Zuhri] dari [Haram bin Muhaiyyishah] dari [ayahnya] bahwa ia bertanay kepada nabi shallallahu 'alaihi wasallam tentang hasil kerja bekam lalu nabi shallallahu 'alaihi wasallam melarangnya kemudian ia menyebutkan keperluannya lalu nabi shallallahu 'alaihi wasallam bersabda: \"Berikan pada para penyiram airmu.\""},"3563":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ أَيُّوبَأَنَّ رَجُلًا مِنْ الْأَنْصَارِ حَدَّثَهُ يُقَالُ لَهُ مُحَيِّصَةُ كَانَ لَهُ غُلَامٌ حَجَّامٌ فَزَجَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِهِ فَقَالَ أَفَلَا أُطْعِمُهُ يَتَامَى لِي قَالَ لَا قَالَ أَفَلَا أَتَصَدَّقُ بِهِ قَالَ لَا فَرَخَّصَ لَهُ أَنْ يَعْلِفَهُ نَاضِحَهُ","id":"Telah bercerita kepada kami ['Abdush Shamad] telah bercerita kepada kami [Hisyam] dari [Yahya] dari [Muhammad bin Ayyub] bahwa seorang Anshar bernama [Muhaiyyishah] bercerita kepadanya, ia memiliki budak tukang bekam, Rasulullah shallallahu 'alaihi wasallam melarangnya untuk mendapat upah dari bekam lalu ia berkata: Bolehkah aku memberi makan anak-anak yatimku darinya? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak.\" Ia berkata: Bolehkah aku mensedekahkannya? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak.\" Lalu Rasulullah shallallahu 'alaihi wasallam memberinya keringanan untuk memberikannya kepada tukang penyiram air miliknya."},"3564":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ سَلَمَةَ بْنِ صَخْرٍ الْبَيَاضِيِّ قَالَكُنْتُ امْرَأً أُصِيبُ مِنْ النِّسَاءِ مَا لَا يُصِيبُ غَيْرِي قَالَ فَلَمَّا دَخَلَ شَهْرُ رَمَضَانَ خِفْتُ فَتَظَاهَرْتُ مِنْ امْرَأَتِي فِي الشَّهْرِ قَالَ فَبَيْنَمَا هِيَ تَخْدُمُنِي ذَاتَ لَيْلَةٍ إِذْ تَكَشَّفَ لِي مِنْهَا شَيْءٌ فَلَمْ أَلْبَثْ أَنْ وَقَعْتُ عَلَيْهَا فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ حَرِّرْ رَقَبَةً قَالَ قُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أَمْلِكُ رَقَبَةً غَيْرَ رَقَبَتِي قَالَ فَصُمْ شَهْرَيْنِ مُتَتَابِعَيْنِ فَقُلْتُ وَهَلْ أَصَابَنِي الَّذِي أَصَابَنِي إِلَّا مِنْ الصِّيَامِ قَالَ فَأَطْعِمْ سِتِّينَ مِسْكِينًا","id":"Telah bercerita kepada kami ['Abdullah bin Idris] dari [Muhammad bin Ishaq] dari [Muhammad bin 'Amru bin 'Atho`] dari [Sulaiman bin Yasar] dari [Salamah bin Shakhr Al Bayadli] berkata: Aku adalah orang yang terserang godaan wanita tidak seperti yang terkena pada orang lain. Saat masuk bulan ramadlan, aku khawatir lalu aku menzhihar istriku pada bulan itu. Saat ia melayaniku pada suatu malam, sedikit bagian tubuhnya tersingkap, tidak lama berselang aku pun menggaulinya kemudian aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan memberitahukan hal itu kepada beliau. Beliau bersabda: \"Merdekakan satu budak.\" Aku berkata: Demi Yang mengutusmu dengan kebenaran, aku tidak memiliki budak kecuali seorang budak milikku.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau begitu puasalah dua bulan berturut-turut.\" Aku berkata: Yang menimpaku itu tidak lain adalah karena puasa. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau begitu berilah makan enampuluh orang miskin.\""},"3565":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِفَاعَةَ بْنِ شَدَّادٍ قَالَكُنْتُ أَقُومُ عَلَى رَأْسِ الْمُخْتَارِ فَلَمَّا تَبَيَّنَتْ لِي كِذَابَتُهُ هَمَمْتُ أَيْمُ اللَّهِ أَنْ أَسُلَّ سَيْفِي فَأَضْرِبَ عُنُقَهُ حَتَّى تَذَكَّرْتُ حَدِيثًا حَدَّثَنِيهِ عَمْرُو بْنُ الْحَمِقِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ آمَنَ رَجُلًا عَلَى نَفْسِهِ فَقَتَلَهُ أُعْطِيَ لِوَاءَ الْغَدْرِ يَوْمَ الْقِيَامَةِ","id":"Telah bercerita kepada kami [Bahz] telah bercerita kepada kami [Hammad bin Salamah] dari ['Abdul Malik bin 'Umair] dari [Rifa'ah bin Syaddad] berkata: Aku pernah berdiri diatas kepala Al Mukhtar, saat jelas bagiku kedustaannya, demi Allah aku menghunus pedangku dan ingin menebas lehernya hingga aku teringat suatu hadits yang diceritakan ['Amru bin Al Hamaq] padaku, ia berkata: Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberi jaminan aman atas keselamatan dirinya lalu membunuhnya maka ia akan diberi bendera pengkhianatan pada hari kiamat.\""},"3566":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا عِيسَى الْقَارِئُ أَبُو عُمَرَ حَدَّثَنِي السَّدِيُّ عَنْ رِفَاعَةَ الْقِتْبَانِيِّ قَالَدَخَلْتُ عَلَى الْمُخْتَارِ قَالَ فَأَلْقَى لِي وِسَادَةً وَقَالَ لَوْلَا أَنَّ أَخِي جِبْرِيلَ قَامَ عَنْ هَذِهِ لَأَلْقَيْتُهَا لَكَ قَالَ فَأَرَدْتُ أَنْ أَضْرِبَ عُنُقَهُ فَذَكَرْتُ حَدِيثًا حَدَّثَنِي بِهِ أَخِي عَمْرُو بْنُ الْحَمِقِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا مُؤْمَنٍ أَمَّنَ مُؤْمِنًا عَلَى دَمِهِ فَقَتَلَهُ فَأَنَا مِنْ الْقَاتِلِ بَرِيءٌ","id":"Telah bercerita kepada kami [Ibnu Numair] telah bercerita kepada kami ['Isa Al Qari` Abu 'Umar] telah bercerita kepadaku [As Sudi] dari [Rifa'ah Al Qitbani] berkata: Aku memasuki kediaman Al Mukhtar lalu ia memberiku bantal dan berkata: Andai saja saudaraku, Jibril, berdiri meninggalkannya niscaya aku akan membuangnya untukmu. Aku berkeinginan untuk menebas lehernya lalu aku teringat suatu hadits yang diceritakan oleh saudaraku [('Amru bin Al Hamaq)] ia berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa pun orang mu`min yang memberi jaminan keamanan atas nyawa orang mu`min lain lalu ia membunuhnya maka aku terbebas dari pembunuh itu.\""},"3567":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ سَلْمَانَ قَالَقَالَ بَعْضُ الْمُشْرِكِينَ وَهُمْ يَسْتَهْزِئُونَ بِهِ إِنِّي لَأَرَى صَاحِبَكُمْ يُعَلِّمُكُمْ حَتَّى الْخِرَاءَةِ قَالَ سَلْمَانُ أَجَلْ أَمَرَنَا أَنْ لَا نَسْتَقْبِلَ الْقِبْلَةَ وَلَا نَسْتَنْجِيَ بِأَيْمَانِنَا وَلَا نَكْتَفِيَ بِدُونِ ثَلَاثَةِ أَحْجَارٍ لَيْسَ فِيهَا رَجِيعٌ وَلَا عَظْمٌ","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Al A'masy] dari [Ibrahim] dari ['Abdur Rahman bin Yazid] dari [Salman] berkata: Sebagaian orang-orang musyrik berkata seraya mengolok-oloknya: Sesungguhnya aku mengetahui teman kalian mengajarkan cara buang air besar pada kalian. Berkata Salman: Benar, beliau memerintahkan kami agar tidak menghadap ke kiblat, tidak beristinja` dengan tangan kanan dan tidak cukup dengan kurang dari tiga batu yang bukan kotoran dan tulang."},"3568":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ حَدَّثَنَا رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَ��َلَّمَ قَالَقَالَ رَجُلٌ إِنِّي لَأَرَى صَاحِبَكُمْ يُعَلِّمُكُمْ كَيْفَ تَصْنَعُونَ حَتَّى إِنَّهُ لَيُعَلِّمُكُمْ إِذَا أَتَى أَحَدُكُمْ الْغَائِطَ قَالَ قُلْتُ نَعَمْ أَجَلْ وَلَوْ سَخِرْتَ إِنَّهُ لَيُعَلِّمُنَا كَيْفَ يَأْتِي أَحَدُنَا الْغَائِطَ وَإِنَّهُ يَنْهَانَا أَنْ يَسْتَقْبِلَ أَحَدُنَا الْقِبْلَةَ وَأَنْ يَسْتَدْبِرَهَا وَأَنْ يَسْتَنْجِيَ أَحَدُنَا بِيَمِينِهِ وَأَنْ يَتَمَسَّحَ أَحَدُنَا بِرَجِيعٍ وَلَا عَظْمٍ وَأَنْ يَسْتَنْجِيَ بِأَقَلَّ مِنْ ثَلَاثَةِ أَحْجَارٍ","id":"Telah bercerita kepada kami [Abu Sa'id] telah bercerita kepada kami [Za`idah] telah bercerita kepada kami [Manshur] dari [Ibrahim] dari ['Abdur Rahman bin Yazid] telah bercerita kepada kami [seorang sahabat nabi shallallahu 'alaihi wasallam] berkata: Seseorang berkata: Sesungguhnya aku tahu teman kalian mengajarkan bagaimana kalian bekerja hignga ia mengajar bila salah seorang diantara kalian pergi ke WC. Aku menjawab: Ya, benar meski kau menghina, sesungguhnya beliau mengajaran kami bagaimana cara kami pergi ke WC, beliau melarang salah seorang dari kami menghadap kiblat dan membelakanginya, melarang salah seorang dari kami beristinja` dengan tangan kanan, tidak mengusap menggunakan kotoran dan tulang dan tidak beristinja` dengan kurang dari tiga batu."},"3569":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا زَائِدَةُ حَدَّثَنَا عُمَرُ بْنُ قَيْسٍ الْمَاصِرُ عَنْ عَمْرِو بْنِ أَبِي قُرَّةَ قَالَ كَانَ حُذَيْفَةُ بِالْمَدَائِنِ فَكَانَ يَذْكُرُ أَشْيَاءَ قَالَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ حُذَيْفَةُ إِلَى سَلْمَانَ فَيَقُولُ سَلْمَانُ يَا حُذَيْفَةُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْضَبُ فَيَقُولُ وَيَرْضَى وَيَقُولُ لَقَدْ عَلِمْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ فَقَالَ أَيُّمَا رَجُلٍ مِنْ أُمَّتِي سَبَبْتُهُ سَبَّةً فِي غَضَبِي أَوْ لَعَنْتُهُ لَعْنَةً فَإِنَّمَا أَنَا مِنْ وَلَدِ آدَمَ أَغْضَبُ كَمَا يَغْضَبُونَ وَإِنَّمَا بَعَثَنِي رَحْمَةً لِلْعَالَمِينَ فَاجْعَلْهَا صَلَاةً عَلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah bercerita kepada kami [Mu'awiyah bin 'Amru] telah bercerita kepada kami [Za`idah] telah bercerita kepada kami ['Umar bin Qais Al Mashir] dari ['Amru bin Abu Qurrah] berkata: Hudzaifah berada di Mada`in, ia menyebut banyak hal yang disampaikan Rasulullah shallallahu 'alaihi wasallam kemudian Hudzaifah mendatangi Salman lalu [Salman] berkata: Hai Hudzaifah! Sesungguhnya Rasulullah shallallahu 'alaihi wasallam itu kadang marah lalu bersabda, kadang senang lalu bersabda, aku tahu bahwa Rasulullah shallallahu 'alaihi wasallam berkhutbah lalu bersabda: \"Siapa saja dari ummatku yang aku cela saat aku marah atau aku laknat, sesungguhnya aku hanyalah manusia biasa, aku marah seperti halnya kalian marah, sesungguhnya aku diutus sebagai rahmat untuk seluruh alam maka jadikanlah itu sebagai doa baginya pada hari kiamat.\""},"3570":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَبِي عُثْمَانَ قَالَكُنْتُ مَعَ سَلْمَانَ الْفَارِسِيِّ تَحْتَ شَجَرَةٍ وَأَخَذَ مِنْهَا غُصْنًا يَابِسًا فَهَزَّهُ حَتَّى تَحَاتَّ وَرَقُهُ ثُمَّ قَالَ يَا أَبَا عُثْمَانَ أَلَا تَسْأَلُنِي لِمَ أَفْعَلُ هَذَا قُلْتُ وَلِمَ تَفْعَلُهُ فَقَالَ هَكَذَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ تَحْتَ شَجَرَةٍ فَأَخَذَ مِنْهَا غُصْنًا يَابِسًا فَهَزَّهُ حَتَّى تَحَاتَّ وَرَقُهُ فَقَالَ يَا سَلْمَانُ أَلَا تَسْأَلُنِي لِمَ أَفْعَلُ هَذَا فَقُلْتُ وَلِمَ تَفْعَلُهُ قَالَ إِنَّ الْمُسْلِمَ إِذَا تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ صَلَّى الصَّلَوَاتِ الْخَمْسَ تَحَاتَّتْ خَطَايَاهُ كَمَا يَتَحَاتُّ هَذَا الْوَرَقُ وَقَالَ{ وَأَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ إِنَّ الْحَسَنَاتِ يُذْهِبْنَ السَّيِّئَاتِ ذَلِكَ ذِكْرَى لِلذَّاكِرِينَ }","id":"Telah bercerita kepada kami ['Affan] telah bercerita kepada kami [Hammad bin Salamah] telah mengkhabarkan kepada kami ['Ali bin Zaid] dari [Abu 'Utsman] berkata: Aku bersama [Salman Al Farisi] berada dibawah pohon dan ia memetik ranting kering, ia menggerakkannya hingga dedauannya rontok lalu berkata: Hai Abu 'Utsman! Apa kau tidak bertanya kenapa aku melakukan ini dan kenapa kau tidak melakukannya? Lalu Salman berkata: Seperti itulah yang dilakukan Rasulullah shallallahu 'alaihi wasallam saat aku bersama beliau berada dibawah sebuah pohon, beliau memetika ranting kering dan menggerakkannya hingga dedaunannya rontok lalu bersabda: \"Hai Salman! Apa kau tidak bertanya kenapa aku melakukan ini dan kenapa kau tidak melakukannya?\" Lalu beliau bersabda: \"Sesungguhnya orang muslim bila berwudlu dan memperbaiki wudlunya lalu shalat lima waktu maka kesalahan-kesalahannya berguguran seperti rontoknya dedaunan ini.\" Beliau bersabda: \"Tegakkanlah shalat didua penghujung siang dan sebagian dari malam, sesungguhnya kebaikan-kebaikan itu menghilangkan keburukan-keburukan, itu adalah peringatan bagi orang-orang yang ingat.\""},"3571":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ قَالَ أَخْبَرَنِي أَبِي عَنْ عَبْدِ اللَّهِ بْنِ وَدِيعَةَ عَنْ سَلْمَانَ الْخَيْرِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَغْتَسِلُ رَجُلٌ يَوْمَ الْجُمُعَةِ وَيَتَطَهَّرُ بِمَا اسْتَطَاعَ مِنْ طُهْرٍ وَيَدَّهِنُ مِنْ دُهْنِهِ أَوْ يَمَسُّ مِنْ طِيبِ بَيْتِهِ ثُمَّ يَرُوحُ إِلَى الْمَسْجِدِ فَلَا يُفَرِّقُ بَيْنَ اثْنَيْنِ ثُمَّ يُصَلِّي مَا كَتَبَ اللَّهُ لَهُ ثُمَّ يُنْصِتُ لِلْإِمَامِ إِذَا تَكَلَّمَ إِلَّا غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ الْأُخْرَى","id":"Telah bercerita kepada kami [Hajaj bin Muhammad] telah bercerita kepada kami [Ibnu Abi Dzi'b] dari [Sa'id Al Maqburi] berkata: telah mengkhabarkan kepadaku [ayahku] dari ['Abdullah bin Wadi'ah] dari [Salman Al Khair] dari nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Tidaklah seseorang mandi pada hari jum'at, bersuci semampunya, mengenakan minyak rambut atau mengenakan wewangian dari rumahnya kemudian pergi ke masjid kemudian tidak menyela di antara dua orang lalu shalat lalu diam untuk mendengarkan imam melainkan dosanya di antara dia dan jum'at lainnya diampuni.\""},"3572":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ مَنْصُورٍ عَنِ الْحَسَنِ قَالَلَمَّا احْتُضِرَ سَلْمَانُ بَكَى وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيْنَا عَهْدًا فَتَرَكْنَا مَا عَهِدَ إِلَيْنَا أَنْ يَكُونَ بُلْغَةُ أَحَدِنَا مِنْ الدُّنْيَا كَزَادِ الرَّاكِبِ قَالَ ثُمَّ نَظَرْنَا فِيمَا تَرَكَ فَإِذَا قِيمَةُ مَا تَرَكَ بِضْعَةٌ وَعِشْرُونَ دِرْهَمًا أَوْ بِضْعَةٌ وَثَلَاثُونَ دِرْهَمًا","id":"Telah bercerita kepada kami [Husyaim] dari [Manshur] dari [Al Hasan] berkata: Saat [Salman] sekarat, ia menangis dan berkata: Sesunggunya Rasulullah shallallahu 'alaihi wasallam memerintahkan sesuatu kepada kami lalu kami meninggalkan yang diperintahkan pada kami itu; hendaklah kehidupan duniawi salah seorang dari kami seperti perbekalan orang yang bepergian. Berkata Al Hasan: Kemudian kami melihat peninggalannya, dan nilai harta peninggaannya adalah duapuluh sekian dirham atau tigapuluh sekian dirham."},"3573":{"ar":"حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ سَلْمَانَ قَالَقَالَ الْمُشْرِكُونَ إِنَّ هَذَا لَيُعَلِّمُكُمْ حَتَّى إِنَّهُ لَيُعَلِّمُكُمْ الْخِرَاءَةَ قَالَ قُلْتُ لَئِنْ قُلْتُمْ ذَاكَ لَقَدْ نَهَانَا أَنْ نَسْتَقْبِلَ الْقِبْلَةَ أَوْ نَسْتَدْبِرَهَا أَوْ نَسْتَنْجِيَ بِأَيْمَانِنَا أَوْ يَكْتَفِيَ أَحَدُنَا بِدُونِ ثَلَاثَةِ أَحْجَارٍ أَوْ يَسْتَنْجِيَ أَحَدُنَا بِرَجِيعٍ أَوْ عَظْمٍ","id":"Telah bercerita kepada kami [Ibnu Fudlail] telah bercerita kepada kami [Al A'masy] dari [Ibrahim] dari ['Abdur Rahman bin Yazid] dari [Salman] berkata: Orang-orang musyrik berkata: Sesungguhnya orang itu mengajarkan kalian apa saja hingga ia mengajarkan kalian buang kotoran. Aku berkata: Bila kalian mengatakan seperti itu, beliau melarang kami menghadap kiblat atau membelakanginya, beristinja` dengan tangan kanan, beliau melarang salah seorang diantara kami hanya mencukupkan kurang dari tiga batu atau salah seorang diantara kami beristinja` dengan kotoran atau tulang."},"3574":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ سَلْمَانَ قَالَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَيَسْتَحِي أَنْ يَبْسُطَ الْعَبْدُ إِلَيْهِ يَدَيْهِ يَسْأَلُهُ خَيْرًا فَيَرُدَّهُمَا خَائِبَتَيْنِحَدَّثَنَا يَزِيدُ أَخْبَرَنَا رَجُلٌ فِي مَجْلِسِ عَمْرِو بْنِ عُبَيْدٍ أَنَّهُ سَمِعَ أَبَا عُثْمَانَ يُحَدِّثُ بِهَذَا عَنْ سَلْمَانَ الْفَارِسِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَزِيدُ سَمُّوهُ لِي قَالُوا هُوَ جَعْفَرُ بْنُ مَيْمُونٍ قَالَ عَبْد اللَّهِ قَالَ أَبِي يَعْنِي جَعْفَرَ صَاحِبَ الْأَنْمَاطِ","id":"Telah bercerita kepada kami [Yazid] telah mengkhabarkan kepada kami [Sulaiman At Taimi] dari [Abu 'Utsman] dari [Salman] berkata: Sesungguhnya Allah 'azza wajalla malu seorang hamba membentangan tangannya kepadaNya seraya meminta kebaikan lalu ditolak dengan sia-sia. Telah bercerita kepada kami [Yazid] telah mengkhabarkan kepada kami [seseorang] di majlis 'Amru bin 'Ubaid bahwa ia mendengar [Abu Utsman] menceritakannya dari [Salman Al Farisi] dari nabi shallallahu 'alaihi wasallam, berkata Yazid: Sebutkan namanya? Berkata 'Utsman: Dia adalah Ja'far bin Maimun berkata 'Abdullah berkata ayahku maksudnya Ja'far, pemilik permadani."},"3575":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ قَالَكُنَّا مَعَ سَلْمَانَ تَحْتَ شَجَرَةٍ فَأَخَذَ غُصْنًا مِنْهَا فَنَفَضَهُ فَتَسَاقَطَ وَرَقُهُ فَقَالَ أَلَا تَسْأَلُونِي عَمَّا صَنَعْتُ فَقُلْنَا أَخْبِرْنَا فَقَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ظِلِّ شَجَرَةٍ فَأَخَذَ غُصْنًا مِنْهَا فَنَفَضَهُ فَتَسَاقَطَ وَرَقُهُ فَقَالَ أَلَا تَسْأَلُونِي عَمَّا صَنَعْتُ فَقُلْنَا أَخْبِرْنَا يَا رَسُولَ اللَّهِ فَقَالَ إِنَّ الْعَبْدَ الْمُسْلِمَ إِذَا قَامَ إِلَى الصَّلَاةِ تَحَاتَّتْ عَنْهُ خَطَايَاهُ كَمَا تَحَاتَّ وَرَقُ هَذِهِ الشَّجَرَةِ","id":"Telah bercerita kepada kami [Yazid] telah mengkhabarkan kepada kami [Hammad bin Salamah] dari ['Ali bin Zaid] dari [Abu 'Utsman An Nahdi] berkata: Kami pernah bersama [Salman] di bawah pohon dan ia memetik ranting kering, ia menggerakkannya hingga dedauannya rontok lalu berkata: Hai Abu 'Utsman! Apa kau tidak bertanya kenapa aku melakukan ini? 'Utsman berkata: Berilah khabar kepada kami, lalu Salman berkata: Kami pernah bersama Rasulullah Shallalahu 'alaihi wa sallamdibawah naungan sebuah pohon, beliau memetik ranting dan menggerakkannya hingga dedaunannya rontok lalu bersabda: \"Hai Salman! Apa kau tidak bertanya kenapa aku melakukan ini?\" 'Utsman berkata: Berilah kami kabar wahai Rasulullah! beliau bersabda: \" Sesungguhnya orang muslim bila shalat lima waktu maka kesalahan-kesalahannya berguguran seperti rontoknya dedaunan ini.\""},"3576":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ مُغِيرَةَ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ قَرْثَعٍ الضَّبِّيِّ عَنْ سَلْمَانَ الْفَارِسِيِّ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَدْرِي مَا يَوْمُ الْجُمُعَةِ قُلْتُ هُوَ الْيَوْمُ الَّذِي جَمَعَ اللَّهُ فِيهِ أَبَاكُمْ قَالَ لَكِنِّي أَدْرِي مَا يَوْمُ الْجُمُعَةِ لَا يَتَطَهَّرُ الرَّجُلُ فَيُحْسِنُ طُهُورَهُ ثُمَّ يَأْتِي الْجُمُعَةَ فَيُنْصِتُ حَتَّى يَقْضِيَ الْإِمَامُ صَلَاتَهُ إِلَّا كَانَ كَفَّارَةً لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ الْمُقْبِلَةِ مَا اجْتُنِبَتْ الْمَقْتَلَةُ","id":"Telah bercerita kepada kami [Husyaim] dari [Al Mughirah] dari [Abu Ma'syar] dari [Ibrahim] dari ['Alqamah] dari [Qartsa' Adl Dlibbi] dari [Salman Al Farisi] berkata: Rasulullah Shallalahu 'alaihi wa sallambertanya kepadaku: \"Tahukah kamu apa itu hari jum'at?\" aku menjawab: Dialah hari dimana Allah mengumpulkan ayah Tuan dihari itu.\" Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Tapi aku tahu apa itu hari jum'at, tidaklah seseorang bersuci lalu memperbaikinya kemudian mendatangi shalat jum'at lalu diam hingga imam usai shalat melainkan menjadi penghapus baginya diantara ia dan jum'at selanjutnya selama hal yang membinasakan dijauhi.\""},"3577":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ سَلَمَةَ يَعْنِي ابْنَ كُهَيْلٍ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدٍ قَالَلَطَمْتُ مَوْلًى لَنَا فَقَالَ لَهُ أَبِي اقْتَصَّ ثُمَّ قَالَ كُنَّا مَعْشَرَ بَنِي مُقَرِّنٍ سَبْعَةً لَيْسَ لَنَا خَادِمٌ إِلَّا وَاحِدَةٌ فَلَطَمَهَا أَحَدُنَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتِقُوهَا فَقِيلَ لَهُ لَيْسَ لَهُمْ خَادِمٌ غَيْرُهَا قَالَ لِتَخْدُمَنَّهُمْ فَإِذَا اسْتَغْنَوْا عَنْهَا فَلْيُعْتِقُوهَا","id":"Telah bercerita kepada kami ['Abdur Rahman bin Mahdi] dari [Sufyan] dari [Salamah bin Kuhail] dari [Mu'awiyah bin Suwaid] berkata: Aku menampar salah seorang budak milik kami lalu [ayahku] berkata padanya: Balaslah. Lalu ia berkata: Kami adalah tujuh orang dari Bani Muqarrin, kami tidak memiliki seorang pelayan pun kecuali seorang wanita, salah seorang diantara kami menamparnya lalu nabi Shallalahu 'alaihi wa sallambersabda: \"Merdekakanlah dia.\" Dikatakan kepada beliau: Mereka tidak memiliki pelayan lain. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \" silahkan melayani mereka dan bila mereka sudah tidak lagi memerlukannya, hendaklah mereka memerdekakannya.\""},"3578":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ حُصَيْنٍ قَالَ سَمِعْتُ هِلَالَ بْنَ يِسَافٍ يُحَدِّثُ عَنْ سُوَيْدِ بْنِ مُقَرِّنٍ قَالَكُنَّا نَبِيعُ اللَّبَنَ فِي دَارِ سُوَيْدِ بْنِ مُقَرِّنٍ قَالَ فَخَرَجَتْ جَارِيَةٌ لِسُوَيْدٍ فَكَلَّمَتْ رَجُلًا مِنَّا فَسَبَّتْهُ فَلَطَمَ وَجْهَهَا فَقَالَ سُوَيْدٌ لَطَمْتَهَا لَقَدْ رَأَيْتُنِي وَإِنِّي لَسَابِعُ سَبْعَةٍ مِنْ إِخْوَتِي مَا لَنَا إِلَّا خَادِمٌ فَعَمَدَ أَحَدُنَا فَلَطَمَهَا فَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعِتْقِهَا","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Hushain] berkata: Aku mendengar [Hilal bin Yisaf] bercerita dari [Suwaid bin Muqarrin] berkata: Kami menjual susu di kediaman Suwaid bin Muqarrin lalu seorang budak wanita milik Suwaid keluar kemudian aku berbicara dengan seseorang dari golongan kami, budak wanita itu mencelanya lalu ia menampar wajah budak wanita itu kemudian Rasulullah Shallalahu 'alaihi wa sallam memerintakan kami agar memerdekakannya."},"3579":{"ar":"حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا حُصَيْنٌ عَنْ هِلَالِ بْنِ يِسَافٍأَنَّ رَجُلًا كَانَ نَازِلًا فِي دَارِ سُوَيْدِ بْنِ مُقَرِّنٍ قَالَ فَلَطَمَ خَادِمًا قَالَ فَغَضِبَ سُوَيْدٌ فَقَالَ أَمَا وَجَدْتَ إِلَّا حُرَّ وَجْهِهِ وَلَقَدْ رَأَيْتُنِي وَنَحْنُ سَابِعُ سَبْعَةٍ مِنْ وَلَدِ مُقَرِّنٍ وَمَا لَنَا خَادِمٌ إِلَّا وَاحِدٌ عَمَدَ إِلَيْهِ وَاحِدٌ فَلَطَمَهُ فَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَجَعْنَا أَنْ نُعْتِقَهُ فَأَعْتَقْنَاهُ","id":"Telah bercerita kepada kami [Husyaim] telah memberitakan kepada kami [Hushain] dari [Hilal bin Yisaf] bahwa seseorang bertamu dikediaman Suwaid bin Muqarrin lalu ia menampar seorang budak milkiknya, [Suwaid] marah lalu berkata: Tidaklah kau mendapatinya melainkan ia telah merdeka, dulu aku adalah anak ketujuh dari keturunan Muqarrin, kami hanya memiliki seorang pelayan, salah seorang diantara kami menghampirinya lalu menamparnya lalu Rasulullah Shallalahu 'alaihi wa sallam memerintahkan kami untuk memerdekakannya saat kami pulang lalu kami pun memerdekakannya."},"3580":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي حَمْزَةَ قَالَ سَمِعْتُ هِلَالًا رَجُلًا مِنْ بَنِي مَازِنٍ يُحَدِّثُ عَنْ سُوَيْدِ بْنِ مُقَرِّنٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَبِيذٍ فِي جَرَّةٍ فَسَأَلْتُهُ فَنَهَانِي عَنْهَا فَكَسَرْتُهَا","id":"Telah bercerita kepada kami [Rauh] telah bercerita kepada kami [Syu'bah] dari [Abu Hamzah] berkata: Aku mendengar [Hilal] -seorang dari Bani Mazin- bercerita dari [Suwaid bin Muqarrin] berkata: Aku mendatangi Rasulullah Shallalahu 'alaihi wa sallamdengan membawa anggur dalam periuk, aku menanyakannya lalu beliau melarangnya, aku pun memecahkannya."},"3581":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ وَبَهْزٌ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ قَالَ بَهْزٌ قَالَ أَنْبَأَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ عَلْقَمَةَ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ مَعْقِلِ بْنِ يَسَارٍأَنَّ عُمَرَ اسْتَعْمَلَ النُّعْمَانَ بْنَ مُقَرِّنٍ فَذَكَرَ الْحَدِيثَ قَالَ يَعْنِي النُّعْمَانَ وَلَكِنِّي شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ إِذَا لَمْ يُقَاتِلْ أَوَّلَ النَّهَارِ أَخَّرَ الْقِتَالَ حَتَّى تَزُولَ الشَّمْسُ وَتَهُبَّ الرِّيَاحُ وَيَنْزِلَ النَّصْرُ","id":"Telah bercerita kepada kami ['Abdur Rahman] dan [Bahz] keduanya berkata: telah bercerita kepada kami [Hammad bin Salamah] dari [Abu 'Imran Al Jauni] berkata: berkata Bahz: telah memberitakan kepada kami Abu 'Imran Al Jauni dari ['Alqamah bin 'Abdullah Al Muzanni] dari [Ma'qil bin Yasar] bahwa 'Umar menugaskan An Nu'man bin Muqarrin lalu ia menyebutkan hadits, berkata [An Nu'man]: Tapi aku turut serta berperang bersama Rasulullah shallallahu 'alaihi wasallam, bila beliau tidak berperang dipermulaan siang, beliau menunda perang hingga matahari condong, angin bertiup dan pertolongan datang."},"3582":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ أَنْبَأَنَا أَبُو بَكْرٍ عَنِ الْأَعْمَشِ عَنْ أَبِي خَالِدٍ الْوَالِبِيِّ عَنِ النُّعْمَانِ بْنِ مُقَرِّنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَبَّ رَجُلٌ رَجُلًا عِنْدَهُ قَالَ فَجَعَلَ الرَّجُلُ الْمَسْبُوبُ يَقُولُ عَلَيْكَ السَّلَامُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّ مَلَكًا بَيْنَكُمَا يَذُبُّ عَنْكَ كُلَّمَا يَشْتُمُكَ هَذَا قَالَ لَهُ بَلْ أَنْتَ وَأَنْتَ أَحَقُّ بِهِ وَإِذَا قَالَ لَهُ عَلَيْكَ السَّلَامُ قَالَ لَا بَلْ لَكَ أَنْتَ أَحَقُّ بِهِ","id":"Telah bercerita kepada kami [Aswad bin 'Amir] telah memberitakan kepada kami [Abu Bakar] dari [Al A'masy] dari [Abu Khalid Al Walibi] dari [An Nu'man bin Muqarrin] berkata: Rasulullah Shallalahu 'alaihi wa sallambersabda saat seseorang mencela orang lain didekat beliau, orang yang dicela berkata: 'ALAIKAS SALAAM: \"Ingatlah sesungguhnya satu malaikat diantara kalian berdua membelamu, setiap orang itu mencelamu, malaikat itu berkata: Justru kau lebih berhak atas hal itu. Dan saat ia mengucapkan padamu: 'ALAIKAS SALAAM, malaikat itu berkata: Justru kau lebih berhak atas hal itu.\""},"3583":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَرْبٌ يَعْنِي ابْنَ شَدَّادٍ حَدَّثَنَا حُصَيْنٌ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنِ النُّعْمَانِ بْنِ مُقَرِّنٍ قَالَقَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَرْبَعِ مِائَةٍ مِنْ مُزَيْنَةَ فَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَمْرِهِ فَقَالَ بَعْضُ الْقَوْمِ يَا رَسُولَ اللَّهِ مَا لَنَا طَعَامٌ نَتَزَوَّدُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعُمَرَ زَوِّدْهُمْ فَقَالَ مَا عِنْدِي إِلَّا فَاضِلَةٌ مِنْ تَمْرٍ وَمَا أُرَاهَا تُغْنِي عَنْهُمْ شَيْئًا فَقَالَ انْطَلِقْ فَزَوِّدْهُمْ فَانْطَلَقَ بِنَا إِلَى عُلِّيَّةٍ لَهُ فَإِذَا فِيهَا تَمْرٌ مِثْلُ الْبَكْرِ الْأَوْرَقِ فَقَالَ خُذُوا فَأَخَذَ الْقَوْمُ حَاجَتَهُمْ قَالَ وَكُنْتُ أَنَا فِي آخِرِ الْقَوْمِ قَالَ فَالْتَفَتُّ وَمَا أَفْقِدُ مَوْضِعَ تَمْرَةٍ وَقَدْ احْتَمَلَ مِنْهُ أَرْبَعُ مِائَةِ رَجُلٍ","id":"Telah bercerita kepada kami ['Abdush Shamad] telah bercerita kepada kami [Harb bin Syaddad] telah bercerita kepada kami [Hushain] dari [Salim bin Abu Al Ja'ad] dari [An Nu'man bin Muqarrin] berkata: Kami mendatangi Rasulullah Shallalahu 'alaihi wa sallambersama empat ratus orang dari Muzainah lalu Rasulullah Shallalahu 'alaihi wa sallammemerintahkan kami sesuatu, sebagaian kaum berkata: Wahai Rasulullah! kami tidak punya makanan untuk perbekalan. Lalu nabi Shallalahu 'alaihi wa sallambersabda kepada 'Umar: \"Berilah mereka perbekalan.\" Berkata 'Umar: Aku hanya memiliki sisa kurma dan menurutku itu tidak mencukupi mereka sama sekali. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Pergilah dan berilah mereka bekal.\" 'Umar pergi bersama kami menuju kamarnya ternyata didalamnya ada kurma seperti anak unta kelabu lalu berkata 'Umar: Ambillah. Mereka pun mengambil keperluan mereka dan aku Nu'man bin Muqarrin adalah orang yang paling akhir, aku menoleh dan aku tidak kehilangan tempat kurma padahal empat ratus orang telah mengambilnya."},"3584":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنِ الْحَجَّاجِ يَعْنِي الصَّوَّافَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنِ ابْنِ جَابِرِ بْنِ عَتِيكٍ الْأَنْصَارِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الْغَيْرَةِ مَا يُحِبُّ اللَّهُ وَمِنْهَا مَا يُبْغِضُ اللَّهُ وَمِنْ الْخُيَلَاءِ مَا يُحِبُّ اللَّهُ وَمِنْهَا مَا يُبْغِضُ اللَّهُ فَأَمَّا الْغَيْرَةُ الَّتِي يُحِبُّ اللَّهُ فَالْغَيْرَةُ فِي رِيبَةٍ وَأَمَّا الَّتِي يُبْغِضُ اللَّهُ فَالْغَيْرَةُ فِي غَيْرِ الرِّيبَةِ وَأَمَّا الْخُيَلَاءُ الَّتِي يُحِبُّ اللَّهُ أَنْ يَتَخَيَّلَ الْعَبْدُ بِنَفْسِهِ لِلَّهِ عِنْدَ الْقِتَالِ وَأَنْ يَتَخَيَّلَ بِالصَّدَقَةِحَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَرْبٌ يَعْنِي ابْنَ شَدَّادٍ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ الْقُرَشِيُّ حَدَّثَنِي ابْنُ جَابِرِ بْنِ عَتِيكٍ أَنَّ أَبَاهُ أَخْبَرَهُ وَكَانَ أَبُوهُ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الْغَيْرَةِ فَذَكَرَ مَعْنَاهُ وَقَالَ الْخُيَلَاءُ الَّتِي يُحِبُّ اللَّهُ اخْتِيَالُ الرَّجُلِ فِي الْقِتَالِ وَاخْتِيَالُهُ فِي الصَّدَقَةِ وَالْخُيَلَاءُ الَّتِي يُبْغِضُ اللَّهُ الْخُيَلَاءُ فِي الْبَغْيِ أَوْ قَالَ فِي الْفَخْرِ","id":"Telah bercerita kepada kami [Isma'il] dari [Hajjaj Ash Shawwaf] dari [Yahya bin Abu Katsir] dari [Muhammad bin Ibrahim] dari [Ibnu Jabir bin 'Atik Al Anshari] dari [ayahnya] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Sesungguhnya diantara cemburu itu ada yang disukai Allah dan ada yang dibenci Allah dan diantara sikap sombong itu ada yang disukai Allah dan ada yang dibenci Allah, cemburu yang disukai Allah adalah cemburu dalam keraguan dan yang dibenci Allah adalah cemburu diluar keraguan, sedangkan sikap sombong yang disukai Allah sombongnya seorang hamba untuk Allah saat perang dan sombong dengan sedekah.\" Telah bercerita kepada kami [Abdush Shamad] telah menceritakan kepada kami [Harb yaitu Ibnu Syaddad] telah menceritakan kepada kami [Yahya yaitu Ibnu Abi Katsir] telah menceritakan kepada kami [Muhammad bin Ibrahim Al Qurasy] telah bercerita kepadaku [Ibnu Jabir bin 'Atik] bahwa [ayahnya] memberitahu padanya dan ayahnya adalah salah seorang sahabat Rasulullah Shallalahu 'alaihi wa sallambahwa nabi Shallalahu 'alaihi wa sallambersabda: \"Sesungguhnya diantara cemburu itu\" lalu ia 'Atik menyebut makna hadits dan berkata dalam riwayatnya: \"Sombong yang disukai Allah adalah sombongnya seseorang saat perang dan sombong saat bersedekah, sedangkan sombong yang dibenci Allah adalah sombong dalam kekejian -atau bersabda: \"Dalam kebanggaan.\""},"3585":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ : مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ جَابِرِ بْنِ عَتِيكٍ عَنْ جَابِرِ بْنِ عَتِيكٍ أَنَّهُ قَالَجَاءَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ فِي بَنِي مُعَاوِيَةَ قَرْيَةٍ مِنْ قُرَى الْأَنْصَارِ فَقَالَ لِي هَلْ تَدْرِي أَيْنَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَسْجِدِكُمْ هَذَا فَقُلْتُ نَعَمْ فَأَشَرْتُ لَهُ إِلَى نَاحِيَةٍ مِنْهُ فَقَالَ هَلْ تَدْرِي مَا الثَّلَاثُ الَّتِي دَعَا بِهِنَّ فِيهِ فَقُلْتُ نَعَمْ قَالَ فَأَخْبِرْنِي بِهِمْ فَقُلْتُ دَعَا بِأَنْ لَا يُظْهِرَ عَلَيْهِمْ عَدُوًّا مِنْ غَيْرِهِمْ وَلَا يُهْلِكَهُمْ بِالسِّنِينَ فَأُعْطِيَهُمَا وَدَعَا بِأَنْ لَا يَجْعَلَ بَأْسَهُمْ بَيْنَهُمْ فَمَنَعَنِيهَا قَالَ صَدَقْتَ فَلَا يَزَالُ الْهَرْجُ إِلَى يَوْمِ الْقِيَامَةِ","id":"Berkata Ahmad; Aku membacakan riwayat kepada ['Abdur Rahman bin Mahdi]: [Malik] dari ['Abdullah bin 'Abdullah bin Jabir bin 'Atik] dari [Jabir bin 'Atik] ia berkata: 'Abdullah bin 'Umar mendatangi kami di tempat Bani Mu'awiyah, salah satu perkampungan kaum Anshar lalu 'Abdullah bertanya kepadaku: Tahukah kamu dimana dulu Rasulullah Shallalahu 'alaihi wa sallamshalat di masjid kalian ini? Aku berkata: Ya. Lalu aku menunjukkan ke salah satu sisinya. 'Abdullah bertanya: Tahukah kau tiga hal yang didoakan nabi Shallalahu 'alaihi wa sallamditempat itu? Aku menjawab: Ya. Berkata 'Abdullah: Beritahukan padaku. Aku berkata: Rasulullah Shallalahu 'alaihi wa sallamberdoa agar mereka tidak dikalahkan oleh musuh selain mereka dan agar mereka tidak dibinasakan oleh paceklik, keduanya dikabulkan dan beliau berdoa agar tidak menjadikan serangan terjadi diantara mereka sendiri lalu Allah mencegahnya. Berkata 'Abdullah bin 'Umar: Kau benar, pembunuhan akan tetap terjadi hingga hari kiamat."},"3586":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا الْحَجَّاجُ بْنُ أَبِي عُثْمَانَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ أَنَّ ابْنَ جَابِرِ بْنِ عَتِيكٍ حَدَّثَهُ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الْغَيْرَةِ مَا يُحِبُّ اللَّهُ وَمِنْهَا مَا يُبْغِضُ اللَّهُ وَمِنْ الْخُيَلَاءِ مَا يُحِبُّ اللَّهُ وَمِنْهَا مَا يُبْغِضُ اللَّهُ فَالْغَيْرَةُ الَّتِي يُحِبُّ اللَّهُ الْغَيْرَةُ فِي الرِّيبَةِ وَالْغَيْرَةُ الَّتِي يُبْغِضُ اللَّهُ الْغَيْرَةُ فِي غَيْرِ رِيبَةٍ وَالْخُيَلَاءُ الَّتِي يُحِبُّ اللَّهُ اخْتِيَالُ الْعَبْدِ بِنَفْسِهِ لِلَّهِ عِنْدَ الْقِتَالِ وَاخْتِيَالُهُ بِالصَّدَقَةِ وَالْخُيَلَاءُ الَّتِي يُبْغِضُ اللَّهُ الْخُيَلَاءُ فِي الْفَخْرِ وَالْكِبْرِ أَوْ كَالَّذِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah bercerita kepada kami [Isma'il] telah bercerita kepada kami [Hajjaj bin Abu 'Utsman] telah bercerita kepada kami [Yahya bin Abu Katsir] dari [Muhammad bin Ibrahim] bahwa [Ibnu Jabir bin 'Atik] bercerita kepadanya dari [ayahnya] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Sesungguhnya diantara cemburu itu ada yang disukai Allah dan ada yang dibenci Allah dan diantara sikap sombong itu ada yang disukai Allah dan ada yang dibenci Allah, cemburu yang disukai Allah adalah cemburu dalam keraguan dan yang dibenci Allah adalah cemburu diluar keraguan, sedangkan sikap sombong yang disukai Allah sombongnya seorang hamba untuk Allah saat perang dan sombong dengan sedekah, sedangkan sombong yang dibenci Allah adalah sombong dalam kebanggaan atau keangkuhan atau seperti yang disabdakan Rasulullah shallallahu 'alaihi wasallam.\""},"3587":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ جَبْرِ بْنِ عَتِيكٍ عَنْ عَمِّهِ قَالَدَخَلْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَيِّتٍ مِنْ الْأَنْصَارِ وَأَهْلُهُ يَبْكُونَ فَقُلْتُ أَتَبْكُونَ وَهَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُنَّ يَبْكِينَ مَا دَامَ عِنْدَهُنَّ فَإِذَا وَجَبَتْ فَلَا يَبْكِينَفَقَالَ جَبْرٌ فَحَدَّثْتُ بِهِ عُمَرَ بْنَ حُمَيْدٍ الْقُرَشِيَّ فَقَالَ لِي مَاذَا وَجَبَتْ قَالَ إِذَا أُدْخِلَ قَبْرَهُ","id":"Telah bercerita kepada kami [Abu Nu'aim] telah bercerita kepada kami [Isra`il] dari ['Abdullah bin 'Isa] dari [Jabr bin 'Atik] dari [pamannya] berkata; Aku mengunjungi jenzah seorang Anshar dan keluarganya bersama Rasulullah shallallahu 'alaihi wasallam, mereka manangis lalu aku berkata: Kenapa kalian menangis sementara disini ada Rasulullah shallallahu 'alaihi wasallam. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Biarlah mereka menangis selama jenazahnya ada didekat mereka dan bila sudah wajib maka janganlah mereka menangis.\" Berkata Jabr: Aku menceritakannya pada 'Umar bin Humaid Al Qurasy lalu ia bertanya kepadaku: Wajib apa? Aku menjawab: Bila sudah dimasukkan ke dalam kubur."},"3588":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنِ ابْنِ جَابِرِ بْنِ عَتِيكٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الْغَيْرَةِ مَا يُحِبُّ اللَّهُ وَمِنْهَا مَا يُبْغِضُ اللَّهُ وَإِنَّ مِنْ الْخُيَلَاءِ مَا يُحِبُّ اللَّهُ وَمِنْهَا مَا يُبْغِضُ اللَّهُ وَأَمَّا الْغَيْرَةُ الَّتِي يُحِبُّ اللَّهُ فَالْغَيْرَةُ الَّتِي فِي الرِّيبَةِ وَأَمَّا الْغَيْرَةُ الَّتِي يُبْغِضُ اللَّهُ فَالْغَيْرَةُ فِي غَيْرِ الرِّيبَةِ وَأَمَّا الْخُيَلَاءُ الَّتِي يُحِبُّ اللَّهُ فَاخْتِيَالُ الرَّجُلِ بِنَفْسِهِ عِنْدَ الْقِتَالِ وَاخْتِيَالُهُ عِنْدَ الصَّدَقَةِ وَالْخُيَلَاءُ الَّتِي يُبْغِضُ اللَّهُ فَاخْتِيَالُ الرَّجُلِ فِي الْفَخْرِ وَالْبَغْيِ","id":"Telah bercerita kepada kami ['Affan] telah bercerita kepada kami [Aban] telah bercerita kepada kami [Yahya bin Abu Katsir] dari [Muhammad bin Ibrahim bin Al Harits] dari [Ibnu Jabir bin 'Atik] dari [ayahnya] bahwa Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Sesungguhnya diantara cemburu itu ada yang disukai Allah dan ada yang dibenci Allah dan diantara sikap sombong itu ada yang disukai Allah dan ada yang dibenci Allah, cemburu yang disukai Allah adalah cemburu dalam keraguan dan yang dibenci Allah adalah cemburu diluar keraguan, sedangkan sikap sombong yang disukai Allah sombongnya seorang hamba untuk Allah saat perang dan sombong dengan sedekah, sedangkan sombong yang dibenci Allah adalah sombongnya seseorang dalam kebanggaan dan kekejian.\" "},"3589":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ جَابِرِ بْنِ عَتِيكٍ عَنْ عَتِيكِ بْنِ الْحَارِثِ بْنِ عَتِيكٍ فَهُوَ جَدُّ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَبُو أُمِّهِ أَنَّهُ أَخْبَرَهُ أَنَّ جَابِرَ بْنَ عَتِيكٍ أَخْبَرَهُأَنَّ عَبْدَ اللَّهِ بْنَ ثَابِتٍ لَمَّا مَاتَ قَالَتْ ابْنَتُهُ وَاللَّهِ إِنْ كُنْتُ لَأَرْجُو أَنْ تَكُونَ شَهِيدًا أَمَا إِنَّكَ كُنْتَ قَدْ قَضَيْتَ جِهَازَكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ قَدْ أَوْقَعَ أَجْرَهُ عَلَى قَدْرِ نِيَّتِهِ وَمَا تَعُدُّونَ الشَّهَادَةَ قَالُوا قَتْلٌ فِي سَبِيلِ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهَادَةُ سَبْعٌ سِوَى الْقَتْلِ فِي سَبِيلِ اللَّهِ الْمَطْعُونُ شَهِيدٌ وَالْغَرِقُ شَهِيدٌ وَصَاحِبُ ذَاتِ الْجَنْبِ شَهِيدٌ وَالْمَبْطُونُ شَهِيدٌ وَصَاحِبُ الْحَرْقِ شَهِيدٌ وَالَّذِي يَمُوتُ تَحْتَ الْهَدْمِ شَهِيدٌ وَالْمَرْأَةُ تَمُوتُ بِجُمْعٍ شَهِيدَةٌ","id":"Telah bercerita kepada kami [Rauh] telah bercerita kepada kami [Malik] dari ['Abdullah bin 'Abdullah bin Jabir bin 'Atik] dari ['Atik bin Al Harits bin 'Atik] -kakek 'Abdullah bin 'Agbdullah, ayah dari ibunya- ia memberitahu padanya bahwa [Jabir bin 'Atik] memberitahunya bahwa 'Abdullah bin Tsabit saat meninggal, putrinya berkata: Demi Allah dulu aku sangat berharap engkau mati syahid, ingat engkau telah menunaikan perbekalanku, lalu Rasulullah shallallahu 'alaihi wasallam. Shallalahu 'alaihi wa sallam bersabda: \"Sesungguhnya Allah memberlakukan pahalanya berdasarkan ukuran niatnya, dan menurut kalian siapakah syuhada` itu?\" mereka menjawab: Orang yang terbunuh di jalan Allah. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Mati syahid itu ada tujuh selain terbunuh dijalan Allah; mati terkena tha'un syahid, mati tenggelam syahid, mati karena sakit lambung syahid, mati karena sakit perut syahid, mati terbakar syahid, mati tertimpa bangunan syahid dan wanita yang mati bersama janinnya syahidah.\""},"3590":{"ar":"حَدَّثَنَا الْحَارِثُ بْنُ مُرَّةَ الْحَنَفِيُّ أَبُو مُرَّةَ حَدَّثَنَا نَفِيسٌ عَنْ عَبْدِ اللَّهِ بْنِ جَابِرٍ الْعَبْدِيِّ قَالَكُنْتُ فِي الْوَفْدِ الَّذِي أَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عَبْدِ الْقَيْسِ قَالَ وَلَسْتُ مِنْهُمْ وَإِنَّمَا كُنْتُ مَعَ أَبِي قَالَ فَنَهَاهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشُّرْبِ فِي الْأَوْعِيَةِ الَّتِي سَمِعْتُمْ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَالْمُزَفَّتِ","id":"Telah bercerita kepada kami [Al Harits bin Murrah Al Hanafi Abu Murrah] telah bercerita kepada kami [Nafis] dari ['Abdullah bin Jabir Al 'Abdi] b erkata: Aku pernah berada dalam rombongan utusan yang mendatangi Rasulullah Shallalahu 'alaihi wa sallamdari Bani 'Abdul Qais tapi aku bukan berasal dari golongan mereka tapi aku hanya bersama ayahku lalu Rasulullah Shallalahu 'alaihi wa sallam melarang mereka untuk meminum diwada-wadah yang kalian dengar; saluran air, tempat anggur, batu yang diukir dan tempat tir."},"3591":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنْ عُثْمَانَ الْبَتِّيِّ عَنْ عَبْدِ الْحَمِيدِ بْنِ سَلَمَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ أَبَوَيْهِ اخْتَصَمَا فِيهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَحَدُهُمَا مُسْلِمٌ وَالْآخَرُ كَافِرٌ فَخَيَّرَهُ فَتَوَجَّهَ إِلَى الْكَافِرِ مِنْهُمَا فَقَالَ اللَّهُمَّ اهْدِهِ فَتَوَجَّهَ إِلَى الْمُسْلِمِ فَقَضَى لَهُ بِهِ","id":"Telah bercerita kepada kami [Isma'il] dari ['Utsman] dari ['Abdul Hamid bin Salamah] dari [ayahnya] dari [kakeknya] bahwa keduanya orang tuanya mempersengketakanya ke hadapan nabi shallallahu 'alaihi wasallam, salah satunya muslim dan lainnya kafir lalu beliau memberinya pilihan, ia mengarah ke orang tua yang kafir lalu Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ya Allah, tunjukilah dia.\" Lalu ia beralih ke orang tua yang muslim lalu beliau memutuskannya untuk orang tua yang muslim."},"3592":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا عُثْمَانُ أَبُو عَمْرٍو الْبَتِّيِّ عَنْ عَبْدِ الْحَمِيدِ بْنِ سَلَمَةَأَنَّ جَدَّهُ أَسْلَمَ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ تُسْلِمْ جَدَّتُهُ وَلَهُ مِنْهَا ابْنٌ فَاخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ شِئْتُمَا خَيَّرْتُمَا الْغُلَامَ قَالَ وَأَجْلَسَ الْأَبَ فِي نَاحِيَةٍ وَالْأُمَّ نَاحِيَةً فَخَيَّرَهُ فَانْطَلَقَ نَحْوَ أُمِّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اهْدِهِ قَالَ فَرَجَعَ إِلَى أَبِيهِ","id":"Telah bercerita kepada kami [Husyaim] telah bercerita kepada kami ['Utsman Abu 'Amru Al Batti] dari ['Abdul Hamid bin Salamah] bahwa kakeknya masuk Islam dimasa Rasulullah Shallalahu 'alaihi wa sallam tapi neneknya tidak masuk Islam, ia memiliki anak darinya lalu keduanya bersengketa dihadapan Rasulullah shallallahu 'alaihi wasallam, beliau bersabda kepada keduanya: \"Bila kalian berdua mau akau akan memberi hak pilih kepada kalian.\" Lalu Rasulullah Shallalahu 'alaihi wa sallam mempersilahkan duduk si ayah disalah satu sisi dan si ibu disalah sisi lain lalu anak kecil itu mendekat ke arah ibunya lalu Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ya Allah, tunjukilah ia.\" Anak itu kembali ke ayahnya."},"3593":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ أَخْبَرَنِي أَبِي عَنْ جَدِّي رَافِعِ بْنِ سِنَانٍأَنَّهُ أَسْلَمَ وَأَبَتْ امْرَأَتُهُ أَنْ تُسْلِمَ فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ ابْنَتِي وَهِيَ فَطِيمٌ أَوْ شَبَهُهُ وَقَالَ رَافِعٌ ابْنَتِي فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْعُدْ نَاحِيَةً وَقَالَ لَهَا اقْعُدِي نَاحِيَةً فَأَقْعَدَ الصَّبِيَّةَ بَيْنَهُمَا ثُمَّ قَالَ ادْعُوَاهَا فَمَالَتْ إِلَى أُمِّهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اهْدِهَا فَمَالَتْ إِلَى أَبِيهَا فَأَخَذَهَا","id":"Telah bercerita kepadaku ['Ali bin Bahr] telah bercerita kepada kami ['Isa bin Yunus] telah bercerita kepada kami ['Abdul Hamid bin Ja'far] telah mengkhabarkan kepadaku [ayahku] dari [kakekku, Rafi' bin Sinan] bahwa ia masuk Islam tapi istrinya enggan masuk Islam, lalu istrinya mendatangi nabi Shallalahu 'alaihi wa sallam dan berkata: Putriku masih menetek atau sepertinya -berkata Rafi' dalam riwayatnya: putriku- lalu nabi Shallalahu 'alaihi wa sallam bersabda padanya: \"Duduklah disalah satu sisi\" dan bersabda kepada istrinya: \"Duduklah disisi lain, \" kemudian putri kecil didudukkan diantara keduanya lalu Rasulullah Shallalahu 'alaihi wa sallambersabda: \"Panggillah dia.\" Putri itu mengarah ke ibunya lalu nabi Shallalahu 'alaihi wa sallambersabda: \"Ya Allah, tunjukilah dia.\" Lalu beralih ke ayahnya kemudian ayahnya mengambilnya."},"3594":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَنْبَأَنَا عُثْمَانُ الْبَتِّيُّ عَنْ عَبْدِ الْحَمِيدِ بْنِ سَلَمَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ نَقْرَةِ الْغُرَابِ وَعَنْ فَرْشَةِ السَّبُعِ وَأَنْ يُوطِنَ الرَّجُلُ مَقَامَهُ فِي الصَّلَاةِ كَمَا يُوطِنُ الْبَعِيرُ","id":"Telah bercerita kepada kami [Isma'il] telah memberitakan kepada kami ['Utsman Al Batti] dari ['Abdul Hamid bin Salamah] dari [ayahnya] bahwa Rasulullah Shallalahu 'alaihi wa sallam melarang seseorang mencocok laksana gagak, membentang laksana binatang buas dan menempati tempatnya saat shalat laksana unta menempati tempatnya.\""},"3595":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا سُفْيَانُ عَنْ عُثْمَانَ الْبَتِّيِّ عَنْ عَبْدِ الْحَمِيدِ الْأَنْصَارِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ جَدَّهُ أَسْلَمَ وَأَبَتْ امْرَأَتُهُ أَنْ تُسْلِمَ فَجَاءَ بِابْنٍ لَهُ صَغِيرٍ لَمْ يَبْلُغْ قَالَ فَأَجْلَسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَبَ هَاهُنَا وَالْأُمَّ هَاهُنَا ثُمَّ خَيَّرَهُ وَقَالَ اللَّهُمَّ اهْدِهِ فَذَهَبَ إِلَى أَبِيهِ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah memberitakan kepada kami [Sufyan] dari ['Utsman Al Batti] dari ['Abdul Hamid Al Anshari] dari [ayahnya] dari [kakeknya] bahwa kakeknya masuk Islam sementara istrinya tidak mau masuk Islam, ia membawa anak kecilnya yang belum baligh kemudian nabi Shallalahu 'alaihi wa sallam mendudukkan si ayah di sana dan ibunya disini, setelah itu beliau mempersilahkan anak itu untuk memilih, beliau bersabda: \"Ya Allah, tunjukilah ia.\" Lalu si anak itu menghampiri ayahnya."},"3596":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا سَعْدُ بْنُ سَعِيدٍ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ عَنْ قَيْسِ بْنِ عَمْرٍو قَالَرَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُصَلِّي بَعْدَ صَلَاةِ الصُّبْحِ رَكْعَتَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَلَاةُ الصُّبْحِ مَرَّتَيْنِ فَقَالَ الرَّجُلُ إِنِّي لَمْ أَكُنْ صَلَّيْتُ الرَّكْعَتَيْنِ اللَّتَيْنِ قَبْلَهُمَا فَصَلَّيْتُهُمَا الْآنَ قَالَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah bercerita kepada kami [Ibnu Numair] telah bercerita kepada kami [Sa'ad bin Sa'id] telah bercerita kepadaku [Muhammad bin Ibrahim At Taimi] dari [Qais bin 'Amru] berkata: nabi Shallalahu 'alaihi wa sallammelihat seseorang shalat dua rakaat setelah shalat shubuh lalu Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Apakah shalat shubuh itu dua kali.\" Orang itu berkata: Aku belum shalat sunnah dua rakaat sebelumnya, sekarang aku melakukannya. Berkata Qais: Rasulullah Shallalahu 'alaihi wa sallam diam."},"3597":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ وَسَمِعْتُ عَبْدَ رَبِّهِ بْنَ سَعِيدٍ أَخَا يَحْيَى بْنِ سَعِيدٍ يُحَدِّثُ عَنْ جَدِّهِ قَالَخَرَجَ إِلَى الصُّبْحِ فَوَجَدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصُّبْحِ وَلَمْ يَكُنْ رَكَعَ رَكْعَتَيْ الْفَجْرِ فَصَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَامَ حِينَ فَرَغَ مِنْ الصُّبْحِ فَرَكَعَ رَكْعَتَيْ الْفَجْرِ فَمَرَّ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا هَذِهِ الصَّلَاةُ فَأَخْبَرَهُ فَسَكَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَضَى وَلَمْ يَقُلْ شَيْئًا","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah memberitakan kepada kami [Ibnu Juraij] berkata dan aku (Ahmad) mendengar [Abdu Rabbih bin Sa'id, saudara Yahya bin Sa'id] bercerita dari [kakeknya] berkata: Ia pergi untuk shalat shubuh lalu ia melihat Rasulullah Shallalahu 'alaihi wa sallam sudah memulai shalat shubuh sementara ia belum shalat dua rakaat sunnah fajar, lalu ia shalat bersama nabi Shallalahu 'alaihi wa sallam kemudian setelah selesai shalat shubuh ia bangun kemudian shalat sunnah dua rakaat fajar. Nabi Shallalahu 'alaihi wa sallam melewatinya lalu bersabda: \"Shalat apa ini?\" lalu ia memberitahukan kepada beliau lalu beliau diam dan lewat, beliau tidak bersabda apa pun."},"3598":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنِي الْحَجَّاجُ بْنُ أَبِي عُثْمَانَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاوِيَةَ بْنِ الْحَكَمِ السُّلَمِيِّ قَالَبَيْنَا نَحْنُ نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ عَطَسَ رَجُلٌ مِنْ الْقَوْمِ فَقُلْتُ يَرْحَمُكَ اللَّهُ فَرَمَانِي الْقَوْمُ بِأَبْصَارِهِمْ فَقُلْتُ وَا ثُكْلَ أُمِّيَاهْ مَا شَأْنُكُمْ تَنْظُرُونَ إِلَيَّ قَالَ فَجَعَلُوا يَضْرِبُونَ بِأَيْدِيهِمْ عَلَى أَفْخَاذِهِمْ فَلَمَّا رَأَيْتُهُمْ يُصْمِتُونِي لَكِنِّي سَكَتُّ فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبِأَبِي هُوَ وَأُمِّي مَا رَأَيْتُ مُعَلِّمًا قَبْلَهُ وَلَا بَعْدَهُ أَحْسَنَ تَعْلِيمًا مِنْهُ وَاللَّهِ مَا كَهَرَنِي وَلَا شَتَمَنِي وَلَا ضَرَبَنِي قَالَ إِنَّ هَذِهِ الصَّلَاةَ لَا يَصْلُحُ فِيهَا شَيْءٌ مِنْ كَلَامِ النَّاسِ هَذَا إِنَّمَا هِيَ التَّسْبِيحُ وَالتَّكْبِيرُ وَقِرَاءَةُ الْقُرْآنِ أَوْ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ حَدِيثُ عَهْدٍ بِالْجَاهِلِيَّةِ وَقَدْ جَاءَ اللَّهُ بِالْإِسْلَامِ وَإِنَّ مِنَّا قَوْمًا يَأْتُونَ الْكُهَّانَ قَالَ فَلَا تَأْتُوهُمْ قُلْتُ إِنَّ مِنَّا قَوْمًا يَتَطَيَّرُونَ قَالَ ذَاكَ شَيْءٌ يَجِدُونَهُ فِي صُدُورِهِمْ فَلَا يَصُدَّنَّهُمْ قُلْتُ إِنَّ مَنَّا قَوْمًا يَخُطُّونَ قَالَ كَانَ نَبِيٌّ يَخُطُّ فَمَنْ وَافَقَ خَطَّهُ فَذَلِكَ","id":"Telah bercerita kepada kami [Isma'il bin Ibrahim] telah bercerita kepadaku [Hajjaj bin Abu 'Utsman] telah bercerita kepadaku [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] dari ['Atho` bin Yasar] dari [Mu'awiyah bin Al Hakam As Sulami] berkata: Saat kami shalat bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba seseorang bersin, aku mengucapkan: YARHAMUKALLAAH, lalu orang-orang menatapku, aku berkata: Celaka aku, kenapa kalian menatapku. Mereka memukul-mukulkan tangan mereka ke lutut. Saat aku melihat mereka menyuruhku diam, aku pun diam, seusai shalat Rasulullah Shallalahu 'alaihi wa sallam memberi pelajaran yang paling indah yang belum pernah aku lihat sebelum dan sesudahnya, demi Allah beliau tidak membentakku, tidak mencelaku dan tidak memukulku, beliau bersabda: \"Sesungguhnya shalat ini tidak layak ada sesuatu kata-kata orang pun didalamnya, shalat hanyalah tasbih, takbir dan bacaan Al Quran, \" atau seperti yang disabdakan Rasulullah shallallahu 'alaihi wasallam. Aku berkata: Wahai Rasulullah, kami adalah kaum yang belum lama ini berada dimasa jahiliyah, Allah membawa Islam dan sebagaian dari kami ada kaum yang biasa mendatangi dukun. Rasulullah Shallalahu 'alaihi wa sallambersabda: \"Jangan kalian mendatangi mereka.\" Aku berkata: Diantara kami ada kaum yang biasa merasa sial. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Itu adalah sesuatu yang mereka dapatkan dihati mereka, karena itu jangan sekali-kali ia (kesialan) menghalangi mereka.\" Aku berkata: Diantara kami ada kaum yang membuat garis. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Dulu ada seorang nabi membuat garis, barangsiapa yang garisnya sama dengan garis nabi itu maka itu benar.\""},"3599":{"ar":"قَالَوَكَانَتْ لِي جَارِيَةٌ تَرْعَى غَنَمًا لِي فِي قِبَلِ أُحُدٍ وَالْجَوَّانِيَّةِ فَاطَّلَعْتُهَا ذَاتَ يَوْمٍ فَإِذَا الذِّئْبُ قَدْ ذَهَبَ بِشَاةٍ مِنْ غَنَمِهَا وَأَنَا رَجُلٌ مِنْ بَنِي آدَمَ آسَفُ كَمَا يَأْسَفُونَ لَكِنِّي صَكَكْتُهَا صَكَّةً فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَظَّمَ ذَلِكَ عَلَيَّ قُلْتُ يَا رَسُولَ اللَّهِ أَفَلَا أُعْتِقُهَا قَالَ ائْتِنِي بِهَا فَأَتَيْتُهُ بِهَا فَقَالَ لَهَا أَيْنَ اللَّهُ فَقَالَتْ فِي السَّمَاءِ قَالَ مَنْ أَنَا قَالَتْ أَنْتَ رَسُولُ اللَّهِ قَالَ أَعْتِقْهَا فَإِنَّهَا مُؤْمِنَةٌ وَقَالَ مَرَّةً هِيَ مُؤْمِنَةٌ فَأَعْتِقْهَا","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya dari [Mu'awiyah]; berkata perawi; Aku dulu memiliki seorang budak wanita yang menggembala kambing disisi gunung Uhud dan Jawaniyah, aku melihatnya dari atas pada suatu hari ternyata serigala memakan salah satu kambingnya dan aku adalah seorang dari Bani Adam, aku menyesal seperti mereka tapi aku aku memukulnya dengan keras kemudian aku mendatangi nabi shallallahu 'alaihi wasallam, beliau membesarkan hal itu padaku, aku berkata: Wahai Rasulullah, perkenanankan aku memerdekakannya. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Bawa dia kemari.\" Aku membawanya lalu beliau bersabda kepadanya: Dimana Allah? Budak wanita itu menjawab: Di langit. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Siapa aku?\" ia menjawab: Engkau utusan Allah. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Merdekakan, ia mu`minah.\" Ia (Mu'awiah) pernah berkata dalam riwayatnya: \"Ia mu`minah, merdekakan.\""},"3600":{"ar":"حَدَّثَنَا هَاشِمٌ عَنِ ابْنِ أَبِي ذِئْبٍ عَنِ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ مُعَاوِيَةَ بْنِ الْحَكَمِ السُّلَمِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَشْيَاءُ كُنَّا نَصْنَعُهَا فِي الْجَاهِلِيَّةِ كُنَّا نَأْتِي الْكُهَّانَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَأْتُوا الْكُهَّانَ قَالَ وَكُنَّا نَتَطَيَّرُ قَالَ ذَاكَ شَيْءٌ يَجِدُهُ أَحَدُكُمْ فِي نَفْسِهِ فَلَا يَصُدَّنَّكُمْ","id":"Telah bercerita kepada kami [Hasyim] dari [Ibnu Abi Dzi'b] dari [Az Zuhri] dari [Abu Salamah] dari [Mu'awiyah bin Al Hakam As Sulami] berkata: Aku berkata: Wahai Rasulullah, kami dulu melakukannya dimasa jahiliyah, dulu kami biasa mendatangi dukun. Nabi Shallalahu 'alaihi wa sallam bersabda: \"Jangan kau datangi dukun.\" Ia Mu'awiyah berkata: Dulu kami biasa merasa sial. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Itu adalah sesuatu yang didapatkan oleh salah seorang dari kalian didalam jiwanya, jangan sekali-kali ia (kesialan) menghalangi kalian.\""},"3601":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَنْبَأَنَا شُعَيْبٌ عَنِ الزُّهْرِيِّ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ مُعَاوِيَةَ بْنَ الْحَكَمِ السُّلَمِيَّ وَكَانَ صَحَابِيًّا قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ أُمُورًا كُنَّا نَفْعَلُهَا فِي الْجَاهِلِيَّةِ كُنَّا نَتَطَيَّرُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاكَ شَيْءٌ يَجِدُهُ أَحَدُكُمْ فِي نَفْسِهِ فَلَا يَصُدَّنَّكُمْ فَقُلْتُ وَكُنَّا نَأْتِي الْكُهَّانَ قَالَ وَلَا تَأْتُوا الْكُهَّانَ","id":"Telah bercerita kepada kami [Abu Al Yaman] telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri] telah mengkhabarkan kepadaku [Abu Salamah bin 'Abdur Rahman] bahwa [Mu'awiyah bin Al Hakam As Sulami, seorang sahabat] berkata: Aku berkata: Wahai Rasulullah, bagaimana menurut Tuan hal-hal yang dulu kami lakukan dimasa jahiliyah, dulu kami merasa sial. Nabi Shallalahu 'alaihi wa sallam bersabda: \"Itu adalah sesuatu yang didapatkan oleh salah seorang dari kalian didalam jiwanya, jangan sekali-kali ia (kesialan) menghalangi kalian.\" Aku berkata: Dulu kami biasa mendatangi dukun. Nabi Shallalahu 'alaihi wa sallam bersabda: \"Jangan kau datangi dukun.\""},"3602":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ سَمِعْتُ يَحْيَى بْنَ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ أَنَّ عَطَاءَ بْنَ يَسَارٍ حَدَّثَهُ أَنَّ مُعَاوِيَةَ بْنَ الْحَكَمِ حَدَّثَهُ بِثَلَاثَةِ أَحَادِيثَ حَفِظَهَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ حَدِيثُ عَهْدٍ بِجَاهِلِيَّةٍ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ جَاءَ بِالْإِسْلَامِ وَإِنَّ مِنَّا رِجَالًا يَخُطُّونَ قَالَ قَدْ كَانَ نَبِيٌّ مِنْ الْأَنْبِيَاءِ يَخُطُّ فَمَنْ وَافَقَ خَطَّهُ فَذَلِكَ قَالَ قُلْتُ إِنَّ مِنَّا رِجَالًا يَتَطَيَّرُونَ قَالَ ذَاكَ شَيْءٌ يَجِدُونَهُ فِي صُدُورِهِمْ فَلَا يَصُدَّنَّكُمْ قَالَ قُلْتُ إِنَّ مَنَّا رِجَالًا يَأْتُونَ الْكُهَّانَ قَالَ فَلَا تَأْتُوهُمْ قَالَ فَهَذَا حَدِيثٌ","id":"Telah bercerita kepada kami ['Affan] telah bercerita kepada kami [Hammam] aku mendengar [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] bahwa ['Atha` bin Yasar] bercerita kepadanya bahwa [Mu'awiyah bin Al Hakam] menceritakan tiga hadits kepadanya yang ia hafal dari Rasulullah shallallahu 'alaihi wasallam. Ia Mu'awiyah berkata: Aku berkata: Wahai Rasulullah, kami adalah kaum yang belum lama ini berada dimasa jahiliyah dan Allah 'azza wajalla membawa Islam, diantara kami ada kaum yang membuat garis. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Dulu ada seorang nabi membuat garis, barangsiapa yang garisnya sama dengan garis nabi itu maka itu benar.\" Aku berkata: Diantara kami ada yang biasa merasa sial. Rasulullah Shallalahu 'alaihi wa sallambersabda: \"Itu adalah sesuatu yang mereka dapatkan dihati mereka, karena itu jangan sekali-kali ia (kesialan) menghalangi mereka.\" Aku berkata: Sebagaian dari kami ada yang biasa mendatangi dukun. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Jangan kalian mendatangi mereka.\" Ia Mu'awiyah bin Al Hakam berkata: Ini hadits pertama."},"3603":{"ar":"قَالَوَكَانَتْ لِي غَنَمٌ فِيهَا جَارِيَةٌ لِي تَرْعَاهَا فِي قِبَلِ أُحُدٍ والْجَوَّانِيَّةِ فَاطَّلَعْتُ عَلَيْهَا ذَاتَ يَوْمٍ فَوَجَدْتُ الذِّئْبَ قَدْ ذَهَبَ مِنْهَا بِشَاةٍ فَأَسِفْتُ وَأَنَا رَجُلٌ مِنْ بَنِي آدَمَ آسَفُ مِثْلَ مَا يَأْسَفُونَ وَإِنِّي صَكَكْتُهَا صَكَّةً قَالَ فَعَظُمَ ذَلِكَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَفَلَا أُعْتِقُهَا قَالَ ادْعُهَا فَدَعَوْتُهَا فَقَالَ لَهَا أَيْنَ اللَّهُ قَالَتْ فِي السَّمَاءِ قَالَ مَنْ أَنَا قَالَتْ أَنْتَ رَسُولُ اللَّهِ قَالَ إِنَّهَا مُؤْمِنَةٌ فَأَعْتِقْهَا قَالَ هَذَانِ حَدِيثَانِ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya dari [Mu'awiyah]; Berkata: Aku dulu memiliki seorang budak wanita yang menggembala kambing disisi gunung Uhud dan Jawaniyah, aku melihatnya dari atas pada suatu hari ternyata serigala memakan salah satu kambingnya dan aku adalah seorang dari Bani Adam, aku menyesal seperti mereka tapi aku aku memukulnya dengan keras kemudian aku mendatangi nabi shallallahu 'alaihi wasallam, beliau membesarkan hal itu padaku, aku berkata: Wahai Rasulullah, perkenanankan aku memerdekakannya. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Bawa dia kemari.\" Aku membawanya lalu beliau bersabda kepadanya: Dimana Allah? Budak wanita itu menjawab: Dilangit. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Siapa aku?\" ia menjawab: Engkau utusan Allah. Rasulullah Shallalahu 'alaihi wa sallambersabda: \"Ia mu`minah, merdekakan.\" Berkata; Ini hadits kedua."},"3604":{"ar":"قَالَفَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ فَعَطَسَ رَجُلٌ مِنْ الْقَوْمِ فَقُلْتُ يَرْحَمُكَ اللَّهُ فَرَمَانِي الْقَوْمُ بِأَبْصَارِهِمْ فَقُلْتُ وَا ثُكْلَ أُمِّيَاهْ مَا شَأْنُكُمْ تَنْظُرُونَ إِلَيَّ قَالَ فَضَرَبُوا بِأَيْدِيهِمْ عَلَى أَفْخَاذِهِمْ فَلَمَّا رَأَيْتُهُمْ يُصْمِتُونِي سَكَتُّ حَتَّى صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَانِي قَالَ فَبِأَبِي وَأُمِّي مَا رَأَيْتُ مُعَلِّمًا قَبْلَهُ وَلَا بَعْدَهُ أَحْسَنَ تَعْلِيمًا مِنْهُ فَمَا ضَرَبَنِي وَلَا كَهَرَنِي وَلَا سَبَّنِي وَقَالَ إِنَّ هَذِهِ الصَّلَاةَ لَا يَصْلُحُ فِيهَا شَيْءٌ مِنْ كَلَامِ النَّاسِ هَذَا إِنَّمَا هِيَ التَّسْبِيحُ وَالتَّكْبِيرُ وَقِرَاءَةُ الْقُرْآنِ أَوْ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ ثَلَاثَةُ أَحَادِيثَ حَدَّثَنِيهَاحَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ الْعَطَّارُ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنَا هِلَالُ بْنُ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاوِيةَ بْنِ الْحَكَمِ السُّلَمِيِّ حَدَّثَنِي بِهَذَا الْحَدِيثِ بِنَحْوِهِ فَزَادَ فِيهِ وَقَالَ إِنَّمَا هِيَ التَّسْبِيحُ وَالتَّكْبِيرُ وَالتَّحْمِيدُ وَقِرَاءَةُ الْقُرْآنِ أَوْ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya), [Mu'awiyah bin Al Hakam] berkata, Aku shalat dibelakang Rasulullah Shallalahu 'alaihi wa sallampada suatu hari, tiba-tiba seseorang bersin, aku mengucapkan: YARHAMUKALLAAH, lalu orang-orang menatapku, aku berkata: Celaka aku, kenapa kalian menatapku. Mereka memukul-mukulkan tangan mereka ke lutut. Saat aku melihat mereka menyuruhku diam, aku pun diam, seusai shalat Rasulullah Shallalahu 'alaihi wa sallam memanggilku, sungguh aku tidak pernah melihat seorang pengajar sebelum dan sesudahnya yang ajarannya paling bagus melebihi beliau, beliau tidak membentakku, tidak mencelaku dan tidak memukulku, beliau bersabda: \"Sesungguhnya shalat ini tidak layak ada sesuatu kata-kata orang pun didalamnya, shalat hanyalah tasbih, takbir dan bacaan Al Quran, \" atau seperti yang disabdakan Rasulullah shallallahu 'alaihi wasallam. Ini ada tiga hadits yang diceritakannya kepadaku. Telah bercerita kepada kami [Affan] telah menceritakan kepada kami [Aban bin Yazid Al Athar] telah menceritakan kepadaku [Yahya bin Abu Katsir] telah bercerita kepada kami [Hilal bin Abu Maimunah] dari ['Atho` bin Yasar] dari [Mu'awiyah bin Al Hakam As Sulami] ia menceritakan hadits sepertinya padaku, ia menambahkan dalam riwayatnya: \"Sesungguhnya ia hanyalah tasbih, takbir, tahmid dan bacaan Al Quran\" atau seperti yang disabdakan Rasulullah shallallahu 'alaihi wasallam."},"3605":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ حَجَّاجٍ الصَّوَّافِ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي هِلَالُ بْنُ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاوِيَةَ السُّلَمِيِّ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَعَطَسَ رَجُلٌ مِنْ الْقَوْمِ فَقُلْتُ يَرْحَمُكَ اللَّهُ فَرَمَانِي الْقَوْمُ بِأَبْصَارِهِمْ فَقُلْتُ وَا ثُكْلَ أُمِّيَاهْ مَا شَأْنُكُمْ تَنْظُرُونَ إِلَيَّ قَالَ فَجَعَلُوا يَضْرِبُونَ بِأَيْدِيهِمْ عَلَى أَفْخَاذِهِمْ فَعَرَفْتُ أَنَّهُمْ يُصْمِتُونِي لَكِنِّي سَكَتُّ فَلَمَّا قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ بِأَبِي هُوَ وَأُمِّي مَا شَتَمَنِي وَلَا كَهَرَنِي وَلَا ضَرَبَنِي فَقَالَ إِنَّ هَذِهِ الصَّلَاةَ لَا يَصْلُحُ فِيهَا شَيْءٌ مِنْ كَلَامِ النَّاسِ هَذَا إِنَّمَا هِيَ التَّسْبِيحُ وَالتَّكْبِيرُ وَقِرَاءَةُ الْقُرْآنِ أَوْ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ حَدِيثُ عَهْدٍ بِجَاهِلِيَّةٍ وَقَدْ جَاءَ اللَّهُ بِالْإِسْلَامِ وَمِنَّا رِجَالٌ يَأْتُونَ الْكُهَّانَ قَالَ فَلَا تَأْتُوهُمْ قُلْتُ وَمِنَّا رِجَالٌ يَتَطَيَّرُونَ قَالَ فَإِنَّ ذَلِكَ شَيْءٌ يَجِدُونَهُ فِي صُدُورِهِمْ فَلَا يَصُدَّنَّهُمْ قُلْتُ وَمِنَّا رِجَالٌ يَخُطُّونَ قَالَ كَانَ نَبِيٌّ مِنْ الْأَنْبِيَاءِ يَخُطُّ فَمَنْ وَافَقَ خَطَّهُفَذَاكَ","id":"Telah bercerita kepada kami [Yahya bin Sa'id] dari [Hajjaj Ash Shawwaf] telah bercerita kepadaku [Yahya bin Abu Katsir] telah bercerita kepadaku [Hilal bin Abu Maimunah] dari ['Atha` bin Yasar] dari [Mu'awiyah bin Al Hakam] berkata: Aku shalat bersama Rasulullah Shallalahu 'alaihi wa sallamlalu ada orang bersin, aku mengucapkan: YARHAMUKALLAAH, lalu orang-orang menatapku, aku berkata: Celaka aku, kenapa kalian menatapku. Mereka memukul-mukulkan tangan mereka ke lutut. Saat aku tahu mereka menyuruhku diam, aku pun diam, seusai shalat Rasulullah Shallalahu 'alaihi wa sallammemberi pelajaran yang paling indah yang belum pernah aku lihat sebelum dan sesudahnya, demi Allah beliau tidak membentakku, tidak mencelaku dan tidak memukulku, beliau bersabda: \"Sesungguhnya shalat ini tidak layak ada sesuatu kata-kata orang pun didalamnya, shalat hanyalah tasbih, takbir dan bacaan Al Quran, \" atau seperti yang disabdakan Rasulullah shallallahu 'alaihi wasallam. Aku berkata: Wahai Rasulullah, kami adalah kaum yang belum lama ini berada dimasa jahiliyah, Allah membawa Islam dan sebagaian dari kami ada kaum yang biasa mendatangi dukun. Rasulullah Shallalahu 'alaihi wa sallambersabda: \"Jangan kalian mendatangi mereka.\" Aku berkata: Diantara kami ada kaum yang biasa merasa sial. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Itu adalah sesuatu yang mereka dapatkan dihati mereka, karena itu jangan sekali-kali ia (kesialan) menghalangi mereka.\" Aku berkata: Diantara kami ada kaum yang membuat garis. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Dulu ada seorang nabi membuat garis, barangsiapa yang garisnya sama dengan garis nabi itu maka itu benar.\""},"3606":{"ar":"قَالَوَبَيْنَمَا جَارِيَةٌ لِي تَرْعَى غُنَيْمَاتٍ لِي فِي قِبَلِ أُحُدٍ وَالْجَوَّانِيَّةِ فَاطَّلَعْتُ عَلَيْهَا اطِّلَاعَةً فَإِذَا الذِّئْبُ قَدْ ذَهَبَ مِنْهَا بِشَاةٍ وَأَنَا رَجُلٌ مِنْ بَنِي آدَمَ يَأْسَفُ كَمَا يَأْسَفُونَ لَكِنِّي صَكَكْتُهَا صَكَّةً قَالَ فَعَظُمَ ذَلِكَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ أَلَا أُعْتِقُهَا قَالَ ابْعَثْ إِلَيْهَا قَالَ فَأَرْسَلَ إِلَيْهَا فَجَاءَ بِهَا فَقَالَ أَيْنَ اللَّهُ قَالَتْ فِي السَّمَاءِ قَالَ فَمَنْ أَنَا قَالَتْ أَنْتَ رَسُولُ اللَّهِ قَالَ أَعْتِقْهَا فَإِنَّهَا مُؤْمِنَةٌ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya, dari [Mu'awiyah]; Berkata (Mu'awiyah bin Al Hakam): Aku dulu memiliki seorang budak wanita yang menggembala kambing disisi gunung Uhud dan Jawaniyah, aku melihatnya dari atas pada suatu hari ternyata serigala memakan salah satu kambingnya dan aku adalah seorang dari Bani Adam, aku menyesal seperti mereka tapi aku aku memukulnya dengan keras kemudian aku mendatangi nabi shallallahu 'alaihi wasallam, beliau membesarkan hal itu padaku, aku berkata: Wahai Rasulullah, perkenanankan aku memerdekakannya. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Bawa dia kemari.\" Aku membawanya lalu beliau bersabda kepadanya: Dimana Allah? Budak wanita itu menjawab: Di langit. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Siapa aku?\" ia menjawab: Engkau utusan Allah. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Merdekakan, karena adalah mu`minah.\""},"3607":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا لَيْثٌ حَدَّثَنِي عُقَيْلٌ عَنِ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ مُعَاوِيَةَ بْنِ الْحَكَمِ السُّلَمِيِّأَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ أَشْيَاءَ كُنَّا نَفْعَلُهَا فِي الْجَاهِلِيَّةِ كُنَّا نَتَطَيَّرُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ شَيْءٌ تَجِدُهُ فِي نَفْسِكَ فَلَا يَصُدَّنَّكُمْ قَالَ يَا رَسُولَ اللَّهِ كُنَّا نَأْتِي الْكُهَّانَ قَالَ فَلَا تَأْتِ","id":"Telah bercerita kepada kami [Hajjaj] telah bercerita kepada kami [Laits] telah bercerita kepadaku ['Uqail] dari [Ibnu Syihab] dari [Abu Salamah bin 'Abdur Rahman bin 'Auf] dari [Mu'awiyah bin Al Hakam As Sulami] bahwa ia berkata kepada Rasulullah Shallalahu 'alaihi wa sallam: Wahai Rasulullah, bagaimana menurut Tuan hal-hal yang dulu kami lakukan dimasa jahiliyah, dulu kami merasa sial. Nabi Shallalahu 'alaihi wa sallambersabda: \"Itu adalah sesuatu yang kau dapatkan didalam jiwamu, jangan sekali-kali ia (kesialan) menghalangi kalian.\" Aku berkata: Dulu kami biasa mendatangi dukun. Nabi Shallalahu 'alaihi wa sallam bersabda: \"Jangan kau datangi.\""},"3608":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ قَالَ حَدَّثَنِي مَحْمُودُ بْنُ الرَّبِيعِ عَنْ عِتْبَانَ بْنِ مَالِكٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي قَدْ أَنْكَرْتُ بَصَرِي وَالسُّيُولُ تَحُولُ بَيْنِي وَبَيْنَ مَسْجِدِي فَلَوَدِدْتُ أَنَّكَ جِئْتَ فَصَلَّيْتَ فِي بَيْتِي مَكَانًا أَتَّخِذُهُ مَسْجِدًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْعَلُ إِنْ شَاءَ اللَّهُ قَالَ فَمَرَّ عَلَى أَبِي بَكْرٍ فَاسْتَتْبَعَهُ فَانْطَلَقَ مَعَهُ فَاسْتَأْذَنَ فَدَخَلَ عَلَيَّ فَقَالَ وَهُوَ قَائِمٌ أَيْنَ تُرِيدُ أَنْ أُصَلِّيَ فَأَشَرْتُ لَهُ حَيْثُ أُرِيدُ قَالَ ثُمَّ حَبَسْتُهُ عَلَى خَزِيرٍ صَنَعْنَاهُ لَهُ قَالَ فَسَمِعَ أَهْلُ الْوَادِي يَعْنِي أَهْلَ الدَّارِ فَثَابُوا إِلَيْهِ حَتَّى امْتَلَأَ الْبَيْتُ فَقَالَ رَجُلٌ أَيْنَ مَالِكُ بْنُ الدُّخْشُنِ وَرُبَّمَا قَالَ مَالِكُ بْنُ الدُّخَيْشِنِ فَقَالَ رَجُلٌ ذَاكَ رَجُلٌ مُنَافِقٌ لَا يُحِبُّ اللَّهَ وَلَا رَسُولَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُ هُوَ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ قَالَ يَا رَسُولَ اللَّهِ أَمَّا نَحْنُ فَنَرَى وَجْهَهُ وَحَدِيثَهُ إِلَى الْمُنَافِقِينَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْضًا لَا تَقُولُ هُوَ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ قَالَ بَلَى يَا رَسُولَ اللَّهِ قَالَ فَلَنْ يُوَافِيَ عَبْدٌ يَوْمَ الْقِيَامَةِ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ إِلَّا حُرِّمَ عَلَى النَّارِ قَالَ مَحْمُودٌ فَحَدَّثْتُ بِهَذَا الْحَدِيثِ نَفَرًا فِيهِمْ أَبُو أَيُّوبَ الْأَنْصَارِيُّ فَقَالَ مَا أَظُنُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا قُلْتَ قَالَ فَآلَيْتُ إِنْ رَجَعْتُ إِلَى عِتْبَانَ أَنْ أَسْأَلَهُ فَرَجَعْتُ إِلَيْهِ فَوَجَدْتُهُ شَيْخًا كَبِيرًا قَدْ ذَهَبَ بَصَرُهُ وَهُوَ إِمَامُ قَوْمِهِ فَجَلَسْتُ إِلَى جَنْبِهِ فَسَأَلْتُهُ عَنْ هَذَا الْحَدِيثِ فَحَدَّثَنِيهِ كَمَا حَدَّثَنِيهِ أَوَّلَ مَرَّةٍقَالَ مَعْمَرٌ فَكَانَ الزُّهْرِيُّ إِذَا حَدَّثَ بِهَذَا الْحَدِيثِ قَالَ ثُمَّ نَزَلَتْ فَرَائِضُ وَأُمُورٌ نَرَى أَنَّ الْأَمْرَ انْتَهَى إِلَيْهَا فَمَنْ اسْتَطَاعَ أَنْ لَا يَفْتُرَ فَلَا يَفْتُرْ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] berkata: telah bercerita kepadaku [Mahmud bin Ar Rabi'] dari ['Itban bin Malik] berkata: Aku mendatangi nabi Shallalahu 'alaihi wa sallamlalu aku berkata: Aku mengingkari penglihatanku dan aliran air menghalangiku untuk ke masjid, aku ingin Tuan datang lalu shalat di rumahku di suatu tempat yang akan aku jadikan masjid. Nabi Shallalahu 'alaihi wa sallam bersabda: Aku akan datang, insya Allah. Beliau melintasi Abu Bakar lalu Abu Bakar mengikuti beliau dan pergi bersama beliau. Beliau meminta izin lalu masu ke kediamanku, beliau bersabda dengan berdiri: \"Kau ingin aku shalat dimana?\" lalu aku menunjukkan tempat yang aku inginkan kepada beliau lalu aku tandai tempat itu dengan tombak yang kami buat. Lalu para penghuni lembah mendengar, mereka berdatangan menemui beliau hingga rumah penuh sesak, seseorang berkata: Mana Malik bin Ad Dukhsyun, mungkin ia berkata: Malik bin Ad Dukhaisyin, lalu seseorang berkata: Ia adalah orang munafik yang tidak mencintai Allah dan rasulNya. Lalu nabi Shallalahu 'alaihi wa sallam bersabda: \"Jangan berkata seperti itu, ia mengucapkan LAA ILAAHA ILLALLAAH dengan mengharapkan keridhaanNya.\" Orang itu berkata: Sedangkan kami wahai Rasulullah, kami melihat wajah dan pembicaraannya condong kepada kaum munafik. Nabi Shallalahu 'alaihi wa sallambersabda: \"Sekali lagi, jangan berkata seperti itu, ia mengucapkan LAA ILAAHA ILLALLAAH dengan mengharapkan keridhaanNya.\" Orang itu berkata: Betul, wahai Rasulullah. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Tidakah seorang hamba yang mengucapkan: LAA ILAAHA ILLALLAAH karena mengharapkan keridhaan Allah lalu bertemu dengan hari kiamat melainkan diharamkanlah neraka baginya.\" Berkata Mahmud: Aku menceritakan hadits ini kepada beberapa orang, diantaranya Abu Ayyub Al Anshari lalu ia berkata: Aku kira Rasulullah Shallalahu 'alaihi wa sallamtidak bersabda seperti yang kau katakan. Aku bersumpah bila aku kembali menemui 'Itban aku akan bertanya padanya. Aku kembali menemuinya dan ternyata ia sudah tua renta, penghilatannya sudah tiada dan ia adalah pemimpin kaumnya. Aku duduk didekatnya lalu aku menanyakan hadits itu padanya, ia menceritakannya kepadaku seperti yang ia ceritakan pertama kali dulu. Berkata Ma'mar: Az Zuhri menceritakan hadits ini, ia berkata: Kemudian kewajiban-kewajiban dan beberapa hal turun, kami menilainya sudah tuntas, maka barangsiapa yang mampu untuk tidak lemah, jangan lemah."},"3609":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ حَدَّثَنَا مَحْمُودُ بْنُ الرَّبِيعِ عَنْ عِتْبَانَ بْنِ مَالِكٍفَلَقِيتُ عِتْبَانَ بْنَ مَالِكٍ فَقُلْتُ مَا حَدِيثٌ بَلَغَنِي عَنْكَ قَالَ فَحَدِّثْنِي قَالَ كَانَ فِي بَصَرِي بَعْضُ الشَّيْءِ فَبَعَثْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي أُحِبُّ أَنْ تَجِيءَ إِلَى مَنْزِلِي تُصَلِّيَ فِيهِ فَأَتَّخِذَهُ مُصَلًّى قَالَ فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ شَاءَ مِنْ أَصْحَابِهِ قَالَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَنْزِلِهِ وَأَصْحَابُهُ يَتَحَدَّثُونَ وَيَذْكُرُونَ الْمُنَافِقِينَ وَمَا يَلْقَوْنَ مِنْهُمْ وَيُسْنِدُونَ عِظَمَ ذَلِكَ إِلَى مَالِكِ بْنِ الدُّخَيْشِنِ وَوَدُّوا أَنْ لَوْ دَعَا عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصَابَ شَرًّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَيْسَ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ قَالُوا يَا رَسُولَ اللَّهِ إِنَّهُ لَيَقُولُ ذَلِكَ وَمَا هُوَ فِي قَلْبِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَشْهَدُ أَحَدٌ أَنَّهُ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ فَتَطْعَمَهُ النَّارُ أَوْ تَمَسَّهُ النَّارُحَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ حَدَّثَنِي مَحْمُودُ بْنُ الرَّبِيعِ عَنْ عِتْبَانَ بْنِ مَالِكٍ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ فَذَكَرَ نَحْوَهُ قَالَ ثُمَّ حَبَسْتُهُ عَلَى خَزِيرٍ لَنَا صَنَعْنَاهُ لَهُ فَسَمِعَ بِهِ أَهْلُ الْوَادِي يَعْنِي أَهْلَ الدَّارِ فَثَابُوا إِلَيْهِ حَتَّى امْتَلَأَ الْبَيْتُ فَقَالَ رَجُلٌ أَيْنَ مَالِكُ بْنُ الدُّخْشُنِ قَالَ وَرُبَّمَا قَالَ الدُّخَيْشِنِ","id":"Telah bercerita kepada kami [Hajjaj] telah bercerita kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit Al Bunani] dari [Anas bin Malik] telah bercerita kepada kami [Mahmud bin Ar Rabi'] dari ['Itban bin Malik] lalu saya bertemu 'Itban bin Malik aku berkata: Hadits apa yang sampai padaku darimu? Ia berkata lalu ia bercerita kepadaku, ia berkata: Dimataku ada sesuatu lalu aku mengirim utusan menemui Rasulullah shallallahu 'alaihi wasallam, aku berkata: Aku ingin Tuan datang ke rumahku, Tuan shalat disana lalu aku menjadikannya sebagai tempat shalat. Rasulullah Shallalahu 'alaihi wa sallam datang dan beberapa sahabat beliau yang mau ikut lalu Rasulullah Shallalahu 'alaihi wa sallamshalat dirumahnya sementara para sahabatnya bercerita dan menyebut-nyebut kaum munafik serta yang mereka dapat dari mereka, mereka menyandarkan besarnya hal itu kepada Malik bin Ad Dukhaisy dan mereka ingin Rasulullah Shallalahu 'alaihi wa sallam mendoakan keburukan untuknya lalu ia akan tertimba keburukan, Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Bukankah ia bersaksi bahwa tidak ada Ilah (yang haq) selain Allah dan aku adalah utusan Allah?\" mereka menjawab: Benar wahai Rasulullah Shallallahu 'alaihi wa Salam, ia mengucapkannya lalu apa yang ada dihatinya? Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Tidaklah seseorang bersaksi bahwa tidak ada Ilah (yang haq) selain Allah dan aku adalah utusan Allah lalu akan dilahap atau disentuh api.\" Telah bercerita kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Ma'mar] dari [Az Zuhri] telah bercerita kepadaku [Mahmud bin Ar Rabi'] dari ['Itban bin Malik] berkata: Aku mendatangi nabi Shallalahu 'alaihi wa sallamlalu aku berkata, ia menyebut sepertinya, 'Itban berkata: Kemudian aku menandainya (tempat shalat) dengan tombak yang kami buat untuk beliau lalu penduduk lembah mendengarnya, mereka mendatangi beliau hingga rumah penuh lalu seseorang berkata: Mana Malik bin Ad Dukhsyun, berkata 'Itban dalam riwayatnya: Mungkin ia menyebut: Ad Dukhaisyin."},"3610":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ عَنِ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عِتْبَانَ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي بَيْتِهِ سُبْحَةَ الضُّحَى فَقَامُوا وَرَاءَهُ فَصَلَّوْا بِصَلَاتِهِ","id":"Telah bercerita kepada kami ['Utsman bin 'Umar] telah bercerita kepada kami [Yunus] dari [Az Zuhri] dari [Mahmud bin Ar Rabi'] dari ['Itban bin Malik] Rasulullah Shallalahu 'alaihi wa sallam shalat sunnah dirumah beliau lalu mereka berdiri dibelakang beliau dan shalat mengikuti beliau."},"3611":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ أَبِي الْبَدَّاحِ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ لِلرِّعَاءِ بِأَنْ يَرْمُوا يَوْمًا وَيَدَعُوا يَوْمًا","id":"Telah bercerita kepada kami [Sufyan bin 'Uyainah] dari ['Abdullah bin Abu Bakar] dari [ayahnya] dari [Abu Al Baddah] dari [ayahnya] bahwa nabi Shallalahu 'alaihi wa sallammemberi keringanan kepada para penggembala untuk melempar (jumrah) sehari dan meninggalkan sehari."},"3612":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ أَبِي الْبَدَّاحِ بْنِ عَاصِمِ بْنِ عَدِيٍّ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ لِرِعَاءِ الْإِبِلِ فِي الْبَيْتُوتَةِ عَنْ مِنًى يَرْمُونَ يَوْمَ النَّحْرِ ثُمَّ يَرْمُونَ الْغَدَ أَوْ مِنْ بَعْدِ الْغَدِ الْيَوْمَيْنِ ثُمَّ يَرْمُونَ يَوْمَ النَّفْرِ","id":"Telah bercerita kepada kami ['Abdur Rahman] telah bercerita kepada kami [Malik] dari ['Abdullah bin Abu Bakar] dari [ayahnya] dari [Abu Al Baddah bin 'Ashim bin 'Adi] dari [ayahnya] Rasulullah Shallalahu 'alaihi wa sallam memberi keringanan kepada para penggembala unta untuk tidak bermalam di Mina melempar (jumrah) pada hari nahar (penyembelihan kurban, pent.) kemudian mereka melempar (jumrah) pada keesokan hari atau lusa kemudian mereka melempar (jumrah) pada hari nafar."},"3613":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ أَبِي الْبَدَّاحِ بْنِ عَاصِمِ بْنِ عَدِيٍّ عَنْ أَبِيهِ قَالَرَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرِعَاءِ الْإِبِلِ فِي الْبَيْتُوتَةِ أَنْ يَرْمُوا يَوْمَ النَّحْرِ ثُمَّ يَجْمَعُوا رَمْيَ يَوْمَيْنِ بَعْدَ النَّحْرِ فَيَرْمُونَهُ فِي أَحَدِهِمَا قَالَ مَالِكٌ ظَنَنْتُ أَنَّهُ فِي الْآخِرِ مِنْهُمَا ثُمَّ يَرْمُونَ يَوْمَ النَّفْرِ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Malik] dari ['Abdullah bin Abu Bakar] dari [ayahnya] dari [Abu Al Baddah bin 'Ashim bin 'Adi] dari [ayahnya] berkata: Rasulullah Shallalahu 'alaihi wa sallammemberi keringanan kepada para penggembala unta untuk tidak bermalam di Mina melempar (jumrah) pada hari nahar (penyembelihan kurban, pent.) kemudian mereka melempar (jumrah) pada keesokan hari atau lusa kemudian mereka melempar (jumrah) pada hari nafar."},"3614":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ وَرَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُحَمَّدُ بْنُ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِيهِ عَنْ أَبِي الْبَدَّاحِ عَنْ عَاصِمِ بْنِ عَدِيٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْخَصَ لِلرِّعَاءِ أَنْ يَتَعَاقَبُوا فَيَرْمُوا يَوْمَ النَّحْرِ ثُمَّ يَدَعُوا يَوْمًا وَلَيْلَةً ثُمَّ يَرْمُوا الْغَدَ","id":"Telah bercerita kepada kami [Muhammad bin Bakar] dan [Rauh] dan telah bercerita kepada kami [Ibnu Juraij] telah mengkhabarkan kepadaku [Muhammad bin Abu Bakar bin Muhammad bin 'Amru] dari [ayahnya] dari [Abu Al Baddah] dari ['Ashim bin 'Adi] bahwa nabi Shallalahu 'alaihi wa sallam memberi keringanan untuk para penggembala untuk terlambat lau mereka melempar (jumrah) di hari nahar kemudian mereka meninggalkan sehari semalam kemudian keesokan harinya baru melempar (jumrah)."},"3615":{"ar":"حَدَّثَنَا يَزِيدُ أَنْبَأَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ أَبِيهِ قَالَ قَالَ أَبُو دَاوُدَ الْمَازِنِيُّ حَدَّثَنَا يَزِيدُ أَنْبَأَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ أَبِيهِ قَالَ قَالَ مُحَمَّدٌ فَحَدَّثَنِي أَبِي عَنْ رَجُلٍ مِنْ بَنِي مَازِنٍ عَنْ أَبِي دَاوُدَ الْمَازِنِيِّ وَكَانَ شَهِدَ بَدْرًا قَالَ قَالَإِنِّي لَأَتْبَعُ رَجُلًا مِنْ الْمُشْرِكِينَ لِأَضْرِبَهُ إِذْ وَقَعَ رَأْسُهُ قَبْلَ أَنْ يَصِلَ إِلَيْهِ سَيْفِي فَعَرَفْتُ أَنَّهُ قَدْ قَتَلَهُ غَيْرِي","id":"Telah bercerita kepada kami [Yazid] telah memberitakan kepada kami [Muhammad bin Ishaq] dari [ayahnya] berkata: Berkata [Abu Dawud Al Mazini] telah bercerita kepada kami [Yazid] telah memberitakan kepada kami [Muhammad bin Ishaq] dari [ayahnya] berkata: Berkata Muhammad lalu ayahku bercerita kepadaku dari [seorang Bani Mazin] dari [Abu Dawud Al Mazini] -yang pernah turut serta dalam perang Badar- berkata: Aku mengikuti seorang musyrik untuk aku bunuh tiba-tiba kepalanya jatuh sebelum pedangku mengenai kepalanya, aku tahu ia dibunuh oleh selainku."},"3616":{"ar":"حَدَّثَنَا يُونُسُ وَسُرَيْجٌ قَالَ حَدَّثَنَا فُلَيْحٌ عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ أَبِي سَلَمَةَ قَالَ كَانَ أَبُو هُرَيْرَةَ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ فِي الْجُمُعَةِ سَاعَةً فَذَكَرَ الْحَدِيثَ قُلْتُ وَاللَّهِ لَوْ جِئْتُ أَبَا سَعِيدٍ فَسَأَلْتُهُ فَذَكَرَ الْحَدِيثَ ثُمَّ خَرَجْتُ مِنْ عِنْدِهِ فَدَخَلْتُ عَلَى عَبْدِ اللَّهِ بْنِ سَلَامٍ فَسَأَلْتُ عَنْهَا فَقَالَ خَلَقَ اللَّهُ آدَمَ يَوْمَ الْجُمُعَةِ وَأُهْبِطَ إِلَى الْأَرْضِ يَوْمَ الْجُمُعَةِ وَقَبَضَهُ يَوْمَ الْجُمُعَةِ وَفِيهِ تَقُومُ السَّاعَةُ فَهِيَ آخِرُ سَاعَةٍ وَقَالَ سُرَيْجٌ فَهِيَ آخِرُ سَاعَتِهِ فَقُلْتُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي صَلَاةٍ وَلَيْسَتْ بِسَاعَةِ صَلَاةٍ قَالَ أَوَلَمْ تَعْلَمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُنْتَظِرُ الصَّلَاةِ فِي صَلَاةٍ قُلْتُ بَلَى هِيَ وَاللَّهِ هِيَ","id":"Telah bercerita kepada kami [Yunus] dan [Suraij] berkata: Telah bercerita kepada kami [Fulaih] dari [Sa'id bin Al Harits] dari [Abu Salamah] berkata: [Abu Hurairah] bercerita kepadanya dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya dihari jum'at itu ada waktu\" Abu Hurairah menyebut hadits. Aku berkata: Demi Allah, andai aku mendatangi Abu Sa'id lalu aku bertanya padanya, lalu Abu Sa'id menyebutkan hadits itu kemudian aku pergi, setelah itu aku bertamu ke kediaman ' [Abdullah bin Salam], aku bertanya kepadanya tentang hari jum'at, ia menjawab; Allah menciptakan Adam dihari jum'at, Adam diturunkan ke bumi pada hari kum'at, Allah mencabut nyawanya pada hari jum'at, dihari itu kiamat terjadi, dan itulah saat-saat terakhir. Berkata Suraij: Itulah saat terakhirnya. Lalu aku berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Di dalam shalat namun bukan saat shalat.\" Berkata Abu Sa'id; Apa kau tidak tahu Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Orang yang menunggu shalat berada dalam shalat.\" Aku Suraij; Benar, demi Allah itulah dia."},"3617":{"ar":"حَدَّثَنَا حُسَيْنٌ يَعْنِي ابْنَ مُحَمَّدٍ حَدَّثَنَا الْفُضَيْلُ يَعْنِي ابْنَ سُلَيْمَانَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ خُنَيْسٍ الْغِفَارِيِّ عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَمَا بَيْنَ كَدَاءٍ وَأُحُدٍ حَرَامٌ حَرَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا كُنْتُ لِأَقْطَعَ بِهِ شَجَرَةً وَلَا أَقْتُلَ بِهِ طَائِرًا","id":"Telah bercerita kepada kami [Husain bin Muhammad] telah bercerita kepada kami [Al Fudlail bin Sulaiman] telah bercerita kepada kami [Muhammad bin Abu Yahya] dari [Ubaidullah bin Khunais Al Ghifari] dari ['Abdullah bin Salam] berkata: Antara Kada` dan Uhud terdapat kawasan haram yang diharamkan Rasulullah Shallallahu 'alaihi wa Salam, aku tidak memotong pepohonannya dan tidak membunuh burung ditempat itu."},"3618":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ يَعْلَي أَبُو مُحَيَّاةَ التَّيْمِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ حَدَّثَنِي ابْنُ أَخِي عَبْدِ اللَّهِ بْنِ سَلَامٍ عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ اسْمِي عَبْدُ اللَّهِ بْنُ سَلَامٍ فَسَمَّانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدُ اللَّهِ بْنُ سَلَامٍ","id":"Telah bercerita kepada kami ['Abdullah bin Muhammad] telah bercerita kepada kami [Yahya bin Ya'la Abu Muhaiyah At Taimi] dari ['Abdul Malik bin 'Umair] telah bercerita kepadaku [Ibnu Akhi Abdullah bin Salam] dari ['Abdullah bin Salam] berkata: Aku mendatangi Rasulullah shallallahu 'alaihi wasallam, saat itu namaku bukan Abdullah bin Salam, lalu Rasulullah Shallalahu 'alaihi wa sallam memberiku nama Abdullah bin Salam."},"3619":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ أَنَّ يَحْيَى بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ عَنْ أَبِيهِ قَالَبَيْنَمَا نَحْنُ نَسِيرُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ سَمِعَ الْقَوْمَ وَهُمْ يَقُولُونَ أَيُّ الْأَعْمَالِ أَفْضَلُ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيمَانٌ بِاللَّهِ وَرَسُولِهِ وَجِهَادٌ فِي سَبِيلِ اللَّهِ وَحَجٌّ مَبْرُورٌ ثُمَّ سَمِعَ نِدَاءً فِي الْوَادِي يَقُولُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَشْهَدُ وَأَشْهَدُ أَنْ لَا يَشْهَدَ بِهَا أَحَدٌ إِلَّا بَرِئَ مِنْ الشِّرْكِقَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ هَارُونَ","id":"Telah bercerita kepada kami [Harun bin Ma'ruf] telah bercerita kepada kami [Ibnu Wahab] telah bercerita kepada kami ['Amru bin Al Harits] dari [Sa'id bin Abu Hilal] bahwa [Yahya bin 'Abdur Rahman] bercerita kepadanya dari ['Aun bin 'Abdullah] dari [Yusuf bin 'Abdullah bin Salam] dari [ayahnya] berkata; Saat kami bersama Rasulullah shallallahu 'alaihi wasallam, ia mendengar suatu kaum, mereka berkata: Amalan apa yang paling utama wahai Rasulullah? Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Beriman kepada Allah dan rasulNya, jihad di jalan Allah, haji mabrur\" kemudian ia mendengar panggilan dari lembah yang mengucapkan: Aku bersaksi bahwa tidak ada ilah (yang haq) selain Allah dan Muhammad adalah utusan Allah. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Dan aku benar-benar bersaksi bahwa tidaklah seseorang bersaksi akan hal itu melainkan ia terbebas dari kesyirikan.\" Berkata 'Abdullah: Aku mendengarnya dari Harun."},"3620":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ : مَالِكٌ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَثُمَّ لَقِيتُ عَبْدَ اللَّهِ بْنَ سَلَامٍ فَذَكَرَ الْحَدِيثَ ثُمَّ قَالَ عَبْدُ اللَّهِ بْنُ سَلَامٍ قَدْ عَلِمْتُ أَيَّةَ سَاعَةٍ هِيَ قَالَ أَبُو هُرَيْرَةَ فَقُلْتُ لَهُ فَأَخْبِرْنِي وَلَا تَضِنَّ عَلَيَّ قَالَ عَبْدُ اللَّهِ هِيَ آخِرُ سَاعَةٍ مِنْ يَوْمِ الْجُمُعَةِ قَالَ أَبُو هُرَيْرَةَ كَيْفَ تَكُونُ آخِرَ سَاعَةٍ مِنْ يَوْمِ الْجُمُعَةِ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَادِفُهَا عَبْدٌ مُسْلِمٌ يُصَلِّي وَتِلْكَ سَاعَةٌ لَا يُصَلَّى فِيهَا قَالَ عَبْدُ اللَّهِ بْنُ سَلَامٍ أَلَمْ يَقُلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَلَسَ مَجْلِسًا يَنْتَظِرُ فِيهِ الصَّلَاةَ فَهُوَ فِي الصَّلَاةِ حَتَّى يُصَلِّيَ فَقُلْتُ بَلَى قَالَ فَهُوَ ذَاكَ","id":"Berkata (Ahmad) Aku meriwayatkan dari ['Abdur Rahman] dengan membaca: [Malik] dari [Yazid bin 'Abdullah bin Al Had] dari [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Abu Salamah bin 'Abdur Rahman] dari [Abu Hurairah] berkata, lalu aku menemui Abdullah bin Salam kemudian ia menyebutkan hadits, lalu berkata ['Abdullah bin Salam]: Aku tahu kapankah saat itu. Berkata Abu Hurairah lalu aku berkata padanya: Beritahukan padaku, jangan pelit padaku. ia berkata: Itu adalah saat terakhir hari jum'at. Berkata (Abu Hurairah); Bagaimana bisa saat terakhir hari jum'at sementara Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Tidaklah seorang hamba muslim bertepatan dengan saat itu sementara ia tengah shalat.\" Berkata 'Abdullah bin Salam: Bukankah Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Barangsiapa duduk disuatu majlis seraya menunggu shalat berarti ia tengah shalat hingga ia usai shalat.\" Aku menjawab: Benar. Berkata 'Abdullah bin Salam: Itulah dia."},"3621":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَفَلَقِيتُ عَبْدَ اللَّهِ بْنَ سَلَامٍ فَحَدَّثْتُهُ حَدِيثِي وَحَدِيثَ كَعْبٍ فِي قَوْلِهِ فِي كُلِّ سَنَةٍ قَالَ كَذَبَ كَعْبٌ هُوَ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كُلِّ يَوْمِ جُمُعَةٍ قُلْتُ إِنَّهُ قَدْ رَجَعَ قَالَ أَمَا وَالَّذِي نَفْسُ عَبْدِ اللَّهِ بْنِ سَلَامٍ بِيَدِهِ إِنِّي لَأَعْرِفُ تِلْكَ السَّاعَةَ قَالَ قُلْتُ يَا عَبْدَ اللَّهِ فَأَخْبِرْنِي بِهَا قَالَ هِيَ آخِرُ سَاعَةٍ مِنْ يَوْمِ الْجُمُعَةِ قَالَ قُلْتُ قَالَ لَا يُوَافِقُ مُؤْمِنٌ وَهُوَ يُصَلِّي قَالَ أَمَا سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ انْتَظَرَ صَلَاةً فَهُوَ فِي صَلَاةٍ حَتَّى يُصَلِّيَ قُلْتُ بَلَى قَالَ فَهُوَ كَذَلِكَ","id":"Telah bercerita kepada kami [Yazid bin Harun] telah bercerita kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah] berkata; Aku menemui 'Abdullah bin Salam lalu aku ceritakan haditsku padanya dan hadits Ka'ab tentang sabda Rasulullah Shallalahu 'alaihi wa sallam setiap tahunnya. Berkata 'Abdullah bin Salam: Ka'ab berdusta, saat itu seperti yang disabdakan Rasulullah Shallalahu 'alaihi wa sallam adalah setiap jum'at. Aku berkata: Ka'ab menarik kembali ucapannya. Berkata 'Abdullah bin Salam: Ingat, demi Dzat yang jiwa 'Abdullah bin Salam berada ditanganNya, sesungguhnya aku benar-benar tahu saat itu. Aku berkata: Beritahukan saat itu kepadaku wahai 'Abdullah. Berkata 'Abdullah bin Salam: Itu adalah waktu terakhir hari jum'at. Aku berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Tidaklah seorang mu`min bertepatan (dengan saat itu, pent.) sementara ia tengah shalat.\" Berkata 'Abdullah bin Salam: Bukankah Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Barangsiapa yang menunggu shalat maka ia tengah shalat hingga ia usai shalat.\" Aku menjawab: Betul. Berkata 'Abdullah bin Salam: Itulah dia."},"3622":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ قَيْسِ بْنِ عَبَّادٍ قَالَكُنْتُ فِي الْمَسْجِدِ فَجَاءَ رَجُلٌ فِي وَجْهِهِ أَثَرٌ مِنْ خُشُوعٍ فَدَخَلَ فَصَلَّى رَكْعَتَيْنِ فَأَوْجَزَ فِيهَا فَقَالَ الْقَوْمُ هَذَا رَجُلٌ مِنْ أَهْلِ الْجَنَّةِ فَلَمَّا خَرَجَ اتَّبَعْتُهُ حَتَّى دَخَلَ مَنْزِلَهُ فَدَخَلْتُ مَعَهُ فَحَدَّثْتُهُ فَلَمَّا اسْتَأْنَسَ قُلْتُ لَهُ إِنَّ الْقَوْمَ لَمَّا دَخَلْتَ قَبْلُ الْمَسْجِدَ قَالُوا كَذَا وَكَذَا قَالَ سُبْحَانَ اللَّهِ مَا يَنْبَغِي لِأَحَدٍ أَنْ يَقُولَ مَا لَا يَعْلَمُ وَسَأُحَدِّثُكَ لِمَ إِنِّي رَأَيْتُ رُؤْيَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَصَصْتُهَا عَلَيْهِ رَأَيْتُ كَأَنِّي فِي رَوْضَةٍ خَضْرَاءَ قَالَ ابْنُ عَوْنٍ فَذَكَرَ مِنْ خُضْرَتِهَا وَسَعَتِهَا وَسْطُهَا عَمُودُ حَدِيدٍ أَسْفَلُهُ فِي الْأَرْضِ وَأَعْلَاهُ فِي السَّمَاءِ فِي أَعْلَاهُ عُرْوَةٌ فَقِيلَ لِيَ اصْعَدْ عَلَيْهِ فَقُلْتُ لَا أَسْتَطِيعُ فَجَاءَنِي مِنْصَفٌ قَالَ ابْنُ عَوْنٍ هُوَ الْوَصِيفُ فَرَفَعَ ثِيَابِي مِنْ خَلْفِي فَقَالَ اصْعَدْ عَلَيْهِ فَصَعِدْتُ حَتَّى أَخَذْتُ بِالْعُرْوَةِ فَقَالَ اسْتَمْسِكْ بِالْعُرْوَةِ فَاسْتَيْقَظْتُ وَإِنَّهَا لَفِي يَدِي قَالَ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَصَصْتُهَا عَلَيْهِ فَقَالَ أَمَّا الرَّوْضَةُ فَرَوْضَةُ الْإِسْلَامِ وَأَمَّا الْعَمُودُ فَعَمُودُ الْإِسْلَامِ وَأَمَّا الْعُرْوَةُ فَهِيَ الْعُرْوَةُ الْوُثْقَى أَنْتَ عَلَى الْإِسْلَامِ حَتَّى تَمُوتَ قَالَ وَهُوَ عَبْدُ اللَّهِ بْنُ سَلَامٍ","id":"Telah bercerita kepada kami [Ishaq bin Yusuf] telah bercerita kepada kami [Ibnu 'Aun] dari [Muhammad] dari [Qais bin 'Abbad] berkata; Aku berada di masjid lalu seseorang datang dan diwajahnya terdapat sisa kekhusyu'an, ia masuk lalu shalat dua rakaat ringan, orang-orang berkata: Orang itu termasuk penghuni surga. Saat ia keluar, aku mengikutinya hingga ia masuk rumah, aku masuk bersamanya lalu aku bercerita kepadanya, saat ia mendengar, aku berkata padanya: Saat kau masuk masjid, orang-orang berkata seperti ini dan itu. Orang itu berkata: Subhaanallaah, tidak sepatutnya orang mengatakan sesuatu yang tidak diketahui, aku akan menceritakan kepadaku, aku bermimpi sesuatu dimasa Rasulullah Shallalahu 'alaihi wa sallamlalu aku ceritakan mimpin itu pada beliau, aku bermimpi sepertinya aku berada ditaman hijau -berkata Ibnu 'Aun dalam riwayatnya: Ia menyebut hijaunya, luasnya dan di tengahnya ada tiang besi, bawahnya di bumi dan atasnya di langit, di atasnya ada tali lalu dikatakan kepadaku; Naiklah. Aku berkata: Aku tidak bisa. Lalu datanglah misnhaf -berkata Ibnu 'Aun: Pelayan- lalu ia mengangkat bajuku dari belakang, ia berkata: Naiklah. Aku pun naik hingga aku meraih tali, ia berkata: Berpeganganlah pada tali. Lalu aku terbangun dan tali itu ada ditanganku. Aku mendatangi nabi Shallalahu 'alaihi wa sallamkemudian aku ceritakan padanya. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Maksud tanam itu adalah Islam, tiang itu adalah tiang Islam sedangkan tali itu adalah tali yang erat, engkau berada dalam Islam hingga meninggal.\" Berkata Ibnu 'Aun dalam riwayatnya; Dia adalah ['Abdullah bin Salam]."},"3623":{"ar":"حَدَّثَنَا يَعْمَرُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَنْبَأَنَا الْأَوْزَاعِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي هِلَالُ بْنُ أَبِي مَيْمُونَةَ أَنَّ عَطَاءَ بْنَ يَسَارٍ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ سَلَامٍ حَدَّثَهُ أَوْ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَتَذَاكَرْنَا بَيْنَنَا فَقُلْنَا أَيُّكُمْ يَأْتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَسْأَلَهُ أَيُّ الْأَعْمَالِ أَحَبُّ إِلَى اللَّهِ وَهِبْنَا أَنْ يَقُومَ مِنَّا أَحَدٌ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْنَا رَجُلًا رَجُلًا حَتَّى جَمَعَنَا فَجَعَلَ بَعْضُنَا يُشِيرُ إِلَى بَعْضٍ فَقَرَأَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ سَبَّحَ لِلَّهِ مَا فِي السَّمَوَاتِ وَمَا فِي الْأَرْضِ إِلَى قَوْلِهِ كَبُرَ مَقْتًا عِنْدَ اللَّهِ }قَالَ فَتَلَاهَا مِنْ أَوَّلِهَا إِلَى آخِرِهَاقَالَ فَتَلَاهَا عَلَيْنَا ابْنُ سَلَامٍ مِنْ أَوَّلِهَا إِلَى آخِرِهَا قَالَ فَتَلَاهَا عَلَيْنَا عَطَاءُ بْنُ يَسَارٍ مِنْ أَوَّلِهَا إِلَى آخِرِهَا قَالَ يَحْيَى فَتَلَاهَا عَلَيْنَا هِلَالٌ مِنْ أَوَّلِهَا إِلَى آخِرِهَا قَالَ الْأَوْزَاعِيُّ فَتَلَاهَا عَلَيْنَا يَحْيَى مِنْ أَوَّلِهَا إِلَى آخِرِهَا","id":"Telah bercerita kepada kami [Ya'mar] telah bercerita kepada kami ['Abdullah bin Al Mubarok] telah memberitakan kepada kami [Al Auza'i] telah bercerita kepada kami [Yahya bin Abu Katsir] telah bercerita kepadaku [Hilal bin Abi Maimunah] bahwa ['Atho` bin Yasar] bercerita kepadanya bahwa ['Abdullah bin Salam] bercerita kepadanya atau ia berkata; Telah bercerita kepadaku [Abu Salamah bin 'Abdur Rahman] dari ['Abdullah bin Salam] berkata; Kami saling mengingat satu sama lain lalu kami berkata; Siapa diantara kalian yang ingin mendatangi Rasulullah Shallalahu 'alaihi wa sallamuntuk bertanya amalan apa yang paling dicintai Allah Subhaanahu wa Ta'ala, saat itu kami segan dan tidak ada seorang pun diantara kami berdiri lalu Rasulullah Shallalahu 'alaihi wa sallammengirim seseorang untuk menemui kami hingga ia mengumpulkan kami, kami saling menuding satu sama lain, lalu Rasulullah Shallalahu 'alaihi wa sallammembacakan kepada kami: SABBAHA LILLAAHI MAA FISSAMAAWAATI WA MAA FIL`ARDLI hingga firmanNya: KABURA MAQTAN 'INDALAAH. Berkata 'Abdullah bin Salam: Utusan Rasulullah Shallalahu 'alaihi wa sallam membaca dari awal hingga akhir. Berkata Yahya; Hilal membacakannya untuk kami dari awal hingga akhir. Berkata Al Auza'I; Yahya membacakannya untuk kami dari awal hingga akhir."},"3624":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى وَعَفَّانُ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنِ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ قَالَقَدِمْتُ الْمَدِينَةَ فَجَلَسْتُ إِلَى شِيَخَةٍ فِي مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ شَيْخٌ يَتَوَكَّأُ عَلَى عَصًا لَهُ فَقَالَ الْقَوْمُ مَنْ سَرَّهُ أَنْ يَنْظُرَ إِلَى رَجُلٍ مِنْ أَهْلِ الْجَنَّةِ فَلْيَنْظُرْ إِلَى هَذَا فَقَامَ خَلْفَ سَارِيَةٍ فَصَلَّى رَكْعَتَيْنِ فَقُمْتُ إِلَيْهِ فَقُلْتُ لَهُ قَالَ بَعْضُ الْقَوْمِ كَذَا وَكَذَا فَقَالَ الْجَنَّةُ لِلَّهِ عَزَّ وَجَلَّ يُدْخِلُهَا مَنْ يَشَاءُ وَإِنِّي رَأَيْتُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُؤْيَا رَأَيْتُ كَأَنَّ رَجُلًا أَتَانِي فَقَالَ انْطَلِقْ فَذَهَبْتُ مَعَهُ فَسَلَكَ بِي مَنْهَجًا عَظِيمًا فَعَرَضَتْ لِي طَرِيقٌ عَنْ يَسَارِي فَأَرَدْتُ أَنْ أَسْلُكَهَا فَقَالَ إِنَّكَ لَسْتَ مِنْ أَهْلِهَا ثُمَّ عَرَضَتْ لِي طَرِيقٌ عَنْ يَمِينِي فَسَلَكْتُهَا حَتَّى انْتَهَيْتُ إِلَى جَبَلٍ زَلِقٍ فَأَخَذَ بِيَدِي فَزَجَلَ بِي فَإِذَا أَنَا عَلَى ذُرْوَتِهِ فَلَمْ أَتَقَارَّ وَلَا أَتَمَاسَكْ فَإِذَا عَمُودٌ مِنْ حَدِيدٍ فِي ذُرْوَتِهِ حَلْقَةٌ مِنْ ذَهَبٍ فَأَخَذَ بِيَدِي فَزَجَلَ بِي حَتَّى أَخَذْتُ بِالْعُرْوَةِ فَقَالَ اسْتَمْسِكْ فَقُلْتُ نَعَمْ فَضَرَبَ الْعَمُودَ بِرِجْلِهِ فَاسْتَمْسَكْتُ بِالْعُرْوَةِ فَقَصَصْتُهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَأَيْتَ خَيْرًا أَمَّا الْمَنْهَجُ الْعَظِيمُ فَالْمَحْشَرُ وَأَمَّا الطَّرِيقُ الَّتِي عَرَضَتْ عَنْ يَسَارِكَ فَطَرِيقُ أَهْلِ النَّارِ وَلَسْتَ مِنْ أَهْلِهَا وَأَمَّا الطَّرِيقُ الَّتِي عَرَضَتْ عَنْ يَمِينِكَ فَطَرِيقُ أَهْلِ الْجَنَّةِ وَأَمَّا الْجَبَلُ الزَّلِقُ فَمَنْزِلُ الشُّهَدَاءِ وَأَمَّا الْعُرْوَةُ الَّتِي اسْتَمْسَكْتَ بِهَا فَعُرْوَةُ الْإِسْلَامِ فَاسْتَمْسِكْ بِهَا حَتَّى تَمُوتَ قَالَ فَأَنَا أَرْجُو أَنْ أَكُونَ مِنْ أَهْلِ الْجَنَّةِ قَالَ وَإِذَا هُوَ عَبْدُ اللَّهِ بْنُ سَلَامٍ","id":"Telah bercerita kepada kami [Hasan bin Musa] dan [Affan] keduanya berkata: Telah bercerita kepada kami [Hammad bin Salamah] dari ['Ashim bin Bahdalah] dari [Al Musayyib bin Rafi'] dari [Kharasyah bin Al Hurr] berkata; Aku datang ke Madinah lalu aku menghampiri seorang tua di masjid nabi shallallahu 'alaihi wasallam, kemudian orang tua lain datang dengan bertumpu pada tongkat miliknya, orang-orang berkata: Siapa yang ingin melihat salah seorang penghuni surga, silahkan lihat orang itu. Orang itu berdiri dibelakang tiang lalu shalat dua rakaat, aku menghampirinya lalu aku berkata: Sebagaian kaum berkata seperti ini dan itu. Orang itu berkata: Surga itu milik Allah 'azza wajalla, Ia memasukkan siapa saja yang dikehendaki ke sana, dulu aku pernah bermimpi dimasa Rasulullah shallallahu 'alaihi wasallam, aku bermimpi sepertinya ada seseorang mendatangiku lalu berkata; Ayo pergi. Aku pergi bersamanya, ia menempuh jalan besar bersamaku, di sebelah kiriku terbentang jalan lalu aku ingin melaluinya, orang itu berkata: Kau tidak termasuk pengikut jalan itu. Kemudian terbentang jalan di sebelah kananku, aku menempuh jalan itu hingga tiba disebuah gunung curam, orang itu meraih tanganku lalu mendorongku ternyata aku telah berada dipuncaknya, aku tidak memegangi apa pun ternyata ada tiang dari besi, ujungnya ada untaian emas lalu aku meraihnya, orang itu mendorongku hingga aku meraih tali itu, orang itu berkata: Peganglah tali itu. Aku berkata: Ya. Orang itu mendorong tiang itu dengan kakinya lalu aku berpegangan pada tali itu. Aku kemudian menceritakan mimpi itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Mimpimu baik, jalan besar itu adalah padang mahsyar, jalan yang terbentang di sebelah kirimu adalah jalan penghuni neraka dan engkau bukan pengikutnya, sedangkan jalan yang terbentang di sebelah kananmu adalah jalan penghuni surga, gunung curam itu adalah tempat para syuhada`, tali yang kau pegang itu adalah tali Islam, peganglah tali itu hingga kau mati.\" Ia berkata: Aku berharap menjadi penghuni surga. Berkata Kharasyah; Ternyata orang itu adalah ['Abdullah bin Salam]."},"3625":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ قَيْسِ بْنِ سَعْدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَدِمْتُ الشَّامَ فَلَقِيتُ كَعْبًا فَكَانَ يُحَدِّثُنِي عَنْ التَّوْرَاةِ وَأُحَدِّثُهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَتَيْنَا عَلَى ذِكْرِ يَوْمِ الْجُمُعَةِ فَحَدَّثْتُهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجُمُعَةِ سَاعَةً لَا يُوَافِقُهَا مُسْلِمٌ يَسْأَلُ اللَّهَ فِيهَا خَيْرًا إِلَّا أَعْطَاهُ إِيَّاهُ فَقَالَ كَعْبٌ صَدَقَ اللَّهُ وَرَسُولُهُ هِيَ فِي كُلِّ سَنَةٍ مَرَّةٌ قُلْتُ لَا فَنَظَرَ كَعْبٌ سَاعَةً ثُمَّ قَالَ صَدَقَ اللَّهُ وَرَسُولُهُ هِيَ فِي كُلِّ شَهْرٍ مَرَّةٌ قُلْتُ لَا فَنَظَرَ سَاعَةً فَقَالَ صَدَقَ اللَّهُ وَرَسُولُهُ فِي كُلِّ جُمُعَةٍ مَرَّةٌ قُلْتُ نَعَمْ فَقَالَ كَعْبٌ أَتَدْرِي أَيُّ يَوْمٍ هُوَ قُلْتُ وَأَيُّ يَوْمٍ هُوَ قَالَ فِيهِ خَلَقَ اللَّهُ آدَمَ وَفِيهِ تَقُومُ السَّاعَةُ وَالْخَلَائِقُ فِيهِ مُصِيخَةٌ إِلَّا الثَّقَلَيْنِ الْجِنَّ وَالْإِنْسَ خَشْيَةَ الْقِيَامَةِ فَقَدِمْتُ الْمَدِينَةَ فَأَخْبَرْتُ عَبْدَ اللَّهِ بْنَ سَلَامٍ بِقَوْلِ كَعْبٍ فَقَالَ كَذَبَ كَعْبٌ قُلْتُ إِنَّهُ قَدْ رَجَعَ إِلَى قَوْلِي فَقَالَ أَتَدْرِي أَيُّ سَاعَةٍ هِيَ قُلْتُ لَا وَتَهَالَكْتُ عَلَيْهِ أَخْبِرْنِي أَخْبِرْنِي فَقَالَ هِيَ فِيمَا بَيْنَ الْعَصْرِ وَالْمَغْرِبِ قُلْتُ كَيْفَ وَلَا صَلَاةَ قَالَ أَمَا سَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَزَالُ الْعَبْدُ فِي صَلَاةٍ مَا كَانَ فِي مُصَلَّاهُ يَنْتَظِرُ الصَّلَاةَ","id":"Telah bercerita kepada kami ['Affan] telah bercerita kepada kami [Hammad bin Salamah] dari [Qais bin Sa'ad] dari [Muhammad bin Ibrahim At Taimi] dari [Abu Salamah bin 'Abdur Rahman] dari [Abu Hurairah] berkata; Aku datang ke Syam lalu aku menemui Ka'ab, ia bercerita kepadaku tentang taurat dan aku bercerita kepadanya dari Rasulullah Shallalahu 'alaihi wa sallam hingga kami sampai pada pembahasan hari jum'at, aku menceritakannya dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya di hari jum'at ada saat tidaklah seroang muslim meminta kebaikan pada Allah di saat itu melainkan pasti diberi.\" Berkata Sa'ad: Maha Benar Allah dan rasulNya, itu setiap tahun sekali. Aku berkata: Tidak. Lalu Ka'ab menatap dan berkata: Maha Benar Allah dan rasulNya, itu setiap bulan sekali. Aku berkata: Tidak. Maha Benar Allah dan rasulNya, itu setiap pekan sekali. Aku berkata: Ya. Lalu Ka'ab berkata: Tahukah kami hari apa itu? Aku berkata: Itulah hari dimana Allah menciptakan Adam, terjadinya hari kiamat dan para makhluk mendengar saat itu kecuali jin dan manusia karena takut pada hari kiamat. Lalu aku tiba di Madinah kemudian aku menyampaikan khabar kepada ['Abdullah bin Salam] tentang perkataan Ka'ab, lalu ia berkata; Ka'ab berdusta. Aku berkata: Ia menarik ucapannya dan berpegangan pada ucapanku. Berkata 'Abdullah bin Salam: Tahukah kau, kapankah saat itu? Aku berkata: Tidak, dan aku lelah karenanya, beritahukan padaku, beritahukan padaku. Berkata 'Abdullah bin Salam: Itu adalah saat antara ashar dan maghrib. Aku berkata: Bagaimana bisa, tidak ada shalat diantaranya. Berkata 'Abdullah bin Salam: Apa kau tidak mendengar nabi Shallalahu 'alaihi wa sallambersabda: \"Seorang hamba senantiasa berada dalam shalat selama ia berada ditempat shalatnya seraya menunggu shalat.\""},"3626":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبِي مِنْ كِتَابِهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا رَبَاحُ بْنُ زَيْدٍ حَدَّثَنِي عُمَرُ بْنُ حَبِيبٍ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ قَالَدَخَلْتُ عَلَى أَبِي الطُّفَيْلِ فَوَجَدْتُهُ طَيِّبَ النَّفْسِ فَقُلْتُ لَأَغْتَنِمَنَّ ذَلِكَ مِنْهُ فَقُلْتُ يَا أَبَا الطُّفَيْلِ النَّفَرُ الَّذِينَ لَعَنَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَيْنِهِمْ مَنْ هُمْ فَهَمَّ أَنْ يُخْبِرَنِي بِهِمْ فَقَالَتْ لَهُ امْرَأَةٌ سَوْدَاءُ مَهْ يَا أَبَا الطُّفَيْلِ أَمَا بَلَغَكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ إِنَّمَا أَنَا بَشَرٌ فَأَيُّمَا عَبْدٍ مِنْ الْمُؤْمِنِينَ دَعَوْتُ عَلَيْهِ دَعْوَةً فَاجْعَلْهَا لَهُ زَكَاةً وَرَحْمَةً","id":"Telah bercerita kepada kami Abdullah telah bercerita kepadaku ayahku dari kitabnya; telah bercerita kepada kami [Ibrahim bin Khalid] telah bercerita kepada kami [Rabah bin Zaid] telah bercerita kepadaku ['Umar bin Habib] dari ['Abdullah bin 'Utsman bin Khutsaim] berkata: Aku bertamu ke kediaman Abu Ath Thufail ternyata ia tengah bergembira, aku berkata (dihati): Aku akan mendapatkannya darinya. Aku berkata: Wahai Abu Ath Thufail, orang-orang yang dilaknat Rasulullah shallallahu 'alaihi wasallam, siapa diantara mereka? Ia hendak memberitahukanku siapakah mereka kemudian [seoarang wanita hitam] berkata padanya: Diam kamu wahai Abu Thufail, apakah kau tidak mendengar bahwa Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ya Allah, sesungguhnya aku hanya manusia biasa, siapapun orang beriman yang aku doakan keburukan maka jadikanlah doa itu sebagai pembersih dan rahmat.\""},"3627":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ أَبِي الطُّفَيْلِ قَالَلَمَّا بُنِيَ الْبَيْتُ كَانَ النَّاسُ يَنْقُلُونَ الْحِجَارَةَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْقُلُ مَعَهُمْ فَأَخَذَ الثَّوْبَ فَوَضَعَهُ عَلَى عَاتِقِهِ فَنُودِيَ لَا تَكْشِفْ عَوْرَتَكَ فَأَلْقَى الْحَجَرَ وَلَبِسَ ثَوْبَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah bercerita kepada kami [Ma'mar] dari ['Abdullah bin 'Utsman bin Khutsaim] dari [Abu Ath Thufail] berkata; Saat baitullah dibangun, orang-orang memindahkan batu, nabi Shallalahu 'alaihi wa sallam turun memindahkan batu bersama mereka, beliau mengambil baju lalu diletakkan diatas punggung beliau, beliau dipanggil: Jangan kau buka auratmu, lalu beliau membuang batu dan mengenakan pakaian."},"3628":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ حَدَّثَنَا عُثْمَانُ بْنُ عُبَيْدٍ الرَّاسِبِيُّ قَالَ سَمِعْتُ أَبَا الطُّفَيْلِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نُبُوَّةَ بَعْدِي إِلَّا الْمُبَشِّرَاتِ قَالَ قِيلَ وَمَا الْمُبَشِّرَاتُ يَا رَسُولَ اللَّهِ قَالَ الرُّؤْيَا الْحَسَنَةُ أَوْ قَالَ الرُّؤْيَا الصَّالِحَةُ","id":"Telah bercerita kepada kami [Yunus bin Muhammad] telah bercerita kepada kami [Hammad bin Zaid] telah bercerita kepada kami ['Utsman bin 'Ubaid Ar Rasibi] berkata: Aku mendengar [Abu Ath Thufail] berkata: Rasulullah Shallalahu 'alaihi wa sallambersabda: \"Tidak ada kenabian setelahku kecuali berita gembira-berita gembira.\" Beliau ditanya: Apa itu berita gembira-berita gembira? Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Mimpi baik.\""},"3629":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا الْجُرَيْرِيُّ قَالَكُنْتُ أَطُوفُ مَعَ أَبِي الطُّفَيْلِ فَقَالَ مَا بَقِيَ أَحَدٌ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرِي قَالَ قُلْتُ وَرَأَيْتَهُ قَالَ نَعَمْ قَالَ قُلْتُ كَيْفَ كَانَ صِفَتُهُ قَالَ كَانَ أَبْيَضَ مَلِيحًا مُقْصِدًا","id":"Telah bercerita kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Al Jurairi] berkata; Aku pernah berthawaf bersama [Abu Ath Thufail], ia berkata: Tidak terisa lagi seorang pun yang pernah melihat Rasulullah Shallalahu 'alaihi wa sallam selain aku. Aku berkata: Kau pernah melihat beliau? Ia menjawab: Ya. Aku bertanya: Bagaimana cirri-ciri beliau? Ia menjawab: Beliau putih, rupawan dan sederhana."},"3630":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مَعْرُوفٌ الْمَكِّيُّ قَالَ سَمِعْتُ أَبَا الطُّفَيْلِ عَامِرَ بْنَ وَاثِلَةَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا غُلَامٌ شَابٌّ يَطُوفُ بِالْبَيْتِ عَلَى رَاحِلَتِهِ يَسْتَلِمُ الْحَجَرَ بِمِحْجَنِهِ","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Ma'ruf Al Makki] berkata; Aku mendengar [Abu Ath Thufail 'Amir bin Watsilah] berkata: Aku melihat Rasulullah shallallahu 'alaihi wasallam, saat itu aku masih muda, beliau berthawaf di sekitar ka'bah diatas kendaraan beliau, beliau menyentuh hajar aswad dengan tongkat yang berkeluk."},"3631":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ خُثَيْمٍ عَنْ أَبِي الطُّفَيْلِوَذَكَرَ بِنَاءَ الْكَعْبَةِ فِي الْجَاهِلِيَّةِ قَالَ فَهَدَمَتْهَا قُرَيْشٌ وَجَعَلُوا يَبْنُونَهَا بِحِجَارَةِ الْوَادِي تَحْمِلُهَا قُرَيْشٌ عَلَى رِقَابِهَا فَرَفَعُوهَا فِي السَّمَاءِ عِشْرِينَ ذِرَاعًا فَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْمِلُ حِجَارَةً مِنْ أَجْيَادٍ وَعَلَيْهِ نَمِرَةٌ فَضَاقَتْ عَلَيْهِ النَّمِرَةُ فَذَهَبَ يَضَعُ النَّمِرَةَ عَلَى عَاتِقِهِ فَيُرَى عَوْرَتُهُ مِنْ صِغَرِ النَّمِرَةِ فَنُودِيَ يَا مُحَمَّدُ خَمِّرْ عَوْرَتَكَ فَلَمْ يُرَى عُرْيَانًا بَعْدَ ذَلِكَ","id":"Telah bercerita kepada kami ['Abdur Razzaq] telah memberitakan kepada kami [Ma'mar] dari [Ibnu Khutsaim] dari [Abu Ath Thufail] ia menyebutkan kisah pembangunan ka'bah di masa jahiliyah. Kaum Quraisy meruntuhkannya dan mereka membangunnya dengan bebatuan lembah yang diusung oleh kaum Quraisy dengan pundak-pundak mereka, mereka meninggikannya hingga mencapai duapuluh dzira'. Saat nabi Shallalahu 'alaihi wa sallam membawa batu lembah, beliau mengenakan baju panjang lalu bajunya menyempit hingga naik sebatas punggung sehingga aurat beliau terlihat karena kecilnya baju, diserukan: Hai Muhammad, tutupi auratmu. Setelah itu beliau tidak pernah terlihat telanjang lagi."},"3632":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَبِي الطُّفَيْلِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُ فِيمَا يَرَى النَّائِمُ كَأَنِّي أَنْزِعُ أَرْضًا وَرَدَتْ عَلَيَّ وَغَنَمٌ سُودٌ وَغَنَمٌ عُفْرٌ فَجَاءَ أَبُو بَكْرٍ فَنَزَعَ ذَنُوبًا أَوْ ذَنُوبَيْنِ وَفِيهِمَا ضَعْفٌ وَاللَّهُ يَغْفِرُ لَهُ ثُمَّ جَاءَ عُمَرُ فَنَزَعَ فَاسْتَحَالَتْ غَرْبًا فَمَلَأَ الْحَوْضَ وَأَرْوَى الْوَارِدَةَ فَلَمْ أَرَ عَبْقَرِيًّا أَحْسَنَ نَزْعًا مِنْ عُمَرَ فَأَوَّلْتُ أَنَّ السُّودَ الْعَرَبُ وَأَنَّ الْعُفْرَ الْعَجَمُ","id":"Telah bercerita kepada kami ['Abdush Shamad] telah bercerita kepada kami [Hammad bin Salamah] telah bercerita kepada kami ['Ali bin Zaid] dari [Abu Ath Thufail] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Aku bermimpi seperti yang dimimpikan orang tidur, sepertinya aku menarik sebidang tanah yang menghampiriku beserta kambing berwarna hitam dan kambing lusuh, lalu Abu Bakar datang dan menarik satu atau dua timba berisi air penuh, ia lemah menarik keduanya dan Allah mengampuninya lalu 'Umar datang dan menarik lalu ia beralih menghadap ke barat, ia memenuhi telaga dan memberi minum yang datang. Aku tidak melihat pemimpin yang lebih baik tarikannya seperti 'Umar, lalu aku mengartian kambing berwarna hitam sebagai bangsa arab dan kambing lusuh adalah bangsa ajam.\""},"3633":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا عَبْدُ اللَّهِ ابْنُ الْمُبَارَكِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ قَالَ سَمِعْتُ أَبَا الطُّفَيْلِ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَلَ مِنْ الْحَجَرِ إِلَى الْحَجَرِ","id":"Telah bercerita kepada kami [Yahya bin Adam] telah bercerita kepada kami ['Abdullah bin Al Mubarak] dari ['Ubaidullah bin Abu Ziyad] berkata: Aku mendengar [Abu Ath Thufail] bercerita bahwa Rasulullah Shallalahu 'alaihi wa sallam berlari kecil dari hajar aswad ke hajar aswad."},"3634":{"ar":"حَدَّثَنَا يُونُسُ وَعَفَّانُ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَبِي الطُّفَيْلِأَنَّ رَجُلًا وُلِدَ لَهُ غُلَامٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ بِبَشَرَةِ وَجْهِهِ وَدَعَا لَهُ بِالْبَرَكَةِ قَالَ فَنَبَتَتْ شَعَرَةٌ فِي جَبْهَتِهِ كَهَيْئَةِ الْقَوْسِ وَشَبَّ الْغُلَامُ فَلَمَّا كَانَ زَمَنُ الْخَوَارِجِ أَحَبَّهُمْ فَسَقَطَتْ الشَّعَرَةُ عَنْ جَبْهَتِهِ فَأَخَذَهُ أَبُوهُ فَقَيَّدَهُ وَحَبَسَهُ مَخَافَةَ أَنْ يَلْحَقَ بِهِمْ قَالَ فَدَخَلْنَا عَلَيْهِ فَوَعَظْنَاهُ وَقُلْنَا لَهُ فِيمَا نَقُولُ أَلَمْ تَرَ أَنَّ بَرَكَةَ دَعْوَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ وَقَعَتْ عَنْ جَبْهَتِكَ فَمَا زِلْنَا بِهِ حَتَّى رَجَعَ عَنْ رَأْيِهِمْ فَرَدَّ اللَّهُ عَلَيْهِ الشَّعَرَةَ بَعْدُ فِي جَبْهَتِهِ وَتَابَ","id":"Telah bercerita kepada kami [Yunus] dan ['Affan] keduanya berkata: telah bercerita kepada kami [Hammad bin Salamah] dari ['Ali bin Zaid] dari [Abu Ath Thufail] bahwa seseorang memiliki anak dimasa Rasulullah Shallalahu 'alaihi wa sallam lalu ia mendatangi nabi shallallahu 'alaihi wasallam, beliau membeslah kulit wajahnya dan mendoakan keberkahan baginya kemudian tumbuh bulu didahinya seperti panah dan anak itu pun tumbuh menjadi pemuda. Dimasa khawarij, ia menyukai mereka lalu satu bulu dari dahinya rontok kemudian ayahnya mengambil pemuda itu dan menahannya karena khawatir akan menemui mereka. Kami menjenguknya, kami menasehatinya dan kami berkata padanya: Apa kau tidak tahu bahwa berkah doa Rasulullah Shallalahu 'alaihi wa sallamtelah runtuh dari dahimu. Kami tetap berada didekatnya ingga ia menarik pendapat mereka kemudian Allah mengembalikan lagi bulunya di dahinya dan bertaubat."},"3635":{"ar":"حَدَّثَنَا يَعْمَرُ بْنُ بِشْرٍ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ مُبَارَكٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي زِيَادٍ قَالَ سَمِعْتُ أَبَا الطُّفَيْلِ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَلَ ثَلَاثًا مِنْ الْحَجَرِ إِلَى الْحَجَرِ","id":"Telah bercerita kepada kami [Ya'mar bin Bisyr] telah bercerita kepada kami ['Abdullah bin Mubarak] telah bercerita kepada kami ['Ubaidullah bin Abu Ziyad] berkata; Aku mendengar [Abu Ath Thufail] berkata: Rasulullah Shallalahu 'alaihi wa sallamberlari-lari kecil dari hajar aswad ke hajar aswad sebanyak tiga kali."},"3636":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ الْأَشْجَعِي��ِ عَنْ أَبِيهِ قَالَدَفَعَ إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنَةَ أُمِّ سَلَمَةَ وَقَالَ إِنَّمَا أَنْتَ ظِئْرِي قَالَ فَمَكَثَ مَا شَاءَ اللَّهُ ثُمَّ أَتَيْتُهُ فَقَالَ مَا فَعَلَتْ الْجَارِيَةُ أَوْ الْجُوَيْرِيَةُ قَالَ قُلْتُ عِنْدَ أُمِّهَا قَالَ فَمَجِيءُ مَا جِئْتَ قَالَ قُلْتُ تُعَلِّمُنِي مَا أَقُولُ عِنْدَ مَنَامِي فَقَالَ اقْرَأْ عِنْدَ مَنَامِكَ قُلْ يَا أَيُّهَا الْكَافِرُونَ قَالَ ثُمَّ نَمْ عَلَى خَاتِمَتِهَا فَإِنَّهَا بَرَاءَةٌ مِنْ الشِّرْكِ","id":"Telah bercerita kepada kami [Yahya bin Adam] telah bercerita kepada kami [Isra`il] dari [Abu Ishaq] dari [Farwah bin Naufal Al Asyja`i] dari [ayahnya] berkata: Nabi Shallalahu 'alaihi wa sallammemberikan kepadaku anak perempuan Ummu Salamah dan bersabda: \"Kamu adalah pengasuhku.\" Naufal berkata: Rasulullah Shallalahu 'alaihi wa sallam diam sejenak kemudian saya datang kepadanya dan beliau bertanya: \"Bagaiamana kondisi anak perempuan itu?\" Naufal menjawab: Dia bersama ibunya. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Apa maksud kedatanganmu?\" Naufal berkata: Ajarkan kepadaku apa yang harus saya katakan ketika beranjak tidur. Rasulullah Shallalahu 'alaihi wa sallambersabda: \"Bacalah ketika kau hendak tidur: QUL YAA AYYUHAL KAAFIRUUN, kemudian tidurlah setelah membaca penutupnya karena yang demikian itu adalah pembebasan diri dari kesyirikan.\""},"3637":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنِ الْمِقْدَادِ بْنِ الْأَسْوَدِ قَالَقَالَ لِي عَلِيٌّ سَلْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُلَاعِبُ أَهْلَهُ فَيَخْرُجُ مِنْهُ الْمَذْيُ مِنْ غَيْرِ مَاءِ الْحَيَاةِ فَلَوْلَا أَنَّ ابْنَتَهُ تَحْتِي لَسَأَلْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ الرَّجُلُ يُلَاعِبُ أَهْلَهُ فَيَخْرُجُ مِنْهُ الْمَذْيُ مِنْ غَيْرِ مَاءِ الْحَيَاةِ قَالَ يَغْسِلُ فَرْجَهُ وَيَتَوَضَّأُ وُضُوءَهُ لِلصَّلَاةِ","id":"Telah bercerita kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Muhammad bin Ishaq] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Al Miqdad bin Al Aswad] berkata; 'Ali berkata kepadaku; Tanyakan kepada Rasulullah Shallalahu 'alaihi wa sallamtentang seseorang yang mencumbu istrinya lalu keluar air madzi, bukan air mani, andai istriku bukan putri beliau pasti aku bertanya pada beliau. Aku berkata: Wahai Rasulullah, seseorang mencumbu istrinya lalu mengeluarkan air madzi, bukan air mani. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ia harus membasuh kelamuannya dan berwudlu seperti wudlu untuk shalat.\""},"3638":{"ar":"حَدَّثَنَا يَزِيدُ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنِ الْمِقْدَادِ بْنِ الْأَسْوَدِ قَالَقَدِمْتُ أَنَا وَصَاحِبَانِ لِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَصَابَنَا جُوعٌ شَدِيدٌ فَتَعَرَّضْنَا لِلنَّاسِ فَلَمْ يُضِفْنَا أَحَدٌ فَانْطَلَقَ بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَنْزِلِهِ وَعِنْدَهُ أَرْبَعُ أَعْنُزٍ فَقَالَ لِي يَا مِقْدَادُ جَزِّئْ أَلْبَانَهَا بَيْنَنَا أَرْبَاعًا فَكُنْتُ أُجَزِّئُهُ بَيْنَنَا أَرْبَاعًا فَاحْتَبَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَحَدَّثْتُ نَفْسِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَتَى بَعْضَ الْأَنْصَارِ فَأَكَلَ حَتَّى شَبِعَ وَشَرِبَ حَتَّى رَوِيَ فَلَوْ شَرِبْتُ نَصِيبَهُ فَلَمْ أَزَلْ كَذَلِكَ حَتَّى قُمْتُ إِلَى نَصِيبِهِ فَشَرِبْتُهُ ثُمَّ غَطَّيْتُ الْقَدَحَ فَلَمَّا فَرَغْتُ أَخَذَنِي مَا قَدُمَ وَمَا حَدُثَ فَقُلْتُ يَجِيءُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَائِعًا وَلَا يَجِدُ شَيْئًا فَتَسَجَّيْتُ وَجَعَلْتُ أُحَدِّثُ نَفْسِي فَبَيْنَا أَنَا كَذَلِكَ إِذْ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ تَسْلِيمَةً يُسْمِعُ الْيَقْظَانَ وَلَا يُوقِظُ النَّائِمَ ثُمَّ أَتَى الْقَدَحَ فَكَشَفَهُ فَلَمْ يَرَ شَيْئًا فَقَالَ اللَّهُمَّ أَطْعِمْ مَنْ أَطْعَمَنِي وَاسْقِ مَنْ سَقَانِي وَاغْتَنَمْتُ الدَّعْوَةَ فَقُمْتُ إِلَى الشَّفْرَةِ فَأَخَذْتُهَا ثُمَّ أَتَيْتُ الْأَعْنُزَ فَجَعَلْتُ أَجْتَسُّهَا أَيُّهَا أَسْمَنُ فَلَا تَمُرُّ يَدَيَّ عَلَى ضَرْعِ وَاحِدَةٍ إِلَّا وَجَدْتُهَا حَافِلًا فَحَلَبْتُ حَتَّى مَلَأْتُ الْقَدَحَ ثُمَّ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ اشْرَبْ يَا رَسُولَ اللَّهِ فَرَفَعَ رَأْسَهُ إِلَيَّ فَقَالَ بَعْضُ سَوْآتِكَ يَا مِقْدَادُ مَا الْخَبَرُ قُلْتُ اشْرَبْ ثُمَّ الْخَبَرَ فَشَرِبَ حَتَّى رَوِيَ ثُمَّ نَاوَلَنِي فَشَرِبْتُ فَقَالَ مَا الْخَبَرُ فَأَخْبَرْتُهُ فَقَالَ هَذِهِ بَرَكَةٌ نَزَلَتْ مِنْ السَّمَاءِ فَهَلَّا أَعْلَمْتَنِي حَتَّى نَسْقِيَ صَاحِبَيْنَا فَقُلْتُ إِذَا أَصَابَتْنِي وَإِيَّاكَ الْبَرَكَةُ فَمَا أُبَالِي مَنْ أَخْطَأَتْ","id":"Telah bercerita kepada kami [Yazid] telah memberitakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari ['Abdur Rahman bin Abu Laila] dari [Al Miqdad bin Al Aswad] berkata: Aku bersama dua temanku mendatangi Rasulullah shallallahu 'alaihi wasallam, kami sangat lapar sekali, kami mendatangi orang-orang tapi tidak ada seorang pun yang menjamu kami lalu Rasulullah Shallalahu 'alaihi wa sallampergi bersama kami ke rumah beliau, beliau memiliki empat ekor kambing lalu beliau bersabda kepadaku: \"Wahai Miqdad, perahlah susu-susunya untuk kami berempat.\" Aku memerahnya untuk kami berempat. Pada suatu malam Rasulullah Shallalahu 'alaihi wa sallamtidak datang, hatiku berkata beliau mendatangi sebagian orang Anshar lalu beliau makan hingga kenyang dan minum sampai puas, andai saja aku meminum bagian beliau. Aku terus seperti itu hingga aku mendatangi bagian beliau lalu aku meminumnya lalu aku menutupi gelas itu. Seusainya aku tersadar dengan apa yang terjadi. Aku berkata dalam hatiku: Rasulullah Shallalahu 'alaihi wa sallam datang dalam keadaan lapar dan beliau tidak punya apa-apa. Aku berusaha tenang dan aku pun berkata dalam hatiku. Saat aku seperti itu tiba-tiba Rasulullah Shallalahu 'alaihi wa sallam masuk, beliau mengucapkan salam dengan suara yang bisa didengar oleh orang yang terjaga namun tidak bisa membangungkan orang tidur. Beliau mendekati gelas, beliau membukanya namun beliau tidak melihat apa pun, Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ya Allah, berilah makanan orang yang memberiku makan, dan berilah minum orang yang memberiku minum.\" Aku pun mendapatkan doa Rasulullah Shallalahu 'alaihi wa sallamlalu aku mengambil parang dan mendatangi kambing-kambingku, aku pun melihat dengan seksama mana diantaranya yang paling gemuk. Tidaklah tanganku melintasi satu pun kantung susu kambing melainkan pasti berisi penuh susu. Aku pun memeras hingga sepenuh gelas besar lalu aku mendatangi Rasulullah shallallahu 'alaihi wasallam, aku berkata: Silahkan Tuan minum wahai Rasulullah shallallahu 'alaihi wasallam. Beliau menengadahkan kepada ke arahku, Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Tunggu dulu wahai Miqdad, ada berita apa.\" Aku berkata: Silahkan Tuan minum, setelah itu baru aku beritahu. Beliau minum hingga puas lalu beliau memberikan gelas itu padaku, aku pun minum. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ada khabar apa?\" lalu aku memberitahu beliau. Beliau bersabda: \"Ini adalah berkah yang turun dari langit, bukankah kau tadi memberitahu kami supaya kami bisa memberi minum kedua teman kami.\" Aku berkata: Bila berkah turun padaku dan Tuan, aku tidak perduli siapa pun yang tidak kebagian."},"3639":{"ar":"حَدَّثَنَا يَعْمَرُ بْنُ بِشْرٍ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ أَنْبَأَنَا صَفْوَانُ بْنُ عَمْرٍو حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ قَالَجَلَسْنَا إِلَى الْمِقْدَادِ بْنِ الْأَسْوَدِ يَوْمًا فَمَرَّ بِهِ رَجُلٌ فَقَالَ طُوبَى لِهَاتَيْنِ الْعَيْنَيْنِ اللَّتَيْنِ رَأَتَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ لَوَدِدْنَا أَنَّا رَأَيْنَا مَا رَأَيْتَ وَشَهِدْنَا مَا شَهِدْتَ فَاسْتُغْضِبَ فَجَعَلْتُ أَعْجَبُ مَا قَالَ إِلَّا خَيْرًا ثُمَّ أَقْبَلَ إِلَيْهِ فَقَالَ مَا يَحْمِلُ الرَّجُلُ عَلَى أَنْ يَتَمَنَّى مَحْضَرًا غَيَّبَهُ اللَّهُ عَنْهُ لَا يَدْرِي لَوْ شَهِدَهُ كَيْفَ كَانَ يَكُونُ فِيهِ وَاللَّهِ لَقَدْ حَضَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْوَامٌ أَكَبَّهُمْ اللَّهُ عَلَى مَنَاخِرِهِمْ فِي جَهَنَّمَ لَمْ يُجِيبُوهُ وَلَمْ يُصَدِّقُوهُ أَوَلَا تَحْمَدُونَ اللَّهَ إِذْ أَخْرَجَكُمْ لَا تَعْرِفُونَ إِلَّا رَبَّكُمْ مُصَدِّقِينَ لِمَا جَاءَ بِهِ نَبِيُّكُمْ قَدْ كُفِيتُمْ الْبَلَاءَ بِغَيْرِكُمْ وَاللَّهِ لَقَدْ بَعَثَ اللَّهُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَشَدِّ حَالٍ بُعِثَ عَلَيْهَا نَبِيٌّ مِنْ الْأَنْبِيَاءِ فِي فَتْرَةٍ وَجَاهِلِيَّةٍ مَا يَرَوْنَ أَنَّ دِينًا أَفْضَلُ مِنْ عِبَادَةِ الْأَوْثَانِ فَجَاءَ بِفُرْقَانٍ فَرَقَ بِهِ بَيْنَ الْحَقِّ وَالْبَاطِلِ وَفَرَّقَ بَيْنَ الْوَالِدِ وَوَلَدِهِ حَتَّى إِنْ كَانَ الرَّجُلُ لَيَرَى وَالِدَهُ وَوَلَدَهُ أَوْ أَخَاهُ كَافِرًا وَقَدْ فَتَحَ اللَّهُ قُفْلَ قَلْبِهِ لِلْإِيمَانِ يَعْلَمُ أَنَّهُ إِنْ هَلَكَ دَخَلَ النَّارَ فَلَا تَقَرُّ عَيْنُهُ وَهُوَ يَعْلَمُ أَنَّ حَبِيبَهُ فِي النَّارِ وَأَنَّهَا لَلَّتِي قَالَ عَزَّ وَجَلَّ{ الَّذِينَ يَقُولُونَ رَبَّنَا هَبْ لَنَا مِنْ أَزْوَاجِنَا وَذُرِّيَّاتِنَا قُرَّةَ أَعْيُنٍ }","id":"Telah bercerita kepada kami [Ya'mur bin Bisyr] telah bercerita kepada kami ['Abdullah bin Al Mubarok] telah memberitakan kepada kami [Shafwan bin 'Amru] telah bercerita kepadaku ['Abdur Rahman bin Jubair bin Nufair] dari [ayahnya] berkata; Kami menemani [Al Miqdad bin Al Aswad] pada suatu hari lalu seseorang melewatinya, ia berkata; Alangkah beruntungnya dua mata yang pernah melihat Rasulullah shallallahu 'alaihi wasallam, kami ingin melihat seperti yang engkau lihat, menyaksikan seperti yang kau saksikan. Al Miqdad dibuat marah lalu ia terkesima dengan kebaikan yang diucapkan lalu ia menghampirinya Al Miqdad, ia berkata: Apa gerangan yang membuat orang itu mengharapkan sesuatu yang telah terjadi yang telah disembunyikan Allah darinya, ia tidak tahu andai ia menyaksikan bagaimana bila ia ada disana, demi Allah, beberapa kaum yang ditelungkupkan Allah diatas hidung mereka di neraka jahanam pernah mendatangi Rasulullah shallallahu 'alaihi wasallam, mereka tidak menerima seruan nabi Shallalahu 'alaihi wa sallam dan tidak membenarkan beliau, kenapa kalian tidak memuji Allah Subhaanahu wa Ta'ala saat kalian lahir kalian hanya mengenal Rabb kalian dan membenarkan yang dibawa nabi kalian, kalian telah dilindungi dari bencana yang menimpa orang lain selain kalian. Demi Allah, Allah Subhaanahu wa Ta'ala mengutus nabi Shallalahu 'alaihi wa sallam dalam kondisi yang sangat sulit untuk seorang nabi, disuatu masa dan kejahiliyahan, mereka tidak menilai agama lebih baik dari paganisme, beliau datang membawa al-Qur'an, dengannya beliau membedakan antara yang haq dan yang batil, membedakan antara orang tua dan anak hingga seseorang menilai orang tua, anak atau saudaranya sebagai orang kafir dan Allah Subhaanahu wa Ta'ala telah membuka kunci hatinya untuk keimanan, ia tahu bila ia mati akan masuk neraka sehingga hatinya tidak tenang karena tahu orang tercintanya berada di neraka dan itulah yang difirmankan Allah 'azza wajalla: \"Ya Rabb kami, anugerahkanlah kepada kami isteri-isteri kami dan keturunan kami sebagai penyenang hati (Kami), dan jadikanlah kami imam bagi orang-orang yang bertakwa.\" (Al-Furqaan: 74) "},"3640":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْمِقْدَادِ قَالَأَقْبَلْتُ أَنَا وَصَاحِبَانِ لِي قَدْ ذَهَبَتْ أَسْمَاعُنَا وَأَبْصَارُنَا مِنْ الْجَهْدِ قَالَ فَجَعَلْنَا نَعْرِضُ أَنْفُسَنَا عَلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ أَحَدٌ يَقْبَلُنَا قَالَ فَانْطَلَقْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقَ بِنَا إِلَى أَهْلِهِ فَإِذَا ثَلَاثُ أَعْنُزٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَلِبُوا هَذَا اللَّبَنَ بَيْنَنَا قَالَ فَكُنَّا نَحْتَلِبُ فَيَشْرَبُ كُلُّ إِنْسَانٍ نَصِيبَهُ وَنَرْفَعُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَصِيبَهُ فَيَجِيءُ مِنْ اللَّيْلِ فَيُسَلِّمُ تَسْلِيمًا لَا يُوقِظُ نَائِمًا وَيُسْمِعُ الْيَقْظَانَ ثُمَّ يَأْتِي الْمَسْجِدَ فَيُصَلِّي ثُمَّ يَأْتِي شَرَابَهُ فَيَشْرَبُهُ قَالَ فَأَتَانِي الشَّيْطَانُ ذَاتَ لَيْلَةٍ فَقَالَ مُحَمَّدٌ يَأْتِي الْأَنْصَارَ فَيُتْحِفُونَهُ وَيُصِيبُ عِنْدَهُمْ مَا بِهِ حَاجَةٌ إِلَى هَذِهِ الْجُرْعَةِ فَاشْرَبْهَا قَالَ مَا زَالَ يُزَيِّنُ لِي حَتَّى شَرِبْتُهَا فَلَمَّا وَغَلَتْ فِي بَطْنِي وَعَرَفَ أَنَّهُ لَيْسَ إِلَيْهَا سَبِيلٌ قَالَ نَدَّمَنِي فَقَالَ وَيْحَكَ مَا صَنَعْتَ شَرِبْتَ شَرَابَ مُحَمَّدٍ فَيَجِيءُ وَلَا يَرَاهُ فَيَدْعُو عَلَيْكَ فَتَهْلِكَ فَتَذْهَبُ دُنْيَاكَ وَآخِرَتُكَ قَالَ وَعَلَيَّ شَمْلَةٌ مِنْ صُوفٍ كُلَّمَا رَفَعْتُهَا عَلَى رَأْسِي خَرَجَتْ قَدَمَايَ وَإِذَا أَرْسَلْتُ عَلَى قَدَمَيَّ خَرَجَ رَأْسِي وَجَعَلَ لَا يَجِيءُ لِي نَوْمٌ قَالَ وَأَمَّا صَاحِبَايَ فَنَامَا فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ كَمَا كَانَ يُسَلِّمُ ثُمَّ أَتَى الْمَسْجِدَ فَصَلَّى فَأَتَى شَرَابَهُ فَكَشَفَ عَنْهُ فَلَمْ يَجِدْ فِيهِ شَيْئًا فَرَفَعَ رَأْسَهُ إِلَى السَّمَاءِ قَالَ قُلْتُ الْآنَ يَدْعُو عَلَيَّ فَأَهْلِكُ فَقَالَ اللَّهُمَّ أَطْعِمْ مَنْ أَطْعَمَنِي وَاسْقِ مَنْ سَقَانِي قَالَ فَعَمَدْتُ إِلَى الشَّمْلَةِ فَشَدَدْتُهَا لِي فَأَخَذْتُ الشَّفْرَةَ فَانْطَلَقْتُ إِلَى الْأَعْنُزِ أَجُسُّهُنَّ أَيُّهُنَّ أَسْمَنُ فَأَذْبَحُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُنَّ حُفَّلٌ كُلُّهُنَّ فَعَمَدْتُ إِلَى إِنَاءٍ لِآلِ مُحَمَّدٍ مَا كَانُوا يَطْمَعُونَ أَنْ يَحْلِبُوا فِيهِ وَقَالَ أَبُو النَّضْرِ مَرَّةً أُخْرَى أَنْ يَحْتَلِبُوا فِيهِ فَحَلَبْتُ فِيهِ حَتَّى عَلَتْهُ الرَّغْوَةُ ثُمَّ جِئْتُ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَمَا شَرِبْتُمْ شَرَابَكُمْ اللَّيْلَةَ يَا مِقْدَادُ قَالَ قُلْتُ اشْرَبْ يَا رَسُولَ اللَّهِ فَشَرِبَ ثُمَّ نَاوَلَنِي فَقُلْتُ يَا رَسُولَ اللَّهِ اشْرَبْ فَشَرِبَ ثُمَّ نَاوَلَنِي فَأَخَذْتُ مَا بَقِيَ فَشَرِبْتُ فَلَمَّا عَرَفْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ رَوِيَ فَأَصَابَتْنِي دَعْوَتُهُ ضَحِكْتُ حَتَّى أُلْقِيتُ إِلَى الْأَرْضِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى سَوْآتِكَ يَا مِقْدَادُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ كَانَ مِنْ أَمْرِي كَذَا صَنَعْتُ كَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا كَانَتْ هَذِهِ إِلَّا رَحْمَةً مِنْ اللَّهِ أَلَا كُنْتَ آذَنْتَنِي نُوقِظُ صَاحِبَيْكَ هَذَيْنِ فَيُصِيبَانِ مِنْهَا قَالَ قُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أُبَالِي إِذَا أَصَبْتَهَا وَأَصَبْتُهَا مَعَكَ مَنْ أَصَابَهَا مِنْ النَّاسِ","id":"Telah bercerita kepada kami [Hasyim bin Al Qasim] telah bercerita kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari ['Abdur Rahman bin Abu Laila] dari [Al Miqdad] berkata; Aku bersama dua temanku, saat itu pendengaran dan penglihatan kami sudah tidak ada karena kelelahan, kami mendatangi para sahabat Rasulullah Shallalahu 'alaihi wa sallam tapi tidak ada seorang pun yang menjamu kami, lalu kami pergi menemui Rasulullah Shallalahu 'alaihi wa sallamkemudian beliau pergi bersama kami ke rumah istri beliau, beliau memiliki tiga ekor kambing lalu beliau bersabda: \"Perahlah susu-susunya untuk kami.\" Kami memerahnya lalu masing-masing dari kami meminum bagiannya kemudian kami angkat bagian untuk Rasulullah shallallahu 'alaihi wasallam. Pada suatu malam Rasulullah Shallalahu 'alaihi wa sallam datang, beliau mengucapkan salam dengan suara yang bisa didengar oleh orang yang terjaga namun tidak bisa membangungkan orang tidur, beliau ke masjid lalu shalat, setelah itu beliau mendatangi minuman beliau kemudian minum. Para suatu malam setan mendatangiku, ia berkata: Muhammad mendatangi kaum Anshar, mereka memberinya hadiah sementara mereka memerlukan minuman ini, minumlah. Setan terusa saja menggodaku hingga aku meminumnya. Saat sudah masuk ke perutku dan aku sadar minuman itu sudah tidak bisa lagi dikeluarkan, setan membuatku menyesal. Hatiku berkata: Celaka, apa yang kau lakukan, kau meminum minuman Muhammad lalu beliau datang dan tidak melihatnya (minuman) sehingga beliau akan mendoakan kejelekan padamu di dunia dan akhiratmu. Berkata Al Miqdad: Aku mengenakan selimut dari wool, setiap kali aku tutupkan kepala, kakiku terlihat dan bila aku tutupkan dikakiku, kepalaku terlihat. Kantuk tidak juga mendatangiku sementara kedua temanku sudah tertidur. Setelah itu Rasulullah Shallalahu 'alaihi wa sallam datang dan mengucapkan salam seperti salam biasanya, setelah itu beliau ke masjid dan shalat, setelah itu beliau mendekati gelas, beliau membukanya namun beliau tidak melihat apa pun, Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ya Allah, berilah makanan orang yang memberiku makan, dan berilah minum orang yang memberiku minum.\" Aku lalu mengambil selimutku lalu aku ikat, aku lalu mengambil parang dan mendatangi kambing-kambingku, aku pun melihat dengan seksama mana diantaranya yang paling gemuk lalu aku akan menyembelihnya untuk Rasulullah shallallahu 'alaihi wasallam. Ternyata semuanya penuh susunya, lalu aku mengambil bejana untuk keluarga Muhammad yang biasa mereka pakai makan untuk aku isi perahan susu - berkata Abu An Nadlrah dalam riwayatnya: Tempat mereka memerah susu- lalu aku memerahnya hingga berisi penuh, setelah itu aku mendatangi Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Apa kalian sudah meminum minuman kalian malam ini hai Miqdad?\" aku berkata: Silahkan Tuan minum. Beliau minum lalu beliau memberikan gelas itu padaku, aku berkata: Silahkan Tuan minum, beliau minum lalu memberikan sisanya padaku, aku pun minum, aku tahu Rasulullah Shallalahu 'alaihi wa sallam sudah puas, beliau berdoa untukku, aku tertawa hingga jatuh ke tanah, Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Tunggu dulu Miqdad?\" aku berkata: Dulu aku seperti ini dan aku pernah melakukan seperti itu, lalu beliau bersabda: \"Ini hanyalah rahmat dari Allah, bukankah tadi kau memberitahuku untuk membangukan kedua temanmu itu agar keduanya bisa meminumnya. Aku berkata: \"Demi Dzat yang mengutusmu dengan kebenaran, aku tidak perduli pada orang lain bila Tuan mendapatkannya (rahmat) bersamaku."},"3641":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ حَدَّثَنِي سُلَيْمُ بْنُ عَامِرٍ حَدَّثَنِي الْمِقْدَادُ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا كَانَ يَوْمُ الْقِيَامَةِ أُدْنِيَتْ الشَّمْسُ مِنْ الْعِبَادِ حَتَّى تَكُونَ قِيدَ مِيلٍ أَوْ مِيلَيْنِ قَالَ فَتَصْهَرُهُمْ الشَّمْسُ فَيَكُونُونَ فِي الْعَرَقِ كَقَدْرِ أَعْمَالِهِمْ مِنْهُمْ مَنْ يَأْخُذُهُ إِلَى عَقِبَيْهِ وَمِنْهُمْ مَنْ يَأْخُذُهُ إِلَى رُكْبَتِهِ وَمِنْهُمْ مَنْ يَأْخُذُهُ إِلَى حَقْوَيْهِ وَمِنْهُمْ مَنْ يُلْجِمُهُ إِلْجَامًا","id":"Telah bercerita kepada kami ['Ali bin Ishaq] telah bercerita kepada kami [Ibnu Al Mubarak] dari ['Abdur Rahman bin Yazid bin Jabir] telah bercerita kepadaku [Sulaim bin 'Amir] telah bercerita kepadaku [Al Miqdad, sahabat Rasulullah shallallahu 'alaihi wasallam] berkata: Saya mendengar Rasulullah Shallalahu 'alaihi wa sallam bersabda: \" \"Ketika hari kiamat kelak, matahari akan didekatkan kepada manusia hingga seukuran satu atau dua mil, mereka disengat oleh matahara hingga mereka kebanjiran keringat menurut kadar amal mereka, diantara mereka ada yang dibanjiri keringat hingga dua mata kakinya, diantara mereka ada yang di banjiri keringat hingga kedua lututnya, dan diantara mereka ada yang di banjiri keringat hingga lehernya dan bahkan ada diantara mereka yang benar-benar ditenggelamkan.\""},"3642":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ حَدَّثَنِي إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ ضَمْضَمِ بْنِ زُرْعَةَ عَنْ شُرَيْحِ بْنِ عُبَيْدٍ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ وَعَمْرِو بْنِ الْأَسْوَدِ عَنِ الْمِقْدَادِ بْنِ الْأَسْوَدِ وَأَبِي أُمَامَةَ قَالَاإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْأَمِيرَ إِذَا ابْتَغَى الرِّيبَةَ فِي النَّاسِ أَفْسَدَهُمْ","id":"Telah bercerita kepada kami [Yazid bn 'Abdur Rabbih] telah bercerita kepada kami [Baqiyah bin Al Walid] telah bercerita kepadaku [Isma'il bin 'Ayyasy] dari [Dlamdlam bin Zur'ah] dari [Syuraih bin 'Ubaid] dari [Jubair bin Nufair] dan [Amru bin Al Aswad] dari [Al Miqdad bin Al Aswad] dan [Abu Umamah] keduanya berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Sesungguhnya seorang pemimpin bila mencari keraguan ditengah-tengah rakyat berarti ia merusak mereka.\""},"3643":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا الْفَرَجُ حَدَّثَنَا سُلَيْمَانُ بْنُ سُلَيْمٍ قَالَ قَالَ الْمِقْدَادُ بْنُ الْأَسْوَدِ لَا أَقُولُ فِي رَجُلٍ خَيْرًا وَلَا شَرًّا حَتَّى أَنْظُرَ مَا يُخْتَمُ لَهُ يَعْنِي بَعَدَ شَيْءٍ سَمِعْتُهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ وَمَا سَمِعْتَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَقَلْبُ ابْنِ آدَمَ أَشَدُّ انْقِلَابًا مِنْ الْقِدْرِ إِذَا اجْتَمَعَتْ غَلْيًا","id":"Telah bercerita kepada kami [Hasyim bin Al Qasim] telah bercerita kepada kami [Al Faraj] telah bercerita kepadaku [Sulaiman bin Sulaim] berkata: Berkata [Al Miqdad bin Al Aswad]: Aku tidak menilai baik atau buruk pada seseorang hingga aku melihat akhir hidupnya, yaitu setelah aku mendengar Rasulullah shallallahu 'alaihi wasallam. Ia ditanya: Apa yang kau dengar? Berkata Al Miqdad bin Al Aswad: Aku mendengar Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Sungguh hati manusia itu lebih berbolak-balik melebihi tungku bila airnya mendidih.\""},"3644":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ أَخْبَرَنِي عَطَاءُ بْنُ يَزِيدَ اللَّيْثِيُّ ثُمَّ الْجُنْدُعِيُّ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَدِيِّ بْنِ الْخِيَارِ أَخْبَرَهُ أَنَّ الْمِقْدَادَ بْنَ عَمْرٍو الْكِنْدِيَّ وَكَانَ حَلِيفًا لِبَنِي زُهْرَةَ وَكَانَ مِمَّنْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُ أَنَّهُقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ إِنْ لَقِيتُ رَجُلًا مِنْ الْكُفَّارِ فَاقْتَتَلْنَا فَضَرَبَ إِحْدَى يَدَيَّ بِالسَّيْفِ فَقَطَعَهَا ثُمَّ لَاذَ مِنِّي بِشَجَرَةٍ فَقَالَ أَسْلَمْتُ لِلَّهِ أَأَقْتُلُهُ يَا رَسُولَ اللَّهِ بَعْدَ أَنْ قَالَهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقْتُلْهُ قَالَ يَا رَسُولَ اللَّهِ إِنَّهُ قَطَعَ إِحْدَى يَدَيَّ ثُمَّ قَالَ ذَلِكَ بَعْدَ مَا قَطَعَهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقْتُلْهُ فَإِنَّهُ بِمَنْزِلَتِكَ قَبْلَ أَنْ تَقْتُلَهُ وَإِنَّكَ بِمَنْزِلَتِهِ قَبْلَ أَنْ يَقُولَ كَلِمَتَهُ الَّتِي قَالَ","id":"Telah bercerita kepada kami [Ya'qub] telah bercerita kepada kami [Ibnu Akhi Ibnu Syihab] dari [pamannya] telah mengkhabarkan kepadaku ['Atha` bin Yazid Al Laitsi Al Jundu'i] bahwa ['Ubaidullah bin 'Adi bin Al Khiyar] memberitahunya bahwa [Al Miqdad bin 'Amru Al Kindi] -sekutu Bani Zuhrah dan termasuk salah satu orang yang turut serta dalam perang Badar bersama Rasulullah shallallahu 'alaihi wasallam- memberitahunya, ia berkata kepada Rasulullah Shallalahu 'alaihi wa sallam: Wahai Rasulullah bagaimana pendapat Tuan bila aku berhadapan dengan seorang kafir lalu kami berperang hingga ia menebasku salah satu tanganku dengan pedang, kemudian ia berlindung dari seranganku pada sebuah pohon kemudian berkata: Aku masuk Islam karena Allah, apakah saya membunuhnya? Rasulullah Shallalahu 'alaihi wa sallambersabda: \"Jangan kau bunuh.\" Al Miqdad berkata: wahai Rasulullah, ia telah menebas salah satu tanganku. Al Miqdad bin Al Aswad mengucapkannya setelah orang kafir menebas salah satu tangannya. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Jangan membunuhnya, karena dia sama seperti kamu sebelum kamu melakukan apa yang kau lakukan terhadapnya dan kamu sepertinya sebelum ia mengucapkan kalimatnya.\""},"3645":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَنْبَأَنَا مَالِكٌ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنِ الْمِقْدَادِ بْنِ الْأَسْوَدِ أَنَّهُسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يَدْنُو مِنْ امْرَأَتِهِ فَيُمْذِي قَالَ إِذَا وَجَدَ ذَلِكَ أَحَدٌ فَلْيَنْضَحْ فَرْجَهُ قَالَ يَعْنِي يَغْسِلُهُ وَلْيَتَوَضَّأْ وُضُوءَهُ لِلصَّلَاةِ","id":"Telah bercerita kepada kami ['Utsman bin 'Umar] telah memberitakan kepada kami [Malik] dari [Salim Abu An Nadlr] dari [Sulaiman bin Yasar] dari [Al Miqdad bin Al Aswad] ia bertanya kepada Rasulullah Shallalahu 'alaihi wa sallam tentang seseorang yang mendekati istrinya hingga mengeluarkan air madzi, beliau bersabda: \"Bila seseorang mendapatkan seperti itu, hendaklah ia memercikkan air ke kemaluannya -berkata Al Miqdad bin Al Aswad: Maksud beliau membasuhnya- dan hendaklah berwudlu seperti wudlu untuk shalat.\""},"3646":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو عُبَيْدَةَ الْوَلِيدُ بْنُ كَامِلٍ مِنْ أَهْلِ حِمْصَ الْبَجَلِيُّ حَدَّثَنِي الْمُهَلَّبُ بْنُ حُجْرٍ الْبَهْرَانِيُّ عَنْ ضُبَاعَةَ بِنْتِ الْمِقْدَادِ بْنِ الْأَسْوَدِ عَنْ أَبِيهَا أَنَّهُ قَالَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى إِلَى عَمُودٍ وَلَا عُودٍ وَلَا شَجَرَةٍ إِلَّا جَعَلَهُ عَلَى حَاجِبِهِ الْأَيْمَنِ وَالْأَيْسَرِ وَلَا يَصْمُدُ لَهُ صَمْدًا","id":"Telah bercerita kepada kami ['Ali bin 'Ayyasy] telah menceritakan kepada kami [Abu 'Ubaidah Al Walid bin Kamil] penduduk Himsh Al Bajali, telah bercerita kepadaku [Al Muhallab bin Hujr Al Bahrani] dari [Dluba'ah binti Al Miqdad bin Al Aswad] dari [ayahnya] ia berkata; Aku tidak pernah melihat Rasulullah Shallalahu 'alaihi wa sallam shalat menghadap tiang, kayu atau pohon melainkan beliau memposisikannya di sebelah alis kanan dan kiri, beliau tidak bersandar padanya."},"3647":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا مَالِكٌ يَعْنِي ابْنَ مِغْوَلٍ قَالَ سَمِعْتُ سَيَّارًا أَبَا الْحَكَمِ غَيْرَ مَرَّةٍ يُحَدِّثُ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا يَعْنِي قُبَاءً قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ أَثْنَى عَلَيْكُمْ فِي الطُّهُورِ خَيْرًا أَفَلَا تُخْبِرُونِي قَالَ يَعْنِي قَوْلَهُ{ فِيهِ رِجَالٌ يُحِبُّونَ أَنْ يَتَطَهَّرُوا وَاللَّهُ يُحِبُّ الْمُطَّهِّرِينَ }قَالَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا نَجِدُهُ مَكْتُوبًا عَلَيْنَا فِي التَّوْرَاةِ الِاسْتِنْجَاءُ بِالْمَاءِحَدَّثَنَا يَزِيدُ عَنْ سَلَّامِ بْنِ مِسْكِينٍ حَدَّثَنَا شَهْرُ بْنُ حَوْشَبٍ عَنْ مُحَمَّدِ بْنِ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ وَذَكَرَ حَدِيثَ الْجَارِ","id":"Telah bercerita kepada kami [Yahya bin Adam] telah bercerita kepada kami [Malik bin Mighwal] berkata: Aku mendengar [Sayyar Abu Al Hakam] bercerita bukan hanya sekali dari [Syahr bin Hausyab] dari [Muhammad bin 'Abdullah bin Salam] berkata: Saat Rasulullah Shallalahu 'alaihi wa sallam mendatangi kami (di Quba`), beliau bersabda: \"Sesungguhnya Allah 'azza wajalla memuji baik kalian dalam hal bersuci, maukah kalian memberitahukannya kepadaku?\" berkata Muhammad bin 'Abdullah bin Salam: Maksudnya firman Allah Subhaanahu wa Ta'ala: \"Di dalamnya mesjid itu ada orang-orang yang ingin membersihkan diri. dan Sesungguhnya Allah menyukai orang-orang yang bersih.\" (At-Taubah: 108) mereka berkata: Wahai Rasulullah, kami menemukan istinja` dengan air tertulis di taurat. Telah bercerita kepada kami Yazid dari Sallam bin Miskin telah bercerita kepada kami Syahr bin Hausyab dari Muhammad bin Yusuf bin 'Abdullah bin Salam lalu ia menyebutkan hadits tentang tetangga."},"3648":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا بُكَيْرُ بْنُ الْأَشَجِّ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ أَنَّهُ قَالَسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَحْنُ بِخَيْرٍ أَمْ مَنْ بَعْدَنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنْفَقَ أَحَدُهُمْ أُحُدًا ذَهَبًا مَا بَلَغَ مُدَّ أَحَدِكُمْ وَلَا نَصِيفَهُ","id":"Telah bercerita kepada kami [Hasan bin Musa] telah bercerita kepada kami [Ibnu Lahi'ah] telah bercerita kepada kami [Bukair bin Al Asyuj] dari [Yusuf bin 'Abdullah bin Salam] ia berkata: Ia bertanya pada Rasulullah Shallalahu 'alaihi wa sallam apakah kami yang terbaik ataukah orang-orang setelah kami? Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Andai salah seorang dari mereka menginfakkan emas sebesar gunung Uhud niscaya tidak akan mencapai mud salah seorang dari kalian, tidak juga separuhnya.\""},"3649":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كُنَاسَةَ حَدَّثَنَا يَحْيَى بْنُ أَبِي الْهَيْثَمِ الْعَطَّارُ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَسَمَّانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوسُفَ وَأَجْلَسَنِي فِي حَجْرِهِ","id":"Telah bercerita kepada kami [Muhammad bin Kunasah] telah bercerita kepada kami [Yahya bin Abu Al Haitsam Al 'Aththar] dari [Yusuf bin 'Abdullah bin Salam] berkata: Rasulullah Shallalahu 'alaihi wa sallam memberiku nama Yusuf dan menempatkanku di bilik beliau."},"3650":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا يَحْيَى بْنُ أَبِي الْهَيْثَمِ الْعَطَّارُ قَالَ سَمِعْتُ يُوسُفَ بْنَ عَبْدِ اللَّهِ بْنِ سَلَامٍ يَقُولُسَمَّانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَسَحَ عَلَى رَأْسِي","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Yahya bin Abu Al Haitsam Al Aththar] berkata: Aku mendengar [Yusuf bin 'Abdullah bin Salam] berkata: Rasulullah Shallalahu 'alaihi wa sallam memberiku nama dan mengusap kepalaku."},"3651":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مِسْعَرٌ عَنِ النَّضْرِ بْنِ قَيْسٍ قَالَ سَمِعْتُ يُوسُفَ بْنَ عَبْدِ اللَّهِ بْنِ سَلَامٍ يَقُولُسَمَّانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوسُفَ","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Mis'ar] dari [An Nadlr bin Qais] berkata: Aku mendengar [Yusuf bin 'Abdullah bin Salam] berkata: Rasulullah Shallalahu 'alaihi wa sallam memberiku nama Yusuf."},"3652":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنِ الْوَلِيدِ بْنِ الْوَلِيدِ أَنَّهُقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَجِدُ وَحْشَةً قَالَ فَإِذَا أَخَذْتَ مَضْجَعَكَ فَقُلْ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ غَضَبِهِ وَعِقَابِهِ وَشَرِّ عِبَادِهِ وَمِنْ هَمَزَاتِ الشَّيَاطِينِ وَأَنْ يَحْضُرُونِ فَإِنَّهُ لَا يَضُرُّكَ وَبِالْحَرِيِّ أَنْ لَا يَقْرَبَكَ","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Al Walid] ia berkata: Wahai Rasulullah, aku selalu kesepian. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Bila kau hendak tidur bacalah: `A'UDZU BIKALIMAATILLAAHIT TAAMMAATI MIN GHADLABIHI WA 'IQAABIHI WA SYARRI 'IBAADIHI WA MIN HAMAZAATISY SYAYAATHIINI WA AN YAHDLURUUN karena setan tidak akan membahayakanmu dan tentu tidak akan mendekatimu.\"  "},"3653":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنِ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ أَبِي عَمَّارٍ قَالَسَأَلْتُ قَيْسَ بْنَ سَعْدٍ عَنْ صَدَقَةِ الْفِطْرِ فَقَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ أَنْ تَنْزِلَ الزَّكَاةُ ثُمَّ نَزَلَتْ الزَّكَاةُ فَلَمْ نُنْهَ عَنْهَا وَلَمْ نُؤْمَرْ بِهَا وَنَحْنُ نَفْعَلُهُ وَسَأَلْتُهُ عَنْ صَوْمِ عَاشُورَاءَ فَقَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ أَنْ يَنْزِلَ رَمَضَانُ ثُمَّ نَزَلَ رَمَضَانُ فَلَمْ نُؤْمَرْ بِهِ وَلَمْ نُنْهَ عَنْهُ وَنَحْنُ نَفْعَلُهُ","id":"Telah bercerita kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Sufyan Ats Tsauri] dari [Salamah bin Kuhail] dari [Al Qasim bin Mukhaimirah] dari [Abu 'Ammar] berkata: Aku bertanya kepada [Qais bin Sa'ad] tentang zakat fitrah, ia menjawab: Rasulullah Shallalahu 'alaihi wa sallam memerintahkan kami sebelum perintah zakat turun, setelah itu perintah zakat turun dan beliau tidak melarang kami mengeluarkannya dan tidak memerintahkan kami sementara kami tetap melakukannya. Aku bertanya kepadanya Qais tentang puasa 'asyura`, ia menjawab: Rasulullah Shallalahu 'alaihi wa sallam memerintahkan kami (puasa 'asyura`) sebelum turun perintah puasa ramadlon kemudian perintah puasa ramadlon turun, beliau tidak memerintahkan kami dan tidak melarang kami (puasa 'asyura`) sementara kami tetap melakukannya."},"3654":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَبِيبٍ أَنَّ قَيْسَ بْنَ سَعْدِ بْنِ عُبَادَةَ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَدَّدَ سُلْطَانَهُ بِمَعْصِيَةِ اللَّهِ أَوْهَنَ اللَّهُ كَيْدَهُ يَوْمَ الْقِيَامَةِ","id":"Telah bercerita kepada kami [Hasan bin Musa] telah bercerita kepada kami [Ibnu Lahi'ah] telah bercerita kepada kami [Yazid bin Abu Hubaib] bahwa [Qais bin Sa'ad bin 'Ubadah] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Barangsiapa menguatkan kekuasaannya dengan mendurhakai Allah, Allah akan melemahkan tipu dayanya pada hari kiamat.\""},"3655":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ وَمُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنِ ابْنِ أَبِي لَيْلَىأَنَّ سَهْلَ بْنَ حُنَيْفٍ وَقَيْسَ بْنَ سَعْدٍ كَانَا قَاعِدَيْنِ بِالْقَادِسِيَّةِ فَمَرُّوا بِجِنَازَةٍ فَقَامَا فَقِيلَ إِنَّمَا هُوَ مِنْ أَهْلِ الْأَرْضِ فَقَالَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرُّوا عَلَيْهِ بِجِنَازَةٍ فَقَامَ فَقِيلَ لَهُ إِنَّهُ يَهُودِيٌّ فَقَالَ أَلَيْسَتْ نَفْسًا","id":"Telah bercerita kepada kami [Yahya bin Sa'id] dari [Syu'bah] dan [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Ibnu Abi Laila] bahwa [Sahal bin Hunaif] dan [Qais bin Sa'ad] pernah memimpin pasukan di Qadisiyah, mereka melintasi suatu jenazah, keduanya berhenti. Ada yang berkata: Ia adalah penghuni kawasan ini, keduanya berkata: Suatu ketika jenazah dibawah melintas di hadapan Rasulullah Shallalahu 'alaihi wa sallam, beliau berdiri lalu ada yang berkata pada beliau: Ia orang Yahudi. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Bukankah ia manusia?\""},"3656":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنِ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ أَبِي عَمَّارٍ الْهَمْدَانِيِّ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَدَقَةِ الْفِطْرِ قَبْلَ أَنْ تَنْزِلَ الزَّكَاةُ فَلَمَّا نَزَلَتْ الزَّكَاةُ لَمْ يَأْمُرْنَا وَلَمْ يَنْهَنَا وَنَحْنُ نَفْعَلُهَا","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Al Qasim bin Mukhaimirah] dari [Abu 'Ammar Al Hamdani] dari [Qais bin Sa'ad] berkata: Rasulullah Shallalahu 'alaihi wa sallam memerintahkan kami mengeluarkan zakat fitrah sebelum perintah zakat turun, saat perintah zakat turun, beliau tidak memerintahkan dan tidak melarang kami, sementara kami tetap melakukannya."},"3657":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي لَيْلَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ عَنْ مُحَمَّدِ بْنِ شُرَحْبِيلَ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَأَتَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعْنَا لَهُ غِسْلًا فَاغْتَسَلَ ثُمَّ أَتَيْنَاهُ بِمِلْحَفَةٍ وَرْسِيَّةٍ فَاشْتَمَلَ بِهَا فَكَأَنِّي أَنْظُرُ إِلَى أَثَرِ الْوَرْسِ عَلَى عُكَنِهِ ثُمَّ أَتَيْنَاهُ بِحِمَارٍ لِيَرْكَبَ فَقَالَ صَاحِبُ الْحِمَارِ أَحَقُّ بِصَدْرِ حِمَارِهِ فَقُلْنَا يَا رَسُولَ اللَّهِ فَالْحِمَارُ لَكَ","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Ibnu Abi Laila] dari [Muhammad bin 'Abdur Rahman bin Sa'ad bin Ruzarah] dari [Muhammad bin Syurahbil] dari [Qais bin Sa'ad] berkata: nabi Shallalahu 'alaihi wa sallam mendatangi kami lalu kami menyediakan air lalu beliau mandi, kami memberi beliau selimut merah, beliau mengenakanya dan sepertinya au melihat sisa-sisa merah di leher beliau kamudian kami memberi beliau keledai untuk beliau tunggangi, beliau bersabda: \"Pemilik keledai lebih berhak menunggangi.\" Kami berkata: Wahai Rasulullah, kini keledai milik Tuan.\""},"3658":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ سَمِعْتُ شُعْبَةَ يُحَدِّثُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ الْحَسَنَ يُحَدِّثُ عَنْ سَعْدِ بْنِ عُبَادَةَأَنَّ أُمَّهُ مَاتَتْ فَقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أُمِّي مَاتَتْ أَفَأَتَصَدَّقُ عَنْهَا قَالَ نَعَمْ قَالَ فَأَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ سَقْيُ الْمَاءِقَالَ فَتِلْكَ سِقَايَةُ آلِ سَعْدٍ بِالْمَدِينَةِ قَالَ شُعْبَةُ فَقُلْتُ لِقَتَادَةَ مَنْ يَقُولُ تِلْكَ سِقَايَةُ آلِ سَعْدٍ قَالَ الْحَسَنُ","id":"Telah bercerita kepada kami [Hajjaj] berkata: Aku mendengar [Syu'bah] berceriat dari [Qatadah] berkata: Aku mendengar [Al Hasan] bercerita dari [Sa'ad bin 'Ubadah] ibunya meninggal dunia lalu ia berkata kepda Rasulullah Shallalahu 'alaihi wa sallam: Ibuku meninggal, apakah aku bersedekah untuknya? Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ya.\" Ia bertanya: Sedekah apa yang paling utama? Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Memberi minum.\" Berkata Al Hasan: Itulah sumur keluarga Sa'ad di Madinah. Berkata Syu'bah: Aku berkata kepada Qatadah: Siapa yang berkata: Itulah sumur keluarga Sa'ad? Ia menjawab: Al Hasan."},"3659":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ أَبُو دَاوُدَ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ عَنْ سَعْدِ بْنِ عُبَادَةَأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أُمِّي مَاتَتْ وَعَلَيْهَا نَذْرٌ أَفَيُجْزِئُ عَنْهَا أَنْ أُعْتِقَ عَنْهَا قَالَ أَعْتِقْ عَنْ أُمِّكَ","id":"Telah bercerita kepada kami ['Affan] telah bercerita kepada kami [Sulaiman bin Katsir Abu Dawud] dari [Az Zuhri] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] dari [Sa'ad bin 'Ubadah] ia mendantangi nabi Shallalahu 'alaihi wa sallam lalu berkata: Ibuku meninggal dunia dan ia memiliki tanggungan nadzar, apakah aku bisa mencukupinya dengan memerdekakan budak untuknya? Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Merdekakan (budak) untuk ibumu.\""},"3660":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي شُمَيْلَةَ حَدَّثَنِي رَجُلٌ عَنْ سَعِيدٍ الصَّرَّافِ أَوْ هُوَ سَعِيدٌ الصَّرَّافُ عَنْ إِسْحَاقَ بْنِ سَعْدِ بْنِ عُبَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا الْحَيَّ مِنْ الْأَنْصَارِ مِحْنَةٌ حُبُّهُمْ إِيمَانٌ وَبُغْضُهُمْ نِفَاقٌقَالَ عَفَّانُ وَقَدْ حَدَّثَنَا بِهِ مَرَّةً وَلَيْسَ فِيهِ شَكٌّ أَمَلَّهُ عَلَيَّ أَوَّلًا عَلَى الصِّحَّةِ","id":"Telah bercerita kepada kami ['Affan] telah bercerita kepada kami [Hammad bin Zaid] dari ['Abdur Rahman bin Abu Syumailah] telah bercerita kepadaku [seseorang] dari [Sa'ad Ash Sharraf atau Sa'id Ash Sharraf] dari [Ishaq bin Sa'ad bin 'Ubadah] dari [ayahnya] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Sesungguhnya penduduk Anshar ini adalah ujian, mencintai mereka berarti keimanan dan membenci mereka berarti kemunafikan.\" Berkata 'Affan: Telah menceritakannya kepada kami bukan hanya sekali Hammad dan tidak ada keraguan padanya, ia mendiktekan riwayat itu pada pertama kali saat ia masih sehat."},"3661":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ : مَالِكٌ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ فَذَكَرَ الْحَدِيثَ قَالَ أَبُو هُرَيْرَةَ فَلَقِيتُ أَبَا بَصْرَةَ الْغِفَارِيَّ قَالَ مِنْ أَيْنَ أَقْبَلْتَ فَقُلْتُ مِنْ الطُّورِ فَقَالَ أَمَا لَوْ أَدْرَكْتُكَ قَبْلَ أَنْ تَخْرُجَ إِلَيْهِ مَا خَرَجْتَ إِلَيْهِسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُعْمَلُ الْمَطِيُّ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ إِلَى الْمَسْجِدِ الْحَرَامِ وَإِلَى مَسْجِدِي وَإِلَى مَسْجِدِ إِيلِيَاءَ أَوْ بَيْتِ الْمَقْدِسِ يَشُكُّ","id":"Berkata Ahmad: Aku meriwayatkan dari ['Abdur Rahman] dengan membaca: [Malik] dari [Yazid bin 'Abdullah bin Al Had] dari [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Abu Salamah bin 'Abdur Rahman] dari [Abu Hurairah] lalu ia menyebutkan hadits. Berkata Abu Hurairah: Aku menemui [Abu Bashrah Al Ghifari] berkata: Kamu dari mana? Aku menjawab: Dari Thur. berkata Abu Bashrah: Andai aku menemuimu sebelum kau pergi meninggalkannya pasti kau tidak pergi, aku pernah mendengar Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Binatang tunggangan tidak boleh dipakai kecuali ke tiga masjid; Masjidil Haram, masjidku dan Masjid Elia atau Baitul Maqdis, \" Abu Bashrah ragu."},"3662":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ مُبَارَكٍ عَنْ سَعِيدِ بْنِ يَزِيدَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍأَنَّ أَبَا بَصْرَةَ خَرَجَ فِي رَمَضَانَ مِنْ الْإِسْكَنْدَرِيَّةِ أُتِيَ بِطَعَامِهِ فَقِيلَ لَهُ لَمْ تَغِبْ عَنَّا مَنَازِلُنَا بَعْدُ فَقَالَ أَتَرْغَبُونَ عَنْ سُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَمَا زِلْنَا مُفْطِرِينَ حَتَّى بَلَغُوا مَكَانَ كَذَا وَكَذَا","id":"Telah bercerita kepada kami [Yahya bin Adam] telah bercerita kepada kami [Ibnu Mubarak] dari [Sa'id bin Yazid] dari [Yazid bin Abu Habib] bahwa [Abu Bashrah] pergi di bulan ramadlon dari Iskandaria, ia diberi makanan lalu dikatakan padanya: Jangan kau tinggalkan rumah-rumah kami. Berkata Abu Bashrah: Apa kalian membenci sunnah Rasulullah Shallalahu 'alaihi wa sallam? Berkata Yazid: Kami terus tidak puasa hingga mereka sampai di tempat ini dan itu."},"3663":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ عَبْدِ الْمَلِكِ عَنْ عُمَرَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّهُ قَالَلَقِيَ أَبُو بَصْرَةَ الْغِفَارِيُّ أَبَا هُرَيْرَةَ وَهُوَ جَاءٍ مِنْ الطُّورِ فَقَالَ مِنْ أَيْنَ أَقْبَلْتَ قَالَ مِنْ الطُّورِ صَلَّيْتُ فِيهِ قَالَ أَمَا لَوْ أَدْرَكْتُكَ قَبْلَ أَنْ تَرْحَلَ إِلَيْهِ مَا رَحَلْتَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ الْمَسْجِدِ الْحَرَامِ وَمَسْجِدِي هَذَا وَالْمَسْجِدِ الْأَقْصَى","id":"Telah bercerita kepada kami [Husain bin Muhammad] telah bercerita kepada kami [Syaiban] dari ['Abdul Malik] dari ['Umar bin 'Abdur Rahman bin Al Harits bin Hisyam] ia berkata: [Abu Bashrah Al Ghifari] menemui Abu Hurairah saat ia tiba dari Thur, bertanya Abu Bashrah Al Ghifari: Dari mana kamu? Abu Hurairah menjawab: Dari Thur, aku shalat di sana. Berkata Abu Bashrah Al Ghifari: Andai aku menemuimu sebelum kau pergi meninggalkannya pasti kau tidak pergi, aku pernah mendengar Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Binatang tunggangan tidak boleh diikat kecuali ke tiga masjid; Masjidil Haram, masjidku dan Masjidil Aqsa.\""},"3664":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ أَنْبَأَنَا سَعِيدُ بْنُ يَزِيدَ حَدَّثَنِي ابْنُ هُبَيْرَةَ عَنْ أَبِي تَمِيمٍ الْجَيْشَانِيِّأَنَّ عَمْرَو بْنَ الْعَاصِ خَطَبَ النَّاسَ يَوْمَ الْجُمُعَةِ فَقَالَ إِنَّ أَبَا بَصْرَةَ حَدَّثَنِي أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ زَادَكُمْ صَلَاةً وَهِيَ الْوِتْرُ فَصَلُّوهَا فِيمَا بَيْنَ صَلَاةِ الْعِشَاءِ إِلَى صَلَاةِ الْفَجْرِ قَالَ أَبُو تَمِيمٍ فَأَخَذَ بِيَدِي أَبُو ذَرٍّ فَسَارَ فِي الْمَسْجِدِ إِلَى أَبِي بَصْرَةَ فَقَالَ لَهُ أَنْتَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا قَالَ عَمْرٌو قَالَ أَبُو بَصْرَةَ أَنَا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah bercerita kepada kami ['Ali bin Ishaq] telah bercerita kepada kami ['Abdullah bin Al Mubarak] telah memberitakan kepada kami [Sa'id bin Yazid] telah bercerita kepadaku [Ibnu Hubairah] dari [Abu Tamim Al Jaisyani] bahwa ['Amru bin Al 'Ash] berkhutbah di hari jum'at, ia berkata; [Abu Bashrah Al Ghifari] bercerita kepadaku bahwa nabi Shallalahu 'alaihi wa sallam bersabda: \"Sesungguhnya nabi Shallalahu 'alaihi wa sallam menambahkan satu shalat untuk kalian, yaitu shalat witir, lakukanlah antara shalat 'isya` hingga shalat fajar\" -berkata Abu Tamim: Abu Dzarr meraih tanganku lalu ia berjalan di masjid menemui Abu Bashrah Al Ghifari, Abu Dzarr berkata: Kau mendengar dari Rasulullah Shallalahu 'alaihi wa sallam seperti itu? Bekata 'Amru: Abu Bashrah Al Ghifari berkata: Aku mendengarnya dari Rasulullah Shallalahu 'alaihi wa sallam."},"3665":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَحَجَّاجٌ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يِسَافٍ عَنْ أَبِي الْمُثَنَّى عَنْ أَبِي أُبَيِّ ابْنِ امْرَأَةِ عُبَادَةَ بْنِ الصَّامِتِ قَالَ حَجَّاجٌ عَنِ ابْنِ امْرَأَةِ عُبَادَةَ بْنِ الصَّامِتِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيَكُونُ أُمَرَاءُ يَشْغَلُهُمْ أَشْيَاءُ وَيُؤَخِّرُونَ الصَّلَاةَ عَنْ وَقْتِهَا فَصَلُّوا الصَّلَاةَ لِوَقْتِهَا ثُمَّ اجْعَلُوا صَلَاتَكُمْ مَعَهُمْ تَطَوُّعًا","id":"Telah bercerita kepada kami [Muhammad bin Ja'far] dan [Hajjaj] keduanya berkata: Telah bercerita kepada kami [Syu'bah] dari [Manshur] dari [Hilal bin Yisaf] dari [Abu Al Mutsanna] dari [Abu Ubai] putra istrinya 'Ubadah bin Ash Shamit, berkata Hajjaj dari putra istrinya 'Ubadah bin Ash Shamit dari nabi Shallalahu 'alaihi wa sallam bersabda: \"Akan ada para pemimpin yang disibukkan oleh berbagai hal, mereka menunda shalat dari waktunya, shalatlah kalian diwaktunya kemudian jadikan shalat kalian bersama mereka sebagai shalat sunnah.\""},"3666":{"ar":"حَدَّثَنَا يَحْيَى بنُ سَعِيدٍ حَدَّثَنِي سُفْيَانُ حَدَّثَنَا مَنْصُورٌ عَنْ هِلَالِ بْنِ يِسَافٍ عَنْ رَجُلٍ مِنْ آلِ خَالِدِ بْنِ عُرْفُطَةَ عَنْ آخَرَ قَالَكُنْتُ مَعَ سَالِمِ بْنِ عُبَيْدٍ فِي سَفَرٍ فَعَطَسَ رَجُلٌ فَقَالَ السَّلَامُ عَلَيْكُمْ فَقَالَ عَلَيْكَ وَعَلَى أُمِّكَ ثُمَّ سَارَ فَقَالَ لَعَلَّكَ وَجَدْتَ فِي نَفْسِكَ قَالَ مَا أَرَدْتُ أَنْ تَذْكُرَ أُمِّي قَالَ لَمْ أَسْتَطِعْ إِلَّا أَنْ أَقُولَهَا كُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَعَطَسَ رَجُلٌ فَقَالَ السَّلَامُ عَلَيْكَ فَقَالَ عَلَيْكَ وَعَلَى أُمِّكَ ثُمَّ قَالَ إِذَا عَطَسَ أَحَدُكُمْ فَلْيَقُلْ الْحَمْدُ لِلَّهِ عَلَى كُلِّ حَالٍ أَوْ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ وَلْيُقَلْ لَهُ يَرْحَمُكُمْ اللَّهُ أَوْ يَرْحَمُكَ اللَّهُ شَكَّ يَحْيَى وَلْيَقُلْ يَغْفِرُ اللَّهُ لِي وَلَكُمْ","id":"Telah bercerita kepada kami [Yahya bin Sa'id] telah bercerita kepadaku [Sufyan] telah bercerita kepada kami [Manshur] dari [Hilal bin Yisaf] dari [seorang keluarga terakhir Khalid bin 'Urfuthah] berkata: Aku pernah bersama [Salim bin 'Ubaid] dalam suatu perjalanan lalu seseorang bersin, ia mengucapkan: ASSALAAMU 'ALAIKUM. Salim menjawab: 'ALAIK WA 'ALAA UMMIKA. Salim berjalan kemudian berkata: Sepertinya kau sedang sedih. Orang itu berkata: Aku tidak ingin engkau mengingatkanku pada ibuku. Berkata Salim: Aku tidak bisa berbuat apa pun selain menyampaikannya, dulu aku pernah bersama Rasulullah Shallalahu 'alaihi wa sallam dalam suatu perjalanan lalu seseorang bersin, ia mengucapkan: ASSALAAMU 'ALAIKA, beliau bersabda: \"'ALAIKA WA 'ALAA UMMIKA.\" Setelah itu beliau bersabda: \"Bila salah seorang diantara kalian bersin hendaklah mengucapkan: ALHAMDULILLAAH 'ALA KULLI HAAL atau ALHAMDULILLAAHI RABBIL 'AALAMIIN, kemudian hendaklah ia dijawab: YARHAMUKUMULLAAH atau YARHAMUKALLAAH -Yahya ragu- dan hendaklah ia mengucapkan: YAGHFIRULLAAHU LII WA LAKUM.\""},"3667":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلِ بْنِ غَزْوَانَ حَدَّثَنَا مُحَمَّدُ بْنُ سَعْدٍ الْأَنْصَارِيُّ قَالَ سَمِعْتُ أَبَا ظَبْيَةَ الْكَلَاعِيَّ يَقُولُ سَمِعْتُ الْمِقْدَادَ بْنَ الْأَسْوَدِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ مَا تَقُولُونَ فِي الزِّنَا قَالُوا حَرَّمَهُ اللَّهُ وَرَسُولُهُ فَهُوَ حَرَامٌ إِلَى يَوْمِ الْقِيَامَةِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ لَأَنْ يَزْنِيَ الرَّجُلُ بِعَشْرَةِ نِسْوَةٍ أَيْسَرُ عَلَيْهِ مِنْ أَنْ يَزْنِيَ بِامْرَأَةِ جَارِهِ قَالَ فَقَالَ مَا تَقُولُونَ فِي السَّرِقَةِ قَالُوا حَرَّمَهَا اللَّهُ وَرَسُولُهُ فَهِيَ حَرَامٌ قَالَ لَأَنْ يَسْرِقَ الرَّجُلُ مِنْ عَشْرَةِ أَبْيَاتٍ أَيْسَرُ عَلَيْهِ مِنْ أَنْ يَسْرِقَ مِنْ جَارِهِ","id":"Telah bercerita kepada kami ['Ali bin 'Abdullah] telah bercerita kepada kami [Muhammad bin Fudlail bin Ghazwan] telah bercerita kepada kami [Muhammad bin Sa'ad Al Anshari] berkata: Aku mendengar [Abu Zlabyah Al Kala'i] berkata: Aku mendengar [Al Miqdad bin Al Aswad] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda kepada para sahabat beliau: \"Zina menurut kalian bagaimana?\" Mereka menjawab: Allah dan rasulNya mengharamkannya, ia haram hingga hari kiamat. Rasulullah Shallalahu 'alaihi wa sallam bersabda kepada para sahabat beliau: \"Sungguh seseorang berzina dengan sepuluh wanita itu lebih ringan baginya bagi pada berzina dengan istri tetangganya.\" Beliau bersabda: \"Mencuri menurut kalian bagaimana?\" mereka menjawab: Allah dan rasulNya mengharamkannya, ia haram hingga hari kiamat. Rasulullah Shallalahu 'alaihi wa sallam bersabda kepada para sahabat beliau: \"Sungguh seseorang mencuri dari sepuluh rumah itu lebih ringan baginya bagi pada mencuri dari tetangganya.\""},"3668":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْحَجَّاجِ أَنْبَأَنَا حَاتِمُ بْنُ إِسْمَاعِيلَ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ عَبَّادِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِي غَطَفَانَ عَنْ أَبِي رَافِعٍ قَالَذَبَحْنَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةً فَأَمَرَنَا فَعَالَجْنَا لَهُ شَيْئًا مِنْ بَطْنِهَا فَأَكَلَ ثُمَّ قَامَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah bercerita kepada kami [Ahmad bin Al Hajjaj] telah memberitakan kepada kami [Hatim bin Isma'il] dari [Muhammad bin 'Ajlan] dari ['Abbad bin 'Ubaidullah bin Abu Rafi'] dari [Abu Ghathafan] dari [Abu Rafi'] berkata: Kami menyembelih seekor kambing untuk Rasulullah Shallalahu 'alaihi wa sallam, beliau memerintahkan kami lalu kami memasak sebagian isi perutnya lalu beliau makan, setelah itu beliau berdiri dan tidak berwudlu."},"3669":{"ar":"حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ مُحَمَّدٍ الْخَطَّابِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ أَنَّ بُكَيْرَ بْنَ عَبْدِ اللَّهِ حَدَّثَهُ عَنِ الْحَسَنِ بْنِ عَلِيِّ بْنِ أَبِي رَافِعٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَبِي رَافِعٍ قَالَبَعَثَتْنِي قُرَيْشٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلَمَّا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَعَ فِي قَلْبِي الْإِسْلَامُ فَقُلْتُ يَا رَسُولَ اللَّهِ لَا أَرْجِعُ إِلَيْهِمْ قَالَ إِنِّي لَا أَخِيسُ بِالْعَهْدِ وَلَا أَخِيسُ الْبِرَّ وَارْجِعْ إِلَيْهِمْ فَإِنْ كَانَ فِي قَلْبِكَ الَّذِي فِيهِ الْآنَ فَارْجِعْقَالَ بُكَيْرٌ وَأَخْبَرَنِي الْحَسَنُ أَنَّ أَبَا رَافِعٍ كَانَ قِبْطِيًّا","id":"Telah bercerita kepada kami ['Abdul Jabbar bin Muhammad Al Khaththabi] telah bercerita kepada kami ['Abdullah bin Wahab] dari ['Amru bin Al Harits] bahwa [Bukair bin 'Abdullah] bercerita kepadanya dari [Al Hasan bin 'Ali bin Abu Rafi'] dari [ayahnya] dari kakeknya, Abu Rafi' berkata: Kaum Quraisy mengutusku untuk menemui nabi Shallalahu 'alaihi wa sallam. Saat aku melihat nabi Shallalahu 'alaihi wa sallam, Islam menghujam di hatiku, aku berkata: Wahai Rasulullah, aku tidak akan kembali pada mereka. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Sesungguhnya aku tidak mengingkari janji, aku tidak mengingkari kebaikan, kembalilah kepada mereka, bila dihatimu sekarang ada sesuatu, kembalilah.\" Berkata Bukair dan telah mengkhabarkan kepadaku Hasan bahwa Abu Rafi' adalah orang Qibti."},"3670":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ حَسَنٍ عَنْ بَعْضِ أَهْلِهِ عَنْ أَبِي رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَخَرَجْنَا مَعَ عَلِيٍّ حِينَ بَعَثَهُ رَسُولُ اللَّهِ بِرَايَتِهِ فَلَمَّا دَنَا مِنْ الْحِصْنِ خَرَجَ إِلَيْهِ أَهْلُهُ فَقَاتَلَهُمْ فَضَرَبَهُ رَجُلٌ مِنْ يَهُودَ فَطَرَحَ تُرْسَهُ مِنْ يَدِهِ فَتَنَاوَلَ عَلِيٌّ بَابًا كَانَ عِنْدَ الْحِصْنِ فَتَرَّسَ بِهِ نَفْسَهُ فَلَمْ يَزَلْ فِي يَدِهِ وَهُوَ يُقَاتِلُ حَتَّى فَتَحَ اللَّهُ عَلَيْهِ ثُمَّ أَلْقَاهُ مِنْ يَدِهِ حِينَ فَرَغَ فَلَقَدْ رَأَيْتُنِي فِي نَفَرٍ مَعِي سَبْعَةٌ أَنَا ثَامِنُهُمْ نَجْهَدُ عَلَى أَنْ نَقْلِبَ ذَلِكَ الْبَابَ فَمَا نَقْلِبُهُ","id":"Telah bercerita kepada kami [Ya'qub] telah bercerita kepada kami [ayahku] dari [Muhammad bin Ishaq] berkata: telah bercerita kepadaku ['Abdullah bin Hasan] dari [salah seorang keluarganya] dari [Abu Rafi', pelayan Rasulullah Shallalahu 'alaihi wa sallam] berkata: Kami pergi bersama 'Ali saat diutus Rasulullah Shallalahu 'alaihi wa sallam, saat kami mendekati benteng, para penduduk menghampirinya kemudian 'Ali memerangi mereka, seorang yahudi memukulnya lalu ia membuang perisai ditangannya kemudian meraih sebuah pintu yang ada dibenteng dan dijadikan sebagi perisai untuk melindungi dirinya, pintu itu tetap dipegang 'Ali hingga Allah memberikan kemenangan untuknya, setelah itu ia membuang pintu itu dari tangannya setelah perang usai. Aku bersama dengan sekelompok tujuh orang dan aku adalah yang kedelapan, kami berusaha dengan keras membalikkan pintu itu tapi kami tidak bisa."},"3671":{"ar":"حَدَّثَنَا حُسَيْنٌ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ أَبِي رَافِعٍ قَالَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ أَمْلَحَيْنِ مَوْجِيَّيْنِ خَصِيَّيْنِ فَقَالَ أَحَدُهُمَا عَمَّنْ شَهِدَ بِالتَّوْحِيدِ وَلَهُ بِالْبَلَاغِ وَالْآخَرُ عَنْهُ وَعَنْ أَهْلِ بَيْتِهِ قَالَ فَكَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كَفَانَا","id":"Telah bercerita kepada kami [Husain] telah bercerita kepada kami [Syarik] dari [Abdullah bin Muhammad] dari ['Ali bin Husain] dari [Abu Rafi'] berkata: Rasulullah Shallalahu 'alaihi wa sallam berkurban dua kambing gibas kelabu, ikal dan dikebiri, beliau bersabda: \"Salah satunya untuk orang yang bersaksi dengan kalimat tahudi dan yang kesampaian seruan sedangkan yang lain untukku dan keluargaku.\" Berkata Abu Rafi': Sepertinya Rasulullah Shallalahu 'alaihi wa sallam telah mencukupi kami."},"3672":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ أَنْبَأَنَا عَبْدُ اللَّهِ أَنْبَأَنَا ابْنُ لَهِيعَةَ حَدَّثَنِي أَبُو النَّضْرِ أَنَّ عُبَيْدَ اللَّهِ بْنَ أَبِي رَافِعٍ حَدَّثَهُ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَعْرِفَنَّ مَا يَبْلُغُ أَحَدَكُمْ مِنْ حَدِيثِي شَيْءٌ وَهُوَ مُتَّكِئٌ عَلَى أَرِيكَتِهِ فَيَقُولُ مَا أَجِدُ هَذَا فِي كِتَابِ اللَّهِ تَعَالَى","id":"Telah bercerita kepada kami ['Ali ibn Ishaq] telah memberitakan kepada kami ['Abdullah] telah memberitakan kepada kami [Ibnu Lahi'ah] telah bercerita kepadaku [Abu An Nadlr] bahwa ['Ubaidullah bin Abu Rafi'] bercerita kepadanya dari [ayahnya] dari nabi Shallalahu 'alaihi wa sallam bersabda: \"Aku sungguh mengetahui suatu haditsku yang sampai pada salah seorang diantara kalian sementara ia tengah bersandar diatas tahtanya lalu ia berkata: Aku tidak menemukannya dalam kitab Allah Ta'ala.\""},"3673":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي رَافِعٍ عَنْ عَمَّتِهِ سَلْمَى عَنْ أَبِي رَافِعٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ عَلَى نِسَائِهِ فِي يَوْمٍ فَجَعَلَ يَغْتَسِلُ عِنْدَ هَذِهِ وَعِنْدَ هَذِهِ فَقِيلَ يَا رَسُولَ اللَّهِ لَوْ جَعَلْتَهُ غُسْلًا وَاحِدًا قَالَ هَذَا أَزْكَى وَأَطْيَبُ وَأَطْهَرُ","id":"Telah bercerita kepada kami ['Affan] telah bercerita kepada kami [Hammad] telah memberitakan kepada kami ['Abdur Rahman bin Abu Rafi'] dari [bibinya, Salma] dari [Abu Rafi'] Rasulullah Shallalahu 'alaihi wa sallam menggilir seluruh istri-istri beliau dalam sehari lalu beliau mandi di rumah dia dan di rumah dia kemudian ada yang berkata: Wahai Rasulullah, andai saja Tuan mandi sekali saja. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ini lebih suci, lebih baik dan lebih bersih.\""},"3674":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ قَالَ مُحَمَّدٌ يَعْنِي ابْنَ إِسْحَاقَ فَحَدَّثَنِي حُسَيْنُ بْنُ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عِكْرِمَةَ قَالَ قَالَ أَبُو رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنْتُ غُلَامًا لِلْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ وَكَانَ الْإِسْلَامُ قَدْ دَخَلَنَا فَأَسْلَمْتُ وَأَسْلَمَتْ أُمُّ الْفَضْلِ وَكَانَ الْعَبَّاسُ قَدْ أَسْلَمَ وَلَكِنَّهُ كَانَ يَهَابُ قَوْمَهُ وَكَانَ يَكْتُمُ إِسْلَامَهُ وَكَانَ أَبُو لَهَبٍ عَدُوُّ اللَّهِ قَدْ تَخَلَّفَ عَنْ بَدْرٍ وَبَعَثَ مَكَانَهُ الْعَاصَ بْنَ هِشَامِ بْنِ الْمُغِيرَةِ وَكَذَلِكَ كَانُوا صَنَعُوا لَمْ يَتَخَلَّفْ رَجُلٌ إِلَّا بَعَثَ مَكَانَهُ رَجُلًا فَلَمَّا جَاءَنَا الْخَيْرُ كَبَتَهُ اللَّهُ وَأَخْزَاهُ وَوَجَدْنَا أَنْفُسَنَا قُوَّةً فَذَكَرَ الْحَدِيثَ وَمِنْ هَذَا الْمَوْضُوعِ فِي كِتَابِ يَعْقُوبَ مُرْسَلٌ لَيْسَ فِيهِ إِسْنَادٌ وَقَالَ فِيهِ أَخُو بَنِي سَالِمِ بْنِ عَوْفٍ قَالَ وَكَانَ فِي الْأُسَارَى أَبُو وَدَاعَةَ بْنُ صُبَيْرَةَ السَّهْمِيُّفَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لَهُ بِمَكَّةَ ابْنًا كَيِّسًا تَاجِرًا ذَا مَالٍ لَكَأَنَّكُمْ بِهِ قَدْ جَاءَنِي فِي فِدَاءِ أَبِيهِ وَقَدْ قَالَتْ قُرَيْشٌ لَا تَعْجَلُوا بِفِدَاءِ أُسَارَاكُمْ لَا يَتَأَرَّبُ عَلَيْكُمْ مُحَمَّدٌ وَأَصْحَابُهُ فَقَالَ الْمُطَّلِبُ بْنُ أَبِي وَدَاعَةَ صَدَقْتُمْ فَافْعَلُوا وَانْسَلَّ مِنْ اللَّيْلِ فَقَدِمَ الْمَدِينَةَ وَأَخَذَ أَبَاهُ بِأَرْبَعَةِ آلَافِ دِرْهَمٍ فَانْطَلَقَ بِهِ وَقَدِمَ مِكْرَزُ بْنُ حَفْصِ بْنِ الْأَخْيَفِ فِي فِدَاءِ سُهَيْلِ بْنِ عَمْرٍو وَكَانَ الَّذِي أَسَرَهُ مَالِكُ بْنُ الدُّخْشُنِ أَخُو بَنِي مَالِكِ بْنِ عَوْفٍ","id":"Telah bercerita kepada kami [Yazid bin Harun] berkata: Bekata [Muhammad bin Ishaq] telah bercerita kepadaku [Husain bin 'Adullah bin 'Ubaidullah bin 'Abbas] dari ['Ikrimah] berkata: Berkata [Abu Rafi', pelayan Rasulullah Shallalahu 'alaihi wa sallam]: Aku dulu adalah budak milik 'Abbas bin 'Abdul Muththallib dan Islam sudah memasuki kami, aku masuk Islam dan Ummu Al Fadll juga masuk Islam, 'Abbas sudah masuk Islam sebelumnya hanya saja ia takut pada kaumnya, ia menyembunyikan keIslamannya. Abu Lahab, musuh Allah tidak turut serta dalam perang badar dan mengirim Al 'Ash bin Hisyam bin Al Mughirah untuk menggantikan posisinya, seperti itulah yang mereka lakukan, tidak ada seorang pun yang tidak turut serta melainkan pasti menyuruh seseorang untuk menggantikannya. Saat kebaikan yang telah ditetapkan Allah Subhaanahu wa Ta'ala datang pada kami dan kami melihat diri kami kuat. Ia Abu Rafi' menyebutkan hadits. Topik ini juga disebutkan dalam kitab mursal milik Ya'qub yang tidak ada sanadnya. Dalam riwayatnya disebutkan: Seorang Bani Salim bin 'Auf berkata: Di antara yang ditawan adalah Abu Wada'ah bin Shubairah As Suhami, Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ia memiliki seorang anak cerdas dan seorang pedagang di Makkah dan punya uang, datangkan dia untuk menebus ayahnya.\" Sementara itu kaum Quraisy berkata: Janganlah kalian terburu-buru menebus tawanan-tawanan kalian, jangan sampai Muhammad dan para sahabatnya menipu kalian. Berkata Al Muththallib bin Abu Wada'ah: Kalian benar. Mereka beraksi dan menyusup di malam hari, ia tiba di Madinah dan menebus ayahnya seharga empat ribu dirham. Ia pergi membawa ayahnya dan menemui Mikraz bin Hafsh bin Al Akhsyaf yang tengah menebus Suhail bin 'Amru yang ditawan oleh Malik bin Ad Dukhsyun, orang dari Bani Malik bin 'Auf."},"3675":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي الْعَبَّاسُ بْنُ أَبِي خِدَاشٍ عَنِ الْفَضْلِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِي رَافِعٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا أَبَا رَافِعٍ اقْتُلْ كُلَّ كَلْبٍ بِالْمَدِينَةِ قَالَ فَوَجَدْتُ نِسْوَةً مِنْ الْأَنْصَارِ بِالصَّوْرَيْنِ مِنْ الْبَقِيعِ لَهُنَّ كَلْبٌ فَقُلْنَ يَا أَبَا رَافِعٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَغْزَى رِجَالَنَا وَإِنَّ هَذَا الْكَلْبَ يَمْنَعُنَا بَعْدَ اللَّهِ وَاللَّهِ مَا يَسْتَطِيعُ أَحَدٌ أَنْ يَأْتِيَنَا حَتَّى تَقُومَ امْرَأَةٌ مِنَّا فَتَحُولَ بَيْنَهُ وَبَيْنَهُ فَاذْكُرْهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَهُ أَبُو رَافِعٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أَبَا رَافِعٍ اقْتُلْهُ فَإِنَّمَا يَمْنَعُهُنَّ اللَّهُ عَزَّ وَجَلَّ","id":"Telah bercerita kepada kami [Rauh] telah bercerita kepada kami [Ibnu Juraij] telah memberitakan kepadaku [Al 'Abbas bin Abu Khidasy] dari [Al Fadll bin 'Ubaidullah bin Abu Rafi'] dari [Abu Rafi'] nabi Shallalahu 'alaihi wa sallam bersabda: \"Hai Abu Rafi', bunuh semua anjing yang ada di Madinah.\" Berkata Abu Rafi': Aku menemui beberapa wanita Anshar berada di dekat dua pohon kurma di Baqi', mereka memiliki anjing, mereka berkata: Hai Abu Rafi', Rasulullah Shallalahu 'alaihi wa sallam memberangkatkan suami-suami kami berperang dan anjing ini menjaga kami setelah Allah, tidak ada seorang pun yang mendatangi kami hingga seorang wanita diantara kami berdiri lalu ia terhalang oleh anjing ini, beritahukanlah kepada nabi Shallalahu 'alaihi wa sallam. Kemudian Abu Rafi' memberitahukan hal itu kepada nabi Shallalahu 'alaihi wa sallam, beliau bersabda: \"Hai Abu Rafi', bunuhlah anjing itu, yang menjaga mereka hanyalah Allah 'azza wajalla.\""},"3676":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَمْرٍو يَعْنِي ابْنَ أَبِي عَمْرٍو عَنِ الْمُغِيرَةِ بْنِ أَبِي رَافِعٍ عَنْ أَبِي رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُتِيَ بِكَتِفِ شَاةٍ فَأَكَلَهَا ثُمَّ قَامَ إِلَى الصَّلَاةِ وَلَمْ يَمَسَّ قَطْرَةَ مَاءٍ","id":"Telah bercerita kepada kami [Qutaibah bin Sa'id] telah bercerita kepada kami ['Abdul 'Aziz bin Muhammad] dari ['Amru bin Abu 'Amru] dari [Al Mughirah bin Abu Rafi'] dari [Abu Rafi', pelayan Rasulullah Shallalahu 'alaihi wa sallam] ia melihat Rasulullah Shallalahu 'alaihi wa sallam diberi lengan kambing, beliau memakannya kemudian lalu shalat dan tidak menyentuh setetes air pun."},"3677":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا ابْنُ عَجْلَانَ عَنْ عَبَّادِ بْنِ أَبِي رَافِعٍ عَنْ أَبِي غَطَفَانَ عَنْ أَبِي رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَذَبَحْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةً فَأَمَرَنِي فَقَلَيْتُ لَهُ مِنْ بَطْنِهَا فَأَكَلَ مِنْهَا ثُمَّ قَامَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah bercerita kepada kami ['Ali bin Bahr] telah bercerita kepada kami [Hatim bin Isma'il] telah bercerita kepada kami [Ibnu 'Ajlan] dari ['Abbad bin Abu Rafi'] dari [Abu Ghathafan] dari [Abu Rafi', pelayan Rasulullah Shallalahu 'alaihi wa sallam] berkata: Aku menyembelih kambing untuk Rasulullah Shallalahu 'alaihi wa sallam, beliau memerintahkanku lalu aku menggoreng isi perutnya, beliau memakannya kemudian shalat dan tidak berwudlu."},"3678":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنِي أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرِ بْنِ الزُّبَيْرِ قَالَ سَمِعْتُ زِيَادَ بْنَ ضَمْرَةَ بْنِ سَعِيدٍ السُّلَمِيَّ يُحَدِّثُ عُرْوَةَ بْنَ الزُّبَيْرِ عَنْ أَبِيهِ ضَمْرَةَ وَعَنْ جَدِّهِ وَكَانَا شَهِدَا حُنَيْنًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَاصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ ثُمَّ عَمَدَ إِلَى ظِلِّ شَجَرَةٍ فَجَلَسَ فِيهِ وَهُوَ بِحُنَيْنٍ فَقَامَ إِلَيْهِ الْأَقْرَعُ بْنُ حَابِسٍ وَعُيَيْنَةُ بْنُ حِصْنِ بْنِ حُذَيْفَةَ بْنِ بَدْرٍ يَخْتَصِمَانِ فِي عَامِرِ بْنِ الْأَضْبَطِ الْأَشْجَعِيِّ وَعُيَيْنَةُ يَطْلُبُ بِدَمِ عَامِرٍ وَهُوَ يَوْمَئِذٍ رَئِيسُ غَطَفَانَ وَالْأَقْرَعُ بْنُ حَابِسٍ يَدْفَعُ عَنْ مُحَلَّمِ بْنِ جَثَّامَةَ بِمَكَانِهِ مِنْ خِنْدِفٍ فَتَدَاوَلَا الْخُصُومَةَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَسْمَعُ فَسَمِعْنَا عُيَيْنَةَ وَهُوَ يَقُولُ وَاللَّهِ يَا رَسُولَ اللَّهِ لَا أَدَعُهُ حَتَّى أُذِيقَ نِسَاءَهُ مِنْ الْحَرِّ مَا ذَاقَ نِسَائِي وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَلْ تَأْخُذُونَ الدِّيَةَ خَمْسِينَ فِي سَفَرِنَا هَذَا وَخَمْسِينَ إِذَا رَجَعْنَا قَالَ وَهُوَ يَأْبَى عَلَيْهِ إِذْ قَامَ رَجُلٌ مِنْ بَنِي لَيْثٍ يُقَالُ لَهُ مُكَيْتِلٌ قَصِيرٌ مَجْمُوعٌ فَقَالَ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا وَجَدْتُ لِهَذَا الْقَتِيلِ شَبَهًا فِي غُرَّةِ الْإِسْلَامِ إِلَّا كَغَنَمٍ وَرَدَتْ فَرُمِيَتْ أَوَائِلُهَا فَنَفَرَتْ أُخْرَاهَا اسْنُنِ الْيَوْمَ وَغَيِّرْ غَدًا قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ ثُمَّ قَالَ بَلْ تَأْخُذُونَ الدِّيَةَ خَمْسِينَ فِي سَفَرِنَا هَذَا وَخَمْسِينَ إِذَا رَجَعْنَا قَالَ فَقَبِلُوا الدِّيَةَ ثُمَّ قَالُوا أَيْنَ صَاحِبُكُمْ يَسْتَغْفِرْ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَامَ رَجُلٌ آدَمُ ضَرْبٌ طَوِيلٌ عَلَيْهِ حُلَّةٌ لَهُ قَدْ كَانَ تَهَيَّأَ فِيهَا لِلْقَتْلِ حَتَّى جَلَسَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا اسْمُكَ قَالَ أَنَا مُحَلَّمُ بْنُ جَثَّامَةَ قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ ثُمَّ قَالَ اللَّهُمَّ لَا تَغْفِرْ لِمُحَلَّمِ بْنِ جَثَّامَةَ فَقَامَ وَهُوَ يَتَلَقَّى دَمْعَهُ بِفَضْلِ رِدَائِهِقَالَ فَأَمَّا نَحْنُ بَيْنَنَا فَنَقُولُ إِنَّا نَرْجُو أَنْ يَكُونَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ اسْتَغْفَرَ لَهُ وَأَمَّا مَا ظَهَرَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَذَا","id":"Telah bercerita kepada kami [Ya'qub] telah bercerita kepadaku [ayahnya] dari [Muhammad bin Ishaq] telah bercerita kepadaku [Muhammad bin Ja'far bin Az Zubair] berkata: Aku mendengar [Ziyad bin Dlamrah bin Sa'id As Sulami] bercerita kepada 'Urwah bin Az Zubair dari [ayahnya, Dlamrah] dan dari [kakeknya], keduanya turut serta dalam perang Hunain bersama Rasulullah Shallalahu 'alaihi wa sallam, keduanya berkata: Rasulullah Shallalahu 'alaihi wa sallam shalat zhuhur bersama kami lalu beliau menghampiri naungan pohon, beliau duduk di sana saat berada di Hunain. Al Aqra' bin Habis dan 'Uyainah bin Hishn bin Hudzaifah bin Badr menghampiri beliau, keduanya mempersengketakan 'Amir bin Al Adlbath Al Asyja'i dan 'Uyainah yang menuntut balas kematian 'Amir, saat itu ia adalah pemimpin Ghathafan, dan Al Aqra' bin Habis membela kedudukan Muhallim bin Jatstsamah sebagai pemimpin dari Khindif. Persengketaan terjadi didekat Rasulullah Shallalahu 'alaihi wa sallam dan kami mendengar. Kami mendengar 'Uyainah berkata: Demi Allah, wahai Rasulullah aku tidak akan meninggalkannya hingga aku menikmati wanita-wanita merdekanya seperti halnya aku menikmati istri-istriku. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Tidak, tapi kalian mendapatkan diyat sebesar limapuluh dalam perjalanan kami ini dan limapuluh saat kami kembali.\" Berkata Abu Rafi': 'Uyainah enggan menerima tawaran Rasulullah Shallalahu 'alaihi wa sallam. Tiba-tiba seseorang dari Bani Laits bernama Mukaitil, orang pendek, berdiri lalu berkata: Wahai Rasulullah, aku tidak menemukan kesamaan untuk korban pembunuhan ini dipermulaan Islam melainkan seperti sekawanan kambing yang datang lalu yang ada depan dilemparkan hingga yang belakang lari. Buatlah aturan hari ini lalu rubahlah esok hari. Berkata Abu Rafi': Kemudian Rasulullah Shallalahu 'alaihi wa sallam mengangkat tangan beliau lalu bersabda: \"Tidak, tapi kalian mendapatkan diyat sebesar limapuluh dalam perjalanan kami ini dan limapuluh saat kami kembali.\" Mereka berkata: Mana teman kalian yang dimintakan ampunan oleh Rasulullah Shallalahu 'alaihi wa sallam? Seseorang berpustur tinggi dan tegap berdiri, ia mengenakan hiasan yang dipersiapkan untuk perang, ia berjalan hingga duduk dihadapan Rasulullah Shallalahu 'alaihi wa sallam, beliau bertanya: \"Siapa namamu?\" orang itu menjawab: Muhallim bin Jatstsamah. Berkata Abu Rafi': Rasulullah Shallalahu 'alaihi wa sallam mengangkat tangan beliau lalu bersabda: \"Ya Allah, Jangan Kau ampuni Muhallim bin Jatstsamah.\" Ia berdiri seraya menyumbat darahnya dengan lebihan selendangnya. Berkata Abu Rafi': Sementara itu kami berkata: Kami memohon agar Rasulullah Shallalahu 'alaihi wa sallam memintakan ampunan baginya tapi inilah yang terlihat dari Rasulullah Shallalahu 'alaihi wa sallam."},"3679":{"ar":"حَدَّثَنَا هَارُونُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي أَبُو صَخْرٍ عَنْ عَبْدِ اللَّهِ بْنِ مُعَتِّبِ بْنِ أَبِي بُرْدَةَ الظَّفَرِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَخْرُجُ مِنْ الْكَاهِنَيْنِ رَجُلٌ يَدْرُسُ الْقُرْآنَ دِرَاسَةً لَا يَدْرُسُهَا أَحَدٌ يَكُونُ بَعْدَهُ","id":"Telah bercerita kepada kami [Harun] telah bercerita kepada kami ['Abdullah bin Wahab] telah mengkhabarkan kepadaku [Abu Shakhr] dari ['Abdullah bin Mu'attib bin Abu Burdah Azh Zhafari] dari [ayahnya] dari [kakeknya] berkata: Aku mendengar Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Akan lahir dari dua dukun seseorang yang mempelajari Al Quran dengan pejalaran yang tidak pernah dilakukan oleh seorang pun setelahnya.\""},"3680":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَاقَ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنِ الْقَعْقَاعِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي حَدْرَدٍ عَنْ أَبِيهِ عَبْدِ اللَّهِ بْنِ أَبِي حَدْرَدٍ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى إِضَمَ فَخَرَجْتُ فِي نَفَرٍ مِنْ الْمُسْلِمِينَ فِيهِمْ أَبُو قَتَادَةَ الْحَارِثُ بْنُ رِبْعِيٍّ وَمُحَلَّمُ بْنُ جَثَّامَةَ بْنِ قَيْسٍ فَخَرَجْنَا حَتَّى إِذَا كُنَّا بِبَطْنِ إِضَمَ مَرَّ بِنَا عَامِرٌ الْأَشْجَعِيُّ عَلَى قَعُودٍ لَهُ مُتَيْعٌ وَوَطْبٌ مِنْ لَبَنٍ فَلَمَّا مَرَّ بِنَا سَلَّمَ عَلَيْنَا فَأَمْسَكْنَا عَنْهُ وَحَمَلَ عَلَيْهِ مُحَلَّمُ بْنُ جَثَّامَةَ فَقَتَلَهُ بِشَيْءٍ كَانَ بَيْنَهُ وَبَيْنَهُ وَأَخَذَ بَعِيرَهُ وَمُتَيْعَهُ فَلَمَّا قَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخْبَرْنَاهُ الْخَبَرَ نَزَلَ فِينَا الْقُرْآنُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا ضَرَبْتُمْ فِي سَبِيلِ اللَّهِ فَتَبَيَّنُوا وَلَا تَقُولُوا لِمَنْ أَلْقَى إِلَيْكُمْ السَّلَامَ لَسْتَ مُؤْمِنًا تَبْتَغُونَ عَرَضَ الْحَيَاةِ الدُّنْيَا فَعِنْدَ اللَّهِ مَغَانِمُ كَثِيرَةٌ كَذَلِكَ كُنْتُمْ مِنْ قَبْلُ فَمَنَّ اللَّهُ عَلَيْكُمْ فَتَبَيَّنُوا إِنَّ اللَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيرًا }","id":"Telah bercerita kepada kami [Ya'qub] telah bercerita kepada kami [ayahku] dari [Ibnu Ishaq] telah bercerita kepadaku [Yazid bin 'Abdullah bin Qusaith] dari [Al Qa'qa' bin 'Abdullah bin Abu Hadrad] dari [ayahnya, 'Abdullah bin Abu Hadrad] berkata: Rasulullah Shallalahu 'alaihi wa sallam mengutus kami ke Idlam, aku pergi bersama beberapa kalangan muslimin, diantara mereka ada Abu Qatadah Al Harits bin Rib'i dan Muhallim bin Jatstsamah bin Qais, kami pergi hingga perada di tengah-tengah Idlam, saat itu 'Amir Al Asyaja'i melintasi kami bersama beberapa orang yang tidak turut perang, ia membawa timba dan wadah susu dari kulit. Saat melintasi kami, 'Amir mengucapkan salam, kami menangkapnya lalu dibawa oleh Muhallim bin Jatstsamah lalu membunuhnya karena suatu hal yang terjadi diantara keduanya, Muhallim mengambil unta dan perbekalannya. Saat kami mendatangi Rasulullah Shallalahu 'alaihi wa sallam dan kami memberitahukan peristiwa itu kepada beliau, turunlah ayat Al Quran berkenaan dengan kami: \"Hai orang-orang yang beriman, apabila kamu pergi (berperang) di jalan Allah, maka telitilah dan janganlah kamu mengatakan kepada orang yang mengucapkan salam kepadamu: \"Kamu bukan seorang mukmin\" (lalu kamu membunuhnya), dengan maksud mencari harta benda kehidupan di dunia, karena di sisi Allah ada harta yang banyak, begitu jugalah keadaan kamu dahulu, lalu Allah menganugerahkan nikmatNya atas kamu, maka telitilah. Sesungguhnya Allah Maha mengetahui apa yang kamu kerjakan.\" (An-Nisaa': 94) "},"3681":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ عَنْ عَبْدِ الْوَاحِدِ بْنِ أَبِي عَوْنٍ عَنْ جَدَّتِهِ عَنِ ابْنِ أَبِي حَدْرَدٍ الْأَسْلَمِيِّ أَنَّهُذَكَرَ أَنَّهُ تَزَوَّجَ امْرَأَةً فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَعِينُهُ فِي صَدَاقِهَا فَقَالَ كَمْ أَصْدَقْتَ قَالَ قُلْتُ مِائَتَيْ دِرْهَمٍ قَالَ لَوْ كُنْتُمْ تَغْرِفُونَ الدَّرَاهِمَ مِنْ وَادِيكُمْ هَذَا مَا زِدْتُمْ مَا عِنْدِي مَا أُعْطِيكُمْ قَالَ فَمَكَثْتُ ثُمَّ دَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَنِي فِي سَرِيَّةٍ بَعَثَهَا نَحْوَ نَجْدٍ فَقَالَ اخْرُجْ فِي هَذِهِ السَّرِيَّةِ لَعَلَّكَ أَنْ تُصِيبَ شَيْئًا فَأُنَفِّلَكَهُ قَالَ فَخَرَجْنَا حَتَّى جِئْنَا الْحَاضِرَ مُمْسِينَ قَالَ فَلَمَّا ذَهَبَتْ فَحْمَةُ الْعِشَاءِ بَعَثَنَا أَمِيرُنَا رَجُلَيْنِ رَجُلَيْنِ قَالَ فَأَحَطْنَا بِالْعَسْكَرِ وَقَالَ إِذَا كَبَّرْتُ وَحَمَلْتُ فَكَبِّرُوا وَاحْمِلُوا وَقَالَ حِينَ بَعَثَنَا رَجُلَيْنِ لَا تَفْتَرِقَا وَلَأَسْأَلَنَّ وَاحِدًا مِنْكُمَا عَنْ خَبَرِ صَاحِبِهِ فَلَا أَجِدُهُ عِنْدَهُ وَلَا تُمْعِنُوا فِي الطَّلَبِ قَالَ فَلَمَّا أَرَدْنَا أَنْ نَحْمِلَ سَمِعْتُ رَجُلًا مِنْ الْحَاضِرِ صَرَخَ يَا خَضْرَةُ فَتَفَاءَلْتُ بِأَنَّا سَنُصِيبُ مِنْهُمْ خَضْرَةً قَالَ فَلَمَّا أَعْتَمْنَا كَبَّرَ أَمِيرُنَا وَحَمَلَ وَكَبَّرْنَا وَحَمَلْنَا قَالَ فَمَرَّ بِي رَجُلٌ فِي يَدِهِ السَّيْفُ فَاتَّبَعْتُهُ فَقَالَ لِي صَاحِبِي إِنَّ أَمِيرَنَا قَدْ عَهِدَ إِلَيْنَا أَنْ لَا نُمْعِنَ فِي الطَّلَبِ فَارْجِعْ فَلَمَّا رَأَيْتُ إِلَّا أَنْ أَتَّبِعَهُ قَالَ وَاللَّهِ لَتَرْجِعَنَّ أَوْ لَأَرْجِعَنَّ إِلَيْهِ وَلَأُخْبِرَنَّهُ أَنَّكَ أَبَيْتَ قَالَ فَقُلْتُ وَاللَّهِ لَأَتَّبِعَنَّهُ قَالَ فَاتَّبَعْتُهُ حَتَّى إِذَا دَنَوْتُ مِنْهُ رَمَيْتُهُ بِسَهْمٍ عَلَى جُرَيْدَاءِ مَتْنِهِ فَوَقَعَ فَقَالَ ادْنُ يَا مُسْلِمُ إِلَى الْجَنَّةِ فَلَمَّا رَآنِي لَا أَدْنُو إِلَيْهِ وَرَمَيْتُهُ بِسَهْمٍ آخَرَ فَأَثْخَنْتُهُ رَمَانِي بِالسَّيْفِ فَأَخْطَأَنِي وَأَخَذْتُ السَّيْفَ فَقَتَلْتُهُ وَاحْتَزَزْتُ بِهِ رَأْسَهُ وَشَدَدْنَا نَعَمًا كَثِيرَةً وَغَنَمًا قَالَ ثُمَّ انْصَرَفْنَا قَالَ فَأَصْبَحْتُ فَإِذَا بَعِيرِي مَقْطُورٌ بِهِ بَعِيرٌ عَلَيْهِ امْرَأَةٌ جَمِيلَةٌ شَابَّةٌ قَالَ فَجَعَلَتْ تَلْتَفِتُ خَلْفَهَا فَتُكَبِّرُ فَقُلْتُ لَهَا إِلَى أَيْنَ تَلْتَفِتِينَ قَالَتْ إِلَى رَجُلٍ وَاللَّهِ إِنْ كَانَ حَيًّا خَالَطَكُمْ قَالَ قُلْتُ وَظَنَنْتُ أَنَّهُ صَاحِبِي الَّذِي قَتَلْتُ قَدْ وَاللَّهِ قَتَلْتُهُ وَهَذَا سَيْفُهُ وَهُوَ مُعَلَّقٌ بِقَتَبِ الْبَعِيرِ الَّذِي أَنَا عَلَيْهِ قَالَ وَغِمْدُ السَّيْفِ لَيْسَ فِيهِ شَيْءٌ مُعَلَّقٌ بِقَتَبِ بَعِيرِهَا فَلَمَّا قُلْتُ ذَلِكَ لَهَا قَالَتْ فَدُونَكَ هَذَا الْغِمْدَ فَشِمْهُ فِيهِ إِنْ كُنْتَ صَادِقًا قَالَ فَأَخَذْتُهُ فَشِمْتُهُ فِيهِ فَطَبَقَهُ قَالَ فَلَمَّا رَأَتْ ذَلِكَ بَكَتْ قَالَ فَقَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي مِنْ ذَلِكَ النَّعَمِ الَّذِي قَدِمْنَا بِهِ","id":"Telah bercerita kepada kami [Ya'qub] telah bercerita kepada kami [ayahku] dari ['Abdullah bin Ja'far] dari ['Abdul Wahid bin Abu 'Aun] dari [neneknya] dari [Ibnu Abi Hadrad Al Aslami] ia menyebutkan bahwa ia menikahi seorang wanita lalu mendatangi Rasulullah Shallalahu 'alaihi wa sallam untuk meminta bantuan membayar maharnya. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Berapa kau memberinya mahar?\" ia menjawab: Duaratus dirham. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Andai kalian menciduk dirham-dirham dari lembah kalian ini niscaya milik kalian lebih banyak dari milik kami dan niscaya kau tidak memberimu. Ia berkata: Aku diam lalu Rasulullah Shallalahu 'alaihi wa sallam memanggilku kemudian beliau mengirimku untuk menemui tentara sariyah yang beliau kirim ke arah Najed. Beliau bersabda: \"Temuilah tentara sariyah itu mudah-mudahan mereka mendapatkan sesuatu lalu aku akan memberimu harta rampasan perang.\" Berkata Ibnu Abi Hadrad: Kami pergi hingga tiba di Hadlir pada sore hari. Saat gelapnya malam berlalu, pemimpin kami mengutus kami dua orang-dua orang, kami mengepung kamp. Pemimpin kami berkata: Bila aku bertakbir dan menyerang, kalian harus bertakbir dan menyerang. Pemimpin kami berkata saat mengutus dua orang: Kalian jangan berpencar dan aku akan bertanya kepada salah seorang dari kalian berdua tentang kondisi temannya. Tapi aku tidak menemukannya didekatnya sementara mereka tidak serius mencari. Saat kami hendak menyerang, kami mendengar seseorang dari Hadlar berteriak: Wahai orang-orang Hadlar. Mereka merasa sial bahwa kami maju, pemimpin kami bertakbir dan menyerang, kami pun bertakbir dan menyerang. Berkata Ibnu Abi Hadrad: Seseorang melintasi kami dengan membawa pedang, aku mengikutinya lalu kawanku berkata: Pemimpin kita memerintahkan agar kita tidak teliti dalam mencari, karena itu kembalilah. Saat aku mengikutinya, ia berkata: Demi Allah, kau yang kembali atau aku yang kembali menemuinya dan aku akan memberitahukan padanya bahwa kau menyerang. Aku berkata: Demi Allah aku akan mengikutinya. Aku pun mengikuti orang itu hingga aku mendekatinya, aku melesakkan anak panah ke musuh lain lalu aku membunuhnya, orang yang aku ikuti melemparkan pedang ke arahku tapi meleset, aku ambil pedangnya lalu aku membunuhnya dan memotong kepalanya, kami mengikat unta dan kambing dalam jumlah besar. Kami pun kembali pulang. Dipagi harinya ternyata unta milikku dihela oleh unta lain yang ditunggangi oleh wanita muda yang cantik. Wanita itu menoleh ke belakang lalu bertakbir. Aku berkata: Kemana kau menoleh? Wanita itu menjawab: Ke seseorang yang demi Allah bila masih hidup akan menemani kalian. Aku kira orang yang dimaksud adalah temanku yang aku bunuh. Aku berkata: Demi Allah aku telah membunuhnya dan ini pedang miliknya. Pedang itu tergantung di pelana unta yang aku tunggangi sementara sarung pedang yang tergantung di pelana unta wanita itu kosong. Saat aku mengatakan hal itu pada wanita itu, wanita itu berkata: Tetaplah berada di tempatmu, angkatlah sarung pedang ini bila kau benar. Lalu aku mengambilnya dan mengangkatnya, ia lalu menutupnya. Saat melihatnya, wanita itu menangis. Kami tiba dihadapan Rasulullah Shallalahu 'alaihi wa sallam lalu beliau memberi sebagaian dari harta yang kami bawa itu."},"3682":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي عُثْمَانَ قَالَقَالَ بِلَالٌ يَا رَسُولَ اللَّهِ لَا تَسْبِقْنِي بِآمِينَ","id":"Telah bercerita kepada kami [Muhammad bin Fudlail] telah bercerita kepada kami ['Ashim] dari [Abu 'Utsman] berkata: Berkata [Bilal]: Wahai Rasulullah, jangan Tuan mendahuluiku dengan ucapan: AAMIIN."},"3683":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ عَنْ بِلَالٍ قَالَمَسَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْخُفَّيْنِ وَالْخِمَارِ","id":"Telah bercerita kepada kami [Abu Mu'awiyah] telah bercerita kepada kami [Al A'masy] dari [Al Hakam] dari ['Abdur Rahman bin Abu Laila] dari [Ka'ab bin 'Ujrah] dari [Bilal] berkata: Rasulullah Shallalahu 'alaihi wa sallam membasuh sepatu dan selendang."},"3684":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَ قَالَقُلْتُ لِبِلَالٍ كَيْفَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرُدُّ عَلَيْهِمْ حِينَ كَانُوا يُسَلِّمُونَ عَلَيْهِ فِي الصَّلَاةِ قَالَ كَانَ يُشِيرُ بِيَدِهِ","id":"Telah bercerita kepada kami [Waki'] telah bercerita kepada kami [Hisyam bin Sa'ad] dari [Nafi'] dari [Ibnu 'Umar] berkata: Aku bertanya kepada [Bilal]: Bagaiaman cara Rasulullah Shallalahu 'alaihi wa sallam menjawab salam orang bila sedang shalat? Bilal menjawab: Beliau berisyarat dengan tangan beliau."},"3685":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ بِلَالٍ قَالَلَمْ يَكُنْ يَنْهَى عَنْ الصَّلَاةِ إِلَّا عِنْدَ طُلُوعِ الشَّمْسِ فَإِنَّهَا تَطْلُعُ بَيْنَ قَرْنَيْ الشَّيْطَانِ","id":"Telah bercerita kepada kami [Waki'] dari [Syu'bah] dari [Qais bin Muslim] dari [Thariq bin Syihab] dari [Bilal] berkata: Rasulullah Shallalahu 'alaihi wa sallam tidak melarang shalat kecuali saat matahari terbit karena saat itu matahari terbit di antara dua tanduk setan."},"3686":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا أَبُو الْعَلَاءِ وَمُحَمَّدُ بْنُ يَزِيدَ عَنْ أَبِي الْعَلَاءِ عَنْ قَتَادَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ بِلَالٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah bercerita kepada kami [Yazid bin Harun] telah bercerita kepada kami [Abu Al 'Ala`] dan [Muhammad bin Yazid] dari [Abu Al 'Ala`] dari [Qatadah] dari [Syahr bin Hausyab] dari [Bilal] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Orang yang membekam dan yang dibekam hendaklah berbuka.\""},"3687":{"ar":"حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنِ الصُّنَابِحِيِّ عَنْ بِلَالٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْلَةُ الْقَدْرِ لَيْلَةُ أَرْبَعٍ وَعِشْرِينَ","id":"Telah bercerita kepada kami [Musa bin Dawud] telah bercerita kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari [Ash Shunabihi] dari [Bilal] nabi Shallalahu 'alaihi wa sallam bersabda: \"Lailatul qadar adalah malam keduapuluh empat.\""},"3688":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ وَعَبْدُ الرَّزَّاقِ قَالَا أَنْبَأَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو بَكْرِ بْنُ حَفْصِ بْنِ عُمَرَ أَخْبَرَنِي أَبُو عَبْدِ الرَّحْمَنِ عَنْ أَبِي عَبْدِ اللَّهِ أَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍيَسْأَلُ بِلَالًا كَيْفَ مَسَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْخُفَّيْنِ قَالَ تَبَرَّزَ ثُمَّ دَعَا بِمِطْهَرَةٍ أَيْ إِدَاوَةٍ فَغَسَلَ وَجْهَهُ وَيَدَيْهِ ثُمَّ مَسَحَ عَلَى خُفَّيْهِ وَعَلَى خِمَارِ الْعِمَامَةِ قَالَ عَبْدُ الرَّزَّاقِ ثُمَّ دَعَا بِمِطْهَرَةٍ بِالْإِدَاوَةِ","id":"Telah bercerita kepada kami [Muhammad bin Bakar] dan [Abdur Razzaq] keduanya berkata: Telah memberitakan kepada kami [Ibnu Juraij] telah mengkhabarkan kepadaku [Abu Bakar bin Hafsh bin 'Umar] telah mengkhabarkan kepadaku [Abu 'Abdur Rahman] dari [Abu 'Abdullah] ia mendengar 'Abdur Rahman bin 'Auf bertanya kepada [Bilal]: Bagaimana cara Rasulullah Shallalahu 'alaihi wa sallam mengusap sepatu, Bilal menjawab; Beliau buang besar lalu minta ember, beliau membasuh wajah dan kedua tangan lalu membasuh kedua sepatu dan selendang beliau. Berkata 'Abdur Razzaq: Lalu beliau meminta ember bersisi air."},"3689":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ حَدَّثَنَا مَكْحُولٌ عَنْ نُعَيْمِ بْنِ خِمَارٍ عَنْ بِلَالٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ امْسَحُوا عَلَى الْخُفَّيْنِ وَالْخِمَارِ","id":"Telah bercerita kepada kami [Abu Sa'id, budak Bani Hasyim] telah bercerita kepada kami [Muhammad bin Rasyid] telah bercerita kepada kami [Makhluk] dari [Nu'aim bin Khimar] dari [Bilal], Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Usaplah sepatu dan kerudung.\""},"3690":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْكَعْبَةَ وَعُثْمَانُ بْنُ طَلْحَةَ وَأُسَامَةُ بْنُ زَيْدٍ وَبِلَالٌ قَدْ غَلَقَهَا فَلَمَّا خَرَجَ سَأَلْتُ بِلَالًا مَاذَا صَنَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَرَكَ عَمُودَيْنِ عَنْ يَمِينِهِ وَعَمُودًا عَنْ يَسَارِهِ وَثَلَاثَةَ أَعْمِدَةٍ خَلْفَهُ ثُمَّ صَلَّى بَيْنَهُ وَبَيْنَ الْقِبْلَةِ ثَلَاثَةُ أَذْرُعٍ","id":"Telah bercerita kepada kami ['Abdur Rahman] telah bercerita kepada kami [Malik] dari [Nafi'] dari [Ibnu 'Umar], Rasulullah Shallalahu 'alaihi wa sallam masuk ka'bah bersama 'Utsman, Thalhah dan Usamah bin Zaid sementara Bilal menutup pintunya. Saat keluar aku bertanya kepada [Bilal] apa yang diakukan nabi Shallalahu 'alaihi wa sallam? Ia menjawab: Beliau meninggalkan dua tiang di sebelah kanan, satu tiang di sebelah kiri dan tiga tiang di belakang beliau lalu beliau shalat, jarak antara beliau dengan kiblat sejauh tiga dzira'."},"3691":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا إِسْرَائِيلُ عَنِ أبِي إِسْحَاقَ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ عَنْ بِلَالٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُوذِنُهُ بِالصَّلَاةِ وَهُوَ يُرِيدُ الصِّيَامَ فَشَرِبَ ثُمَّ نَاوَلَنِي وَخَرَجَ إِلَى الصَّلَاةِ","id":"Telah bercerita kepada kami [Husain bin Muhammad] telah bercerita kepada kami [Isra`il] dari [Abu Ishaq] dari ['Abdullah bin Ma'qal] dari [Bilal] berkata: Aku mendatangi nabi Shallalahu 'alaihi wa sallam untuk memberitahukan shalat, beliau hendak puasa, beliau minum lalu memberiku (minum), setelah itu beliau keluar untuk shalat."},"3692":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَجِبْتُ مِنْ قَضَاءِ اللَّهِ لِلْمُؤْمِنِ إِنَّ أَمْرَ الْمُؤْمِنِ كُلَّهُ خَيْرٌ وَلَيْسَ ذَلِكَ إِلَّا لِلْمُؤْمِنِ إِنْ أَصَابَتْهُ سَرَّاءُ فَشَكَرَ كَانَ خَيْرًا لَهُ وَإِنْ أَصَابَتْهُ ضَرَّاءُ فَصَبَرَ كَانَ خَيْرًا لَهُ","id":"Telah bercerita kepada kami ['Abdur Rahman bin Mahdi] telah bercerita kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari ['Abdur Rahman bin Abu Laila] dari [Shuhaib] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Aku kagum akan ketetapan Allah untuk kaum mu`min, sesungguhnya perihal orang mu`min itu seluruhnya baik dan itu hanya berlaku bagi orang mu`min; bila mendapat kesenangan ia bersyukur dan bersyukur itu baik baginya dan bila tertimpa musibah ia bersabar dan kesabaran itu baik baginya.\""},"3693":{"ar":"حَدَّثَنَا يَزِيدُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَهْلُ الْجَنَّةِ الْجَنَّةَ نُودُوا يَا أَهْلَ الْجَنَّةِ إِنَّ لَكُمْ عِنْدَ اللَّهِ مَوْعِدًا لَمْ تَرَوْهُ فَقَالُوا وَمَا هُوَ أَلَمْ يُبَيِّضْ وُجُوهَنَا وَيُزَحْزِحْنَا عَنْ النَّارِ وَيُدْخِلْنَا الْجَنَّةَ قَالَ فَيُكْشَفُ الْحِجَابُ قَالَ فَيَنْظُرُونَ إِلَيْهِ فَوَاللَّهِ مَا أَعْطَاهُمْ اللَّهُ شَيْئًا أَحَبَّ إِلَيْهِمْ مِنْهُ ثُمَّ قَرَأَ{ لِلَّذِينَ أَحْسَنُوا الْحُسْنَى وَزِيَادَةٌ }وَقَالَ مَرَّةً إِذَا دَخَلَ أَهْلُ الْجَنَّةِ","id":"Telah bercerita kepada kami [Yazid] telah bercerita kepada kami [Hammad bin Salamah] dari [Tsabit Al Bannanni] dari ['Abdur Rahman bin Abu Laila] dari [Shuhaib] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Bila para penghuni surga masuk surga, mereka dipanggil: Wahai penghuni surga, sesungguhnya kalian memiliki janji di sisi Allah yang belum kalian lihat. Mereka bertanya: Apa itu, bukankah Ia telah memperseri wajah kami, menyelematkan kami dari neraka dan memasukkan kami ke surga?\" Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Hijab pun di buka lalu mereka melihatNya. Demi Allah, tidak ada sesuatu pun yang diberikan Allah kepada mereka yang lebih mereka senangi melebihi hal itu (melihat Allah, pent.).\" lalu beliau membaca: \"Bagi orang-orang yang berbuat baik, ada pahala yang terbaik (surga) dan tambahannya.\" (Yuunus: 26) "},"3694":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ زُهَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ حَمْزَةَ بْنِ صُهَيْبٍأَنَّ صُهَيْبًا كَانَ يُكَنَّى أَبَا يَحْيَى وَيَقُولُ إِنَّهُ مِنْ الْعَرَبِ وَيُطْعِمُ الطَّعَامَ الْكَثِيرَ فَقَالَ لَهُ عُمَرُ يَا صُهَيْبُ مَا لَكَ تُكَنَّى أَبَا يَحْيَى وَلَيْسَ لَكَ وَلَدٌ وَتَقُولُ إِنَّكَ مِنْ الْعَرَبِ وَتُطْعِمُ الطَّعَامَ الْكَثِيرَ وَذَلِكَ سَرَفٌ فِي الْمَالِ فَقَالَ صُهَيْبٌ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَنَّانِي أَبَا يَحْيَى وَأَمَّا قَوْلُكَ فِي النَّسَبِ فَأَنَا رَجُلٌ مِنْ النَّمِرِ بْنِ قَاسِطٍ مِنْ أَهْلِ الْمَوْصِلِ وَلَكِنِّي سُبِيتُ غُلَامًا صَغِيرًا قَدْ غَفَلْتُ أَهْلِي وَقَوْمِي وَأَمَّا قَوْلُكَ فِي الطَّعَامِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ خِيَارُكُمْ مَنْ أَطْعَمَ الطَّعَامَ وَرَدَّ السَّلَامَ فَذَلِكَ الَّذِي يَحْمِلُنِي عَلَى أَنْ أُطْعِمَ الطَّعَامَ","id":"Telah bercerita kepada kami ['Abdur Rahman bin Mahdi] dari [Zuhair] dari ['Abdullah bin Muhammad bin 'Uqail] dari [Hamzah bin Shuhaib] bahwa [Shuhaib] diberi kuniah Abu Yahya, ia berkata: Ia berasal dari arab dan sering memberi makan. 'Umar bertanya kepadanya: Hai Shuhaib, kenapa kau diberi kuniah Abu Yahya padahal kau tidak punya anak, kau berkata bahwa kau dari bangsa arab dan sering memberi makan, itu adalah tindakan berlebihan dalam harta? Shuhaib menjawab: Rasulullah Shallalahu 'alaihi wa sallam memberiku kuniah Abu Yahya, berkenaan dengan perkataanmu tentang nasab, aku berasal dari Bani An Namir bin Qasith dari Maushil, tapi aku ditawan saat masih kecil, keluarga dan kaumku melupakanku, sedangkan perkataanmu tentang makanan, Rasulullah Shallalahu 'alaihi wa sallam pernah bersabda: \"Yang terbaik dari kalian adalah yang memberi makan dan menjawab salam, \" itulah yang mendorongku untuk memberi makan."},"3695":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى هَمَسَ شَيْئًا لَا أَفْهَمُهُ وَلَا يُخْبِرُنَا بِهِ قَالَ أَفَطِنْتُمْ لِي قُلْنَا نَعَمْ قَالَ إِنِّي ذَكَرْتُ نَبِيًّا مِنْ الْأَنْبِيَاءِ أُعْطِيَ جُنُودًا مِنْ قَوْمِهِ فَقَالَ مَنْ يُكَافِئُ هَؤُلَاءِ أَوْ مَنْ يَقُومُ لِهَؤُلَاءِ أَوْ غَيْرَهَا مِنْ الْكَلَامِ فَأُوحِيَ إِلَيْهِ أَنْ اخْتَرْ لِقَوْمِكَ إِحْدَى ثَلَاثٍ إِمَّا أَنْ نُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِنْ غَيْرِهِمْ أَوْ الْجُوعَ أَوْ الْمَوْتَ فَاسْتَشَارَ قَوْمَهُ فِي ذَلِكَ فَقَالُوا أَنْتَ نَبِيُّ اللَّهِ فَكُلُّ ذَلِكَ إِلَيْكَ خِرْ لَنَا فَقَامَ إِلَى الصَّلَاةِ وَكَانُوا إِذَا فَزِعُوا فَزِعُوا إِلَى الصَّلَاةِ فَصَلَّى مَا شَاءَ اللَّهُ قَالَ ثُمَّ قَالَ أَيْ رَبِّ أَمَّا عَدُوٌّ مِنْ غَيْرِهِمْ فَلَا أَوْ الْجُوعُ فَلَا وَلَكِنْ الْمَوْتُ فَسُلِّطَ عَلَيْهِمْ الْمَوْتُ فَمَاتَ مِنْهُمْ سَبْعُونَ أَلْفًا فَهَمْسِي الَّذِي تَرَوْنَ أَنِّي أَقُولُ اللَّهُمَّ بِكَ أُقَاتِلُ وَبِكَ أُصَاوِلُ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] Telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari ['Abdur Rahman bin Abu Laila] dari [Shuhaib] berkata: Bila shalat, Rasulullah Shallalahu 'alaihi wa sallam membaca pelan yang tidak aku fahami dan beliau tidak memberitahukannya kepada kami. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Apakah kalian ingin mengatahuinya?\" kami menjawab: Ya. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Sesungguhnya aku mengingat salah seorang nabi, aku diberi salu bala tentara dari kaumnya.\" Beliau bersabda: \"Siapa yang membalas mereka?\" atau beliau bersabda \"Siapa yang menunaikan untuk mereka?\" atau sabda lainnya, lalu nabi itu diberi wahyu: Pilihlah salah satu dari tiga hal untuk kaummu, Kami memberi kuasa musuh dari selain mereka atas mereka, lapar ataukah kematian. Ia meminta pendapat ummatnya menganai hal itu, mereka berkata: Engkau Nabi Allah, semua itu terserah engkau, pilihkan untuk kami. Lalu ia berdiri untuk shalat dan biasanya bila mereka dirundung ketakukan, mereka shalat lalu ia shalat dengan lamanya. Berkata Shuhaib: Setelah itu Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ya Rabb, berkenaan dengan musuh dari selain mereka, jangan, atau lapar, jangan, tapi kematian saja.\" Lalu kematian dikuasakan kepada mereka hingga tujuhpuluh ribu diantara mereka meninggal dunia. Lalu bisikanku yang kalian lihat, aku berdoa: Ya Allah, bersamaMu aku berperang dan bersamaMu aku menyerang, tidak ada dan tiada kekuatan kecuali milik Allah.\""},"3696":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ إِذَا لَقِيَ الْعَدُوَّ اللَّهُمَّ بِكَ أَحُولُ وَبِكَ أَصُولُ وَبِكَ أُقَاتِلُ","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Hammad] dari [Tsabit] dari ['Abdur Rahman bin Abu Laila] dari [Shuhaib] Rasulullah Shallalahu 'alaihi wa sallam bersabda bila bertemu musuh: \"Ya Allah, bersamaMu aku berdaya, bersamaMu aku menyerang dan bersamaMu aku berperang.\""},"3697":{"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ حَمْزَةَ بْنِ صُهَيْبٍ عَنْ أَبِيهِ قَالَفَقَالَ لِعُمَرَ أَمَّا قَوْلُكَ اكْتَنَيْتَ وَلَيْسَ لَكَ وَلَدٌ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَنَّانِي أَبَا يَحْيَى فَأَمَّا قَوْلُكَ فِيكَ سَرَفٌ فِي الطَّعَامِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُكُمْ مَنْ أَطْعَمَ الطَّعَامَ أَوْ الَّذِينَ يُطْعِمُونَ الطَّعَامَ","id":"Telah menceritakan kepada kami [Zakariya bin 'Adi] Telah menceritakan kepada kami ['Ubaidullah bin 'Amru] dari ['Abdullah bin Muhammad bin 'Aqil] dari [Hamzah bin Shuhaib] dari [ayahnya] berkata lalu ia berkata kepada 'Umar: Berkenaan dengan perkataanmu bahwa aku diberi kuniah padahal kau tidak punya pemuda adalah karena Rasulullah Shallalahu 'alaihi wa sallam memberiku kuniah Abu Yahya, sedangkan perkataannmu bahwa aku berlebihan dalam memberi makanan karena Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Yang terbaik diantara kalian adalah yang memberi makan atau orang-orang yang memberi makan.\""},"3698":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدٌ مَعَ أَصْحَابِهِ إِذْ ضَحِكَ فَقَالَ أَلَا تَسْأَلُونِي مِمَّ أَضْحَكُ قَالُوا يَا رَسُولَ اللَّهِ وَمِمَّ تَضْحَكُ قَالَ عَجِبْتُ لِأَمْرِ الْمُؤْمِنِ إِنَّ أَمْرَهُ كُلَّهُ خَيْرٌ إِنْ أَصَابَهُ مَا يُحِبُّ حَمِدَ اللَّهَ وَكَانَ لَهُ خَيْرٌ وَإِنْ أَصَابَهُ مَا يَكْرَهُ فَصَبَرَ كَانَ لَهُ خَيْرٌ وَلَيْسَ كُلُّ أَحَدٍ أَمْرُهُ كُلُّهُ لَهُ خَيْرٌ إِلَّا الْمُؤْمِنُقَالَ أَبِي و حَدَّثَنَاه عَفَّانُ أَيْضًا حَدَّثَنَاهُ سُلَيْمَانُ حَدَّثَنَا ثَابِتٌ هَذَا اللَّفْظَ بِعَيْنِهِ وَأُرَاهُ وَهِمَ هَذَا لَفْظُ حَمَّادٍ وَقَدْ حَدَّثَنَا قَالَ سُلَيْمَانُ حَدَّثَنَا ثَابِتٌ نَحْوًا مِنْ لَفْظِ عَبْدِ الرَّحْمَنِ عَنْ سُلَيْمَانَ وَذَلِكَ مِنْ كِتَابِهِ قَرَأَهُ عَلَيْنَا","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammad bin Salamah] Telah menceritakan kepada kami [Tsabit] dari ['Abdur Rahman bin Abu laila] dari [Shuhaib] berkata: Saat Rasulullah Shallalahu 'alaihi wa sallam duduk bersama pada sahabat, tiba-tiba beliau tertawa, beliau bersabda: \"Apakah kalian tidak bertanya kepadaku kenapa aku tertawa?\" mereka bertanya: Wahai Rasulullah, apa yang Tuan tertawakan? Beliau bersabda: \"Aku kagum akan hal ihwal orang mu`min, bila mendapat kesenangan ia memuji Allah dan dan bersyukur itu baik baginya dan bila tertimpa musibah ia bersabar dan kesabaran itu baik baginya, tidak semua orang yang seluruh hal ihwalnya baik kecuali orang mu`min.\" Berkata ayahku: Dan kami menceritakannya kepada ['Affan], kami menceritakannya kepada [Sulaiman] Telah menceritakan kepada kami [Tsabit] teks matan ini secara persis dan menurutku Hammad salah dalam teks ini, ia menceritakan kepada kami, berkata Sulaiman; Telah menceritakan kepada kami Tsabit seperti teks matan Abdur Rahman dari Sulaiman, riwayat itu dari kitabnya, ia membacanya untuk kami."},"3699":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا ثَابِتٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ مَلِكٌ فِيمَنْ كَانَ قَبْلَكُمْ وَكَانَ لَهُ سَاحِرٌ فَلَمَّا كَبِرَ السَّاحِرُ قَالَ لِلْمَلِكِ إِنِّي قَدْ كَبِرَتْ سِنِّي وَحَضَرَ أَجَلِي فَادْفَعْ إِلَيَّ غُلَامًا فَلَأُعَلِّمُهُ السِّحْرَ فَدَفَعَ إِلَيْهِ غُلَامًا فَكَانَ يُعَلِّمُهُ السِّحْرَ وَكَانَ بَيْنَ السَّاحِرِ وَبَيْنَ الْمَلِكِ رَاهِبٌ فَأَتَى الْغُلَامُ عَلَى الرَّاهِبِ فَسَمِعَ مِنْ كَلَامِهِ فَأَعْجَبَهُ نَحْوُهُ وَكَلَامُهُ فَكَانَ إِذَا أَتَى السَّاحِرَ ضَرَبَهُ وَقَالَ مَا حَبَسَكَ وَإِذَا أَتَى أَهْلَهُ ضَرَبُوهُ وَقَالُوا مَا حَبَسَكَ فَشَكَا ذَلِكَ إِلَى الرَّاهِبِ فَقَالَ إِذَا أَرَادَ السَّاحِرُ أَنْ يَضْرِبَكَ فَقُلْ حَبَسَنِي أَهْلِي وَإِذَا أَرَادَ أَهْلُكَ أَنْ يَضْرِبُوكَ فَقُلْ حَبَسَنِي السَّاحِرُ وَقَالَ فَبَيْنَمَا هُوَ كَذَلِكَ إِذْ أَتَى ذَاتَ يَوْمٍ عَلَى دَابَّةٍ فَظِيعَةٍ عَظِيمَةٍ وَقَدْ حَبَسَتْ النَّاسَ فَلَا يَسْتَطِيعُونَ أَنْ يَجُوزُوا فَقَالَ الْيَوْمَ أَعْلَمُ أَمْرُ الرَّاهِبِ أَحَبُّ إِلَى اللَّهِ أَمْ أَمْرُ السَّاحِرِ فَأَخَذَ حَجَرًا فَقَالَ اللَّهُمَّ إِنْ كَانَ أَمْرُ الرَّاهِبِ أَحَبَّ إِلَيْكَ وَأَرْضَى لَكَ مِنْ السَّاحِرِ فَاقْتُلْ هَذِهِ الدَّابَّةَ حَتَّى يَجُوزَ النَّاسُ وَرَمَاهَا فَقَتَلَهَا وَمَضَى النَّاسُ فَأَخْبَرَ الرَّاهِبَ بِذَلِكَ فَقَالَ أَيْ بُنَيَّ أَنْتَ أَفْضَلُ مِنِّي وَإِنَّكَ سَتُبْتَلَى فَإِنْ ابْتُلِيتَ فَلَا تَدُلَّ عَلَيَّ فَكَانَ الْغُلَامُ يُبْرِئُ الْأَكْمَهَ وَسَائِرَ الْأَدْوَاءِ وَيَشْفِيهِمْ وَكَانَ جَلِيسٌ لِلْمَلِكِ فَعَمِيَ فَسَمِعَ بِهِ فَأَتَاهُ بِهَدَايَا كَثِيرَةٍ فَقَالَ اشْفِنِي وَلَكَ مَا هَاهُنَا أَجْمَعُ فَقَالَ مَا أَشْفِي أَنَا أَحَدًا إِنَّمَا يَشْفِي اللَّهُ عَزَّ وَجَلَّ فَإِنْ أَنْتَ آمَنْتَ بِهِ فَدَعَوْتُ اللَّهَ فَشَفَاكَ فَآمَنَ فَدَعَا اللَّهَ لَهُ فَشَفَاهُ ثُمَّ أَتَى الْمَلِكَ فَجَلَسَ مِنْهُ نَحْوَ مَا كَانَ يَجْلِسُ فَقَالَ لَهُ الْمَلِكُ يَا فُلَانُ مَنْ رَدَّ عَلَيْكَ بَصَرَكَ فَقَالَ رَبِّي قَالَ أَنَا قَالَ لَا لَكِنْ رَبِّي وَرَبُّكَ اللَّهُ قَالَ أَوَلَكَ رَبٌّ غَيْرِي قَالَ نَعَمْ فَلَمْ يَزَلْ يُعَذِّبُهُ حَتَّى دَلَّهُ عَلَى الْغُلَامِ فَبَعَثَ إِلَيْهِ فَقَالَ أَيْ بُنَيَّ قَدْ بَلَغَ مِنْ سِحْرِكَ أَنْ تُبْرِئَ الْأَكْمَهَ وَالْأَبْرَصَ وَهَذِهِ الْأَدْوَاءَ قَالَ مَا أَشْفِي أَنَا أَحَدًا مَا يَشْفِي غَيْرُ اللَّهِ عَزَّ وَجَلَّ قَالَ أَنَا قَالَ لَا قَالَ أَوَلَكَ رَبٌّ غَيْرِي قَالَ نَعَمْ رَبِّي وَرَبُّكَ اللَّهُ فَأَخَذَهُ أَيْضًا بِالْعَذَابِ فَلَمْ يَزَلْ بِهِ حَتَّى دَلَّ عَلَى الرَّاهِبِ فَأَتَى بِالرَّاهِبِ فَقَالَ ارْجِعْ عَنْ دِينِكِ فَأَبَى فَوَضَعَ الْمِنْشَارَ فِي مَفْرِقِ رَأْسِهِ حَتَّى وَقَعَ شِقَّاهُ وَقَالَ لِلْأَعْمَى ارْجِعْ عَنْ دِينِكَ فَأَبَى فَوَضَعَ الْمِنْشَارَ فِي مَفْرِقِ رَأْسِهِ حَتَّى وَقَعَ شِقَّاهُ فِي الْأَرْضِ وَقَالَ لِلْغُلَامِ ارْجِعْ عَنْ دِينِكَ فَأَبَى فَبَعَثَ بِهِ مَعَ نَفَرٍ إِلَى جَبَلِ كَذَا وَكَذَا فَقَالَ إِذَا بَلَغْتُمْ ذُرْوَتَهُ فَإِنْ رَجَعَ عَنْ دِينِهِ وَإِلَّا فَدَهْدِهُوهُ مِنْ فَوْقِهِ فَذَهَبُوا بِهِ فَلَمَّا عَلَوْا بِهِ الْجَبَلَ قَالَ اللَّهُمَّ اكْفِنِيهِمْ بِمَا شِئْتَ فَرَجَفَ بِهِمْ الْجَبَلُ فَدُهْدِهُوا أَجْمَعُونَ وَجَاءَ الْغُلَامُ يَتَلَمَّسُ حَتَّى دَخَلَ عَلَى الْمَلِكِ فَقَالَ مَا فَعَلَ أَصْحَابُكَ فَقَالَ كَفَانِيهِمْ اللَّهُ عَزَّ وَجَلَّ فَبَعَثَهُ مَعَ نَفَرٍ فِي قُرْقُورٍ فَقَالَ إِذَا لَجَجْتُمْ بِهِ الْبَحْرَ فَإِنْ رَجَعَ عَنْ دِينِهِ وَإِلَّا فَغَرِّقُوهُ فَلَجَّجُوا بِهِ الْبَحْرَ فَقَالَ الْغُلَامُ اللَّهُمَّ اكْفِنِيهِمْ بِمَا شِئْتَ فَغَرِقُوا أَجْمَعُونَ وَجَاءَ الْغُلَامُ يَتَلَمَّسُ حَتَّى دَخَلَ عَلَى الْمَلِكِ فَقَالَ مَا فَعَلَ أَصْحَابُكَ قَالَ كَفَانِيهِمْ اللَّهُ عَزَّ وَجَلَّ ثُمَّ قَالَ لِلْمَلِكِ إِنَّكَ لَسْتَ بِقَاتِلِي حَتَّى تَفْعَلَ مَا آمُرُكَ بِهِ فَإِنْ أَنْتَ فَعَلْتَ مَا آمُرُكَ بِهِ قَتَلْتَنِي وَإِلَّا فَإِنَّكَ لَا تَسْتَطِيعُ قَتْلِي قَالَ وَمَا هُوَ قَالَ تَجْمَعُ النَّاسَ فِي صَعِيدٍ ثُمَّ تَصْلُبُنِي عَلَى جِذْعٍ فَتَأْخُذُ سَهْمًا مِنْ كِنَانَتِي ثُمَّ قُلْ بِسْمِ اللَّهِ رَبِّ الْغُلَامِ فَإِنَّكَ إِذَا فَعَلْتَ ذَلِكَ قَتَلْتَنِي فَفَعَلَ وَوَضَعَ السَّهْمَ فِي كَبِدِ قَوْسِهِ ثُمَّ رَمَى فَقَالَ بِسْمِ اللَّهِ رَبِّ الْغُلَامِ فَوَضَعَ السَّهْمَ فِي صُدْغِهِ فَوَضَعَ الْغُلَامُ يَدَهُ عَلَى مَوْضِعِ السَّهْمِ وَمَاتَ فَقَالَ النَّاسُ آمَنَّا بِرَبِّ الْغُلَامِ فَقِيلَ لِلْمَلِكِ أَرَأَيْتَ مَا كُنْتَ تَحْذَرُ فَقَدْ وَاللَّهِ نَزَلَ بِكَ قَدْ آمَنَ النَّاسُ كُلُّهُمْ فَأَمَرَ بِأَفْوَاهِ السِّكَكِ فَخُدِّدَتْ فِيهَا الْأُخْدُودُ وَأُضْرِمَتْ فِيهَا النِّيرَانُ وَقَالَ مَنْ رَجَعَ عَنْ دِينِهِ فَدَعُوهُ وَإِلَّا فَأَقْحِمُوهُ فِيهَا قَالَ فَكَانُوا يَتَعَادَوْنَ فِيهَا وَيَتَدَافَعُونَ فَجَاءَتْ امْرَأَةٌ بِابْنٍ لَهَا تُرْضِعُهُ فَكَأَنَّهَا تَقَاعَسَتْ أَنْ تَقَعَ فِي النَّارِ فَقَالَ الصَّبِيُّ يَا أُمَّهْ اصْبِرِي فَإِنَّكِ عَلَى الْحَقِّ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammad bin Salamah] telah mengkhabarkan kepada kami [Tsabit] dari ['Abdur Rahman bin Abu Laila] dari [Shuhaib] bahwa Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Dulu sebelum kalian ada seorang raja, ia memiliki tukang sihir, saat tukang sihir sudah tua, ia berkata kepada rajanya: Aku sudah tua dan ajalku sudah tiba, serahkan seorang pemuda kepadaku untuk aku ajari sihir. Lalu seorang pemuda diserahkan padanya, ia mengajarkan sihir kepada pemuda itu. (Jarak) antara tukang sihir dan si raja terdapat seorang rahib. Si pemuda itu mendatangi rahib dan mendengar kata-katanya, ia kagum akan kata-kata si rahib itu sehingga bila datang ke si penyihir pasti dipukul, ia bertanya: Apa yang menahanmu? Dan bila ia mendatangi keluarganya, mereka pasti memukulinya, mereka bertanya: Apa yang menahamu? Pemuda itu mengeluhkan hal itu kepada si rahib, ia berkata: Bila tukang sihir hendak memukulmu, katakan: Keluargaku menahanku, dan bila keluargamu hendak memukulmu, katakan: Si tukang sihir menahanku. Saat seperti itu, pada suatu hari ia mendekati sebuah hewan yang besar yang menghalangi jalanan orang, ia mengambil batu lalu berkata: Ya Allah, bila urusan si rahib lebih Engkau sukai dan membuatmu senang dari pada tukang sihir itu maka bunuhlah binatang ini hingga orang bisa lewat. Ia melemparkan batu itu dan membunuhnya, orang-orang pun bisa lewat. Ia memberitahukan hal itu kepada si rahib. Si rahib berkata: Pemudaku, engkau lebih baik dariku dan engkau akan mendapat ujian, bila kau mendapat ujian jangan menunjukku. Si pemuda itu bisa menyembuhkan orang buta dan berbagai penyakit. Salah seorang teman raja buta lalu ia mendengarnya, ia mendatangi pemuda itu dengan membawa hadiah yang banyak, ia berkata: Sembuhkan aku dan kau akan mendapatkan yang aku kumpulkan disini. Pemuda itu berkata: Aku tidak menyembuhkan seorang pun, yang menyembuhkan hanyalah Allah 'azza wajalla, bila kau beriman padanya, aku akan berdoa kepadaNya agar menyembuhkanmu. Teman si raja itu pun beriman lalu si anan itu berdoa kepada Allah Subhaanahu wa Ta'ala lalu ia pun sembuh. Teman raja itu kemudian mendatangi raja lalu duduk didekatnya. Si raja berkata: Hai fulan, siapa yang menyembuhkan matamu? Orang itu menjawab: Rabbku. Si raja berkata: Aku? Orang itu berkata: Bukan, tapi Rabbku dan Rabbmu adalah Allah. Si raja berkata: Apa kau punya tuhan selainku? Ia menjawab: Ya. Si raja terus menyiksanya hingga ia menunjukkan pada pemuda itu lalu ia mengirim utusan menemuinya, ia berkata: Pemudaku, sihirmu yang bisa menyembuhkan orang buta, sopak dan penyakit-penyakit ini telah terdengar dimana-mana. Pemuda itu berkata: Bukan aku yang menyembuhkan, tidak ada yang bisa menyembuhkan selain Allah 'azza wajalla. Raja berkata: Aku? Pemuda itu berkata: Bukan. Raja berkata: Apa kau punya tuhan selainku? Pemuda itu menjawab: Ya, Rabbku dan Rabbmu adalah Allah. Si raja menyiksa pemuda itu hingga ia menunjukkan kepada si rahib. Si raja mendatangi si rahib dan berkata: Tinggalkan agamamu. Si rahib tidak mau lalu si raja meletakkan gergaji tepat ditengah kepalanya hingga sebelahnya terkapar di tanah. Si raja berkata kepada pemuda itu: Tinggalkan agamamu. Pemuda itu tidak mau. Lalu si raja mengirimnya ke gunung beserta sekian tentaranya, raja berkata: Bila kalian sudah mencapai puncaknya, bila ia mau meninggalkan agamanya (biarkanlah dia) dan bila tidak mau, lemparkan dari atas gunung. Saat mereka berada diatas gunung, pemuda itu berdoa: Ya Allah, cukupilah aku dari mereka sekehendakMu. Ternyata gunung mengguncang mereka dan mereka semua terlempar. Pemuda itu kembali pulang hingga tiba dihadapan raja. Raja berkata: Bagaimana kondisi kawan-kawanmu? Pemuda itu menjawab: Allah 'azza wajalla mencukupiku dari mereka. Si raja lalu mengirimnya ke sebuah perahu bersama sekian tentaranya, raja berkata: Bawalah ke tengah laut, bila ia mau meninggalkan agamanya (bawalah dia pulang) dan bila ia tidak mau meninggalkannya, tenggelamkan dia. Mereka membawanya ke tengah laut lalu pemuda itu berdoa: Ya Allah, cukupilah aku dari mereka sekehendakMu. Akhirnya mereka semua tenggelam. Pemuda itu pulang hingga tiba dihadapan raja, raja bertanya: Bagaiaman keadaan teman-temanmu. Pemuda itu menjawab: Allah 'azza wajalla mencukupiku dari mereka. Setelah itu ia berkata kepada raja: Kau tidak akan bisa membunuhku hingga kau mau melakukan yang aku perintahkan, bila kau mau melakukan yang aku perintahkan, kau akan membunuhku. Raja bertanya: Apa itu? Pemuda itu berkata: Kumpulkan semua orang ditanah luas lalu saliblah aku diatas pelepah, ambillah satu anak panah dari sarung panahku lalu ucapkan: Dengan nama Allah, Rabb pemuda ini. Bila kau melakukannya kau akan membunuhku. Akhirnya raja itu melakukannya. Ia meletakkan anak panah ditengah-tengah panah lalu melesakkannya seraya berkata: Dengan nama Allah, Rabb pemuda ini. Anak panah di lesakkan ke pelipis pemuda itu lalu pemuda meletakkan tangannya ditempat panah menancap kemudian mati. Orang-orang berkata: Kami beriman dengan Rabb pemuda itu. Dikatakan kepada raja: Tahukah kamu akan sesuatu yang kau khawatirkan, demi Allah kini telah menimpamu. Orang-orang beriman seluruhnya. Si raja kemudian memerintahkan membuat lubang di jalanan kemudian disulut api. Raja berkata: Siapa pun yang meninggalkan agamanya, biarkan dan bila tidak mau jerumuskan didalamnya. Mereka dengan cepat mendatanginya dan saling mendorong hingga datanglah seorang wanita bersama anaknya yang masih menyusu, sepertinya ia hendak mundur agar tidak terjatuh dalam kubangan api lalu si bayi itu berkata: Ibuku, bersabarlah, sesungguhnya engkau berada diatas kebenaran.\""},"3700":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ مَعْبَدِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أُمِّهِ وَكَانَتْ قَدْ صَلَّتْ الْقِبْلَتَيْنِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى أَنْ يُنْتَبَذَ التَّمْرُ وَالزَّبِيبُ جَمِيعًا وَقَالَ انْتَبِذْ كُلَّ وَاحِدٍ مِنْهَا وَحْدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Ma'bad bin Ka'ab bin Malik] dari [ibunya] -ia shalat menghadap dua kiblat bersama Rasulullah Shallalahu 'alaihi wa sallam- berkata: Aku pernah mendengar Rasulullah Shallalahu 'alaihi wa sallam melarang kurma dan anggur dibuat menjadi minuman secara bersamaan, beliau bersabda: \"Buatlahlah masing-masingnya menjadi minuman secara tersendiri.\""},"3701":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا رَبَاحٌ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أُمِّهِأَنَّ أُمَّ مُبَشِّرٍ دَخَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَجَعِهِ الَّذِي قُبِضَ فِيهِ فَقَالَتْ بِأَبِي وَأُمِّي يَا رَسُولَ اللَّهِ مَا تَتَّهِمُ بِنَفْسِكَ فَإِنِّي لَا أَتَّهِمُ إِلَّا الطَّعَامَ الَّذِي أَكَلَ مَعَكَ بِخَيْبَرَ وَكَانَ ابْنُهَا مَاتَ قَبْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَأَنَا لَا أَتَّهِمُ غَيْرَهُ هَذَا أَوَانُ قَطْعِ أَبْهَرِي","id":"Telah menceritakan kepada kami [Ibrahim bin Khalid] Telah menceritakan kepada kami [Rabah] Telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Abdur Rahman bin 'Abdullah bin Ka'ab bin Malik] dari [ibunya] bahwa Ummu Mubasysyir bertamu ke kediaman Rasulullah Shallalahu 'alaihi wa sallam saat beliau sakit keras yang menyebabkan beliau wafaT, ia berkata: Engkau lebih aku muliakan dari pada ayah dan ibuku wahai Rasulullah, apa yang Tuan sangkakan pada diri Tuan, aku menyangka makanan yang aku makan bersama Tuan di Khaibar -putranya meninggal sebelum Nabi Shallallahu 'Alaihi Wasalam wafat- Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Aku tidak menyangka lainnya, ini adalah saat terputusnya tulang punggungku.\""},"3702":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ ثُمَامَةَ قَالَخَرَجْنَا مَعَ فَضَالَةَ بْنِ عُبَيْدٍ إِلَى أَرْضِ الرُّومِ وَكَانَ عَامِلًا لِمُعَاوِيَةَ عَلَى الدَّرْبِ فَأُصِيبَ ابْنُ عَمٍّ لَنَا فَصَلَّى عَلَيْهِ فَضَالَةُ وَقَامَ عَلَى حُفْرَتِهِ حَتَّى وَارَاهُ فَلَمَّا سَوَّيْنَا عَلَيْهِ حُفْرَتَهُ قَالَ أَخِفُّوا عَنْهُ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُنَا بِتَسْوِيَةِ الْقُبُورِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] Telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Tsumamah] berkata: Kami pergi bersama [Fadlalah bin 'Ubaid] ke kawasan Romawi, ia adalah bawahan Mu'awiyah untuk tugas peperangan dan saudara sepupu kami terbunuh, Fadlalalah menshalatinya lalu ia berdiri diatas liang hingga ia menutupinya dengan tanah. Saat tanah kami ratakan, ia berkata: Ratakan karena Rasulullah Shallalahu 'alaihi wa sallam dulu memerintahkan kami untuk meratakan kubur.  "},"3703":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ يَزِيدَ بْنِ حَبِيبٍ عَنْ أَبِي مَرْزُوقٍ عَنْ فَضَالَةَ الْأَنْصَارِيِّ سَمِعْتُهُ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَيْهِمْ فِي يَوْمٍ كَانَ يَصُومُهُ فَدَعَا بِإِنَاءٍ فِيهِ مَاءٌ فَشَرِبَ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّ هَذَا الْيَوْمَ كُنْتَ تَصُومُهُ قَالَ أَجَلْ وَلَكِنْ قِئْتُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] Telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Yazid bin Hubaib] dari [Abu Marzuq] dari [Fadlalah bin 'Ubaid] aku mendengarnya bercerita bahwa Rasulullah Shallalahu 'alaihi wa sallam pergi mendatangi mereka saat beliau puasa lalu beliau meminta bejana berisi air kemudian minum, kami berkata: Wahai Rasulullah, bukankah Tuan puasa? Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Benar, tapi aku muntah.\""},"3704":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِئُ حَدَّثَنَا حَيْوَةُ قَالَ أَخْبَرَنِي أَبُو هَانِئٍ حُمَيْدُ بْنُ هَانِئٍ عَنْ عَمْرِو بْنِ مَالِكٍ الْجَنْبِيِّ حَدَّثَنِي أَنَّهُ سَمِعَ فَضَالَةَ بْنَ عُبَيْدٍ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُسَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَدْعُو فِي الصَّلَاةِ وَلَمْ يَذْكُرْ اللَّهَ عَزَّ وَجَلَّ وَلَمْ يُصَلِّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَجِلَ هَذَا ثُمَّ دَعَاهُ فَقَالَ لَهُ وَلِغَيْرِهِ إِذَا صَلَّى أَحَدُكُمْ فَلْيَبْدَأْ بِتَحْمِيدِ رَبِّهِ وَالثَّنَاءِ عَلَيْهِ ثُمَّ لِيُصَلِّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ لِيَدْعُ بَعْدُ بِمَا شَاءَ","id":"Telah menceritakan kepada kami [Abu 'Abdur Rahman Al Muqri`] Telah menceritakan kepada kami [Haiwah] berkata: Telah mengkhabarkan kepadaku [Abu Hani` Humaid bin Hani`] dari ['Amru bin Malik Al Janbi] telah menceritakan kepadaku, ia mendengar [Fadlalah Al Anshari, sahabat Rasulullah Shallalahu 'alaihi wa sallam] berkata: Rasulullah Shallalahu 'alaihi wa sallam mendengar seseorang berdoa sementara itu ia tidak menyebut Allah 'azza wajalla dan tidak membaca shalawat untuk Nabi Shallallahu 'Alaihi Wasalam, lalu Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Ia terburu-buru.\" Beliau lalu mendoakannya, setelah itu beliau bersabda kepadanya dan yang lain: \"Bila salah seorang dari kalian berdoa, hendaklah dimulai dengan memuja dan memuji Allah kemudian hendaklah membaca shalawat untuk Nabi Shallallahu 'Alaihi Wasalam, setelah itu silahkan berdoa sekehendaknya.\""},"3705":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِئُ حَدَّثَنَا حَيْوَةُ قَالَ أَخْبَرَنِي أَبُو هَانِئٍ عَنْ عَمْرِو بْنِ مَالِكٍ حَدَّثَهُ أَنَّهُ سَمِعَ فَضَالَةَ بْنَ عُبَيْدٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى بِالنَّاسِ خَرَّ رِجَالٌ مِنْ قَامَتِهِمْ فِي الصَّلَاةِ لِمَا بِهِمْ مِنْ الْخَصَاصَةِ وَهُمْ مِنْ أَصْحَابِ الصُّفَّةِ حَتَّى يَقُولَ الْأَعْرَابُ إِنَّ هَؤُلَاءِ مَجَانِينُ فَإِذَا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ انْصَرَفَ إِلَيْهِمْ فَقَالَ لَهُمْ لَوْ تَعْلَمُونَ مَا لَكُمْ عِنْدَ اللَّهِ عَزَّ وَجَلَّ لَأَحْبَبْتُمْ لَوْ أَنَّكُمْ تَزْدَادُونَ حَاجَةً وَفَاقَةً قَالَ فَضَالَةُ وَأَنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Abu 'Abdur Rahman Al Muqri'] Telah menceritakan kepada kami [Haiwah] berkata: Telah mengkhabarkan kepadaku [Abu Hani`] dari ['Amru bin Malik] telah menceritakan kepadanya bahwa ia mendengar [Fadlalah bin 'Ubaid] berkata: saat Rasulullah Shallalahu 'alaihi wa sallam mengimami shalat, beberapa orang jatuh saat berdiri karena mereka kesusahan dan mereka adalah para penghuni emperan masjid hingga orang-orang badui berkata: Mereka adalah orang-orang gila. Saat Rasulullah Shallalahu 'alaihi wa sallam usai shalat, beliau menoleh ke arah mereka lalu bersabda kepada mereka: \"Andai kalian tahu bagianmu di sisi Allah 'azza wajalla pastilah kalian menyukai bila seandainya kalian lebih miskin dan melarat.\" Berkata Fadlalah bin 'Ubaid: Saat itu aku bersama Rasulullah Shallalahu 'alaihi wa sallam."},"3706":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ حَدَّثَنَا حَيْوَةُ وَابْنُ لَهِيعَةَ قَالَا أَنْبَأَنَا أَبُو هَانِئٍ عَنْ عَلِيِّ بْنِ رَبَاحٍ عَنْ فَضَالَةَ بْنِ عُبَيْدٍ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقِلَادَةٍ فِيهَا ذَهَبٌ وَخَرَزٌ تُبَاعُ وَهِيَ مِنْ الْغَنَائِمِ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالذَّهَبِ الَّذِي فِي الْقِلَادَةِ فَنُزِعَ وَحْدَهُ ثُمَّ قَالَ الذَّهَبُ بِالذَّهَبِ وَزْنًا بِوَزْنٍ","id":"Telah menceritakan kepada kami [Abu 'Abdur Rahman] Telah menceritakan kepada kami [Haiwah] dan [Ibnu Lahi'ah] keduanya berkata: Telah memberitakan kepada kami [Abu Hani`] dari ['Ali bin Rabah] dari [Fadlalah bin 'Ubaid] berkata: Kalung yang ada emas dan merjannya dijual dan dibawa kehadapan Rasulullah Shallalahu 'alaihi wa sallam, kalung itu berasal dari harta rampasan perang kemudian Rasulullah Shallalahu 'alaihi wa sallam memerintahkan memerintahkan mencabut emas yang ada dikalung itu, beliau mencabutnya sendiri kemudian bersabda: \"Emas dengan emas, ukuran berat yang sama.\""},"3707":{"ar":"حَدَّثَنَا إِبْرَهِيمُ بْنُ إِسْحَاقَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ قَالَ أَخْبَرَنِي أَبُو هَانِئٍ الْخَوْلَانِيُّ أَنَّ عَمْرَو بْنَ مَالِكٍ الْجَنْبِيَّ أَخْبَرَهُ أَنَّهُ سَمِعَ فَضَالَةَ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَاتَ عَلَى مَرْتَبَةٍ مِنْ هَذِهِ الْمَرَاتِبِ بُعِثَ عَلَيْهَاقَالَ حَيْوَةُ يَقُولُ رِبَاطٌ حَجٌّ أَوْ نَحْوُ ذَلِكَ","id":"Telah menceritakan kepada kami [Ibrahim bin Ishaq] Telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Haiwah bin Syuraih] berkata: Telah mengkhabarkan kepadaku [Abu Hani` Al Khaulani] bahwa ['Amru bin Malik Al Janbi] memberitahunya, ia mendengar [Fadlalah bin 'Ubaid] bercerita dari Rasulullah Shallalahu 'alaihi wa sallam, beliau beresabda: \"Barangsiapa meninggal dunia diatas salah satu tugas ini maka ia akan dibangkitkan diatasnya.\" Berkata [Haiwah]: Beliau bersabda: \"Menjaga perbatasan, \" \"Haji\" atau sejenisnya."},"3708":{"ar":"و حَدَّثَنَاه الطَّالَقَانِيُّ فِي هَذَا الْإِسْنَادِ عَنِ ابْنِ الْمُبَارَكِ قَالَيُسَلِّمُ الْفَارِسُ عَلَى الْمَاشِي وَالْمَاشِي عَلَى الْقَائِمِ وَالْقَلِيلُ عَلَى الْكَثِيرِحَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ حَدَّثَنَا حَيْوَةُ قَالَ أَخْبَرَنِي أَبُو هَانِئٍ أَنَّ أَبَا عَلِيٍّ عَمْرَو بْنَ مَالِكٍ الْجَنْبِيَّ مِثْلَهُ","id":"(Masih dari [Fadhalah bin 'Ubaid]). Dan telah menceritakan kepada kami [Ath Thalaqani] dalam sanad ini dari [Ibnu Al Mubarak] berkata: Orang yang berkuda mengucap salam kepada orang yang berjalan, orang yang berjalan mengucap salam kepada orang yang berdiri, orang yang sedikit mengucap salam kepada orang yang banyak. Telah menceritakan kepada kami [Abu 'Abdur Rahman] Telah menceritakan kepada kami [Haiwah] berkata: Telah mengkhabarkan kepadaku [Abu Hani'] bahwa [Abu 'Ali 'Amru bin Malik Al Jambi] menceritakan seperti hadits di atas."},"3709":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ حَدَّثَنَا حَيْوَةُ قَالَ أَخْبَرَنِي أَبُو هَانِئٍ أَنَّ أَبَا عَلِيٍّ أَخْبَرَهُ أَنَّهُ سَمِعَ فَضَالَةَ بْنَ عُبَيْدٍ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ طُوبَى لِمَنْ هُدِيَ إِلَى الْإِسْلَامِ وَكَانَ عَيْشُهُ كَفَافًا وَقَنَعَ","id":"Telah menceritakan kepada kami [Abu 'Abdur Rahman] Telah menceritakan kepada kami [Haiwah] berkata: Telah mengkhabarkan kepadaku [Abu Hani`] bahwa [Abu 'Ali] memberitahunya, ia mendengar [Fadlalah bin 'Ubaid] mendengar Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Beruntunglah orang yang ditunjukkan menuju Islam dan hidupnya serba cukup namun ia menerima.\""},"3710":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ حَدَّثَنَا حَيْوَةُ وَابْنُ لَهِيعَةَ قَالَا أَنْبَأَنَا أَبُو هَانِئٍ أَنَّ أَبَا عَلِيٍّ الْجَنْبِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ فَضَالَةَ بْنَ عُبَيْدٍ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ مَاتَ عَلَى مَرْتَبَةٍ مِنْ هَذِهِ الْمَرَاتِبِ بُعِثَ عَلَيْهَا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu 'Abdur Rahman] Telah menceritakan kepada kami [Haiwah] dan [Ibnu Lahi'ah] keduanya berkata: Telah memberitakan kepada kami [Abu Hani`] bahwa [Abu 'Ali Al Janbi] bercerita kepadanya, ia mendengar [Fadlalah bin 'Ubaid] bercerita dari Rasulullah Shallalahu 'alaihi wa sallam, beliau bersabda: \"Barangsiapa meninggal dunia diatas salah satu tugas ini maka ia akan dibangkitkan diatasnya pada hari kiamat.\""},"3711":{"ar":"حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ الْمُقَدَّمِيُّ قَالَ سَمِعْتُ حَجَّاجًا يَذْكُرُ عَنْ مَكْحُولٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُحَيْرِيزٍ قَالَقُلْتُ لِفَضَالَةَ بْنِ عُبَيْدٍ أَرَأَيْتَ تَعْلِيقَ يَدِ السَّارِقِ فِي الْعُنُقِ أَمِنَ السُّنَّةِ قَالَ نَعَمْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِسَارِقٍ فَأَمَرَ بِهِ فَقُطِعَتْ يَدُهُ ثُمَّ أَمَرَ بِهَا فَعُلِّقَتْ فِي عُنُقِهِقَالَ حَجَّاجٌ وَكَانَ فَضَالَةُ مِمَّنْ بَايَعَ تَحْتَ الشَّجَرَةِ قَالَ أَبُو عَبْد الرَّحْمَنِ عَبْد اللَّهِ بْن أَحْمَد قُلْتُ لِيَحْيَى بْنِ مَعِينٍ سَمِعْتَ مِنْ عُمَرَ بْنِ عَلِيٍّ الْمُقَدَّمِيِّ شَيْئًا قَالَ أَيُّ شَيْءٍ كَانَ عِنْدَهُ قُلْتُ حَدِيثُ فَضَالَةَ بْنِ عُبَيْدٍ فِي تَعْلِيقِ الْيَدِ فَقَالَ لَا حَدَّثَنَا بِهِ عَفَّانُ عَنْهُ","id":"Telah menceritakan kepada kami ['Umar bin 'Ali Al Muqaddami] berkata: Aku mendengar [Hajjaj] bercerita dari [Makhlul] dari ['Abdur Rahman bin Muhairiz] berkata: Aku berkata kepada [Fadlalah bin 'Ubaid]: Bagaimana menurutmu, apakah mengalungkan tangan dileher seorang pencuri itu termasuk sunnah? Ia menjawab: Ya, dulu aku pernah melihat seorang pencuri dibawa ke hadapan Rasulullah Shallalahu 'alaihi wa sallam lalu Rasulullah Shallalahu 'alaihi wa sallam memerintahkan agar tangannya diputus, setelah itu beliau memerintahkan agar tangannya dikalungkan di lehernya. Berkata Hajjaj: Fadlalah bin 'Ubaid termasuk salah seorang yang berbaiat Ridlwan dibawah pohon. Berkata Abu 'Abdur Rahman 'Abdullah bin Ahmad: Aku berkata kepada Yahya bin Ma'in: Aku mendengar sesuatu dari 'Umar bin 'Ali Al Muqaddami: Apa yang ia miliki? Aku Berkata: Hadits Fadlalah bin 'Ubaid Al Anshari tentang mengalungkan tangan. Ia: Tidak, 'Affan telah menceritakan kepada kami darinya Fadlalah bin 'Ubaid."},"3712":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنْ هِشَامِ بْنِ يُوسُفَ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَاسْتَأْذَنْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَدْخُلُ كُلِّي أَوْ بَعْضِي قَالَ ادْخُلْ كُلُّكَ فَدَخَلْتُ عَلَيْهِ وَهُوَ يَتَوَضَّأُ وُضُوءًا مَكِيثًا فَقَالَ لِي يَا عَوْفُ بْنَ مَالِكٍ أَعْدِدْ سِتًّا قَبْلَ السَّاعَةِ مَوْتُ نَبِيِّكُمْ خُذْ إِحْدَى ثُمَّ فَتْحُ بَيْتِ الْمَقْدِسِ ثُمَّ مَوْتٌ يَأْخُذُكُمْ تُقْعَصُونَ فِيهِ كَمَا تُقْعَصُ الْغَنَمُ ثُمَّ تَظْهَرُ الْفِتَنُ وَيَكْثُرُ الْمَالُ حَتَّى يُعْطَى الرَّجُلُ الْوَاحِدُ مِائَةَ دِينَارٍ فَيَسْخَطَهَا ثُمَّ يَأْتِيكُمْ بَنُو الْأَصْفَرِ تَحْتَ ثَمَانِينَ غَايَةً تَحْتَ كُلِّ غَايَةٍ اثْنَا عَشَرَ أَلْفًا","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata: Telah memberitakan kepada kami [Sufyan bin Husain] dari [Hisyam bin Yusuf] dari ['Auf bin Malik] berkata: Aku meminta izin kepada Nabi Shallallahu 'Alaihi Wasalam, aku berkata: Aku masuk sebagaian saja atau seluruhnya. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Masuklah secara keseluruhan.\" Aku masuk saat beliau tengah berwudlu pelan-pelan lalu bersabda kepadaku: \"Hai 'Auf bin Malik, hitunglah enam hal sebelum (terjadinya) kiamat; wafatnya nabi kalian, ambillah salah satunya, penaklukkan Baitul Maqdis, kematian yang menggeleparkan kalian layaknya kambing tergelepar, munculnya fitnah, banyaknya harta hingga seseorang memberi seratus dinar lalu dimarahi kemudian Bani Ashfar mendatangi kalian dibawah delapan puluh bendera, setiap benderanya ada duabelas ribu bendera.\""},"3713":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ قَالَ حَدَّثَنَا الضَّحَّاكُ بْنُ عُثْمَانَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ قَالَدَخَلَ عَوْفُ بْنُ مَالِكٍ هُوَ وَذُو الْكَلَاعِ مَسْجِدَ بَيْتِ الْمَقْدِسِ فَقَالَ لَهُ عَوْفٌ عِنْدَكَ ابْنُ عَمِّكَ فَقَالَ ذُو الْكَلَاعِ أَمَا إِنَّهُ مِنْ خَيْرِ أَوْ مِنْ أَصْلَحِ النَّاسِ فَقَالَ عَوْفٌ أَشْهَدُ لَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَقُصُّ إِلَّا أَمِيرٌ أَوْ مَأْمُورٌ أَوْ مُتَكَلِّفٌ","id":"Telah menceritakan kepada kami [Abu Bakar Al Hanafi] berkata: Telah menceritakan kepada kami [Adl Dlahhak bin 'Utsman] dari [Bukair bin 'Abdullah bin Al Asyujj] berkata: Auf bin Malik dan Dzu Al Kala' memasuki Baitul Maqdis, 'Auf berkata padanya: Kau punya saudara sepupu. Berkata Dzul Kala': Ia adalah orang paling shalih. Berkata ['Auf]: Aku bersaksi, aku pernah mendengar Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Tidak ada yang membalas kecuali pemimpin, orang yang ditunjuk pemimpin atau orang yang memaksa-maksakan diri.\""},"3714":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ أَنْبَأَنَا النَّهَّاسُ عَنْ شَدَّادٍ أَبِي عَمَّارٍ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَيَا طَاعُونُ خُذْنِي إِلَيْكَ قَالُوا لِمَ تَقُولُ هَذَا أَلَيْسَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْمُؤْمِنَ لَا يَزِيدُهُ طُولُ الْعُمُرِ إِلَّا خَيْرًا قَالَ بَلَى فَذَكَرَ مِثْلَ حَدِيثِ وَكِيعٍ","id":"Telah menceritakan kepada kami [Muhammad bin Bakar] berkata; Telah memberitakan kepada kami [An Nahhas] dari [Syaddad Abu 'Ammar] dari ['Auf bin Malik Al Asyaja'i] berkata: Wahai tha'un, seranglah aku. Mereka berkata: Kenapa kau berkata seperti itu, bukankah kau mendengar Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Sesungguhnya panjangnya usia orang mu`min itu tidaklah menambah selain kebaikan.\" Ia berkata: Benar, lalu ia menyebutkan seperti hadits Waki'."},"3715":{"ar":"حَدَّثَنَا يَحْيَي بْنُ سَعِيدٍ عَنْ عَبْدِ الْحَمِيدِ يَعْنِي أَبَا جَعْفَرٍ قَالَ حَدَّثَنِي صَالِحُ بْنُ أَبِي عَرِيبٍ عَنْ كَثِيرِ بْنِ مُرَّةَ الْحَضْرَمِيِّ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ دَخَلَ وَنَحْنُ فِي الْمَسْجِدِ وَبِيَدِهِ عَصًا وَقَدْ عَلَّقَ رَجُلٌ أَقْنَاءَ حَشَفٍ فَطَسَّ بِالْعَصَا فِي ذَلِكَ الْقِنْوِ ثُمَّ قَالَ لَوْ شَاءَ رَبُّ هَذِهِ الصَّدَقَةِ تَصَدَّقَ بِأَطْيَبَ مِنْ هَذَا إِنَّ رَبَّ هَذِهِ الصَّدَقَةِ يَأْكُلُ الْحَشَفَ يَوْمَ الْقِيَامَةِ","id":"Telah bercerita kepada kami [Yahya bin Sa'id] dari ['Abdul Hamid Abu Ja'far] berkata: telah bercerita kepadaku [Shalih bin Abu 'Arib] dari [Katsir bin Murrah Al Hadlrami] dari ['Auf bin Malik Al Asyja'i] berkata: Rasulullah Shallalahu 'alaihi wa sallam keluar menghampiri kami atau masuk (menghampiri kami) dan kami tengah berada di masjid, di tangan beliau ada tongkat, seseorang menggantungkan tandan kurma yang sudah rusak, beliau menusukkan tongat beliau pada tandan kuram itu lalu bersabda: \"Andai pemilik sedekah ini berkehendak pastilah ia bersedekah dengan yang lebih baik darinya, sesungguhnya pemilik sedekah ini sungguh akan makan kurma rusak pada hari kiamat.\""},"3716":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَيِّتٍ قَالَ فَفَهِمْتُ مِنْ صَلَاتِهِ عَلَيْهِ اللَّهُمَّ اغْفِرْ لَهُ وَارْحَمْهُ وَاغْسِلْهُ بِالْمَاءِ وَالثَّلْجِ وَنَقِّهِ مِنْ الْخَطَايَا كَمَا نَقَّيْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ","id":"Telah bercerita kepada kami ['Abdur Rahman bin Mahdi] dari [Mu'awiyah] dari ['Abdur Rahman bin Jubair] dari [ayahnya] dari ['Auf bin Malik] berkata: Rasulullah Shallalahu 'alaihi wa sallam menshalati mayit. Berkata 'Auf: Aku tahu doa beliau untuk mayit itu: ALLAHUMMAGHFIR LAHU WARHAMHU WAGHSILHU BIL MAA`I WATSTSALJI MINAL KHATHAAYAA KAMA NAQQAITATS TSAUBAL ABYADLA MINAD DANASI (Ya Allah, ampunilah dia, rahamatilah dia, mandikanlah dia dengan air, salju dan es, bersihkanlah ia dari kesalahan-kesalahan seperti Engkau membersihkan baju putih dari kotoran)."},"3717":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ أَزْهَرَ بْنِ سَعِيدٍ عَنْ ذِي كَلَاعٍ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقُصَّاصُ ثَلَاثَةٌ أَمِيرٌ أَوْ مَأْمُورٌ أَوْ مُخْتَالٌ","id":"Telah bercerita kepada kami ['Abdur Rahman] dari [Mu'awiyah bin Shalih] dari [Azhar bin Sa'id] dari [Dzi Kala'] dari ['Auf bin Malik] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Pencerita itu ada tiga; pemimpin, yang ditunjuk oleh pemimpin atau orang sombong.\""},"3718":{"ar":"حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي مَلِيحٍ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَعَرَّسَ بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَافْتَرَشَ كُلُّ رَجُلٍ مِنَّا ذِرَاعَ رَاحِلَتِهِ قَالَ فَانْتَهَيْتُ إِلَى بَعْضِ الْإِبِلِ فَإِذَا نَاقَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ قُدَّامَهَا أَحَدٌ قَالَ فَانْطَلَقْتُ أَطْلُبُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا مُعَاذُ بْنُ جَبَلٍ وَعَبْدُ اللَّهِ بْنُ قَيْسٍ قَائِمَانِ قُلْتُ أَيْنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَا مَا نَدْرِي غَيْرَ أَنَّا سَمِعْنَا صَوْتًا بِأَعْلَى الْوَادِي فَإِذَا مِثْلُ هَزِيزِ الرَّحْلِ قَالَ امْكُثُوا يَسِيرًا ثُمَّ جَاءَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ أَتَانِي اللَّيْلَةَ آتٍ مِنْ رَبِّي فَخَيَّرَنِي بَيْنَ أَنْ يَدْخُلَ نِصْفُ أُمَّتِي الْجَنَّةَ وَبَيْنَ الشَّفَاعَةِ فَاخْتَرْتُ الشَّفَاعَةَ فَقُلْنَا نَنْشُدُكَ اللَّهَ وَالصُّحْبَةَ لَمَا جَعَلْتَنَا مِنْ أَهْلِ شَفَاعَتِكَ قَالَ فَإِنَّكُمْ مِنْ أَهْلِ شَفَاعَتِي قَالَ فَأَقْبَلْنَا مَعَانِيقَ إِلَى النَّاسِ فَإِذَا هُمْ قَدْ فَزِعُوا وَفَقَدُوا نَبِيَّهُمْ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ أَتَانِي اللَّيْلَةَ مِنْ رَبِّي آتٍ فَخَيَّرَنِي بَيْنَ أَنْ يَدْخُلَ نِصْفُ أُمَّتِي الْجَنَّةَ وَبَيْنَ الشَّفَاعَةِ وَإِنِّي اخْتَرْتُ الشَّفَاعَةَ قَالُوا يَا رَسُولَ اللَّهِ نَنْشُدُكَ اللَّهَ وَالصُّحْبَةَ لَمَا جَعَلْتَنَا مِنْ أَهْلِ شَفَاعَتِكَ قَالَ فَلَمَّا أَضَبُّوا عَلَيْهِ قَالَ فَأَنَا أُشْهِدُكُمْ أَنَّ شَفَاعَتِي لِمَنْ لَا يُشْرِكُ بِاللَّهِ شَيْئًا مِنْ أُمَّتِيحَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ الْهُذَلِيِّ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ فَأَنَاخَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَخْنَا مَعَهُ فَذَكَرَ مَعْنَاهُ إِلَّا أَنَّهُ قَالَ وَبَيْنَ أَنْ يَدْخُلَ نِصْفُ أُمَّتِي الْجَنَّةَ","id":"Telah bercerita kepada kami [Bahz] berkata: telah bercerita kepada kami [Abu 'Awanah] berkata: telah bercerita kepada kami [Qatadah] dari [Abu Malih] dari ['Auf bin Malik Al Asyja'i] berkata: Pada suatu malam Rasulullah Shallalahu 'alaihi wa sallam bersama kami lalu setiap orang diantara kami berbantalkan lengan kendaraan tunggangannya. Berkata 'Auf: Aku mendatangi sebagaian unta dan ternyata unta Rasulullah Shallalahu 'alaihi wa sallam tidak dijaga oleh seorang pun. Aku pergi mencari Rasulullah Shallalahu 'alaihi wa sallam, ternyata disana ada Mu'adz bin Jabal dan 'Abdullah bin Qais tengah berdiri, aku bertanya: Di mana Rasulullah Shallalahu 'alaihi wa sallam? Keduanya menjawab: Kami tidak tahu, tapi kami mendengar suara di puncak bukit seperti getaran alat penumbuk, aku berkata: TInggallah sebentar. Kemudian Rasulullah Shallalahu 'alaihi wa sallam mendatangi kami, beliau bersabda: \"Sesungguhnya ada yang mendatangiku dari Rabbku 'azza wajalla lalu memberiku pilihan antara separuh ummatku masuk surga atau syafaat lalu aku memilih syafaat.\" Kami berkata: Kami mengingatkan Tuan pada Allah dan persahabatan kecuali Tuan menjadikan kami termasuk yang mendapatkan syafaat Tuan. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Kalian termasuk bagian dari mereka.\" Kami pergi lalu seseorang, dua orang tiba, beliau memberitahu kepada mereka khabar yang beliau sampaikan pada kami, mereka mengingatkan beliau pada Allah dan persahabatan kecuali beliau menjadikan mereka termasuk yang mendapatkan syafaat beliau, beliau bersabda: \"Kalian termasuk bagian dari mereka.\" Orang-orang pun mendengar hal itu, mereka mendatangi beliau, mereka berkata: Jadikanlah kami termasuk bagian dari mereka. Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Aku bersaksi pada kalian, sesungguhnya syafaat itu untuk orang yang meninggal dunia dari ummatku yang tidak menyekutukan Allah dengan apa pun.\" Telah bercerita kepada kami Muhammad bin Bakar berkata telah bercerita kepada kami Sa'id dari Qadatah dari Abu Al Malih Al Hudzali dari 'Auf bin Malik Al Asyja'i berkata: Kami bersama Rasulullah Shallalahu 'alaihi wa sallam dalam salah satu perjalanan beliau lalu nabi Allah menderumkan unta, kami turut menderumkan unta bersama beiau. 'Auf menyebutkan makna hadits, hanya saja ia berkata dalam riwayatnya: \"Dan antara separuh ummatku masuk surga.\""},"3719":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ قَالَ أَنْبَأَنَا عَبْدُ الْحَمِيدِ قَالَ حَدَّثَنَا صَالِحُ بْنُ أَبِي عَرِيبٍ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَدَخَلَ عَوْفُ بْنُ مَالِكٍ مَسْجِدَ حِمْصَ قَالَ وَإِذَا النَّاسُ عَلَى رَجُلٍ فَقَالَ مَا هَذِهِ الْجَمَاعَةُ قَالُوا كَعْبٌ يَقُصُّ قَالَ يَا وَيْحَهُ أَلَا سَمِعَ قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقُصُّ إِلَّا أَمِيرٌ أَوْ مَأْمُورٌ أَوْ مُخْتَالٌ","id":"Telah bercerita kepada kami [Abu 'Ashim] berkata: telah memberitakan kepada kami ['Abdul Hamid] berkata: telah bercerita kepada kami [Shalih bin Abu 'Arib] dari [Katsir bin Murrah] dari ['Auf bin Malik] berkata: 'Auf bin Malik masuk masjid Himash, ternyata orang-orang tengah berkumpul dihadapan seseorang, 'Auf bertanya: Perkumpulan apa ini? mereka menajwab: Ka'ab sedang bercerita. Berkata 'Auf: Alangkah celakanya ia, apa ia tidak mendengar sabda Rasulullah Shallalahu 'alaihi wa sallam: \"Tidak ada yang berhak bercerita kecuali pemimpin, yang ditunjuk oleh pemimpin atau orang yang sombong.\""},"3720":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ أَنْبَأَنَا النَّهَّاسُ عَنْ شَدَّادٍ أَبِي عَمَّارٍ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَامْرَأَةٌ سَفْعَاءُ الْخَدَّيْنِ كَهَاتَيْنِ يَوْمَ الْقِيَامَةِ وَجَمَعَ بَيْنَ أُصْبُعَيْهِ السَّبَّابَةِ وَالْوُسْطَى امْرَأَةٌ ذَاتُ مَنْصِبٍ وَجَمَالٍ آمَتْ مِنْ زَوْجِهَا حَبَسَتْ نَفْسَهَا عَلَى أَيْتَامِهَا حَتَّى بَانُوا أَوْ مَاتُوا","id":"Telah bercerita kepada kami [Muhammad bin Bakar] berkata: Telah memberitakan kepada kami [An Nahhas] dari [Syaddad Abu 'Ammar] dari ['Auf bin Malik] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Aku dan wanita dengan pipi berwarna soga seperti dua ini pada hari kiamat -beliau menyatukan diantara dua jari; jari telunjuk dan jari tengah- wanita yang memiliki kedudukan dan kecantikan yang ditinggal mati suaminya, ia menahan dirinya demi anak-anak yatimnya hingga mereka menikah atau meninggal dunia.\""},"3721":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ النَّهَّاسِ عَنْ شَدَّادٍ أَبِي عَمَّارٍ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَامْرَأَةٌ سَفْعَاءُ فِي الْجَنَّةِ كَهَاتَيْنِ امْرَأَةٌ آمَتْ مِنْ زَوْجِهَا فَحَبَسَتْ نَفْسَهَا عَلَى يَتَامَاهَا حَتَّى بَانُوا أَوْ مَاتُواحَدَّثَنَا حُسَيْنٌ فِي تَفْسِيرِ شَيْبَانَ عَنْ قَتَادَةَ قَالَ حَدَّثَنَا صَاحِبٌ لَنَا أَظُنُّهُ أَبَا الْمَلِيحِ الْهُذَلِيَّ عَنْ عَوْفِ بْنِ مَالِكٍ فَذَكَرَهُ وَقَالَ بَيْنَ أَنْ يَدْخُلَ نِصْفُ أُمَّتِي الْجَنَّةَ آخِرُ مُسْنَدِ عَوْفِ بْنِ مَالِكٍ الْأَنْصَارِيِّ وَهُوَ تَمَامُ مُسْنَدِ الْأَنْصَارِ رَضِيَ اللَّهُ عَنْهُمْ","id":"Telah bercerita kepada kami [Waki'] dari [An Nahhas] dari [Syaddad Abu 'Ammar] dari ['Auf bin Malik] berkata: Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Aku dan wanita dengan pipi berwarna soga seperti dua ini pada hari kiamat -eliau menyatukan diantara dua jari; jari telunjuk dan jari tengah- wanita yang memiliki kedudukan dan kecantikan yang ditinggal mati suaminya, ia menahan dirinya demi anak-anak yatimnya hingga mereka menikah atau meninggal dunia.\" Telah bercerita kepada kami Husain tentang penafsiran Syaiban dari Qatadah berkata: telah bercerita kepada kami seorang sahabat kami, menurutku Abu Al Malih Al Hudzali dari 'Auf bin Malik lalu ia menyebutnya dan ia berkata dalam riwayatnya: \"Antara separuh ummatku masuk surga.\" Akhir musnad 'Auf bin Malik Al Anshari dan inilah musnad terakhir kaum Anshar."},"3722":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ أَخْبَرَنَا بُرْدُ بْنُ سِنَانٍ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ غُضَيْفِ بْنِ الْحَارِثِ قَالَقُلْتُ لِعَائِشَةَ أَرَأَيْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْتَسِلُ مِنْ الْجَنَابَةِ فِي أَوَّلِ اللَّيْلِ أَوْ فِي آخِرِهِ قَالَتْ رُبَّمَا اغْتَسَلَ فِي أَوَّلِ اللَّيْلِ وَرُبَّمَا اغْتَسَلَ فِي آخِرِهِ قُلْتُ اللَّهُ أَكْبَرُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي الْأَمْرِ سَعَةً قُلْتُ أَرَأَيْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ فِي أَوَّلِ اللَّيْلِ أَوْ فِي آخِرِهِ قَالَتْ رُبَّمَا أَوْتَرَ فِي أَوَّلِ اللَّيْلِ وَرُبَّمَا أَوْتَرَ فِي آخِرِهِ قُلْتُ اللَّهُ أَكْبَرُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي الْأَمْرِ سَعَةً قُلْتُ أَرَأَيْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْهَرُ بِالْقُرْآنِ أَوْ يُخَافِتُ بِهِ قَالَتْ رُبَّمَا جَهَرَ بِهِ وَرُبَّمَا خَافَتَ قُلْتُ اللَّهُ أَكْبَرُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي الْأَمْرِ سَعَةً","id":"Telah menceritakan kepada kami [Isam'il], dia berkata; Telah mengkabarkan kepada kita [Burdu bin Sinan] dari [Ubadah bin Nusai] dari [Ghudlaif bin Al-Harits] berkata; Saya bertanya kepada [Aisyah]; \"Apakah kamu melihat Rasulullah Shallallahu'alaihiwasallam mandi junub di awal malam atau di akhir malam?\" Aisyah berkata; \"Terkadang beliau mandi di awal malam dan terkadang pula beliau mandi di akhir malam.\" Saya berkata; \"Allahu akbar, segala puji bagi Allah yang telah memberikan keleluasan pada suatu perkara.\" Saya berkata; \"Apakah kamu melihat Rasulullah Shallallahu'alaihiwasallam berwitir di awal malam atau di akhir malam?\" Aisyah berkata; \"Terkadang beliau berwitir di awal malam dan terkadang pula beliau berwitir di akhir malam.\" Saya berkata; \"Allahu akbar, segala puji bagi Allah yang telah memberikan keleluasan pada suatu perkara.\" Saya berkata; \"Apakah kamu melihat Rasulullah Shallallahu'alaihiwasallam mengeraskan bacaan Al Quran atau melirihkannya?.\" Aisyah berkata; \"Terkadang beliau mengeraskannya dan terkadang pula beliau melirihkannya.\" Saya berkata; \"Allahu akbar, segala puji bagi Allah yang telah memberikan keleluasan pada suatu perkara.\""},"3723":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَكْمَلِ الْمُؤْمِنِينَ إِيمَانًا أَحْسَنَهُمْ خُلُقًا وَأَلْطَفَهُمْ بِأَهْلِهِ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Khalid Al-Khudda`] dari [Abi Qilabah] dari [Aisyah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang mukmin yang paling sempurna keimanannya adalah orang yang paling baik akhlaknya dan yang paling lemah lembut dengan istrinya.\""},"3724":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي سُلَيْمَانُ بْنُ مُوسَى عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نُكِحَتْ الْمَرْأَةُ بِغَيْرِ أَمْرِ مَوْلَاهَا فَنِكَاحُهَا بَاطِلٌ فَنِكَاحُهَا بَاطِلٌ فَنِكَاحُهَا بَاطِلٌ فَإِنْ أَصَابَهَا فَلَهَا مَهْرُهَا بِمَا أَصَابَ مِنْهَا فَإِنْ اشْتَجَرُوا فَالسُّلْطَانُ وَلِيُّ مَنْ لَا وَلِيَّ لَهُقَالَ ابْنُ جُرَيْجٍ فَلَقِيتُ الزُّهْرِيَّ فَسَأَلْتُهُ عَنْ هَذَا الْحَدِيثِ فَلَمْ يَعْرِفْهُ قَالَ وَكَانَ سُلَيْمَانُ بْنُ مُوسَى وَكَانَ فَأَثْنَى عَلَيْهِ السُّلْطَانُ الْقَاضِي لِأَنَّ إِلَيْهِ أَمْرَ الْفُرُوجِ وَالْأَحْكَامِ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Ibnu Juraij], dia berkata; \"Telah mengkabarkan kepadaku [Sulaiman bin Musa] dari [Az-Zuhri] dari [Urwah] dari [Aisyah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bila seorang wanita dinikahkan bukan atas perintah walinya maka nikahnya batil, maka nikahnya batil, maka nikahnya batil. Dan, bila (suaminya) Telah menggaulinya maka mahar menjadi haknya. Sedang bila mereka berbantah-bantahan maka penguasa menjadi wali bagi siapa yang tidak mempunyai wali.\" Ibnu Juraij berkata; 'Saya telah menemui Az-Zuhri dan bertanya kepadanya mengenai hadits ini dan beliau tidak mengetahuinya. Dia (Az-Zuhri) Berkata; 'Sulaiman bin Musa telah mendapat sanjungan dari penguasa Al-Qadhi karena dia ahli dalam masalah hukum.'\""},"3725":{"ar":"قَالَ أَخْبَرَنَا إِسْمَاعِيلُ قَالَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَعَدَ بَيْنَ الشُّعَبِ الْأَرْبَعِ ثُمَّ أَلْزَقَ الْخِتَانَ بِالْخِتَانِ فَقَدْ وَجَبَ الْغُسْلُ","id":"Imam Ahmad bin Hambal berkata; \"Telah mengkabarkan kepada kami [Isma'il], dia berkata; Telah mengkabarkan kepada kami [Ali bin Zaid] dari [Sa'id bin Al-Musayyab] dari [Aisyah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apabila (seorang suami) Telah duduk di antara empat sendi (mensetubuhi istrinya) kemudian memasukkan kemaluannya ke dalam kemaluan istrinya maka dia telah wajib mandi.\""},"3726":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمِ بْنِ صُبَيْحٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْخَيَّرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاخْتَرْنَاهُ وَلَمْ يَعْدُدْهَا عَلَيْنَا شَيْئًا","id":"Telah menceritakan kepada kami [Abu Muawiyah] Telah menceritakan kepada kami [Al-A'masy] dari [Muslim bin Shubaih] dari [Masruq] dari [Aisyah] berkata; \"Rasulullah Shallallahu'alaihiwasallam pernah memberi pilihan kepada kami lalu kami memilih beliau dan beliau sama sekali tidak memperhitungkan tawaran pilihan itu sebagai thalak.\""},"3727":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّ��َنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ ضِجَاعُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي يَنَامُ عَلَيْهِ بِاللَّيْلِ مِنْ أَدَمٍ مَحْشُوًّا لِيفًا","id":"Telah menceritakan kepada kami [Abu Muawiyah] Telah menceritakan kepada kami [Hisyam bin Urwah] dari [ayahnya] dari [Aisyah] berkata; \"Suatu malam Nabi Shallallahu'alaihiwasallam pernah tidur di atas tulang rusuknya (beralaskan) kulit yang bulunya telah dibakar.\""},"3728":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ أَخْبَرَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي يَقْرَأُ الْقُرْآنَ وَهُوَ مَاهِرٌ بِهِ مَعَ السَّفَرَةِ الْكِرَامِ الْبَرَرَةِ وَالَّذِي يَقْرَؤُهُ وَهُوَ عَلَيْهِ شَاقٌّ فَلَهُ أَجْرَانِ","id":"Telah menceritakan kepada kami [Isma'il], dia berkata; Telah mengkabarkan kepada kami [Hisyam] dari [Qotadah] dari [Zurarah bin Aufa] dari [sa'ad bin Hisyam] dari [Aisyah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang yang membaca Al Quran sedang ia pandai dalam membacanya maka dia bersama para malaikat utusan yang mulia, sedangkan orang yang membacanya dengan sulit maka ia mendapat dua pahala.\""},"3729":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ عَنْ أَبِي عَطِيَّةَ قَالَدَخَلْتُ أَنَا وَمَسْرُوقٌ عَلَى عَائِشَةَ فَقُلْنَا لَهَا يَا أُمَّ الْمُؤْمِنِينَ رَجُلَانِ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدُهُمَا يُعَجِّلُ الْإِفْطَارَ وَيُعَجِّلُ الصَّلَاةَ وَالْآخَرُ يُؤَخِّرُ الْإِفْطَارَ وَيُؤَخِّرُ الصَّلَاةَ قَالَ فَقَالَتْ أَيُّهُمَا يُعَجِّلُ الْإِفْطَارَ وَيُعَجِّلُ الصَّلَاةَ قَالَ قُلْنَا عَبْدُ اللَّهِ بْنُ مَسْعُودٍ قَالَتْ كَذَاكَ كَانَ يَصْنَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْآخَرُ أَبُو مُوسَىحَدَّثَنَا ابْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ خَيْثَمَةَ وَقَالَ يُعَجِّلُ الْإِفْطَارَ وَيُؤَخِّرُ السَّحُورَ حَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ أَبِي عَطِيَّةَ قَالَ قُلْنَا لِعَائِشَةَ رَجُلَانِ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدُهُمَا يُعَجِّلُ الْمَغْرِبَ وَيُعَجِّلُ الْإِفْطَارَ وَالْآخَرُ يُؤَخِّرُ الْمَغْرِبَ وَيُؤَخِّرُ الْإِفْطَارَ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Abu Muawiyah] Telah menceritakan kepada kami [Al-A'masy] dari [Umarah] dari [Abi Athiyah] berkata; Saya dan Masruq pernah menemui [Aisyah], lalu kami berkata; \"Wahai Ummul Mukminin, ada dua orang sahabat Nabi Shallallahu'alaihiwasallam, salah satu dari mereka berdua menyegerakan berbuka dan menyegerakan shalat, sedangkan yang satu lagi mengakhirkan berbuka dan mengakhirkan shalat.\" (Athiyyah) Berkata; Maka Aisyah bertanya; \"Siapa dari mereka berdua yang menyegerakan berbuka dan menyegerakan sholat?\" Kami berkata; \"Abdullah bin Mas`ud.\" Aisyah berkata; \"Memang seperti itulah yang diperbuat oleh Nabi Shallallahu'alaihiwasallam.\" Sedang lelaki yang lainnya adalah Abu Musa Al-Asy`ari. Telah menceritakan kepada kami [Ibnu Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] berkata; Saya telah mendengar [Khaitsamah] dan dia berkata; \"(Abu Musa) menyegarakan berbuka dan mengakhirkan sahur.\" Telah menceritakan kepada kami [Mu'ammal], Telah menceritakan kepada kami [Sufyan] dari [Al-A`masy] dari [Umaroh] dari [Abu Athiyyah] berkata; Kami berkata kepada [Aisyah]; \"Ada dua orang lelaki dari sahabat Muhammad Shallallahu'alaihiwasallam, salah satu dari mereka berdua menyegerakan (shalat) maghrib dan menyegerakan berbuka dan yang lain mengakhirkan (shalat) maghrib dan mengakhirkan berbuka.\" Lalu ia menyebutkan (seperti cerita di atas).\""},"3730":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ قَالَ حَدَّثَنِي عَبْدُ الْوَاحِدِ بْنُ حَمْزَةَ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي بَعْضِ صَلَاتِهِ اللَّهُمَّ حَاسِبْنِي حِسَابًا يَسِيرًا فَلَمَّا انْصَرَفَ قُلْتُ يَا نَبِيَّ اللَّهِ مَا الْحِسَابُ الْيَسِيرُ قَالَ أَنْ يَنْظُرَ فِي كِتَابِهِ فَيَتَجَاوَزَ عَنْه إِنَّهُ مَنْ نُوقِشَ الْحِسَابَ يَوْمَئِذٍ يَا عَائِشَةُ هَلَكَ وَكُلُّ مَا يُصِيبُ الْمُؤْمِنَ يُكَفِّرُ اللَّهُ عَزَّ وَجَلَّ بِهِ عَنْه حَتَّى الشَّوْكَةُ تَشُوكُهُ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Muhammad bin Ishaq] dia berkata; Telah berkata kepadaku [Abdul Wahid bin Hamzah bin Abdullah bin Az-Zubair] dari [Abbad bin Abdillah bin Az-Zubair] dari [Aisyah] berkata; Saya telah mendengar Nabi Shallallahu'alaihiwasallam pada sebagian shalatnya membaca: \"Ya Allah hisablah aku dengan hisab yang mudah.\" Ketika beliau berpaling saya bekata; \"Wahai Nabi Allah, apa yang dimaksud dengan hisab yang mudah?.\" Beliau bersabda: \"Seseorang yang Allah melihat kitabnya lalu memaafkannya. Karena orang yang diperdebatkan hisabnya pada hari itu, pasti celaka wahai Aisyah, dan setiap musibah yang menimpa orang beriman Allah akan menghapus (dosanya) karenanya, bahkan sampai duri yang menusuknya.\""},"3731":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَكَعَ رَكْعَتَيْ الْفَجْرِ اضْطَجَعَ عَلَى شِقِّهِ الْأَيْمَنِ","id":"Telah menceritakan kepada kami [Isma'il], dia berkata; Telah mengkabarkan kepada kami [Abdurrahman bin Ishaq] dari [Az-Zuhri] dari [Urwah] dari [Aisyah] berkata; \"Apabila Rasulullah Shallallahu'alaihiwasallam telah shalat dua rakaat fajar, beliau berbaring miring ke sebelah kanannya.\""},"3732":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ شَرِيكٍ عَنِ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْتُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِي وَفِي لَيْلَتِي","id":"Telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Muhammad bin Syarik] dari [Ibnu Abi Mulaikah] dari [Aisyah] berkata; \"Nabi Shallallahu'alaihiwasallam wafat di rumahku dan pada malam (jatah giliranku).\""},"3733":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ شَرِيكٍ عَنِ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ أَنَّهَاسَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَيْءٍ مِنْ أَمْرِ الصَّدَقَةِ فَذَكَرَتْ شَيْئًا قَلِيلًا فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطِي وَلَا تُوعِي فَيُوعَى عَلَيْكِ","id":"Telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Muhammad bin Syarik] dari [Ibnu Abi Mulaikah] dari [Aisyah] bahwa dia bertanya kepada Nabi Shallallahu'alaihiwasallam tentang perkara shodaqoh, kemudian Aisyah sampaikan bagaimana kalau halnya harta sangat terbatas. Maka Nabi Shallallahu'alaihiwasallam bersabda: \"Berikanlah (bersedekahlah) dan jangan kamu bakhil terhadapnya sehingga Allah membatasi rejekimu).\""},"3734":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَلِيٌّ عَنْ يَحْيَى قَالَ حَدَّثَنِي أَبُو سَلَمَةَ أَنَّ أُمَّ بَكْرٍ أَخْبَرَتْهُ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْمَرْأَةِ تَرَى مَا يُرِيبُهَا بَعْدَ الطُّهْرِ قَالَ إِنَّمَا هُوَ عُرُوقٌ أَوْ قَالَ عِرْقٌ","id":"Telah menceritakan kepada kami [Abu Amir] telah menceritakan kepada kami [Ali] dari [Yahya] dia berkata; telah menceritakan kepadaku [Abu Salamah] bahwa [Ummu Bakr] menceritakan kepadanya dari [Aisyah] bahwa Nabi Shallallahu'alaihi wasallam bersabda kepada seorang wanita yang melihat sesuatu yang meragukannya setelah suci, beliau bersabda: \"Yang demikian itu hanyalah peluh-peluh.\" atau beliau bersabda: \"Hanyalah peluh.\""},"3735":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ أُسَامَةَ عَنْ عُثْمَانَ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى الَّذِينَ يَصِلُونَ الصُّفُوفَ","id":"Telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Usamah] dari [Ustman bin Urwah] dari [Urwah] dari [Aisyah] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Allah AzzaWaJalla dan malaikat-Nya memberikan sholawat kepada orang-orang yang menyambung shof-shof (merapatkan barisan shalat).\""},"3736":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ الْمَلِكِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَائِشَةَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَكَى رَقَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ بِسْمِ اللَّهِ أَرْقِيكَ مِنْ كُلِّ دَاءٍ يَشْفِيكَ مِنْ شَرِّ حَاسِدٍ إِذَا حَسَدَ وَمِنْ شَرِّ كُلِّ ذِي عَيْنٍ","id":"Telah menceritakan kepada kami [Abu Amir Abdul Malik bin Amru] dia berkata; telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Yazid bin Abdullah bin Al Had] dari [Muhammad bin Ibrohim] dari [Aisyah] bahwa jika Nabi Shallallahu'alaihiwasallam merasa sakit maka Jibril Alaihissalam meruqyahnya, dia membaca: BISMILLAAHI ARQIIKA MIN KULLI DAAIN YASYFIIKA MIN SYARRI HAASIDIN IDZAA HASAD WAMIN SYARRI KULLI DZI AININ (dengan nama Allah saya meruqyahmu dari setiap penyakit, semoga Allah menyembuhkanmu dari kejelekan pendengki yang mendengki, dari kejelekan setiap orang yang memiliki Ain).\" "},"3737":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنِي عَلِيُّ بْنُ زَيْدٍ قَالَ حَدَّثَتْنِي أُمُّ مُحَمَّدٍ أَنَّ عَائِشَةَ حَدَّثَتْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَرْقُدُ مِنْ لَيْلٍ وَلَا نَهَارٍ فَيَسْتَيْقِظُ إِلَّا اسْتَاكَ قَبْلَ الْوُضُوءِ","id":"Telah menceritakan kepada kami [Abdus Shomad] telah menceritakan kepada kami [Hammam] dia berkata; telah menceritakan kepadaku [Ali bin Zaid] dia berkata; telah menceritakan kepadaku [Ummu Muhmmad] bahwa [Aisyah] bercerita kepadanya; bahwa Rasulullah Shallallahu'alaihiwasallam tidaklah tidur di malam hari dan tidak pula di siang hari kemudian bangun, melainkan beliau bersiwak sebelum wudhu."},"3738":{"ar":"أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ قَالَ أَخْبَرَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنِ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى مِنْ يَهُودِيٍّ طَعَامًا فَرَهَنَهُ دِرْعَهُ","id":"Ahmad bin Hanbal telah menceritakan kepada kami [Yahya bin Zakaria bin Abi Zaidah] dia berkata; telah mengabarkan kepada kami [Al A'masy] dari [Ibrohim] dari [Al Aswad] dari [Aisyah] berkata; Rasululah Shallallahu'alaihiwasallam pernah membeli makanan pada seorang yahudi lalu beliau menggadai baju besinya."},"3739":{"ar":"حَدَّثَنَا قُرَّانُ بْنُ تَمَّامٍ عَنِ ابْنِ أَبِي ذِئْبٍ عَنْ مَخْلَدِ بْنِ خُفَافٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْغَلَّةَ بِالضَّمَانِسَمِعْتُ مِنْ قُرَّانَ بْنِ تَمَّامٍ فِي سَنَةِ إِحْدَى وَثَمَانِينَ وَمِائَةٍ وَكَانَ ابْنُ الْمُبَارَكِ بَاقِيًا وَفِيهَا مَاتَ ابْنُ الْمُبَارَكِ","id":"Telah menceritakan kepada kami [Qurron bin Tammam] dari [Ibnu Abi Dzi'b] dari [Makhlad bin Khufaf] dari [Urwah] dari [Aisyah] berkata; Rasulullah Shallallahu'alaihiwasallam menetapkan bahwa penggadaian harus ada jaminan. Saya mendengar dari Qurron bin Tammam pada tahun seratus delapan puluh satu dan waktu itu Ibnu Mubarok masih hidup dan pada tahun itu Ibnu Mubarok wafat."},"3740":{"ar":"حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ حَدَّثَنَا عَاصِمٌ عَنْ مُعَاذَةَ الْعَدَوِيَّةِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ وَهُوَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Marwan bin Mu'awiyyah Al Fazari] telah menceritakan kepada kami [Ashim] dri [Mu'adzah Al Adawiyyah] dari [Aisyah] berkata; \"Saya dan Rasulullah Shallallahu'alaihiwasallam pernah mandi dalam satu bejana dan beliau berada di antara keduanya.\""},"3741":{"ar":"حَدَّثَنَا الْهَيْثَمُ بْنُ جَمِيلٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى امْرَأَةٍ مِنْ الْأَنْصَارِ وَفِي الْبَيْتِ قِرْبَةٌ مُعَلَّقَةٌ فَاخْتَنَثَهَا وَشَرِبَ وَهُوَ قَائِمٌ","id":"Telah menceritakan kepada kami [Al Haitsam bin Jamil] dia berkata; telah menceritakan kepada kami [Muhammad bin Muslim] dia berkata; telah menceritakan kepada kami [Abdurrohman bin Al Qosim] dari [ayahnya] dari [Aisyah] bahwa Nabi Shallallahu'alaihiwasallam menemui seorang wanita Anshor dan di dalam rumahnya terdapat geriba (tempat air yang terbuat dari kulit) yang tergantung, maka beliau memecahkan tutup mulut geriba itu dan beliau minum dengan berdiri."},"3742":{"ar":"قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ الْفَضْلُ بْنُ دُكَيْنٍ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ عَنِ الْفِرَاسِ عَنِ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْأَقْبَلَتْ فَاطِمَةُ تَمْشِي كَأَنَّ مِشْيَتَهَا مِشْيَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَرْحَبًا بِابْنَتِي ثُمَّ أَجْلَسَهَا عَنْ يَمِينِهِ أَوْ عَنْ شِمَالِهِ ثُمَّ إِنَّهُ أَسَرَّ إِلَيْهَا حَدِيثًا فَبَكَتْ فَقُلْتُ لَهَا اسْتَخَصَّكِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثَهُ ثُمَّ تَبْكِينَ ثُمَّ إِنَّهُ أَسَرَّ إِلَيْهَا حَدِيثًا فَضَحِكَتْ فَقُلْتُ مَا رَأَيْتُ كَالْيَوْمِ فَرَحًا أَقْرَبَ مِنْ حُزْنٍ فَسَأَلْتُهَا عَمَّا قَالَ فَقَالَتْ مَا كُنْتُ لِأُفْشِيَ سِرَّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا قُبِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلْتُهَا فَقَالَتْ إِنَّهُ أَسَرَّ إِلَيَّ فَقَالَ إِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام كَانَ يُعَارِضُنِي بِالْقُرْآنِ فِي كُلِّ عَامٍ مَرَّةً وَإِنَّهُ عَارَضَنِي بِهِ الْعَامَ مَرَّتَيْنِ وَلَا أُرَاهُ إِلَّا قَدْ حَضَرَ أَجَلِي وَإِنَّكِ أَوَّلُ أَهْلِ بَيْتِي لُحُوقًا بِي وَنِعْمَ السَّلَفُ أَنَا لَكِ فَبَكَيْتُ لِذَلِكَ ثُمَّ قَالَ أَلَا تَرْضَيْنَ أَنْ تَكُونِي سَيِّدَةَ نِسَاءِ هَذِهِ الْأُمَّةِ أَوْ نِسَاءِ الْمُؤْمِنِينَ قَالَتْ فَضَحِكْتُ لِذَلِكَ","id":"Ia berkata; telah menceritakan kepada kami [Abu Nu'aim Alfadl bin Dukain] berkata; telah menceritakan kepada kami [Zakariya bin Abi Zaidah] dari [Al Firasy] dari [Asy Sya'bi] dari [Masruq] dari [Aisyah] berkata; \" [Fatimah] datang dengan berjalan seperti jalannya Rasulullah shallaallahu 'alaihi wa sallam, beliau pun lantas menyambutnya: \"Selamat datang putriku, \" lalu beliau mendudukkannnya di samping kanan atau kiri beliau. Lantas beliau membisikkan sesuatu kepadanya, ia pun menangis. Beliau pun membisikkan kembali sesuatu kepadanya dan ia tertawa. Aku berkata; \"Aku tidak melihat sesuatu seperti hari ini yang lebih membahagiakan daripada kesedihan.\" Aku bertanya; \"Apa yang beliau sabdakan?\" ia menjawab; \"Aku tidak akan membeberkan rahasia Rasulullah shallaallahu 'alaihi wa sallam hingga Nabi shallaallahu 'alaihi wa sallam meninggal.\" Aku bertanya kepadanya; \"Apa yang beliau katakan?\" Ia menjawab; \"Beliau mengatakan kepadaku: 'Sesungguhnya Jibril 'alaihissalam datang kepadaku, dulu ia membacakan Al Qur'an kepadaku sekali selama setahun, pada tahun itu ia membacakan kepadaku dua kali, dan aku tidak melihatnya kecuali ajalku akan segera datang. Engkau adalah ahli baitku yang pertama kali akan menyusulku, dan sebaik-baik orang yang terdahulu untuk mu adalah aku.' maka aku menangis karena itu. Kemudian beliau bersabda: 'Tidakkah engkau suka jika engkau menjadi pemimpin para wanita umat ini, atau ummul mukminin? ' maka aku tertawa karena itu.\""},"3743":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ قَالَ حَدَّثَنَا أَبِي عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْلَمَّا مَرِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا ابْنَتَهُ فَاطِمَةَ فَسَارَّهَا فَبَكَتْ ثُمَّ سَارَّهَا فَضَحِكَتْ فَسَأَلْتُهَا عَنْ ذَلِكَ فَقَالَتْ أَمَّا حَيْثُ بَكَيْتُ فَإِنَّهُ أَخْبَرَنِي أَنَّهُ مَيِّتٌ فَبَكَيْتُ ثُمَّ أَخْبَرَنِي أَنِّي أَوَّلُ أَهْلِهِ لُحُوقًا بِهِ فَضَحِكْتُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah menceritakan kepada mengabarkan kepada kami [Ibrahim bin Sa'ad] berkata; telah menceritakan kepada kami [Ayahku] dari [Urwah bin Az Zubair] dari [Aisyah] berkata; \"Ketika Rasulullah shallaallahu 'alaihi wa sallam sakit, beliau memanggil putrinya, [Fatimah] lalu beliau membisikkan sesuatu kepadanya dan ia pun menangis. Kemudian beliau membisikkan sesuatu lalu ia tertawa. Aku pun bertanya akan hal itu; ia menjawab; \"Aku menangis karena beliau memberitahuku bahwasannya beliau akan meninggal. Kemudian beliau memberitahuku bahwasanya aku adalah keluarganya yang pertama kali menyusul beliau, aku pun tertawa.\""},"3744":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ سُلَيْمَانَ بْنِ أَبِي سُلَيْمَانَ عَنْ أُمِّهِ أُمِّ سُلَيْمَانَ وَكِلَاهُمَا كَانَ ثِقَةً قَالَتْدَخَلْتُ عَلَى عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهَا عَنْ لُحُومِ الْأَضَاحِيِّ فَقَالَتْ قَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهَا ثُمَّ رَخَّصَ فِيهَا قَدِمَ عَلِيُّ بْنُ أَبِي طَالِبٍ مِنْ سَفَرٍ فَأَتَتْهُ فَاطِمَةُ بِلَحْمٍ مِنْ ضَحَايَاهَا فَقَالَ أَوَلَمْ يَنْهَ عَنْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّهُ قَدْ رَخَّصَ فِيهَا قَالَتْ فَدَخَلَ عَلِيٌّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ ذَلِكَ فَقَالَ لَهُ كُلْهَا مِنْ ذِي الْحِجَّةِ إِلَى ذِي الْحِجَّةِ","id":"Telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepadaku [Ayahku] dari [Muhammad bin Ishaq] berkata; telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Sulaiman bin Abu Sulaiman] dari [ibunya, Ummu Sulaiman] dan keduanya adalah orang yang terpercaya, ia berkata; \"Aku menemui [Aisyah], isteri Nabi shallaallahu 'alaihi wa sallam, lalu aku bertanya kepadanya tentang daging korban?\" ia menjawab; \"(awalnya) Rasulullah shallaallahu 'alaihi wa sallam melarang untuk memakannya, namun kemudian memberikan keringanan padanya.\" Kemudian Ali bin Abi Thalib datang selepas ia berpergian dan Fatimah menemuinya dengan membawa daging korban. Lalu Ali berkata; \"Bukankah Rasulullah shallaallahu 'alaihi wa sallam telah melarangnya.\" ia menjawab; \"Sesungguhnya beliau telah memberi keringanan padanya.\" ia berkata; \"Ali pun lantas menemui Rasulullah shallaallahu 'alaihi wa sallam dan ia bertanya akan hal itu.\" Beliau menjawab: \"Makanlah ia dari Dzilhijjah ke Dzilhijjah.\""},"3745":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ أَبِي سُلَيْمٍ عَنْ عَبْدِ اللَّهِ بْنِ حَسَنٍ عَنْ أُمِّهِ فَاطِمَةَ ابْنَةِ حُسَيْنٍ عَنْ جَدَّتِهَا فَاطِمَةَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْمَسْجِدَ صَلَّى عَلَى مُحَمَّدٍ وَسَلَّمَ وَقَالَ اللَّهُمَّ اغْفِرْ لِي ذُنُوبِي وَافْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ صَلَّى عَلَى مُحَمَّدٍ وَسَلَّمَ ثُمَّ قَالَ اللَّهُمَّ اغْفِرْ لِي ذُنُوبِي وَافْتَحْ لِي أَبْوَابَ فَضْلِكَقَالَ إِسْمَاعِيلُ فَلَقِيتُ عَبْدَ اللَّهِ بْنَ حَسَنٍ فَسَأَلْتُهُ عَنْ هَذَا الْحَدِيثِ فَقَالَ كَانَ إِذَا دَخَلَ قَالَ رَبِّ افْتَحْ لِي بَابَ رَحْمَتِكَ وَإِذَا خَرَجَ قَالَ رَبِّ افْتَحْ لِي بَابَ فَضْلِكَ","id":"Telah menceritakan kepada kami [Ismail bin Ibrahim] berkata; telah menceritakan kepada kami [Laits, yaitu Ibnu Abi Sulaim] dari [Abdullah Bin Hasan] dari ibunya, [Fathimah, anak perempuan Husain] dari neneknya [Fathimah binti Rasulullah shallaallahu 'alaihi wa sallam] ia berkata; \"Apabila Rasulullah shallaallahu 'alaihi wa sallam masuk masjid, beliau bersalawat dan salam ke atas Muhammad dan berdoa: \"ALLAHUMMAGHFIRLI DZUNUBY WAFTAH LI ABWABA RAHMATIKA (Ya Allah, ampunilah dosa-dosaku dan bukakan lah pintu-pintu rahmat-Mu), \" Jika beliau keluar, beliau bersalawat dan salam ke atas Muhammad, beliau lalu berdoa: \"ALLAHUMMAGHFIRLI DZUNUUBY WAFTAHLI ABWAABA FADLLIKA (Ya Allah, ampunilah dosa-dosaku dan bukakanlah pintu-pintu karunia-Mu) \" Isma'il berkata; \"Lalu aku menemui Abdullah Bin Hasan dan aku bertanya akan hadits ini, ia berkata; 'Dulu, jika beliau masuk masjid beliau berdoa: RABBIFTAH LI BABA RAHMATIKA (ya Rabbi, bukakanlah untukku pintu Rahmat-Mu) dan jika beliau keluar, beliau berdoa: \"RABBIFTAH LII BABA FADLIKA (ya Rabbi, bukakanlah untukku pintu karunia-Mu).\""},"3746":{"ar":"قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا لَيْثٌ عَنْ عَبْدِ اللَّهِ بْنِ الْحَسَنِ عَنْ فَاطِمَةَ بِنْتِ حُسَيْنٍ عَنْ جَدَّتِهَا فَاطِمَةَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْمَسْجِدَ قَالَ بِسْمِ اللَّهِ وَالسَّلَامُ عَلَى رَسُولِ اللَّهِ اللَّهُمَّ اغْفِرْ لِي ذُنُوبِي وَافْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ قَالَ بِسْمِ اللَّهِ وَالسَّلَامُ عَلَى رَسُولِ اللَّهِ اللَّهُمَّ اغْفِرْ لِي ذُنُوبِي وَافْتَحْ لِي أَبْوَابَ فَضْلِكَ","id":"Telah (Imam Ahmad bin Hanbal) Berkata; telah menceritakan kepada kami [Abu Mua'wiyah] telah menceritakan kepada kami [Laits] dari [Abdullah Bin Hasan] dari [Fathimah binti Husain] dari [neneknya, Fathimah binti Rasulullah shallallahu 'alaihi wasallam.] berkata; \"Apabila Rasulullah shallaallahu 'alaihi wa sallam masuk masjid, beliau berdoa: \"BISMILLAHI WASSALAAMU 'ALA RASUULILLAH, ALLAHUMMAGHFIR LI DZUNUBI WAFTAHLI ABWAABA RAHMATIKA (dengan menyebut nama Allah serta salam kepada Rasulullah, ya Allah ampunilah dosa-dosaku dan bukakanlah pintu-pintu Rahmat-Mu), \" dan jika keluar beliau berdoa: \"BISMILLAAHI WASSALAAMU 'ALAA RASUULILLAH, ALLAHUMMAGHFIR LII DZUNUUBI WAFTAHLII ABWAABA FADLLIKA (Dengan menyebut nama Allah serta salam kepada Rasulullah, ya Allah ampunilah dosa-dosaku dan bukakanlah pintu-pintu karunia-Mu).\""},"3747":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ أَبِيهِ عَنِ الْحَسَنِ بْنِ الْحَسَنِ عَنْ فَاطِمَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلَ عَرْقًا فَجَاءَ بِلَالٌ بِالْأَذَانِ فَقَامَ لِيُصَلِّيَ فَأَخَذْتُ بِثَوْبِهِ فَقُلْتُ يَا أَبَهْ أَلَا تَتَوَضَّأُ فَقَالَ مِمَّ أَتَوَضَّأُ يَا بُنَيَّةُ فَقُلْتُ مِمَّا مَسَّتْ النَّارُ فَقَالَ لِي أَوَلَيْسَ أَطْيَبُ طَعَامِكُمْ مَا مَسَّتْهُ النَّارُ","id":"Telah menceritakan kepada kami [Hasan bin Musa] telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin Ishaq] dari [Ayahnya] dari [Hasan bin Hasan] dari [Fathimah] berkata; \"Rasulullah shallaallahu 'alaihi wa sallam pernah menemuiku lalu beliau makan daging. Kemudian datanglah Bilal mengumandangkan adzan. Beliau pun bersiap untuk mendirikan shalat, kemudian aku mengambilkan pakaiannya dan berkata; 'Wahai ayahku! tidakkah engkau berwudhu? ' Beliau bertanya: 'Berwudhu dari apa wahai putriku? ' aku menjawab; 'Dari apa yang dimasak? ' Beliau menjawab: 'Bukankah makanan terbaik kalian adalah yang telah dimasak'?\""},"3748":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا الْحَسَنُ يَعْنِي ابْنَ صَالِحٍ عَنْ لَيْثٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَسَنِ عَنْ فَاطِمَةَ بِنْتِ حُسَيْنٍ عَنْ فَاطِمَةَ ابْنَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ إِذَا دَخَلَ الْمَسْجِدَ صَلَّى عَلَى مُحَمَّدٍ وَسَلَّمَ ثُمَّ قَالَ اللَّهُمَّ اغْفِرْ لِي ذُنُوبِي وَافْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ صَلَّى عَلَى مُحَمَّدٍ وَسَلَّمَ وَقَالَ اللَّهُمَّ اغْفِرْ لِي ذُنُوبِي وَافْتَحْ لِي أَبْوَابَ فَضْلِكَ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] berkata; telah menceritakan kepada kami [Al Hasan yakni Ibnu Shalih] dari [Laits] dari [Abdullah bin Al Hasan] dari [Fathimah binti Husain] dari [neneknya, Fathimah binti Rasulullah shallaallahu 'alaihi wa sallam] berkata; \"Apabila Rasulullah shallaallahu 'alaihi wa sallam masuk masjid, beliau berdo'a: BISMILLAHI WASSALAAMU 'ALA RASUULILLAH, ALLAHUMMAGHFIR LI DZUNUBI WAFTAHLI ABWAABA RAHMATIKA (dengan menyebut nama Allah serta salam kepada Rasulullah, ya Allah ampunilah dosa-dosaku dan bukakanlah pintu-pintu Rahmat-Mu), Dan jika keluar, beliau berdo'a: BISMILLAAHI WASSALAAMU 'ALAA RASUULILLAH, ALLAHUMMAGHFIR LII DZUNUUBI WAFTAHLII ABWAABA FADLLIKA (Dengan menyebut nama Allah serta salam kepada Rasulullah, ya Allah ampunilah dosa-dosaku dan bukakanlah pintu-pintu karunia-Mu).\""},"3749":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ رَاشِدٍ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ قَالَدَخَلَتْ فَاطِمَةُ عَلَى أَبِي بَكْرٍ فَقَالَتْ أَخْبَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي أَوَّلُ أَهْلِهِ لُحُوقًا بِهِ","id":"Telah menceritakan kepada kami [Abdurrozaq] berkata; telah menceritakan kepada kami [Muhammad, yaitu ibnu Rasyid] berkata; telah menceritakan kepadaku [Ja'far bin 'Amru bin Umayyah] berkata; \" [Fathimah] pernah menemui Abu Bakr, ia pun berkata; 'Rasulullah shallaallahu 'alaihi wa sallam telah mengabariku bahwa aku adalah keluarganya yang pertama kali menyusul kematiannya'.\""},"3750":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا الْقَاسِمُ بْنُ الْفَضْلِ قَالَ قَالَ لَنَا مُحَمَّدُ بْنُ عَلِيٍّكَتَبَ إِلَيَّ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ أَنْ أَنْسَخَ إِلَيْهِ وَصِيَّةَ فَاطِمَةَ فَكَانَ فِي وَصِيَّتِهَا السِّتْرُ الَّذِي يَزْعُمُ النَّاسُ أَنَّهَا أَحْدَثَتْهُ وَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَلَمَّا رَآهُ رَجَعَ","id":"Telah menceritakan kepada kami [Abdusshamad] telah menceritakan kepada kami [Al Qasim Bin Fadh] berkata; [Muhammad bin Ali] telah berkata kepada kami; \"Umar bin Abdul Azzis pernah menyuratiku agar aku menghapus untuknya wasiat [Fathimah], diwasiat itu tertulis sitr (kain penutup yang bergambar) yang orang-orang berkata bahwa ia telah membuat perkara baru. Rasulullah shallaallahu 'alaihi wa sallam pun menemuinya dan ketika beliau melihat (satr bergambar tersebut), beliau kembali lagi.\""},"3751":{"ar":"حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا زَمْعَةُ عَنِ ابْنِ أَبِي مُلَيْكَةَ قَالَكَانَتْ فَاطِمَةُ تَنْقُزُ الْحَسَنَ بْنَ عَلِيٍّ وَتَقُولُ بِأَبِي شَبَهُ النَّبِيِّلَيْسَ شَبِيهًا بِعَلِيٍّ","id":"Telah menceritakan kepada kami [Abu Dawud Atthoyalisy] telah menceritakan kepada kami [Zam'ah] dari [Ibnu Abu Malikah] berkata; \" [Fathimah] pernah menggendong Hasan Bin Ali, ia berkata kepada ayahku; \"Ia mirip dengan Nabi dan tidak mirip dengan Ali.\""},"3752":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنِ ابْنِ عُمَرَ عَنْ حَفْصَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ مَا شَأْنُ النَّاسِ حَلُّوا وَلَمْ تَحِلَّ مِنْ عُمْرَتِكَ قَالَ إِنِّي قَلَّدْتُ هَدْيِي وَلَبَّدْتُ رَأْسِي فَلَا أَحِلُّ حَتَّى أَحِلَّ مِنْ الْحَجِّ","id":"Telah menceritakan kepada kami [Yahya bin Sai'id] dari [Ubaidullah] berkata; telah menceritakan kepadaku [Nafi'] berkata; telah menceritakan [Ibnu Umar] dari [Hafshah] ia berkata aku berkata; \"Wahai Rasulullah! bagaimana keadaan orang-orang yang mereka telah bertahallul, namun tidak bertahallul dari umrah mu?\" beliau menjawab: \"Sesungguhnya aku memintalkan taki kalung untuk hewan kurbanku sebagai tanda, aku ikat rambutku, aku tidak akan bertahallul hingga aku bertahallul dari haji.\""},"3753":{"ar":"حَدَّثَنَا سُرَيْجٌ وَعَفَّانُ وَيُونُسُ قَالُوا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ وَعُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَأَنَّهُ رَأَى ابْنَ صَائِدٍ فِي سِكَّةٍ مِنْ سِكَكِ الْمَدِينَةِ فَسَبَّهُ ابْنُ عُمَرَ وَوَقَعَ فِيهِ فَانْتَفَخَ حَتَّى سَدَّ الطَّرِيقَ فَضَرَبَهُ ابْنُ عُمَرَ بِعَصًا كَانَتْ مَعَهُ حَتَّى كَسَّرَهَا عَلَيْهِ فَقَالَتْ لَهُ حَفْصَةُ مَا شَأْنُكَ وَشَأْنُهُ مَا يُولِعُكَ بِهِ أَمَا سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا يَخْرُجُ الدَّجَّالُ مِنْ غَضْبَةٍ يَغْضَبُهَا قَالَ عَفَّانُ عِنْدَ غَضْبَةٍ يَغْضَبُهَا وَقَالَ يُونُسُ فِي حَدِيثِهِ مَا تَوَالُعُكَ بِهِ","id":"Telah menceritakan kepada kami [Suraij] dan [Affan] dan [Yunus], mereka berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Ayyub] dan [Ubbaidullah] dari [Nafi'] dari [Ibnu Umar] bahwasanya ia melihat Ibnu Shoid berada di salah satu pintu masuk Madinah, kemudian Ibnu Umar mencelanya, dan ia pun menghinanya, ia pun semakin marah hingga menutupi jalan. Kemudian Ibnu Umar memukulnya dengan tongkat yang dibawanya, hingga ia memecahkannya. Lalu [Hafshah] berkata kepadanya; \"Ada masalah apa engkau dengannya, apa yang membuatmu mencelanya? Tidakkah engkau mendengar Rasulullah shallaallahu 'alaihi wa sallam bersabda: 'Hanyasanya Dajjal itu keluar dari kemarahan yang ia lakukan', \" [Affan] berkata ketika ia marah, [Yunus] berkata pada haditsnya; \"Apa yang membuatmu mencelanya.\""},"3754":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبِي مَرَّةً أُخْرَى حَدَّثَنَا عَبْدُ الْوَهَّابِ الْخَفَّافُ عَنِ ابْنِ عَوْنٍ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَ قَالَلَقِيتُ ابْنَ صَائِدٍ مَرَّتَيْنِ فَأَمَّا مَرَّةً فَلَقِيتُهُ وَمَعَهُ أَصْحَابُهُ فَذَكَرَ الْحَدِيثَ قَالَ وَنَخَرَ كَأَشَدِّ نَخِيرِ حِمَارٍ سَمِعْتُهُ قَالَ فَزَعَمَ أَصْحَابِي أَنِّي ضَرَبْتُهُ بِعَصًا كَانَتْ مَعِي حَتَّى انْكَسَرَتْ وَأَمَّا أَنَا فَلَمْ أَشْعُرْ بِذَلِكَ فَدَخَلْتُ عَلَى أُخْتِي حَفْصَةَ أُمِّ الْمُؤْمِنِينَ فَأَخْبَرْتُهَا بِذَلِكَ فَقَالَتْ وَمَا أَرَدْتَ إِلَيْهِ أَمَا عَلِمْتَ أَنَّهُ قَالَ إِنَّ أَوَّلَ خُرُوجِهِ عَلَى النَّاسِ لِغَضْبَةٍ يَغْضَبُهَا","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku Ayahku telah menceritakan kepada kami [Abdul Wahhab Al Khaffaf] dari [Ibnu 'Aun] dari [Nafi'] dari [Ibnu Umar] berkata; \"Saya pernah bertemu Ibnu Shoid untuk yang kedua kalinya. Yang pertama, saya bertemu dengannya ketika ia bersama para sahabatnya dan ia telah menyebutkan kejadian tersebut.\" ia berkata; \"(yang kedua), ia bersuara seperti suara keledai yang aku sudah pernah mendengarnya.\" Ia berkata; \"Para sahabatku mengklaim bahwa aku telah memukulnya dengan tongkat milikku hingga pecah. Sementara aku tidak merasa telah melakukan hal itu. lalu saya menemui saudara perempuan ku, [Hafshah ummul mukminin], aku pun mengabarkan hal itu.\" Ia pun berkata; \"Apa yang engkau inginkan kepadanya?\" Tidakkah engkau mendengar Rasulullah shallaallahu 'alaihi wa sallam bersabda: 'Hanyasanya Dajjal itu keluar dari kemarahan yang ia lakukan', \""},"3755":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ : مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ حَفْصَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَكَتَ الْمُؤَذِّنُ مِنْ الْأَذَانِ بِالصُّبْحِ وَبَدَا الصُّبْحُ صَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ قَبْلَ أَنْ تُقَامَ الصَّلَاةُ","id":"Telah (Imam Ahmad) Berkata; saya telah membaca kepada [Abdurrahman bin Mahdi]; [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa [Hafshah], isteri Nabi shallaallahu 'alaihi wa sallam telah mengabarkan kepadanya; \"Apabila muadzin telah selesai adzan shubuh dan waktu shubuh sudah terlihat, Rasulullah shallaallahu 'alaihi wa sallam melakukan shalat dua raka'at ringan sebelum dilaksanakannya shalat shubuh.\""},"3756":{"ar":"حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ مُحَمَّدٍ الْخَطَّابِيُّ فِي سَنَةِ ثَمَانٍ وَمِائَتَيْنِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو الرَّقِّيُّ عَنْ عَبْدِ الْكَرِيمِ يَعْنِي الْجَزَرِيَّ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَ عَنْ حَفْصَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَذَّنَ الْمُؤَذِّنُ صَلَّى رَكْعَتَيْنِ وَحَرَّمَ الطَّعَامَ وَكَانَ لَا يُؤَذِّنُ حَتَّى يَطْلُعَ الْفَجْرُ","id":"Telah menceritakan kepada kami [Abdul Jabbar bin Muhammad Al Khattabi] pada tahun dua ratus delapan, ia berkata; telah menceritakan kepada kami [Ubaidullah bin Amru Arraqyu] dari [Abdul Karim, yaitu Al Jazari] dari [Nafi'] dari [Ibnu Umar] dari [Hafshah], apabila muadzin telah mengumandangkan adzan, Nabi shallaallahu 'alaihi wa sallam melakukan shalat dua raka'at dan mengharamkan makanan, sementara adzan tidak dikumandangkan hingga telah terbitnya fajar.\""},"3757":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَ عَنْ حَفْصَةَأَنَّهَا قَالَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَكَ لَمْ تَحِلَّ مِنْ عُمْرَتِكَ قَالَ إِنِّي لَبَّدْتُ رَأْسِي وَقَلَّدْتُ هَدْيِي فَلَا أَحِلُّ حَتَّى أَنْحَرَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Malik] dari [Nafi'] dari [Ibnu Umar] dari [Hafshah] bahwasanya dia bertanya kepada Nabi shallaallahu 'alaihi wa sallam, \"Apa yang membuatmu tidak bertahalul pada umrah engkau?\" beliau menjawab: \"Sesungguhnya aku melipat rambutku, mengalungkan tali kalung untuk hewan kurbanku, dan aku tidak akan bertahalul hingga aku menyembelihnya.\""},"3758":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ زَيْدِ بْنِ مُحَمَّدٍ قَالَ سَمِعْتُ نَافِعًا يُحَدِّثُ عَنِ ابْنِ عُمَرَ عَنْ حَفْصَةَ أَنَّهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا طَلَعَ الْفَجْرُ لَا يُصَلِّي إِلَّا رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Zaid bin Muhammad] berkata; saya telah mendengar [Nafi'] menceritakan dari [Ibnu Umar] dari [Hafshah] bahwasanya ia berkata; \"Apabila telah terbit fajar, Rasulullah shallaallahu 'alaihi wa sallam tidak melakukan shalat kecuali dua raka'at ringan.\""},"3759":{"ar":"حَدَّثَنَا كَثِيرُ بْنُ هِشَامٍ قَالَ حَدَّثَنَا جَعْفَرٌ يَعْنِي ابْنَ بُرْقَانَ حَدَّثَنَا نَافِعٌ عَنِ ابْنِ عُمَرَ أَنَّ حَفْصَةَ أَخْبَرَتْهُ قَالَتْأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَحِلَّ فِي حَجَّتِهِ الَّتِي حَجَّو قَالَ كَثِيرُ بْنُ مُرَّةَ أَنَّ ابْنَ عُمَرَ أَخْبَرَهُ","id":"Telah menceritakan kepada kami [Katsir bin Hisyam] berkata; telah menceritakan kepada kami [Ja'far, yaitu ibnu Burqan] telah menceritakan kepada kami [Nafi'] dari [Ibn Umar] bahwasannya [Hafshah] telah mengabarkan kepadanya; ia berkata; \"Aku diperintah oleh Rasulullah shallaallahu 'alaihi wa sallam untuk bertahallul pada haji yang beliau tunaikan.\" Katsir bin Marrah mengatakan bahwa Ibnu Umar telah mengabarkan kepadanya."},"3760":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ يَعْنِي ابْنَ أَبِي حَمْزَةَ قَالَ قَالَ نَافِعٌ كَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ يَقُولُ أَخْبَرَتْنِي حَفْصَةُ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ أَزْوَاجَهُ أَنْ يَحْلِلْنَ عَامَ حَجَّةِ الْوَدَاعِ فَقَالَتْ لَهُ فُلَانَةُ فَمَا يَمْنَعُكَ أَنْ تَحِلَّ فَقَالَ إِنِّي لَبَّدْتُ رَأْسِي وَقَلَّدْتُ هَدْيِي فَلَسْتُ أَحِلُّ حَتَّى أَنْحَرَ هَدْيِي","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah menceritakan kepada kami [Syu'aib, yaitu Ibnu Abu Hamzah] berkata; [Nafi'] berkata; bahwa [Abdullah bin Umar] berkata; telah mengabarkan kepadaku [Hafshah, isteri Nabi shallallahu 'alaihi wasallam.] bahwa Nabi shallaallahu 'alaihi wa sallam memerintahkan para isterinya untuk bertahalul pada tahun haji wada'. Lalu ada seorang wanita bertanya kepadanya; \"Apa yang menghalangi engkau untuk bertahalul?\" ia menjawab; \"Sesungguhnya aku melipat rambutku, mengalungkan tali kalung untuk hewan kurbanku, dan aku tidak akan bertahalul hingga aku menyembelih hewan kurbanku.\""},"3761":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ حَفْصَةَ ابْنَةِ عُمَرَ قَالَتْلَمَّا أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ أَنْ يَحْلِلْنَ بِعُمْرَةٍ قُلْنَ فَمَا يَمْنَعُكَ يَا رَسُولَ اللَّهِ أَنْ تَحِلَّ مَعَنَا قَالَ إِنِّي قَدْ أَهْدَيْتُ وَلَبَّدْتُ فَلَا أَحِلُّ حَتَّى أَنْحَرَ هَدْيِي وَقَالَ يَعْقُوبُ فِي كِتَابِ الْحَجِّ أَنْحَرَ هَدِيَّتِي","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ayahku] dari [Ibnu Ishaq] berkata; telah menceritakan kepadaku [Nafi'] dari [Abdullah bin Umar] dari [Hafshah, anak perempuan Umar] berkata; \"Ketika Rasulullah shallaallahu 'alaihi wa sallam memerintahkan para isteri beliau agar mereka bertahallul pada umrah mereka, mereka bertanya; 'Apa yang menghalangimu untuk beretahallul dengan kami wahai Rasulullah? ', beliau bersabda: 'Sesungguhnya aku telah mempersiapkan hewan kurban dan mengikat rambutku, maka aku tidak akan bertahallul hingga aku menyembelih kurbanku'.\" Ya'qub meriwayatkan di dalam kitab Haji; 'Saya menyembelih hewan kurbanku.'"},"3762":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا الْحُرُّ بْنُ الصَّيَّاحِ عَنْ هُنَيْدَةَ بْنِ خَالِدٍ عَنِ امْرَأَتِهِ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ تِسْعَ ذِي الْحِجَّةِ وَيَوْمَ عَاشُورَاءَ وَثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ أَوَّلَ اثْنَيْنِ مِنْ الشَّهْرِ وَخَمِيسَيْنِ","id":"Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Abu Awanah] telah menceritakan kepada kami [Al Hurru bin Ashshayyah] dari [Hunaidah bin Khalid] dari [isterinya] dari [sebagian isteri Nabi shallaallahu 'alaihi wa sallam] berkata; \"Rasulullah shallaallahu 'alaihi wa sallam berpuasa pada hari ke sembilan bulan dzulhijjah, pada hari asyura, dan tiga hari setiap bulan, yaitu hari senin pada pekan pekan pertama dan dua hari kamis pada pekan setelah nya.\""},"3763":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَأَبُو كَامِلٍ وَعَفَّانُ قَالُوا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ عَفَّانُ فِي حَدِيثِهِ قَالَ أَخْبَرَنَا أَنَسُ بْنُ سِيرِينَ عَنْ أَبِي مِجْلَزٍ عَنْ حَفْصَةَأَنَّ عُطَارِدَ بْنَ حَاجِبٍ قَدِمَ مَعَهُ ثَوْبُ دِيبَاجٍ كَسَاهُ إِيَّاهُ كِسْرَى فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ اشْتَرَيْتَهُ فَقَالَ إِنَّمَا يَلْبَسُهُ مَنْ لَا خَلَاقَ لَهُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan [Abu Kamil] dan [Affan], mereka berkata; telah menceritakan kepada kami [Hammad bin Salamah] berkata; [Affan] berkata dalam haditsnya; telah mengabarkan kepada kami [Anas bin Sirin] dari [Abu Mijlaz] dari [Hafshah] bahwasanya Uthorid bin Hajib pernah diberi sejenis sutra yang biasa dipakai oleh para Kaisar. Lalu Umar berkata; \"Wahai Rasulullah shallaallahu 'alaihi wa sallam! Seandainya engkau membeli pakaian sepertinya.\" beliau bersabda: \"Hanyasanya orang yang memakainya adalah orang yang tidak akan mendapatkan keberuntungan.\""},"3764":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ نَافِعِ بْنِ عُمَرَ وَأَبُو عَامِرٍ حَدَّثَنَا نَافِعٌ عَنِ ابْنِ أَبِي مُلَيْكَةَ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عَامِرٍ قَالَ نَافِعٌ أُرَاهَا حَفْصَةَأَنَّهَا سُئِلَتْ عَنْ قِرَاءَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّكُمْ لَا تَسْتَطِيعُونَهَا قَالَ فَقِيلَ لَهَا أَخْبِرِينَا بِهَا قَالَ فَقَرَأَتْ قِرَاءَةً تَرَسَّلَتْ فِيهَا قَالَ أَبُو عَامِرٍ قَالَ نَافِعٌ فَحَكَى لَنَا ابْنُ أَبِي مُلَيْكَةَ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }ثُمَّ قَطَّعَ{ الرَّحْمَنِ الرَّحِيمِ }ثُمَّ قَطَّعَ{ مَالِكِ يَوْمِ الدِّينِ }","id":"Telah menceritakan kepada kami [Waki'] dari [Nafi' bin Umar] dan [Abu Amir] telah menceritakan kepada kami [Nafi'] dari [Ibnu Abu Mulaikah] dari [sebagian isteri Nabi shallaallahu 'alaihi wa sallam], [Abu Amir] berkata; berkata [Nafi']; ia pernah melihat [Hafshah] ditanya mengenai bacaannya Rasulullah shallaallahu 'alaihi wa sallam, ia menjawab; \"Sesungguhnya kalian tidak akan mampu melaksanakannya.\" Ia berkata; lalu dikatakan kepadanya; \"Kabarkanlah hal itu kepada kami!\" Ia berkata; \"Ia membacanya secara tartil.\" [Abu Amir] berkata; berkata [Nafi'], [Ibnu Mulaikah] menceritakan kepada kami; ALHAMDULILLAHI RABBIL 'ALAMIIN, kemudian ia memutusnya, ARRAHMAANIR RAHIIM, kemudian ia memutusnya, MAALIKI YAU MUDDIN.\""},"3765":{"ar":"حَدَّثَنَا هُشَيْمُ بْنُ بَشِيرٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ سُبَيْعَةَ ابْنَةَ الْحَارِثِ وَضَعَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِعِشْرِينَ لَيْلَةً أَوْ نَحْوِ ذَلِكَ وَأَرَادَتْ التَّزْوِيجَ فَقَالَ لَهَا أَبُو السَّنَابِلِ لَيْسَ لَكِ ذَلِكَ حَتَّى يَأْتِيَ عَلَيْكِ آخِرُ الْأَجَلَيْنِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تَزَوَّجُ إِذَا شَاءَتْ","id":"Telah menceritakan kepada kami [Husyaim bin Basyir] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sulaiman bin Yasar] dari [Ummu Salamah, isteri Nabi shallaallahu 'alaihi wa sallam] bahwasanya Subai'ah binti Harits melahirkan anaknya pada hari keduapuluh setelah suaminya meninggal, setelah itu ia ingin menikah lagi. Lalu Abu Sanabil berkata kepadanya; \"Engkau tidak boleh melakukannya hingga datang dua waktu (setelah kematian dan melahirkan).\" Hal itu pun diceritakan kepada Nabi shallaallahu 'alaihi wa sallam, beliau pun bersabda: \"Suruhlah ia menikah jika mau.\""},"3766":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ ابْنِ أَبِي نَجِيحٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ أُمِّ سَلَمَةَ قَالَتْلَمَّا مَاتَ أَبُو سَلَمَةَ قُلْتُ غَرِيبٌ وَمَاتَ بِأَرْضِ غُرْبَةٍ فَأَفَضْتُ بُكَاءً فَجَاءَتْ امْرَأَةٌ تُرِيدُ أَنْ تُسْعِدَنِي مِنْ الصَّعِيدِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُرِيدِينَ أَنْ تُدْخِلِي الشَّيْطَانَ بَيْتًا قَدْ أَخْرَجَهُ اللَّهُ عَزَّ وَجَلَّ مِنْهُ قَالَتْ فَلَمْ أَبْكِ عَلَيْهِ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Abi Najih] dari [Ayahnya] dari [Ubaid bin Umair] dari [Ummu Salamah] berkata; ketika Abu Salamah meninggal, aku mengatakan seolah ia terasing dan mati di keterasingan dan aku pun menangis. Kemudian datanglah seorang wanita ingin menangis bersamaku, lantas Rasulullah shallaallahu 'alaihi wa sallam bersabda: \"Apakah engkau ingin memasukkan syetan kedalam rumah yang Allah telah keluarkan darinya, \" ia berkata; \"Aku pun tidak menangisinya lagi.\""},"3767":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حُمَيْدٍ سَمِعَ سَعِيدَ بْنَ الْمُسَيَّبِ عَنْ أُمِّ سَلَمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَتْ الْعَشْرُ فَأَرَادَ رَجُلٌ أَنْ يُضَحِّيَ فَلَا يَمَسَّ مِنْ شَعْرِهِ وَلَا مِنْ بَشَرِهِ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdurrahman bin Humaid] bahwa ia telah mendengar [Sa'id bin Musayyab] dari [Ummu Salamah] dari Nabi shallaallahu 'alaihi wa sallam: \"Apabila telah masuk hari kesepuluh Dzulhijjah, dan ada seseorang yang ingin menyembelih sembelihannya, maka janganlah ia mengambil jatah dari rambut maupun kulitnya.\""},"3768":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ ابْنِ سُوقَةَ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ أُمِّ سَلَمَةَذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَيْشَ الَّذِي يُخْسَفُ بِهِمْ فَقَالَتْ أُمُّ سَلَمَةَ لَعَلَّ فِيهِمْ الْمُكْرَهَ فَقَالَ إِنَّهُمْ يُبْعَثُونَ عَلَى نِيَّاتِهِمْ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Suqah] dari [Nafi' bin Jubair] dari [Ummu Salamah] bahwa Nabi shallaallahu 'alaihi wa sallam pernah menceritakan akan suatu pasukan yang ditenggelamkan, lalu Ummu Salamah berkata; \"Barangkali di antara mereka ada yang terpaksa?\", beliau bersabda: \"Sesungguhnya mereka akan dibangkitkan sesuai niat mereka.\""},"3769":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ سَعِيدٍ يَعْنِي الْمَقْبُرِيَّ عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ وَهُوَ مَوْلَى أُمِّ سَلَمَةَ كَذَا قَالَ سُفْيَانُ أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أَشُدُّ ضَفْرَ رَأْسِي قَالَ يُجْزِئُكِ أَنْ تَصُبِّي عَلَيْهِ الْمَاءَ ثَلَاثًا","id":"Telah menceritakan kepada kami [Sufyan] dari [Ayyub bin Musa] dari [Sa'id, yaitu Al Maqburi] dari [Abdullah bin Rofi', dia adalah bekas budak Ummu Salamah], seperti yang dikatakan Sufyan bahwasanya Ummu Salamah berkata; \"Wahai Rasulullah! sesungguhnya aku adalah seorang wanita dengan rambut terpintal.\" lalu beliau bersabda: \"Cukuplah engkau menyiram di atasnya tiga kali.\""},"3770":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَ قَالَتْ أُمُّ سَلَمَةَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ تَعْجِيلًا لِلظُّهْرِ مِنْكُمْ وَأَنْتُمْ أَشَدُّ تَعْجِيلًا لِلْعَصْرِ مِنْهُ","id":"Telah menceritakan kepada kami [Ismail bin Ibrahim] berkata; telah menceritakan kepada kami [Ibnu Juraij] dari [Abdullah bin Abi Mulaikah] berkata; [Ummu Salamah] berkata; \"Rasulullah shallaallahu 'alaihi wa sallam adalah seorang yang paling menyegerakan shalat zhuhur daripada kalian, sementara kalian lebih menyegerakan shalat Ashar daripada beliau.\""},"3771":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ قَالَسُئِلَتْ عَائِشَةُ وَأُمُّ سَلَمَةَ أَيُّ الْعَمَلِ كَانَ أَعْجَبَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ مَا دَامَ عَلَيْهِ وَإِنْ قَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Fudhail] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] berkata; [Aisyah] dan [Ummu Salamah] pernah ditanya tentang perkara apa yang paling disukai Nabi shallaallahu 'alaihi wa sallam?, ia menjawab; \"Amalan yang kontinu dilakukan walaupun sedikit.\""},"3772":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنِ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ قَالَدَخَلْتُ أَنَا وَأَبِي عَلَى عَائِشَةَ وَأُمِّ سَلَمَةَ قَالَتْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصْبِحُ وَهُوَ جُنُبٌ ثُمَّ يَصُومُ","id":"Telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Azzuhri] dari [Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] berkata; \"Saya dan ayah ku pernah menemui [Aisyah] dan [Ummu Salamah], ia berkata; 'Ketika di pagi hari, Nabi shallaallahu 'alaihi wa sallam masih dalam keadaan junub, kemudian beliau berpuasa'.\""},"3773":{"ar":"حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنِ ابْنِ عَوْنٍ عَنِ الْحَسَنِ عَنْ أُمِّهِ عَنْ أُمِّ سَلَمَةَ قَالَتْمَا نَسِيتُ قَوْلَهُ يَوْمَ الْخَنْدَقِ وَهُوَ يُعَاطِيهِمُ اللَّبَنَ وَقَدْ اغْبَرَّ شَعْرُ صَدْرِهِ وَهُوَ يَقُولُ اللَّهُمَّ إِنَّ الْخَيْرَ خَيْرُ الْآخِرَهْفَاغْفِرْ لِلْأَنْصَارِ وَالْمُهَاجِرَهْقَالَ فَرَأَى عَمَّارًا فَقَالَ وَيْحَهُ ابْنُ سُمَيَّةَ تَقْتُلُهُ الْفِئَةُ الْبَاغِيَةُقَالَ فَذَكَرْتُهُ لِمُحَمَّدٍ يَعْنِي ابْنَ سِيرِينَ فَقَالَ عَنْ أُمِّهِ قُلْتُ نَعَمْ أَمَا إِنَّهَا كَانَتْ تُخَالِطُهَا تَلِجُ عَلَيْهَا","id":"Telah menceritakan kepada kami [Ibnu Abi Adi] dari [Ibnu Aun] dari [Al Hasan] dari [Ibunya] dari [Ummu Salamah] berkata; \"Aku tidak akan pernah lupa akan do'a beliau pada perang Khandak, ketika itu beliau memberi susu kepada para sahabat, sedang bulu dadanya berdebu. Beliau berdo'a: \"ALLAHUMMA INNAL KHOIRA KHOIRUL AKHIRAH FAGHFIR LIL ANSHAR WAL MUHAJIRAH (ya Allah, sesungguhnya kebaiklan itu adalah kebaikan di akhirat, maka ampunilah orang-orang Anshor dan muhajirin) \", beliau pun lantas melihat Ammar dan bersabda: \"Celakalah ibnu Sumayyah, ia akan dibunuh oleh sekelompok pemberontak, \" ia berkata; \"Aku pun menceritakannya kepada Muhammad, yakni Ibnu Sirin, ia berkata dari ibunya; aku berkata; 'Ya.', hanya saja ia mencampurnya dan memasukinya (dengan kata tambahan)."},"3774":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ مَهْدِيٍّ : مَالِكٌ عَنْ سُمَيٍّ وَعَبْدِ رَبِّهِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ وَأُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصْبِحُ جُنُبًا مِنْ جِمَاعٍ غَيْرِ احْتِلَامٍ ثُمَّ يَصُومُوَفِي حَدِيثِ عَبْدِ رَبِّهِ فِي رَمَضَانَ","id":"Telah menceritakan kepada kami [Abdurrahman, yaitu Ibnu Mahdi], [Malik] dari [Summi] dan [Abdu Rabih] dari [Abu Bakr bin Abdurrahman] dari [Aisyah] dan [Ummu Salamah] bahwa ketika di pagi hari Rasulullah shallaallahu 'alaihi wa sallam masih dalam keadaan junub karena jima', bukan karena bermimpi, lalu beliau berpuasa. Dalam hadits Abdurrabih (diriwayatkan), \"Di bulan Ramadhan.\""},"3775":{"ar":"حَدَّثَنَا حَجَّاجٌ وَحَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَا أَنَا ابْنُ أَبِي ذِئْبٍ وَإِسْحَاقُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ ابْنَ أَبِي ذِئْبٍ عَنْ صَالِحٍ مَوْلَى التَّوْأَمَةِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِنِسَائِهِ عَامَ حَجَّةِ الْوَدَاعِ هَذِهِ ثُمَّ ظُهُورَ الْحُصْرِ قَالَ فَكُنَّ كُلُّهُنَّ يَحْجُجْنَ إِلَّا زَيْنَبَ بِنْتَ جَحْشٍ وَسَوْدَةَ بِنْتَ زَمْعَةَ وَكَانَتَا تَقُولَانِ وَاللَّهِ لَا تُحَرِّكُنَا دَابَّةٌ بَعْدَ أَنْ سَمِعْنَا ذَلِكَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِسْحَاقُ بْنُ سُلَيْمَانَ فِي حَدِيثِهِ قَالَتَا وَاللَّهِ لَا تُحَرِّكُنَا دَابَّةٌ بَعْدَ قَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ ثُمَّ ظُهُورَ الْحُصْرِ وَقَالَ يَزِيدُ بَعْدَ أَنْ سَمِعْنَا ذَلِكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hajjaj] dan telah menceritakan kepada kami [Yazid bin Harun] keduanya berkata, telah memberitakan kepada kami [Ibnu Abu Dzi'b] dan [Ishaq bin Sulaiman] berkata, aku mendengar dari [Ibnu Abu Dzi'b] dari [Shalih] budak At Tauamah, dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada para isterinya pada haji Wada': \"Ini (haji yang terakhir), kemudian menetap tinggal di rumah.\" Ketika itu mereka semua melaksanakan haji, kecuali Zainab binti Jahsy dan Saudah binti Zam'ah, keduanya berkata, \"Demi Allah, tunggangan kami tidak bergerak (untuk membawa kami pergi) setelah kami mendengar hal itu dari Rasulullah shallallahu 'alaihi wasallam.\" [Ishaq bin Sulaiman] menyebutkan dalam haditsnya, \"Keduanya berkata, \"Demi Allah, tunggangan kami tidak bergerak (untuk membawa kami pergi) setelah sabda Rasulullah shallallahu 'alaihi wasallam 'Ini (haji yang terakhir) kemudian menetap tinggal di rumah'.\" [Yazid] menyebutkan, \"Setelah kami mendengar itu dari Rasulullah shallallahu 'alaihi wasallam.\""},"3776":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ عُمَرَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ جَحْشٍأَنَّهَا كَانَتْ تُرَجِّلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَتْ مَرَّةً كُنْتُ أُرَجِّلُ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مِخْضَبٍ مِنْ صُفْرٍ","id":"Telah menceritakan kepada kami [Hammad bin Khalid] berkata telah menceritakan kepada kami ['Ubaidullah] -yakni Ibnu 'Umar- dari [Ibrahim bin Muhammad] dari [Bapaknya] dari [Zainab binti Jahsy] bahwa dia pernah menyisir rambut Rasulullah shallallahu 'alaihi wasallam, ia pernah berkata, \"Aku pernah menyisir rambut Rasulullah shallallahu 'alaihi wasallam di dalam bejana yang terbuat dari kuningan.\""},"3777":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ قَالَ حَدَّثَنَا الدَّرَاوَرْدِيُّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ زَيْنَبَ بِنْتِ جَحْشٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَوَضَّأُ فِي مِخْضَبٍ مِنْ صُفْرٍ","id":"Telah menceritakan kepada kami ['Ali bin Bahr] berkata, telah menceritakan kepada kami [Ad Darawardi] berkata, telah mengabarkan kepada kami ['Ubaidullah bin 'Umar] dari [Muhammad bin Ibrahim] dari [Zainab binti Jahsy], bahwa Rasulullah shallallahu 'alaihi wasallam berwudlu dari bejana yang terbuat dari kuningan.\""},"3778":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ حُمَيْدِ بْنِ نَافِعٍ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُأَنَّهَا دَخَلَتْ عَلَى زَيْنَبَ بِنْتِ جَحْشٍ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَقُولُ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثِ لَيَالٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami berkata [Abdurrazaq] berkata, telah mengabarkan kepada kami [Malik] dari [Abdullah bin Abu Bakar] dari [Humaid bin Nafi'] bahwa [Zainab binti Abu Salamah] mengabarkan kepadanya, bahwa ia menemui [Zainab binti Jahsy], isteri Nabi shallallahu 'alaihi wasallam, lalu ia berkata, \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar: \"Tidaklah halal bagi seorang Muslimah yang beriman kepada Allah dan Hari Akhir untuk melakukan tahdid (meninggalkan hias dan perhiasan) karena kematian lebih dari tiga malam, kecuali karena kematian suami yaitu selama empat bulan sepuluh hari.\""},"3779":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي أَيُّوبَ الْهَجَرِيِّ عَنْ جُوَيْرِيَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى جُوَيْرِيَةَ فِي يَوْمِ جُمُعَةٍ وَهِيَ صَائِمَةٌ فَقَالَ لَهَا أَصُمْتِ أَمْسِ قَالَتْ لَا قَالَ تَصُومِينَ غَدًا قَالَتْ لَا قَالَ فَأَفْطِرِي","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Ayyub Al Hajary] dari [Juwairiyah] bahwa Rasulullah shallallahu 'alaihi wasallam menemui Juwairiyah pada hari Jum'at, ketika itu dia sedang berpuasa, kemudian beliau bersabda kepadanya: \"Apakah kamu kemarin berpuasa?\" dia menjawab, \"Tidak.\" Beliau bersabda: \"Apakah kamu besok hendak berpuasa?\" dia menjawab, \"Tidak.\" Beliau bersabda: \"Berbukalah sekarang.\""},"3780":{"ar":"حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَبِي أَيُّوبَ عَنْ جُوَيْرِيَةَ بِنْتِ الْحَارِثِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَهِيَ صَائِمَةٌ فَقَالَ أَصُمْتِ أَمْسِ فَقَالَتْ لَا قَالَ أَتُرِيدِينَ أَنْ تَصُومِي غَدًا قَالَتْ لَا قَالَ فَأَفْطِرِي","id":"Telah menceritakan kepada kami [Bahs] berkata, telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Abu Ayyub] dari [Juwairiyyah binti Al Harits] bahwa Nabi shallallahu 'alaihi wasallam menemuinya saat ia sedang berpuasa, kemudian beliau bersabda: \"Apakah kamu kemarin berpuasa?\" ia menjawab, \"Tidak.\" Beliau bersabda: \"Apakah kamu besok hendak berpuasa?\" ia menjawab, \"Tidak.\" Beliau bersabda: \"Berbukalah sekarang.\""},"3781":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شَرِيكٌ عَنْ جَابِرٍ عَنْ خَالَتِهِ أُمِّ عُثْمَانَ عَنْ الطُّفَيْلِ ابْنِ أَخِي جُوَيْرِيَةَ عَنْ جُوَيْرِيَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَبِسَ ثَوْبَ حَرِيرٍ أَلْبَسَهُ اللَّهُ ثَوْبًا مِنْ النَّارِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Syarik] dari [Jabir] dari bibinya [Ummi 'Ustman] dari [Thufail] anak laki-laki dari saudaranya Juwairiyah, dari [Juwairiyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengenakan pakaian sutra, maka Allah akan mengenakan pakaian untuknya dari api neraka pada hari kiamat.\""},"3782":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى آلِ طَلْحَةَ قَالَ سَمِعْتُ كُرَيْبًا مَوْلَى ابْنِ عَبَّاسٍ يُحَدِّثُ عَنِ ابْنِ عَبَّاسٍ عَنْ جُوَيْرِيَةَ بِنْتِ الْحَارِثِ قَالَتْأَتَى عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُدْوَةً وَأَنَا أُسَبِّحُ ثُمَّ انْطَلَقَ لِحَاجَةٍ ثُمَّ رَجَعَ قَرِيبًا مِنْ نِصْفِ النَّهَارِ فَقَالَ مَا زِلْتِ قَاعِدَةً قُلْتُ نَعَمْ فَقَالَ أَلَا أُعَلِّمُكِ كَلِمَاتٍ لَوْ عُدِلْنَ بِهِنَّ عَدَلَتْهُنَّ أَوْ لَوْ وُزِنَّ بِهِنَّ وَزَنَتْهُنَّ يَعْنِي بِجَمِيعِ مَا سَبَّحَتْ سُبْحَانَ اللَّهِ عَدَدَ خَلْقِهِ ثَلَاثَ مَرَّاتٍ سُبْحَانَ اللَّهِ زِنَةَ عَرْشِهِ ثَلَاثَ مَرَّاتٍ سُبْحَانَ اللَّهِ رِضَا نَفْسِهِ ثَلَاثَ مَرَّاتٍ سُبْحَانَ اللَّهِ مِدَادَ كَلِمَاتِهِ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami Hajjaj telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin 'Abdurrahman] bekas budak keluarga Thalhah, ia berkata; aku mendengar [Kuraib] budak Ibnu Abbas, menceritakan dari [Ibnu Abbas] dari [Juwairiyah binti Al Harits] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemuiku waktu Shubuh, ketika itu aku sedang bertasbih, kemudian beliau pergi untuk suatu keperluan dan kembali lagi sebelum pertengahan siang, beliau bersabda: \"Masihkah kamu duduk (bertasbih)?\" aku menjawab, \"Ya.\" Beliau lalu bersabda: \"Maukah kamu aku ajari beberapa kalimat jika ia diseimbangkan dengannya maka ia akan seimbang, atau jika ia ditimbang maka ia akan sama timbangannya, yakni dengan semua yang kamu tasbihkan; SUBHAANALLAH 'ADADA KHALQIHI (Maha suci Allah sejumlah hitungan makhluk-Nya) tiga kali, SUBHAANALLAH ZINATA 'ARSYIHI (Maha Suci Allah menurut kebesaran Arsy-Nya) tiga kali, SUBHAANALLAH RILHA NAFSIHI (Maha Suci Allah menurut keridlaan-Nya) tiga kali, dan SUBHAANALLAH MIDADA KALIMATIHI (Maha Suci Allah sebanyak paparan kalimat-Nya) tiga kali.\""},"3783":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ يَحْيَى بْنِ أَبِي إِسْحَاقَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍأَنَّ عُمَرَ بْنَ الْخَطَّابِ وَجَدَ رِيحَ طِيبٍ بِذِي الْحُلَيْفَةِ فَقَالَ مِمَّنْ هَذِهِ الرِّيحُ فَقَالَ مُعَاوِيَةُ مِنِّي يَا أَمِيرَ الْمُؤْمِنِينَ فَقَالَ مِنْكَ لِعَمْرِي فَقَالَ طَيَّبَتْنِي أُمُّ حَبِيبَةَ وَزَعَمَتْ أَنَّهَا طَيَّبَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ إِحْرَامِهِ فَقَالَ اذْهَبْ فَأَقْسِمْ عَلَيْهَا لَمَا غَسَلَتْهُ فَرَجَعَ إِلَيْهَا فَغَسَلَتْهُ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Hammad] -yakni Ibnu Salamah- dari [Yahya bin Abu Ishaq] dari [Sulaiman bin Yasar] bahwa 'Umar bin Khattab mencium bau harum di Dzul Hulaifah, lalu dia berkata, \"Dari manakah bau harum ini?\" Mu'awiyah menjawab, \"Dariku wahai Amirul Mukminin.\" Umar berkata, \"Darimu untuk umrahku?\" lalu dia berkata, \" [Ummi Habibah] yang telah memberikan parfum ini dan dia mengatakan bahwa ia pernah memberikan kepada Rasulullah shallallahu 'alaihi wasallam ketika beliau ihram.\" Umar berkata, \"Pergi dan suruhlah ia mencuci.\" Maka Mu'awiyah kembali menemui Ummu Habibah, hingga ia pun mencucinya.\""},"3784":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنِ ابْنِ إِسْحَاقَ عَنِ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ عَنْ مُعَاوِيَةَ قَالَقُلْتُ لِأُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي الثَّوْبِ الَّذِي يَنَامُ مَعَكِ فِيهِ قَالَتْ نَعَمْ مَا لَمْ يَرَ فِيهِ أَذًى","id":"Telah menceritakan kepada kami [Muhammad bin Salamah] dari [Ibnu Ishaq] dari [Yazid bin Abu Habib] dari [Suwaid bin Qais] dari [Mu'awiyah bin Hudaij] dari [Mu'awiyah] dia berkata, \"Aku berkata kepada [Ummi Habibah] isteri Nabi shallallahu 'alaihi wasallam, \"Apakah dulu Rasulullah shallallahu 'alaihi wasallam pernah shalat dengan pakaian yang dikenakannya ketika tidur bersamamu?\" Dia menjawab, \"Ya. Jika beliau tidak melihat ada kotoran padanya.\""},"3785":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ قَالَ حَدَّثَنَا ضَمْرَةُ بْنُ حَبِيبٍ أَنَّ مُحَمَّدَ بْنَ أَبِي سُفْيَانَ الثَّقَفِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ أُمَّ حَبِيبَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَعَلَيَّ وَعَلَيْهِ ثَوْبٌ وَاحِدٌ فِيهِ كَانَ مَا كَانَ","id":"Telah menceritakan kepada kami [Zaid bin Khubab] berkata, telah menceritakan kepada kami [Mu'awiyah bin Shalih] berkata, telah menceritakan kepada kami [Dlamrah bin Habib] bahwa [Muhammad bin Abu Sufyan At Tsaqafi] menceritakan kepadanya, bahwa dirinya mendengar [Ummu Habibah] isteri Nabi shallallahu 'alaihi wasallam berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam shalat dengan tetap memakai pakaian yang dipakai waktu bersamaku.\""},"3786":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ طَلْحَةَ بْنِ يَزِيدَ بْنِ رُكَانَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِي الْجَرَّاحِ مَوْلَى أُمِّ حَبِيبَةَ عَنْ أُمِّ حَبِيبَةَ أَنَّهَا حَدَّثَتْهُ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ كَمَا يَتَوَضَّئُونَ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Muhammad bin Thalhah bin Yazid bin Rukanah] dari [Salim bin Abdullah bin Umar] dari [Abu Al Jarrah] bekas budak Ummu Habibah, dari [Ummi Habibah] dia mengabarkan kepadanya, dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya aku tidak memberatkan umatku niscaya akan aku perintahkan mereka memakai siwak setiap akan shalat sebagaimana mereka berwudlu.\""},"3787":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ قَالَلَمَّا نَزَلَ عَنْبَسَةَ بْنَ أَبِي سُفْيَانَ الْمَوْتُ اشْتَدَّ جَزَعُهُ فَقِيلَ لَهُ مَا هَذَا الْجَزَعُ قَالَ إِنِّي سَمِعْتُ أُمَّ حَبِيبَةَ يَعْنِي أُخْتَهُ تَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى أَرْبَعًا قَبْلَ الظُّهْرِ وَأَرْبَعًا بَعْدَهَا حَرَّمَ اللَّهُ لَحْمَهُ عَلَى النَّارِ فَمَا تَرَكْتُهُنَّ مُنْذُ سَمِعْتُهُنَّ","id":"Telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Hasan bin 'Athiyah] dia berkata, \"Ketika ['Anbasyah bin Abu Sufyan] mendekati ajalnya, kegelisahannya semakin menjadi-jadi, lalu dikatakan kepadanya, \"Kegelisahan apa ini?\" dia menjawab, \"Aku mendengar [Ummu Habibah], yakni saudara perempuannya, berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa shalat empat rakaat sebelum zhuhur dan empat rakaat setelahnya, maka Allah akan haramkan dagingnya dari api neraka.' Oleh karena itu aku tidak pernah lagi meninggalkannya semenjak aku mendengarnya.\""},"3788":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ قَالَ حَدَّثَنِي شُعْبَةُ عَنْ حُمَيْدِ بْنِ نَافِعٍ قَالَ سَمِعْتُ زَيْنَبَ بِنْتَ أُمِّ سَلَمَةَ قَالَتْتُوُفِّيَ حَمِيمٌ لِأُمِّ حَبِيبَةَ فَدَعَتْ بِصُفْرَةٍ فَمَسَحَتْ بِذِرَاعَيْهَا وَقَالَتْ إِنَّمَا أَصْنَعُ هَذَا لِشَيْءٍ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ حَجَّاجٌ لِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ مُسْلِمَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُحِدَّ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجِهَا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًاوَحَدَّثَتْهُ زَيْنَبُ عَنْ أُمِّهَا وَعَنْ زَيْنَبَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ عَنِ امْرَأَةٍ مِنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dan [Hajjaj] berkata, telah menceritakan kepadaku [Syu'bah] dari [Humaid bin Nafi'] berkata, aku mendengar [Zainab binti Abu Salamah] berkata, \"Sewaktu kerabat dekatnya [Ummu Habibah] meninggal, maka dia meminta bejana yang terbuat dari wewangian, kemudian dia mengusap kedua sikunya dan berkata, \"Aku melakukan seperti ini karena sesuatu yang pernah aku dengar dari Rasulullah shallallahu 'alaihi wasallam.\" [Hajjaaj] berkata, \"Sebab Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita Muslimah yang beriman dengan Allah dan hari akhir melakukan tahdid (tidak berhias) melebihi tiga hari kecuali karena kematian suaminya, yakni selama empat bulan sepuluh hari.\" Dan [Zainab] telah menceritakan kepadanya dari [Ibunya], dan dari [Zainab] isteri Nabi shallallahu 'alaihi wasallam, atau seorang wanita dari isteri - isteri Nabi shallallahu 'alaihi wasallam.\""},"3789":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ أَبِي الْمَلِيحِ عَنْ أُمِّ حَبِيبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا سَمِعَ الْمُؤَذِّنَ يُؤَذِّنُ قَالَ كَمَا يَقُولُ حَتَّى يَسْكُتَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Abu Al Malih] dari [Ummu Habibah] dari Nabi shallallahu 'alaihi wasallam, bahwa jika beliau mendengar muadzin mengumandangkan adzan, maka beliau mengatakan seperti apa yang dikatakannya hingga selesai adzan.\""},"3790":{"ar":"حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنْ أَبِي صَالِحٍ أَنَّ أُمَّ حَبِيبَةَ حَدَّثَتْعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ صَلَّى فِي يَوْمٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً بَنَى اللَّهُ لَهُ أَوْ بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Bahs] berkata, telah menceritakan kepada kami [Hammad bin Yazid] berkata, telah menceritakan kepada kami ['Ashim bin Bahdalah] dari [Abu Shalih] bahwa [Ummu Habibah] berkata dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa shalat dua belas rakaat dalam sehari, maka Allah akan membangun untuknya atau dibangunkan untuknya sebuah rumah di surga.\""},"3791":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ قَالَ نَافِعٌ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ أَبَا الْجَرَّاحِ مَوْلَى أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَ عَبْدَ اللَّهِ بْنَ عُمَرَ أَنَّ أُمَّ حَبِيبَةَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعِيرَ الَّتِي فِيهَا الْجَرَسُ لَا تَصْحَبُهَا الْمَلَائِكَةُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] berkata, telah menceritakan kepada kami [Syu'aib] berkata, [Nafi'] berkata, telah mengabarkan kepadaku [Salim bin Abdullah bin Umar] bahwa [Abu Jarah] bekas budak Ummu Habibah, isteri Nabi shallallahu 'alaihi wasallam, berkata kepada Abdullah bin 'Umar bahwa [Ummu Habibah] mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya malaikat tidak akan menyertai rombongan musafir yang terdapat lonceng pada mereka.\""},"3792":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ سَمِعْتُهُ يُحَدِّثُ يَعْنِي أَبَاهُ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ أُسَامَةَ بْنِ الْهَادِ أَنَّ سَالِمَ بْنَ عَبْدِ اللَّهِ بْنِ عُمَرَ حَدَّثَهُ أَنَّ أَبَا الْجَرَّاحِ مَوْلَى أُمِّ حَبِيبَةَ أَخْبَرَهُ أَنَّ أُمَّ حَبِيبَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصْحَبُ الْمَلَائِكَةُ قَوْمًا فِيهِمْ جَرَسٌ","id":"Telah menceritakan kepada kami [Ya'qub] berkata, aku mendengarnya menceritakan, yakni [bapaknya] dari [Yazid bin Abdullah bin Usamah bin Al Hadi] bahwa [Salim bin Abdullah bin Umar] telah menceritakan kepadanya, bahwa [Abu Al Jarrah] budak Ummu Habibah, telah mengabarkan kepadanya bahwa [Ummu Habibah] isteri Nabi shallallahu 'alaihi wasallam menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malaikat tidak akan menyertai kaum yang terdapat lonceng di dalamnya.\""},"3793":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا مَالِكٌ وَإِسْحَاقُ بْنُ عِيسَى قَالَ أَخْبَرَنِي مَالِكٌ قَالَ عَبْد اللَّهِ و حَدَّثَنَا مُصْعَبٌ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ وَمُجَمِّعٍ ابْنَيْ يَزِيدَ ابْنِ جَارِيَةَ عَنْ خَنْسَاءَ بِنْتِ خِذَامٍأَنَّ أَبَاهَا زَوَّجَهَا وَهِيَ كَارِهَةٌ وَكَانَتْ ثَيِّبًا فَرَدَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِكَاحَهُ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Malik] dan [Ishak bin 'Isa] berkata, telah mengabarkan kepada kami [Malik] berkata Abdullah, dan telah menceritakan kepada kami [Mush'ab] berkata, telah mengabarkan kepada kami [Malik] dari ['Abdurrahman bin Qasim] dari [Bapaknya] dari ['Abdurrahman] dan [Mujammi' bin Yazid bin Jariyah] dari [Khansa' binti Khidam], bahwa ayahnya telah menikahkan dirinya padahal ia tidak mau -dia adalah seorang janda-, maka Nabi shallallahu 'alaihi wasallam pun membatalkan pernikahan tersebut.\""},"3794":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَحْيَى يَعْنِي ابْنَ سَعِيدٍ قَالَ حَدَّثَنَا الْقَاسِمُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ وَمُجَمِّعٍ شَيْخَيْنِ مِنْ الْأَنْصَارِأَنَّ خَنْسَاءَ أَنْكَحَهَا أَبُوهَا وَكَرِهَتْ ذَلِكَ فَرَدَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Yahya] -yakni Ibnu Sa'id- berkata, telah menceritakan kepada kami [Al Qasim] dari ['Abdurrahman bin Yazid] dan [Mujammi'] dua orang Syaikh kaum Anshar, bahwa Khansa' dinikahkan oleh bapaknya akan tetapi dia membencinya, maka Rasulullah shallallahu 'alaihi wasallam membatalkan pernikahan tersebut.\""},"3795":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَنِ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ مُجَمِّعِ بْنِ يَزِيدَ عَنْ أُمِّ مُجَمِّعٍقَالَ زَوَّجَ خِدَامٌ ابْنَتَهُ وَهِيَ كَارِهَةٌ فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبِي زَوَّجَنِي وَأَنَا كَارِهَةٌ قَالَ فَرَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِكَاحَ أَبِيهَا","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami dari [Al Qasim bin Muhammad] dari [Mujammi' bin Yazid] dari [Ummu Mujammi'] ia berkata, \"Khidam menikahkan anak perempuannya, sementara anaknya tidak menyukai pernikahan tersebut, maka dia menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, bapakku telah menikahkan aku padahal aku membencinya?\" Mujammi' berkata, \"Rasulullah shallallahu 'alaihi wasallam kemudian membatalkan pernikahan tersebut.\""},"3796":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنِ الْقَاسِمِ بْنِ مُحَمَّدٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ الْأَنْصَارِيَّ وَمُجَمِّعَ بْنَ يَزِيدَ الْأَنْصَارِيَّ أَخْبَرَاهُأَنَّ رَجُلًا مِنْهُمْ يُدْعَى خِذَامًا أَنْكَحَ ابْنَةً لَهُ فَكَرِهَتْ نِكَاحَ أَبِيهَا فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَرَدَّ عَنْهَا نِكَاحَ أَبِيهَا فَتَزَوَّجَتْ أَبَا لُبَابَةَ بْنَ عَبْدِ الْمُنْذِرِفَذَكَرَ يَحْيَى أَنَّهُ بَلَغَهُ أَنَّهَا كَانَتْ ثَيِّبًا","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Al Qasim bin Muhammad] bahwa ['Abdurrahman bin Yazid Al Anshari] dan [Mujamma' bin Yazid Al Anshari] mengabarkan kepadanya, bahwa seorang laki-laki dari mereka yang biasa dipanggil Khidzam, telah menikahkan anak perempuannya, sementara anaknya tidak menyetujui pernikahan yang ditentukan oleh bapaknya tersebut, kemudian dia (anak perempuan) menemui Nabi shallallahu 'alaihi wasallam dan menceritakan kejadiannya kepada beliau, maka beliau mengembalikan pernikahan yang di lakukan oleh bapaknya kepada dirinya, kemudian ia menikah dengan Abu Lubabah bin Mundzir.\" Yahya menyebutkan bahwa telah sampai kepadanya, bahwa dia (anak perempuan) adalah seorang janda.\""},"3797":{"ar":"قَالَ قَرَأْتُ عَل��ى يَعْقُوبَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي حَجَّاجُ بْنُ السَّائِبِ بْنِ أَبِي لُبَابَةَ بْنِ عَبْدِ الْمُنْذِرِ الْأَنْصَارِيُّ أَنَّ جَدَّتَهُ أُمَّ السَّائِبِ خُنَاسَ بِنْتِ خِذَامِ بْنِ خَالِدٍكَانَتْ عِنْدَ رَجُلٍ قَبْلَ أَبِي لُبَابَةَ تَأَيَّمَتْ مِنْهُ فَزَوَّجَهَا أَبُوهَا خِذَامُ بْنُ خَالِدٍ رَجُلًا مِنْ بَنِي عَمْرِو بْنِ عَوْفِ بْنِ الْخَزْرَجِ فَأَبَتْ إِلَّا أَنْ تَحُطَّ إِلَى أَبِي لُبَابَةَ وَأَبَى أَبُوهَا إِلَّا أَنْ يُلْزِمَهَا الْعَوْفِيَّ حَتَّى ارْتَفَعَ أَمْرُهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ أَوْلَى بِأَمْرِهَا فَأَلْحِقْهَا بِهَوَاهَا قَالَ فَانْتُزِعَتْ مِنْ الْعَوْفِيِّ وَتَزَوَّجَتْ أَبَا لُبَابَةَ فَوَلَدَتْ لَهُ أَبَا السَّائِبِ بْنَ أَبِي لُبَابَةَ","id":"Berkata aku membaca kepada [Ya'kub bin Ibrahim] berkata, telah menceritakan kepada kami [Bapakku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Hajjaj bin As Saib bin Abu Lubabah bin Abdul Mundzir Al Anshari] bahwa neneknya, ibu As Saib, Khunnas binti Khidzam bin Khalid, pernah menjadi isteri seseorang sebelum menikah dengan Abu Lubabah. Ketika ia menjadi janda, bapaknya, Khidam bin Khalid, menikahkah dirinya dengan seorang laki-laki dari bani Amru bin 'Auf bin Al Khazraj, tetapi dia enggan menerimanya dan menetapkan (pilihannya) kepada Abu Lubabah, sedangkan bapaknya enggan dan mengharuskannya untuk tetap dengan Al Aufi, sehingga persoalannya sampai kepada Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Sesungguhnya dia (anak perempuan Khidam) lebih berhak dengan urusannya, maka biarkanlah dia menetapkan pilihannya sendiri.\" Perempuan itu kemudian menikah dengan Abu Lubabah dan melahirkan Abu Saib bin Abu Lubabah.\""},"3798":{"ar":"قَالَ قَرَأْتُ عَلَى أَبِي : يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ إِسْحَاقَ عَنِ الْحَجَّاجِ بْنِ السَّائِبِ بْنِ أَبِي لُبَابَةَ قَالَكَانَتْ خُنَاسُ بِنْتُ خِذَامٍ عِنْدَ رَجُلٍ تَأَيَّمَتْ مِنْهُ فَزَوَّجَهَا أَبُوهَا رَجُلًا مِنْ بَنِي عَوْفٍ وَحَطَّتْ هِيَ إِلَى أَبِي لُبَابَةَ فَأَبَى أَبُوهَا إِلَّا أَنْ يُلْزِمَهَا الْعَوْفِيَّ وَأَبَتْ هِيَ حَتَّى ارْتَفَعَ شَأْنُهُمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هِيَ أَوْلَى بِأَمْرِهَا فَأَلْحِقْهَا بِهَوَاهَا فَتَزَوَّجَتْ أَبَا لُبَابَةَ فَوَلَدَتْ لَهُ أَبَا السَّائِبِ","id":"Abdullah berkata; aku membacanya di hadapan bapakku; [Yazid bin Harun] berkata, telah menceritakan kepada kami [Muhammad] -yakni Ibnu Ishaq- dari [Al Hajjaj bin As Saib bin Abu Lubabah] berkata, \"Khunas binti Khidam adalah isteri dari seorang laki-laki lalu ia menjanda, bapaknya kemudian ingin menikahkannya dengan seorang laki-laki dari bani Auf, akan tetapi dia lebih memilih Abu Lubabah, sedangkan bapaknya enggan dan mengharuskannya untuk tetap dengan Al Aufi, sehingga persoalannya sampai kepada Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Sesungguhnya dia (anak perempuan Khidam) lebih berhak dengan urusannya, maka biarkanlah dia menetapkan pilihannya sendiri.\" Perempuan itu kemudian menikah dengan Abu Lubabah dan melahirkan Abu Saib bin Abu Lubabah.\""},"3799":{"ar":"حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا لَيْثٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ يَزِيدَ يَعْنِي ابْنَ حَبِيبٍ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ طَلْحَةَ بْنِ يَزِيدَ بْنِ رُكَانَةَ أَنَّ خَالَتَهُ أُخْتَ مَسْعُودِ ابْنِ الْعَجْمَاءِ حَدَّثَتْهُأَنَّ أَبَاهَا قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَخْزُومِيَّةِ الَّتِي سَرَقَتْ قَطِيفَةً نَفْدِيهَا بِأَرْبَعِينَ أُوقِيَّةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ تَطَّهَّرَ خَيْرٌ لَهَا فَأَمَرَ بِهَا فَقُطِعَتْ يَدُهَا وَهِيَ مِنْ بَنِي عَبْدِ الْأَشْهَلِ أَوْ مِنْ بَنِي عَبْدِ الْأَسَدِ","id":"Telah menceritakan kepada kami [Yunus] berkata, telah menceritakan kepada kami [Laits] dari [Yahya bin Sa'id] dari [Yazid] -yakni Ibnu Habib- dari [Muhammad bin Ishaq] dari [Muhammad bin Thalhah bin Yazid bin Rukanah] bahwa bibinya [Saudari Mas'ud bin 'Ajm`a] mengabarkan kepadanya, bahwa ayahnya berkata kepada Rasulullah shallallahu 'alaihi wasallam tentang seorang wanita Makhzumi yang mencuri pakaian beludru, yang kemudian tebusannya kami bayar dengan uang senilai empat puluh Auqiyah (1 auqiyah=40 dirham), kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika hal itu dibersihkan maka akan lebih baik baginya, \" lalu beliau memerintah agar tangannya dipotong, dia adalah dari golongan bani 'Abdil Asyhal atau dari Bani Asad."},"3800":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ قَالَ حَدَّثَنَا يُوسُفُ بْنُ الْمَاجِشُونِ عَنْ أَبِيهِ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ جَدَّتِهِ رُمَيْثَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَلَوْ أَشَاءُ أَنْ أُقَبِّلَ الْخَاتَمَ الَّذِي بَيْنَ كَتِفَيْهِ مِنْ قُرْبِي مِنْهُ لَفَعَلْتُ يَقُولُ اهْتَزَّ لَهُ عَرْشُ الرَّحْمَنِ تَبَارَكَ وَتَعَالَى يُرِيدُ سَعْدَ بْنَ مُعَاذٍ يَوْمَ تُوُفِّيَحَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ قَالَ حَدَّثَنَا يُوسُفُ بْنُ الْمَاجِشُونِ قَالَ أَخْبَرَنِي أَبِي عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ الظَّفَرِيِّ عَنْ جَدَّتِهِ رُمَيْثَةَ قَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Abu Al Abbas] berkata, telah menceritakan kepada kami [Yusuf bin Al Majisyun] dari [Bapaknya] dari ['Ashim bin 'Umar bin Qatadah] dari neneknya [Rumaitsah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika aku ingin cium stempel (tanda) yang berada pada kedua pundaknya karena kedekatannya denganku, maka aku akan melakukannya.\" Beliau melanjutkan: \"Saat kematiannya -maksudnya adalah Sa'd bin Mu'adz- Arsy Ar Rahman Tabaaraka wa Ta'ala bergetar karenanya.\" Telah menceritakan kepada kami [Sulaiman bin Dawud Al Hasyimi] berkata, telah menceritakan kepada kami [Yusuf bin Majisyun] berkata, telah mengabarkan kepadaku [ayahku] dari ['Ashim bin Umar bin Qatadah Azh Zhafari] dari neneknya [Rumaitsah] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam, lalu dia menyebutkan yang semisal dengannya.\""},"3801":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ فَأْرَةً وَقَعَتْ فِي سَمْنٍ فَمَاتَتْ فَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خُذُوهَا وَمَا حَوْلَهَا فَأَلْقُوهُ وَكُلُوهُ","id":"Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah] dari [Ibnu Abbas] dari [Maimunah] bahwa seekor tikus terjatuh pada minyak samin lalu mati di dalamnya, kemudian Rasulullah shallallahu 'alaihi wasallam ditanya akan hal itu, maka beliau bersabda: \"Ambillah ia dan apa yang ada di sekitarnya, lalu buanglah kemudian makanlah minyak tersebut.\""},"3802":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الشَّعْثَاءِ جَابِرٍ يَعْنِي ابْنَ زَيْدٍ عَنِ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Amru bin dinar] dari [Abu Asy Sya'tsa' Jabir] -yakni Ibnu Zaid- dari [Ibnu Abbas] dari [Maimunah] dia berkata, \"Aku dan Rasulullah shallallahu 'alaihi wasallam mandi bersama dari satu bejana.\""},"3803":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنِ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ بِنْتِ الْحَارِثِ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ يَبْدَأُ فَيَغْسِلُ يَدَيْهِ ثُمَّ يُفْرِغُ بِيَمِينِهِ عَلَى شِمَالِهِ فَيَغْسِلُ فَرْجَهُ ثُمَّ يَضْرِبُ يَدَهُ عَلَى الْأَرْضِ فَيَمْسَحُهَا ثُمَّ يَغْسِلُهَا ثُمَّ يَتَوَضَّأُ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ يُفْرِغُ عَلَى رَأْسِهِ وَعَلَى سَائِرِ جَسَدِهِ ثُمَّ يَتَنَحَّى فَيَغْسِلُ رِجْلَيْهِحَدَّثَنَا وَكِيعٌ عَنِ الْأَعْمَشِ قَالَ عَبْد اللَّهِ و حَدَّثَنِي أَبُو الرَّبِيعِ قَالَ حَدَّثَنَا وَكِيعٌ عَنِ الْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنِ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [Kuraib] dari [Ibnu Abbas] dari [Maimunah binti Al Harist] dia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam mandi karena junub, maka beliau memulai dari mencuci tangannya kemudian mengalirkan air dari kanannya ke bagian kirinya. Kemudian beliau mencuci kemaluannya, lalu memukulkan tangannya ke atas tanah dan mengusapnya lalu mencucinya. Kemudian beliau berwudlu sebagaimana wudlu untuk shalat, lalu mengalirkan air di atas kepalanya dan seluruh badannya, kemudian beliau berpindah tempat dan mencuci kakinya.\" Telah menceritakan kepada kami [Waki'] dari [Al A'masy]. Abdullah berkata; telah menceritakan kepada kami [Abu Ar Rabi'] berkata; telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Salim bin Abu Ja'd] dari [Kuraib] dari [Ibnu Abbas] dari [Maimunah] dari Nabi shallallahu 'alaihi wasallam seperti itu.\""},"3804":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ أَخْبَرَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنِ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ بِفَضْلِ غُسْلِهَا مِنْ الْجَنَابَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Abu Daud At Thayalisi] berkata, telah mengabarkan kepada kami [Syarik] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] dari [Maimunah], bahwa Nabi shallallahu 'alaihi wasallam berwudlu dengan air sisa mandi junub Maimunah.\""},"3805":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنِ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْأَجْنَبْتُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاغْتَسَلْتُ مِنْ جَفْنَةٍ فَفَضَلَتْ فَضْلَةٌ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَغْتَسِلَ مِنْهَا فَقُلْتُ إِنِّي قَدْ اغْتَسَلْتُ مِنْهَا فَقَالَ إِنَّ الْمَاءَ لَيْسَ عَلَيْهِ جَنَابَةٌ أَوْ لَا يُنَجِّسُهُ شَيْءٌ فَاغْتَسَلَ مِنْهُ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] berkata, telah menceritakan kepada kami [Syarik] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] dari [Maimunah] isteri Nabi shallallahu 'alaihi wasallam, dia berkata, \"Aku dan Rasulullah shallallahu 'alaihi wasallam junub, kemudian aku mandi dari bejana dan masih ada sisa air. Kemudian Rasulullah shallallahu 'alaihi wasallam datang untuk mandi darinya, maka aku pun berkata, 'Tadi aku telah memakainya untuk mandi? ' Beliau lalu menjawab: 'Sesungguhnya air tidak (berubah) karena janabat, atau tidak menjadi najis dengan sesuatu.' Kemudian beliau mandi darinya.\""},"3806":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ مَيْمُونَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى وَعَلَيْهِ مِرْطٌ لِبَعْضِ نِسَائِهِ وَعَلَيْهَا بَعْضُهُ قَالَ سُفْيَانُ أُرَاهُ قَالَ حَائِضٍ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Asy Syaibani] dari [Abdullah bin Syaddad] dari [Maimunah], bahwa ketika Nabi shallallahu 'alaihi wasallam shalat, sebagian kain isterinya mengenenai (menempel pada) beliau, dan sebagiannya lagi mengenai isterinya.\" Sufyan berkata, \"Menurutku ia menyebutkan, \"Haid.\""},"3807":{"ar":"حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا الشَّيْبَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ مَيْمُونَةَ بِنْتِ الْحَ��رِثِ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى الْخُمْرَةِ","id":"Telah menceritakan kepada kami [Husyaim] berkata, telah mengabarkan kepada kami [Asy Syaibani] dari [Abdullah bin Syaddad] dari [Maimunah binti Al Harist] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat di atas tikar kecil.\""},"3808":{"ar":"حَدَّثَنَا بَكْرُ بْنُ عِيسَى الرَّاسِبِيُّ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا سُلَيْمَانُ الشَّيْبَانِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ شَدَّادِ بْنِ الْهَادِ قَالَسَمِعْتُ خَالَتِي مَيْمُونَةَ بِنْتَ الْحَارِثِ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا كَانَتْ تَكُونُ حَائِضًا وَهِيَ مُفْتَرِشَةٌ بِحِذَاءِ مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي عَلَى خُمْرَتِهِ إِذَا سَجَدَ أَصَابَنِي طَرَفُ ثَوْبِهِ","id":"Telah menceritakan kepada kami [Bakr bin 'Isa Ar Rasibi] telah menceritakan kepada kami [Abu 'Awanah] berkata, telah menceritakan kepada kami [Sulaiman Asy Syaibani] berkata, telah menceritakan kepada kami [Abdullah bin Syaddad bin Al Hadi] berkata, aku mendengar bibiku [Maimunah binti Al Harits] isteri Nabi shallallahu 'alaihi wasallam, bahwa saat dirinya sedang haid, dia berbaring di depan tempat sujud Rasulullah shallallahu 'alaihi wasallam yang sedang shalat, \"Ketika beliau sujud, sebagian kain beliau mengenaiku.\""},"3809":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا الشَّيْبَانِيُّ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ مَيْمُونَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى الْخُمْرَةِ فَيَسْجُدُ فَيُصِيبُنِي ثَوْبُهُ وَأَنَا إِلَى جَنْبِهِ وَأَنَا حَائِضٌ","id":"Telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami [Asy Syaibani] dari [Yazid bin Al 'Asham] dari [Maimunah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat di atas tikar kecil, sewaktu sujud kain beliau mengenai aku yang sedang berada di sampingnya, padahal aku sedang haid.\""},"3810":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ ابْنِ الْأَصَمِّ قَالَ أَبِي وَقُرِئَ عَلَى سُفْيَانَ اسْمُهُ عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ ابْنِ أَخِي يَزِيدَ بْنِ الْأَصَمِّ عَنْ عَمِّهِ عَنْ مَيْمُونَةَ وَهِيَ خَالَتُهُ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ وَثَمَّ بَهْمَةٌ أَرَادَتْ أَنْ تَمُرَّ بَيْنَ يَدَيْهِ تَجَافَى","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibnu Al 'Asham], Bapakku berkata; dan dibacakan atas Sufyan; namanya adalah 'Ubaidullah bin Abdullah, anak Akhi Yazid bin Al 'Asham, dari [pamannya] dari [Maimunah] -dan dia adalah bibinya- dia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam sujud, lalu ada seekor anak kambing yang ingin lewat maka beliau meregangkan kedua (siku) tangannya.\""},"3811":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي إِدْرِيسَ عَنِ ابْنِ صَفْوَانَ عَنْ صَفِيَّةَ أُمِّ الْمُؤْمِنِينَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْتَهِي النَّاسُ عَنْ غَزْوِ هَذَا الْبَيْتِ حَتَّى يَغْزُوَهُ جَيْشٌ حَتَّى إِذَا كَانُوا بِبَيْدَاءَ مِنْ الْأَرْضِ خُسِفَ بِأَوَّلِهِمْ وَآخِرِهِمْ وَلَمْ يَنْجُ أَوْسَطُهُمْ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ الْمُكْرَهَ مِنْهُمْ قَالَ يَبْعَثُهُمْ اللَّهُ عَلَى مَا فِي أَنْفُسِهِمْقَالَ سُفْيَانُ قَالَ سَلَمَةُ فَحَدَّثَنِي عُبَيْدُ بْنُ أَبِي الْجَعْدِ عَنْ مُسْلِمٍ نَحْوَ هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Abu Idris] dari [Ibnu Shafyan] dari [Shafiyah] Ummul Mukminin, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia tidak akan berhenti memerangi rumah ini (Baitullah) hingga sekumpulan tentara memeranginya, ketika mereka sampai di tanah sahara, mereka ditenggelamkan dari yang pertama dan yang terakhir, begitu juga yang di tengah-tengah mereka tidak selamat.\" Para sahabat bertanya, \"Wahai Rasulullah, bagaimana dengan orang yang terpaksa yang berada di antara mereka?\" Beliau menjawab: \"Allah akan membangkitkan mereka sesuai dengan niat yang ada dalam hati mereka.\" [Sufyan] berkata; [Salamah] berkata; telah menceritakan kepadaku ['Ubaid bin Abu Ja'd] dari [Muslim] seperti hadits ini.\""},"3812":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ يَعْنِي ابْنَ كُهَيْلٍ عَنْ أَبِي إِدْرِيسَ عَنِ ابْنِ صَفْوَانَ عَنْ صَفِيَّةَ بِنْتِ حُيَيٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْتَهِي النَّاسُ عَنْ غَزْوِ هَذَا الْبَيْتِ حَتَّى إِذَا كَانُوا بِبَيْدَاءَ مِنْ الْأَرْضِ خُسِفَ أَوَّلُهُمْ وَآخِرُهُمْ وَلَمْ يَنْجُ أَوْسَطُهُمْ قَالُوا يَا رَسُولَ اللَّهِ يَكُونُ فِيهِمْ الْمُكْرَهُ قَالَ يَبْعَثُهُمْ اللَّهُ عَلَى مَا فِي أَنْفُسِهِمْحَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ عَنْ أَبِي إِدْرِيسَ الْمُرْهِبِيُّ عَنْ مُسْلِمِ بْنِ صَفْوَانَ عَنْ صَفِيَّةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْتَهِي النَّاسُ وَذَكَرَ الْحَدِيثَ وَسَاقَهُ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Salamah] -yakni Ibnu Kuhail- dari [Abu Idris] dari [Ibnu Shafwan] dari [Shafiyah binti Huyai] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Manusia tidak akan berhenti memerangi rumah ini (Ka'bah), sehingga ketika mereka sampai di padang pasir, mereka dibinasakan baik yang pertama maupun yang terakhir, dan orang-orang yang berada di tengah pun tidak akan selamat.\" Mereka (para sahabat) bertanya, \"Wahai Rasulullah, bagaimana jika di dalamnya ada yang dipaksa?\" Beliau bersabda: \"Allah akan membangkitkan sesuai dengan niat mereka.\" Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Sufyan] dari [Salamah] dari [Abu Idris Al Murhibi] dari [Muslim bin Shafwan] dari [Shafiyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia tidak akan berhenti….kemudian dia menyebutkan hadits tersebut.\""},"3813":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ يَعْلَى بْنَ حَكِيمٍ عَنْ صُهَيْرَةَ بِنْتِ جَيْفَرٍ قَالَتْدَخَلْتُ عَلَى صَفِيَّةَ بِنْتِ حُيَيٍّ فَسَأَلْتُ عَنْ نَبِيذِ الْجَرِّ فَقَالَتْ حَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيذَ الْجَرِّ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Bapakku] berkata, saya mendengar [Ya'la bin Hakim] dari [Shuhairah binti Jaifar] dia berkata, \"Saya menemui [Shafiyah binti Huyai], kemudian saya bertanya tentang perasan nabidz yang dibuat dalam benaja dari tembikar, dia lalu menjawab, \"Rasulullah shallallahu 'alaihi wasallam mengharamkan perasan nabidz yang dibuat dalam bajana dari tembikar.\" "},"3814":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ وَعَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنِ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ صَفِيَّةَ بِنْتِ حُيَيٍّ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُعْتَكِفًا فَأَتَيْتُهُ أَزُورُهُ لَيْلًا فَحَدَّثْتُهُ ثُمَّ قُمْتُ فَانْقَلَبْتُ فَقَامَ مَعِي يَقْلِبُنِي وَكَانَ مَسْكَنُهَا فِي دَارِ أُسَامَةَ بْنِ زَيْدٍ فَمَرَّ رَجُلَانِ مِنْ الْأَنْصَارِ فَلَمَّا رَأَيَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْرَعَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رِسْلِكُمَا إِنَّهَا صَفِيَّةُ بِنْتُ حُيَيٍّ فَقَالَا سُبْحَانَ اللَّهِ يَا رَسُولَ اللَّهِ فَقَالَ إِنَّ الشَّيْطَانَ يَجْرِي مِنْ الْإِنْسَانِ مَجْرَى الدَّمِ وَإِنِّي خَشِيتُ أَنْ يَقْذِفَ فِي قُلُوبِكُمَا شَرًّا أَوْ قَالَ شَيْئًا","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dan ['Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari ['Ali bin Husain] dari [Shafiyah binti Huhai] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam beri'tikaf, lalu saya datang mengunjunginya pada malam hari, setelah berbincang-bincang saya pun berdiri untuk kembali, lantas beliau berdiri untuk mengantarku -tempat tinggal Shafiyah adalah di rumah Usamah bin Zaid-. Lalu lewatlah dua laki-laki Anshar, ketika mereka melihat Nabi shallallahu 'alaihi wasallam mereka mempercepat langkah mereka, kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Perlahanlah, sesungguhnya dia adalah Shafiyah binti Huyai.\" Maka mereka pun berkata, \"Wahai Rasulullah, Maha Suci Allah!\" Beliau lantas bersabda: \"Sesungguhnya setan mengalir dalam diri manusia pada aliran darah, dan aku khawatir jika hati kalian menuduhku berbuat tidak baik atau berkata yang tidak baik.\""},"3815":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنِي أَبِي قَالَ سَمِعْتُ يَعْلَى بْنَ حَكَمٍ يُحَدِّثُ عَنْ صُهَيْرَةَ بِنْتِ جَيْفَرٍ قَالَتْحَجَجْنَا ثُمَّ أَتَيْنَا الْمَدِينَةَ فَدَخَلْنَا عَلَى صَفِيَّةَ بِنْتِ حُيَيٍّ فَوَافَقْنَا عِنْدَهَا نِسْوَةً فَقَالَتْ حَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيذَ الْجَرِّ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepadaku [Bapakku] berkata, saya mendengar [Ya'la bin Hakam] telah menceritakan dari [Shuhairah binti Jaifar] dia berkata, \"Kami melaksanakan haji kemudian kami datang ke Madinah dan menemui [Shafiyah binti Huyai], kebetulan di sampingnya ada beberapa wanita, kemudian dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengharamkan perasan nabidz dalam bejana dari tembikar.\""},"3816":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ حَدَّثَنِي يَعْلَى بْنُ حَكِيمٍ عَنْ صُهَيْرَةَ بِنْتِ جَيْفَرٍ سَمِعَهُ مِنْهَا قَالَتْحَجَجْنَا ثُمَّ انْصَرَفْنَا إِلَى الْمَدِينَةِ فَدَخَلْنَا عَلَى صَفِيَّةَ بِنْتِ حُيَيٍّ فَوَافَقْنَا عِنْدَهَا نِسْوَةً مِنْ أَهْلِ الْكُوفَةِ فَقُلْنَ لَهَا إِنْ شِئْتُنَّ سَأَلْتُنَّ وَسَمِعْنَا وَإِنْ شِئْتُنَّ سَأَلْنَا وَسَمِعْتُنَّ فَقُلْنَا سَلْنَ فَسَأَلْنَ عَنْ أَشْيَاءَ مِنْ أَمْرِ الْمَرْأَةِ وَزَوْجِهَا وَمِنْ أَمْرِ الْمَحِيضِ ثُمَّ سَأَلْنَ عَنْ نَبِيذِ الْجَرِّ فَقَالَتْ أَكْثَرْتُمْ عَلَيْنَا يَا أَهْلَ الْعِرَاقِ فِي نَبِيذِ الْجَرِّ وَمَا عَلَى إِحْدَاكُنَّ أَنْ تَطْبُخَ تَمْرَهَا ثُمَّ تَدْلُكَهُ ثُمَّ تُصَفِّيَهُ فَتَجْعَلَهُ فِي سِقَائِهَا وَتُوكِئَ عَلَيْهِ فَإِذَا طَابَ شَرِبَتْ وَسَقَتْ زَوْجَهَا","id":"Telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepadaku [Jarir bin Hazim] berkata, telah menceritakan kepadaku [Ya'la bin Hakim] dari [Shuhairah binti Jaifar] bahwa dia mendengar darinya berkata; kami melaksanakan haji kemudian kami kembali ke Madinah, kemudian kami menemui [Shafiyah binti Huyai] yang kebetulan di sampingnya ada beberapa wanita dari penduduk Kufah, kami berkata kepadanya, \"Jika kalian menghendaki kalian boleh bertanya dan kami akan mendengarkan, tapi jika kalian menghendaki, kami yang akan bertanya dan kalian yang mendengarkan\". Kami katakan, \"Silahkan kalian bertanya, \" maka mereka bertanya berbagai permasalahan isteri dan suaminya, dan dari perkara haid, kemudian mereka bertanya tentang (hukum) fermentasi kurma dalam kuali. Wahai pendudik Irak, kalian telah banyak bertanya kepada kami tentang fermentasi kurma, tidaklah mengapa salah seorang dari kalian memasak kurmanya kemudian melumatkannya, menyaringnya, ia masukkan dalam wadahnya dan menutupnya? Dan apabila telah masak, ia minum dan ia suguhkan kepada suaminya?\""},"3817":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ ثَابِتٍ قَالَ حَدَّثَتْنِي شُمَيْسَةُ أَوْ سُمَيَّةُ قَالَ عَبْدُ الرَّزَّاقِ هُوَ فِي كِتَابِي سُمَيَّةُ عَنْ صَفِيَّةَ بِنْتِ حُيَيٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّ بِنِسَائِهِ فَلَمَّا كَانَ فِي بَعْضِ الطَّرِيقِ نَزَلَ رَجُلٌ فَسَاقَ بِهِنَّ فَأَسْرَعَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَاكَ سَوْقُكَ بِالْقَوَارِيرِ يَعْنِي النِّسَاءَ فَبَيْنَا هُمْ يَسِيرُونَ بَرَكَ بِصَفِيَّةَ بِنْتِ حُيَيٍّ جَمَلُهَا وَكَانَتْ مِنْ أَحْسَنِهِنَّ ظَهْرًا فَبَكَتْ وَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُخْبِرَ بِذَلِكَ فَجَعَلَ يَمْسَحُ دُمُوعَهَا بِيَدِهِ وَجَعَلَتْ تَزْدَادُ بُكَاءً وَهُوَ يَنْهَاهَا فَلَمَّا أَكْثَرَتْ زَبَرَهَا وَانْتَهَرَهَا وَأَمَرَ النَّاسَ بِالنُّزُولِ فَنَزَلُوا وَلَمْ يَكُنْ يُرِيدُ أَنْ يَنْزِلَ قَالَتْ فَنَزَلُوا وَكَانَ يَوْمِي فَلَمَّا نَزَلُوا ضُرِبَ خِبَاءُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَخَلَ فِيهِ قَالَتْ فَلَمْ أَدْرِ عَلَامَ أُهْجَمُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَشِيتُ أَنْ يَكُونَ فِي نَفْسِهِ شَيْءٌ مِنِّي فَانْطَلَقْتُ إِلَى عَائِشَةَ فَقُلْتُ لَهَا تَعْلَمِينَ أَنِّي لَمْ أَكُنْ أَبِيعُ يَوْمِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ أَبَدًا وَإِنِّي قَدْ وَهَبْتُ يَوْمِي لَكِ عَلَى أَنْ تُرْضِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنِّي قَالَتْ نَعَمْ قَالَ فَأَخَذَتْ عَائِشَةُ خِمَارًا لَهَا قَدْ ثَرَدَتْهُ بِزَعْفَرَانٍ فَرَشَّتْهُ بِالْمَاءِ لِيُذَكِّيَ رِيحَهُ ثُمَّ لَبِسَتْ ثِيَابَهَا ثُمَّ انْطَلَقَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَفَعَتْ طَرَفَ الْخِبَاءِ فَقَالَ لَهَا مَا لَكِ يَا عَائِشَةُ إِنَّ هَذَا لَيْسَ بِيَوْمِكِ قَالَتْ ذَلِكَ فَضْلُ اللَّهِ يُؤْتِيهِ مَنْ يَشَاءُ فَقَالَ مَعَ أَهْلِهِ فَلَمَّا كَانَ عِنْدَ الرَّوَاحِ قَالَ لِزَيْنَبَ بِنْتِ جَحْشٍ يَا زَيْنَبُ أَفْقِرِي أُخْتَكِ صَفِيَّةَ جَمَلًا وَكَانَتْ مِنْ أَكْثَرِهِنَّ ظَهْرًا فَقَالَتْ أَنَا أُفْقِرُ يَهُودِيَّتَكَ فَغَضِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ سَمِعَ ذَلِكَ مِنْهَا فَهَجَرَهَا فَلَمْ يُكَلِّمْهَا حَتَّى قَدِمَ مَكَّةَ وَأَيَّامَ مِنًى فِي سَفَرِهِ حَتَّى رَجَعَ إِلَى الْمَدِينَةِ وَالْمُحَرَّمَ وَصَفَرَ فَلَمْ يَأْتِهَا وَلَمْ يَقْسِمْ لَهَا وَيَئِسَتْ مِنْهُ فَلَمَّا كَانَ شَهْرُ رَبِيعٍ الْأَوَّلِ دَخَلَ عَلَيْهَا فَرَأَتْ ظِلَّهُ فَقَالَتْ إِنَّ هَذَا لَظِلُّ رَجُلٍ وَمَا يَدْخُلُ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ هَذَا فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَتْهُ قَالَتْ يَا رَسُولَ اللَّهِ مَا أَدْرِي مَا أَصْنَعُ حِينَ دَخَلْتَ عَلَيَّ قَالَتْ وَكَانَتْ لَهَا جَارِيَةٌ وَكَانَتْ تَخْبَؤُهَا مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ فُلَانَةُ لَكَ فَمَشَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى سَرِيرِ زَيْنَبَ وَكَانَ قَدْ رُفِعَ فَوَضَعَهُ بِيَدِهِ ثُمَّ أَصَابَ أَهْلَهُ وَرَضِيَ عَنْهُمْحَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ سُمَيَّةَ عَنْ عَائِشَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي سَفَرٍ فَاعْتَلَّ بَعِيرٌ لِصَفِيَّةَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Tsabit] berkata, telah menceritakan kepadaku Syumaisah atau [Sumayyah], [Abdurrazaq] berkata -dalam kitabku; Sumayyah- dari [Shafiyah binti Huyai] bahwa Nabi shallallahu 'alaihi wasallam melaksanakan haji bersama isteri-isterinya, tatkala sampai di salah satu jalan, ada seorang laki-laki berhenti dan mengawal isteri-isteri beliau dengan cepat, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Hati-hatilah jika mengawal seorang wanita.\" Tatkala mereka (rombongan) berjalan, tiba-tiba untanya Shafiyah menderum, dia adalah wanita yang paling bagus dalam berkendaraan (di antara isteri-isteri beliau) hingga ia pun menangis. Tatkala Rasulullah shallallahu 'alaihi wasallam mendengar perihal itu, beliau menghampirinya sambil menghapus air matanya, namun tangisan shafiyah semakin menjadi. Ketika beliau melarang dan Shafiyah masih tetap menangis, maka beliau pun mengeraskan suara dan memerintahkan orang-orang untuk singgah, maka mereka semua singgah, padahal beliau tidak ingin singgah. Shafiyah lalu berkata, \"Semuanya pun singgah. Hari itu adalah hariku, tatkala mereka singgah, tenda beliau didirikan dan beliau langsung masuk ke dalamnya.\" Shafiyah melanjutkan, \"Saya tidak tahu kenapa Rasulullah shallallahu 'alaihi wasallam masuk secara tiba-tiba, saya khawatir jangan-jangan beliau marah terhadapku. Saya langsung menemui 'Aisyah dan berkata kepadanya, 'Sesungguhnya saya belum pernah menggadaikan giliranku untuk Rasulullah shallallahu 'alaihi wasallam dengan sesuatupun, dan hari ini saya hadiahkan giliranku untukmu dengan syarat kamu jadikan Rasulullah shallallahu 'alaihi wasallam kembali ridla terhadapku.' Aisyah menjawab, 'Ya.' Shafiyah berkata, \"Lantas 'Aisyah mengambil kerudungnya yang telah diberi minyak wangi Za'faran dan dicampuri dengan minyak, agar harumnya semerbak. Kemudian dia mengenakan pakaiannya. Lalu dia menemui Rasulullah shallallahu 'alaihi wasallam sambil membuka ujung tendanya. Beliau pun bersabda kepadanya: \"Ada apa denganmu wahai 'Aisyah, hari ini bukan giliranmu?\" Aisyah menjawab, \"Itu adalah karunia yang diberikan oleh Allah kepada siapa yang dikehendaki-Nya.\" Beliau pun berbincang bersama isterinya. Tatkala beliau dalam perjalanan, beliau bersabda kepada Zainab binti Jahsyi: \"Wahai Zainab, berikanlah untamu kepada Shafiyah, karena dia adalah wanita yang paling banyak berkendaraan.\" Zainab menjawab, \"Apakah saya harus memberi kepada wanita Yahudimu?\" Tatkala Nabi shallallahu 'alaihi wasallam mendengar ucapannya, beliau pun marah dan tidak mengajaknya berbicara sampai beliau tiba di Makkah, juga pada hari-hari selama di Mina hingga kembali ke Madinah, dan selama bulan Muharam dan Shafar pun beliau tidak memberikan giliran kepadanya hingga Zainab berputus asa dari beliau. Ketika bulan Rabi'ul Awwal, beliau menemuinya, waktu dia (Zainab) melihat ada bayang-bayang seseorang dia berkata, 'Sesungguhnya ini adalah bayang-bayang seorang laki-laki, dan tidak mungkin jika Nabi shallallahu 'alaihi wasallam menemuiku, tapi bayang-bayang siapakah ini? Lantas Nabi shallallahu 'alaihi wasallam masuk untuk menemuinya, tatkala dia melihatnya dia berkata, 'Wahai Rasulullah, saya tidak mengerti apa yang seharusnya saya perbuat ketika tuan menemuiku? ' Sumayyah berkata, \"Shafiyah memiliki budak perempuan yang menyembunyikan diri dari Nabi shallallahu 'alaihi wasallam, lalu budak itu berkata, 'apakah fulanah (Zainab) adalah isterimu? ' Kemudian Nabi shallallahu 'alaihi wasallam menuju ranjangnya Zainab dan menggaulinya, dan beliau pun ridla terhadap mereka.\" Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammad] -yaitu Ibnu Salamah- dia berkata, Telah menceritakan kepada kami [Tsabit] dari [Sumayyah] dari ['Aisyah] bahwasanya Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, tiba-tiba hewan tunggangan Shafiyah sakit, kemudian ia menyebutkan hadits semisalnya.\""},"3818":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ عَنْ أُمِّهِ أَنَّهَاسَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِالْمُرْسَلَاتِ عُرْفًا","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah] dari [Ibnu Abbas] dari [Ibunya] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam biasa membaca surat Al Mursalat pada shalat maghrib.\""},"3819":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنِ ابْنِ عَبَّاسٍأَنَّهُ أَفْطَرَ بِعَرَفَةَ أُتِيَ بِرُمَّانٍ فَأَكَلَهُ وَقَالَ حَدَّثَتْنِي أُمُّ الْفَضْلِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْطَرَ بِعَرَفَةَ أَتَتْهُ بِلَبَنٍ فَشَرِبَهُ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibn Abbas], bahwa dia berbuka puasa di Arafah, saat disuguhkan buah delima kepadanya ia pun memakannya. Kemudian dia berkata, \" [Ummu Fadll] menceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam berbuka puasa di Arafah, ia menyuguhkan susu untuk beliau, lalu beliau pun meminumnya.\""},"3820":{"ar":"حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ حُمَيْدٍ عَنْ أَنَسٍ عَنْ أُمِّ الْفَضْلِ بِنْتِ الْحَارِثِ قَالَتْصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ مُتَوَشِّحًا فِي ثَوْبِ الْمَغْرِبِ فَقَرَأَ الْمُرْسَلَاتِ مَا صَلَّى صَلَاةً بَعْدَهَا حَتَّى قُبِضَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa bin Daud] telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Salamah] dari [Humaid] dari [Anas] dari [Ummu Fadll binti Al Harits] dia berkata, \"Kami mengerjakan shalat bersama Rasulullah shallallahu 'alaihi wasallam di dalam rumahnya, beliau mengenakan pakaian shalat maghrib, kemudian beliau membaca (surat) Al Mursalaat, dan tidaklah beliau shalat setelahnya sampai beliau shallallahu 'alaihi wasallam wafat.\""},"3821":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ أَبِي النَّضْرِ قَالَ سَمِعْتُ عُمَيْرًا مَوْلَى أُمِّ الْفَضْلِ أُمِّ بَنِي الْعَبَّاسِ عَنْ أُمِّ الْفَضْلِ قَالَتْشَكُّوا فِي صَوْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَرَفَةَ فَقَالَتْ أُمُّ الْفَضْلِ أَنَا أَعْلَمُ لَكُمْ ذَلِكَ فَبَعَثَتْ بِلَبَنٍ فَشَرِبَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Abu An Nadlr] berkata, saya mendengar [Umair] bekas budak Ummu Fadll Ummu bani Abbas, dari [Ummu Fadll] dia berkata, \"Mereka mengadukan tentang puasa Nabi shallallahu 'alaihi wasallam di hari Arafah, maka Ummu Fadll pun berkata, 'Saya lebih mengetahui dari kalian tentang masalah tersebut', kemudian ia mengirimkan susu kepada beliau dan beliau pun meminumnya.\""},"3822":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ قَالَ أَخْبَرَنَا لَيْثٌ وَيُونُسُ قَالَ حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ سَعْدٍ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ هِنْدَ بِنْتِ الْحَارِثِ عَنْ أُمِّ الْفَضْلِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى الْعَبَّاسِ وَهُوَ يَشْتَكِي فَتَمَنَّى الْمَوْتَ فَقَالَ يَا عَبَّاسُ يَا عَمَّ رَسُولِ اللَّهِ لَا تَتَمَنَّ الْمَوْتَ إِنْ كُنْتَ مُحْسِنًا تَزْدَادُ إِحْسَانًا إِلَى إِحْسَانِكَ خَيْرٌ لَكَ وَإِنْ كُنْتَ مُسِيئًا فَإِنْ تُؤَخَّرْ تَسْتَعْتِبْ خَيْرٌ لَكَ فَلَا تَتَمَنَّ الْمَوْتَ قَالَ يُونُسُ وَإِنْ كُنْتَ مُسِيئًا فَإِنْ تُؤَخَّرْ تَسْتَعْتِبْ مِنْ إِسَاءَتِكَ خَيْرٌ لَكَ","id":"Telah menceritakan kepada kami [Abu Salamah Al Khuza'i] berkata, telah mengabarkan kepada kami [Laits] dan [Yunus] berkata, telah menceritakan kepada kami [Laits] -yakni Ibnu Sa'd- dari [Yazid bin Al Hadi] dari [Hindun binti Al Harits] dari [Ummi Fadll], bahwa Nabi shallallahu 'alaihi wasallam menjenguk Al Abbas yang sedang sakit dan berharap untuk mati, beliau lantas bersabda: \"Wahai Abbas, wahai paman Rasulullah, janganlah kamu mengharapkan kematian, jika kamu berbuat baik lalu engkau menambah kebaikan pada amal baikmu adalah lebih baik bagimu, dan jika kamu berbuat buruk, lalu umurmu diperpanjang dan kamu ridla maka itu lebih baik, maka janganlah kamu mengharap kematian.\" Yunus menyebutkan, \"jika kamu berbuat buruk, lalu umurmu diperpanjang dan kamu ridla dari keburukanmu maka itu lebih baik bagimu.\""},"3823":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ قَابُوسَ بْنِ أَبِي الْمُخَارِقِ عَنْ أُمِّ الْفَضْلِ قَالَتْرَأَيْتُ كَأَنَّ فِي بَيْتِي عُضْوًا مِنْ أَعْضَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ فَجَزِعْتُ مِنْ ذَلِكَ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ خَيْرًا تَلِدُ فَاطِمَةُ غُلَامًا فَتَكْفُلِينَهُ بِلَبَنِ ابْنِكِ قُثَمٍ قَالَتْ فَوَلَدَتْ حَسَنًا فَأُعْطِيتُهُ فَأَرْضَعْتُهُ حَتَّى تَحَرَّكَ أَوْ فَطَمْتُهُ ثُمَّ جِئْتُ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَجْلَسْتُهُ فِي حِجْرِهِ فَبَالَ فَضَرَبْتُ بَيْنَ كَتِفَيْهِ فَقَالَ ارْفُقِي بِابْنِي رَحِمَكِ اللَّهُ أَوْ أَصْلَحَكِ اللَّهُ أَوْجَعْتِ ابْنِي قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ اخْلَعْ إِزَارَكَ وَالْبَسْ ثَوْبًا غَيْرَهُ حَتَّى أَغْسِلَهُ قَالَ إِنَّمَا يُغْسَلُ بَوْلُ الْجَارِيَةِ وَيُنْضَحُ بَوْلُ الْغُلَامِ","id":"Telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Israil] dari [Simak] dari [Qabus bin Abu Al Mukhariq] dari [Ummi Fadll] dia berkata, \"Aku melihat seakan-akan di rumahku ada bagian dari bagian tubuh Rasulullah shallallahu 'alaihi wasallam. Sehingga aku pun menjadi cemas, aku lalu mendatangi Rasulullah shallallahu 'alaihi wasallam dan menyebutkan akan hal itu, beliau lalu bersabda: \"Kabar baik, Fatimah akan melahirkan seorang anak, lalu kamu yang menanggungnya dengan susu anakmu, Qutsam.\" Ummu Fadll berkata, \"kemudian Fatimah melahirkan Hasan, kemudian aku memberinya, aku susui hingga ia bergerak -menyampihnya-, setelah itu bayi tersebut aku bawa ke hadapan Rasulullah shallallahu 'alaihi wasallam dan aku dudukkan di pangkuannya. Namun anak itu kencing hingga aku pun memukul antara kedua pundaknya, maka beliau pun bersabda: \"Bersikap lembutlah kepada anakku semoga Allah merahmatimu -atau, semoga Allah memberikan kebaikan kepadamu-, kamu telah membuat cemas cucuku.\" Aku lalu berkata, 'Wahai Rasulullah, lepaslah sarungmu dan pakailah kain yang lain hingga aku mencucinya, ' beliau bersabda: \"Hanyasanya yang dicuci itu adalah dari kencing yang sudah dewasa, adapun anak kecil cukup dipercikkan saja.\""},"3824":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ وَسَمِعْتُهُ أَنَا مِنْ أَبِي مَعْمَرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ أَبِي زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أُمِّ الْفَضْلِ بِنْتِ الْحَارِثِ وَهِيَ أُمُّ وَلَدِ الْعَبَّاسِ أُخْتُ مَيْمُونَةَ قَالَتْأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ فَجَعَلْتُ أَبْكِي فَرَفَعَ رَأْسَهُ فَقَالَ مَا يُبْكِيكِ قُلْتُ خِفْنَا عَلَيْكَ وَمَا نَدْرِي مَا نَلْقَى مِنْ النَّاسِ بَعْدَكَ يَا رَسُولَ اللَّهِ قَالَ أَنْتُمْ الْمُسْتَضْعَفُونَ بَعْدِي","id":"Telah menceritakan kepada kami [Abu Ma'mar], dan saya mendengarnya dari [Abu Ma'mar] berkata, telah menceritakan kepada kami [Abdullah bin Idris] berkata, telah menceritakan kepada kami [Yazid] -yakni Ibnu Abu Ziyad- dari [Abdullah bin Al Harits] dari [Ummu Fadll binti Harits] dia adalah Ummu Walad Al Abbas, saudara perempuan Maimunah, ia berkata, \"Saya mendatangi Nabi shallallahu 'alaihi wasallam yang sedang sakit, saat aku menangis, beliau mengangkat kepalanya seraya bersabda: \"Apa yang membuatmu menangis?\" Saya menjawab, \"Kami mencemaskanmu, dan kami tidak tahu bagaimana keadaan manusia yang kami temui setelahmu wahai Rasulullah.\" Beliau bersabda: \"Kalian akan melemah setelah kepergianku.\""},"3825":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ صَالِحٍ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أُمِّ الْفَضْلِ قَالَتْأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي رَأَيْتُ فِي مَنَامِي أَنَّ فِي بَيْتِي أَوْ حُجْرَتِي عُضْوًا مِنْ أَعْضَائِكَ قَالَ تَلِدُ فَاطِمَةُ إِنْ شَاءَ اللَّهُ غُلَامًا فَتَكْفُلِينَهُ فَوَلَدَتْ فَاطِمَةُ حَسَنًا فَدَفَعَتْهُ إِلَيْهَا فَأَرْضَعَتْهُ بِلَبَنِ قُثَمَ وَأَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا أَزُورُهُ فَأَخَذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعَهُ عَلَى صَدْرِهِ فَبَالَ عَلَى صَدْرِهِ فَأَصَابَ الْبَوْلُ إِزَارَهُ فَزَخَخْتُ بِيَدِي عَلَى كَتِفَيْهِ فَقَالَ أَوْجَعْتِ ابْنِي أَصْلَحَكِ اللَّهُ أَوْ قَالَ رَحِمَكِ اللَّهُ فَقُلْتُ أَعْطِنِي إِزَارَكَ أَغْسِلْهُ فَقَالَ إِنَّمَا يُغْسَلُ بَوْلُ الْجَارِيَةِ وَيُصَبُّ عَلَى بَوْلِ الْغُلَامِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami [Ayyub] dari [Shalih Abu Al Khalil] dari [Abdullah bin Al Harits] dari [Ummu Fadll] dia berkata, \"Saya menemui Nabi shallallahu 'alaihi wasallam seraya berkata, \"Sesungguhnya saya bermimpi bahwa di rumahku atau di kamarku ada bagian dari bagian tubuhmu?\" Beliau bersabda: \"Insyaallah Fatimah akan melahirkan seorang bayi (anak), kemudian kamu yang akan mengasuhnya.\" Lalu Fatimah melahirkan Hasan, lantas Fatimah pun menyerahkan bayi tersebut kepadanya, kemudian ia menyusuinya dengan susu Qutsam. Setelah itu aku bawa anak tersebut kepada Nabi shallallahu 'alaihi wasallam di hari berkunjungku, maka Nabi shallallahu 'alaihi wasallam mengambilnya dan meletakkannya di atas dada, anak itu lalu kencing di atas dada beliau sehingga kencingnya mengenai kain sarung beliau, maka saya memukul di antara pundaknya. Beliau pun bersabda: \"Kamu telah menyakiti cucuku, semoga Allah memperbaiki dirimu.\" Atau, beliau berkata: \"Semoga Allah merahmatimu.\" Saya pun berkata, \"Lepaslah sarungmu hingga saya dapat mencucinya.\" Namun beliau bersabda: \"Hanyasanya yang dicuci itu adalah dari kencing anak perempuan, adapun anak laki-laki cukup dipercikkan saja.\""},"3826":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا حَمَّادٌ عَنْ قَتَادَةَ عَنْ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أُمِّ الْفَضْلِأَنَّ الرَّسُولَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُحَرِّمُ الْإِمْلَاجَةُ أَوْ الْإِمْلَاجَتَانِ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Hammad] dari [Qatadah] dari [Abu Al Khalil] dari [Abdullah bin Al Harits] dari [Ummu Fadll] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu atau dua hisapan tidak menjadikan haram.\""},"3827":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مَالِكٍ حَدَّثَنِي سَالِمٌ أَبُو النَّضْرِ عَنْ عُمَيْرٍ مَوْلَى أُمِّ الْفَضْلِ أَنَّ أُمَّ الْفَضْلِ أَخْبَرَتْهُأَنَّهُمْ شَكُّوا فِي صَوْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَرَفَةَ فَأَرْسَلَتْ إِلَيْهِ بِلَبَنٍ فَشَرِبَ وَهُوَ يَخْطُبُ النَّاسَ بِعَرَفَةَ عَلَى بَعِيرِهِحَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ قَابُوسَ بْنِ مُخَارِقٍ عَنْ أُمِّ الْفَضْلِ قَالَتْ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ مِثْلَ حَدِيثِ عَفَّانَ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ صَالِحٍ أَبِي الْخَلِيلِ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Malik] telah menceritakan kepadaku [Salim Abu Nadlr] dari ['Umair] bekas budak Ummu Fadll, bahwa [Ummu Fadll] mengabarkan kepadanya, bahwa orang-orang mengadukan tentang puasa Nabi shallallahu 'alaihi wasallam pada hari 'Arafah, kemudian Ummu Fadll mengirim susu untuk beliau, lalu beliau meminumnya padahal beliau sedang berkhutbah di hadapan manusia di atas untanya di hari Arafah.\" Telah menceritakan kepada kami [Hajjaj] berkata, telah menceritakan kepada kami [Syarik] dari [Simak bin Harb] dari [Qabus bin Mukhariq] dari [Ummu Fadll] dia berkata, \"Saya menemui Nabi shallallahu 'alaihi wasallam…kemudian dia menyebutkan seperti hadits 'Affan.\" Abdullah berkata; telah menceritakan kepada kami Wuhaib berkata, telah menceritakan kepada kami Ayyub dari Shalih Abu Al Khalil lalu ia menyebutkan seperti itu.\""},"3828":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنِ ابْنِ طَاوُسٍ عَنِ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ عَنْ أُمِّ هَانِئٍ قَالَتْنَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ بِأَعْلَى مَكَّةَ فَأَتَيْتُهُ فَجَاءَ أَبُو ذَرٍّ بِجَفْنَةٍ فِيهَا مَاءٌ قَالَتْ إِنِّي لَأَرَى فِيهَا أَثَرَ الْعَجِينِ قَالَتْ فَسَتَرَهُ يَعْنِي أَبَا ذَرٍّ فَاغْتَسَلَ ثُمَّ صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِ رَكَعَاتٍ وَذَلِكَ فِي الضُّحَى","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [Al Mutthalib bin Abdullah bin Hanthab] dari [Ummi Hani] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam turun dari atas dataran tinggi Makkah saat hari penaklukan Makkah, maka aku pun datang menemui beliau. Lalu datanglah Abu Dzar dengan membawa bejana besar yang di dalamnya terdapat air.\" Ummi Hani berkata, \"Sesungguhnya saya melihat di dalamnya ada bekas adonan. Kemudian dia menutupi beliau, yakni Abu Dzar, sehingga beliau pun mandi. Nabi shallallahu 'alaihi wasallam kemudian shalat delapan rakaat, dan ketika itu adalah waktu dluha.\""},"3829":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أُمِّ هَانِئٍوَكَانَ نَازِلًا عَلَيْهَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ سُتِرَ عَلَيْهِ فَاغْتَسَلَ فِي الضُّحَى فَصَلَّى ثَمَانِ رَكَعَاتٍ لَا يُدْرَى أَقِيَامُهَا أَطْوَلُ أَمْ سُجُودُهَا","id":"Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] berkata, telah menceritakan kepadaku [Ibnu Syihab] dari [Abdullah bin Al Harits] dari [Ummu Hani'] -saat itu beliau menemuinya-, bahwa Nabi shallallahu 'alaihi wasallam pada hari penaklukan kota Makkah ditutupi, lalu beliau mandi di waktu dluha. Setelah itu beliau mengerjakan delapan rakaat, dan tidak diketahui apakah yang lebih panjang berdirinya atau sujudnya.\""},"3830":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أُمِّ هَانِئٍ قَالَتْقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ مَرَّةً وَلَهُ أَرْبَعُ غَدَائِرَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ummu Hani'] dia berkata, \"Pernah Nabi shallallahu 'alaihi wasallam memasuki Makkah sedangkan beliau mempunyai empat ikatan pada rambutnya.\""},"3831":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ أُسَامَةَ قَالَ أَخْبَرَنِي حَاتِمُ بْنُ أَبِي صَغِيرَةَ وَرَوْحٌ قَالَ حَدَّثَنَا حَاتِمُ بْنُ أَبِي صَغِيرَةَ قَالَ حَدَّثَنَا سِمَاكُ بْنُ حَرْبٍ عَنْ أَبِي صَالِحٍ مَوْلَى أُمِّ هَانِئٍ قَالَ رَوْحٌ فِي حَدِيثِهِ حَدَّثَتْنِي أُمُّ هَانِئٍ فَقَالَتْ لِيسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ تَعَالَى{ وَتَأْتُونَ فِي نَادِيكُمْ الْمُنْكَرَ }قَالَ كَانُوا يَخْذِفُونَ أَهْلَ الطَّرِيقِ وَيَسْخَرُونَ مِنْهُمْ فَذَاكَ الْمُنْكَرُ الَّذِي كَانُوا يَأْتُونَ قَالَ رَوْحٌ فَذَلِكَ قَوْلُهُ تَعَالَى{ وَتَأْتُونَ فِي نَادِيكُمْ الْمُنْكَرَ }","id":"Telah menceritakan kepada kami [Hammad bin Usamah] berkata, telah mengabarkan kepadaku [Hatim bin Abu Shaghirah], dan [Rauh] berkata, telah menceritakan kepada kami [Hatim bin Abu Shaghirah] berkata, telah menceritakan kepada kami [Simak bin Harb] dari [Abu Shalih] bekas budak Ummu Hani', [Rauh] menyebutkan dalam haditsnya; telah menceritakan kepadaku [Ummi Hani'] ia berkata kepadaku, \"Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai firman Allah Ta'ala: '(Apakah Sesungguhnya kamu patut mendatangi laki-laki, menyamun dan mengerjakan kemungkaran di tempat-tempat pertemuanmu?) ' (Al-'Ankabuut: 29), beliau bersabda: \"Mereka melempari orang yang berada di jalan dan mencela mereka, itulah kemungkaran yang mereka lakukan.\" [Rauh] berkata, \"Itulah tafsir dari firman Allah Ta'ala: '(Apakah Sesungguhnya kamu patut mendatangi laki-laki, menyamun dan mengerjakan kemungkaran di tempat-tempat pertemuanmu?) '"},"3832":{"ar":"حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ جَعْدَةَ عَنْ أُمِّ هَانِئٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَدَعَا بِشَرَابٍ فَشَرِبَ ثُمَّ نَاوَلَهَا فَشَرِبَتْ فَقَالَتْ يَا رَسُولَ اللَّهِ أَمَا إِنِّي كُنْتُ صَائِمَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّائِمُ الْمُتَطَوِّعُ أَمِيرُ نَفْسِهِ إِنْ شَاءَ صَامَ وَإِنْ شَاءَ أَفْطَرَقَالَ قُلْتُ لَهُ سَمِعْتَهُ أَنْتَ مِنْ أُمِّ هَانِئٍ قَالَ لَا حَدَّثَنِيهِ أَبُو صَالِحٍ وَأَهْلُنَا عَنْ أُمِّ هَانِئٍ حَدَّثَنَا سُلَيْمَانُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ كُنْتُ أَسْمَعُ سِمَاكًا يَقُولُ حَدَّثَنَا ابْنَ أُمِّ هَانِئٍ فَأَتَيْتُ أَنَا خَيْرَهُمَا وَأَفْضَلَهُمَا فَسَأَلْتُهُ وَكَانَ يُقَالُ لَهُ جَعْدَةُ","id":"Telah menceritakan kepada kami [Abu Daud At Thayalisi] berkata, telah menceritakan kepada kami [Syu'bah] dari [Ja'dah] dari [Ummu Hani'], bahwa Rasulullah shallallahu 'alaihi wasallam menemuinya lalu beliau minta air minum, lalu beliau meminumnya kemudian memberikan sisanya kepadanya hingga ia pun meminumnya. Ummu Hani` lalu berkata, \"Wahai Rasulullah, sebenarnya aku sedang berpuasa.\" Rasulullah kemudian shallallahu 'alaihi wasallam bersabda: \"Seorang yang berpuasa sunnah adalah pemimpin bagi dirinya, jika ia mau maka ia berpuasa jika ia mau maka ia boleh berbuka.\" Abdullah berkata, \"Aku bertanya kepadanya, \"Apakah kamu mendengarnya dari Ummu Hani'? dia menjawab, \"Tidak. [Abu Shalih] mengabarkannya kepadaku -dan keluarganya- dari [Ummu Hani`].\" Telah menceritakan kepada kami Sulaiman berkata, telah menceritakan kepada kami Syu'bah berkata; aku mendengar Simak berkata; telah menceritakan kepada kami Ummu Hani' berkata, \"Lalu aku menemui orang yang lebih baik dari keduanya, lalu bertanya kepadanya. Orang tersebut dipanggil dengan nama Ja'dah.\""},"3833":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ أَبُو زَيْدٍ حَدَّثَنَا هِلَالٌ يَعْنِي ابْنَ خَبَّابٍ قَالَ نَزَلْتُ أَنَا وَمُجَاهِدٌ عَلَى يَحْيَى بْنِ جَعْدَةَ بْنِ أُمِّ هَانِئٍ فَحَدَّثَنَا عَنْ أُمِّ هَانِئٍ قَالَتْأَنَا أَسْمَعُ قِرَاءَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَوْفِ اللَّيْلِ وَأَنَا عَلَى عَرِيشِي هَذَا وَهُوَ عِنْدَ الْكَعْبَةِ","id":"Telah menceritakan kepada kami [Abdus Shamad] berkata, telah menceritakan kepada kami [Tsabit bin Yazid Abu Zaid] telah menceritakan kepada kami [Hilal] -yakni Ibnu Khabab- dia berkata, saya dan Mujahid datang menemui [Yahya bin Ja'dah bin Ummi Hani'] maka dia menceritakan kepada kami dari [Ummu Hani'] bahwa dia berkata, \"Saya mendengar bacaan shallallahu 'alaihi wasallam pada tengah malam, sedang saya berada di atas atap rumah ini dan beliau berada di sisi Ka'bah.\""},"3834":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا مُحَمَّدٌ يَعْنِي ابْنَ عَمْرٍو عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِي مُرَّةَ مَوْلَى أُمِّ هَانِئٍ قَالَ مُحَمَّدٌ وَقَدْ رَأَيْتُ أَبَا مُرَّةَ وَكَانَ شَيْخًا قَدْ أَدْرَكَ أُمَّ هَانِئٍ عَنْ أُمِّ هَانِئٍ قَالَتْأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فَقُلْتُ يَا رَسُولَ اللَّهِ قَدْ أَجَرْتُ حَمْوَيْنِ لِي فَزَعَمَ ابْنُ أُمِّي أَنَّهُ قَاتَلَهُ تَعْنِي عَلِيًّا قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَجَرْنَا مَنْ أَجَرْتِ يَا أُمَّ هَانِئٍ وَصُبَّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاءٌ فَاغْتَسَلَ ثُمَّ الْتَحَفَ بِثَوْبٍ عَلَيْهِ وَخَالَفَ بَيْنَ طَرَفَيْهِ عَلَى عَاتِقِهِ فَصَلَّى الضُّحَى ثَمَانِي رَكَعَاتٍ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Muhammad] -yakni bin Amru- dari [Ibrahim bin Abdullah bin Hunain] dari [Abu Murrah] bekas budak Ummu Hani', Muhammad berkata, \"Sungguh saya pernah melihat Abu Murrah, seorang Syaikh yang pernah bertemu dengan Ummu Hani', dari [Ummu Hani`] ia berkata, \"Saya menemui Rasulullah shallallahu 'alaihi wasallam pada saat penaklukan Makkah, lalu saya tanyakan, \"Wahai Rasulullah, sungguh saya telah menjamin kedua iparku, sedangkan anak ibuku menyangka bahwa dia telah membunuh Ali?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Sungguh, saya telah menjamin orang yang kamu jamin wahai Ummu Hani'.\" Kemudian dia Ummu Hani` menuangkan air untuk Rasulullah shallallahu 'alaihi wasallam, setelah mandi beliau berselimut dengan kain yang ada padanya, dengan menyelempangkan ujungnya ke pundak, lalu beliau mengerjakan shalat delapan rakaat.\""},"3835":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ رَجُلٍ عَنْ أُمِّ هَانِئٍ قَالَتْلَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ جَاءَتْ فَاطِمَةُ حَتَّى قَعَدَتْ عَنْ يَسَارِهِ وَجَاءَتْ أُمُّ هَانِئٍ وَقَعَدَتْ عَنْ يَمِينِهِ وَجَاءَتْ الْوَلِيدَةُ بِشَرَابٍ فَتَنَاوَلَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَرِبَ ثُمَّ نَاوَلَهُ أُمَّ هَانِئٍ عَنْ يَمِينِهِ فَقَالَتْ لَقَدْ كُنْتُ صَائِمَةً فَقَالَ لَهَا أَشَيْءٌ تَقْضِينَهُ عَلَيْكِ قَالَتْ لَا قَالَ لَا يَضُرُّكِ إِذًا","id":"Telah menceritakan kepada kami [Aswad bin Amir] berkata, telah menceritakan kepada kami [Israil] dari [Simak] dari [seorang laki-laki] dari [Ummu Hani'] dia berkata, \"Tatkala penaklukan Kota Makkah, Fatimah datang dan duduk di samping kiri Rasulullah shallallahu 'alaihi wasallam, kemudian Ummu Hani` datang dan duduk sisi kanan beliau. Setelah itu datanglah seorang budak perempuan membawa minuman, maka Nabi shallallahu 'alaihi wasallam mengambilnya dan meminumnya, kemudian beliau memberikan sisanya kepada Ummu Hani' yang ada di sebelah kanannya, namun ia berkata, \"Sesungguhnya saya sedang berpuasa.\" Beliau lantas bersabda kepadanya: \"Apakah puasa itu sesuatu yang kamu gunakan untuk qadla?\" ia menjawab, \"Tidak.\" Beliau lalu bersabda: \"Kalau begitu, tidak mengapa kamu minum.\""},"3836":{"ar":"حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ يَعْنِي ابْنَ أَبِي خَالِدٍ عَنْ أَبِي صَالِحٍ عَنْ أُمِّ هَانِئٍ قَالَتْلَمَّا دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ حَجَبُوهُ وَأُتِيَ بِمَاءٍ فَاغْتَسَلَ ثُمَّ صَلَّى الضُّحَى ثَمَانِيَ رَكَعَاتٍ مَا رَآهُ أَحَدٌ بَعْدَهَا صَلَّاهَا","id":"Telah menceritakan kepada kami [Ya'la bin 'Ubaid] berkata, telah menceritakan kepada kami [Isma'il] -yakni Ibnu Abu Khalid- dari [Abu Shalih] dari [Ummu Hani'] dia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam masuk (rumah) di hari pembukaan Kota Makkah, beliau ditutupi dan diberi air kemudian mandi, setelah itu beliau shalat dluha delapan rakaat, tidak seorang pun yang melihatnya shalat setelahnya.\""},"3837":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنِ ابْنِ أَبِي لَيْلَى قَالَ مَا أَخْبَرَنِي أَحَدٌ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى غَيْرَ أُمِّ هَانِئٍ فَإِنَّهَا حَدَّثَتْأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ بَيْتَهَا يَوْمَ فَتْحِ مَكَّةَ فَاغْتَسَلَ وَصَلَّى ثَمَانِيَ رَكَعَاتٍ مَا رَأَتْهُ صَلَّى صَلَاةً قَطُّ أَخَفَّ مِنْهَا غَيْرَ أَنَّهُ كَانَ يُتِمُّ الرُّكُوعَ وَالسُّجُودَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] dari [Ibnu Abu Laila] dia berkata, \"Tidak ada seorang pun yang mengabarkan kepadaku bahwa ia pernah melihat Nabi shallallahu 'alaihi wasallam shalat dluha selain [Ummu Hani'], ia menceritakan kepadaku bahwa Nabi shallallahu 'alaihi wasallam masuk rumahnya pada hari Fathu Makkah, kemudian beliau mandi dan shalat delapan rakaat. Ia (Ummu Hani`) tidak pernah melihat beliau mengerjakan shalat yang lebih ringan dari itu, hanya saja beliau menyempurnakan rukuk dan sujud.\""},"3838":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ عَنْ مُسْلِمٍ الْقُرِّيِّ قَالَسَأَلْتُ ابْنَ عَبَّاسٍ عَنْ مُتْعَةِ الْحَجِّ فَرَخَّصَ فِيهَا وَكَانَ ابْنُ الزُّبَيْرِ يَنْهَى عَنْهَا فَقَالَ هَذِهِ أُمُّ ابْنِ الزُّبَيْرِ تُحَدِّثُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِيهَا فَادْخُلُوا عَلَيْهَا فَاسْأَلُوهَا قَالَ فَدَخَلْنَا عَلَيْهَا فَإِذَا امْرَأَةٌ ضَخْمَةٌ عَمْيَاءُ فَقَالَتْ قَدْ رَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Syu'bah] dari [Muslim Al Qurri] berkata, \"Aku bertanya kepada [Ibnu Abbas] tentang nikah mut'ah pada waktu haji yang kemudian dia memberi keringanan di dalamnya, sedangkan Ibnu Zubair melarangnya. Ibnu Abbas menjawab, \" [Ibunya Ibnu Zubair] menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam telah memberi keringanan di dalamnya, maka temuilah dia dan tanyakan padanya.\" Maka mereka pun bertanya kepadanya.\" Ibnu Abbas berkata, \"Kami lalu masuk menenuinya, ternyata ia adalah seorang wanita besar badannya dan buta, lalu dia berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah memberi keringanan di dalamnya.\""},"3839":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنِ الزُّهْرِيِّ عَنْ بَعْضِهِمْ عَنْ مَوْلَى لِأَسْمَاءَ عَنْ أَسْمَاءَ أَنَّهَا قَالَتْكَانَ الْمُسْلِمُونَ ذَوِي حَاجَةٍ يَأْتَزِرُونَ بِهَذِهِ النَّمِرَةِ فَكَانَتْ إِنَّمَا تَبْلُغُ أَنْصَافَ سُوقِهِمْ أَوْ نَحْوَ ذَلِكَ فَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ يَعْنِي النِّسَاءَ فَلَا تَرْفَعْ رَأْسَهَا حَتَّى نَرْفَعَ رُءُوسَنَا كَرَاهِيَةَ أَنْ تَنْظُرَ إِلَى عَوْرَاتِ الرِّجَالِ مِنْ صِغَرِ أُزُرِهِمْحَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ عَبْدِ اللَّهِ بْنِ مُسْلِمِ بْنِ شِهَابٍ أَخِي الزُّهْرِيِّ عَنْ مَوْلًى لِأَسْمَاءَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ مِنْكُنَّ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Ibrahim bin Khalid] berkata, telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Az Zuhri] dari [sebagian mereka], dari [bekas budaknya Asma'] dari [Asma'] bahwa dia berkata, \"Kaum Muslimin mempunyai hajat, mereka memakai kain sarung dengan kain wool ini, dan hanyasanya (kain sarung mereka) hanya sebatas betis mereka atau semisalnya, kemudian aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda (kepada kaum wanita): 'Barangsiapa beriman dengan Allah dan hari akhir -yakni para wanita-, maka janganlah mengangkat kepadalanya sehingga kami mengangkat kepala kami.' Beliau ucapkan ituy karena kawatir mereka (kaum wanita) melihat auratnya laki-laki, disebabkan sarung mereka yang kecil.\" Telah menceritakan kepada kami [Abu Al A'la] dari [Ma'mar] dari [Abdullah bin Muslim bin Syihab] saudara laki-lakinya Az Zuhri, dari [bekas budaknya Asma'] dari [Asma' binti Abu Bakar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dari kalian (para wanita) beriman kepada Allah dan hari akhir….kemudian dia menyebutkan hadits tersebut.\""},"3840":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنِي النُّعْمَانُ بْنُ رَاشِدٍ عَنِ ابْنِ أَخِي الزُّهْرِيِّ عَنْ مَوْلًى لِأَسْمَاءَ بِنْتِ أَبِي بَكْرٍ عَنْ أَسْمَاءَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ النِّسَاءِ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا تَرْفَعْ رَأْسَهَا حَتَّى يَرْفَعَ الرِّجَالُ رُءُوسَهُمْ قَالَتْ وَذَلِكَ أَنَّ أُزُرَهُمْ كَانَتْ قَصِيرَةً مَخَافَةَ أَنْ تَنْكَشِفَ عَوْرَاتُهُمْ إِذَا سَجَدُوا","id":"Telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepadaku [An Nu'man bin Rasyid] dari [Akhi Az Zuhri] dari [bekas budaknya Asma' binti Abu Bakar] dari [Asma'] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai kaum wanita, barangsiapa beriman kepada Allah dan hari akhir, maka janganlah mengangkat kepalanya sehingga kaum laki-laki mengangkat kepala mereka.\" Asma' berkata, \"Yang demikian itu karena sarung mereka sangat pendek sehingga dikawatirkan aurat mereka akan tersingkap sewaktu sujud.\""},"3841":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ النِّسَاءِ مَنْ كَانَ مِنْكُنَّ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا تَرْفَعْ رَأْسَهَا حَتَّى يَرْفَعَ الْإِمَامُ رَأْسَهُ مِنْ ضِيقِ ثِيَابِ الرِّجَالِ","id":"Telah menceritakan kepada kami [Suraij bin Nu'man] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Urwah] dari [Asma' binti Abu Bakar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai kaum wanita, barangsiapa di antara kalian beriman kepada Allah dan hari akhir, maka janganlah mengangkat kepalanya sehingga imam mengangkat kepalanya.\" (Hal itu) dikarenakan sangat sempitnya (pendeknya) pakaian para lelaki.\""},"3842":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ جَدَّتِهِ فَمَا أَدْرِي أَسْمَاءَ بِنْتَ أَبِي بَكْرٍ أَوْ سُعْدَى بِنْتَ عَوْفٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى ضُبَاعَةَ بِنْتِ الزُّبَيْرِ بْنِ عَبْدِ الْمُطَّلِبِ فَقَالَ مَا يَمْنَعُكَ مِنْ الْحَجِّ يَا عَمَّةُ قَالَتْ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ سَقِيمَةٌ وَإِنِّي أَخَافُ الْحَبْسَ قَالَ فَأَحْرِمِي وَاشْتَرِطِي أَنَّ مَحِلَّكِ حَيْثُ حُبِسْتِ","id":"Telah menceritakan kepada kami [Ibnu Numair] berkata, telah menceritakan kepada kami [Utsman bin Hakim] dari [Abu Bakar bin Abdullah bin Zubair] dari neneknya, aku tidak tahu apakah [Asma binti Abu Bakar] atau [Su'da binti 'Auf] bahwa Rasulullah shallallahu 'alaihi wasallam menemui Dluba'ah binti Zubair bin Abdul Muthalib, beliau bersabda: \"Apa yang menghalangimu menunaikan haji wahai bibi?\" dia menjawab, \"Wahai Rasulullah, sesungguhnya aku adalah perempuan yang menderita sakit dan aku khawatir jika aku terhalang karenanya.\" Beliau bersabda: \"Berihramlah dan bersyaratlah bahwa batas tahalulmu adalah hingga kamu mampu.\""},"3843":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ حُدِّثْتُ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ أَنَّهَا قَالَتْفَزِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ كَسَفَتْ الشَّمْسُ فَأَخَذَ دِرْعًا حَتَّى أَدْرَكَ بِرِدَائِهِ فَقَامَ بِالنَّاسِ قِيَامًا طَوِيلًا يَقُومُ ثُمَّ يَرْكَعُ قَالَتْ فَجَعَلْتُ أَنْظُرُ إِلَى الْمَرْأَةِ الَّتِي هِيَ أَكْبَرُ مِنِّي قَائِمَةً وَإِلَى الْمَرْأَةِ الَّتِي هِيَ أَسْقَمُ مِنِّي قَائِمَةً فَقُلْتُ إِنِّي أَحَقُّ أَنْ أَصْبِرَ عَلَى طُولِ الْقِيَامِ مِنْكِو قَالَ ابْنُ جُرَيْجٍ حَدَّثَنِي مَنْصُورُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَزِعَ","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, [aku diberi cerita] dari [Asma' binti Abu Bakar] bahwa dia berkata, \"Nabi shallallahu 'alaihi wasallam terkejut pada waktu terjadi gerhana matahari, kemduian beliau mengambil jubah dan selendangnya, kemudian beliau shalat bersama manusia sampai berdiri lama, kemudian beliau rukuk.\" Asma berkata, \"Aku lihat ke arah seorang wanita yang lebih tua dariku, ia tegak berdiri, dan aku juga melihat kepada wanita yang lebih lemah dariku, dan ia tetap berdiri tegak. Maka aku berkata, \"Sungguh, aku lebih berhak bersabar atas lamanya berdiri daripada kamu.\" [Ibnu Juraij] berkata, telah menceritakan kepadaku [Manshur bin 'Abdurrahman] dari ibunya [Shafiyah binti Syaibah] dari [Asma' binti Abu Bakar] bahwa Nabi shallallahu 'alaihi wasallam terkejut.\""},"3844":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي يَحْيَى بْنُ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ جَدَّتِهِ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْلَمَّا وَقَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذِي طُوًى قَالَ أَبُو قُحَافَةَ لِابْنَةٍ لَهُ مِنْ أَصْغَرِ وَلَدِهِ أَيْ بُنَيَّةُ اظْهَرِي بِي عَلَى أَبِي قَبِيسٍ قَالَتْ وَقَدْ كُفَّ بَصَرُهُ قَالَتْ فَأَشْرَفْتُ بِهِ عَلَيْهِ فَقَالَ يَا بُنَيَّةُ مَاذَا تَرَيْنَ قَالَتْ أَرَى سَوَادًا مُجْتَمِعًا قَالَ تِلْكَ الْخَيْلُ قَالَتْ وَأَرَى رَجُلًا يَسْعَى بَيْنَ ذَلِكَ السَّوَادِ مُقْبِلًا وَمُدْبِرًا قَالَ يَا بُنَيَّةُ ذَلِكَ الْوَازِعُ يَعْنِي الَّذِي يَأْمُرُ الْخَيْلَ وَيَتَقَدَّمُ إِلَيْهَا ثُمَّ قَالَتْ قَدْ وَاللَّهِ انْتَشَرَ السَّوَادُ فَقَالَ قَدْ وَاللَّهِ إِذَا دَفَعَتْ الْخَيْلُ فَأَسْرِعِي بِي إِلَى بَيْتِي فَانْحَطَّتْ بِهِ وَتَلَقَّاهُ الْخَيْلُ قَبْلَ أَنْ يَصِلَ إِلَى بَيْتِهِ وَفِي عُنُقِ الْجَارِيَةِ طَوْقٌ لَهَا مِنْ وَرِقٍ فَتَلَقَّاهُ الرَّجُلُ فَاقْتَلَعَهُ مِنْ عُنُقِهَا قَالَتْ فَلَمَّا دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَدَخَلَ الْمَسْجِدَ أَتَاهُ أَبُو بَكْرٍ بِأَبِيهِ يَعُودُهُ فَلَمَّا رَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَلَّا تَرَكْتَ الشَّيْخَ فِي بَيْتِهِ حَتَّى أَكُونَ أَنَا آتِيهِ فِيهِ قَالَ أَبُو بَكْرٍ يَا رَسُولَ اللَّهِ هُوَ أَحَقُّ أَنْ يَمْشِيَ إِلَيْكَ مِنْ أَنْ تَمْشِيَ أَنْتَ إِلَيْهِ قَالَ فَأَجْلَسَهُ بَيْنَ يَدَيْهِ ثُمَّ مَسَحَ صَدْرَهُ ثُمَّ قَالَ لَهُ أَسْلِمْ فَأَسْلَمَ وَدَخَلَ بِهِ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَأْسُهُ كَأَنَّهُ ثَغَامَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيِّرُوا هَذَا مِنْ شَعْرِهِ ثُمَّ قَامَ أَبُو بَكْرٍ فَأَخَذَ بِيَدِ أُخْتِهِ فَقَالَ أَنْشُدُ بِاللَّهِ وَبِالْإِسْلَامِ طَوْقَ أُخْتِي فَلَمْ يُجِبْهُ أَحَدٌ فَقَالَ يَا أُخَيَّةُ احْتَسِبِي طَوْقَكِ","id":"Telah menceritakan kepada kami [Ya'kub] berkata, telah menceritakan kepada kami [Bapakku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Yahya bin Abbad bin Abdullah bin Zubair] dari [Bapaknya] dari neneknya [Asma binti Abu Bakar] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam wukuf di Dzi Thuwa, Abu Quhafah berkata kepada anak perempuannya yang paling kecil, 'Hai anakku, tampakkanlah aku pada Abu Qabis.\" -Asma berkata; Abu Quhafah adalah seorang yang buta- Anaknya lalu berkata, \" Lalu aku melakukan untuknya, Abu Quhafah lalu berkata, \"Wahai puteriku, apa yang kamu lihat?\"anaknya menjawab, \"Aku melihat gumpalan hitam yang sedang berkumpul.\" Abu Quhafah berkata, \"Itu adalah kuda tunggangan.\" Anaknya berkata lagi, \"Aku juga melihat seseorang yang berlari di antara kumpulan itu ke depan dan belakang.\" Abu Quhafah berkata, \"Wahai puteriku, itulah Wazi', yakni orang yang menyuruh kuda kuda agar maju kedepan.\" Anaknya berkata, \"Demi Allah, kumpulan itu bergerak!\" Abu Quhafah berkata, \"Demi Allah, jika kuda telah bergerak maka bersegeralah denganku ke rumahku.\" Lalu anak perempuan tersebut terjatuh dengan ayahnya, sehingga para penunggang pun menemukannya sebelum dia sampai ke rumahnya, dan di leher gadis itu terdapat kalung miliknya dari perak, lalu seseorang menemuinya dan melepaskan dari lehernya.\" Asma melanjutkan, \"Ketika Rasulullah shallallahu 'alaihi wasallam memasuki Makkah dan beliau masuk ke dalam masjid, Abu Bakar dan ayahnya datang menemui Rasulullah shallallahu 'alaihi wasallam, maka ketika Rasulullah shallallahu 'alaihi wasallam melihatnya beliau bersabda: \"Kenapa kamu tidak meninggalkan orang tua ini di rumahnya hingga aku dapat mendatanginya?\" Abu Bakar menjawab, \"Wahai Rasulullah, dia lebih berhak untuk berjalan menemuimu daripada tuan yang berjalan menemuinya.\" Asma berkata, \"Lalu beliau mendudukkan ayah Abu Bakar di sisinya lalu mengusap dadanya dan bersabda: \"Masuklah Islam.\" Maka dia pun masuk Islam. Dan Abu Bakar membawa ayahnya menemui Rasulullah shallallahu 'alaihi wasallam sementara dikepalanya seakan-akan tumbuhan berwarna putih, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ubahlah ini dari rambutnya, \" kemudian Abu Bakar berdiri dan memegang tangan saudarinya lalu berkata, \"Aku bersumpah kepada Allah dan Islam akan kalung saudariku.\" Namun tidak seorangpun menjawabnya.\" Abu Bakar lalu berkata, \"Wahai saudariku, mintalah kalungmu.\""},"3845":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي يَحْيَى بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ أَنَّ أَبَاهُ حَدَّثَهُ عَنْ جَدَّتِهِ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْلَمَّا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَرَجَ مَعَهُ أَبُو بَكْرٍ احْتَمَلَ أَبُو بَكْرٍ مَالَهُ كُلَّهُ مَعَهُ خَمْسَةَ آلَافِ دِرْهَمٍ أَوْ سِتَّةَ آلَافِ دِرْهَمٍ قَالَتْ وَانْطَلَقَ بِهَا مَعَهُ قَالَتْ فَدَخَلَ عَلَيْنَا جَدِّي أَبُو قُحَافَةَ وَقَدْ ذَهَبَ بَصَرُهُ فَقَالَ وَاللَّهِ إِنِّي لَأَرَاهُ قَدْ فَجَعَكُمْ بِمَالِهِ مَعَ نَفْسِهِ قَالَتْ قُلْتُ كَلَّا يَا أَبَتِ إِنَّهُ قَدْ تَرَكَ لَنَا خَيْرًا كَثِيرًا قَالَتْ فَأَخَذْتُ أَحْجَارًا فَتَرَكْتُهَا فَوَضَعْتُهَا فِي كُوَّةِ الْبَيْتِ كَانَ أَبِي يَضَعُ فِيهَا مَالَهُ ثُمَّ وَضَعْتُ عَلَيْهَا ثَوْبًا ثُمَّ أَخَذْتُ بِيَدِهِ فَقُلْتُ يَا أَبَتِ ضَعْ يَدَكَ عَلَى هَذَا الْمَالِ قَالَتْ فَوَضَعَ يَدَهُ عَلَيْهِ فَقَالَ لَا بَأْسَ إِنْ كَانَ قَدْ تَرَكَ لَكُمْ هَذَا فَقَدْ أَحْسَنَ وَفِي هَذَا لَكُمْ بَلَاغٌ قَالَتْ لَا وَاللَّهِ مَا تَرَكَ لَنَا شَيْئًا وَلَكِنِّي قَدْ أَرَدْتُ أَنْ أُسْكِنَ الشَّيْخَ بِذَلِكَ","id":"Telah menceritakan kepada kami [Ya'kub] berkata, telah menceritakan kepada kami [Bapakku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Yahya bin Abdullah bin Zubair] bahwa [bapaknya] telah menceritakan kepadanya dari neneknya [Asma' binti Abu Bakar] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam keluar dan Abu Bakar keluar bersama beliau, Abu Bakar membawa seluruh hartanya yang berjumlah lima ribu atau enam ribu dirham.\" Asma berkata, \"Abu Bakar pergi membawa uang tersebut.\" Asma berkata, \"Kakekku, Abu Quhafah (yang saat itu telah buta), lalu masuk menemui kami seraya berkata, \"Demi Allah, aku melihatnya telah memberi kalian musibah dengan harta dan dirinya!\" Asma menjawab, \"Aku lalu berkata, \"Sekali-kali tidak wahai kakekku! Sungguh, dia telah meninggalkan bagi kami kebaikan.\" Asma melanjutkan, \"Lalu aku mengambil batu-batuan dan meninggalkan lalu menaruhnya di pintu rumah, yang ayahku biasa menaruh harta di sana. Lantas aku meletakkan kain di atas bebatuan tersebut, setelah itu aku meraih tangannya dan berkata, \"Hai kakekku, taruhlah tanganmu di atas harta ini.\" Asma melanjutkan, \"Lalu dia menaruh tangannya di atasnya seraya berkata, \"Tidaklah mengapa jika dia meninggalkan untuk kalian harta ini, sungguh dia telah berbuat baik, dan dengan ini cukup untuk kalian.\" Asma berkata, \"Demi Allah, tidak! Abu Bakar tidak meninggalkan untuk kami sedikitpun, namun aku hanya ingin menenangkan hati kakekku dengan itu.\""},"3846":{"ar":"حَدَّثَنَا حَسَنٌ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا عُقَيْلُ بْنُ خَالِدٍ عَنِ ابْنِ شِهَابٍ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍأَنَّهَا كَانَتْ إِذَا ثَرَدَتْ غَطَّتْهُ شَيْئًا حَتَّى يَذْهَبَ فَوْرُهُ ثُمَّ تَقُولُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ أَعْظَمُ لِلْبَرَكَةِحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عُقَيْلٍ و حَدَّثَنَا عَتَّابٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ قَالَ أَنْبَأَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنِي عُقَيْلُ بْنُ خَالِدٍ عَنِ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ أَنَّهَا كَانَتْ إِذَا ثَرَدَتْ غَطَّتْهُ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Hasan] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] berkata, telah menceritakan kepada kami [Uqail bin Khalid] dari [Ibnu Syihab] dari [Asma' binti Abu Bakar] bahwa jika dia membuat roti, maka dia menutupinya dengan sesuatu hingga cepat jadi, lalu dia berkata, \"Sungguh, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, itu lebih barokah.\" [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] dari ['Uqail], dan telah menceritakan kepada kami ['Atab] berkata, telah menceritakan kepada kami [Abdullah] berkata; telah memberitakan kepada kami [Ibnu Lahi'ah] berkata; telah menceritakan kepadaku ['Uqail bin Khalid] dari [Ibnu Syihab] dari ['Urwah] dari [Asma' binti Abu Bakar] bahwa jika dia membuat roti, maka dia menutupinya…lalu dia menyebutkan (hadits) semisalnya.\""},"3847":{"ar":"حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا عِمْرَانُ بْنُ يَزِيدَ حَدَّثَنَا مَنْصُورٌ عَنْ أُمِّهِ عَنِ أَسْمَاءَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُهِلِّينَ بِالْحَجِّ فَقَالَتْ فَقَالَ لَنَا مَنْ كَانَ مَعَهُ هَدْيٌ فَلْيَقُمْ عَلَى إِحْرَامِهِ وَمَنْ لَمْ يَكُنْ مَعَهُ هَدْيٌ فَلْيَحْلِلْ","id":"Telah menceritakan kepada kami [Yunus] berkata, telah menceritakan kepada kami ['Imran bin Yazid] telah menceritakan kepada kami [Manshur] dari [Ibunya] dari [Asma'] dia berkata, \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam berniat untuk melaksanakan haji.\" Asma berkata, \"Beliau bersabda: \"Barangsiapa memiliki hadyu (kewajiban menyembelih kambing) maka hendaknya ia tetap dalam ihramnya, dan barangsiapa tidak memiliki hadyu hendaknya ia bertahallul.\""},"3848":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ قَالَتْدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنٍ لِي لَمْ يَطْعَمْ فَبَالَ عَلَيْهِ فَدَعَا بِمَاءٍ فَرَشَّهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari ['Ubaidillah] dari [Ummi Qais binti Mihshan] dia berkata, \"Aku menemui Nabi shallallahu 'alaihi wasallam bersama anakku yang belum bisa makan, lalu dia mengencingi beliau, kemudian beliau meminta air dan menyiram di atasnya.\""},"3849":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ أُخْتِ عُكَّاشَةَ بْنِ مِحْصَنٍ قَالَتْدَخَلْتُ بِابْنٍ لِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَأْكُلْ الطَّعَامَ فَبَالَ فَدَعَا بِمَاءٍ فَرَشَّهُ وَدَخَلْتُ بِابْنٍ لِي قَدْ أَعْلَقْتُ عَنْهُ وَقَالَ مَرَّةً عَلَيْهِ مِنْ الْعُذْرَةِ فَقَالَ عَلَامَ تَدْغَرْنَ أَوْلَادَكُنَّ بِهَذَا الْعِلَاقِ عَلَيْكُمْ بِهَذَا الْقُسْطِ وَقَالَ مَرَّةً سُفْيَانُ الْعُودِ الْهِنْدِيِّ فَإِنَّ بِهِ سَبْعَةَ أَشْفِيَةٍ مِنْهَا ذَاتُ الْجَنْبِ يُسْعَطُ مِنْ الْعُذْرَةِ وَيُلَدُّ مِنْ ذَاتِ الْجَنْبِ","id":"Telah menceritakan kepada kami [Sufyan] dari [AzZuhri] dari ['Ubaidullah] dari [Ummu Qais binti Mihshan] saudara perempuannya Ukasah bin Mihshan, dia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam bersama anak laki-lakiku yang belum bisa makan, kemudian dia kencing, maka beliau meminta air lalu menyiramnya. Aku juga pernah menemui beliau dengan anak laki-lakiku yang aku memakaikan kalung di lehernya -sekali waktu ia menyebutkan; karena sakit-, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kenapa kalian menggantungkankan kalung ini pada anak kalian yang sakit? Hendaknya kalian memakai kust (sejenis kayu) ini.\" Sekali waktu Sufyan menyebutkan, \"Kayu Hindi, karena di dalamnya ada tujuh macam kesembuhan, di antaranya; penyakit tulang rusuk, bisa menyembuhkan penyakit dan menghilangkan penyakit tulang rusuk.\""},"3850":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي ثَابِتٌ أَبُو الْمِقْدَامِ قَالَ حَدَّثَنِي عَدِيُّ بْنُ دِينَارٍ قَالَ سَمِعْتُ أُمَّ قَيْسٍ بِنْتَ مِحْصَنٍ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الثَّوْبِ يُصِيبُهُ دَمُ الْحَيْضِ قَالَ حُكِّيهِ بِضِلَعٍ وَاغْسِلِيهِ بِالْمَاءِ وَالنَّدِّ وَسِدْرٍ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] berkata, telah menceritakan kepadaku [Tsabit Abu Miqdam] berkata, telah menceritakan kepadaku ['Ady bin Dinar] berkata kepadaku, dia berkata, \"Aku mendengar [Ummi Qais binti Mihshan] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam tentang pakaian yang terkena darah haid, beliau bersabda: \"Keriklah ia dengan kayu dan cucilah dengan air, wewangian dan daun bidara.\""},"3851":{"ar":"حَدَّثَنَا حَجَّاجٌ وهَاشِمٌ قَالَا حَدَّثَنَا لَيْثٌ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي الْحَسَنِ مَوْلَى أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ عَنْ أُمِّ قَيْسٍ أَنَّها قَالَتْتُوُفِّيَ ابْنِي فَجَزِعْتُ عَلَيْهِ فَقُلْتُ لِلَّذِي يَغْسِلُهُ لَا تَغْسِلْ ابْنِي بِالْمَاءِ الْبَارِدِ فَتَقْتُلَهُ فَانْطَلَقَ عُكَّاشَةُ بْنُ مِحْصَنٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِقَوْلِهَا فَتَبَسَّمَ ثُمَّ قَالَ مَا قَالَتْ طَالَ عُمْرُهَاقَالَ فَلَا أَعْلَمُ امْرَأَةً عُمِّرَتْ مَا عُمِّرَتْ","id":"Telah menceritakan kepada kami [Hajjaj] dan [Hasyim] keduanya berkata, telah menceritakan kepada kami [Laits] berkata, telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Abu Al Hasan] bekas budaknya Ummu Qais, dari [Ummi Qais] dia berkata, anakku meninggal dan aku menderita sakit karenanya, lalu aku berkata kepada yang memandikannya, \"Janganlah kamu memandikan anakku dengan air yang dingin karena kamu bisa membunuhnya.\" kemudian 'Ukasyah bin Mihshan pergi menemui Rasulullah shallallahu 'alaihi wasallam dan mengabari beliau apa yang dikatakannya, maka beliaupun tersenyum kemudian bersabda: \"Dia tidak mengatakan umurnya akan panjang.\" Ukasyah berkata, \"Aku tidak tahu wanita lain yang diberi umur seperti umurnya.\""},"3852":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أُمِّْ قَيْسٍ بِنْتِ مِحْصَنٍ الْأَسَدِيَّةِ أُخْتِ عُكَّاشَةَ قَالَتْجِئْتُ بِابْنٍ لِي قَدْ أَعْلَقْتُ عَنْهُ أَخَافُ أَنْ يَكُونَ بِهِ الْعُذْرَةُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَامَ تَدْغَرْنَ أَوْلَادَكُنَّ بِهَذِهِ الْعَلَائِقِ عَلَيْكُنَّ بِهَذَا الْعُودِ الْهِنْدِيِّ قَالَ يَعْنِي الْكُسْتَ فَإِنَّ فِيهِ سَبْعَةَ أَشْفِيَةٍ مِنْهَا ذَاتُ الْجَنْبِ ثُمَّ أَخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَبِيَّهَا فَوَضَعَهُ فِي حِجْرِهِ فَبَالَ عَلَيْهِ فَدَعَا بِمَاءٍ فَنَضَحَهُ وَلَمْ يَكُنْ الصَّبِيُّ بَلَغَ أَنْ يَأْكُلَ الطَّعَامَقَالَ الزُّهْرِيُّ فَمَضَتْ السُّنَّةُ بِأَنْ يُرَشَّ بَوْلُ الصَّبِيِّ وَيُغْسَلَ بَوْلُ الْجَارِيَةِ قَالَ الزُّهْرِيُّ فَيُسْتَسْعَطُ لِلْعُذْرَةِ وَيُلَدُّ لِذَاتِ الْجَنْبِ","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ummu Qais binti Mihshan Al Asadiyah] saudara perempuannya Ukasah, dia berkata, \"Aku datang bersama anak laki-lakiku yang aku pakaikan kalung di lehernya, karena khawatir jika ia terkena penyakit. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Kenapa kalian menggantungkankan kalung ini di bagian yang sakit pada anak kalian, hendaknya kalian memakai kayu Hindy ini.\" -perawi berkata; yakni al kust (sejenis kayu beraroma wangi) - karena di dalamnya ada tujuh macam kesembuhan, di antaranya penyakit tulang rusuk.\" Kemudian Nabi shallallahu 'alaihi wasallam mengambil anak tersebut dan meletakkannya pangkuan beliau, namun anak itu mengencinginya hingga beliau minta diambilkan air seraya memercikinya, dan anak itu belum memakan makanan.\" Az Zuhry berkata, \"Maka berlakulah sunnah bahwa kencingnya bayi laki-laki itu cukup diperciki, sedangkan anak perempuan dicucui.\" Az Zuhry berkata, \"Maka ia (kayu Hindi) dapat menyembuhkan penyakit dan mencegah penyakit tulang rusuk.\""},"3853":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلُ عَنْ ثَابِتٍ أَبِي الْمِقْدَامِ عَنْ عَدِيِّ بْنِ دِينَارٍ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ دَمِ الْحَيْضِ يُصِيبُ الثَّوْبَ فَقَالَ حُكِّيهِ وَلَوْ بِضِلَعٍ","id":"Telah menceritakan kepada kami [Waki'] dari [Israil] dari [Tsabit Abu Miqdam] dari [Adi bin Dinar] dari [Ummu Qais binti Mihshan] dia berkata, \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang darah haid yang mengenai pakaian, beliau bersabda: \"Keriklah ia walaupun dengan kayu.\""},"3854":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ثَابِتٍ عَنْ عَدِيِّ بْنِ دِينَارٍ مَوْلَى أُمِّ قَيْسٍ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ دَمِ الْحَيْضِ يُصِيبُ الثَّوْبَ فَقَالَ اغْسِلِيهِ بِمَاءٍ وَسِدْرٍ وَحُكِّيهِ بِضِلَعٍ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sufyan] dari [Tsabit] dari [Adi bin Dinar] bekas budak Ummu Qais, dari [Ummu Qais binti Mihshan] dia berkata, \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang darah haid yang mengenai pakaian, beliau bersabda: \"Cucilah ia dengan air yang dicampur daun bidara dan gosoklah dengan kayu.\""},"3855":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَخْبَرَنَا يُونُسُ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ أُمَّ قَيْسٍ بِنْتَ مِحْصَنٍ إِحْدَى بَنِي أَسَدِ بْنِ خُزَيْمَةَ وَكَانَتْ مِنْ الْمُهَاجِرَاتِ الْأُوَلِ اللَّائِي بَايَعْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَخْبَرَتْنِي أَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنٍ لَهَا لَمْ يَبْلُغْ أَنْ يَأْكُلَ الطَّعَامَ فَذَكَرَ الْحَدِيثَ وَقَالَ عَلَامَ تَدْغَرْنَ أَوْلَادَكُنَّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَقَالَ حَدَّثَنَا مَعْمَرٌ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ أُمِّْ قَيْسٍ بِنْتِ مِحْصَنٍأَنَّهَا جَاءَتْ بِابْنٍ لَهَا وَقَدْ أَعْلَقَتْ عَلَيْهِ مِنْ الْعُذْرَةِ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَامَ تَدْغَرْنَ أَوْلَادَكُنَّ بِهَذِهِ الْعُلُقِ عَلَيْكُنَّ بِهَذَا الْعُودِ الْهِنْدِيِّ فَإِنَّ فِيهِ سَبْعَةَ أَشْفِيَةٍ مِنْهَا ذَاتُ الْجَنْبِ ثُمَّ أَخَذَ الصَّبِيَّ فَبَالَ عَلَيْهِ فَدَعَا بِمَاءٍ فَنَضَحَهُقَالَ ابْنُ شِهَابٍ مَضَتْ السُّنَّةُ بِذَلِكَ","id":"Telah menceritakan kepada kami [Utsman bin Umar] berkatam telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] bahwa [Ummu Qais binti Mihshan] -seorang wanita dari Bani Asad bin Khuzaimah, dan dia termasuk wanita yang pertama kali berhijrah, yang berbaiat kepada Rasulullah shallallahu 'alaihi wasallam- dia berkata, \"Ummu Qais mengabarkan kepadaku bahwa dia pernah menemui Rasulullah shallallahu 'alaihi wasallam dengan anaknya yang belum bisa menelan makanan, lalu dia menyebutkan hadits. Beliau bersabda: \"Atas dasar apa kalian menekan bagian yang sakit pada anak kalian?\" Abdullah berkata; telah menceritakan kepada kami [Muhammad bin Ja'far], dan telah menceritakan kepada kami [Ma'mar] berkata; telah menceritakan kepada kami [Az Zuhr] dari [Ubidullah bin Utbah bin Mas'ud] dari [Ummu Qais binti Mihshan] bahwa dia datang dengan anaknya dan dia memakaikan kalung dilehernya karena sakit di tenggorokannya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Atas dasar apa kalian menekah pada bagian yang sakit anak kalian dengan mengantungkan benda ini? hendaklah kalian pakaikan kayu Hindi ini, karena di dalamnya tujuh macam kesembuhan, di antaranya penyakit tulang rusuk.\" Lalu beliau meraih anak itu, namun ia mengencingi beliau, beliau lantas minta air dan menyiramnya.\" Ibnu Syihab berkata, \"Maka berlakukan sunnah seperti itu.\""},"3856":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنِ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ سَهْلَةَ امْرَأَةِ أَبِي حُذَيْفَةَ أَنَّهَا قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ سَالِمًا مَوْلَى أَبِي حُذَيْفَةَ يَدْخُلُ عَلَيَّ وَهُوَ ذُو لِحْيَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْضِعِيهِ فَقَالَتْ كَيْفَ أُرْضِعُهُ وَهُوَ ذُو لِحْيَةٍ فَأَرْضَعَتْهُ فَكَانَ يَدْخُلُ عَلَيْهَا","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami [Hammad] -yakni Ibnu Salamah- dari ['Abdurrahman bin Al Qasim] dari [Al Qasim bin Muhammad] dari [Shalah] istri Abu Hudzaifah, dia berkata, \"Aku berkata, \"Wahai Rasulullah, sesungguhnya Salim, bekas budak Abu Hudzaifah, masuk rumahku sedang dia sudah tumbuh jenggotnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Susuilah dia.\" Isteri Abu Hudzaifah berkata, \"Bagaimana aku menyusuinya sedangkan jenggotnya telah tumbuh?\" Namuan kemudian ia menyusuinya sehingga Salim pun bisa masuk ke dalam rumahnya.\""},"3857":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ سَمِعَ ابْنُ الْمُنْكَدِرِ أُمَيْمَةَ بِنْتَ رُقَيْقَةَ تَقُولُبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ فَلَقَّنَنَا فِيمَا اسْتَطَعْتُنَّ وَأَطَقْتُنَّ قُلْتُ اللَّهُ وَرَسُولُهُ أَرْحَمُ مِنَّا مِنْ أَنْفُسِنَا قُلْتُ يَا رَسُولَ اللَّهِ بَايِعْنَا قَالَ إِنِّي لَا أُصَافِحُ النِّسَاءَ إِنَّمَا قَوْلِي لِامْرَأَةٍ قَوْلِي لِمِائَةِ امْرَأَةٍ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] berkata; [Ibnu Munkadir] mendengar [Umaimah binti Ruqaiqah] berkata, \"Aku membaiat Rasulullah shallallahu 'alaihi wasallam dengan beberapa wanita, lalu beliau mentalqin kami pada apa yang kami bisa dan mampu. Aku berkata, \"Allah dan Rasul-Nya lebih menyayangi kita daripada diri kita. Aku pun berkata, \"Wahai Rasulullah, baatlah kami!\" Beliau bersabda: 'Sesungguhnya aku tidak menjabat tangan wanita, hanyasanya perkataanku untuk seorang wanita sebagaimana perkataanku untuk seratus wanita.\""},"3858":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ أُمَيْمَةَ بِنْتِ رُقَيْقَةَ التَّيْمِيَّةِ قَالَتْأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ مِنْ الْمُسْلِمِينَ لِنُبَايِعَهُ فَقُلْنَا يَا رَسُولَ اللَّهِ جِئْنَا لِنُبَايِعَكَ عَلَى أَنْ لَا نُشْرِكَ بِاللَّهِ شَيْئًا وَلَا نَسْرِقَ وَلَا نَزْنِيَ وَلَا نَقْتُلَ أَوْلَادَنَا وَلَا نَأْتِيَ بِبُهْتَانٍ نَفْتَرِيهِ بَيْنَ أَيْدِينَا وَأَرْجُلِنَا وَلَا نَعْصِيَكَ فِي مَعْرُوفٍ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا اسْتَطَعْتُنَّ وَأَطَعْتُنَّ قَالَتْ قُلْنَا اللَّهُ وَرَسُولُهُ أَرْحَمُ بِنَا مِنْ أَنْفُسِنَا بَايِعْنَا يَا رَسُولَ اللَّهِ قَالَ اذْهَبْنَ فَقَدْ بَايَعْتُكُنَّ إِنَّمَا قَوْلِي لِمِائَةِ امْرَأَةٍ كَقَوْلِي لِامْرَأَةٍ وَاحِدَةٍ قَالَتْ وَلَمْ يُصَافِحْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنَّا امْرَأَةً","id":"Telah menceritakan kepada kami [Ya'kub bin Ibrahim] berkata, telah menceritakan kepadaku [Bapakku] dari [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Muhammad bin Al Munkadir] dari [Umaimah binti Ruqaiqah At Taimiyah] dia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam dengan beberapa wanita dari kaum Muslimin untuk berbaiat kepada beliau, kami berkata, \"Wahai Rasulullah, kami datang membaiatmu untuk tidak menyekutukan Allah dengan sesutu pun, tidak mencuri, tidak berzina, tidak akan membunuh anak-anak kami, tidak akan berbuat dusta yang mereka ada-adakan antara tangan dan kaki kami dan tidak akan mendurhakaimu dalam urusan yang baik.\" Umaimah berkata, \"Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menurut kemampuan kalian dan ketaatan kalian.\" Umaimah berkata, \"Kami berkata, \"Allah dan Rasul-Nya lebih menyayangi kita daripada diri kita, wahai Rasulullah, baiatlah kami!\" Beliau bersabda: \"Pergilah, sesungguhnya aku telah membaiat kalian semua, hanyasanya perkataanku untuk seratus wanita sebagaimana perkatanku untuk satu orang wanita.\" Umaimah berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak menjabat tangan wanita dari kami.\""},"3859":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى قَالَ أَخْبَرَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أُمَيْمَةَ بِنْتِ رُقَيْقَةَ أَنَّها قَالَتْأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ نُبَايِعُهُ فَقُلْنَا يَا رَسُولَ اللَّهِ نُبَايِعُكَ عَلَى أَنْ لَا نُشْرِكَ بِاللَّهِ شَيْئًا وَلَا نَسْرِقَ وَلَا نَزْنِيَ وَلَا نَأْتِيَ بِبُهْتَانٍ نَفْتَرِيهِ بَيْنَ أَيْدِينَا وَأَرْجُلِنَا وَلَا نَعْصِيَكَ فِي مَعْرُوفٍ قَالَ قَالَ فِيمَا اسْتَطَعْتُنَّ وَأَطَعْتُنَّ قَالَتْ فَقُلْنَا اللَّهُ وَرَسُولُهُ أَرْحَمُ بِنَا مِنَّا بِأَنْفُسِنَا هَلُمَّ نُبَايِعُكَ يَا رَسُولَ اللَّهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَا أُصَافِحُ النِّسَاءَ إِنَّمَا قَوْلِي لِمِائَةِ امْرَأَةٍ كَقَوْلِي لِامْرَأَةٍ وَاحِدَ��ٍ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] berkata, telah mengabarkan kepada kami [Malik] dari [Muhammad bin Al Munkadir] dari [Umaimah binti Ruqaiqah] bahwa dia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam bersama para wanita untuk membaiatnya. Kami katakanm \"Wahai Rasulullah, kami membaiatmu untuk tidak menyekutukan Allah dengan sesuatu apapun, tidak mencuri, tidak berzina, tidak berdusta yang kami ada-adakan antara tangan dan kaki kami, dan tidak durhaka terhadap tuan dalam hal yang ma'ruf.\" Umaimah berkata, \"Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Menurut kemampuan dan ketaatan kalian.\" Umaimah berkata, \"Kemudian kami berkata, \"Allah dan Rasul-Nya lebih menyayangi kita daripada diri kita, kemarilah wahai Rasulullah, kami akan membaiatmu. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku tidak berjabat tangan wanita, hanyasanya perkataanku untuk seratus wanita sebagaimana perkataanku untuk satu orang wanita.\""},"3860":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدٍ يَعْنِي ابْنَ الْمُنْكَدِرِ عَنْ أُمَيْمَةَ بِنْتِ رُقَيْقَةَ قَالَتْأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسَاءٍ نُبَايِعُهُ فَأَخَذَ عَلَيْنَا مَا فِي الْقُرْآنِ أَنْ لَا نُشْرِكَ بِاللَّهِ شَيْئًا الْآيَةَ قَالَ فِيمَا اسْتَطَعْتُنَّ وَأَطَعْتُنَّ قُلْنَا اللَّهُ وَرَسُولُهُ أَرْحَمُ بِنَا مِنْ أَنْفُسِنَا قُلْنَا يَا رَسُولَ اللَّهِ أَلَا تُصَافِحُنَا قَالَ إِنِّي لَا أُصَافِحُ النِّسَاءَ إِنَّمَا قَوْلِي لِامْرَأَةٍ وَاحِدَةٍ كَقَوْلِي لِمِائَةِ امْرَأَةٍ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sufyan] dari [Muhammad] -yakni Ibnu Munkadir- dari [Umaimah binti Ruqaiqah] dia berkata, \"Aku mendatangi Nabi shallallahu 'alaihi wasallam bersama dengan para wanita untuk membaiatnya, maka beliau mengambil (membaiat) atas kami sebagaimana yang ada dalam Al Qur'an '(kami tidak menyekutukan Allah dengan sesuatu pun) ', beliau bersabda: \"Menurut kemampuan dan ketaatan kalian.\" Kami berkata, \"Allah dan Rasul-Nya lebih menyayangi kita daripada diri kita, kami berkata, \"Wahai Rasulullah, tidakkah tuan menjabat tangan kami?\" Beliau bersabda: \"Sesungguhnya perkataanku untuk satu orang wanita sebagaimana perkataanku untuk seratus wanita.\""},"3861":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ أُمَيْمَةَ بِنْتَ رُقَيْقَةَ تُحَدِّثُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَسْتُ أُصَافِحُ النِّسَاءَ إِنَّمَا قَوْلِي لِامْرَأَةٍ وَاحِدَةٍ كَقَوْلِي لِمِائَةِ امْرَأَةٍ","id":"Telah menceritakan kepada kami [Waki'] dia berkata, telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir] dia berkata, aku mendengar [Umaimah binti Ruqaiqah] menceritakan, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Aku tidak menjabat tangan seorang wanita, hanyasanya perkataanku untuk satu orang wanita sebagaimana perkataanku untuk seratus orang wanita.\""},"3862":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنِي سُفْيَانُ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنِ امْرَأَتِهِ عَنْ أُخْتِ حُذَيْفَةَ قَالَتْخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مَعْشَرَ النِّسَاءِ أَمَا لَكُنَّ فِي الْفِضَّةِ مَا تَحَلَّيْنَ أَمَا إِنَّهُ لَيْسَ مِنْكُنَّ امْرَأَةٌ تَحَلَّى ذَهَبًا تُظْهِرُهُ إِلَّا عُذِّبَتْ بِهِحَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ امْرَأَتِهِ عَنِ أُخْتِ خُذَيْفَةَ قَالَتْ خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata, telah menceritakan kepadaku [Sufyan] dari [Manshur] dari [Rib'i] dari [istrinya] dari [saudara perempuannya Khudzaifah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami, beliau bersabda: \"Wahai para wanita, silahkan kalian berhias dengan perak terserah kalian, namun ketahuilah bahwa tidaklah seseorang diantara kalian berhias dengan emas, kemudian ia tampakkan, kecuali ia akan disiksa.\" Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Mansur] dari [Rib'i bin Hirasy] dari [istrinya] dari [saudari Hudzaifah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami….lalu dia menyebutkan (hadits) semisalnya.\""},"3863":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنْ امْرَأَتِهِ عَنْ أُخْتِ حُذَيْفَةَ وَكُنَّ لَهُ أَخَوَاتٌ قَدْ أَدْرَكْنَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْخَطَبَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مَعْشَرَ النِّسَاءِ أَلَيْسَ لَكُنَّ فِي الْفِضَّةِ مَا تَحَلَّيْنَ أَمَا إِنَّهُ لَيْسَتْ مِنْكُنَّ امْرَأَةٌ تَتَحَلَّى ذَهَبًا تُظْهِرُهُ إِلَّا عُذِّبَتْ بِهِ","id":"Telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Rib'i] dari [istrinya] dari [saudarinya Khudzaifah] dan dia mempunyai beberapa saudari perempuan, \"Sungguh mereka telah bertemu Nabi shallallahu 'alaihi wasallam, dia berkata, \"Nabi shallallahu 'alaihi wasallam berkhutbah kepada kami, beliau katakan: \"Wahai para wanita, silahkan kalian berhias dengan perak terserah kalian, namun ketahuilah bahwa tidaklah seseorang diantara kalian berhias dengan emas, kemudian ia tampakkan, kecuali ia akan disiksa.\""},"3864":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ النُّعْمَانِ قَالَ سَمِعْتُ طَلْحَةَ الْأَيَامِيَّ يُحَدِّثُ وَيَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ النُّعْمَانِ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنِ امْرَأَةٍ مِنْ بَنِي عَبْدِ الْقَيْسِ عَنْ أُخْتِ عَبْدِ اللَّهِ بْنِ رَوَاحَةَ الْأَنْصَارِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ وَجَبَ الْخُرُوجُ عَلَى كُلِّ ذَاتِ نِطَاقٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Nu'man] berkata, aku mendengar [Thalhah Al Ayyamiy] menceritakan, dan [Yahya bin Sa'id] dari [Syu'bah] berkata, telah mengabarkan kepadaku [Muhammad bin An Nu'man] dari [Thalhah bin Musharif] dari [seorang wanita] dari bani 'Abdul Qais, dari [saudarinya Abdullah bin Rawahah Al Anshari] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Wajib keluar yang telah menggunakan ikat pinggang.\""},"3865":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ قَالَ حَدَّثَتْنِي الرُّبَيِّعُ بِنْتُ مُعَوِّذِ ابْنِ عَفْرَاءَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِينَا فَيُكْثِرُ فَأَتَانَا فَوَضَعْنَا لَهُ الْمِيضَأَةَ فَتَوَضَّأَ فَغَسَلَ كَفَّيْهِ ثَلَاثًا وَمَضْمَضَ وَاسْتَنْشَقَ مَرَّةً مَرَّةً وَغَسَلَ وَجْهَهُ ثَلَاثًا وَذِرَاعَيْهِ ثَلَاثًا وَمَسَحَ رَأْسَهُ بِمَا بَقِيَ مِنْ وَضُوئِهِ فِي يَدَيْهِ مَرَّتَيْنِ بَدَأَ بِمُؤَخَّرِهِ ثُمَّ رَدَّ يَدَهُ إِلَى نَاصِيَتِهِ وَغَسَلَ رِجْلَيْهِ ثَلَاثًا وَمَسَحَ أُذُنَيْهِ مُقَدَّمَهُمَا وَمُؤَخَّرَهُمَا","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdullah bin Muhammad bin Aqil] berkata, telah menceritakan kepadaku [Ar Rubayi' binti Mu'awidz bin Afra'] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendatangi kami dalam keadaan berdebu, kemudian kami menaruh untuknya bejana untuk berwudlu, maka beliau pun berwudlu. Beliau mencuci kedua telapaknya tangannya tiga kali, berkumur-kumur dan memasukkan air ke hidung (istinsyaq) sekali-sekali, kemudian membasuh mukanya tiga kali dan lengannya tiga kali, lalu mengusap kepalanya dari air sisa wudlunya yang ada di tangannya dua kali, beliau memulai dari pangkalnya kemudian mengembalikan tangannya sampai ke ujungnya, kemudian beliau mencuci kakinya tiga kali dan membasuh kedua telinganya dari pangkal dan akhirnya.\""},"3866":{"ar":"حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ خَالِدِ بْنِ ذَكْوَانَ عَنِ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَ قَالَتْكُنَّا نَغْزُو مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَسْقِي الْقَوْمَ وَنَخْدُمُهُمْ وَنَرُدُّ الْجَرْحَى وَالْقَتْلَى إِلَى الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Bisyr bin Al Mufadlal] dari [Khalid bin Dzakwan] dari [Rubayi' binti Mu'awidz bin 'Afra'] dia berkata, \"Kami berperang bersama Rasulullah shallallahu 'alaihi wasallam, kami memberi minum orang-orang dan membantu keperluan mereka, mengembalikan yang terluka dan yang gugur ke Madinah.\""},"3867":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنِ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَ قَالَتْأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعْنَا لَهُ الْمِيضَأَةَ فَتَوَضَّأَ ثَلَاثًا ثَلَاثًا وَمَسَحَ بِرَأْسِهِ مَرَّتَيْنِ بَدَأَ بِمُؤَخَّرِهِ وَأَدْخَلَ أُصْبُعَيْهِ فِي أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Muhammad bin Aqil] dari [Ar Rubayi' binti Muawidz bin Afra'] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemui kami, kemudian kami meletakkan untuknya sebuah tempat wudlu hingga beliau pun tiga kali-tiga kali dan membasuh kepalanya dua kali. Beliau memulainya dari ujungnya, kemudian memasukkan kedua jarinya pada kedua telinganya.\""},"3868":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنِ ابْنِ عَقِيلٍ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذٍ قَالَتْأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقِنَاعٍ فِيهِ رُطَبٌ وَأَجْرُ زُغْبٍ فَوَضَعَ فِي يَدِي شَيْئًا فَقَالَ تَحَلَّيْ بِهَذَا وَاكْتَسِي بِهَذَا","id":"Telah menceritakan kepada kami [Waki'] dari [Syarik] dari [Ibnu Aqil] dari [Rubayi' binti Mu'widz] dia berkata, \"Aku mendatangi Rasulullah shallallahu 'alaihi wasallam dengan membawa keranjang kurma ruthab dan ketimun yang masih muda, lalu beliau meletakkan di tanganku sesuatu dan bersabda: \"Berhiaslah dengan ini dan pakailah ini.\""},"3869":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ وَمُهَنَّأُ بْنُ عَبْدِ الْحَمِيدِ أَبُو شِبْلٍ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ خَالِدِ بْنِ ذَكْوَانَ قَالَ عَبْدُ الصَّمَدِ فِي حَدِيثِهِ حَدَّثَنَا أَبُو الْحُسَيْنِ عَنِ الرُّبَيِّعِ وَقَالَ خَالِدٌ فِي حَدِيثِهِ قَالَ حَدَّثَتْنِي الرُّبَيِّعُ بِنْتُ مُعَوِّذِ ابْنِ عَفْرَاءَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عُرْسِي فَقَعَدَ فِي مَوْضِعِ فِرَاشِي هَذَا وَعِنْدِي جَارِيَتَانِ تَضْرِبَانِ بِالدُّفِّ وَتَنْدُبَانِ آبَائِي الَّذِينَ قُتِلُوا يَوْمَ بَدْرٍ فَقَالَتَا فِيمَا تَقُولَانِ وَفِينَا نَبِيٌّ يَعْلَمُ مَا يَكُونُ فِي الْيَوْمِ وَفِي غَدٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا هَذَا فَلَا تَقُولَاهُ","id":"Telah menceritakan kepada kami [Abdus Shamad] dan [Muhanna' bin Abdul Hamid Abu Syibl] keduanya berkata, telah menceritakan kepada kami [Hammad] dari [Khalid bin Dzakwan], [Abdus Shamad] menyebutkan dalam haditsnya; telah menceritakan kepada kami [Abu Al Husain] dari [Rubayi'], dan [Khalid] menyebutkan dalam haditsnya, dia berkata, \"Rubayi' bin Mu'awidz bin 'Afra' menceritakan kepadaku, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam datang di hari pernikahanku, beliau duduk di kasurku ini. sementara aku mempunyai dua budak wanita yang sedang menabuh duff (gendang) dan mengisahkan tentang orang tuaku yang terbunuh pada perang Badar, di antara yang mereka dendangkan adalah, 'Di antara kita ada seorang Nabi yang mengetahui kejadian pada hari ini dan esok hari', kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adapun tentang ini maka janganlah kalian mengatakannya.\""},"3870":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ قَالَ أَخْبَرَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنِ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَ قَالَتْأَهْدَيْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِنَاعًا مِنْ رُطَبٍ وَأَجْرٍ زُغْبٍ قَال��تْ فَأَعْطَانِي مِلْءَ كَفَّيْهِ حُلِيًّا أَوْ قَالَ ذَهَبًا فَقَالَ تَحَلَّيْ بِهَذَا","id":"Telah menceritakan kepada kami [Abu Salamah Al Khuza'i] berkata, telah mengabarkan kepada kami [Syarik] dari [Abdullah bin Muhammad bin Aqil] dari [Ar Rubayi' binti Al Mu'awidz bin Afra'] dia berkata, \"Aku memberi hadiah kepada Rasulullah shallallahu 'alaihi wasallam satu keranjang kurma segar dan mentimun yang masih muda, kemudian beliau meletakkan di tanganku satu genggam batu permata -atau ia mengatakan; emas- seraya bersabda: \"Berhiaslah dengan ini.\""},"3871":{"ar":"حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا لَيْثٌ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلِ بْنِ أَبِي طَالِبٍ عَنِ الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ عِنْدَهَا فَمَسَحَ الرَّأْسَ كُلَّهُ مِنْ فَوْقِ الشَّعْرِ كُلِّ نَاحِيَةٍ لِمُنْصَبِّ الشَّعْرِ لَا يُحَرِّكُ الشَّعْرَ عَنْ هَيْئَتِهِ","id":"Telah menceritakan kepada kami [Yunus] berkata, telah menceritakan kepada kami [Laits] dari [Muhammad bin Ajlan] dari [Abdullah bin Muhammad bin Aqil bin Abu Thalib] dari [Ar Rubayi' binti Mu'awidz bin 'Afra'] bahwa Rasulullah shallallahu 'alaihi wasallam berwudlu di sampingnya, maka beliau membasuh kepala semuanya dari atas rambut sampai kecelah-celah rambutnya, beliau tidak merubah posisi rambut dari asalnya.\""},"3872":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ ذَكْوَانَ قَالَ حَدَّثَتْنِي رُبَيِّعُ بِنْتُ مُعَوِّذٍ قَالَتْبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قُرَى الْأَنْصَارِ قَالَ مَنْ كَانَ مِنْكُمْ صَائِمًا فَلْيُتِمَّ صَوْمَهُ وَمَنْ كَانَ أَكَلَ فَلْيَصُمْ بَقِيَّةَ يَوْمِهِ","id":"Telah menceritakan kepada kami ['Affan] dia berkata, telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] dia berkata, telah menceritakan kepada kami [Khalid bin Dzakwan] dia berkata, telah menceritakan kepadaku [Rubayi' binti Mu'awidz] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutus pada perkampungan Anshar seraya bersabda: \"Barangsiapa di antara kalian berpuasa hendaknya ia menyempurnakan puasanya, barangsiapa telah makan maka hendaknya ia berpuasa pada sisa harinya.\""},"3873":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا أَبُو حُسَيْنٍ قَالَكَانَ يَوْمٌ لِأَهْلِ الْمَدِينَةِ يَلْعَبُونَ فَدَخَلْتُ عَلَى الرُّبَيِّعِ بِنْتِ مُعَوِّذِ ابْنِ عَفْرَاءَ فَقَالَتْ دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَعَدَ عَلَى مَوْضِعَ فِرَاشِي هَذَا وَعِنْدِي جَارِيَتَانِ تَنْدُبَانِ آبَائِي الَّذِينَ قُتِلُوا يَوْمَ بَدْرٍ تَضْرِبَانِ بِالدُّفُوفِ وَقَالَ عَفَّانُ مَرَّةً بِالدُّفِّ فَقَالَتَا فِيمَا تَقُولَانِ وَفِينَا نَبِيٌّ يَعْلَمُ مَا يَكُونُ فِي غَدٍ فَقَالَ أَمَّا هَذَا فَلَا تَقُولَاهُ","id":"Telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Hammad bin Salamah] berkata, telah menceritakan kepada kami [Abu Husain] berkata, \"Suatu hari penduduk Madinah mengadakan permainan, kemudian aku menemui [Rubayi' binti Mu'awidz bin Afra'], dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemuiku, kemudian beliau duduk di salah satu dipanku ini, sedangkan aku memiliki dua orang pelayan perempuan yang sedang menabuh rebana mengenang para bapak-bapak mereka yang terbunuh pada waktu perang Badar. -Sekali waktu Affan menyebutkan 'rebana'- Dan di antara yang mereka dendangkan adalah, 'Di antara kami ada seorang nabi yang mengetahui perihal esok hari', maka beliau bersabda: \"Adapun yang ini, hendaklah kalian berdua tidak mengucapkannya.\""},"3874":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا لَيْثٌ عَنِ ابْنِ عَجْلَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنِ الرُّبَيِّعِ بِنْتِ مُعَوِّذٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ عِنْدَهَا فَمَسَحَ بِرَأْسِهِ الرَّأْسِ كُلِّهِ مِنْ وَرَاءِ الشَّعْرِ كُلَّ نَاحِيَةٍ لِمُنْصَبِّ الشَّعْرِ لَا يُحَرِّكُ الشَّعْرَ عَنْ هَيْئَتِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Laits] dari [Ibnu Ajlan] dari [Abdullah bin Muhammad bin Aqil] dari [Ar Rubayi' binti Mu'awidz] bahwa Rasulullah shallallahu 'alaihi wasallam berwudlu di sisinya, beliau lalu membasuh kepala semuanya, dari belakang rambut sampai sisi rambut, sedangkan beliau tidak menggeser posisi rambutnya.\""},"3875":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الرَّازِيُّ قَالَ حَدَّثَنَا سَلَمَةُ بْنُ الْفَضْلِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَاقَ عَنِ الْخَطَّابِ بْنِ صَالِحٍ عَنْ أُمِّهِ قَالَتْ حَدَّثَتْنِي سَلَامَةُ بِنْتُ مَعْقِلٍ قَالَتْكُنْتُ لِلْحُبَابِ بْنِ عَمْرٍو وَلِي مِنْهُ غُلَامٌ فَقَالَتْ لِيَ امْرَأَتُهُ الْآنَ تُبَاعِينَ فِي دَيْنِهِ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَاحِبُ تَرِكَةِ الْحُبَابِ بْنِ عَمْرٍو فَقَالُوا أَخُوهُ أَبُو الْيُسْرِ كَعْبُ بْنُ عَمْرٍو فَدَعَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَبِيعُوهَا وَأَعْتِقُوهَا فَإِذَا سَمِعْتُمْ بِرَقِيقٍ قَدْ حَسَبَنِي فَأْتُونِي أُعَوِّضُكُمْ فَفَعَلُوا فَاخْتَلَفُوا فِيمَا بَيْنَهُمْ بَعْدَ وَفَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قَوْمٌ أُمُّ الْوَلَدِ مَمْلُوكَةٌ لَوْلَا ذَلِكَ لَمْ يُعَوِّضْهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا وَقَالَ بَعْضُهُمْ هِيَ حُرَّةٌ قَدْ أَعْتَقَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفِيَّ كَانَ الِاخْتِلَافُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Ar Razi] berkata, telah menceritakan kepada kami [Salamah bin Al Fadll] berkata, telah menceritakan kepadaku [Muhammad bin Ishaq] dari [Khatthab bin Shalih] dari [Ibunya] dia berkata, \" [Salamah binti Ma'qil] menceritakan kepadaku, ia berkata, \"Aku adalah budak Hubab bin Amru bersama seorang pemuda lain, lalu istrinya berkata kepadaku, 'Sekarang kamu akan dijual untuk memenuhi hutangnya', lalu aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan menyampaikan hal itu pada beliau, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah pemilik warisan Hubab bin Amru?\" para shabat menjawab, \"Saudaranya, Abu Yusr Ka'ab bin Amru.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memanggilnya dan bersabda: \"Janganlah kamu menjualnya, namun bebaskanlah dia. Jika kamu mendengar ada budak telah menahanku, maka datanglah kepadaku maka aku akan menggantikannya.\" Maka mereka pun melakukannya, lalu di antara mereka berselisih setelah wafatnya Rasulullah shallallahu 'alaihi wasallam, sekelompok orang berkata, 'Ummul Walad (budak yang melahirkan dari benih tuannya) itu dimilikinya, karena kalau tidak seperti itu maka Rasulullah shallallahu 'alaihi wasallam tidak akan menggantikannya.' Dan sebagian lain berkata, 'Dia mereka. Sebab Rasulullah shallallahu 'alaihi wasallam telah membebaskannya.' Maka status diriku ini masih diperselisihkan.\""},"3876":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ هِلَالٍ يَعْنِي ابْنَ خَبَّابٍ عَنْ عِكْرِمَةَ عَنِ ابْنِ عَبَّاسٍ أَنَّ ضُبَاعَةَ بِنْتَ الزُّبَيْرِ بْنِ عَبْدِ الْمُطَّلِبِأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ أَنْ أَحُجَّ فَأَشْتَرِطُ قَالَ نَعَمْ قَالَتْ فَكَيْفَ أَقُولُ قَالَ قُولِي لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ مَحِلِّي مِنْ الْأَرْضِ حَيْثُ تَحْبِسُنِي","id":"Telah menceritakan kepada kami [Abbad bin Al Awwam] dari [Hilal] -yakni Ibnu Khabbab- dari [Ikrimah] dari [Ibnu Abbas] bahwa [Dluba'ah binti Zubair bin Abdul Mutthalib] menemui Nabi shallallahu 'alaihi wasallam, dia berkata, \"Wahai Rasulullah, sesungguhnya aku ingin pergi haji, bolehkah aku memberi syarat?\" Beliau menjawab: \"Ya.\" Dluba'ah lalu bertanya, \"Lantas apa yang harus aku ucapkan?\" Beliau menjawab: \"Ucapkanlah 'LABBAIK ALLAAHUMMA LABBAIK MAHALLI MINAL ARDLI HAITSU TAHBISUNI (Aku penuhi panggilan-Mu ya Allah, aku penuhi panggilan-Mu dari bumi hingga ia menghalangiku) '.\""},"3877":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ إِسْحَاقَ قَالَ حَدَّثَنِي ابْنُ مُبَارَكٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ وَعَلِيُّ بْنُ إِسْحَاقَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا أُسَامَةُ بْنُ زَيْدٍ عَنِ الْفَضْلِ بْنِ الْفَضْلِ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ ضُبَاعَةَ بِنْتِ الزُّبَيْرِ بْنِ عَبْدِ الْمُطَّلِبِأَنَّهَا ذَبَحَتْ فِي بَيْتِهَا شَاةً فَأَرْسَلَ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَطْعِمِينَا مِنْ شَاتِكُمْ فَقَالَتْ لِلرَّسُولِ وَاللَّهِ مَا بَقِيَ عِنْدَنَا إِلَّا الرَّقَبَةُ وَإِنِّي أَسْتَحِي أَنْ أُرْسِلَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالرَّقَبَةِ فَرَجَعَ الرَّسُولُ فَأَخْبَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ارْجِعْ إِلَيْهَا فَقُلْ لَهَا أَرْسِلِي بِهَا فَإِنَّهَا هَادِيَةٌ وَأَقْرَبُ الشَّاةِ إِلَى الْخَيْرِ وَأَبْعَدُهَا مِنْ الْأَذَى","id":"Telah menceritakan kepada kami [Ibrahim bin Ishaq] berkata, telah menceritakan kepadaku [Ibnu Mubarak] dari [Usamah bin Zaid] dan [Ali bin Ishaq] berkata, telah menceritakan kepada kami [Abdullah] berkata, telah mengabarkan kepada kami [Usamah bin Zaid] dari [Fadll bin Fadll] dari ['Abdurrahman Al A'raj] dari [Dluba'ah binti Zubair bin Abdul Mutthalib], bahwa dia menyembelih seekor kambing di rumahnya, lalu Rasulullah shallallahu 'alaihi wasallam mengirimkan utusan kepadanya agar kalian memberi makan kami dengan daging kambingmu, lalu Dluba'ah berkata kepada utusan beliau, \"Demi Allah, tidak ada sisa lagi kecuali hanya kakinya, dan aku malu jika aku mengirimkannya kepada Rasulullah shallallahu 'alaihi wasallam.\" Utusan itupun kembali dan mengabarkannya kepada Rasulullah shallallahu 'alaihi wasallam. Beliau lantas bersabda: \"Kembalilah kepadanya dan katakan 'kirimkanlah daging itu', sesungguhnya kambing itu adalah hadiah dan ia adalah daging kambing yang paling dekat kepada kebaikan dan yang paling jauh dari penyakit.\""},"3878":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُمِّ حَرَامٍ أَنَّهَا قَالَتْبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِلًا فِي بَيْتِي إِذْ اسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقُلْتُ بِأَبِي وَأُمِّي أَنْتَ مَا يُضْحِكُكَ فَقَالَ عُرِضَ عَلَيَّ نَاسٌ مِنْ أُمَّتِي يَرْكَبُونَ ظَهْرَ هَذَا الْبَحْرِ كَالْمُلُوكِ عَلَى الْأَسِرَّةِ فَقُلْتُ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ اللَّهُمَّ اجْعَلْهَا مِنْهُمْ ثُمَّ نَامَ أَيْضًا فَاسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقُلْتُ بِأَبِي وَأُمِّي مَا يُضْحِكُكَ قَالَ عُرِضَ عَلَيَّ نَاسٌ مِنْ أُمَّتِي يَرْكَبُونَ هَذَا الْبَحْرَ كَالْمُلُوكِ عَلَى الْأَسِرَّةِ فَقُلْتُ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَفَغَزَتْ مَعَ عُبَادَةَ بْنِ الصَّامِتِ وَكَانَ زَوْجَهَا فَوَقَصَتْهَا بَغْلَةٌ لَهَا شَهْبَاءُ فَوَقَعَتْ فَمَاتَتْ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَخْبَرَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُمِّ حَرَامٍ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِي فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Hammad] -yakni Ibnu Salamah- dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Hiban] dari [Anas bin Malik] dari [Ummu Haram] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam tidur siang di rumahku, tiba-tiba beliau bangun dan tertawa, aku lalu berkata, \"Demi ayah dan ibuku sebagai tebusanmu, kenapa tuan tertawa?\" Beliau menjawab: \"Ditampakkan orang-orang dari umatku yang mereka barlayar di atas laut ini seperti raja-raja atas tawanannya.\" Aku berkata do'akanlah agar aku menjadi bagian dari mereka, beliau pun bersabda: \"Ya Allah, jadikanlah dia bagian darinya.\" Kemudian Beliau tertidur kembali dan bangun dengan tertawa, aku lalu bertanya, \"Demi ayah dan ibuku sebagai tebusanmu, kenapa tuan tertawa?\" Beliau menjawab: \"Ditampakkan orang-orang dari umatku yang mereka barlayar di atas laut ini seperti raja-raja atas tawanannya.\" Aku pun berkata lagi, \"Do'akanlah agar aku menjadi bagian dari mereka.\" Beliau lalu bersabda: \"Kamu adalah termasuk yang pertama-tama.\" Maka Ummu Haram pun berperang bersama Ubadah bin Shamit suaminya, lalu bighal betinanya yang putih memecahkan lehernya hingga ia pun terjatuh dan gugur.\"Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Hammad bin Salamah] ia berkata; telah mengabarkan kepadaku [Yahya bin Sa'id] dari [Muhammad bin yahya bin Habban] dari [Anas bin Malik] dari [Ummu Haram] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam berada di rumahk….lalu dia menyebutkan (hadits) yang semakna dengannya.\""},"3879":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكٍ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ جُدَامَةَ بِنْتَ وَهْبٍ حَدَّثَتْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ هَمَمْتُ أَنْ أَنْهَى عَنْ الْغِيلَةِ حَتَّى ذَكَرْتُ أَنَّ فَارِسَ وَالرُّومَ يَصْنَعُونَهُ فَلَا يَضُرُّ أَوْلَادَهُمْ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Malik] dari [Abu Al Aswad] dari [Urwah] dari [Aisyah] bahwa [Judamah binti Wahab] berkata kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, tadinya aku ingin melarang dari ghilah, namun aku teringat bahwa orang-orang Persi dan Romawi malkukannya dan itu tidak membahayakan anak-anak mereka.\""},"3880":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ قَالَ أَخْبَرَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ جُدَامَةَ بِنْتِ وَهْبٍ الْأَسَدِيَّةِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَقَدْ هَمَمْتُ أَنْ أَنْهَى عَنْ الْغِيلَةِ حَتَّى ذَكَرْتُ أَنَّ فَارِسَ وَالرُّومَ يَفْعَلُونَ ذَلِكَ فَلَا يَضُرُّ أَوْلَادَهُمْ","id":"Telah menceritakan kepada kami [Abu Salamah Al Khuza'i] berkata, telah mengabarkan kepada kami [Malik] dari [Muhammad bin 'Abdurrahman bin Naufal] dari [Urwah] dari ['Aisyah] dari [Judamah binti Wahb Al Asadiyah] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, tadinya aku ingin melarang dari ghilah, namun aku teringat bahwa orang-orang Persi dan Romawi malkukannya dan itu tidak membahayakan anak-anak mereka.\""},"3881":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ جُدَامَةَ بِنْتِ وَهْبٍ الْأَسَدِيَّةِ وَكَانَتْ مِنْ الْمُهَاجِرَاتِ الْأُوَلِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْعَزْلِ فَقَالَ هُوَ الْوَأْدُ الْخَفِيُّحَدَّثَنَا أبُو عَبدِ الْرَحَمَنِ قَالَ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي أَبُو الْأَسْوَدِ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Abu Al Aswad] dari [Urwah] dari [Aisyah] dari [Judamah binti Wahb Al Asadiyah] dan dia adalah wanita yang turut berhijrah pertama kali, dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam ditanya mengenai 'Azl (mengeluarkan mani diluar kemaluan ketika berjima'), lalu beliau bersabda: \"Itu adalah pembunuhan terselubung.\" Telah menceritakan kepada kami Abu 'Abdurrahman ia berkata; telah menceritakan kepada kami Sa'id -yakni Ibn Abu Ayyub- ia berkata; telah menceritakan kepadaku Abu Aswad lalu ia menyebutkan (hadits tersebut).\""},"3882":{"ar":"حَدَّثَنَا حَسَنٌ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا زَبَّانُ عَنْ سَهْلٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ أُمَّ الدَّرْدَاءِ تَقُولُخَرَجْتُ مِنْ الْحَمَّامِ فَلَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مِنْ أَيْنَ يَا أُمَّ الدَّرْدَاءِ قَالَتْ مِنْ الْحَمَّامِ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ مَا مِنْ امْرَأَةٍ تَضَعُ ثِيَابَهَا فِي غَيْرِ بَيْتِ أَحَدٍ مِنْ أُمَّهَاتِهَا إِلَّا وَهِيَ هَاتِكَةٌ كُلَّ سِتْرٍ بَيْنَهَا وَبَيْنَ الرَّحْمَنِحَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ قَالَ حَدَّثَنَا رِشْدِينُ قَالَ حَدَّثَنِي زَبَّانُ عَنْ سَهْلِ بْنِ مُعَاذٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ أُمَّ الدَّرْدَاءِ تَقُولُ خَرَجْتُ مِنْ الْحَمَّامِ فَلَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Hasan] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] berkata, telah menceritakan kepada kami [Zabban] dari [Sahl] dari [Bapaknya] bahwa dia mendengar [Ummu Darda'] berkata, \"Aku keluar dari tempat pemandian umum, lalu aku bertemu dengan Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Darimana kamu wahai Ummi Darda'?\" dia menjawab, \"Dari tempat pemandian umum.\" Beliau bersabda: \"Tidaklah seorang wanita yang meletakkan bajunya di rumah selain dari rumah ibu-ibunya kecuali ia hanya membuka aibnya antara ia dengan Ar Rahman.\" Telah menceritakan kepada kami [Yahya bin Ghailan] ia berkata; telah menceritakan kepada kami [Risydin] ia berkata; telah menceritakan kepadaku [Zabban] dari [Sahl bin Muadz] dari [ayahnya] bahwa dia mendengar [Ummi Darda'] berkata, \"Aku keluar dari tempat pemandian umum dan bertemu dengan Rasulullah shallallahu 'alaihi wasallam….kemudian dia menyebutkan hadistnya.\""},"3883":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ الدُّؤَلِيِّ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ عَنْ أُمِّ الدَّرْدَاءِتَرْفَعُ الْحَدِيثَ قَالَتْ مَنْ رَابَطَ فِي شَيْءٍ مِنْ سَوَاحِلِ الْمُسْلِمِينَ ثَلَاثَةَ أَيَّامٍ أَجْزَأَتْ عَنْهُ رِبَاطَ سَنَةٍ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] berkata, telah menceritakan kepada kami [Isma'il bin Iyyas] dari [Muhammad bin Amru bin Halhalah Ad Duali] dari [Ishaq bin Abdullah] dari [Ummu Darda'] yang dia marfu'kan haditsnya, dia berkata, \"Barangsiapa melakukan ribath di perbatasan-perbatasan kaum muslimin selama tiga hari, maka itu cukup baginya seperti ribath setahun.\""},"3884":{"ar":"حَدَّثَنَا هَارُونُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ وَقَالَ حَيْوَةُ أَخْبَرَنِي أَبُو صَخْرٍ أَنَّ يُحَنَّسَ أَبَا مُوسَى حَدَّثَهُ أَنَّ أُمَّ الدَّرْدَاءِ حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِيَهَا يَوْمًا فَقَالَ مِنْ أَيْنَ جِئْتِ يَا أُمَّ الدَّرْدَاءِ فَقَالَتْ مِنْ الْحَمَّامِ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ امْرَأ��ةٍ تَنْزِعُ ثِيَابَهَا إِلَّا هَتَكَتْ مَا بَيْنَهَا وَبَيْنَ اللَّهِ عَزَّ وَجَلَّ مِنْ سِتْرٍ","id":"Telah menceritakan kepada kami [Harun] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, dan [Haiwah] berkata, telah mengabarkan kepadaku [Abu Shahr] bahwa [Yuhannas Abu Musa] menceritakan kepadanya bahwa [Ummu Darda'] telah menceritakan kepadanya, bahwa suatu hari Rasulullah shallallahu 'alaihi wasallam bertemu dengannya, maka beliau bersabda: \"Dari mana kamu wahai Ummu Darda?\" Ummu Darda lalu menjawab, \"Dari tempat pemandian umum?\" kemudian beliau bersabda: \"Tidaklah seorang wanita yang melepas pakaiannya, kecuali ia membuka aibnya dari tabir antara dia dengan Allah Azza Wa Jalla.\""},"3885":{"ar":"حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أُمِّ مُبَشِّرٍ امْرَأَةِ زَيْدِ بْنِ حَارِثَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ حَفْصَةَ فَقَالَ لَا يَدْخُلُ النَّارَ أَحَدٌ شَهِدَ بَدْرًا وَالْحُدَيْبِيَةَ قَالَتْ حَفْصَةُ أَلَيْسَ اللَّهُ عَزَّ وَجَلَّ يَقُولُ{ وَإِنْ مِنْكُمْ إِلَّا وَارِدُهَا }قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَهْ{ ثُمَّ نُنَجِّي الَّذِينَ اتَّقَوْا }","id":"Telah menceritakan kepada kami [Ibnu Idris] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari [Ummu Mubasyir] isteri Zaid bin Haritsah, ia berkata, \"Saat Rasulullah shallallahu 'alaihi wasallam berada di rumah Hafshah, beliau bersabda: \"Tidak akan masuk neraka seseorang yang mengikuti perang Badar dan Hudaibiyah.\" Hafshah berkata, \"Bukankah Allah Azza Wa Jalla berfirman: '(Dan tidak ada seorangpun dari padamu, melainkan mendatangi neraka itu) ' (Qs. Maryam: 71). Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Lalu bagaimana dengan firman Allah Ta'ala: '(Kemudian kami akan menyelamatkan orang-orang yang bertakwa) ' (Qs. Maryam: 72)."},"3886":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ أُمِّ مُبَشِّرٍ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ غَرَسَ غَرْسًا أَوْ زَرَعَ زَرْعًا فَأَكَلَ مِنْهُ إِنْسَانٌ أَوْ سَبُعٌ أَوْ دَابَّةٌ أَوْ طَيْرٌ فَهُوَ لَهُ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir bin Abdullah] dari [Ummu Mubasyir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menanam tanaman, kemudian ada orang, atau binatang buas, atau hewan ternak, atau burung memakannya kecuali itu akan menjadi sedekah baginya.\""},"3887":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أُمِّ مُبَشِّرٍ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا فِي حَائِطٍ مِنْ حَوَائِطِ بَنِي النَّجَّارِ فِيهِ قُبُورٌ مِنْهُمْ قَدْ مَاتُوا فِي الْجَاهِلِيَّةِ فَسَمِعَهُمْ وَهُمْ يُعَذَّبُونَ فَخَرَجَ وَهُوَ يَقُولُ اسْتَعِيذُوا بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ وَإِنَّهُمْ لَيُعَذَّبُونَ فِي قُبُورِهِمْ قَالَ نَعَمْ عَذَابًا تَسْمَعُهُ الْبَهَائِمُ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari [Ummu Mubasyir] dia berkata, \"Saat Rasulullah shallallahu 'alaihi wasallam menemuiku, aku berada di salah satu kebun milik Bani Najjar yang di dalamnya banyak terdapat kuburan, yang di antara mereka ada yang telah mati si masa Jahiliyah. Ketika mendengar penghuni kubur tersebut disiksa, beliau pun keluar dan bersabda: \"Mintalah perlindungan kepada Allah dari adzab kubur.\" Ummu Mubasyir berkata, \"Wahai Rasulullah, apakah mereka diadzab dikuburan mereka?\" Beliau bersabda: \"Ya, adzab yang bisa didengar oleh hewan.\""},"3888":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زَائِدَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أُمِّ مُبَشِّرٍ قَالَتْجَاءَ غُلَامُ حَاطِبٍ فَقَالَ وَاللَّهِ لَا يَدْخُلُ حَاطِبٌ الْجَنَّةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَبْتَ قَدْ شَهِدَ بَدْرًا وَالْحُدَيْبِيَةَ","id":"Telah menceritakan kepada kami [Mu'awiyah bin Amru] berkata, telah menceritakan kepada kami [Zaidah] dari [Sulaiman] dari [Abu Sufyan] dari [Jabir] dari [Ummu mubasyir] dia berkata, \"Budak laki-lakinya Hatib datang dan berkata, \"Demi Allah, Hathib tidak akan masuk surga!\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kamu telah berdusta! Sungguh, dia telah menyaksikan perang badar dan juga peristiwa Hudaibiyyah.\""},"3889":{"ar":"حَدَّثَنَا يَحْيَى عَنِ ابْنِ عَجْلَانَ قَالَ حَدَّثَنَا بُكَيْرُ بْنُ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَإِذَا شَهِدَتْ إِحْدَاكُنَّ الْعِشَاءَ فَلَا تَمَسَّ طِيبًا","id":"Telah menceritakan kepada kami [Yahya] dari [Ibnu Ajlan] berkata, telah menceritakan kepada kami [Bukair bin Abdullah bin Al Asyaj] dari [Busr bin Sa'id] dari [Zainab] isteri Abdullah, dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jika kalian mengikuti shalat isya' maka janganlah memakai minyak wangi.\""},"3890":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ وَسَعْدٌ قَالَا حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ هِشَامٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ قَالَ أَخْبَرَتْنِي زَيْنَبُ الثَّقَفِيَّةُ امْرَأَةُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا إِذَا خَرَجَتْ إِحْدَاكُنَّ إِلَى الْعِشَاءِ فَلَا تَمَسَّ طِيبًا","id":"Berkata, telah menceritakan kepada kami [Ya'kub] dan [Sa'd] keduanya berkata, telah menceritakan kepada kami [Bapakku] dari [Shalih] dari [Muhammad bin Abdullah bin Amru bin Hisyam] dari [Bukair bin Abdullah bin Al Asyaj] dari [Busr bin Sa'id] dia berkata, [Zainab As Tsaqafiyah] isteri Abdullah bin Mas'ud, mengabarkan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Jika di antara kalian mengikuti shalat isya' maka janganlah memakai minyak wangi.\""},"3891":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَمْرِو بْنِ الْحَارِثِ بْنِ الْمُصْطَلِقِ عَنِ ابْنِ أَخِي زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ عَنْ زَيْنَبَ قَالَتْخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مَعْشَرَ النِّسَاءِ تَصَدَّقْنَ وَلَوْ مِنْ حُلِيِّكُنَّ فَإِنَّكُنَّ أَكْثَرُ أَهْلِ جَهَنَّمَ يَوْمَ الْقِيَامَةِ قَالَتْ وَكَانَ عَبْدُ اللَّهِ رَجُلًا خَفِيفَ ذَاتِ الْيَدِ فَقُلْتُ لَهُ سَلْ لِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُجْزِئُ عَنِّي مِنْ الصَّدَقَةِ النَّفَقَةُ عَلَى زَوْجِي وَأَيْتَامٍ فِي حِجْرِي قَالَتْ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُلْقِيَتْ عَلَيْهِ الْمَهَابَةُ فَقَالَ اذْهَبِي أَنْتِ فَاسْأَلِيهِ قَالَتْ فَانْطَلَقْتُ فَانْتَهَيْتُ إِلَى بَابِهِ فَإِذَا عَلَيْهِ امْرَأَةٌ مِنْ الْأَنْصَارِ اسْمُهَا زَيْنَبُ حَاجَتِي حَاجَتُهَا قَالَتْ فَخَرَجَ عَلَيْنَا بِلَالٌ قَالَتْ فَقُلْنَا لَهُ سَلْ لَنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُجْزِئُ عَنَّا مِنْ الصَّدَقَةِ النَّفَقَةُ عَلَى أَزْوَاجِنَا وَأَيْتَامٍ فِي حُجُورِنَا قَالَتْ فَدَخَلَ عَلَيْهِ بِلَالٌ فَقَالَ عَلَى الْبَابِ زَيْنَبُ فَقَالَ أَيُّ الزَّيَانِبِ قَالَ فَقَالَ زَيْنَبُ امْرَأَةُ عَبْدِ اللَّهِ وَزَيْنَبُ امْرَأَةٌ مِنْ الْأَنْصَارِ تَسْأَلَانِكَ عَنْ النَّفَقَةِ عَلَى أَزْوَاجِهِمَا وَأَيْتَامٍ فِي حُجُورِهِمَا أَيُجْزِئُ ذَلِكَ عَنْهُمَا مِنْ الصَّدَقَةِ قَالَتْ فَخَرَجَ إِلَيْنَا فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُمَا أَجْرَانِ أَجْرُ الْقَرَابَةِ وَأَجْرُ الصَّدَقَةِ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masi] dari [Syaqiq] dari [Amru bin Al Harits bin Al Musthaliq] dari [anak] saudaranya Zainab isterinya Abdullah dari [Zainab] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami, beliau bersabda: \"Wahai para wanita bersedekahlah walaupun dengan perhiasan kalian, sesungguh kalian adalah penduduk Jahannam yang paling banyak pada hari Kiamat.\" Zainab berkata, \"Abdullah adalah seorang laki-laki yang kurus yang tangannya panjang, lalu aku berkata kepadanya, \"Tanyakan untukku pada Rasulullah shallallahu 'alaihi wasallam apakah cukup bagiku bersedekah dengan memberi nafkah pada suamiku dan anak-anak yatim yang aku asuh?\" Zainab berkata, \"Rasulullah shallallahu 'alaihi wasallam telah diberi pemberian, \" Ibnu Mas'ud lalu berkata, \"Pergilah kamu sendiri dan tanyakanlah.\" Maka aku pun pergi, hingga ketika aku sampai di pintu rumah beliau, ternyata di rumah beliau ada seorang wanita Anshar yang namanya Zainab. Keperluanku seperti keperluannya juga.\" Zainab berkata, \"Bilal kemudian keluar menemui kami.\" Zainab berkata, \"Kami lalu berkata kepadanya, 'Tanyakan kepada Rasulullah shallallahu 'alaihi wasallam apakah cukup bagi kami sedekah dengan memberi nafkah kepada suami-suami kami dan anak-anak yatim yang kami asuh? ' lalu Bilal pun masuk menemui Rasulullah shallallahu 'alaihi wasallam lalu dia berkata di pintu, \"Ada Zainab!\" Beliau bertanya: \"Zainab yang mana?\" Bilal menjawab, \"Zainab isteri Abdullah dan Zainab wanita Anshar. Keduanya bertanya tentang nafkah yang mereka berikan kepada suami-suami mereka dan anak-anak yatim yang mereka asuh, apakah mencukupi sedekah mereka (sah)?\" Zinab (isteri Abdullah bin Mas'ud) Berkata, \"Lalu Bilal keluar dan kepada kami, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagi mereka dua pahala, pahala karib kerabat dan pahala sedekah.\""},"3892":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنِ الْأَعْمَشِ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ كُلْثُومٍ عَنْ زَيْنَبَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَّثَ النِّسَاءَ خِطَطَهُنَّ","id":"Telah menceritakan kepada kami [Aswad bin Amir] berkata, telah menceritakan kepada kami [Syarik] dari [Al A'masy] dari [Jami' bin Syaddad] dari [Kultsum] dari [Zainab] bahwa Nabi shallallahu 'alaihi wasallam mewariskan untuk isteri-isteri beliau berupa tanah-tanah mereka.\""},"3893":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْأَعْمَشُ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ كُلْثُومٍ قَالَتْكَانَتْ زَيْنَبُ تَفْلِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ امْرَأَةُ عُثْمَانَ بْنِ مَظْعُونٍ وَنِسَاءٌ مِنْ الْمُهَاجِرَاتِ يَشْكُونَ مَنَازِلَهُنَّ وَأَنَّهُنَّ يَخْرُجْنَ مِنْهُ وَيُضَيَّقُ عَلَيْهِنَّ فِيهِ فَتَكَلَّمَتْ زَيْنَبُ وَتَرَكَتْ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكِ لَسْتِ تَكَلَّمِينَ بِعَيْنَيْكِ تَكَلَّمِي وَاعْمَلِي عَمَلَكِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ أَنْ يُوَرَّثَ مِنْ الْمُهَاجِرِينَ النِّسَاءُ فَمَاتَ عَبْدُ اللَّهِ فَوَرِثَتْهُ امْرَأَتُهُ دَارًا بِالْمَدِينَةِ","id":"Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Al A'masy] dari [Jami' bin Syaddad] dari [Kultsum] dia berkata, \"Zainab membersihkan kepala Rasulullah shallallahu 'alaihi wasallam sementara di sisinya ada isteri Utsman bin Madz'un dan beberapa wanita muhajirin, mereka mengeluhkan rumah-rumah mereka, mereka keluar darinya karena merasa sempit di dalamnya. Lalu Zainab berhenti sejenak dari membersihkan kepala Rasulullah shallallahu 'alaihi wasallam dan berkata kepada mereka, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kamu tidak berkata dengan kedua matamu, maka katakan dan amalkanlah.\" Rasulullah shallallahu 'alaihi wasallam memerintahkan pada hari itu agar para wanita mendapatkan warisan dari kaum muhajirin, ketika Abdullah meninggal, maka isterinya mendapatkan warisan rumah di Madinah.\""},"3894":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا فُلَيْحٌ عَنْ أَيُّوبَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ صَعْصَعَةَ عَنْ يَعْقُوبَ بْنِ أَبِي يَعْقُوبَ عَنْ أُمِّ الْمُنْذِرِ بِنْتِ قَيْسٍ الْأَنْصَارِيَّةِ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ عَلِيٌّ وَعَلِيٌّ نَاقِهٌ مِنْ مَرَضٍ وَلَنَا دَوَالٍ مُعَلَّقَةٌ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ مِنْهَا وَقَامَ عَلِيٌّ يَأْكُلُ مِنْهَا فَطَفِقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِعَلِيٍّ مَهْ إِنَّكَ نَاقِهٌ حَتَّى كَفَّ قَالَتْ وَصَنَعْتُ شَعِيرًا وَسِلْقًا فَجِئْتُ بِهِ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَلِيٍّ مِنْ هَذَا أَصِبْ فَهُوَ أَنْفَعُ لَكَحَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا فُلَيْحٌ عَنْ أَيُّوبَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ يَعْقُوبَ بْنِ أَبِي يَعْقُوبَ عَنْ أُمِّ الْمُنْذِرِ الْعَدَوِيَّةِ قَالَتْ دَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ عَلِيٌّ وَعَلِيٌّ نَاقِهٌ فَذَكَرَ الْحَدِيثَ إِلَّا أَنَّهُ قَالَ ثُمَّ جَعَلْتُ لَهُمْ سِلْقًا وَشَعِيرًا قَالَ أَبِي وَكَذَلِكَ قَالَ فَزَارَةُ بْنُ عَمْرٍو سِلْقًا","id":"Telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Fulaih] dari [Ayyub bin Abdurrahman bin Sha'sha'ah] dari [Ya'qub bin Abu Ya'qub] dari [Ummi Mundzir binti Qais Al Anshariyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendatangiku bersama Ali, sedangkan Ali baru sembuh dari penyakitnya. Ketika itu kami mempunyai tangkai-tangkai kurma yang belum matang yang kami gantungkan, Rasulullah shallallahu 'alaihi wasallam pun berdiri dan memakannya, maka Ali pun ikut berdiri dan memakannya. Nabi shallallahu 'alaihi wasallam kemudian bersabda kepada Ali: \"Hai, kamu baru saja sembuh!, \" sampai dia berhenti memakannya.\" Ummul Mundzir berkata, \"Aku lalu membuat (makanan dari) gandum dan ubi kemudian kubawa kepada beliau.\" Ya'qub berkata, \"Nabi shallallahu 'alaihi wasallam lalu bersabda kepada Ali: \"Makanlah ini, sebab itu lebih bermanfaat bagi kamu.\" Telah menceritakan kepada kami [Yunus] berkata; telah menceritakan kepada kami [Fulaih] dari [Ayyub bin Abdurrahman] dari [Ya'qub bin Abu Ya'qub] dari [Ummu Mundzir Al Adawiyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendatangiku bersama Ali, sedangkan Ali ketika itu baru sembuh dari penyakitnya…. lalu dia menyebutkan hadist, hanya saja ia menyebutkan, \"kemudian aku membuatkan untuk mereka gandum dan ubi.\" Bapakku (Imam Ahmad) Berkata demikian, [Fazarah bin Amru] juga menyebutkan, 'ubi'.\""},"3895":{"ar":"حَدَّثَنَا سُرَيْجٌ قَالَ حَدَّثَنَا فُلَيْحٌ عَنْ أَيُّوبَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ صَعْصَعَةَ الْأَنْصَارِيِّ عَنْ يَعْقُوبَ بْنِ أَبِي يَعْقُوبَ عَنْ أُمِّ الْمُنْذِرِ بِنْتِ قَيْسٍ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ عَلِيُّ بْنُ أَبِي طَالِبٍ وَعَلِيٌّ نَاقِهٌ مِنْ مَرَضٍ قَالَتْ وَلَنَا دَوَالٍ مُعَلَّقَةٌ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلِيٌّ يَأْكُلَانِ مِنْهَا فَطَفِقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَهْلًا فَإِنَّكَ نَاقِهٌ حَتَّى كَفَّ عَلِيٌّ قَالَتْ وَقَدْ صَنَعْتُ شَعِيرًا وَسِلْقًا فَلَمَّا جِئْنَا بِهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَلِيٍّ مِنْ هَذَا أَصِبْ فَهُوَ أَوْفَقُ لَكَ فَأَكَلَا ذَلِكَ","id":"Telah menceritakan kepada kami [Suraij] berkata, telah menceritakan kepada kami [Fulaih] dari [Ayyub bin Abdurrahman bin Sha'sha'ah Al Anshari] dari [Ya'qub bin Abu Ya'qub] dari [Ummu Mundzir binti Qais] berkata, \"Rasulullah shallallahu 'alaihi wasallam menemuiku bersama Ali bin Abu Thalib yang saat itu bari sembuh dari penyakitnya.\" Ummul Mundzir berkata, \"Ketika itu kami mempunyai tangkai-tangkai kurma yang belum matang dan masih menggantung, kemudian Nabi shallallahu 'alaihi wasallam dan Ali berdiri untuk memakannya, tiba-tiba-tiba Rasulullah shallallahu 'alaihi wasallam besabda: 'Hati-hati, sesungguhnya kamu baru saja sembuh'. Maka Ali pun menahan dirinya.\" Ummul Mundzir melanjutkan, \"Lalu aku membuat (makanan dari) gandum dan ubi, tatkala aku menyuguhkan kepadanya, Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ali: \"Makanlah ini, karena ia lebih bermanfaat (buatmu).\" Kemudian keduanya memakannya."},"3896":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ أَنَّ عُمَرَ بْنَ كَثِيرِ بْنِ أَفْلَحَ مَوْلَى أَبِي أَيُّوبَ الْأَنْصَارِيِّ أَخْبَرَهُ أَنَّهُ سَمِعَ عُبَيْدَ سَنُوطَا يُحَدِّثُ عَنْ خَوْلَةَ بِنْتِ قَيْسٍ امْرَأَةِ حَمْزَةَ بْنِ عَبْدِ الْمُطَّلِبِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى حَمْزَةَ فَتَذَاكَرَا الدُّنْيَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الدُّنْيَا خَضِرَةٌ حُلْوَةٌ مَنْ أَخَذَهَا بِحَقِّهَا بُورِكَ لَهُ فِيهَا وَرُبَّ مُتَخَوِّضٍ فِي مَالِ اللَّهِ وَمَالِ رَسُولِهِ لَهُ النَّارُ يَوْمَ يَلْقَى اللَّهَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Yahya bin Sa'id] bahwa [Umar bin Katsir bin Aflah] bekas budak Abu Ayyub Al Anshari, mengabarkan kepadanya, bahwa dirinya mendengar [Ubaid bin Sanuth] menceritakan dari [Khaulah binti Qais] isteri Hamzah bin Abdul Muthalib, bahwa Rasulullah shallallahu 'alaihi wasallam bertemu dengan Hamzah, lalu keduanya bercerita mengenai dunia, Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya dunia itu hijau dan manis, barangsiapa mengambilnya dengan hak maka ia akan diberkahi, dan berapa banyak orang yang mengambil harta Allah dan harta Rasul-Nya tanpa hak, maka baginya neraka pada saat bertemu dengan-Nya kelak.\""},"3897":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُمَرَ بْنِ كَثِيرِ بْنِ أَفْلَحَ عَنْ عُبَيْدِ سَنُوطَا عَنْ خَوْلَةَأَنَّهَا سَمِعَتْ حَمْزَةَ يُذَاكِرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدُّنْيَا فَقَالَ إِنَّ الدُّنْيَا حُلْوَةٌ خَضِرَةٌ وَرُبَّ مُتَخَوِّضٍ فِي مَالِ اللَّهِ وَرَسُولِهِ لَهُ النَّارُ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Yahya bin Sa'id] dari [Umar bin Katsir bin Aflah] dari [Ubaid Sanutha] dari [Khaulah] bahwa dirinya mendengar dari Hamzah menyebutkan kepada Nabi shallallahu 'alaihi wasallam tentang dunia, maka beliau bersabda: \"Sesungguhnya dunia itu manis dan hijau, dan berapa banyak orang yang mengambil harta Allah dan harta Rasul-Nya tanpa hak kemudian masuk neraka.\""},"3898":{"ar":"حَدَّثَنَا أَبُو قُرَّةَ مُوسَى بْنُ طَارِقٍ الزُّبَيْدِيُّ قَالَ حَدَّثَنَا مُوسَى بْنُ عُرْوَةَ عَنْ أُمِّ خَالِدٍ بِنْتِ خَالِدٍ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Abu Qurrah Musa bin Thariq Az Zubaidi] dia berkata, telah menceritakan kepada kami [Musa bin Urwah] dari [Ummi Khalid binti Khalid] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam memohon perlindungan dari adzab kubur.\""},"3899":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا إِسْحَاقُ بْنُ سَعِيدٍ عَنْ أَبِيهِ عَنْ أُمِّ خَالِدٍ بِنْتِ خَالِدِ بْنِ سَعِيدِ بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِكِسْوَةٍ فِيهَا خَمِيصَةٌ صَغِيرَةٌ فَقَالَ مَنْ تَرَوْنَ أَحَقَّ بِهَذِهِ فَسَكَتَ الْقَوْمُ فَقَالَ ائْتُونِي بِأُمِّ خَالِدٍ فَأُتِيَ بِهَا فَأَلْبَسَهَا إِيَّاهَا ثُمَّ قَالَ لَهَا مَرَّتَيْنِ أَبْلِي وَأَخْلِقِي وَجَعَلَ يَنْظُرُ إِلَى عَلَمٍ فِي الْخَمِيصَةِ أَحْمَرَ أَوْ أَصْفَرَ وَيَقُولُ سَنَاهْ سَنَاهْ يَا أُمَّ خَالِدٍوَسَنَاهْ فِي كَلَامِ الْحَبَشِ الْحَسَنُ","id":"Telah menceritakan kepada kami [Abu An Nadlr] berkata, telah menceritakan kepada kami [Ishaq bin Sa'id] dari [ayahnya] dari [Ummu Khalid binti Khalid bin Sa'id bin Ash], bahwa telah didatangkan kepada Rasulullah shallallahu 'alaihi wasallam sebuah bungkusan yang di dalamnya terdapat kain sutera yang kecil, beliau bersabda: \"Menurut kalian siapa yang berhak menggunakan ini?\" lalu orang-orang terdiam, beliau bersabda lagi: \"Datangkan kepadaku Ummu Khalid, \" lalu didatangkanlah Ummu Khalid kepada beliau, lalu beliau memakaikannya dan bersabda kepadanya dua kali: \"Kamu pantas dan cocok memakainya, \" beliau lalu memerhatikan kain sutera kecil yang berwarna merah atau kuning seraya berkata: \"Sanah, sanah wahai Ummi Khalid.\" Sanah dalam bahasa Habasy berarti bagus.\""},"3900":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُوسَى بْنِ عُقْبَةَ سَمِعَ أُمَّ خَالِدٍ بِنْتَ خَالِدٍ قَالَ وَلَمْ أَسْمَعْ أَحَدًا يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَهَاسَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Musa bin Uqbah] ia mendengar [Ummu Khalid binti Khalid], Musa berkata, \"Aku belum pernah mendengar seorang pun yang berkata 'aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam' selain dia, bahwa dia mendengar Nabi shallallahu 'alaihi wasallam memohon perlindungan dari adzab kubur.\""},"3901":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ حَبِيبِ بْنِ زَيْدٍ عَنْ مَوْلَاتِهِمْ لَيْلَى عَنْ عَمَّتِهِ أُمِّ عُمَارَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا قَالَ وَثَابَ إِلَيْهَا رِجَالٌ مِنْ قَوْمِهَا قَالَ فَقَدَّمَتْ إِلَيْهِمْ تَمْرًا فَأَكَلُوا فَتَنَحَّى رَجُلٌ مِنْهُمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا شَأْنُهُ فَقَالَ إِنِّي صَائِمٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهُ مَا مِنْ صَائِمٍ يَأْكُلُ عِنْدَهُ فَوَاطِرُ إِلَّا صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ حَتَّى يَقُومُوا","id":"Telah menceritakan kepada kami [Aswad bin Amir] berkata, telah menceritakan kepada kami [Syarik] dari [Habib bin Zaid] dari bekas budak mereka [Laila] dari bibinya [Ummu Umarah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah datang kepadanya, Habib berkata, \"Orang-orang dari kaumnya ikut berkumpul ke rumah Ummu Umarah bersama beliau.\" Habib melanjutkan, \"Kemudian Ummu Umarah menyuguhi mereka dengan kurma dan mereka pun memakannya, namuan ada seorang laki-laki dari mereka menyingkir, maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Ada apa dengannya?\" Laki-laki itu lalu menjawab, \"Aku sedang berpuasa.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Sungguh, tidaklah seorang yang berpuasa berada di sisi orang-orang yang sedang makan kecuali malaikat akan bershalawat kepadanya hingga mereka berdiri.\""},"3902":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ قَالَ حَدَّثَنِي حَبِيبٌ الْأَنْصَارِيُّ عَنْ لَيْلَى عَنْ جَدَّتِهِ أُمِّ عُمَارَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَقَرَّبَتْ إِلَيْهِ طَعَامًا قَالَ ادْنِي فَكُلِي قَالَتْ إِنِّي صَائِمَةٌ قَالَ الصَّائِمُ إِذَا أُكِلَ عِنْدَهُ صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] berkata, telah menceritakan kepadaku [Habib Al Anshari] dari [Laila] dari neneknya [Ummu Umarah] bahwa Nabi shallallahu 'alaihi wasallam pernah menemuinya, lalu dia mendekatkan makanan untuk beliau, beliau pun bersabda: \"Kemari dan makanlah.\" Ummu Umarah lantas berkata, \"Sesungguhnya aku sedang berpuasa.\" Beliau kemudian bersabda: \"Jika ada seseorang yang makan di sisinya (orang yang puasa), maka Malaikat akan bershalawat kepadanya.\""},"3903":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبٍ الْأَنْصَارِيِّ قَالَ سَمِعْتُ مَوْلَاةً لَنَا يُقَالُ لَهَا لَيْلَى تُحَدِّثُ عَنْ جَدَّتِهِ أُمِّ عُمَارَةَ بِنْتِ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَدَعَتْ لَهُ بِطَعَامٍ فَقَالَ لَهَا كُلِي فَقَالَتْ إِنِّي صَائِمَةٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الصَّائِمَ إِذَا أُكِلَ عِنْدَهُ صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ حَتَّى يَفْرَغُوا وَرُبَّمَا قَالَ حَتَّى يَقْضُوا أَكْلَهُمْ","id":"Telah menceritakan kepada kami [Hasyn bin Al Qasim] berkata, telah menceritakan kepada kami [Syu'bah] dari [Habib Al Anshari] berkata; Aku mendengar budak kami yang bernama [Laila] menceritakan dari neneknya [Ummu Umarah binti Ka'b] bahwa Rasulullah shallallahu 'alaihi wasallam menemuinya, kemudian dia menyuguhkan makanan kepada beliau, lalu beliau bersabda kepadanya: \"Makanlah.\" Ummu Umarah lalu menjawab, \"Sesungguhnya aku sedang berpuasa.\" Nabi shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya orang yang sedang berpuasa, jika ada orang lain makan di sisinya, maka Malaikat akan bershalawat kepadanya sampai mereka selesai (makan).\" Dan mungkin beliau bersabda: \"Sampai mereka menghabiskan makanannya.\""},"3904":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ وَيُونُسُ الْمَعْنَى قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ عُثْمَانَ بْنِ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْحَاطِبِ قَالَ حَدَّثَنِي أَبِي عَنْ أُمِّهِ عَائِشَةَ بِنْتِ قُدَامَةَ قَالَتْكُنْتُ أَنَا مَعَ أُمِّي رَائِطَةَ بِنْتِ سُفْيَانَ الْخُزَاعِيَّةِ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَايِعُ النِّسْوَةَ وَيَقُولُ أُبَايِعُكُنَّ عَلَى أَنْ لَا تُشْرِكْنَ بِاللَّهِ شَيْئًا وَلَا تَسْرِقْنَ وَلَا تَزْنِينَ وَلَا تَقْتُلْنَ أَوْلَادَكُنَّ وَلَا تَأْتِينَ بِبُهْتَانٍ تَفْتَرِينَهُ بَيْنَ أَيْدِيكُنَّ وَأَرْجُلِكُنَّ وَلَا تَعْصِينَ فِي مَعْرُوفٍ قَالَتْ فَأَطْرَقْنَ فَقَالَ لَهُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَ نَعَمْ فِيمَا اسْتَطَعْتُنَّ فَكُنَّ يَقُلْنَ وَأَقُولُ مَعَهُنَّ وَأُمِّي تُلَقِّنُنِي قُولِي أَيْ بُنَيَّةُ نَعَمْ فِيمَا اسْتَطَعْتُ فَكُنْتُ أَقُولُ كَمَا يَقُلْنَ","id":"Telah menceritakan kepada kami [Ibrahim bin Abu Abbas] dan [Yunus Al Makna] keduanya berkata, telah menceritakan kepada kami [Abdurrahman] -yakni Ibnu Utsman bin Ibrahim bin Muhammad bin Hathib- dia berkata, telah menceritakan kepadaku [ayahku] dari ibunya ['Aisyah binti Qudamah] dia berkata, \"Saat aku bersama ibuku, Raithah binti Sufyan Al Khuza'iyah, Nabi shallallahu 'alaihi wasallam sedang membaiat para wanita, beliau bersabda: \"Aku membaiat kalian agar kalian tidak menyekutukan Allah dengan sesuatupun, tidak mencuri dan tidak berzina, tidak membunuh anak-anak kalian, tidak mengada-ngada dengan kedustaan yang diperbuat oleh tangan-tangan dan kaki-kaki kalian serta tidak durhaka di dalam hal yang ma'ruf.\" Aisyah berkata, \"Mereka lalu mengangguk, kemudian Nabi shallallahu 'alaihi wasallam bersabda kepada mereka: \"Katakanlah 'Ya', sebatas apa yang kalian mampui, \" lalu mereka mengatakannya dan aku mengatakan bersama mereka, sementara ibuku mendiktekan untukku, 'Katakanlah hai anakku, 'Ya semampuku', maka aku mengatakan sebagaimana mereka katakan.\""},"3905":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ وَيُونُسُ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ وَحَدَّثَنِي أَبِي عَنْ أُمِّهِ عَائِشَةَ بِنْتِ قُدَامَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَزِيزٌ عَلَى اللَّهِ عَزَّ وَجَلَّ أَنْ يَأْخُذَ كَرِيمَتَيْ مُسْلِمٍ ثُمَّ يُدْخِلَهُ النَّارَقَالَ يُونُسُ يَعْنِي عَيْنَيْهِ","id":"Telah menceritakan kepada kami [Ibrahim] dan [Yunus] keduanya berkata, telah menceritakan kepada kami [Abdurrahman] dia berkata, dan telah menceritakan kepadaku [ayahku] dari ibunya ['Aisyah binti Qudamah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah merasa keberatan jika mengambil dua mata seorang muslim lantas memasukkan orang itu ke neraka, \" Yunus berkata, \"Yakni kedua matanya.\""},"3906":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ بْنِ مِقْسَمٍ قَالَ حَدَّثَتْنِي عَمَّتِي سَارَةُ بِنْتُ مِقْسَمٍ عَنْ مَيْمُونَةَ بِنْتِ كَرْدَمٍ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ وَهُوَ عَلَى نَاقَتِهِ وَأَنَا مَعَ أَبِي وَبِيَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِرَّةٌ كَدِرَّةِ الْكُتَّابِ فَسَمِعْتُ الْأَعْرَابَ وَالنَّاسَ يَقُولُونَ الطَّبْطَبِيَّةَ فَدَنَا مِنْهُ أَبِي فَأَخَذَ بِقَدَمِهِ فَأَقَرَّ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ فَمَا نَسِيتُ فِيمَا نَسِيتُ طُولَ أُصْبُعِ قَدَمِهِ السَّبَّابَةِ عَلَى سَائِرِ أَصَابِعِهِ قَالَتْ فَقَالَ لَهُ أَبِي إِنِّي شَهِدْتُ جَيْشَ عِثْرَانَ قَالَتْ فَعَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ الْجَيْشَ فَقَالَ طَارِقُ بْنُ الْمُرَقَّعِ مَنْ يُعْطِينِي رُمْحًا بِثَوَابِهِ قَالَ فَقُلْتُ وَمَا ثَوَابُهُ قَالَ أُزَوِّجُهُ أَوَّلَ بِنْتٍ تَكُونُ لِي قَالَ فَأَعْطَيْتُهُ رُمْحِي ثُمَّ تَرَكْتُهُ حَتَّى وُلِدَتْ لَهُ ابْنَةٌ وَبَلَغَتْ فَأَتَيْتُهُ فَقُلْتُ لَهُ جَهِّزْ لِي أَهْلِي فَقَالَ لَا وَاللَّهِ لَا أُجَهِّزُهَا حَتَّى تُحْدِثَ صَدَاقًا غَيْرَ ذَلِكَ فَحَلَفْتُ أَنْ لَا أَفْعَلَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِقَدْرِ أَيِّ النِّسَاءِ هِيَ قَالَ قَدْ رَأَتْ الْقَتِيرَ قَالَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهَا عَنْكَ لَا خَيْرَ لَكَ فِيهَا قَالَ فَرَاعَنِي ذَلِكَ وَنَظَرْتُ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَأْثَمُ وَلَا يَأْثَمُ صَاحِبُكَ قَالَتْ فَقَالَ لَهُ أَبِي فِي ذَلِكَ الْمَقَامِ إِنِّي نَذَرْتُ أَنْ أَذْبَحَ عَدَدًا مِنْ الْغَنَمِ قَالَ لَا أَعْلَمُهُ إِلَّا قَالَ خَمْسِينَ شَاةً عَلَى رَأْسِ بُوَانَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ عَلَيْهَا مِنْ هَذِهِ الْأَوْثَانِ شَيْءٌ قَالَ لَا قَالَ فَأَوْفِ لِلَّهِ بِمَا نَذَرْتَ لَهُ قَالَتْ فَجَمَعَهَا أَبِي فَجَعَلَ يَذْبَحُهَا وَانْفَلَتَتْ مِنْهُ شَاةٌ فَطَلَبَهَا وَهُوَ يَقُولُ اللَّهُمَّ أَوْفِ عَنِّي بِنَذْرِي حَتَّى أَخَذَهَا فَذَبَحَهَاحَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ بْنِ ضَبَّةَ الطَّائِفِيُّ قَالَ حَدَّثَتْنِي عَمَّةٌ لِي يُقَالُ لَهَا سَارَةُ بِنْتُ مِقْسَمٍ عَنْ مَوْلَاتِهَا مَيْمُونَةَ بِنْتِ كَرْدَمٍ أَنَّهَا كَانَتْ مَعَ أَبِيهَا فَذَكَرَتْ أَنَّهَا رَأَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى نَاقَةٍ وَبِيَدِهِ دِرَّةٌ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Abdullah bin Yazid bin Miqsam] berkata, telah menceritakan kepadaku bibiku [Sarah binti Miqsam] dari [Maimunah binti Kardam] dia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam di Makkah dan beliau berada di atas untanya, sedangkan aku bersama ayahku. Pada tangan Rasulullah shallallahu 'alaihi wasallam terdapat tongkat seperti tongkat seorang penulis. Aku lalu mendengar orang-orang mengatakan At thabtiyah (tongkat), lalu ayahku mendekati tongkat tersebut dan mengambilnya dengan kakinya, dan Rasulullah shallallahu 'alaihi wasallam melihatnya (seakan setuju).\" Maimunah berkata, \"Maka aku tidak akan lupa apa yang aku lihat bahwa panjang jari telunjuk kakinya melebihi yang lain. Lalu ayahku berkata kepada beliau, \"Sesungguhnya aku pernah bergabung dengan pasukan 'Itsron!\" Dan Rasulullah shallallahu 'alaihi wasallam mengetahui akan pasukan itu.\" Thariq bin Muraqqa' berkata, \"Siapakah yang mampu memberiku tombak maka ia akan memperoleh imbalan?\" Ayah Maimunah berkata, 'Aku bertanya, 'Apa balasannya? ' Thariq menjawab, 'Aku akan menikahkannya dengan putri pertama yang aku miliki, \" Ayahku berkata, 'Lalu aku memberikan tombakku, kemudian aku tinggalkan hingga isterinya melahirkan anak perempuan. Ketika anaknya sampai umur baligh aku mendatanginya dan berkata, 'Siapkan calom isteriku, ' namun Thariq berkata, 'Tidak, aku tidak akan menyiapkannya untukmu hingga kamu memberikan mahar kepadanya, ' maka aku bersumpah tidak akan melakukannya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita seperti apa dia?\" dia (ayah Maimunah) menjawab, \"Ia terlihat beruban.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Tinggalkan ia, karena ia tidak ada kebaikannya bagimu.\" Dia (ayah Maimunah) Berkata, \"Hal itu membuatku lega, dan aku menunggunya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu berbuat dosa, dan temanmu itu tidak berdosa.\" Maimunah berkata, \"Lalu ayahku berkata di tempat itu, \"Aku bernadzar (janji) akan menyembelih beberapa kambing -perawi berkata; aku tidak mengetahui kecuali dia mengatakan; lima puluh ekor kambing- di atas Buwanah (tempat orang musyrik menyembelih). Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah ia bermaksud menyembelih sesuatu pada berhala ini?\" dia (ayah Maimunah) menjawab, \"Tidak.\" Beliau lalu bersabda: \"Laksanakanlah nadzar yang kau niatkan untuk Allah tersebut.\" Maimunah berkata, \"Lalu ayahku mengumpulkan kambing-kambingnya dan mulai menyembelihnya, lalu seekor kambing terlepas darinya hingga ia pun mencarinya, kemudian dia berdoa, \"Allahumma aufi 'anny binadzri (Ya Allah penuhilah dariku nadzarku) ', hingga menemukannya dan menyembelihnya.\" Telah menceritakan kepada kami [Abdus Shamad] berkata; telah menceritakan kepada kami [Abdullah bin Yazid bin Dlabbah Atthaifi] berkata, \"Bibiku yang bernama [Sarah binti Miqsam] menceritakan kepadaku dari bekas budaknya [Maimunah binti Kardam], bahwa saat bersama ayahnya ia meyebutkan bahwa ia melihat Rasulullah shallallahu 'alaihi wasallam berada di atas untanya dan di tangannya ada tongkat…lalu dia menyebutkan hadistnya.\""},"3907":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ بْنِ يَعْلَى الطَّائِفِيَّ عَنْ يَزِيدَ بْنِ مِقْسَمٍ عَنْ مَوْلَاتِهِ مَيْمُونَةَ بِنْتِ كَرْدَمٍ قَالَتْكُنْتُ رِدْفَ أَبِي فَسَمِعْتُهُ يَسْأَلُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي نَذَرْتُ أَنْ أَنْحَرَ بِبُوَانَةَ فَقَالَ أَبِهَا وَثَنٌ أَمْ طَاغِيَةٌ فَقَالَ لَا قَالَ أَوْفِ بِنَذْرِكَ","id":"Telah menceritakan kepada kami [Abu Ahmad] berkata, telah menceritakan kepada kami [Abdullah] -yakni Ibnu Abdurrahman bin Ya'la At Taha'ifi- dari [Yazid bin Miqsam] dari bekas budaknya [Maimunah binti Kirdam] dia berkata, \"Aku memboceng ayahku, maka aku mendengar dia bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Wahai Rasulullah, sesungguhnya aku bernadzar untuk menyembelih di Buwanah (tempat penyembelihan orang-orang musyrik).\" Maka beliau bersabda: \"Apakah si sana ada patung atau sesembahan?\" dia (ayah Maimunah) menjawab, \"Tidak.\" Beliau lalu bersabda: \"Tepatilah nadzarmu.\""},"3908":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنِي خَارِجَةُ بْنُ الْحَارِثِ الْمُزَنِيُّ قَالَ حَدَّثَنِي سَالِمُ بْنُ سَرْجٍ قَالَ سَمِعْتُ أُمَّ صُبَيَّةَ الْجُهَنِيَّةِ تَقُولُاخْتَلَفَتْ يَدِي وَيَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْوُضُوءِ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata, telah menceritakan kepadaku [Kharijah bin Harits Al Muzanni] berkata, telah menceritakan kepadaku [Salim bin Sarj] ia berkata, \"Aku mendengar [Ummu Subayyah Al Juhaniyah] berkata, \"Tanganku dan tangan Rasulullah shallallahu 'alaihi wasallam masuk dalam satu bejana ketika wudlu.\""},"3909":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ أُسَامَةَ بْنِ يَزِيدَ قَالَ حَدَّثَنِي سَالِمٌ أَبُو النُّعْمَانِ عَنْ أُمِّ صُبَيَّةَ قَالَتْاخْتَلَفَتْ يَدِي وَيَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِنَاءٍ وَاحِدٍ فِي الْوُضُوءِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Usamah bin yazid] berkata, telah menceritakan kepadaku [Salim Abu An Nu'man] dari [Ummu Subayyah] dia berkata, \"Tanganku dan tangan Rasulullah shallallahu 'alaihi wasallam masuk dalam satu bejana ketika wudlu.\""},"3910":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا بَشَّارُ بْنُ عَبْدِ الْمَلِكِ وَقَالَ حَدَّثَتْنِي أُمُّ حَكِيمٍ بِنْتُ دِينَارٍ عَنْ مَوْلَاتِهَا أُمِّ إِسْحَاقَأَنَّهَا كَانَتْ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُتِيَ بِقَصْعَةٍ مِنْ ثَرِيدٍ فَأَكَلَتْ مَعَهُ وَمَعَهُ ذُو الْيَدَيْنِ فَنَاوَلَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرْقًا فَقَالَ يَا أُمَّ إِسْحَاقَ أَصِيبِي مِنْ هَذَا فَذَكَرْتُ أَنِّي كُنْتُ صَائِمَةً فَرَدَدْتُ يَدِي لَا أُقَدِّمُهَا وَلَا أُؤَخِّرُهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَكِ قَالَتْ كُنْتُ صَائِمَةً فَنَسِيتُ فَقَالَ ذُو الْيَدَيْنِ الْآنَ بَعْدَمَا شَبِعْتِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتِمِّي صَوْمَكِ فَإِنَّمَا هُوَ رِزْقٌ سَاقَهُ اللَّهُ إِلَيْكِ","id":"Telah menceritakan kepada kami [Abdus Shamad] berkata, telah menceritakan kepada kami [Basyar bin Abdul Malik], dan berkata telah menceritakan kepadaku [Ummu Hakim binti Dinar] dari bekas budaknya [Ummi Ishaq], bahwa dia berada di samping Rasulullah shallallahu 'alaihi wasallam lalu dihidangkan satu nampan roti, dan ia pun makan bersama beliau yang saat itu bersama Dzul Yadain. Rasulullah shallallahu 'alaihi wasallam kemudian memberinya air susu seraya bersabda: \"Wahai Ummu Ishaq, minumlah air ini.\" Lalu aku teringat bahwa aku sedang berpuasa, maka tanganku aku tahan, tidak maju dan tidak mundur. Rasulullah shallallahu 'alaihi wasallam pun bertanya: \"Ada apa denganmu?\" Ummu Ishaq menjawab, \"Aku sedang berpuasa, dan lalu aku lupa.\" Lalu Dzul Yadain berkata, \"Sekarang baru kamu ingat setelah kenyang!\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sempurnakanlah puasamu, sesungguhnya ia adalah rizki dari Allah yang diberikan kepadamu.\""},"3911":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا أَبُو جَعْفَرٍ يَعْنِي الرَّازِيَّ عَنْ حُصَيْنٍ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ مَسْرُوقٍ عَنْ أُمِّ رُومَانَ وَهِيَ أُمُّ عَائِشَةَ قَالَتْكُنْتُ أَنَا وَعَائِشَةُ قَاعِدَةٌ فَدَخَلَتْ امْرَأَةٌ مِنْ الْأَنْصَارِ فَقَالَتْ فَعَلَ اللَّهُ بِفُلَانٍ وَفَعَلَ تَعْنِي ابْنَهَا قَالَتْ فَقُلْتُ لَهَا وَمَا ذَلِكَ قَالَتْ ابْنِي كَانَ فِيمَنْ حَدَّثَ الْحَدِيثَ قَالَتْ فَقُلْتُ لَهَا وَمَا الْحَدِيثُ قَالَتْ كَذَا وَكَذَا فَقَالَتْ عَائِشَةُ أَسَمِعَ بِذَلِكَ أَبُو بَكْرٍ قَالَتْ نَعَمْ قَالَتْ أَسَمِعَ بِذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ نَعَمْ فَوَقَعَتْ أَوْ سَقَطَتْ مَغْشِيًّا عَلَيْهَا فَأَفَاقَتْ حُمَّى بِنَافِضٍ فَأَلْقَيْتُ عَلَيْهَا الثِّيَابَ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا لِهَذِهِ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ أَخَذَتْهَا حُمَّى بِنَافِضٍ قَالَ لَعَلَّهُ مِنْ الْحَدِيثِ الَّذِي تُحُدِّثَ بِهِ قَالَتْ قُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ فَرَفَعَتْ عَائِشَةُ رَأْسَهَا وَقَالَتْ إِنْ قُلْتُ لَمْ تَعْذِرُونِي وَإِنْ حَلَفْتُ لَمْ تُصَدِّقُونِي وَمَثَلِي وَمَثَلُكُمْ كَمَثَلِ يَعْقُوبَ وَبَنِيهِ حِينَ قَالَ{ فَصَبْرٌ جَمِيلٌ وَاللَّهُ الْمُسْتَعَانُ عَلَى مَا تَصِفُونَ }فَلَمَّا نَزَلَ عُذْرُهَا أَتَاهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهَا بِذَلِكَ فَقَالَتْ بِحَمْدِ اللَّهِ لَا بِحَمْدِكَ أَوْ قَالَتْ وَلَا بِحَمْدِ أَحَدٍ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] berkata, telah menceritakan kepada kami [Abu Ja'far] -yakni Ar Razi- dari [Hushain] dari [Syaqiq bin Salamah] dari [Masruq] dari [Ummu Rumman] dia adalah ibu 'Aisyah, dia berkata, \"Aku duduk bersama 'Aisyah, tiba-tiba masuklah seorang wanita Anshar dan berkata, \"Allah telah melakukan sesuatu terhadap fulan -yang dia maksud fulan ialah anaknya-. Ummu Rumman berkata, \"Aku lalu bertanya kepadanya, \"Apa itu?\" Dia menjawab, \"Anakku termasuk orang yang mengucapkan perkataan itu.\" Ummu Rumman berkata, \"Aku lalu bertanya, \"Perkataan apa itu?\" ia menjawab, \"Seperti ini dan seperti ini.\" 'Aisyah lalu berkata, \"Apakah Abu Bakar telah mendengar hal itu?\" Dia menjawab, \"Ya.\" Aisyah bertanya lagi, \"Apakah Rasulullah shallallahu 'alaihi wasallam telah mendengar hal itu?\" dia menjawab, \"Ya.\" Maka 'Aisyah pun tersungkur, atau jatuh pingsan. Kemudian dia siuman dengan demam dan gemetar, lalu aku menyelimutinya dengan kain, setelah itu masuklah Rasulullah shallallahu 'alaihi wasallam seraya bersabda: \"Kenapa dia?\" Ummu Rumman berkata, \"Aku lalu menjawab, \"Wahai Rasulullah, dia terkena demam dan badannya gemetaran.\" Beliau bersabda: \"Barangkali dari kejadian yang dia dengar.\" Ummu Rumman berkata, \"Aku lalu menjawab, \"Benar wahai Rasulullah.\" 'Aisyah lantas mengangkat kepalanya dan berkata, \"Jika aku berkata maka tuan tidak akan memberiku udzur, jika aku bersumpah tuan tidak akan mempercayaiku. Permisalanku dengan kalian adalah seperti kisah Ya'qub dengan anak-anaknya ketika dia mengatakan: '(Maka kesabaran yang baik Itulah (kesabaranku), dan Allah sajalah yang dimohon pertolongan-Nya terhadap apa yang kamu ceritakan) '. (Qs. Yusuf: 18). Ketika (ayat) yang memaafkannya turun, Rasulullah shallallahu 'alaihi wasallam mendatangi Aisyah dan mengabarkan kepadanya, kemudian Aisyah berkata, \"Segala puji milik Allah tidak dengan memujimu, \" atau dia mengatakan, \"Tidak dengan memuji seorangpun.\""},"3912":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ قَالَ حَدَّثَنَا حُصَيْنٌ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ أُمِّ رُومَانَ قَالَتْبَيْنَا أَنَا عِنْدَ عَائِشَةَ إِذْ دَخَلَتْ عَلَيْنَا امْرَأَةٌ مِنْ الْأَنْصَارِ فَقَالَتْ فَعَلَ اللَّهُ بِابْنِهَا وَفَعَلَ قَالَتْ عَائِشَةُ وَلِمَ قَالَتْ إِنَّهُ كَانَ فِيمَنْ حَدَّثَ الْحَدِيثَ قَالَتْ عَائِشَةُ وَأَيُّ حَدِيثٍ قَالَتْ كَذَا وَكَذَا قَالَتْ وَقَدْ بَلَغَ ذَاكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ نَعَمْ وَبَلَغَ أَبَا بَكْرٍ قَالَتْ نَعَمْ قَالَتْ فَخَرَّتْ عَائِشَةُ مَغْشِيًّا عَلَيْهَا فَمَا أَفَاقَتْ إِلَّا وَعَلَيْهَا حُمَّى بِنَافِضٍ قَالَتْ فَقُمْتُ فَدَثَّرْتُهَا قَالَتْ وَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا شَأْنُ هَذِهِ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ أَخَذَتْهَا حُمَّى بِنَافِضٍ قَالَ لَعَلَّهُ فِي حَدِيثٍ تُحُدِّثَ بِهِ قَالَتْ فَاسْتَوَتْ لَهُ عَائِشَةُ قَاعِدَةً فَقَالَتْ وَاللَّهِ لَئِنْ حَلَفْتُ لَكُمْ لَا تُصَدِّقُونِي وَلَئِنْ اعْتَذَرْتُ إِلَيْكُمْ لَا تَعْذِرُونِي فَمَثَلِي وَمَثَلُكُمْ كَمَثَلِ يَعْقُوبَ وَبَنِيهِ{ وَاللَّهُ الْمُسْتَعَانُ عَلَى مَا تَصِفُونَ }قَالَتْ وَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَأَنْزَلَ اللَّهُ عُذْرَهَا فَرَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُ أَبُو بَكْرٍ فَدَخَلَ فَقَالَ يَا عَائِشَةُ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ أَنْزَلَ عُذْرَكِ قَالَتْ بِحَمْدِ اللَّهِ لَا بِحَمْدِكَ قَالَتْ قَالَ لَهَا أَبُو بَكْرٍ تَقُولِينَ هَذَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ نَعَمْ قَالَتْ فَكَانَ فِيمَنْ حَدَّثَ الْحَدِيثَ رَجُلٌ كَانَ يَعُولُهُ أَبُو بَكْرٍ فَحَلَفَ أَبُو بَكْرٍ أَنْ لَا يَصِلَهُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا يَأْتَلِ أُولُوا الْفَضْلِ مِنْكُمْ وَالسَّعَةِ }إِلَى آخِرِ الْآيَةِ قَالَ أَبُو بَكْرٍ بَلَى فَوَصَلَهُ","id":"Telah menceritakan kepada kami [Ali bin Ashim] berkata, telah menceritakan kepada kami [Hushain] dari [Abu Wail] dari [Masruq] dari [Ummu Rumman] dia berkata, \"Ketika aku berada di sisi 'Aisyah tiba-tiba masuklah seorang wanita Anshar kepada kami, dia mengatakan bahwa Allah telah melakukan sesuatu kepada anaknya. 'Aisyah pun bertanya, \"Ada apa?\" Wanita itu menjawab, \"Sesungguhnya dia termasuk dari orang yang mengatakan kejadian itu (berita bohong).\" 'Aisyah bertanya lagi, \"Kejadian apa?\" Wanita itu menjawab, \"Seperti ini dan seperti ini.\" Aisyah terus bertanya, \"Apakah hal itu telah sampai pada Rasulullah shallallahu 'alaihi wasallam?\" Wanita itu menjawab, \"Ya.\" Aisyah bertanya lagi, \"Apakah telah sampai kepada Abu Bakar?\" Wanita itu menjawab, \"Ya.\" Ummu Rumman berkata, \"Aisyah lalu jatuh pingsan karena berita tersebut, dan dia tidak siuman kecuali dengan demam dan badan gemetar.\" Ummu Rumman melanjutkan, \"Lalu aku bangun dan menyelimutinya. Kemudian Rasulullah shallallahu 'alaihi wasallam pun masuk seraya bersabda: \"Ada apa dengan orang ini?\" Ummu Rumman menjawab, \"Wahai Rasulullah, dia terserang demam dan badannya gemetar.\" Beliau lalu bersabda: \"Barangkali dari kabar yang ia ceritakan.\" Ummu Rumman lalu mendudukkan 'Aisyah hingga 'Aisyah pun berkata, \"Demi Allah, jika aku bersumpah kepada kalian, kalian tidak akan mempercayaiku, dan jika aku meminta udzur kepada kalian, maka kalian tidak akan memberiku udzur. Permisalanku dengan kalian adalah seperti kisah Ya'qub dengan anak-anaknya ketika dia mengatakan: '(Dan Allah sajalah yang dimohon pertolongan-Nya terhadap apa yang kamu ceritakan) ' (Qs. Yusuf: 18). Ummu Rumman berkata, \"Lalu Rasulullah shallallahu 'alaihi wasallam keluar. Setelah itu Allah menurunkan pembersihan (pembelaan) atas diri Aisyah, lalu Rasulullah shallallahu 'alaihi wasallam kembali bersama Abu Bakar dan masuk seraya bersabda: \"Wahai 'Aisyah, sesungguhnya Allah Azza wa Jalla telah menurunkan udzurmu.\" Aisyah menjawab, \"Dengan memuji Allah tidak dengan memujimu.\" Ummu Rumman berkata, \"Abu Bakar lantas berkata kepada Aisyah, \"Akankah kamu mengatakan seperti ini kepada Rasulullah shallallahu 'alaihi wasallam?\" Aisyah menjawab, \"Ya.\" Dan di antara yang menyebarkan kejadian itu adalah seseorang yang sering dibantu oleh Abu Bakar, maka Abu Bakar bersumpah untuk tidak mambantunya lagi. Maka Allah Azza Wa Jalla menurunkan ayat: '(Dan janganlah orang-orang yang mempunyai kelebihan dan kelapangan di antara kamu bersumpah bahwa mereka (tidak) akan memberi (bantuan) kepada kaum kerabatnya...) ' (Qs. An Nuur: 22) sampai akhir ayat. Maka Abu Bakar pun berkata, \"Tentu.\" Lalu diapun membantunya lagi.\""},"3913":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ أَبِي يَحْيَى قَالَ حَدَّثَتْنِي أُمِّي عَنْ أُمِّ بِلَالٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ضَحُّوا بِالْجَذَعِ مِنْ الضَّأْنِ فَإِنَّهُ جَائِزٌ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Abu Yahya] berkata, telah menceritakan kepadaku [Ibuku] dari [Ummu Bilal] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sembelihlah jadza' (unta atau sapi yang masuk tahun kedua) dari hewan ternak dan hal itu boleh.\""},"3914":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا أَبُو ضَمْرَةَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَحْيَى مَوْلَى الْأَسْلَمِيِّينَ عَنْ أُمِّهِ قَالَ أَخْبَرَتْنِي أُمُّ بِلَالٍ ابْنَةُ هِلَالٍ عَنْ أَبِيهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَجُوزُ الْجَذَعُ مِنْ الضَّأْنِ أُضْحِيَّةً","id":"Telah menceritakan kepada kami [Ali bin Bahr] telah menceritakan kepada kami [Abu Dlamrah] berkata, telah menceritakan kepada kami [Muhammad bin Abu Yahya] bekas budak Al Aslamiyyin, dari [Ibunya] dia berkata, telah menceritakan kepadaku [Ummu Bilal] dari [putrinya Hilal] dari ayahnya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diperbolehkan berkurban dengan menyembelih jadza' (unta atau sapi yang masuk tahun kedua) dari hewan ternak.\""},"3915":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا مُوسَى بْنُ وَرْدَانَ قَالَ أَخْبَرَنِي عُبَيْدُ بْنُ حُنَيْنٍ مَوْلَى خَارِجَةَأَنَّ الْمَرْأَةَ الَّتِي سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صِيَامِ يَوْمِ السَّبْتِ حَدَّثَتْهُ أَنَّهَا سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ لَا لَكِ وَلَا عَلَيْكِ","id":"Telah menceritakan kepada kami [Hasan bin Musa] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] berkata, telah menceritakan kepada kami [Musa bin Wardan] berkata, telah mengabarkan kepadaku ['Ubaid bin Hunain] bekas budak Kharijah, bahwa [wanita yang bertanya kepada Rasulullah shallallahu 'alaihi wasallam] tentang puasa pada hari sabtu, menceritakan kepadanya bahwa dia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal itu. Beliau lalu menjawab: \"Tidak terhadapmu dan tidak pula atasmu.\""},"3916":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ قَالَ حَدَّثَنَا ثَوْرٌ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ عَنْ أُخْتِهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصُومُوا يَوْمَ السَّبْتِ إِلَّا مَا افْتُرِضَ عَلَيْكُمْ فَإِنْ لَمْ يَجِدْ أَحَدُكُمْ إِلَّا عُودَ عِنَبٍ أَوْ لِحَى شَجَرَةٍ فَلْيَمْضُغْهَا","id":"Telah menceritakan kepada kami [Abu Ashim] berkata, telah menceritakan kepada kami [Tsaur] dari [Khalid bin Ma'dan] dari [Abdullah bin Busr] dari [Saudarinya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berpuasa pada hari sabtu kecuali kalau hal itu diwajibkan atas kalian, jika di antara kalian tidak mendapatkan kecuali setangkai anggur atau kulit tanaman maka hendaknya ia menelannya.\""},"3917":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ قَالَ أَخْبَرَنَا مُوسَى بْنُ وَرْدَانَ عَنْ عُبَيْدٍ الْأَعْرَجِ قَالَ حَدَّثَتْنِي جَدَّتِيأَنَّهَا دَخَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَغَدَّى وَذَلِكَ يَوْمَ السَّبْتِ فَقَالَ تَعَالَيْ فَكُلِي فَقَالَتْ إِنِّي صَائِمَةٌ فَقَالَ لَهَا صُمْتِ أَمْسِ فَقَالَتْ لَا قَالَ فَكُلِي فَإِنَّ صِيَامَ يَوْمِ السَّبْتِ لَا لَكِ وَلَا عَلَيْكِ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] berkata, telah mengabarkan kepada kami [Ibnu Lahi'ah] berkata, telah mengabarkan kepada kami [Musa bin Wardan] dari [Ubaid Al A'raj] berkata, telah menceritakan kepadaku [nenekku] bahwa dia menemui Rasulullah shallallahu 'alaihi wasallam saat beliau sedang makan siang, dan saat itu adalah hari sabtu. Beliau lalu bersabda: \"Kemari dan ikutlah makan.\" Maka aku menjawab, \"Sesungguhnya aku sedang berpuasa.\" Lantas beliau bersabda kepadanya: \"Apakah kemarin kamu berpuasa?\" dia menjawab, \"Tidak.\" Beliau bersabda: \"Makanlah, sesungguhnya puasa hari sabtu bukanlah untukmu dan tidak pula (menjadi kewajiban) atasmu.\""},"3918":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ الْوَلِيدِ الزُّبَيْدِيِّ عَنْ لُقْمَانَ بْنِ عَامِرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ عَنْ أُخْتِهِ الصَّمَّاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَصُومَنَّ أَحَدُكُمْ يَوْمَ السَّبْتِ إِلَّا فِي فَرِيضَةٍ وَإِنْ لَمْ يَجِدْ إِلَّا لِحَى شَجَرَةٍ فَلْيُفْطِرْ عَلَيْهَا","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Muhammad bin Walid Az Zubaidi] dari [Luqman bin Amir] dari [Khalid bin Ma'dan] dari [Abdullah bin Busr] dari saudarinya [Ash Shamma'] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian berpuasa pada hari sabtu kecuali kalau hal itu diwajibkan atas kalian, jika di antara kalian tidak mendapatkan kecuali kulit tanaman maka hendaknya ia menelannya.\""},"3919":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنِ امْرَأَتِهِ عَنْ أُخْتٍ لِحُذَيْفَةَ قَالَتْخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ ��َلَيْهِ وَسَلَّمَ فَقَالَ يَا مَعْشَرَ النِّسَاءِ لَا تَحَلَّيْنَ الذَّهَبَ أَمَا لَكُنَّ فِي الْفِضَّةِ مَا تَحَلَّيْنَ بِهِ مَا مِنْكُنَّ امْرَأَةٌ تَحَلَّى ذَهَبًا تُظْهِرُهُ إِلَّا عُذِّبَتْ بِهِ","id":"Telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Rib'i] dari [isterinya] dari [saudari Hudzaifah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami, beliau bersabda: \"Wahai para wanita janganlah kalian berhias dengan emas, dan tidak mengapa kalian berhias dengan perak, tidaklah di antara kalian para wanita yang berhias dengan emas dan menampakkannya kecuali ia akan diadzab dengannya.\""},"3920":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ حُصَيْنٍ عَنْ أَبِي عُبَيْدَةَ بْنِ حُذَيْفَةَ عَنْ عَمَّتِهِ فَاطِمَةَ أَنَّهَا قَالَتْأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعُودُهُ فِي نِسَاءٍ فَإِذَا سِقَاءٌ مُعَلَّقٌ نَحْوَهُ يَقْطُرُ مَاؤُهُ عَلَيْهِ مِنْ شِدَّةِ مَا يَجِدُ مِنْ حَرِّ الْحُمَّى قُلْنَا يَا رَسُولَ اللَّهِ لَوْ دَعَوْتَ اللَّهَ فَشَفَاكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَشَدِّ النَّاسِ بَلَاءً الْأَنْبِيَاءَ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Hushain] dari [Abu Ubaidah bin Hudzaifah] dari bibinya [Fatimah] bahwa dia berkata, \"Kami mendatangi Rasulullah shallallahu 'alaihi wasallam bersama beberapa wanita untuk mengunjungi beliau, ternyata ada tempat minum yang menggantung di sampingnya, yang airnya menetesi beliau disebabkan oleh panas karena demam yang beliau derita. Kami lalu berkata kepada beliau, \"Wahai Rasulullah, seandainya tuan berdoa kepada Allah hingga Dia menyembuhkanmu.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Sesungguhnya manusia yang paling besar ujiannya adalah para Nabi, kemudian orang-orang yang mengikutinya, kemudian orang-orang yang mengikuti mereka, kemudian orang-orang yang mengikuti mereka.\""},"3921":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ وَسَمِعْتُهُ أَنَا مِنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ زُرْعَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مَوْلًى لِمَعْمَرٍ التَّيْمِيِّ عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍ قَالَتْقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَاذَا كُنْتِ تَسْتَشْفِينَ قَالَتْ بِالشُّبْرُمِ قَالَ حَارٌّ جَارٌّ ثُمَّ اسْتَشْفَيْتُ بِالسَّنَا قَالَ لَوْ كَانَ شَيْءٌ يَشْفِي مِنْ الْمَوْتِ كَانَ السَّنَا أَوْ السَّنَا شِفَاءٌ مِنْ الْمَوْتِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad], dan aku telah mendengarnya dari [Abdullah bin Muhammad bin Abu Syaibah] dia berkata, telah menceritakan kepada kami [Abu Usamah] dari [Abdul Hamid bin Ja'far] dari [Zur'ah bin Abdurrahman] dari [bekas budaknya Ma'mar at Taimi], dari [Asma binti 'Umais] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Dengan apa kamu berobat?\" dia menjawab, \"Dengan Syubrum (sejenis tumbuhan berbiji).\" Beliau bersabda, \"Panas, panas.\" Lalu aku berobat dengan Sana (sejenis tumbuhan), beliau bersabda: \"Jika ada yang bisa menyembuhkan dari kematian, maka itu adalah Sana.\" Atau, \"Sana adalah penyembuh dari kematian.\""},"3922":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُوسَى الْجُهَنِيِّ قَالَدَخَلْتُ عَلَى فَاطِمَةَ بِنْتِ عَلِيٍّ فَقَالَ لَهَا رَفِيقِي أَبُو سَهْلٍ كَمْ لَكِ قَالَتْ سِتَّةٌ وَثَمَانُونَ سَنَةً قَالَ مَا سَمِعْتِ مِنْ أَبِيكِ شَيْئًا قَالَتْ حَدَّثَتْنِي أَسْمَاءُ بِنْتُ عُمَيْسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِعَلِيٍّ أَنْتَ مِنِّي بِمَنْزِلَةِ هَارُونَ مِنْ مُوسَى إِلَّا أَنَّهُ لَيْسَ بَعْدِي نَبِيٌّ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Musa Al Juhani] dia berkata, aku menemui [Fatimah binti 'Ali], lalu temanku, Abu Sahl, berkata kepadanya, \"Berapa umurmu?\" Fatimah menjawab, \"Delapan puluh enam tahun.\" Sahl bertanya lagi, \"Sesuatu apakah yang kamu dengan dari bapakmu?\" Fatimah menjawab, \" [Asma binti Umais] menceritakan kepadaku, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ali: \"Kamu bagiku seperti kedudukan Harun bagi Musa, hanyasanya tidak ada Nabi setelahku.\""},"3923":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبْدُ الْعَزِيزِ قَالَ حَدَّثَنَا هِلَالٌ مَوْلَانَا عَنِ أَبِي عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ عَنْ أُمِّهِ أَسْمَاءَ بِنْتِ عُمَيْسٍ قَالَتْعَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَاتٍ أَقُولُهَا عِنْدَ الْكَرْبِ اللَّهُ رَبِّي لَا أُشْرِكُ بِهِ شَيْئًا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abdul Aziz] berkata, telah menceritakan kepada kami budak kami [Hilal] dari [Umar bin Abdul Aziz] dari [Abdullah bin Ja'far] dari ibunya [Asma binti Umais] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengajariku beberapa kalimat yang aku katakan ketika terkena bencana, yaitu: 'ALLAHU RABBI LAA USYRIKU BIHI SYAI`A (Allah adalah Rabbku yang aku tidak sekutukan dengan apapun) '.\""},"3924":{"ar":"حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ طَلْحَةَ قَالَ حَدَّثَنَا الْحَكَمُ بْنُ عُتَيْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْيَوْمَ الثَّالِثَ مِنْ قَتْلِ جَعْفَرٍ فَقَالَ لَا تَحِدِّي بَعْدَ يَوْمِكِ هَذَا","id":"Telah menceritakan kepada kami [Yazid] berkata, telah memberitakan kepada kami [Muhammad bin Thalhah] berkata, telah menceritakan kepada kami [Al Hakam bin Utaibah] dari [Abdullah bin Syaddad] dari [Asma' binti Umais] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemuiku pada hari ketiga dari kematian Ja'far, suamiku. Beliau bersabda: \"Janganlah kamu melakukan ihdad (meninggalkan perhiasan dan berhias) setelah harimu ini.\""},"3925":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ : مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍأَنَّهَا وَلَدَتْ مُحَمَّدَ بْنَ أَبِي بَكْرٍ بِالْبَيْدَاءِ فَذَكَرَ ذَلِكَ أَبُو بَكْرٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْهَا فَلْتَغْتَسِلْ ثُمَّ لِتُهِلَّ","id":"Abdullah berkata; aku bacakan kepada [Abdurrahman]: [Malik] dari [Abdurrahman bin Qasim] dari [Ayahnya] dari [Asma' binti Umais] bahwa dia melahirkan Muhammad bin Abu Bakar di Baida', lalu Abu Bakar menceritakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Perintahkan dia mandi, lalu berniat untuk berhaji.\""},"3926":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنِ الْوَلِيدِ بْنِ كَثِيرٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُسْلِمٍ الطَّوِيلُ صَاحِبُ الْمَصَاحِفِ أَنَّ كِلَابَ بْنَ تَلِيدٍ أَخَا بَنِي سَعْدِ بْنِ لَيْثٍ أَنَّهُ بَيْنَا هُوَ جَالِسٌ مَعَ سَعِيدِ بْنِ الْمُسَيَّبِ جَاءَهُ رَسُولُ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمِ بْنِ عَدِيٍّ يَقُولُ إِنَّ ابْنَ خَالَتِكَ يَقْرَأُ عَلَيْكَ السَّلَامَ وَيَقُولُ أَخْبِرْنِي كَيْفَ الْحَدِيثُ الَّذِي كُنْتَ حَدَّثْتَنِي عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍ فَقَالَ سَعِيدُ بْنُ الْمُسَيَّبِ أَخْبِرْهُ أَنَّ أَسْمَاءَ بِنْتَ عُمَيْسٍ أَخْبَرَتْنِيأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَصْبِرُ عَلَى لَأْوَاءِ الْمَدِينَةِ وَشِدَّتِهَا أَحَدٌ إِلَّا كُنْتُ لَهُ شَفِيعًا أَوْ شَهِيدًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepadaku [ayahku] dari [Walid bin Katsir] berkata, telah menceritakan kepada kami [Abdullah bin Muslim At Thawil] pemilik kitab Mushannif, bahwa Kilab bin Talid saudara Bani Sa'ad bin Laits, ketika dia duduk bersama [Sa'id Ibnul Musayyab] datanglah utusan Nafi' bin Jubair bin Mut'im bin Adi. Dia berkata, \"Sesungguhnya anak bibimu menyampaikan salam untukmu dan dia berkata, \"Kabarkanlah padaku bagaimana hadits yang kamu riwayatkan dari [Asma binti Umais] kepadaku?\" lalu Sa'id Ibnul Musayyab berkata, \"Kabarkan padanya bahwa Asma binti Umais mengabariku, bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang bersabar terhadap sempit dan kerasnya (iklim) Madinah, kecuali aku akan menjadi saksi baginya atau memberikan syafa'at untuknya pada hari kiamat.\""},"3927":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ أُمِّ عِيسَى الْجَزَّارِ عَنْ أُمِّ جَعْفَرٍ بِنْتِ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ أَبِي طَالِبٍ عَنْ جَدَّتِهَا أَسْمَاءَ بِنْتِ عُمَيْسٍ قَالَتْلَمَّا أُصِيبَ جَعْفَرٌ وَأَصْحَابُهُ دَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ دَبَغْتُ أَرْبَعِينَ مَنِيئَةً وَعَجَنْتُ عَجِينِي وَغَسَّلْتُ بَنِيَّ وَدَهَنْتُهُمْ وَنَظَّفْتُهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْتِينِي بِبَنِي جَعْفَرٍ قَالَتْ فَأَتَيْتُهُ بِهِمْ فَشَمَّهُمْ وَذَرَفَتْ عَيْنَاهُ فَقُلْتُ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي مَا يُبْكِيكَ أَبَلَغَكَ عَنْ جَعْفَرٍ وَأَصْحَابِهِ شَيْءٌ قَالَ نَعَمْ أُصِيبُوا هَذَا الْيَوْمَ قَالَتْ فَقُمْتُ أَصِيحُ وَاجْتَمَعَ إِلَيَّ النِّسَاءُ وَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَهْلِهِ فَقَالَ لَا تُغْفِلُوا آلَ جَعْفَرٍ مِنْ أَنْ تَصْنَعُوا لَهُمْ طَعَامًا فَإِنَّهُمْ قَدْ شُغِلُوا بِأَمْرِ صَاحِبِهِمْ","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepadaku [ayahku] dari [Muhammad bin Ishaq] berkata, telah menceritakan kepada kami [Abdullah bin Abu Bakr] dari [Ummu Isa Al Jazzar] dari [Ummu Ja'far binti Muhammad bin Ja'far bin Abu Thalib] dari neneknya [Asma binti Umais] dia berkata, \"Ketika Ja'far dan beberapa saudara-saudaranya terkena musibah, aku menemui Rasulullah shallallahu 'alaihi wasallam, sedangkan aku telah menyamak empat puluh kulit hewan dan membuat adonan roti. Aku telah memandikan anak-anakku dan aku telah menyisir rambut dan merapikan mereka semua, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Datangkanlah kepadaku anak-anak Ja'far.\" Asma berkata, \"Lalu aku membawa mereka semua dan Rasulullah pun menciumi mereka, lantas meneteslah air mata beliau. Aku bertanya, \"Wahai Rasulullah, apa yang menyebabkanmu menangis, apakah telah sampai kabar kepadamu tentang Ja'far dan beberapa sahabatnya?\" Beliau menjawab: \"Ya, mereka mendapatkan musibah pada hari ini.\" Asma berkata, \"Lalu aku berdiri dan berteriak kemudian para wanita mengelilingiku, dan Rasulullah shallallahu 'alaihi wasallam keluar menuju keluarga beliau dan bersabda: \"Jangan kalian biarkan keluarga Ja'far membuatkan makanan untuk mereka, karena mereka sedang tersibukkan dengan perkara teman mereka.\""},"3928":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سَعْدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَتْنِي زَيْنَبُ بِنْتُ كَعْبٍ عَنْ فُرَيْعَةَ بِنْتِ مَالِكٍ قَالَتْخَرَجَ زَوْجِي فِي طَلَبِ أَعْلَاجٍ لَهُ فَأَدْرَكَهُمْ بِطَرَفِ الْقَدُومِ فَقَتَلُوهُ فَأَتَانِي نَعْيُهُ وَأَنَا فِي دَارٍ شَاسِعَةٍ مِنْ دُورِ أَهْلِي فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقُلْتُ إِنَّ نَعْيَ زَوْجِي أَتَانِي فِي دَارٍ شَاسِعَةٍ مِنْ دُورِ أَهْلِي وَلَمْ يَدَعْ لِي نَفَقَةً وَلَا مَالًا لِوَرَثَتِهِ وَلَيْسَ الْمَسْكَنُ لَهُ فَلَوْ تَحَوَّلْتُ إِلَى أَهْلِي وَأَخْوَالِي لَكَانَ أَرْفَقَ بِي فِي بَعْضِ شَأْنِي قَالَ تَحَوَّلِي فَلَمَّا خَرَجْتُ إِلَى الْمَسْجِدِ أَوْ إِلَى الْحُجْرَةِ دَعَانِي أَوْ أَمَرَ بِي فَدُعِيتُ فَقَالَ امْكُثِي فِي بَيْتِكِ الَّذِي أَتَاكِ فِيهِ نَعْيُ زَوْجِكِ حَتَّى يَبْلُغَ الْكِتَابُ أَجَلَهُ قَالَتْ فَاعْتَدَدْتُ فِيهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا قَالَتْ فَأَرْسَلَ إِلَيَّ عُثْمَانُ فَأَخْبَرْتُهُ فَأَخَذَ بِهِحَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ سَعْدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَتْنِي زَيْنَبُ بِنْتُ كَعْبٍ عَنْ فُرَيْعَةَ بِنْتِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sa'd bin Ishaq] berkata, telah menceritakan kepadaku [Zainab binti Ka'b] dari [Furai'ah binti Malik] dia berkata, \"Suamiku keluar untuk meminta pertolongan kepada orang-orang kafir, ketika dia sampai dipenghujung jalan, mereka membunuhnya, lalu datanglah pembawa kabar kematiannya kepadaku, sedangkan rumahku jauh dari rumah-rumah keluargaku. Lantas aku menemui Rasulullah shallallahu 'alaihi wasallam dan menceritakan akan hal itu, aku katakan, 'Sesungguhnya pembawa kabar kematian suamiku datang kepadaku, sedangkan aku berada di rumah yang jauh dari rumah-rumah keluargaku, dan suamiku tidak meninggalkan untukku nafkah apalagi harta yang akan diwariskannya. Dan dia tidak mempunyai rumah, jika aku pindah ke rumah keluargaku, atau paman-pamanku niscaya akan mempermudah beberapa urusanku.\" Beliau bersabda: \"Pindahlah, \" ketika aku keluar masjid, atau keruanganku, beliau memanggilku atau menyuruh seeorang memanggilku. Maka aku pun dipanggil, beliau lantas bersabda: \"Tetaplah di rumah saat pembawa kabar itu datang hingga habis masa iddahnya.\" Asma berkata, \"Lalu aku menunggu di sana empat bulan sepuluh hari. Kemudian Utsman mengirim kepadaku sesuatu, lalu aku mengabarkannya dan iapun mengambilnya.\" Telah menceritakan kepada kami [Bisyr bin Mufadlal] dari [Sa'd bin Ishaq] dia berkata; telah menceritakan kepadaku [Zainab binti Ka'b] dari [Furai'ah binti Malik] dari Nabi shallallahu 'alaihi wasallam seperti itu.\""},"3929":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا هَانِئُ بْنُ عُثْمَانَ الْجُهَنِيُّ عَنْ أُمِّهِ حُمَيْضَةَ بِنْتِ يَاسِرٍ عَنْ جَدَّتِهَا يُسَيْرَةَ وَكَانَتْ مِنْ الْمُهَاجِرَاتِ قَالَتْقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا نِسَاءَ الْمُؤْمِنَاتِ عَلَيْكُنَّ بِالتَّهْلِيلِ وَالتَّسْبِيحِ وَالتَّقْدِيسِ وَلَا تَغْفُلْنَ فَتَنْسَيْنَ الرَّحْمَةَ وَاعْقِدْنَ بِالْأَنَامِلِ فَإِنَّهُنَّ مَسْئُولَاتٌ مُسْتَنْطَقَاتٌ","id":"Telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah menceritakan kepada kami [Hani' bin Utsman Al Juhani] dari ibunya [Humaidlah binti Yasir] dari neneknya [Yusairah] dia adalah seorang wanita muhajirin, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Wahai kaum wanita yang beriman, bertahlillah, bertasbihlah, dan bertaqdislah (mensucikan Allah) dan janganlah kalian lalai, sehingga kalian lupa akan rahmat (Allah). Dan ikatlah pada ujung jari-jari, karena hal itu akan ditanya dan akan menjawab.\""},"3930":{"ar":"حَدَّثَنَا هَارُونُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ حَدَّثَنِي دَاوُدُ بْنُ قَيْسٍ عَنْ عَبْدِ اللَّهِ بْنِ سُوَيْدٍ الْأَنْصَارِيِّ عَنْ عَمَّتِهِ أُمِّ حُمَيْدٍ امْرَأَةِ أَبِي حُمَيْدٍ السَّاعِدِيِّأَنَّهَا جَاءَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُحِبُّ الصَّلَاةَ مَعَكَ قَالَ قَدْ عَلِمْتُ أَنَّكِ تُحِبِّينَ الصَّلَاةَ مَعِي وَصَلَاتُكِ فِي بَيْتِكِ خَيْرٌ لَكِ مِنْ صَلَاتِكِ فِي حُجْرَتِكِ وَصَلَاتُكِ فِي حُجْرَتِكِ خَيْرٌ مِنْ صَلَاتِكِ فِي دَارِكِ وَصَلَاتُكِ فِي دَارِكِ خَيْرٌ لَكِ مِنْ صَلَاتِكِ فِي مَسْجِدِ قَوْمِكِ وَصَلَاتُكِ فِي مَسْجِدِ قَوْمِكِ خَيْرٌ لَكِ مِنْ صَلَاتِكِ فِي مَسْجِدِيقَالَ فَأَمَرَتْ فَبُنِيَ لَهَا مَسْجِدٌ فِي أَقْصَى شَيْءٍ مِنْ بَيْتِهَا وَأَظْلَمِهِ فَكَانَتْ تُصَلِّي فِيهِ حَتَّى لَقِيَتْ اللَّهَ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Harun] telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah menceritakan kepadaku [Daud bin Qais] dari [Abdullah bin Suwaid Al Anshari] dari bibinya [Ummu Humaid] isteri Abu Humaid As Sa'di, bahwa dia menemui Nabi shallallahu 'alaihi wasallam lalu berkata, \"Wahai Rasulullah, sesungguhnya aku menyukai shalat bersamamu!\" Beliau bersabda: \"Aku sudah tahu jika kamu suka shalat denganku, namun shalatmu di rumahmu lebih baik daripada shalatmu di kamarmu, dan shalatmu di kamarmu lebih baik daripda shalat di rumahmu, dan shalatmu di rumahmu lebih baik daripada shalatmu di masjid kaummu, dan shalatmu di masjid kaummu lebih baik daripada shalat di masjidku.\" Ummu Humaid berkata, \"Lalu dia diperintahkan untuk membuat masjid di tempat yang paling pojok dalam rumahnya dan yang paling gelap, setelah itu dia shalat di sana hingga dia menemui Allah Azza Wa Jalla.\""},"3931":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ أَنَّ صَالِحًا أَبَا الْخَلِيلِ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ أَنَّ أُمَّ حَكِيمٍ بِنْتَ الزُّبَيْرِ حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى ضُبَاعَةَ بِنْتِ الزُّبَيْرِ فَنَهَسَ مِنْ كَتِفٍ عِنْدَهَا ثُمَّ صَلَّى وَمَا تَوَضَّأَ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Sa'id bin Abu Urubah] dari [Qatadah] bahwa [Shalih Abu Khalil] telah menceritakan kepadanya dari [Abdullah bin Harits bin Naufal] bahwa [Ummu Hakim binti Zubair] menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam mendatangi Dluba'ah binti Zubair, beliau lalu memakan daging (pundak kambing) kemudian shalat dan tidak berwudlu karenanya.\""},"3932":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا رَافِعُ بْنُ سَلَمَةَ الْأَشْجَعِيُّ قَالَ حَدَّثَنِي حَشْرَجُ بْنُ زِيَادٍ عَنْ جَدَّتِهِ أُمِّ أَبِيهِ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ خَيْبَرَ وَأَنَا سَادِسَةُ سِتِّ نِسْوَةٍ قَالَتْ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ مَعَهُ نِسَاءً قَالَتْ فَأَرْسَلَ إِلَيْنَا فَدَعَانَا قَالَتْ فَرَأَيْنَا فِي وَجْهِهِ الْغَضَبَ فَقَالَ مَا أَخْرَجَكُنَّ وَبِأَمْرِ مَنْ خَرَجْتُنَّ قُلْنَا خَرَجْنَا مَعَكَ نُنَاوِلُ السِّهَامَ وَنَسْقِي السَّوِيقَ وَمَعَنَا دَوَاءٌ لِلْجُرْحِ وَنَغْزِلُ الشَّعْرَ فَنُعِينُ بِهِ فِي سَبِيلِ اللَّهِ قَالَ قُمْنَ فَانْصَرِفْنَ قَالَتْ فَلَمَّا فَتَحَ اللَّهُ عَلَيْهِ خَيْبَرَ أَخْرَجَ لَنَا مِنْهَا سِهَامًا كَسِهَامِ الرِّجَالِفَقُلْتُ لَهَا يَا جَدَّتِي وَمَا الَّذِي أَخْرَجَ لَكُنَّ قَالَتْ تَمْرٌ","id":"Telah menceritakan kepada kami [Hasan bin Musa] berkata, telah menceritakan kepada kami [Rafi' bin Salamah Al Asyja'i] berkata, telah menceritakan kepadaku [Hasyraj bin Ziyad] dari [neneknya] ibu dari ayahnya, dia berkata, \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam pada perang Khaibar dan aku adalah orang keenam dari enam wanita.\" Dia berkata, \"Kemudian sampailah kabar kepada Nabi shallallahu 'alaihi wasallam bahwasanya ada beberapa wanita yang ikut bersama beliau, lalu beliau mengirim seseorang kepada kami untuk memanggil kami. Dan kami melihat kemarahan pada wajah beliau, beliau bersabda: \"Apa yang menyebabkan kalian keluar dan atas perintah siapa kalian keluar?\" kami menjawab, \"Kami keluar bersama tuan setelah melakukan undian, membawakan air, dan kami membawa obat-obatan bagi yang terluka, kami pintal rambut dan kami beri pertolongan dengannya di jalan Allah.\" Beliau bersabda: \"Berdiri dan pergilah, \" dia berkata, \"Ketika Allah membukakan Khaibar beliau mengeluarkan untuk kami undian seperti yang dilakukan untuk kaum lelaki.\" Aku lalu berkata kepadanya, \"Hai nenekku, apa yang beliau keluarkan untuk kalian.\" Dia menjawab, \"Kurma.\""},"3933":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا الْمَسْعُودِيُّ قَالَ حَدَّثَنِي مَعْبَدُ بْنُ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ يَسَارٍ عَنْ قُتَيْلَةَ بِنْتِ صَيْفِيٍّ الْجُهَيْنِيَّةِ قَالَتْأَتَى حَبْرٌ مِنْ الْأَحْبَارِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُحَمَّدُ نِعْمَ الْقَوْمُ أَنْتُمْ لَوْلَا أَنَّكُمْ تُشْرِكُونَ قَالَ سُبْحَانَ اللَّهِ وَمَا ذَاكَ قَالَ تَقُولُونَ إِذَا حَلَفْتُمْ وَالْكَعْبَةِ قَالَتْ فَأَمْهَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا ثُمَّ قَالَ إِنَّهُ قَدْ قَالَ فَمَنْ حَلَفَ فَلْيَحْلِفْ بِرَبِّ الْكَعْبَةِ قَالَ يَا مُحَمَّدُ نِعْمَ الْقَوْمُ أَنْتُمْ لَوْلَا أَنَّكُمْ تَجْعَلُونَ لِلَّهِ نِدًّا قَالَ سُبْحَانَ اللَّهِ وَمَا ذَاكَ قَالَ تَقُولُونَ مَا شَاءَ اللَّهُ وَشِئْتَ قَالَ فَأَمْهَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا ثُمَّ قَالَ إِنَّهُ قَدْ قَالَ فَمَنْ قَالَ مَا شَاءَ اللَّهُ فَلْيَفْصِلْ بَيْنَهُمَا ثُمَّ شِئْتَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Mas'udi] berkata, telah menceritakan kepadaku [Ma'bad bin Khalid] dari [Abdullah bin Yasar] dari [Qutailah binti Shafi Al Juhainah] dia berkata, \"Seorang rahib datang menemui Rasulullah shallallahu 'alaihi wasallam lalu berkata, \"Wahai Muhammad, sebaik-baik kaum adalah kalian, jika kalian tidak berbuat syirik.\" Beliau pun bersabda: \"Subhanallah, apa yang kau maksud?\" Qutailah menjawab, \"Jika bersumpah kalian mengatakan 'Demi Ka'bah'.\" Qutailah berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam menunggu sesuatu, lalu beliau bersabda: \"Sesungguhnya telah dikatakan bahwa barangsiapa yang hendak bersumpah maka bersumpahlah dengan pemilik Ka'bah.\" Rahib itu berkata, \"Wahai Muhammad, sebaik-baik kaum adalah kalian jika kalian tidak menjadikan bagi Allah sekutu.\" Beliau bersabda: \"Subhanallah apa yang kau maksud?\" ia menjawab, \"Kalian mengatakan 'Maa syaallah wa syi'ta (Atas kehendak Allah dan atas kehendakmu) '.\" Qutailah berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam menunggu sesuatu lalu beliau bersabda: \"Sesungguhnya telah dikatakan bahwa, barangsiapa mengatakan 'Maa syaallah', maka hendaknya (jika ia meneruskan) ia meneruskan dengan mengatakan 'tsumma syi'ta (kemudian atas kehendak kamu) '.\""},"3934":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رَجُلٍ مِنْ آلِ أَبِي حَثْمَةَ عَنِ الشِّفَاءِ بِنْتِ عَبْدِ اللَّهِ وَكَانَتْ امْرَأَةً مِنْ الْمُهَاجِرَاتِ قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ أَفْضَلِ الْأَعْمَالِ فَقَالَ إِيمَانٌ بِاللَّهِ وَجِهَادٌ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ وَحَجٌّ مَبْرُورٌ","id":"Telah menceritakan kepada kami [Hasyim bin Qasim] berkata, telah menceritakan kepada kami [Al Mas'udi] dari [Abdul Malik bin Umair] dari [seorang laki-laki] dari keluarga Hatsmah, dari [Syifa' binti Abdullah] dia adalah orang yang pernah ikut berhijrah, ia berkata \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam ditanya tentang sebaik-baik amalan, beliau menjawab: \"Iman kepada Allah, berjihad di jalan Allah Azza Wa Jalla dan haji mabrur.\""},"3935":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سُلَيْمَانَ بْنِ أَبِي حَثْمَةَ عَنِ الشِّفَاءِ بِنْتِ عَبْدِ اللَّهِ قَالَتْدَخَلَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا عِنْدَ حَفْصَةَ فَقَالَ لِي أَلَا تُعَلِّمِينَ هَذِهِ رُقْيَةَ النَّمْلَةِ كَمَا عَلَّمْتِيهَا الْكِتَابَةَ","id":"Telah menceritakan kepada kami [Ibrahim bin Mahdi] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Abdul Aziz bin Umar bin Abdul Aziz] dari [Shalih bin Kaisan] dari [Abu Bakr bin Abdurrahman bin Sulaiman bin Abu Hatsmah] dari [Syifa' binti Abdullah] dia berkata, \"Nabi shallallahu 'alaihi wasallam menemui kami saat aku berada di samping Hafshah, beliau bersabda kepadaku: \"Tidakkah kamu mengajarkan ruqyah untuk luka ini sebagaimana kamu mengajarinya menulis.\""},"3936":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا الْمَسْعُودِيُّ وَأَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِئُ قَالَ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رَجُلٍ مِنْ آلِ أَبِي حَثْمَةَ عَنِ الشِّفَاءِ بِنْتِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ الْإِيمَانُ بِاللَّهِ وَالْجِهَادُ فِي سَبِيلِ اللَّهِ وَحَجٌّ مَبْرُورٌ قَالَ أَبُو عَبْدِ الرَّحْمَنِ أَوْ حَجٌّ مَبْرُورٌ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Al Mas'udi] dan [Abu Abdurrahman Al Muqri'] berkata, telah menceritakan kepada kami [Al Mas'udi] dari [Abdul Malik bin Umair] dari [seorang laki-laki] dari keluarga Abu Hatsmah, dari [Syifa' binti Abdullah] bahwa Nabi shallallahu 'alaihi wasallam ditanya mengenai amalan apakah yang paling utama? Beliau menjawab: \"Iman kepada Allah, berjihad di jalan Allah dan haji mabrur.\" Abu Abdurrahman menyebutkan, \"Atau haji mabrur.\""},"3937":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زَيْدٍ الْفَائِشِيِّ عَنِ ابْنَةٍ لِخَبَّابٍ قَالَتْخَرَجَ خَبَّابٌ فِي سَرِيَّةٍ فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَاهَدُنَا حَتَّى كَانَ يَحْلُبُ عَنْزًا لَنَا قَالَتْ فَكَانَ يَحْلُبُهَا حَتَّى يَطْفَحَ أَوْ يَفِيضَ فَلَمَّا رَجَعَ خَبَّابٌ حَلَبَهَا فَرَجَعَ حِلَابُهَا إِلَى مَا كَانَ فَقُلْنَا لَهُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْلُبُهَا حَتَّى يَفِيضَ وَقَالَ مَرَّةً حَتَّى تَمْتَلِئَ فَلَمَّا حَلَبْتَهَا رَجَعَ حِلَابُهَاحَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَالِكٍ الْأَحْمَسِيِّ عَنِ ابْنَةٍ لِخَبَّابِ بْنِ الْأَرَتِّ قَالَتْ خَرَجَ أَبِي فِي غَزَاةٍ وَلَمْ يَتْرُكْ إِلَّا شَاةً فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masi] dari [Abu Ishaq] dari [Abdurrahman bin Zaid Al Faisyi] dari [seorang anak perempuan Khabbab] dia berkata, \"Khabbab keluar pada suatu ekspedisi, dan Nabi shallallahu 'alaihi wasallam mengadakan perjanjian kepada kami hingga beliau memerah seekor kambing untuk kami, beliau memerah susunya hingga memenuhi tempatnya. Ketika Khabbab pulang, dia memerah susu lalu mengembalikan bejananya ke tempat semula, kami lalu berkata kepadanya, \"Jika Rasulullah shallallahu 'alaihi wasallam memerah susu maka beliau melakukannya hingga penuh terisi, atau dia berkata, 'hingga bejana terisi seluruhnya, namun ketika kamu memerah susu, bejananya tidak terisi penuh.\" Telah menceritakan kepada kami [Khalaf bin Walid] berkata; telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Abdurrahman bin Malik Al Ahmasyi] dari [seorang anak perempuan Khabbab bin Al Arats] dia berkata, \"Ayahku keluar pada suatu peperangan dan dia tidak meninggalkan kecuali hanya seekor kambing….lalu dia menyebutkan hadistnya.\""},"3938":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ إِسْمَاعِيلَ بْنِ أَبِي حَبِيبَةَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ الْأَشْهَلِيُّ عَنْ أُمِّ عَامِرٍ بِنْتِ يَزِيدَ امْرَأَةٍ مِنْ الْمُبَايِعَاتِأَنَّهَا أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرْقٍ فِي مَسْجِدِ بَنِي فُلَانٍ فَتَعَرَّقَهُ ثُمَّ قَامَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Ibrahim bin Isma'il bin Abu Habibah] berkata, telah menceritakan kepada kami [Abdurrahman bin Abdullah Al Asyhali] dari [Ummi 'Amir bin Yazid], bahwa di antara para wanita yang berbaiat, ada seseorang dari mereka datang kepada Nabi shallallahu 'alaihi wasallam dengan membawa daging di masjid Bani Fulan, lalu beliau memakannya kemudian berdiri shalat dan tidak berwudlu.\""},"3939":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُجَالِدٌ قَالَ حَدَّثَنَا عَامِرٌ قَالَقَدِمْتُ الْمَدِينَةَ فَأَتَيْتُ فَاطِمَةَ بِنْتَ قَيْسٍ فَحَدَّثَتْنِي أَنَّ زَوْجَهَا طَلَّقَهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ قَالَتْ فَقَالَ لِي أَخُوهُ اخْرُجِي مِنْ الدَّارِ فَقُلْتُ إِنَّ لِي نَفَقَةً وَسُكْنَى حَتَّى يَحِلَّ الْأَجَلُ قَالَ لَا قَالَتْ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّ فُلَانًا طَلَّقَنِي وَإِنَّ أَخَاهُ أَخْرَجَنِي وَمَنَعَنِي السُّكْنَى وَالنَّفَقَةَ فَأَرْسَلَ إِلَيْهِ فَقَالَ مَا لَكَ وَلِابْنَةِ آلِ قَيْسٍ قَالَ يَا رَسُولَ اللَّهِ إِنَّ أَخِي طَلَّقَهَا ثَلَاثًا جَمِيعًا قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرِي يَا ابْنَةَ آلِ قَيْسٍ إِنَّمَا النَّفَقَةُ وَالسُّكْنَى لِلْمَرْأَةِ عَلَى زَوْجِهَا مَا كَانَتْ لَهُ عَلَيْهَا رَجْعَةٌ فَإِذَا لَمْ يَكُنْ لَهُ عَلَيْهَا رَجْعَةٌ فَلَا نَفَقَةَ وَلَا سُكْنَى اخْرُجِي فَانْزِلِي عَلَى فُلَانَةَ ثُمَّ قَالَ إِنَّهُ يُتَحَدَّثُ إِلَيْهَا انْزِلِي عَلَى ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ أَعْمَى لَا يَرَاكِ ثُمَّ لَا تَنْكِحِي حَتَّى أَكُونَ أُنْكِحُكِ قَالَتْ فَخَطَبَنِي رَجُلٌ مِنْ قُرَيْشٍ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْتَأْمِرُهُ فَقَالَ أَلَا تَنْكِحِينَ مَنْ هُوَ أَحَبُّ إِلَيَّ مِنْهُ فَقُلْتُ بَلَى يَا رَسُولَ اللَّهِ فَأَنْكِحْنِي مَنْ أَحْبَبْتَ قَالَتْ فَأَنْكَحَنِي أُسَامَةَ بْنَ زَيْدٍ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Mujalid] berkata, telah menceritakan kepada kami [Amir] dia berkata, \"Saat memasuki Madinah, aku menemui [Fatimah binti Qais] dia mengatakan kepadaku bahwa suaminya telah menceraikannya pada masa Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam mengutusnya (suami) pada suatu ekspedisi.\" Fatimah berkata, \"Kemudian saudaranya berkata kepadaku, \"Keluarlah dari rumah.\" Aku pun berkata, \"Sesungguhnya aku memiliki hak untuk dinafkahi dan tempat tinggal hingga selesai masanya.\" Dia (saudaranya) Berkata, \"Tidak bisa.\" Lalu aku menemui Rasulullah shallallahu 'alaihi wasallam, aku sampaikan kepada beliau, \"Sesungguhnya fulan menceraikan aku dan saudaranya mengeluarkan aku dari rumahnya, ia menghalangiku untuk bertempat tinggal dan tidak memberiku nafkah?\" Kemudian beliau mengirim seseorang menemuinya, beliau bersabda: \"Apa urusanmu dengan anak perempuan keluarga Qais?\" dia menjawab, \"Wahai Rasulullah, sesungguhnya saudaraku telah mentalaknya tiga kali sekaligus.\" Fatimah berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lihatlah hai anak perempuan keluarga Qais, hanyasanya tempat tinggal dan nafkah itu untuk isteri yang ditalak suaminya namun ia masih bisa rujuk kepadanya, apabila ditalak yang tidak bisa rujuk lagi maka tidak ada nafkah dan tempat tinggal, oleh karena itu keluarlah dan tinggallah di rumah fulanah.\" Kemudian beliau berkata -ini ditujukan kepada wanita tersebut-: \"Tinggallah di rumah Ibnu Ummi Maktum karena sesungguhnya ia buta dan tidak melihatmu, lalu janganlah menikah hingga aku menikahkanmu.\" Fatimah berkata, \"Lalu datanglah seorang Quraisy untuk melamarku, kemudian aku mendatangi Rasulullah shallallahu 'alaihi wasallam menanyakan hal itu, beliau bersabda: \"Tidakkah kamu menikahi orang yang lebih aku cintai daripadanya?\" aku menjawab, \"Baik ya Rasulullah, nikahkan aku dengan siapapun yang tuan cintai.\" Fatimah melanjutkan, \"Lalu beliau menikahkanku dengan Usamah bin Zaid.\""},"3940":{"ar":"قَالَ فَلَمَّا أَرَدْتُ أَنْ أَخْرُجَ قَالَتْ اجْلِسْ حَتَّى أُحَدِّثَكَ حَدِيثًا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا مِنْ الْأَيَّامِ فَصَلَّى صَلَاةَ الْهَاجِرَةِ ثُمَّ قَعَدَ فَفَزِعَ النَّاسُ فَقَالَ اجْلِسُوا أَيُّهَا النَّاسُ فَإِنِّي لَمْ أَقُمْ مَقَامِي هَذَا لِفَزَعٍ وَلَكِنَّ تَمِيمًا الدَّارِيَّ أَتَانِي فَأَخْبَرَنِي خَبَرًا مَنَعَنِي الْقَيْلُولَةَ مِنْ الْفَرَحِ وَقُرَّةِ الْعَيْنِ فَأَحْبَبْتُ أَنْ أَنْشُرَ عَلَيْكُمْ فَرَحَ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَنِي أَنَّ رَهْطًا مِنْ بَنِي عَمِّهِ رَكِبُوا الْبَحْرَ فَأَصَابَتْهُمْ رِيحٌ عَاصِفٌ فَأَلْجَأَتْهُمْ الرِّيحُ إِلَى جَزِيرَةٍ لَا يَعْرِفُونَهَا فَقَعَدُوا فِي قُوَيْرِبٍ بِالسَّفِينَةِ حَتَّى خَرَجُوا إِلَى الْجَزِيرَةِ فَإِذَا هُمْ بِشَيْءٍ أَهْلَبَ كَثِيرِ الشَّعْرِ لَا يَدْرُونَ أَرَجُلٌ هُوَ أَوْ امْرَأَةٌ فَسَلَّمُوا عَلَيْهِ فَرَدَّ عَلَيْهِمْ السَّلَامَ قَالُوا أَلَا تُخْبِرُنَا قَالَ مَا أَنَا بِمُخْبِرِكُمْ وَلَا بِمُسْتَخْبِرِكُمْ وَلَكِنْ هَذَا الدَّيْرَ قَدْ رَهِقْتُمُوهُ فَفِيهِ مَنْ هُوَ إِلَى خَبَرِكُمْ بِالْأَشْوَاقِ أَنْ يُخْبِرَكُمْ وَيَسْتَخْبِرَكُمْ قَالَ قُلْنَا فَمَا أَنْتَ قَالَ أَنَا الْجَسَّاسَةُ فَانْطَلَقُوا حَتَّى أَتَوْا الدَّيْرَ فَإِذَا هُمْ بِرَجُلٍ مُوثَقٍ شَدِيدِ الْوَثَاقِ مُظْهِرٍ الْحُزْنَ كَثِيرِ التَّشَكِّي فَسَلَّمُوا عَلَيْهِ فَرَدَّ عَلَيْهِمْ فَقَالَ مِمَّنْ أَنْتُمْ قَالُوا مِنْ الْعَرَبِ قَالَ مَا فَعَلَتْ الْعَرَبُ أَخَرَجَ نَبِيُّهُمْ بَعْدُ قَالُوا نَعَمْ قَالَ فَمَا فَعَلُوا قَالُوا خَيْرًا آمَنُوا بِهِ وَصَدَّقُوهُ قَالَ ذَلِكَ خَيْرٌ لَهُمْ وَكَانَ لَهُ عَدُوٌّ فَأَظْهَرَهُ اللَّهُ عَلَيْهِمْ قَالَ فَالْعَرَبُ الْيَوْمَ إِلَهُهُمْ وَاحِدٌ وَدِينُهُمْ وَاحِدٌ وَكَلِمَتُهُمْ وَاحِدَةٌ قَالُوا نَعَمْ قَالَ فَمَا فَعَلَتْ عَيْنُ زُغَرَ قَالُوا صَالِحَةٌ يَشْرَبُ مِنْهَا أَهْلُهَا لِشَفَتِهِمْ وَيَسْقُونَ مِنْهَا زَرْعَهُمْ قَالَ فَمَا فَعَلَ نَخْلٌ بَيْنَ عَمَّانَ وَبَيْسَانَ قَالُوا صَالِحٌ يُطْعِمُ جَنَاهُ كُلَّ عَامٍ قَالَ فَمَا فَعَلَتْ بُحَيْرَةُ الطَّبَرِيَّةِ قَالُوا مَلْأَى قَالَ فَزَفَرَ ثُمَّ زَفَرَ ثُمَّ زَفَرَ ثُمَّ حَلَفَ لَوْ خَرَجْتُ مِنْ مَكَانِي هَذَا مَا تَرَكْتُ أَرْضًا مِنْ أَرْضِ اللَّهِ إِلَّا وَطِئْتُهَا غَيْرَ طَيْبَةَ لَيْسَ لِي عَلَيْهَا سُلْطَانٌ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى هَذَا انْتَهَى فَرَحِي ثَلَاثَ مِرَارٍ إِنَّ طَيْبَةَ الْمَدِينَةَ إِنَّ اللَّهَ حَرَّمَ حَرَمِي عَلَى الدَّجَّالِ أَنْ يَدْخُلَهَا ثُمَّ حَلَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي لَا إِلَهَ إِلَّا هُوَ مَا لَهَا طَرِيقٌ ضَيِّقٌ وَلَا وَاسِعٌ فِي سَهْلٍ وَلَا فِي جَبَلٍ إِلَّا عَلَيْهِ مَلَكٌ شَاهِرٌ بِالسَّيْفِ إِلَى يَوْمِ الْقِيَامَةِ مَا يَسْتَطِيعُ الدَّجَّالُ أَنْ يَدْخُلَهَا عَلَى أَهْلِهَاقَالَ عَامِرٌ فَلَقِيتُ الْمُحَرَّرَ بْنَ أَبِي هُرَيْرَةَ فَحَدَّثْتُهُ حَدِيثَ فَاطِمَةَ بِنْتِ قَيْسٍ فَقَالَ أَشْهَدُ عَلَى أَبِي أَنَّهُ حَدَّثَنِي كَمَا حَدَّثَتْكَ فَاطِمَةُ غَيْرَ أَنَّهُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ نَحْوَ الْمَشْرِقِ قَالَ ثُمَّ لَقِيتُ الْقَاسِمَ بْنَ مُحَمَّدٍ فَذَكَرْتُ لَهُ حَدِيثَ فَاطِمَةَ فَقَالَ أَشْهَدُ عَلَى عَائِشَةَ أَنَّهَا حَدَّثَتْنِي كَمَا حَدَّثَتْكَ فَاطِمَةُ غَيْرَ أَنَّهَا قَالَتْ الْحَرَمَانِ عَلَيْهِ حَرَامٌ مَكَّةُ وَالْمَدِينَةُ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya), Abdullah berkata -Tatkala aku ingin keluar, dia berkata; duduklah sehingga aku bisa menceritakan kepadamu hadits dari Rasulullah shallallahu 'alaihi wasallam- [Fatimah bin Qais] berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam keluar lalu beliau mengerjakan shalat hajirah (waktu dluha) kemudian beliau duduk, maka orang-orang sama terkejut, lalu beliau bersabda: \"Duduklah wahai manusia, sesungguhnya aku berdiri di tempatku ini tidak untuk mengejutkan kalian, akan tetapi Tamim Ad Dari telah menemuiku dan mengabarkan kepadaku sehingga aku tidak bisa Qailulah (tidur siang) karena sangat menyenangkan dan menyejukkan hati, oleh karenanya aku ingin menyebarkan kepada kalian berita senangnya Nabi kalian. Tamim telah mengabarkan kepadaku bahwa sekelompok orang dari keturunan pamannya yang mengarungi lautan kemudian mereka diterpa oleh angin topan sehingga membuat mereka terdampar di sebuah pulau yang asing bagi mereka, kemudian mereka duduk di sampan sampai keluar menuju pulau, tiba tiba mereka bertemu dengan makluq yang berparas sangat kasar dan berambut gondrong sehingga tidak katahuan apakah dia laki laki atau perempuan. Kemudian mereka mengucapkan salam kepadanya dan dia menjawab salam, mereka bertanya, 'Mahukah kamu bercerita kepada kami? ' Makhluk itu menjawab, 'Aku bukanlah orang yang bercerita dan bukan pula yang meminta cerita kepada kalian, akan tetapi pergilah ke tempat peribadatan ini, yang kalian telah mendekatinya, di dalamnya ada orang yang sangat menanti berita kalian, dia akan bercerita dan meminta cerita kepada kalian'. Kemudian mereka bertanya, 'Maka kami bertanya, 'Siapa kamu? ' dia menjawab, 'Aku adalah Jassasah'. Lalu mereka berjalan sampai tiba di tempat peribadatan, akhirnya mereka mendapatkan seorang lelaki yang penuh dengan rantai, berpenampilan sedih dan banyak mengeluh. Mereka kemudian mengucapkan salam kepadanya, dan dia pun menjawab salam mereka. Lalu dia bertanya, 'Siapa kalian? ' mereka menjawab, 'Kami orang-orang dari bangsa Arab.' Dia bertanya lagi, 'Tidakkah orang-orang arab saat ini mengusir Nabi mereka? ' mereka menjawab, 'Ya, ' dia bertanya lagi, 'Maka apa yang dilakukan oleh orang orang Arab? ' mereka menjawab, 'Mereka melakukan sesuatu yang baik, beriman kepadanya dan membenarkannya.' Dia berkata, 'Itu adalah lebih baik bagi mereka, dan dia mempunyai musuh namun Allah memenangkannya dari mereka.' Lelaki itu kemudian bertanya lagi, 'Berarti orang-orang arab hari ini tuhan mereka satu, agama mereka satu dan kalimat mereka satu? ' mereka menjawab, 'Ya.' Dia bertanya lagi, 'Maka apa yang terjadi dengan 'Ainu Zughar (nama mata air)? ' mereka menjawab, 'Terjadi sesuatu yang baik, para penduduk mengambil air darinya untuk minum, dan menyiram tanaman mereka darinya, ' kemudian dia bertanya lagi, 'Maka apa yang terjadi dengan pohon kurma yang ada di antara Aman dan Baisan? ' mereka menjawab, 'Terjadi sesuatu yang baik, hasil panen darinya dapat memberikan kecukupan makanan setiap tahunnya, ' dia bertanya, 'Kemudian apa yang terjadi dengan perahu Tabariyah? ' mereka menjawab, 'Penuh.\" Tamim berkata, 'Kemudian lelaki itu mengeluarkan nafas, kemudian mengeluarkan nafas lagi dan kemudian mengeluarkan nafas lalu bersumpah, 'Seandainya aku keluar dari tempatku ini, pasti tidak aku tinggalkan satu bumipun dari bumi Allah melainkan akan aku lalui kecuali, Thaibah (nama kota Madinah), tidak ada kekuasaan bagiku atasnya.\" Amir bin Syarahil berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sampai di sini selesai kegembiraanku -tiga kali-. Sesungguhnya kebaikan kota Madinah ialah karena Allah Azza Wa Jalla telah mengharamkan kepada Dajjal untuk memasukinya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersumpah: \"Demi Allah, yang tidak ada tuhan yang berhak disembah selain Dia, tidak ada jalan di dataran maupun perbukitan baik sempit maupun luas kacuali dijaga oleh Malaikat dengan pedang terhunus sampai hari Qiyamat, dan Dajjal tidak akan dapat masuk menemui penduduknya.\" [Amir] berkata, \"Aku lalu bertemu dengan [Al Muharrar bin Abu Hurairah], lalu aku ceritakan kepadanya hadits Fatimah binti Qais hingga ia pun berkata, \"Aku bersaksi atas [bapakku], bahwa dia telah menceritakan kepadaku sebagaimana Fatimah telah menceritakan kepadamu, hanya saja bapakku berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia (Dajjal) akan muncul dari arah timur.\" Amir berkata, \"Kemudian aku bertemu dengan [Al Qasim bin Muhammad] kemudian aku menceritakan kepadanya hadits Fatimah dan dia berkata, \"Aku bersaksi atas ['Aisyah] bahwa dia telah menceritakan kepadaku sebagaimana Fatimah telah menceritakan kepadamu, hanya saja 'Aisyah menyebutkan, \"Dua tanah haram, yaitu Makkah dan Madinah.\""},"3941":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ دَاوُدَ يَعْنِي ابْنَ أَبِي هِنْدٍ عَنِ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ ذَاتَ يَوْمٍ مُسْرِعًا فَصَعِدَ الْمِنْبَرَ وَنُودِيَ فِي النَّاسِ الصَّلَاةُ جَامِعَةٌ فَاجْتَمَعَ النَّاسُ فَقَالَ يَا أَيُّهَا النَّاسُ إِنِّي لَمْ أَدْعُكُمْ لِرَغْبَةٍ نَزَلَتْ وَلَا لِرَهْبَةٍ وَلَكِنَّ تَمِيمًا الدَّارِيَّ أَخْبَرَنِي أَنَّ نَفَرًا مِنْ أَهْلِ فِلَسْطِينَ رَكِبُوا الْبَحْرَ فَقَذَفَتْهُمْ الرِّيحُ إِلَى جَزِيرَةٍ مِنْ جَزَائِرِ الْبَحْرِ فَإِذَا هُمْ بِدَابَّةٍ أَشْعَرَ مَا يُدْرَى أَذَكَرٌ هُوَ أَمْ أُنْثَى لِكَثْرَةِ شَعْرِهِ قَالُوا مَنْ أَنْتَ فَقَالَتْ أَنَا الْجَسَّاسَةُ فَقَالُوا فَأَخْبِرِينَا فَقَالَتْ مَا أَنَا بِمُخْبِرَتِكُمْ وَلَا مُسْتَخْبِرَتِكُمْ وَلَكِنْ فِي هَذَا الدَّيْرِ رَجُلٌ فَقِيرٌ إِلَى أَنْ يُخْبِرَكُمْ وَإِلَى أَنْ يَسْتَخْبِرَكُمْ فَدَخَلُوا الدَّيْرَ فَإِذَا رَجُلٌ أَعْوَرُ مُصَفَّدٌ فِي الْحَدِيدِ فَقَالَ مَنْ أَنْتُمْ قُلْنَا نَحْنُ الْعَرَبُ فَقَالَ هَلْ بُعِثَ فِيكُمْ النَّبِيُّ قَالُوا نَعَمْ قَالَ فَهَلْ اتَّبَعَتْهُ الْعَرَبُ قَالُوا نَعَمْ قَالَ ذَلِكَ خَيْرٌ لَهُمْ قَالَ مَا فَعَلَتْ فَارِسُ هَلْ ظَهَرَ عَلَيْهَا قَالُوا لَمْ يَظْهَرْ عَلَيْهَا بَعْدُ فَقَالَ أَمَا إِنَّهُ سَيَظْهَرُ عَلَيْهَا ثُمَّ قَالَ مَا فَعَلَتْ عَيْنُ زُغَرَ قَالُوا هِيَ تَدْفُقُ مَلْأَى قَالَ فَمَا فَعَلَ نَخْلُ بَيْسَانَ هَلْ أَطْعَمَ قَالُوا قَدْ أَطْعَمَ أَوَائِلُهُ قَالَ فَوَثَبَ وَثْبَةً حَتَّى ظَنَنَّا أَنَّهُ سَيَفْلِتُ فَقُلْنَا مَنْ أَنْتَ قَالَ أَنَا الدَّجَّالُ أَمَا إِنِّي سَأَطَأُ الْأَرْضَ كُلَّهَا غَيْرَ مَكَّةَ وَطَيْبَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْشِرُوا يَا مَعْشَرَ الْمُسْلِمِينَ هَذِهِ طَيْبَةُ لَا يَدْخُلُهَا يَعْنِي الدَّجَّالَ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami [Hammad] -yakni Ibnu Salamah- dari [Daud] -yakni Ibnu Abu Hindi- dari [As Sya'bi] dari [Fatimah binti Qais], bahwa suatu hari Rasulullah shallallahu 'alaihi wasallam datang dengan tergesa-gesa, kemudian beliau naik minbar dan diserukan kepada manusia 'Hendaklah shalat berjamaah'. Orang-orang pun berkumpul, lantas beliau bersabda: \"Wahai sekalian manusia, sesungguhnya aku menyeru kalian bukan karena ada perkara yang mengejutkan atau menyenangkan, akan tetapi Tamim Ad-Dari telah mengabarkan kepadaku bahwa sekelompok penduduk Palestina berlayar di tengah laut, kemudian mereka diombang-ambingkan oleh angin hingga terdampat disebuah pulau dari beberapa pulau di tengah laut. Tiba-tiba ia dikejutkan oleh seekor binatang yang berambut gondrong, tidak diketahui laki-laki ataukah perempuan, disebabkan rambutnya yang terlalu lebat, mereka bertanya, 'Siapakah kamu? ' Ia (binatang) menjawab, 'Aku adalah Jassasah, ' mereka bertanya lagi, 'Mahukah kamu bercerita kepada kami? ' dia menjawab, 'Aku bukanlah orang yang bercerita dan bukan pula yang meminta cerita kepada kalian, akan tetapi pergilah ke tempat peribadatan ini kalian akan menemui seorang laki-laki yang fakir, dia akan bercerita dan meminta cerita kepada kalian.' Lalu mereka memasuki biara, dan ternyata di sana ada seorang laki-laki buta telah terantai dengan besi, dia berkata, 'Siapa kalian? ' kami berkata, 'Kami dari penduduk Arab.' Dia berkata, 'Apakah di antara kalian telah diutus seorang Nabi? ' mereka menjawab, 'Ya.' Dia bertanya lagi, 'Apakah orang-orang Arab mengikutinya? ' mereka menjawab, 'Ya.' Dia lalu berkata, 'Itu lebih baik buat mereka.' Dia bertanya lagi, 'Apa yang diperbuat orang-orang Persia? Apakah dia (Nabi) Telah mengalahkannya? ' Mereka menjawab, 'Dia tidak akan mampu mengalahkannya.' Laki-laki itu pun berkata, 'Sesungguhnya dia (nabi) akan mengalahkannya (menguasainya).' Kemudian dia bertanya lagi, 'Apa yang terjadi dengan mata air Zughar? ' Mereka menjawab, 'Ia penuh dengan air'. Dia bertanya lagi, 'Apa yang terjadi dengan Kurma Baisan? Apakah ia memberikan kecukupan makanan? ' Mereka menjawab, 'Sungguh ia telah memberikan kecukupan makanan untuk penduduknya', tiba-tiba ia melompat dengan sekali lompatan, kami mengira dia akan lepas.' Lantas kami bertanya, 'Siapakah kamu? ' Dia menjawab, 'Aku adalah Dajjal, dan sesungguhnya aku akan melalui bumi semuanya selain Makkah dan Thayyibah.' Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Aku sampaikan kabar gembira untuk kalian wahai kaum Muslimin, inilah Thayibah yang dia tidak akan memasukinya yakni Dajjal.\""},"3942":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنِ الْقَاسِمِ بْنِ غَنَّامٍ عَنْ عَمَّاتِهِ عَنْ أُمِّ فَرْوَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ الصَّلَاةُ لِأَوَّلِ وَقْتِهَا","id":"Telah menceritakan kepada kami [Abu Ashim] berkata, telah mengabarkan kepada kami [Abdullah bin Umar] dari [Qasim bin Ghannam] dari [bibinya] dari [Ummu Farwah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya apakah amalan yang paling utama? Beliau menjawab: \"Shalat di awal waktu.\""},"3943":{"ar":"حَدَّثَنَا الْخُزَاعِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ الْعُمَرِيُّ عَنِ الْقَاسِمِ بْنِ غَنَّامٍ عَنْ جَدَّتِهِ الدُّنْيَا عَنْ أُمِّ فَرْوَةَ وَكَانَتْ قَدْ بَايَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَفْضَلِ الْعَمَلِ فَقَالَ الصَّلَاةُ لِأَوَّلِ وَقْتِهَا","id":"Telah menceritakan kepada kami [Al Khuza'i] telah mengabarkan kepada kami [Abdullah bin Umar Al Umari] dari [Al Qasim bin Ghannam] dari neneknya [Ad Dunya] dari [Ummu Farwah] dan dia telah membai'at Rasulullah shallallahu 'alaihi wasallam, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya mengenai amalan yang paling utama, maka beliau bersabda: \"Shalat di awal waktu.\""},"3944":{"ar":"حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا لَيْثٌ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ بْنِ حَفْصِ بْنِ عَاصِمِ بْنِ عُمَرَ بْنِ الْخَطَّابِ عَنِ الْقَاسِمِ بْنِ غَنَّامٍ عَنْ جَدَّتِهِ أُمِّ أَبِيهِ الدُّنْيَا عَنْ جَدَّتِهِ أُمِّ فَرْوَةَ وَكَانَتْ مِمَّنْ بَايَعَ أَنَّهاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَ الْأَعْمَالَ فَقَالَ أَحَبُّ الْعَمَلِ إِلَى اللَّهِ عَزَّ وَجَلَّ تَعْجِيلُ الصَّلَاةِ لِأَوَّلِ وَقْتِهَا","id":"Telah menceritakan kepada kami [Yunus] berkata, telah menceritakan kepada kami [Laits] dari [Ubaidullah bin Umar bin Hafsh bin Ashim bin Umar bin Khatthab] dari [Qasim bin Ghannam] dari [neneknya] ibu ayahnya, Ad Dunya, dari neneknya [Ummu Farwah] dan dia adalah wanita yang ikut berbaiat, bahwa dirinya mendengar Rasulullah shallallahu 'alaihi wasallam menyebutkan amalan-amalan, maka beliau bersabda: \"Amalan yang paling dicintai Allah Azza Wa Jalla adalah mendahulukan shalat di awal waktu.\""},"3945":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ مَعْقِلِ بْنِ أُمِّ مَعْقِلٍ الْأَسَدِيَّةِ قَالَأَرَادَتْ أُمِّي الْحَجَّ وَكَانَ جَمَلُهَا أَعْجَفَ فَذَكَرَتْ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اعْتَمِرِي فِي رَمَضَانَ فَإِنَّ عُمْرَةً فِي رَمَضَانَ كَحَجَّةٍ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] berkata, telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Ma'qil bin Ummu Ma'qil Al Asadiyah] dia berkata, \"Ibuku ingin melaksanakan haji sedangkan untanya kurus, lalu dia menceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam, lantas beliau pun bersabda: \"Umrahlah pada bulan Ramadan karena Umrah pada bulan Ramadan seperti haji.\""},"3946":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُهَاجِرٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ قَالَ أَخْبَرَنِي رَسُولُ مَرْوَانَ الَّذِي أُرْسِلَ إِلَى أُمِّ مَعْقِلٍ قَالَقَالَتْ جَاءَ أَبُو مَعْقِلٍ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجًّا فَلَمَّا قَدِمَ أَبُو مَعْقِلٍ قَالَ قَالَتْ أُمُّ مَعْقِلٍ قَدْ عَلِمْتُ أَنَّ عَلَيَّ حَجَّةً وَأَنَّ عِنْدَكَ بَكْرًا فَأَعْطِنِي فَلْأَحُجَّ عَلَيْهِ قَالَ فَقَالَ لَهَا إِنَّكِ قَدْ عَلِمْتِ أَنِّي قَدْ جَعَلْتُهُ فِي سَبِيلِ اللَّهِ قَالَتْ فَأَعْطِنِي صِرَامَ نَخْلِكَ قَالَ قَدْ عَلِمْتِ أَنَّهُ قُوتُ أَهْلِي قَالَتْ فَإِنِّي مُكَلِّمَةٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَاكِرَتُهُ لَهُ قَالَ فَانْطَلَقَا يَمْشِيَانِ حَتَّى دَخَلَا عَلَيْهِ قَالَ فَقَالَتْ لَهُ يَا رَسُولَ اللَّهِ إِنَّ عَلَيَّ حَجَّةً وَإِنَّ لِأَبِي مَعْقِلٍ بَكْرًا قَالَ أَبُو مَعْقِلٍ صَدَقَتْ جَعَلْتُهُ فِي سَبِيلِ اللَّهِ قَالَ أَعْطِهَا فَلْتَحُجَّ عَلَيْهِ فَإِنَّهُ فِي سَبِيلِ اللَّهِ قَالَ فَلَمَّا أَعْطَاهَا الْبَكْرَ قَالَتْ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ قَدْ كَبِرْتُ وَسَقِمْتُ فَهَلْ مِنْ عَمَلٍ يُجْزِئُ عَنِّي عَنْ حَجَّتِي قَالَ فَقَالَ عُمْرَةٌ فِي رَمَضَانَ تُجْزِئُ لِحَجَّتِكِ","id":"Telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Abu Awanah] berkata, telah menceritakan kepada kami [Ibrahim bin Muhajir] dari [Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam] berkata, telah mengabarkan kepadaku [utusannya] Marwan yang diutus untuk menemui [Ummu Ma'qil], dia berkata, \"Ummu Ma'qil berkata, \"Abu Ma'qil datang bersama Rasulullah shallallahu 'alaihi wasallam untuk berhaji, tatkala Abu Ma'qil datang, utusan Marwan berkata, \"Ummu Ma'qil berkata, \"Sungguh aku tahu bahwa aku berkewajiban untuk berhaji, sesungguhnya kamu memliki seekor unta yang masih muda, maka berikanlah kepadaku supaya aku bisa berhaji.\" Utusan itu berkata, \"Maka Abu Ma'qil berkata kepadanya, \"Sesungguhnya kamu telah mengetahui bahwasannya ia dijadikan sebagai penopang keluargaku.\" Ummu Ma'qil berkata, \"Kemudian aku berbicara kepada Rasulullah shallallahu 'alaihi wasallam untuk mengadukan kepada beliau, lalu utusan itu berkata, \"Maka keduanya pergi berjalan kaki sampai menemui beliau.\" Utusan itu berkata, \"Maka Ummu Salamah berkata kepada beliau, 'Wahai Rasulullah, sesungguhnya aku berkewajiban menunaikan ibadah haji, sedangkan Abu Ma'qil memiliki seekor unta yang masih muda.\" Abu Ma'qil berkata, \"Dia benar, akan tetapi ia telah aku sedekahkan untuk di jalan Allah.\" Beliau bersabda: \"Berikanlah kepadanya agar dia bisa menunaikan hajinya, karena ia juga di jalan Allah.\" Utusan itu berkata, \"Tatkala untanya dikasihkan kepadanya, maka Ummu Ma'qil berkata, 'Wahai Rasulullah, sesungguhnya aku adalah wanita yang sudah lanjut usia dan lemah, apakah ada amalan yang bisa menggantikanku dari ibadah haji? ' Beliau bersabda: \"Umrah pada bulan Ramadan, itu yang bisa menyamai pahala hajimu.\""},"3947":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى قَالَ أَخْبَرَنِي ابْنُ لَهِيعَةَ عَنْ بُكَيْرٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَنَازَعَنِي عُمَرُ بْنُ الْخَطَّابِ فِي الْمُتَوَفَّى عَنْهَا زَوْجُهَا وَهِيَ حَامِلٌ فَقُلْتُ تُزَوَّجُ إِذَا وَضَعَتْ فَقَالَتْ أُمُّ الطُّفَيْلِ أُمُّ وَلَدِي لِعُمَرَ وَلِي قَدْ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبَيْعَةَ الْأَسْلَمِيَّةَ أَنْ تَنْكِحَ إِذَا وَضَعَتْ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] dia berkata, telah mengabarkan kepadaku [Ibnu Lahi'ah] dari [Bukair] dari [Busr bin Sa'id] dari [Ubay bin Ka'ab] dia berkata, \"Umar bin Khattab berselisih denganku tentang isteri yang ditinggal mati suaminya dalam keadaan hamil. Aku berpendapat, \"Dia boleh dinikahi jika telah melahirkan.\" Lantas [Ummu Thufail], ibu anaku, berkata kepadaku dan kepada Umar, \"Rasulullah shallallahu 'alaihi wasallam telah menyuruh Syubai'ah Al Aslamiyah agar dia menikah jika telah melahirkan.\""},"3948":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ قَالَ سَمِعْتُ أُمَّ الطُّفَيْلِ قَالَ قُتَيْبَةُ امْرَأَةُ أُبَيِّ بْنِ كَعْبٍأَنَّهَا سَمِعَتْ عُمَرَ بْنَ الْخَطَّابِ وَأُبَيَّ بْنَ كَعْبٍ يَخْتَصِمَانِ فَقَالَتْ أُمُّ الطُّفَيْلِ أَفَلَا يَسْأَلُ عُمَرُ بْنُ الْخَطَّابِ سُبَيْعَةَ الْأَسْلَمِيَّةَ تُوُفِّيَ عَنْهَا زَوْجُهَا وَهِيَ حَامِلٌ فَوَضَعَتْ بَعْدَ ذَلِكَ بِأَيَّامٍ فَأَنْكَحَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] dan [Qutaibah bin Sa'id] keduanya berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Bukair bin 'Abdullah bin Al Asyaj] dari [Busr bin Sa'id] dia berkata, aku mendengar [Ummu Thufail], Qutaibah isterinya Ubay bin Ka'b, mengatakan bahwa dia mendengar Umar bin Khatthab dan Ubay bin Ka'b sedang berselisih, maka Ummu Thufail berkata, \"Kenapa Umar bin Khatthab bertanya langsung kepada Subai'ah Al Aslamiyah?\" Dia telah ditinggal mati oleh suaminya dalam konsidi mengandung dan melahirkan anaknya setelah beberapa hari, lalu Rasulullah shallallahu 'alaihi wasallam menikahkannya.\""},"3949":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا الْحَجَّاجُ بْنُ أَرْطَاةَ عَنْ أَبِي يَزِيدَ مَوْلَى عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أُمِّ جُنْدُبٍ الْأَزْدِيَّةِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّهَا النَّاسُ لَا تَقْتُلُوا أَنْفُسَكُمْ عِنْدَ جَمْرَةِ الْعَقَبَةِ وَعَلَيْكُمْ بِمِثْلِ حَصَى الْخَذْفِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] dia berkata, telah menceritakan kepada kami [Hajjaj bin Arthah] dari [Abu Yazid] bekas budak 'Abdullah bin Harits, dari [Ummu Jundub Al Azdiyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hai manusia, janganlah kalian bunuh diri kalian ketika Jumrah 'Aqabah, dan lemparlah dengan kerikil di antara dua jari.\""},"3950":{"ar":"حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا لَيْثٌ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ أُمِّ جُنْدُبٍ الْأَزْدِيَّةِ أَنَّهَاسَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُ أَفَاضَ قَالَ يَا أَيُّهَا النَّاسُ عَلَيْكُمْ بِالسَّكِينَةِ وَالْوَقَارِ وَعَلَيْكُمْ بِمِثْلِ حَصَى الْخَذْفِ","id":"Telah menceritakan kepada kami [Husyaim] dia berkata, telah mengabarkan kepada kami [Laits] dari ['Abdullah bin Syaddad] dari [Ummu Jundub Al Azdiyah] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam sewaktu ifadlah, beliau bersabda: \"Wahai sekalian manusia, hendaklah kalian tetap tenang, dan lemparlah dengan kerikil di antara dua jari.\""},"3951":{"ar":"حَدَّثَنَا سُفْيَانُ قَالَيَا أَيُّهَا النَّاسُ لَا يَقْتُلْ بَعْضُكُمْ بَعْضًا إِذَا رَمَيْتُمْ الْجَمْرَةَ فَارْمُوهَا بِمِثْلِ حَصَى الْخَذْفِقَالَ أَبِي وَقُرِئَ عَلَيْهِ يَزِيدُ يَعْنِي ابْنَ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّهِ يَعْنِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sufyan] dia berkata, \"Wahai sekalian manusia, sebagian kalian membunuh sebagian yang lain ketika melempar Jumrah 'Aqabah, dan lemparlah dengan kerikil di antara dua jari.\" ayahku berkata, dan telah dibacakan kepadanya oleh [Yazid] -yakni Ibnu Abu Ziyad- dari [Sulaiman bin 'Amru bin Al Ahwash] dari [ibunya], yakni dari Nabi shallallahu 'alaihi wasallam.\""},"3952":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا عُثْمَانُ يَعْنِي ابْنَ حَكِيمٍ قَالَ حَدَّثَنِي عَمْرُو الْأَنْصَارِيُّ عَنْ أُمِّ سُلَيْمٍ بِنْتِ مِلْحَانَ وَهِيَ أُمُّ أَنَسِ بْنِ مَالِكٍ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ امْرَأَيْنِ مُسْلِمَيْنِ يَمُوتُ لَهُمَا ثَلَاثَةُ أَوْلَادٍ لَمْ يَبْلُغُوا الْحِنْثَ إِلَّا أَدْخَلَهُمْ اللَّهُ الْجَنَّةَ بِفَضْلِ اللَّهِ وَرَحْمَتِهِ إِيَّاهُمْ","id":"Telah menceritakan kepada kami [Ibnu Numair] dia berkata, telah menceritakan kepada kami ['Utsman] -yakni Ibnu Hakim- dia berkata, telah menceritakan kepadaku ['Amru Al Anshari] dari [Ummu Sulaim binti Milhan] dia adalah ibu Anas bin Malik, bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah dua orang muslim yang ditinggal mati oleh tiga anaknya yang belum baligh, kecuali Allah akan memasukkan mereka ke dalam surga dengan keutamaan Allah dan rahmat-Nya kepada mereka.\""},"3953":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ عَمْرٍو قَالَ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أُمِّ سُلَيْمٍ قَالَتْدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ أُمِّ سَلَمَةَ فَقَالَتْ يَا رَسُولَ اللَّهِ أَرَأَيْتَكَ الْمَرْأَةَ تَرَى فِي مَنَامِهَا مَا يَرَى الرَّجُلُ قَالَتْ أُمُّ سَلَمَةَ فَضَحْتِ النِّسَاءَ قَالَتْ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يَسْتَحْيِي مِنْ الْحَقِّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَأَى ذَلِكَ مِنْكُنَّ فَلْتَغْتَسِلْ","id":"Telah menceritakan kepada kami [Ibnu Numair] dia berkata, telah menceritakan kepada kami [Muhammad] -yakni Ibnu 'Amru- dia berkata, telah menceritakan kepada kami [Abu Salamah] dari [Ummu Sulaim] dia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam di rumah Ummu Salamah, dia berkata, \"Wahai Rasulullah, bagaimana jika wanita bermimpi seperti apa yang dimimpikan lelaki?\" Ummu Salamah berkata, \"Kamu telah membuka aib wanita.\" Ummu Sulaim berkata, \"Sesungguhnya Allah Azza wa Jalla tidak malu kepada kebenaran.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Jika salah seorang dari kalian bermimpi seperti itu maka mandilah.\""},"3954":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ الرُّؤَاسِيُّ قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ عَبْدِ الْكَرِيمِ عَنِ الْبَرَاءِ ابْنِ ابْنَةِ أَنَسٍ وَهُوَ ابْنُ زَيْدٍ عَنْ أَنَسٍ قَالَ حَدَّثَتْنِي أُمِّيأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَفِي بَيْتِهَا قِرْبَةٌ مُعَلَّقَةٌ قَالَتْ فَشَرِبَ مِنْ الْقِرْبَةِ قَائِمًا قَالَتْ فَعَمَدْتُ إِلَى فَمِ الْقِرْبَةِ فَقَطَعْتُهَا","id":"Telah menceritakan kepada kami [Humaid bin 'Abdurrahman Ar Ru'asi] dia berkata, telah menceritakan kepada kami [Zuhair] dari ['Abdul Karim] dari [Barra'] anak dari anak perempuan Anas, dia adalah anak laki-lakinya Zaid, dari [Anas] dia berkata, telah menceritakan kepadaku [ibuku], bahwa Rasulullah shallallahu 'alaihi wasallam menemuinya sedangkan di rumahnya ada kantung air yang digantung, lalu beliau minum dari kantung tersebut dengan berdiri.\" Ummu Anas berkata, \"Lalu aku meraih mulut kantung itu dan memotongnya.\""},"3955":{"ar":"حَدَّثَنَا حَسَنٌ يَعْنِي ابْنَ مُوسَى قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُمِّ سُلَيْمٍأَنَّهَا كَانَتْ مَعَ نِسَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُنَّ يَسُوقُ بِهِنَّ سَوَّاقٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ أَنْجَشَةُ رُوَيْدَكَ سَوْقَكَ بِالْقَوَارِيرِ","id":"Telah menceritakan kepada kami [Hasan] -yakni Ibnu Musa- dia berkata, telah menceritakan kepada kami [Zuhair] dari [Sulaiman At Taimi] dari [Anas bin Malik] dari [Ummu Sulaim], bahwa dia pernah bersama dengan isteri-isteri Nabi shallallahu 'alaihi wasallam (dalam sekedup), yang ditutun oleh para penuntun (unta yang di atasnya di pasang sekedup). Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Anjasyah, pelanlah kamu (membawa mereka) sebagaimana kamu membawa bejana dari kaca.\""},"3956":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُمِّ سُلَيْمٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْتِيهَا فَيَقِيلُ عِنْدَهَا فَتَبْسُطُ لَهُ نِطَعًا فَيَقِيلُ عِنْدَهَا وَكَانَ كَثِيرَ الْعَرَقِ فَتَجْمَعُ عَرَقَهُ فَتَجْعَلُهُ فِي الطِّيبِ وَالْقَوَارِيرِ قَالَتْ وَكَانَ يُصَلِّي عَلَى الْخُمْرَةِ","id":"Telah menceritakan kepada kami ['Affan] dia berkata, telah menceritakan kepada kami [Wuhaib] dia berkata, telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] dari [Ummu Sulaim] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau berkunjung ke rumahnya dan berniat (menumpang untuk) tidur siang di sana. Ummu Sulaim lalu menghamparkan tikar untuk beliau, lantas beliau pun tidur di atasnya. Beliau banyak mengeluarkan keringat, maka Ummu Sulaim pun mengumpulkannya dalam botol untuk minyak wangi.\" Ummu Sulaim berkata, \"Kemudian beliau shalat di atas tikar kecil.\""},"3957":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي إِسْحَاقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ الْأَنْصَارِيُّ عَنْ جَدَّتِهِ أُمِّ سُلَيْمٍ قَالَتْكَانَتْ مُجَاوِرَةَ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَتْ تَدْخُلُ عَلَيْهَا فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ أُمُّ سُلَيْمٍ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِذَا رَأَتْ الْمَرْأَةُ أَنَّ زَوْجَهَا يُجَامِعُهَا فِي الْمَنَامِ أَتَغْتَسِلُ فَقَالَتْ أُمُّ سَلَمَةَ تَرِبَتْ يَدَاكِ يَا أُمَّ سُلَيْمٍ فَضَحْتِ النِّسَاءَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ أُمُّ سُلَيْمٍ إِنَّ اللَّهَ لَا يَسْتَحِي مِنْ الْحَقِّ وَإِنَّا إِنْ نَسْأَلْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّا أَشْكَلَ عَلَيْنَا خَيْرٌ مِنْ أَنْ نَكُونَ مِنْهُ عَلَى عَمْيَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُمِّ سَلَمَةَ بَلْ أَنْتِ تَرِبَتْ يَدَاكِ نَعَمْ يَا أُمَّ سُلَيْمٍ عَلَيْهَا الْغُسْلُ إِذَا وَجَدَتْ الْمَاءَ فَقَالَتْ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ وَهَلْ لِلْمَرْأَةِ مَاءٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنَّى يُشْبِهُهَا وَلَدُهَا هُنَّ شَقَائِقُ الرِّجَالِ","id":"Telah menceritakan kepada kami [Abu Mughirah] dia berkata, telah menceritakan kepada kami [Al Auza'i] dia berkata, telah menceritakan kepadaku [Ishaq bin 'Abdullah bin Abu Thalhah Al Anshari] dari neneknya [Ummu Sulaim] dia mengatakan, bahwa dia bertetangga dengan Ummu Salamah, isteri Nabi shallallahu 'alaihi wasallam, dia pernah masuk manemuinya, setelah itu Nabi shallallahu 'alaihi wasallam masuk.\" Ummu Sulaim berkata, \"Wahai Rasulullah, bagaimana pendapatmu jika seorang isteri bermimpi bahwa suaminya telah menggaulinya? Apakah ia wajib mandi?\" Ummu Salamah berkata, \"celaka kamu wahai Ummu Sulaim, kamu telah membuka aib seorang wanita di hadapan Rasulullah shallallahu 'alaihi wasallam.\" Ummu Sulaim pun berkata, \"Sesungguhnya Allah tidak malu dari kebenaran, dan lebih baik kita bertanya kepada Nabi shallallahu 'alaihi wasallam tentang suatu hal yang masih rancu daripada kita dalam ketidaktahuan.\" Maka Nabi shallallahu 'alaihi wasallam bersabda kepada Ummu Salamah: \"Justru kamulah yang celaka wahai wahai Ummu Sulaim, ia wajib mandi jika mendapati cairan.\" Maka Ummu Salamah berkata, \"Wahai Rasulullah, apakah seorang wanita juga memiliki cairan?\" Lantas Nabi shallallahu 'alaihi wasallam menjawab: \"(Jika tidak) lalu dari mana seorang anak bisa menyerupai ibunya, wanita adalah saudara laki-laki.\""},"3958":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُمِّ سُلَيْمٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي عَلَى الْخُمْرَةِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] dia berkata, telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] dari [Ummu Sulaim] bahwa Rasulullah shallallahu 'alaihi wasallam shalat di atas tikar kecil.\""},"3959":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنِ الْحَارِثِ بْنِ يَعْقُوبَ عَنْ يَعْقُوبَ بْنِ الْأَشَجِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍ عَنْ خَوْلَةَ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَزَلَ مَنْزِلًا فَقَالَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّةِ مِنْ شَرِّ مَا خَلَقَ لَمْ يَضُرَّهُ شَيْءٌ حَتَّى يَظْعَنَ مِنْهُحَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ يَعْقُوبَ بْنِ الْأَشَجِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍ عَنْ خَوْلَةَ قَالَتْ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] dia berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dia berkata, telah menceritakan kepada kami [Yazid bin Abu Habib] dari [Harits bin Ya'qub] dari [Ya'qub bin Al Asyaj] dari ['Amir bin Sa'ad] dari [Sa'd] dari [Khaulah] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa singgah di suatu tempat lalu ia mengatakan A'UUDZU BIKALIMAATILLAHIT TAAMMAH MIN SYARRI MAA KHALAQ (Aku berlindung dengan kalimat-kalimat Allah dari keburukan yang Dia ciptakan) ', maka ia tidak akan diganggu sesuatu pun hingga ia pergi darinya.\" Telah menceritakan kepada kami [Yahya bin Ishaq] dia berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Ja'far bin Rabi'ah] dari [Ya'qub bin Asyaj] dari ['Amir bin Sa'd] dari [Sa'd] dari [Khaulah] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda seperti itu.\""},"3960":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ أَخْبَرَنَا لَيْثٌ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنِ الْحَارِثِ عَنْ يَعْقُوبَ بْنِ عَبْدِ اللَّهِ حَدَّثَهُ أَنَّهُ سَمِعَ بُسْرَ بْنَ سَعِيدٍ يَقُولُ سَمِعْتُ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُ سَمِعْتُ خَوْلَةَ بِنْتَ حَكِيمٍ السُّلَمِيَّةَ تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ نَزَلَ مَنْزِلًا ثُمَّ قَالَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ كُلِّهَا مِنْ شَرِّ مَا خَلَقَ لَمْ يَضُرَّهُ شَيْءٌ حَتَّى يَرْتَحِلَ مِنْ مَنْزِلِهِ ذَلِكَ","id":"Telah menceritakan kepada kami [Hajjaj] dia berkata, telah mengabarkan kepada kami [Laits] dia berkata, telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Harits] dari [Ya'qub bin 'Abdullah] bahwa dia telah mengabarkan kepadanya, bahwa dia mendengar [Busr bin Sa'id] berkata, saya mendengar [Sa'd bin Abu Waqash] berkata, aku mendengar [Khaulah binti Hakim As Sulamiyah] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa singgah di suatu tempat kemudian dia mengucapkan A'UUDZU BIKALIMAATILLAHIT TAAMMAH KULLIHA MIN SYARRI MAA KHALAQ (Aku berlindung dengan kalimat-kalimat Allah yang sempurna semuanya dari keburukan yang Dia ciptakan) ', maka ia tidak akan diganggu sesuatu pun hingga ia pergi darinya.\""},"3961":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا حَجَّاجٌ عَنِ الرَّبِيعِ بْنِ مَالِكٍ عَنْ خَوْلَةَ بِنْتِ حَكِيمٍ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَزَلَ مَنْزِلًا فَقَالَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ كُلِّهَا مِنْ شَرِّ مَا خَلَقَ لَمْ يَضُرَّهُ فِي مَنْزِلِهِ ذَلِكَ شَيْءٌ حَتَّى يَظْعَنَ عَنْهُ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] dia berkata, telah menceritakan kepada kami [Hajjaj] dari [Ar Rabi' bin Malik] dari [Khaulah binti Hakim] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa singgah di suatu tempat kemudian dia mengucapkan A'UUDZU BIKALIMAATILLAHIT TAAMMAH KULLIHA MIN SYARRI MAA KHALAQ (Aku berlindung dengan kalimat-kalimat Allah yang sempurna semuanya dari keburukan yang Dia ciptakan) ', maka ia tidak akan diganggu sesuatupun hingga ia pergi darinya.\""},"3962":{"ar":"حَدَّثَنَا هَاشِمٌ قَالَ حَدَّثَنَا لَيْثٌ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ عُبَيْدِ سَنُوطَا أَبِي الْوَلِيدِ قَالَ سَمِعْتُ خَوْلَةَ بِنْتَ قَيْسِ بْنِ قَهْدٍ وَكَانَتْ تَحْتَ حَمْزَةَ بْنِ عَبْدِ الْمُطَّلِبِ تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ مَنْ أَصَابَهُ بِحَقِّهِ بُورِكَ لَهُ فِيهِ وَرُبَّ مُتَخَوِّضٍ فِيمَا شَاءَتْ نَفْسُهُ مِنْ مَالِ اللَّهِ وَرَسُولِهِ لَيْسَ لَهُ يَوْمَ الْقِيَامَةِ إِلَّا النَّارُ","id":"Telah menceritakan kepada kami [Hasyim] dia berkata, telah menceritakan kepada kami [Laits] dia berkata, telah menceritakan kepadaku [Sa'id bin Abu Sa'id] dari ['Ubaid Sanuth Abu Al Walid] dia berkata, aku mendengar [Khaulah binti Qais bin Qahd] dan dia berada dalam pemeliharaan Hamzah bin 'Abdul Muthalib, dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya harta ini hijau dan manis, barangsiapa mendapatkan dengan haknya maka ia akan diberkahi. Berapa banyak orang yang mengambil harta Allah dan rasul-Nya tanpa haknya sesuai keinginannya, pada hari kiamat nanti ia tidak memilikinya kecuali neraka.\""},"3963":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنِ الْحَارِثِ بْنِ يَعْقُوبَ عَنْ يَعْقُوبَ بْنِ الْأَشَجِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍ عَنْ خَوْلَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ نَزَلَ مَنْزِلًا فَقَالَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ لَمْ يَضُرَّهُ فِيهِ شَيْءٌ حَتَّى يَرْتَحِلَ مِنْهُحَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ يَعْقُوبَ بْنِ الْأَشَجِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍ عَنْ خَوْلَةَ قَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] dia berkata, telah mengabarkan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Al Harits bin Ya'qub] dari [Ya'qub bin Al Asyaj] dari ['Amir bin Sa'd] dari [Sa'd] dari [Khaulah] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa singgah di suatu tempat, lalu ia mengatakan A'UUDZU BIKALIMAATILLAHIT TAMMAH MIN SYARRI MAA KHALAQ (Aku berlindung dengan kalimat-kalimat Allah dari keburukan yang Dia ciptakan) ', maka ia tidak akan diganggu sesuatupun hingga ia pergi darinya.\" Telah menceritakan kepada kami [Yahya bin Ishaq] dia berkata, telah mengabarkan kepada kami [Ibn Lahi'ah] dari [Ja'far bin Rabi'ah] dari [Ya'qub bin Asyaj] dari ['Amir bin Sa'd] dari [Sa'd] dari [Khaulah] dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda seperti itu.\""},"3964":{"ar":"حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ جَعْفَرِ بْنِ عَبْدِ الرَّحْمَنِ الْأَنْصَارِيِّ عَنْ أُمِّ طَارِقٍ مَوْلَاةِ سَعْدٍ قَالَتْجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى سَعْدٍ فَاسْتَأْذَنَ فَسَكَتَ سَعْدٌ ثُمَّ أَعَادَ فَسَكَتَ سَعْدٌ ثُمَّ عَادَ فَسَكَتَ سَعْدٌ فَانْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ فَأَرْسَلَنِي إِلَيْهِ سَعْدٌ أَنَّهُ لَمْ يَمْنَعْنَا أَنْ نَأْذَنَ لَكَ إِلَّا أَنَّا أَرَدْنَا أَنْ تَزِيدَنَا قَالَتْ فَسَمِعْتُ صَوْتًا عَلَى الْبَابِ يَسْتَأْذِنُ وَلَا أَرَى شَيْئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَنْتِ قَالَتْ أُمُّ مِلْدَمٍ قَالَ لَا مَرْحَبًا بِكِ وَلَا أَهْلًا أَتُهْدِينَ إِلَى أَهْلِ قُبَا قَالَتْ نَعَمْ قَالَ فَاذْهَبِي إِلَيْهِمْ","id":"Telah menceritakan kepada kami [Ya'la bin 'Ubaid] dia berkata, telah menceritakan kepada kami [Al A'masy] dari [Ja'far bin 'Abdurrahman Al Anshari] dari [Ummu Thariq] bekas budak Sa'd, dia berkata, \"Nabi datang kepada Sa'd, saat beliau mengucapkan salam Sa'd diam, lalu beliau mengulanginya dan Sa'd tetap diam, lalu beliau mengulanginya dan Sa'd pun tetap diam. Maka Nabi shallallahu 'alaihi wasallam pun beranjak pergi.\" Ummu Thariq berkata, \"Kemudian Sa'd mengutusku menemui beliau, dia mengatakan bahwa sebenarnya kami tidak melarang tuan untuk masuk, hanya saja kami berharap tuan akan memperbanyak (ucapan salam) kepada kami.\" Ummu Thariq melanjutkan, \"Lalu aku mendengar suara di pintu namun aku tidak melihat apapun, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa kamu?\" dia menjawab, \"Ummu Mildam.\" Beliau bersabda: \"Tidak ada selamat datang untukmu, apakah kamu memberi hadiah kepada penduduk Quba'?\" Dia menjawab, \"Ya.\" Beliau pun bersabda: \"Pergilah kepada mereka.\""},"3965":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى وَعَفَّانُ قَالَا حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ قَالَ أَخْبَرَنِي يَحْيَى بْنُ عَبْدِ الْحَمِيدِ بْنِ رَافِعِ بْنِ خَدِيجٍ قَالَ أَخْبَرَتْنِي جَدَّتِي يَعْنِي امْرَأَةَ رَافِعِ بْنِ خَدِيجٍ قَالَ عَفَّانُ عَنْ جَدَّتِهِ أُمِّ أَبِيهِ امْرَأَةِ رَافِعِ بْنِ خَدِيجٍأَنَّ رَافِعًا رَمَى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ وَيَوْمَ خَيْبَرَ قَالَ أَنَا أَشُكُّ بِسَهْمٍ فِي ثَنْدُوَتِهِ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ انْزِعْ السَّهْمَ قَالَ يَا رَافِعُ إِنْ شِئْتَ نَزَعْتُ السَّهْمَ وَالْقُطْبَةَ جَمِيعًا وَإِنْ شِئْتَ نَزَعْتُ السَّهْمَ وَتَرَكْتُ الْقُطْبَةَ وَشَهِدْتُ لَكَ يَوْمَ الْقِيَامَةِ أَنَّكَ شَهِيدٌ قَالَ يَا رَسُولَ اللَّهِ بَلْ انْزِعْ السَّهْمَ وَاتْرُكْ الْقُطْبَةَ وَاشْهَدْ لِي يَوْمَ الْقِيَامَةِ أَنِّي شَهِيدٌ قَالَ فَنَزَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّهْمَ وَتَرَكَ الْقُطْبَةَ","id":"Telah menceritakan kepada kami [Hasan bin Musa] dan ['Affan] keduanya berkata, telah menceritakan kepada kami ['Amru bin Marzuq] dia berkata, telah mengabarkan kepadaku [Yahya bin 'Abdul Hamid bin Rafi' bin Khudaij] dia berkata, telah mengabarkan kepadaku nenekku [Isterinya Rafi' bin Hudaij], [Affan] berkata dari neneknya, yaitu ibnu bapaknya [Isteri Rafi' bin Khadij], bahwa Rafi' melempar bersama Rasulullah shallallahu 'alaihi wasallam ketika perang Uhud dan Khaibar.\" Rafi' berkata, \"Aku menusukkan panah di dadanya.\" Lalu dia mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, lepaslah anak panahnya.\" Beliau bersabda: Wahai Rafi', jika kamu mau maka aku akan melepaskan anak dan mata panahnya sekaligus, dan jika engkau mau maka aku akan melepaskan anak panah dan aku tinggalkan mata panahnya, dan aku akan bersaksi untukmu hari kiamat bahwa kamu syahid.\" Rafi' berkata, \"Wahai Rasulullah, lepaslah anak panahnya dan tinggalkan mata panahnya, bersaksilah untukku pada hari kiamat bahwa aku syahid.\" Perawi berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam melepaskan anak panah itu dan meninggalkan matanya.\""},"3966":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ ابْنِ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ قَالَ سَمِعْتُ بُقَيْرَةَ امْرَأَةَ الْقَعْقَاعِ بْنِ أَبِي حَدْرَدٍ تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ وَهُوَ يَقُولُ إِذَا سَمِعْتُمْ بِجَيْشٍ قَدْ خُسِفَ بِهِ قَرِيبًا فَقَدْ أَظَلَّتْ السَّاعَةُ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu Ishaq] dari [Muhammad bin Ibrahim At Taimi] dia berkata, aku mendengar [Buqairah] isteri Qa'qa' bin Abu Hadrad dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar: \"Jika kalian mendengar ada tentara yang ditenggelamkan dekat kalian, maka hal itu menunjukkan bahwa kiamat telah dekat.\""},"3967":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الرَّازِيُّ قَالَ حَدَّثَنَا سَلَمَةُ بْنُ الْفَضْلِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ بُقَيْرَةَ امْرَأَةِ الْقَعْقَاعِ قَالَتْإِنِّي لَجَالِسَةٌ فِي صُفَّةِ النِّسَاءِ فَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ وَهُوَ يُشِيرُ بِيَدِهِ الْيُسْرَى فَقَالَ يَا أَيُّهَا النَّاسُ إِذَا سَمِعْتُمْ بِخَسْفٍ هَاهُنَا قَرِيبًا فَقَدْ أَظَلَّتْ السَّاعَةُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Ar Razi] dia berkata, telah menceritakan kepada kami [Salamah bin Al Fadll] dia berkata, telah menceritakan kepadaku [Muhammad bin Ishaq] dari [Muhammad bin 'Amru bin 'Atha'] dari [Buqairah] isterinya Qa'qa', dia berkata, \"Sungguh, aku duduk di shafnya para wanita, maka aku mendengar Rasulullah shallallahu 'alaihi wasallam berkhutbah sambil mengisyaratkan dengan tangan kirinya, beliau katakan: \"Wahai sekalian manusia, jika kalian mendengar ada tentara yang ditenggelamkan dekat kalian, maka hal itu menunjukkan bahwa kiamat telah dekat.\""},"3968":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ عَطَاءٍ عَنْ يَزِيدَ يَعْنِي ابْنَ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ الْأَزْدِيِّ قَالَ حَدَّثَتْنِي أُمِّيأَنَّهَا رَأَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمِي جَمْرَةَ الْعَقَبَةِ مِنْ بَطْنِ الْوَادِي وَخَلْفَهُ إِنْسَانٌ يَسْتُرُهُ مِنْ النَّاسِ أَنْ يُصِيبُوهُ بِالْحِجَارَةِ وَهُوَ يَقُولُ أَيُّهَا النَّاسُ لَا يَقْتُلْ بَعْضُكُمْ بَعْضًا وَإِذَا رَمَيْتُمْ فَارْمُوا بِمِثْلِ حَصَى الْخَذْفِ ثُمَّ أَقْبَلَ فَأَتَتْهُ امْرَأَةٌ بِابْنٍ لَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنِي هَذَا ذَاهِبُ الْعَقْلِ فَادْعُ اللَّهَ لَهُ قَالَ لَهَا ائْتِينِي بِمَاءٍ فَأَتَتْهُ بِمَاءٍ فِي تَوْرٍ مِنْ حِجَارَةٍ فَتَفَلَ فِيهِ وَغَسَلَ وَجْهَهُ ثُمَّ دَعَا فِيهِ ثُمَّ قَالَ اذْهَبِي فَاغْسِلِيهِ بِهِ وَاسْتَشْفِي اللَّهَ عَزَّ وَجَلَّ فَقُلْتُ لَهَا هَبِي لِي مِنْهُ قَلِيلًا لِابْنِي هَذَا فَأَخَذْتُ مِنْهُ قَلِيلًا بِأَصَابِعِي فَمَسَحْتُ بِهَا شِقَّةَ ابْنِي فَكَانَ مِنْ أَبَرِّ النَّاسِ فَسَأَلْتُ الْمَرْأَةَ بَعْدُ مَا فَعَلَ ابْنُهَا قَالَتْ بَرِئَ أَحْسَنَ بَرْءٍ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] dia berkata, telah menceritakan kepada kami [Yazid bin Atha'] dari [Yazid] -yakni Ibnu Abu Ziyad- dari [Sulaiman bin 'Amru bin Al Ahwash Al Azdi] dia berkata, telah menceritakan kepadaku [ibuku] bahwa dia melihat Rasulullah shallallahu 'alaihi wasallam melempar jumrah Aqabah dari tengah lembah, sedangkan di belakang beliau ada orang yang melindunginya dari orang-orang yang melempar sehingga tidak mengenainya. Beliau bersabda: \"Hai manusia, janganlah sebagian kalian membunuh sebagian yang lain, jika kalian melempar maka lemparlah dengan batu kerikil antara dua jari.\" Lalu beliau berbalik, kemudian datanglah seorang wanita dengan membawa anaknya, wanita itu berkata, \"Wahai Rasulullah, sesungguhnya anakku ini hilang akalnya, maka do'akanlah dia.\" Beliau bersabda kepadanya: \"Ambilkan air untukku, \" lalu wanita itu membawakan untuk beliau periuk dari batu, kemudian beliau meludah ke dalamnya, beliau lalu basuh wajah anak itu dan mendoakannya. Lantas beliau bersabda: \"Pergi dan mandikan ia dengannya, lalu mintalah kesembuhan kepada Allah Azza wa Jalla.\" Aku berkata kepadanya, \"Berikan padaku sedikit untuk anakku ini.\" Lalu aku mengambil sedikit dengan tanganku dan aku mengusapkan setengahnya pada anakku, maka dia menjadi sebaik-baik manusia, lalu aku bertanya kepada wanita tersebut, apa yang terjadi dengan anakknya, maka dia menjawab, \"Dia sembuh dengan sempurna.\""},"3969":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أُمِّهِ قَالَتْرَأَي��تُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمِي جَمْرَةَ الْعَقَبَةِ يَوْمَ النَّحْرِ مِنْ بَطْنِ الْوَادِي وَهُوَ يَقُولُ يَا أَيُّهَا النَّاسُ لَا يَقْتُلَنَّ بَعْضُكُمْ بَعْضًا وَإِذَا رَمَيْتُمْ الْجِمَارَ فَارْمُوا بِمِثْلِ حَصَى الْخَذْفِ قَالَتْ فَرَمَى سَبْعًا ثُمَّ انْصَرَفَ وَلَمْ يَقِفْ قَالَتْ وَخَلْفَهُ رَجُلٌ يَسْتُرُهُ مِنْ النَّاسِ فَسَأَلْتُ عَنْهُ فَقَالُوا هُوَ الْفَضْلُ بْنُ عَبَّاسٍ","id":"Telah menceritakan kepada kami ['Affan] dia berkata, telah menceritakan kepada kami [Abu 'Awanah] dia berkata, telah menceritakan kepada kami [Yazid bin Abu Ziyad] dari [Sulaiman bin 'Amru bin Al Ahwash] dari [Ibunya] dia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam melempar Jumrah Aqabah pada hari raya nahr (Idul Adlha) dari tengah lembah sembari bersabda: \"Wahai sekalian manusia, janganlah sebagian kalian membunuh sebagian yang lain, jika kalian melempar Jumrah maka lemparlah dengan dan kerikil di antara dua jari.\""},"3970":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي سَلِيطُ بْنُ أَيُّوبَ بْنِ الْحَكَمِ بْنِ سُلَيْمٍ عَنْ أُمِّهِ عَنْ سَلْمَى بِنْتِ قَيْسٍ وَكَانَتْ إِحْدَى خَالَاتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ صَلَّتْ مَعَهُ الْقِبْلَتَيْنِ وَكَانَتْ إِحْدَى نِسَاءِ بَنِي عَدِيِّ بْنِ النَّجَّارِ قَالَتْجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْتُهُ فِي نِسْوَةٍ مِنْ الْأَنْصَارِ فَلَمَّا شَرَطَ عَلَيْنَا أَنْ لَا نُشْرِكَ بِاللَّهِ شَيْئًا وَلَا نَسْرِقَ وَلَا نَزْنِيَ وَلَا نَقْتُلَ أَوْلَادَنَا وَلَا نَأْتِيَ بِبُهْتَانٍ نَفْتَرِيهِ بَيْنَ أَيْدِينَا وَأَرْجُلِنَا وَلَا نَعْصِيَهُ فِي مَعْرُوفٍ قَالَ قَالَ وَلَا تَغْشُشْنَ أَزْوَاجَكُنَّ قَالَتْ فَبَايَعْنَاهُ ثُمَّ انْصَرَفْنَا فَقُلْتُ لِامْرَأَةٍ مِنْهُنَّ ارْجِعِي فَاسْأَلِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا غِشُّ أَزْوَاجِنَا قَالَتْ فَسَأَلَتْهُ فَقَالَ تَأْخُذُ مَالَهُ فَتُحَابِي بِهِ غَيْرَهُ","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] dia berkata, telah menceritakan kepadaku [Salith bin Ayyub bin Al Hakam bin Sulaim] dari [Ibunya] dari [Salma binti Qais] dia adalah salah satu bibi Rasulullah shallallahu 'alaihi wasallam, bahwa dia pernah shalat bersama beliau menghadap dua kiblat, dan termasuk salah satu wanita Bani 'Adi bin Najjar. Dia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam untuk berbait kepada beliau bersama para wanita Anshar, ketika itu beliau memberi kami syarat agar kami tidak menyekutukan Allah dengan sesuatupun, tidak mencuri, tidak berzina, tidak membunuh anak-anak kami, tidak mendatangi keburukan yang kami perbuat antara kedua tangan dan kaki kami, dan tidak bermaksiat dalam kebaikan.\" Salith berkata, \"Rasulullah bersabda: \"Janganlah kalian berbuat curang pada suami-suami kalian.\" Salma binti Qais berkata, \"Maka kami berbaiat kepada beliau kemudian kami beranjak pergi, lalu aku berkata kepada seorang wanita di antara mereka, 'Kembali dan tanyakanlah kepada Rasulullah shallallahu 'alaihi wasallam, apa yang dimaksud berbuat curang kepada suami-suami kami? ' Salma bin Qais berkata, \"Wanita itu lalu kembali dan menanyakannya, kemudian beliau bersabda: \"Kamu mengambil hartanya sedangkan kamu lebih mengutamakan selainnya.\""},"3971":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ حَدَّثَنَا زَيْدُ بْنُ جُبَيْرٍوَسَأَلَهُ رَجُلٌ يَعْنِي ابْنَ عُمَرَ عَمَّا يَقْتُلُ الْمُحْرِمُ مِنْ الدَّوَابِّ فَقَالَ أَخْبَرَتْنِي إِحْدَى نِسْوَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَمَرَ بِقَتْلِ الْفَأْرَةِ وَالْعَقْرَبِ وَالْكَلْبِ الْعَقُورِ وَالْحُدَيَّا وَالْغُرَابِ","id":"Telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepada kami [Abu 'Awanah] berkata, telah menceritakan kepada kami [Zaid bin Jubair] berkata, dan seorang laki-laki telah bertanya kepadanya -yaitu [Ibn Umar] - tentang hewan apa yang boleh dibunuh oleh seorang yang sedang berihram? dia lalu menjawab, \" [Salah seorang isteri Rasulullah shallallahu 'alaihi wasallam] mengabarkan kepadaku bahwa beliau memerintahkan agar membunuh tikus, kalajengking, anjing buas, hudai (nama burung) dan gagak.\""},"3972":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي نُوحُ بْنُ حَكِيمٍ الثَّقَفِيُّ وَكَانَ قَارِئًا لِلْقُرْآنِ عَنْ رَجُلٍ مِنْ بَنِي عُرْوَةَ بْنِ مَسْعُودٍ يُقَالُ لَهُ دَاوُدُ قَدْ وَلَّدَتْهُ أُمُّ حَبِيبَةَ بِنْتُ أَبِي سُفْيَانَ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لَيْلَى ابْنَةِ قَانِفٍ الثَّقَفِيَّةِ قَالَتْكُنْتُ فِيمَنْ غَسَّلَ أُمَّ كُلْثُومٍ بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ وَفَاتِهَا وَكَانَ أَوَّلُ مَا أَعْطَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحِقَاءَ ثُمَّ الدِّرْعَ ثُمَّ الْخِمَارَ ثُمَّ الْمِلْحَفَةَ ثُمَّ أُدْرِجَتْ بَعْدُ فِي الثَّوْبِ الْآخِرِ قَالَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ الْبَابِ مَعَهُ كَفَنُهَا يُنَاوِلُنَاهُ ثَوْبًا ثَوْبًا","id":"Telah menceritakan kepada kami [Ya'qub] berkata, telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] dia berkata, telah menceritakan kepadaku [Nuh bin Hakim At Tsaqafi] dia adalah orang yang mahir dalam al Qur'an, dari seorang laki-laki dari Bani 'Urwah bin Mas'ud yang biasa dipanggil [Daud] -seorang yang telah dilahirkan oleh Ummu Habibah binti Abu Sufyan, salah satu dari isteri Nabi shallallahu 'alaihi wasallam- dari [Laila binti Qanif At Tsaqafiyah] dia berkata, \"Aku adalah salah satu orang yang memandikan Ummu Kultsum binti Rasulullah shallallahu 'alaihi wasallam ketika wafat, yang pertama kali diberikan Rasulullah shallallahu 'alaihi wasallam kepada kami adalah sarung, lalu gamis, lalu kerudung, lalu selimut (kain penutup) dan dilipat (bungkus) dengan kain yang terakhir.\" Laila berkata, \"Saat itu Rasulullah shallallahu 'alaihi wasallam berdiri di samping pintu membawa kafan dan memberikan kepada kami satu persatu.\""},"3973":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ قَالَ حَدَّثَنِي سُلَيْمَانُ بْنُ سُحَيْمٍ عَنْ أُمَيَّةَ بِنْتِ أَبِي الصَّلْتِ عَنِ امْرَأَةٍ مِنْ بَنِي غِفَارٍ وَقَدْ سَمَّاهَا لِي قَالَتْأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ مِنْ بَنِي غِفَارٍ فَقُلْنَا لَهُ يَا رَسُولَ اللَّهِ قَدْ أَرَدْنَا أَنْ نَخْرُجَ مَعَكَ إِلَى وَجْهِكَ هَذَا وَهُوَ يَسِيرُ إِلَى خَيْبَرَ فَنُدَاوِيَ الْجَرْحَى وَنُعِينَ الْمُسْلِمِينَ بِمَا اسْتَطَعْنَا فَقَالَ عَلَى بَرَكَةِ اللَّهِ قَالَتْ فَخَرَجْنَا مَعَهُ وَكُنْتُ جَارِيَةً حَدِيثَةً فَأَرْدَفَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى حَقِيبَةِ رَحْلِهِ قَالَتْ فَوَاللَّهِ لَنَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الصُّبْحِ فَأَنَاخَ وَنَزَلْتُ عَنْ حَقِيبَةِ رَحْلِهِ وَإِذَا بِهَا دَمٌ مِنِّي فَكَانَتْ أَوَّلَ حَيْضَةٍ حِضْتُهَا قَالَتْ فَتَقَبَّضْتُ إِلَى النَّاقَةِ وَاسْتَحْيَيْتُ فَلَمَّا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بِي وَرَأَى الدَّمَ قَالَ مَا لَكِ لَعَلَّكِ نَفِسْتِ قَالَتْ قُلْتُ نَعَمْ قَالَ فَأَصْلِحِي مِنْ نَفْسِكِ وَخُذِي إِنَاءً مِنْ مَاءٍ فَاطْرَحِي فِيهِ مِلْحًا ثُمَّ اغْسِلِي مَا أَصَابَ الْحَقِيبَةَ مِنْ الدَّمِ ثُمَّ عُودِي لِمَرْكَبِكِ قَالَتْ فَلَمَّا فَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ رَضَخَ لَنَا مِنْ الْفَيْءِ وَأَخَذَ هَذِهِ الْقِلَادَةَ الَّتِي تَرَيْنَ فِي عُنُقِي فَأَعْطَانِيهَا وَجَعَلَهَا بِيَدِهِ فِي عُنُقِي فَوَاللَّهِ لَا تُفَارِقُنِي أَبَدًا قَالَ وَكَانَتْ فِي عُنُقِهَا حَتَّى مَاتَتْ ثُمَّ أَوْصَتْ أَنْ تُدْفَنَ مَعَهَا فَكَانَتْ لَا تَطْهُرُ مِنْ حَيْضَةٍ إِلَّا جَعَلَتْ فِي طَهُورِهَا مِلْحًا وَأَوْصَتْ أَنْ يُجْعَلَ فِي غُسْلِهَا حِينَ مَاتَتْ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Muhammad bin Ishaq] dia berkata, telah menceritakan kepadaku [Sulaiman bin Suhaim] dari [Umayyah binti Abu Shalt] dari [seorang wanita] dari Bani Ghifar, dia menyebutkan namanya kepadaku, dia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam dengan beberapa wanita Bani Ghiffar, kami berkata kepada beliau, \"Wahai Rasulullah, sesungguhnya kami ingin berperang bersama tuan pada perang ini -ketika itu beliau dalam perjalanan ke Khaibar-, sehingga kami dapat mengobati yang terluka dan kami membantu kaum muslimin semampu kami.\" Lantas beliau bersabda: \"Semoga diberkahi Allah.\" Lalu kami berangkat bersama beliau, ketika itu aku seorang gadis yang baru tumbuh, maka Rasulullah shallallahu 'alaihi wasallam memboncengkanku di karung perbekalannya.\" Wanita itu berkata, \"Demi Allah, Rasulullah shallallahu 'alaihi wasallam turun pada waktu subuh, lalu menderumkan untanya dan akupun turun dari karung perbekalannya. Tiba-tiba ada darah dariku dan aku haid untuk pertama kalinya. Lalu aku menepi pada unta karena malu, ketika Rasulullah shallallahu 'alaihi wasallam melihat apa yang terjadi denganku dan beliau melihat darah, beliau bersabda: \"Apa yang terjadi denganmu, apakah kamu baru saja haid?\" aku menjawab, \"Ya.\" Beliau bersabda: \"Bersihkan haidmu dan ambillah satu bejana air, lalu masukkan garam ke dalamnya dan cucilah darah yang mengenai karung perbekalan, setelah itu kembalilah naik.\" Wanita itu berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam menaklukkan Khaibar, beliau membagikan Fai' (rampasan perang) kepada kami, beliau lalu mengambil kalung yang kamu lihat di leherku ini, beliau berikan ini kepadaku dan beliau telakkan di leherku. Demi Allah, kalung tersebut tidak pernah berpisah dariku.\" Sulaiman berkata, \"Kalung itu tetap bersamanya sampai dia wafat, dan dia berwasiat agar kalung itu dikubur bersamanya. Dan dia tidak suci dari haidnya kecuali dia mensucikannya dengan garam, maka ia berwasiat agar memandikan dengan garam saat meninggal.\""},"3974":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَتْنِي أُمُّ غُرَابٍ عَنِ امْرَأَةٍ يُقَالُ لَهَا عَقِيلَةُ عَنْ سَلَامَةَ ابْنَةِ الْحُرِّ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَأْتِي عَلَى النَّاسِ زَمَانٌ يَقُومُونَ سَاعَةً لَا يَجِدُونَ إِمَامًا يُصَلِّي بِهِمْ","id":"Telah menceritakan kepada kami [Waki'] dia berkata, telah menceritakan kepadaku [Ummu Ghurab] dari seorang wanita yang disebut ['Aqilah] dari [Salamah binti Hur] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan datang pada manusia suatu masa yang mereka berdiri sesaat untuk shalat namun tidak mendapatkan seseorang yang mengimami mereka.\""},"3975":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَرْوَانُ قَالَ حَدَّثَتْنَا امْرَأَةٌ يُقَالُ لَهَا طَلْحَةُ مَوْلَاةُ بَنِي فَزَارَةَ عَنْ مَوْلَاةٍ لَهُمْ يُقَالُ لَهَا عَقِيلَةُ عَنْ سَلَامَةَ ابْنَةِ الْحُرِّ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَوْ فِي شِرَارِ الْخَلْقِ أَنْ يَتَدَافَعَ أَهْلُ الْمَسْجِدِ لَا يَجِدُونَ إِمَامًا يُصَلِّي بِهِمْ","id":"Telah menceritakan kepada kami [Isma'il bin Muhammad] dia berkata, telah menceritakan kepada kami [Marwan] dia berkata, telah menceritakan kepada kami seorang wanita yang benama [Thalhah] bekas budak bani Fazarah, dari seorang budak mereka yang bernama ['Aqilah] dari [Salamah binti Hur] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, di antara tanda-tanda hari Kiamat, atau sejelek-jelek manusia adalah ketika Jamaah masjid saling menolak untuk maju menjadi imam (karena tidak adanya ilmu) hingga mereka tidak mendapati seorang imam yang memimpin mereka shalat.\""},"3976":{"ar":"حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ عَنْ أَبِيهِ عَنْ سِبَاعِ بْنِ ثَابِتٍ سَمِعْتُ مِنْ أُمِّ كُرْزٍ الْكَعْبِيَّةِ الَّتِي تُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحُدَيْبِيَةِ وَذَهَبْتُ أَطْلُبُ مِنْ اللَّحْمِ عَنْ الْغُلَامِ شَاتَانِ وَعَنْ الْجَارِيَةِ شَاةٌ لَا يَضُرُّكُمْ ذُكْرَانًا كُنَّ أَوْ إِنَاثًا قَالَتْ وَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَقِرُّوا الطَّيْرَ عَلَى مَكِنَاتِهَا","id":"Telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Ubaidillah bin Abu Yazid] dari [ayahnya] dari [Siba' bin Tsabit] aku mendengar dari [Ummu Kurz Al Ka'biyah] yang menceritakan dari Rasulullah shallallahu 'alaihi wasallam, dia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam berada di Hudaibiyah, sedangkan aku pergi meminta daging, untuk anak lelaki dua ekor kambing, dan untuk anak perempuan satu ekor kambing, tidak mengapa apakah (kambing) jantan maupun betina. Dia berkata dan aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Biarkanlah burung tetap berada pada sangkarnya.\""},"3977":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ أَبِيهِ عَنْ سِبَاعِ بْنِ ثَابِتٍ قَالَسَمِعْتُ أَهْلَ الْجَاهِلِيَّةِ يَطُوفُونَ وَهُمْ يَقُولُونَ الْيَوْمُ قَرْنَا عَيْنَانَقْرَعُ الْمَرْوَتَيْنَا","id":"Telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah bin Abu Yazid] dari [ayahnya] dari [Siba' bin Tsabit] dia berkata, \"Aku mendengar orang-orang Jahiliyah thawaf sambil berkata, \"Pada hari ini mata kami bergembira, kami undi dua Marwa kami.\""},"3978":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِيهِ عَنْ سِبَاعِ بْنِ ثَابِتٍ عَنْ أُمِّ كُرْزٍ الْكَعْبِيَّةِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَقَالَ سُفْيَانُ مَرَّةً أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَهَبَتْ النُّبُوَّةُ وَبَقِيَتْ الْمُبَشِّرَاتُ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah] dari [ayahnya] dari [Siba' bin Tsabit] dari [Ummu Kurz Al Ka'biyah] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda, sekali waktu [Sufyan] menyebutkan, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Kenabian akan pergi dan tinggallah pemberi kabar gembira.\""},"3979":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ حَبِيبَةَ بِنْتِ مَيْسَرَةَ عَنْ أُمِّ كُرْزٍ الْكَعْبِيَّةِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ عَنْ الْغُلَامِ شَاتَانِ مُكَافَأَتَانِ وَعَنْ الْجَارِيَةِ شَاةٌقَالَ أَبُو عَبْد الرَّحْمَنِ سَمِعْت أَبِي يَقُولُ سُفْيَانُ يَهِمُ فِي هَذِهِ الْأَحَادِيثِ عُبَيْدُ اللَّهِ سَمِعَهَا مِنْ سِبَاعِ بْنِ ثَابِتٍ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Atha'] dari [Habibah binti Maisarah] dari [Ummu Kurz Al Ka'biyah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Untuk anak laki-laki dua ekor kambing yang sama sedangkan untuk anak perempuan satu ekor kambing.\" Abu 'Abdurrahman berkata, \"Aku mendengar ayahku berkata, \"Sufyan menyangkan 'Ubaidullah mendengar hadits ini dari Siba' bin Tsabit.\""},"3980":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ قَالَ حَدَّثَنِي سِبَاعُ بْنُ ثَابِتٍ عَنْ أُمِّ كُرْزٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْعَقِيقَةِ عَنْ الْغُلَامِ شَاتَانِ مِثْلَانِ وَعَنْ الْجَارِيَةِ شَاةٌ","id":"Telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dia berkata, telah menceritakan kepadaku ['Ubaidullah bin Abu Yazid] dia berkata, telah menceritakan kepadaku [Siba' bin Tsabit] dari [Ummu Kurz] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda mengenai 'Akikah: \"Untuk anak laki-laki dua ekor kambing yang sama, sedangkan untuk anak perempuan satu ekor kambing.\""},"3981":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ عَمِّهِ عِمْرَانَ بْنِ طَلْحَةَ عَنْ أُمِّهِ حَمْنَةَ بِنْتِ جَحْشٍ قَالَتْأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي قَدْ اسْتَحَضْتُ حَيْضَةً مُنْكَرَةً شَدِيدَةً فَقَالَ احْتَشِي كُرْسُفًا قُلْتُ إِنَّهُ أَشَدُّ مِنْ ذَاكَ إِنِّي أَثُجُّهُ ثَجًّا قَالَ تَلَجَّمِي وَتَحَيَّضِي فِي كُلِّ شَهْرٍ فِي عِلْمِ اللَّهِ سِتَّةَ أَيَّامٍ أَوْ سَبْعَةَ أَيَّامٍ ثُمَّ اغْتَسِلِي غُسْلًا وَصُومِي وَصَلِّي ثَلَاثًا وَعِشْرِينَ أَوْ أَرْبَعًا وَعِشْرِينَ وَاغْتَسِلِي لِلْفَجْرِ غُسْلًا وَأَخِّرِي الظُّهْرَ وَعَجِّلِي الْعَصْرَ وَاغْتَسِلِي غُسْلًا وَأَخِّرِي الْمَغْرِبَ وَعَجِّلِي الْعِشَاءَ وَاغْتَسِلِي غُسْلًا وَهَذَا أَحَبُّ الْأَمْرَيْنِ إِلَيَّ وَلَمْ يَقُلْ يَزِيدُ مَرَّةً وَاغْتَسِلِي لِلْفَجْرِ غُسْلًا","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Syarik bin 'Abdullah] dari ['Abdullah bin Muhammad bin 'Aqil] dari [Ibrahim bin Muhammad bin Thalhah] dari pamannya [Imran bin Thalhah] dari ibunya [Hamnah binti Jahsi] dia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, 'Sesungguhnya aku mengeluarkan darah haid yang keruh dan deras? ' lalu beliau bersabda: \"Tutupilah dengan kapas.\" Aku berkata lagi, 'Sungguh, dia lebih deras darinya, aku mengeluarkan darah dengan deras sekali! ' Beliau bersabda: \"Kamu balut dan hitunglah haidmu setiap bulan dalam ilmu Allah selama enam atau tujuh hari kemudian mandilah, lalu berpuasa dan shalatlah dua puluh tiga atau dua puluh empat (hari). Mandilah kamu untuk shalat fajar, akhirkan zhuhur dan segerakan shalat asar lalu mandilah, akhirkan maghrib dan segerakan isya' lalu mandilah, dan inilah antara dua perkara yang aku sukai.\" Namun Yazid tidak menyebutkan, \"Mandilah untuk shalat.\""},"3982":{"ar":"حَدَّثَنَا هَيْثَمُ يَعْنِي ابْنَ خَارِجَةَ قَالَ حَدَّثَنَا حَفْصُ بْنُ مَيْسَرَةَ عَنِ ابْنِ حَرْمَلَةَ عَنْ أَبِي ثِفَالٍ الْمُرِّيِّ أَنَّهُ قَالَ سَمِعْتُ رَبَاحَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ حُوَيْطِبٍ يَقُولُ حَدَّثَتْنِي جَدَّتِي أَنَّهَا سَمِعَتْ أَبَاهَا يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا صَلَاةَ لِمَنْ لَا وُضُوءَ لَهُ وَلَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عَلَيْهِ وَلَا يُؤْمِنُ بِاللَّهِ مَنْ لَا يُؤْمِنُ بِي وَلَا يُؤْمِنُ بِي مَنْ لَا يُحِبُّ الْأَنْصَارَ","id":"Telah menceritakan kepada kami [Haitsam] -yakni Ibnu Kharijah- dia berkata, telah menceritakan kepada kami [Hafsh bin Maisarah] dari [Ibnu Marhalah] dari [Abu Tsifal Al Murri] bahwa dia berkata, aku mendengar [Rabah bin 'Abdurrahman bin Huwaithib] berkata, telah menceritakan kepadaku [nenekku] bahwa dia mendengar [ayahnya] berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak sah shalat seseorang yang tidak berwudlu, tidak ada wudlu bagi yang tidak menyebut asma Allah, tidak beriman kepada Allah orang yang tidak beriman kepadaku dan tidak beriman kepadaku orang yang tidak mencintai orang Anshar.\""},"3983":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا أَبُو مَعْشَرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ عَنْ أَبِي ثِفَالٍ الْمُرِّيِّ عَنْ رَبَاحِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ حُوَيْطِبٍ عَنْ جَدَّتِهِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يُؤْمِنُ بِاللَّهِ مَنْ لَمْ يُؤْمِنْ بِي وَلَمْ يُؤْمِنْ بِي مَنْ لَا يُحِبُّ الْأَنْصَارَ وَلَا صَلَاةَ لِمَنْ لَا وُضُوءَ لَهُ وَلَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عَلَيْهِ","id":"Telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Abu Ma'syar] dari ['Abdurrahman bin Harmalah] dari [Abu Tsifal Al Muri] dari [Rabah bin 'Abdurrahman bin Huwaithib] dari [neneknya] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak beriman kepada Allah orang yang tidak beriman kepadaku, dan tidak beriman kepadaku orang yang tidak mencintai orang Anshar, tidak sah shalat seseorang yang tidak berwudlu, tidak ada wudlu bagi yang tidak menyebut nama Allah.\""},"3984":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ حَرْمَلَةَ أَنَّهُ سَمِعَ أَبَا ثِفَالٍ يُحَدِّثُ يَقُولُ سَمِعْتُ رَبَاحَ بْنَ عَبْدِ الرَّحْمَنِ وَلَمْ يَقُلْ عَفَّانُ مَرَّةً ابْنَ أَبِي سُفْيَانَ بْنِ حُوَيْطِبٍ يَقُولُ حَدَّثَتْنِي جَدَّتِي أَنَّهَا سَمِعَتْ أَبَاهَا يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا صَلَاةَ لِمَنْ لَا وُضُوءَ لَهُ وَلَا وُضُوءَ لِمَنْ لَمْ يَذْكُرْ اسْمَ اللَّهِ عَلَيْهِ وَلَا يُؤْمِنُ بِاللَّهِ مَنْ لَا يُؤْمِنُ بِي وَلَا يُؤْمِنُ بِي مَنْ لَا يُحِبُّ الْأَنْصَارَ","id":"Telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami ['Abdurrahman bin Harmalah] bahwa dia mendengar [Abu Tsifal] bercerita, dia berkata; aku mendengar [Rabah bin 'Abdurrahman], sekali waktu 'Affan tidak menyebutkan Ibnu Abu Sufyan bin Huwaithib ia berkata, telah menceritakan kepadaku [nenekku] bahwa dia mendengar [Bapaknya] berkata; saya telah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak sah shalat seseorang yang tidak berwudlu, tidak ada wudlu bagi yang tidak menyebut nama Allah, tidak beriman kepada Allah orang yang tidak beriman kepadaku, dan tidak beriman kepadaku orang yang tidak mencintai orang Anshar.\""},"3985":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بُجَيْدٍ عَنْ جَدَّتِهِ أُمِّ بُجَيْدٍ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ وَاللَّهِ إِنَّ الْمِسْكِينَ لَيَقِفُ عَلَى بَابِي حَتَّى أَسْتَحْيِيَ فَلَا أَجِدُ فِي بَيْتِي مَا أَرْفَعُ فِي يَدِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْفَعِي فِي يَدِهِ وَلَوْ ظِلْفًا مُحْرَقًاحَدَّثَنَا حَجَّاجٌ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ سَعْدٍ قَالَ حَدَّثَنِي سَعِيدٌ يَعْنِي الْمَقْبُرِيَّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بُجَيْدٍ أَخِي بَنِي حَارِثَةَ أَنَّهُ حَدَّثَتْهُ جَدَّتُهُ وَهِيَ امْرَأَةُ بُجَيْدٍ وَكَانَتْ تُزْعَمُ مِمَّنْ بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Ibnu Abu Dzi'b] dari [Al Muqbiri] dari ['Abdurrahman bin Bujaid] dari neneknya [Ummu Bujaid] dia berkata, aku berkata, \"Wahai Rasulullah, demi Allah, orang-orang miskin berdiri di depan pintu rumahku hingga aku malu, sedangkan aku tidak mendapati di rumahku apa yang bisa aku berikan?\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah dia walau dengan secuil daging panggang.\" Telah menceritakan kepada kami [Hajjaj] dan [Abu Kamil] keduanya berkata, telah menceritakan kepada kami [Laits] -yakni Ibnu Sa'ad- berkata, telah menceritakan kepadaku [Sa'id] -yakni Al Makburi- dari ['Abdurrahman bin Bujaid] saudara Bani Haritsah, bahwa neneknya telah menceritakan kepada kepadanya, dia adalah [isteri Bujaid]. Dan ia mengaku termasuk orang yang pernah berbaiat kepada Rasulullah shallallahu 'alaihi wasallam, dia berkata kepada Rasulullah shallallahu 'alaihi wasallam… lalu dia menyebutkan maknanya.\""},"3986":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي سَعِيدٌ يَعْنِي الْمَقْبُرِيَّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بُجَيْدٍ أَخِي بَنِي حَارِثَةَ أَنَّهُ حَدَّثَتْهُ جَدَّتُهُ وَهِيَ أُمُّ بُجَيْدٍ وَكَانَتْ مِمَّنْ بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ إِنَّ الْمِسْكِينَ لَيَقُومُ عَلَى بَابِي فَمَا أَجِدُ لَهُ شَيْئًا أُعْطِيهِ إِيَّاهُ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ لَمْ تَجِدِي لَهُ شَ��ْئًا تُعْطِينَهُ إِيَّاهُ إِلَّا ظِلْفًا مُحْرَقًا فَادْفَعِيهِ إِلَيْهِ فِي يَدِهِ","id":"Telah menceritakan kepada kami [Hasyim bin Qasim] telah menceritakan kepada kami [Laits] telah menceritakan kepadaku [Sa'id] -yakni Al Maqburi- dari ['Abdurrahman bin Bujaid] saudara Bani Haritsah, bahwa neneknya telah menceritakan kepadanya, neneknya adalah [Ummu Bujaid] salah seorang wanita yang berbaiat kepada Nabi shallallahu 'alaihi wasallam. Dia berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Demi Allah, orang-orang miskin berdiri di depan pintuku, sedangkan aku tidak memiliki sesuatupun untuk aku berikan kepadanya?\" Maka beliau bersabda kepadanya: \"Jika kamu tidak mendapatkan sesuatu yang bisa kamu berikan kepadanya melainkan hanya secuil daging panggang, maka berikanlah itu ke dalam genggaman tangannya.\""},"3987":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بُجَيْدٍ عَنْ جَدَّتِهِ أُمِّ بُجَيْدٍ أَنَّهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِينَا فِي بَنِي عَمْرِو بْنِ عَوْفٍ فَأَتَّخِذُ لَهُ سَوِيقَةً فِي قَعْبَةٍ لِي فَإِذَا جَاءَ سَقَيْتُهَا إِيَّاهُ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُ يَأْتِينِي السَّائِلُ فَأَتَزَهَّدُ لَهُ بَعْضَ مَا عِنْدِي فَقَالَ ضَعِي فِي يَدِ الْمِسْكِينِ وَلَوْ ظِلْفًا مُحْرَقًا","id":"Telah menceritakan kepada kami ['Affan] dia berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin Ishaq] dari [Sa'id bin Abu Sa'id Al Muqbiri] dari ['Abdurrahman bin Bujaid] dari neneknya [Ummu Bujaid] bahwa dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendatangi kami sewaktu di Bani 'Amru bin 'Auf, kemudian aku mengambilkan untuk beliau adonan sawiq dalam bejana milikku. Sewaktu beliau datang, aku langsung menuangkannya.\" Ummu Bujaid berkata, \"Aku katakan, \"Wahai Rasulullah, sesungguhnya seorang pengemis datang kepadaku sedangkan aku ingin tidak mempunyai sesuatu?\" maka beliau bersabda: \"Taruhlah pada tangan si miskin itu walaupun dengan secuil daging panggang.\""},"3988":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورِ بْنِ حَيَّانَ الْأَسَدِيِّ عَنِ ابْنِ بِجَادٍ عَنْ جَدَّتِهِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُدُّوا السَّائِلَ وَلَوْ بِظِلْفِ شَاةٍ مُحْرَقٍ أَوْ مُحْتَرِقٍ","id":"Telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Manshur bin Hayyan Al Asadi] dari [Ibnu Bijad] dari [neneknya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah orang yang meminta walau dengan secuil daging kambing yang telah dipanggang, atau terpanggang.\""},"3989":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ قَالَ حَدَّثَنِي الْمُغِيرَةُ بْنُ عَبْدِ اللَّهِ الْيَشْكُرِيُّ عَنْ أَبِيهِ قَالَانْطَلَقْتُ إِلَى الْكُوفَةِ لِأَجْلِبَ بِغَالًا قَالَ فَأَتَيْتُ السُّوقَ وَلَمْ تُقَمْ قَالَ قُلْتُ لِصَاحِبٍ لِي لَوْ دَخَلْنَا الْمَسْجِدَ وَمَوْضِعُهُ يَوْمَئِذٍ فِي أَصْحَابِ التَّمْرِ فَإِذَا فِيهِ رَجُلٌ مِنْ قَيْسٍ يُقَالُ لَهُ ابْنُ الْمُنْتَفِقِ وَهُوَ يَقُولُ وُصِفَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحُلِّيَ فَطَلَبْتُهُ بِمِنًى فَقِيلَ لِي هُوَ بِعَرَفَاتٍ فَانْتَهَيْتُ إِلَيْهِ فَزَاحَمْتُ عَلَيْهِ فَقِيلَ لِي إِلَيْكَ عَنْ طَرِيقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ دَعُوا الرَّجُلَ أَرِبَ مَا لَهُ قَالَ فَزَاحَمْتُ عَلَيْهِ حَتَّى خَلَصْتُ إِلَيْهِ قَالَ فَأَخَذْتُ بِخِطَامِ رَاحِلَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ زِمَامِهَا هَكَذَا حَدَّثَ مُحَمَّدٌ حَتَّى اخْتَلَفَتْ أَعْنَاقُ رَاحِلَتَيْنَا قَالَ فَمَا يَزَعُنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ مَا غَيَّرَ عَلَيَّ هَكَذَا حَدَّثَ مُحَمَّدٌ قَالَ قُلْتُ ثِنْتَانِ أَسْأَلُكَ عَنْهُمَا مَا يُنَجِّينِي مِنْ النَّارِ وَمَا يُدْخِلُنِي الْجَنَّةَ قَالَ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى السَّمَاءِ ثُمَّ نَكَسَ رَأْسَهُ ثُمَّ أَقْبَلَ عَلَيَّ بِوَجْهِهِ قَالَ لَئِنْ كُنْتَ أَوْجَزْتَ فِي الْمَسْأَلَةِ لَقَدْ أَعْظَمْتَ وَأَطْوَلْتَ فَاعْقِلْ عَنِّي إِذًا اعْبُدْ اللَّهَ لَا تُشْرِكْ بِهِ شَيْئًا وَأَقِمْ الصَّلَاةَ الْمَكْتُوبَةَ وَأَدِّ الزَّكَاةَ الْمَفْرُوضَةَ وَصُمْ رَمَضَانَ وَمَا تُحِبُّ أَنْ يَفْعَلَهُ بِكَ النَّاسُ فَافْعَلْهُ بِهِمْ وَمَا تَكْرَهُ أَنْ يَأْتِيَ إِلَيْكَ النَّاسُ فَذَرْ النَّاسَ مِنْهُ ثُمَّ قَالَ خَلِّ سَبِيلَ الرَّاحِلَةِ","id":"Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Hammam] berkata, telah menceritakan kepada kami [Muhammad bin Juhadah] berkata, telah menceritakan kepadaku [Al Mughirah bin Abdullah Al Yasykuri] dari [Ayahnya] dia berkata, \"Aku pergi ke Kufah untuk mengambil keledai.\" Abdullah berkata, \"Lalu aku mendatangi pasar, dan ternyata pasar belum dimulai. Kemudian aku berkata kepada sahabatku, 'Bagaimana jika kita masuk ke masjid, pada hari itu adalah pasarannya pedagang kurma', ternyata di dalam masjid ada seorang laki-laki yang bernama Qa'is bin Al Muntafiq. Laki-laki itu berkata, \"Telah diterangkan kepadku tentang sifat Rasulullah shallallahu 'alaihi wasallam, kemudian aku mencarinta di Mina, lantas dikatakan kepadaku bahwa beliau berada di Arafah, akhirnya aku menemukan beliau. Kemudian aku berdesak-desakkan untuk menemui beliau, dikatakan kepadaku, 'Menjauhlah dari jalan Rasulullah shallallahu 'alaihi wasallam', kemudian beliau bersabda: \"Biarkan orang itu, biarkan apa yang diinginkan, \" [Ibnul Muntafiq] lalu berkata, \"Kemudian aku bergegas menemui beliau hingga aku berada di depannya. Kemudian aku mengambil tali kekang tunggangan Rasulullah shallallahu 'alaihi wasallam, atau dia berkata; tali pengikatnya -seperti ini yang diriwayatkan Muhammad- hingga kedua leher tunggangan kami beriringan.\" Ibnul Muntafiq berkata, \"Dan Rasulullah shallallahu 'alaihi wasallam tidak mengeluhkan kepadaku, atau dia mengatakan, beliau tidak berubah raut mukanya padaku -seperti ini yang diriwayatkan Muhammad-. Aku lalu berkata, \"Dua hal yang aku tanyakan kepada tuan; apa yang menyebabkan aku bebas dari neraka, dan apa yang menyebabkan aku masuk surga? ' Lalu Rasulullah shallallahu 'alaihi wasallam menengadahkan kepalanya ke langit dan menurunkannya lagi, kemudian menatapku dengan wajahnya, beliau bersabda: \"Jika kamu meringankan soal ini, maka kamu telah menjadikannya perkara besar dan lama, pergi dan sembahlah Allah dan jangan kamu sekutukan dengan sesuatupun, dirikan shalat wajib, tunaikan zakat, dan berpuasalah pada bulan Ramadan. Jika kamu suka orang-orang melakukan sesuatu (kebaikan) kepadamu, maka lakukanlah kebaikan itu kepada mereka, dan jika kamu benci orang-orang melakukan keburukan itu kepadamu, maka jangan kamu lakukan keburukan itu kepada mereka.\" Kemudian beliau bersabda: \"Berikan jalan untukku.\""},"3990":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ عَمْرِو بْنِ حَسَّانَ يَعْنِي الْمَسْلِيَّ قَالَ حَدَّثَنِي الْمُغِيرَةُ بْنُ عَبْدِ اللَّهِ الْيَشْكُرِيُّ عَنْ أَبِيهِ قَالَدَخَلْتُ مَسْجِدَ الْكُوفَةِ أَوَّلَ مَا بُنِيَ مَسْجِدُهَا وَهُوَ فِي أَصْحَابِ التَّمْرِ يَوْمَئِذٍ وَجُدُرُهُ مِنْ سِهْلَةٍ فَإِذَا رَجُلٌ يُحَدِّثُ النَّاسَ قَالَ بَلَغَنِي حَجَّةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّةُ الْوَدَاعِ قَالَ فَاسْتَتْبَعْتُ رَاحِلَةً مِنْ إِبِلِي ثُمَّ خَرَجْتُ حَتَّى جَلَسْتُ لَهُ فِي طَرِيقِ عَرَفَةَ أَوْ وَقَفْتُ لَهُ فِي طَرِيقِ عَرَفَةَ قَالَ فَإِذَا رَكْبٌ عَرَفْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ بِالصِّفَةِ فَقَالَ رَجُلٌ أَمَامَهُ خَلِّ عَنْ طَرِيقِ الرِّكَابِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْحَهُ دَعْهُ فَأَرِبَ مَا لَهُ فَدَنَوْتُ مِنْهُ حَتَّى اخْتَلَفَتْ رَأْسُ النَّاقَتَيْنِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ دُلَّنِي عَلَى عَمَلٍ يُدْخِلُنِي الْجَنَّةَ وَيُنَجِّينِي مِنْ النَّارِ قَالَ بَخٍ بَخٍ لَئِنْ كُنْتَ قَصَّرْتَ فِي الْخُطْبَةِ لَقَدْ أَبْلَغْتَ فِي الْمَسْأَلَةِ اتَّقِ اللَّهَ لَا تُشْرِكْ بِاللَّهِ وَتُقِيمُ الصَّلَاةَ وَتُؤَدِّي الزَّكَاةَ وَتَحُجُّ الْبَيْتَ وَتَصُومُ رَمَضَانَ خَلِّ عَنْ طَرِيقِ الرِّكَابِقَالَ حَدَّثَنَا وَكِيعٌ عَنْ يُونُسَ يَعْنِي ابْنَ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ هَذَا الْحَدِيثَ مِنْ الْمُغِيرَةِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Waki'] dari ['Amru bin Hasan] -yakni Al Masli- dia berkata, telah menceritakan kepadaku [Al Mughirah bin 'Abdullah Al Yasykuri] dari [ayahnya] dia berkata, \"Aku masuk masjid Kufah waktu pertama kali dibangun masjidnya, sedagkan waktu itu ia digunakan oleh para penjual kurma, dan dindingnya terbuat dari pasir yang mudah hancur. Tiba-tiba ada [seorang laki-laki] yang meriwayatkan hadits kepada orang-orang, laki-laki itu berkata, \"Telah sampai berita kepadaku hajinya Rasulullah shallallahu 'alaihi wasallam, yaitu haji wada'.\" Kemudian aku menyusulnya dengan berkendaraan untaku, kemudian aku keluar sampai akhirnya aku duduk di jalan 'Arafah, atau aku berhenti di jalan 'Arafah.\" Abdullah berkata, \"Kemudian muncul satu rombongan, dan aku tahu bahwa dalamrombongan tersebut ada Rasulullah shallallahu 'alaihi wasallam. Lalu seorang laki-laki yang ada di depannya berkata, \"Minggirlah dari jalan pengendara, \" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Celaka kamu! Biarkanlah dia.\" Kemudian aku menyeru mendekat hingga kedua unta (untaku dan unta beliau) kepalanya saling bersentuhan.\" Abdullah berkata, \"Aku lalu berkata, \"Wahai Rasulullah, tunjukkanlah kepadaku amalan yang bisa memasukkan aku ke dalam surga dan menyelamatkan aku dari Neraka.\" Beliau menjawab: \"Bagus, bagus, sekiranya kamu singkat dalam khutbah (doa) sungguh kamu telah sampai pada apa yang kamu minta. Bertakwalah kepada Allah dan jangan menyekutukan Allah, dirikanlah shalat, tunaikanlah zakat, berhaji ke Baitul Haram, dan berpuasa pada bulan Ramadan. Sekarang minggirlah dari jalan pengendara.\" Abdullah berkata, \"Telah menceritakan kepada kami [Waki'] dari [Yunus] -yakni Ibnu Abu Ishaq- dia berkata, aku mendengar hadits ini dari [Mughirah bin 'Abdullah] dari [ayahnya] seperti itu.\""},"3991":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ وَعَمِّهِ قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُوا لُحُومَ الْأَضَاحِيِّ وَادَّخِرُوا","id":"Telah menceritakan kepada kami [Abdul Malik bin 'Amru] dan [Abdurrahman bin Mahdi] keduanya berkata, telah menceritakan kepada kami [Zuhair] -yakni Ibnu Muhammad- dari [Syarik bin Abdullah] dari [Abdurrahman bin Abu Sa'id al Khudri] dari [Ayahnya] dan pamannya [Qatadah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah oleh kalian daging kurban dan simpanlah ia.\""},"3992":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ سِيرِينَ عَنْ أَبِي الْعَلَانِيَةِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأَتَيْتُ هَذِهِ يَعْنِي امْرَأَتَهُ وَعِنْدَهَا لَحْمٌ مِنْ لُحُومِ الْأَضَاحِيِّ قَدْ رَفَعَتْهُ فَرَفَعْتُ عَلَيْهَا الْعَصَا فَقَالَتْ إِنَّ فُلَانًا أَتَانَا فَأَخْبَرَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي كُنْتُ نَهَيْتُكُمْ أَنْ تُمْسِكُوا لُحُومَ الْأَضَاحِيِّ فَوْقَ ثَلَاثَةِ أَيَّامٍ فَكُلُوا وَادَّخِرُوا","id":"Telah menceritakan kepada kami [Abdus Shamad] berkata, telah menceritakan kepada kami [Yazid bin Ibrahim] berkata, telah menceritakan kepada kami [Muhammad] -yakni Ibnu Sirin- dari [Abu Al Alaniyah] dari [Abu Sa'id Al Khudri] berkata, \"Aku menemui ini -yakni isterinya-, sedangkan di sisinya ada daging kurban yang ia telah mengangkatnya, maka aku pun mengangkatnya dengan tongkat. Isteriku lalu berkata, \"Fulan telah datang dan mengabarkan kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku pernah melarang kalian untuk menahan daging kurban lebih dari tiga hari, maka sekarang makanlah dan simpanlah.\""},"3993":{"ar":"حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا لَيْثٌ عَنْ يَزِيدَ يَعْنِي ابْنَ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَأَنَّ قَتَادَةَ بْنَ النُّعْمَانِ الظَّفَرِيَّ وَقَعَ بِقُرَيْشٍ فَكَأَنَّهُ نَالَ مِنْهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا قَتَادَةُ لَا تَسُبَّنَّ قُرَيْشًا فَلَعَلَّكَ أَنْ تَرَى مِنْهُمْ رِجَالًا تَزْدَرِي عَمَلَكَ مَعَ أَعْمَالِهِمْ وَفِعْلَكَ مَعَ أَفْعَالِهِمْ وَتَغْبِطُهُمْ إِذَا رَأَيْتَهُمْ لَوْلَا أَنْ تَطْغَى قُرَيْشٌ لَأَخْبَرْتُهُمْ بِالَّذِي لَهُمْ عِنْدَ اللَّهِ عَزَّ وَجَلَّقَالَ يَزِيدُ سَمِعَنِي جَعْفَرُ بْنُ عَبْدِ اللَّهِ بْنِ أَسْلَمَ وَأَنَا أُحَدِّثُ هَذَا الْحَدِيثَ فَقَالَ هَكَذَا حَدَّثَنِي عَاصِمُ بْنُ عُمَرَ بْنِ قَتَادَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ","id":"Telah menceritakan kepada kami [Yunus] berkata, Telah menceritakan kepada kami [Laits] dari [Yazid] -yakni Ibnul Hadi- dari [Muhammad bin Ibrahim], bahwa Qatadah bin Nu'man Azh Zhafari bertikai dengan kaum Quraisy seakan-akan ia menjelekkan mereka, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Hai Qatadah, janganlah kamu menghina kaum Quraisy, barangkali kamu melihat di antara mereka terdapat orang-orang yang amalanmu lebih rendah dari amalan mereka, perbuatanmu lebih rendah daripada perbuatan mereka, dan kamu iri jika kamu melihat mereka. Jika saja orang-orang Quraisy tidak melampaui batas, maka akan aku kabarkan apa yang Allah Azza Wa Jalla siapkan untuk mereka.\" [Yazid] berkata; [Ja'far bin Abdullah bin Aslam] mendengarku mengatakan hadits ini, dan aku meriwayatkan hadits ini. Lalu dia berkata, seperti ini yang aku dengar dari [Ashim bin Umar bin Qatadah] dari [ayahnya] dari [kakeknya.] "},"3994":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُحْسِنْ إِلَى جَارِهِ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ","id":"Telah mengabarkan kepada kami [Sufyan] dari ['Amru] dari [Nafi' bin Jubair bin Muth'im] dari [Abu Syuraij Al khuza'i] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa beriman kepada Allah dan hari akhir hendaknya ia menghormati tamunya, barangsiapa beriman kepada Allah dan hari akhir hendaknya berbuat baik terhadap tetangganya, dan barangsiapa beriman kepada Allah dan hari akhir hendaklah ia berkata baik atau diam.\""},"3995":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنَا سَعِيدٌ يَعْنِي الْمَقْبُرِيَّ قَالَ سَمِعْتُ أَبَا شُرَيْحٍ الْكَعْبِيَّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ إِنَّ اللَّهَ عَزَّ وَجَلَّ حَرَّمَ مَكَّةَ وَلَمْ يُحَرِّمْهَا النَّاسُ فَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يَسْفِكَنَّ فِيهَا دَمًا وَلَا يَعْضِدَنَّ فِيهَا شَجَرًا فَإِنْ تَرَخَّصَ مُتَرَخِّصٌ فَقَالَ أُحِلَّتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ اللَّهَ أَحَلَّهَا لِي وَلَمْ يُحِلَّهَا لِلنَّاسِ وَهِيَ سَاعَتِي هَذِهِ حَرَامٌ إِلَى أَنْ تَقُومَ السَّاعَةُ إِنَّكُمْ مَعْشَرَ خُزَاعَةَ قَتَلْتُمْ هَذَا الْقَتِيلَ وَإِنِّي عَاقِلُهُ فَمَنْ قُتِلَ لَهُ قَتِيلٌ بَعْدَ مَقَالَتِي هَذِهِ فَأَهْلُهُ بَيْنَ خِيرَتَيْنِ إِمَّا أَنْ يَقْتُلُوا أَوْ يَأْخُذُوا الْعَقْلَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Ibnu Abu Dzi'b] berkata, telah menceritakan kepada kami [Sa'id] -yakni Al Maqbri berkata, aku mendengar [Abu Syuraih Al Ka'bi] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda pada saat penaklukan kota Makkah: \"Sesungguhnya Allah Azza Wa Jalla telah mengharamkan kota Makkah dan manusia belum mengharamkannya, maka barangsiapa beriman kepada Allah dan hari akhir, hendaknya tidak menumpahkan darah di dalamnya, dan tidak menebang pepohonan di dalamnya meskipun dari orang yang meremehkan.\" Abu Syuraih berkata, \"Telah dihalalkan buat Rasulullah shallallahu 'alaihi wasallam, \"Sesungguhnya Allah telah menghalalkan buatku dan tidak menghalalkan buat yang lain, ia haram dari sekarang ini hingga hari Kiamat kelak. Sesungguhnya kalian wahai bani Khuza'ah, telah membunuh orang ini, dan sesungguhnya akulah yag menebus diatnya, maka barangsiapa membunuh seseorang setelah perkataanku ini, maka keluarganya berhak untuk memilih antara dua pilihan; balas bunuh atau mengambil diyatnya.\""},"3996":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مَالِكٌ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ أَبِي شُرَيْحٍ الْكَعْبِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ جَارَهُ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ جَائِزَتُهُ يَوْمٌ وَلَيْلَةٌ الضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ فَمَا كَانَ بَعْدَ ذَلِكَ فَهُوَ صَدَقَةٌ لَا يَحِلُّ لَهُ أَنْ يَثْوِيَ عِنْدَهُ حَتَّى يُخْرِجَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata, Telah menceritakan kepada kami [Malik] berkata, Telah menceritakan kepadaku [Sa'id bin Abu Sa'id] dari [Abu Syuraih Al Ka'bi] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa beriman kepada Allah dan hari akhir hendaknya ia memuliakan tetangganya, barangsiapa beriman kepada Allah dan hari akhir hendaknya ia berkata dengan perkataan yang baik atau diam, dan barangsiapa beriman kepada Allah dan hari akhir hendaknya ia memuliakan tamunya, yaitu melayaninya tiap hari dan malam. Dan masa bertamu itu adalah tiga hari, jika lebih dari itu maka ia menjadi sedekah, dan tidak halal baginya untuk menginap hingga ia (pemilik rumah) mengeluarkannya.\""},"3997":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا ابْنُ أَبِي ذِئْبٍ عَنِ الْمَقْبُرِيِّ عَنْ أَبِي شُرَيْحٍ الْكَعْبِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَاللَّهِ لَا يُؤْمِنُ وَاللَّهِ لَا يُؤْمِنُ وَاللَّهِ لَا يُؤْمِنُ قَالُوا وَمَا ذَاكَ يَا رَسُولَ اللَّهِ قَالَ الْجَارُ لَا يَأْمَنُ جَارُهُ بَوَائِقَهُ قَالُوا يَا رَسُولَ اللَّهِ وَمَا بَوَائِقُهُ قَالَ شَرُّهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata, Telah mengabarkan kepada kami [Ibnu Abu Dzi'b] dari [Maqburi] dari [Abu Syuraih Al Ka'bi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Allah tidak beriman, demi Allah tidak beriman, demi Allah tidak beriman.\" Para sahabat bertanya, \"Apa itu wahai Rasulullah? Beliau menjawab: \"Seseorang yang tetangganya tidak pernah meras aman dari gangguannya?\" mereka bertanya lagi, \"Apa yang dimaksud dengan gangguannya?\" Beliau menjawab: \"Keburukannya.\""},"3998":{"ar":"حَدَّثَنَا صَفْوَانُ قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي شُرَيْحِ بْنِ عَمْرٍو الْخُزَاعِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاكُمْ وَالْجُلُوسَ عَلَى الصُّعُدَاتِ فَمَنْ جَلَسَ مِنْكُمْ عَلَى الصَّعِيدِ فَلْيُعْطِهِ حَقَّهُ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا حَقُّهُ قَالَ غُضُوضُ الْبَصَرِ وَرَدُّ التَّحِيَّةِ وَأَمْرٌ بِمَعْرُوفٍ وَنَهْيٌ عَنْ مُنْكَرٍ","id":"Telah menceritakan kepada kami [Shufwan] berkata, Telah mengabarkan kepada kami [Abdullah bin Sa'id] dari [ayahnya] dari [Abu Syuraih bin 'Amru Al khuza'i] dia berkata, \"Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Janganlah kalian duduk-duduk di jalan umum, maka barangsiapa di antara kalian duduk di jalanan umum hendaklah ia berikan haknya.\" Abu Syuraih berkata, \"Kami lalu bertanya, \"Wahai Rasulullah, apa saja haknya?\" Beliau menjawab: \"Menundukkan pandangan, menjawab salam, memerintahkan kepada kebaikan dan mencegah dari kemungkaran.\""},"3999":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ قَالَ حَدَّثَنَا لَيْثٌ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ عَنْ أَبِي شُرَيْحٍ الْعَدَوِيِّأَنَّهُ قَالَ لِعَمْرِو بْنِ سَعِيدٍ وَهُوَ يَبْعَثُ الْبُعُوثَ إِلَى مَكَّةَ ائْذَنْ لِي أَيُّهَا الْأَمِيرُ أُحَدِّثْكَ قَوْلًا قَامَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغَدَ مِنْ يَوْمِ الْفَتْحِ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي وَأَبْصَرَتْهُ عَيْنَايَ حَيْثُ تَكَلَّمَ بِهِ أَنَّهُ حَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ مَكَّةَ حَرَّمَهَا اللَّهُ وَلَمْ يُحَرِّمْهَا النَّاسُ فَلَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَسْفِكَ فِيهَا دَمًا وَلَا يَعْضِدَ فِيهَا شَجَرَةً فَإِنْ أَحَدٌ تَرَخَّصَ بِقِتَالِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا فَقُولُوا إِنَّ اللَّهَ عَزَّ وَجَلَّ أَذِنَ لِرَسُولِهِ وَلَمْ يَأْذَنْ لَكُمْ وَإِنَّمَا أَذِنَ لِي فِيهَا سَاعَةً مِنْ نَهَارٍ وَقَدْ عَادَتْ حُرْمَتُهَا الْيَوْمَ كَحُرْمَتِهَا بِالْأَمْسِ فَلْيُبَلِّغْ الشَّاهِدُ الْغَائِبَفَقِيلَ لِأَبِي شُرَيْحٍ مَا قَالَ لَكَ عَمْرٌو قَالَ قَالَ أَنَا أَعْلَمُ بِذَلِكَ مِنْكَ يَا أَبَا شُرَيْحٍ إِنَّ الْحَرَمَ لَا يُعِيذُ عَاصِيًا وَلَا فَارًّا بِدَمٍ وَلَا فَارًّا بِجِزْيَةٍ وَكَذَلِكَ قَالَ حَجَّاجٌ بِجِزْيَةٍ وَقَالَ يَعْقُوبُ عَنْ أَبِيهِ عَنِ ابْنِ إِسْحَاقَ وَلَا مَانِعَ جِزْيَةٍ","id":"Telah menceritakan kepada kami [Abu Kamil] berkata, Telah menceritakan kepada kami [Laits] berkata, Telah menceritakan kepadaku [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Syuraih Al 'Adawi] bahwa dia berkata kepada 'Amru bin Sa'id yang saat itu sedang mengirimkan pasukan menuju Makkah, \"Izinkanlah aku wahai amir, aku akan menceritakan kepadamu sebuah hadits. Rasulullah shallallahu 'alaihi wasallam berdiri pada waktu penaklukan kota Makkah, aku dengar dengan kedua telingaku, hatiku meresapi dan mataku melihatnya, bahwa beliau mengatakannya. Setelah mengucapkan syukur dan pujian kepada Allah, beliau bersabda: \"Sesungguhnya kota Makkah telah Allah haramkan, sedangkan manusia belum mengharamkannya, maka tidak halal bagi seorang yang beriman kepada Allah dan hari akhir untuk menumpahkan darah di dalamnya dan menebang pepohonannya. Jika ada seseorang menyangkal bahwa Rasulullah shallallahu 'alaihi wasallam berperang di dalamnya, maka katakanlah oleh kalian bahwa Allah Azza Wa Jalla telah mengizinkan buat Rasul-Nya dan tidak mengizinkan buat kalian, hanyasanya aku dizinkan sesaat di siang hari kemudian kembali diharamkan kesuciannya sebagaimana kemarin. Maka hendaknya orang yang hadir menyampaikan kepada orang yang tidak hadir.\" Maka dikatakan kepada [Abu Syuraih], \"Lalu apa yang dikatakan 'Amru kepadamu?\" Dia berkata, \"'Amru berkata, \"Aku lebih tahu daripada kamu wahai Abu Syuraih! Sesungguhnya Baitul Haram tidak melindungi orang yang durhaka, orang yang lari karena urusan darah serta orang yang lari dari jizyah.\" Hajjaj juga menyebutkan, \"Dengan Jizyah.\" Dan [Ya'qub] juga menyebutkan dari [ayahnya] dari [Ibnu Ishaq], \"Dan orang yang enggan membayar jizyah.\""},"4000":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ عَنْ أَبِي شُرَيْحٍ الْعَدَوِيِّ مِنْ خُزَاعَةَ وَكَانَ مِنْ الصَّحَابَةِ رَضِيَ اللَّهُ عَنْهُمْعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الضِّيَافَةُ ثَلَاثٌ وَجَائِزَتُهُ يَوْمٌ وَلَيْلَةٌ وَلَا يَحِلُّ لِأَحَدٍ أَنْ يُقِيمَ عِنْدَ أَخِيهِ حَتَّى يُؤْثِمَهُ قَالُوا يَا رَسُولَ اللَّهِ مَا يُؤْثِمُهُ قَالَ يُقِيمُ عِنْدَهُ وَلَا يَجِدُ شَيْئًا يَقُوتُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Bakr] berkata, Telah menceritakan kepada kami [Abdul Hamid] berkata, Telah mengabarkan kepadaku [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Syuraih Al Adawi] dari Khuza'ah -dan ia termasuk sahabat Nabi radliallahu 'anhum-, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Masa bertamu adalah tiga hari, maka ia dilayani siang dan malam hari, dan tidak halal bagi seseorang untuk tinggal di rumah saudaranya sehingga menjadikannya berdosa.\" Para sahabat berkata, \"Wahai Rasulullah, apa maksud dari membuatnya berdosa?\" Beliau menjawab: \"Dia tinggal bersama saudaranya sampai saudaranya tidak memiliki sesuatu untuk menjamunya.\""}};
